const DISCOVERY={"1772":[{"type":"地理","name":"チチカカ湖","rank":"5","desc":"標高3800mの位置にある湖。天空の湖とも呼ばれ、その昔、創造神であるヴィラコチャが降り立った湖と言い伝えられている。湖の周りには、多くの遺跡が残されている。","note":"神が降り立つ湖","exp":"830"}],"5935":[{"type":"天文","name":"オベロン","rank":"3","desc":"天王星の衛星の一つ。妖精の王オベロンの名を冠している。クレーターには「マクベス」や「ハムレット」などシェークスピアの作品に登場する人物の名前が付けられている。","note":"クエスト「喜劇の妖精王」<br/>発見物カード:240","exp":"480"}],"123":[{"type":"地理","name":"コリント地峡","rank":"1","desc":"バルカン半島とペロポネソス半島をつなぐ、幅わずか7kmの地峡。この地域は平地が少なく乾燥気味で、オリーブ栽培や牧畜が盛んである。","note":"ギリシャ近海の地形","exp":"70"}],"1972":[{"type":"鳥類","name":"カグー","rank":"2","desc":"ニューカレドニアに生息する鳥。危険を感じると冠羽を逆立て、翼を広げて、敵を威嚇する。大きな翼を持っているが、飛ぶことはできない。","note":"白い鳥の地図","exp":"210"}],"116":[{"type":"地理","name":"ビオコ島","rank":"1","desc":"アフリカ西岸、赤道直下に浮かぶ島。ブビ人が住んでいる。山がちで森林におおわれ、年間を通じて高温で降水量も多い。","note":"ギニア湾の島","exp":"105"}],"6182":[{"type":"歴史遺物","name":"アラム語の書簡","rank":"2","desc":"紀元前5世紀、エジプト南部の街エレファンティネに住んでいたユダヤ人が書いたものらしい書簡のパピルス。当時のエジプトはペルシャ王国の支配下にあり、多数のユダヤ人傭兵たちの居住区も当地にあった。","note":"","exp":"340"}],"5097":[{"type":"港・集落","name":"トゥンベス","rank":"2","desc":"フランシスコ・ピサロがインカ帝国へ向かおうとした時に立ち寄った街。甲冑に身を包み陽の光を受けて輝くピサロの姿を見て、現地の人々は彼を神聖な者と考え、歓迎したという。","note":"到達する","exp":"280"}],"472":[{"type":"宗教遺物","name":"アルテミス像","rank":"1","desc":"ギリシャ神話の女神の像。アポロンの双子の妹で、ローマ神話ではディアナ。アルテミスは狩猟と動物、出産、豊穣の女神である。月の女神・セレネと同一視されることもある。","note":"月の女神の像","exp":"120"}],"6773":[{"type":"海洋生物","name":"カクレウオ","rank":"4","desc":"別名「真珠魚」。各大洋の熱帯域に広く生息している。隙を見てナマコやカキの内部に侵入し、そのまますみかとして利用する習性を持つ。基本宿主には害をなさないが、益をなすこともない。","note":"発見物カード:340","exp":"680"}],"5101":[{"type":"港・集落","name":"トレビゾント","rank":"1","desc":"黒海南岸に位置する街である。過去には独立した帝国だった。農業に適した気候で耕作・畜産・漁業いずれも盛んである。","note":"到達する","exp":"46"}],"5243":[{"type":"中型生物","name":"サイガ","rank":"1","desc":"象のような鼻を持つ奇妙な生物。地元では食料や毛皮にするため捕獲されており、角には薬としての成分が含まれるとされているが真偽は不明である。","note":"","exp":"200"}],"5180":[{"type":"港・集落","name":"ローマ","rank":"1","desc":"紀元前から存在するイタリア最大の都。\n王制、共和制、帝制と長い歴史の中で数多の変遷を遂げ、街中にはさまざまな遺跡が存在する。\nコロッセウムもその遺跡の一つである。","note":"到達する","exp":"38"}],"63":[{"type":"宗教遺物","name":"仏教経典","rank":"2","desc":"釈迦（しゃか）の教えを記したとされる本。このうちスッタニパータという経典が最も古く、釈迦の言葉に最も近いという。長い間に多くの宗派が出たため膨大な種類がある。","note":"インドの宗教書の地図","exp":"260"}],"6179":[{"type":"植物","name":"メジャー・オーク","rank":"3","desc":"ノッティンガム郊外のシャーウッドの森にあるオークの古木。数百年も昔から森に根付いているとされており、ロビン・フッドと森の仲間たちがここで集会を開いていたという言い伝えが残っている。","note":"","exp":"500"}],"5826":[{"type":"財宝","name":"シャルルマーニュの護符","rank":"5","desc":"シャルルマーニュが身に着けていたというペンダント状の護符。所有する者は皇帝になるという伝説がある。この護符を次に所有するのは、いったい誰になるのだろうか。","note":"","exp":"1410"}],"5286":[{"type":"中型生物","name":"リカオン","rank":"2","desc":"アフリカ中南部のサバンナや草原に棲むイヌに似た生物。体は黒・白・オレンジの三色がまだら模様を描き、丸く大きな耳を持つ。数十頭ほどの非常に社会性に富んだ群れを作って生活している。仲間同士で巧みに連携して狩りを行う。","note":"","exp":"240"}],"7012":[{"type":"天文","name":"スアロキン","rank":"5","desc":"いるか座のアルファ星で、青白い多重星。イルカの背中部分に位置する。ベータ星ロタネブと同じく、天文学者ニコロ・カチャトーレのラテン語名「ニコラス」を逆から綴って名づけられた。","note":"北西太平洋海盆視認","exp":""}],"1933":[{"type":"虫類","name":"タイタンオオウスバカミキリ","rank":"2","desc":"巨大なカミキリムシ。大人の手のひら程の大きさで、鋭い顎と爪を持つ。幼虫の体長は、その1.5倍。これほど大きなカミキリムシは他に類を見ない。南米の熱帯雨林に生息。","note":"巨大な虫の地図","exp":"210"}],"2798":[{"type":"虫類","name":"テングアゲハ","rank":"5","desc":"中国南部の山岳地帯に生息しているチョウ。口ひげが長いことからテングの名が付いた。緑や赤の羽が神々しく輝き、かなりの速さで急降下したりと飛び方も雄々しい。まさに、チョウの中の王といえる。","note":"青空の下の幻","exp":"1250"}],"2259":[{"type":"植物","name":"プルメリア","rank":"2","desc":"南国で見られる花。\n甘い香りとはっきりした花弁の色が特徴で、よく髪飾りなどに使用される。茎が折れやすく、そこから分泌される白色の乳液は毒にも薬にもなるらしい。","note":"髪に飾る花","exp":"210"}],"5831":[{"type":"気象・現象","name":"乳房雲","rank":"2","desc":"雲からこぶ状の雲がいくつも垂れ下がっているように見える現象。雲の内部や底での乱気流の動きにより作り出されると考えられる。そのため、この雲を観測する際は大雨や嵐に注意が必要である。","note":"","exp":"320"}],"2358":[{"type":"財宝","name":"宣教師の書簡","rank":"4","desc":"ポルトガル人宣教師である、ガスパル・ヴィレラが書いた書簡。\n堺という日本の港街について、ヴェネツィアのようだと評する記述が見られる。","note":"クエスト「堺の評判」<br/>発見物カード:390","exp":"780"}],"3766":[{"type":"天文","name":"金星","rank":"2","desc":"明け方と夕方に姿を現す、太陽と月に次いで明るい惑星。古代ギリシャのピタゴラスが明けの明星と宵の明星が同じ星だと気づいたとされる。ローマ神話のヴイーナスを始め、美を司る女神の名で呼ばれることが多い。","note":"クエスト「美の女神の星」<br/><br/>発見物カード:175<br/>","exp":"350"}],"1643":[{"type":"地理","name":"タヒチ島","rank":"4","desc":"アオテアロアの北東にある島。沿岸部には黒い砂浜が見られる。この島の住人はアオテアロアの住人と同じく、精緻な文様の刺青を施している。さらに言葉まで非常に似通っているようだ。ここがハワイキなのだろうか…。","note":"とこしえの地","exp":"732"}],"6078":[{"type":"伝承","name":"ウンディーネ","rank":"5","desc":"水の精。四大元素のうち、水を司るとされる精霊。美しい女性の姿をしており、人間と結婚することで魂を得るが、夫に裏切られると魂を失い、夫に復讐したのち水に還るとされている。","note":"","exp":"1060"}],"5296":[{"type":"小型生物","name":"アルマジロトカゲ","rank":"5","desc":"アフリカ南部の岩場に褄む全長20cmほどのトカゲ。背中側の鱗は硬く、岩の隙間などに逃げ込む。逃げ場所がないと尾をくわえて体を丸め、背中の鱗を生かした防御体勢をとる。","note":"","exp":"810"}],"531":[{"type":"歴史遺物","name":"古代の農具","rank":"1","desc":"農作業のために使われる道具。文明によってさまざまである。","note":"古代の道具の地図","exp":"44"}],"1169":[{"type":"地理","name":"バミューダ海域","rank":"2","desc":"北大西洋西部にある海域。150ほどの小島が点在している。この海域は難破事故が多く、魔の海域といわれている。","note":"魔の海域","exp":"380"}],"414":[{"type":"化石","name":"靴底のような虫の石","rank":"1","desc":"平らな虫のような生物の形をした石。フナムシに似ているように思うが、大きすぎる。この近くに、同じような生き物がいるのだろうか？　それより、この石はどうしてこんな模様なのだろう？","note":"奇妙な石の地図","exp":"28"}],"5384":[{"type":"鳥類","name":"アカノガンモドキ","rank":"2","desc":"南米に生息する地上性の鳥。首と脚が長く、頭部には特徴的な冠状の羽が生えている。危険を感じると、人が追いつけないほどの速さで走って逃げる。","note":"パラグアイ川上流　再調査報酬","exp":""}],"1011":[{"type":"小型生物","name":"ヨーロッパミンク","rank":"3","desc":"被毛はこげ茶から黒をしていて、唇には白い筋がある。夜行性で、鳥や哺乳類、魚などの小型生物をエサとしている。","note":"魅惑の毛皮","exp":"478"}],"1352":[{"type":"財宝","name":"海中の虹","rank":"5","desc":"遊色効果の高いムーンストーン。澄んだ青いベースカラーの中で、時折七色にきらめいている部分がある。それを見た人が「まるで海の中で虹を見ているようだ」と言ったことからこの名前がついた。","note":"海中の虹","exp":"1040"}],"2850":[{"type":"虫類","name":"カイコ","rank":"3","desc":"中国北部でよく見られる、家畜化された虫。野生には生息しない。絹や綿を生産するためのまゆを作り出す。","note":"高級織物の素材","exp":"510"}],"6714":[{"type":"海洋生物","name":"キンチャクガニ","rank":"5","desc":"主にインド洋と太平洋の沿岸地帯に分布する体長わずか2cmほどの小型のカニ。イソギンチャクをはさみにつけその刺胞で捕食者を撃退する習性があり、まるでボクシンググローブを付けたかのように見える。別名ボクサークラブ。","note":"","exp":""}],"6061":[{"type":"史跡","name":"カステル・デル・モンテ","rank":"2","desc":"神聖ローマ皇帝フリードリヒ2世が建造した城。\n建てられた用途は定かではないが、軍事用の城塞ではなく、狩りの拠点であったという説もある。八角形を取り入れた特徴的な構造をしている。","note":"","exp":"240"}],"5082":[{"type":"港・集落","name":"セイロン","rank":"1","desc":"インド南端にある島の街。島は高地が多く、茶の栽培が盛んだ。また、宝石の鉱脈が非常に豊富で、さまざまな宝石が産出される。","note":"到達する","exp":"178"}],"1755":[{"type":"海洋生物","name":"ヨーロッパオオナマズ","rank":"2","desc":"上あごに非常に長い一対の口ヒゲをもつ巨大ナマズ。成長すると、体長が5mにもなるようだ。","note":"釣り","exp":"350"}],"6377":[{"type":"気象・現象","name":"逆さ虹","rank":"4","desc":"鮮やかな虹が逆さまに弧を描く現象。太陽の真上に現れることが多いとされる。色の順番も通常の虹とは逆で、下側が赤色になる。空中に浮かぶ氷の結晶が太陽光を屈折させることで発生する。","note":"","exp":"800"}],"2567":[{"type":"美術品","name":"洛中洛外図","rank":"2","desc":"日本の都である京の街中と郊外を、高い位置から見下ろした構図で描いた屏風絵。\n華美な美術品であると同時に、街や人々の様子を示す史料ともなり得る。","note":"金の都","exp":"370"}],"2980":[{"type":"植物","name":"ヒツジグサ","rank":"1","desc":"東アジアや北米などに分布する水生植物。水位が安定している池などに自生する。初夏から秋にかけて、日中に白い花を咲かせる。","note":"水上の花の地図","exp":"190"}],"3576":[{"type":"レリック","name":"アルヴィダ","rank":"","desc":"麗しきスウェーデンの王女でありながら女海賊となったアルヴィダ。今なお、スカンジナビアの人々に愛され続ける存在である。","note":"","exp":""}],"3583":[{"type":"植物","name":"マイレ","rank":"2","desc":"ハワイの山地に生息するツル植物。濃い緑色の葉から爽やかで強い香りを放つ。神聖な植物とされ、古代よりヘイアウの装飾や、決闘の勝利者の首にかけるレイとして利用されている。","note":"女神が統べし低木","exp":"204"}],"6295":[{"type":"地理","name":"バッドランズ","rank":"2","desc":"北米中部に位置する広大な荒地。数十万年の歳月をかけて水と風も浸食された岩山が、独特の地形を形作っている。","note":"","exp":"300"}],"127":[{"type":"宗教遺物","name":"聖母のステンドグラス","rank":"1","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40"}],"3746":[{"type":"天文","name":"春の大曲線","rank":"3","desc":"ヨーロッパで春の夜空の様々な星座の目印となる星群。北斗七星のひしゃくの柄の部分から弧を描くように線を引くと、いくつかの1等星が現れる。この並びを春の大曲線と呼ぶ。","note":"夜空に描かれる弧<br/><br/>発見時経験値480　発見物カード経験値240","exp":"480"}],"250":[{"type":"地理","name":"イビサ島","rank":"1","desc":"バレアレス諸島の西部の島。古代から人が住み、アフリカとイスパニア間の中継点となっていた。青い空と海が美しい島である。","note":"バレアレス諸島西部の調査","exp":"20"}],"6693":[{"type":"植物","name":"クワズイモ","rank":"2","desc":"サトイモ科の植物で、大きな葉をつける。その名の通り食用には向かず、毒性があって激しい腹痛を引き起こす。中国では、毒を以て毒を制すの考え方から、薬として用いられた。","note":"台湾島南東岸で上陸。<br/>南島の赤い花付近。","exp":"210"}],"6368":[{"type":"伝承","name":"サイレントシティ","rank":"5","desc":"世界各地で語られる空中に浮かぶ都市。その街並みは現れるたびに変化し、住人が見える場合もあるという。幻にしては、あまりに輪郭がはっきりと見えるとされている。","note":"幻の空中都市に関する伝承","exp":"990"}],"4977":[{"type":"天文","name":"うみへび座の渦巻星雲","rank":"2","desc":"うみへび座のやや南にある渦巻星雲。周辺はかすかだが、中央部が明るく、三本の腕の伸びている。","note":"「天文学者の観測記録」<br/>発見物カード:160","exp":"320"}],"2656":[{"type":"植物","name":"ムクゲ","rank":"3","desc":"朝鮮では、国の繁栄を意味する花として慕われている植物。一つの枝にたくさんの花を咲かせ、散っても次々と花を咲かせる様が、永遠を感じさせる。\n樹皮や花を乾燥させたものは薬にもなる。","note":"永遠の花","exp":"490"}],"5305":[{"type":"植物","name":"シアの木","rank":"2","desc":"サハラの南に広がるサバンナ地帯に生える、樹高7mから20mほどの樹木。降水量が少ない地域でも育つ。種子からはシアバターと呼ばれる良質の油が採れ、食用や薬として利用されている。","note":"","exp":"250"}],"1771":[{"type":"地理","name":"マルガリータ島","rank":"2","desc":"カラカスの東に浮かぶ島。コロンの第三次航海でベネズエラが発見され、イスパニアはいち早くマルガリータ島周辺に拠点の建造を始めた。島の近海では真珠が豊富に採れるため度々海賊の襲撃に見舞われた。","note":"美しい島<br/><br/>発見時経験値220　発見物カード経験値110","exp":"220"}],"5744":[{"type":"宗教建築","name":"ショパン・アタ","rank":"4","desc":"ウスチュルト台地に存在する地下モスク。12世紀、ユーラシア大陸中央部へ派遣されたイスラム宣教団の1人の名を冠している。彼の師が杖を投げると杖から木が生えたといい、その木がこの地に今なお存在している。","note":"","exp":"700"}],"1364":[{"type":"財宝","name":"クアウテモクの槍","rank":"2","desc":"アステカ帝国の皇帝モクテスマの甥であるクアウテモクのものであるといわれている槍。彼は鷲の戦士として、戦場ではいつも気高くあったという。","note":"アステカ戦士の槍の地図","exp":"260"}],"6678":[{"type":"鳥類","name":"タゲリ","rank":"1","desc":"ミューミューとネコのような声で鳴き、きれいな冠羽を持つかわいい鳥。旅鳥で、夏は北ヨーロッパで繁殖し、冬は南ヨーロッパや北アフリカで過ごす。","note":"","exp":"200"}],"604":[{"type":"歴史遺物","name":"彩色レンガ","rank":"1","desc":"美しく彩色したレンガである。さまざまな色のレンガを組み合わせて、壁や門に模様を描くために使われる。","note":"彩色レンガの地図","exp":"99"}],"2797":[{"type":"宗教建築","name":"老君岩","rank":"5","desc":"道教の神・太上老君を模した巨大な石像。\n周囲の民の間では、この像のひげに触ると幸運が訪れると信じられている。","note":"太上老君","exp":"1180"}],"971":[{"type":"史跡","name":"ビブロス","rank":"1","desc":"古代の砦や街の遺跡。幾度も支配勢力が交替したため、複数の文明の遺構が複雑に重なり合っている。","note":"宝物の要塞","exp":"135"}],"3739":[{"type":"海洋生物","name":"ニシオンデンザメ","rank":"4","desc":"北大西洋の極北部などの寒冷な海に生息する大型のサメ。ずんぐりとした体型で、泳ぎはとても遅い。\n魚類だけでなく、アザラシといった動物も捕食する。","note":"のろまなサメ","exp":"800"}],"3166":[{"type":"史跡","name":"コロッセウム","rank":"3","desc":"古代ローマの帝政期に築かれた円形闘技場。四万人余りの観客を収容でき、幾度もの剣闘士競技が繰り広げられた場所である。皇帝・ネロの巨像（コロッスス）が近くにあったため、コロッセウムと呼ばれるようになったという。","note":"古代遺跡と闘技場","exp":"470"}],"417":[{"type":"化石","name":"半竜半魚の骨","rank":"1","desc":"ドラゴンのような長い首と、イルカのようなヒレを持った生き物の骨。骨とはいっても石になっている。どうして骨が石になるのだろう？　未知の呪術か何かだろうか。","note":"奇妙な石の地図","exp":"120"}],"1992":[{"type":"海洋生物","name":"バルチックチョウザメ","rank":"2","desc":"ほのかに金色がかった茶色の体が特徴のチョウザメ。ヨーロッパ北部に分布するようだ。","note":"釣り","exp":"340"}],"2345":[{"type":"地理","name":"富士山","rank":"5","desc":"優美な裾野を引く、日本を代表する活火山。火山活動の記録が残っており、今後も噴火の可能性がある。\nまた、古来より信仰の対象でもあり、霊峰とも呼ばれる。","note":"クエスト「和歌に詠まれた高嶺」<br/>発見物カード:415","exp":"830"}],"1875":[{"type":"宗教遺物","name":"ヴィラコチャのレリーフ","rank":"2","desc":"ヴィラコチャとは、インカ帝国において信仰されている太陽神である。肌が白く顎ひげをたくわえた大柄な男性として描かれ、人々に文明をもたらした神といわれている。文明を与えた後はクスコの湖岸から水を渡り姿を消した。","note":"湖に降り立つ神","exp":"300"}],"6778":[{"type":"史跡","name":"カルマル城","rank":"5","desc":"12世紀、スウェーデンのカルマルに建てられた城。周囲を海に囲まれており、正面の門から伸びる1本の橋で。陸地と繋がる。1397年カルマル同盟がここで結ばれた。","note":"カード経験値　540","exp":"1080"}],"1161":[{"type":"中型生物","name":"アルマジロ","rank":"3","desc":"頭から背中、尾にかけての皮膚が鎧のように変化している動物。危険を感じると丸くなり外敵の牙や爪から身を守れるようだ。大きさや模様がさまざまだが別種なのか個体差なのかは不明だ。","note":"硬い守り","exp":"473"}],"6335":[{"type":"伝承","name":"鸞鳥","rank":"5","desc":"中国の伝説で語り継がれる霊鳥。読みは「らんちょう」。社会が安定すると現れるといわれている。五音の声を持ち、粘り気のある血液は弓や琴を作るための接着剤として最適だというが…。","note":"伝説の霊長に関する伝承","exp":"1020"}],"6874":[{"type":"中型生物","name":"コサックギツネ","rank":"2","desc":"中央アジアから東アジアにかけて生息する、キツネの一種。なわばりを持たず、移動しながら生活する習性を持つ。名前はロシア語での名称「コルサック」に由来している。","note":"発見物カード:175","exp":"370"}],"6927":[{"type":"天文","name":"エニフ","rank":"2","desc":"ペガスス座のイプシロン星。オレンジ色に輝く超巨星。2等星で、天馬の頭部にあたるところに位置する。名はアラビア語で「鼻」を意味するとされているが、記述は残されていない。","note":"発見物カード:165","exp":"330"}],"218":[{"type":"海洋生物","name":"ハリセンボン","rank":"1","desc":"警戒するとふくらんで多数の針が立つ魚。おそらくフグの仲間であろう。温暖な海でよく見られる。","note":"トゲのある魚の地図","exp":"13"}],"5081":[{"type":"港・集落","name":"セイラ","rank":"1","desc":"アラビア半島の対岸、アフリカ東北部側にある港町。アデン湾から紅海へ向かう途中に位置する。","note":"到達する","exp":"124"}],"429":[{"type":"大型生物","name":"ヌー","rank":"1","desc":"アフリカに広く分布するウシのような動物。大移動をすることがあり、このときは群れが合流して数十万を超える。","note":"牛の群れの地図","exp":"30"}],"6565":[{"type":"地理","name":"ミシガン湖","rank":"5","desc":"北米大陸北東部に位置する湖のひとつ。世界で第五位の面積を誇る広大な湖である。海峡を隔てて隣接しているヒューロン湖とは、水面の高さが一致しているため、同じ湖という見方もできる。","note":"追究クエスト","exp":"1040"}],"1650":[{"type":"地理","name":"ニューカレドニア島","rank":"2","desc":"オーストラリアの東にある細長い島。周囲はサンゴ礁で覆われており、島の内陸部は山がちで、丘陵となっている。気候は穏やかで、島には白檀が自生しているため、商人の注目を集めそうだ。","note":"知られざる島","exp":"330"}],"6597":[{"type":"歴史遺物","name":"センナケリブの六角プリズム","rank":"5","desc":"新アッシリア帝国の王センナケリブ自身が刻んだ碑文で、王宮の庭園などを含めた建設事業と軍事に関しての治世が記録されているという。当初は円筒型のものが使われていたがより多くのことを刻むため角柱型になったといわれる。","note":"レガシー伝説の王都バビロン　右上","exp":"2250"}],"3731":[{"type":"財宝","name":"ウルガ","rank":"5","desc":"モンゴルの伝統的な生活道具。\n長い棒の先に輪にした縄をつけたもので、小型のウマなどを捕えるために使う。","note":"草原地帯の生活道具","exp":"1045"}],"5108":[{"type":"港・集落","name":"ハバナ","rank":"2","desc":"カリブ海のキューバ島北西岸に位置する街。天然の良港で、カリブ特有の産物が流通するほか、良質のタバコが扱われている。","note":"到達する","exp":"238"}],"5074":[{"type":"港・集落","name":"ジャカルタ","rank":"2","desc":"ジャワ島北西岸に位置する街。もとは「スンダ・クラパ」と呼ばれた、スンダ人の小さな集落だった。スンダ人はパジャジャラン王国を築き、マジャパヒト王国の侵攻にも屈しなかった。","note":"到達する","exp":"305"}],"6891":[{"type":"レリック","name":"古の交易都市へと続く道","rank":"","desc":"華南には東西交易によって繁栄を極めた、長安という都市があった。そこへと続く道には、様々な国の商人が行き交っていたという。","note":"","exp":""}],"2902":[{"type":"植物","name":"ホウサイラン","rank":"4","desc":"台湾島まで至る中国南部地方で自生している植物。一月から二月に咲き、正月の床飾りなどに使われる。\n観賞用としても評価が高く、上流階級の人々に好まれた。","note":"高貴な人への贈り物","exp":"640"}],"1953":[{"type":"植物","name":"ビカクシダ","rank":"1","desc":"森林で、木の幹から生えている奇妙な植物。シカの角のように枝分かれした葉を持つ。病気になった葉かと思われたが、根で張り付いているので違う植物だと判明した。","note":"奇妙な形の植物の地図","exp":"170"}],"5395":[{"type":"歴史遺物","name":"クレタ島の陶器","rank":"1","desc":"古代のクレタ島で作られたとみられる陶器。風化のせいで色が薄くなってはいるが、よく見ればウシの絵が描かれているのがわかる。","note":"","exp":""}],"3009":[{"type":"化石","name":"模様のある石","rank":"1","desc":"石の表面に六角形の模様が多数見られる、巨大な石。この石が発見される所では石炭も出てくるというが、なにか関係があるのだろうか？","note":"奇妙な石の地図","exp":"160"}],"1042":[{"type":"地理","name":"アラビア海","rank":"1","desc":"インドとアラビア半島の間の海域。ペルシャ湾や紅海とつながり、インドとアラビア、アフリカの交易の舞台である。古くから栄えている海域で、航行する船が非常に多い。","note":"洋上の交易路","exp":"160"}],"5088":[{"type":"港・集落","name":"タコマ","rank":"2","desc":"港町として栄える北米西部の街。街の東部に広大な森林が広がっており、製材業が盛んである。","note":"到達する","exp":"310"}],"80":[{"type":"美術品","name":"最後の審判（ヴァザーリ）","rank":"1","desc":"ジョルジョ・ヴァザーリ作の天井画。キリスト教の最後の審判の様子が生々しく描かれている。ヴァザーリは絵だけでなく、文筆家としても知られている。","note":"ヴェネツィア教会の天井画","exp":"80"}],"1047":[{"type":"財宝","name":"竜殺しの紋章","rank":"2","desc":"竜を討つ伝説で知られる勇者ゲオルグの末裔の家に伝わる紋章旗。帆布に染め抜いて掲げれば、さぞ勇壮な眺めになることだろう。","note":"竜殺しの紋章<br/><br/>発見時経験値350　発見物カード経験値175","exp":"350"}],"5266":[{"type":"レリック","name":"アトランティスの落日","rank":"","desc":"","note":"","exp":""}],"3690":[{"type":"宗教遺物","name":"ボリスとグレブの聖像","rank":"4","desc":"後に聖人となったキエフ大公国の2人を描いた絵画。異教徒の兄による圧迫に屈することなく、キリスト教信仰を貫いた彼らを敬う者は多い。","note":"聖人列伝の異説","exp":"760"}],"5377":[{"type":"港・集落","name":"アクロポリス","rank":"3","desc":"伝説の地アトランティスの首都。円を基本とした造りで、周囲には運河が掘られ、高い城壁で守られた難攻不落の要塞都市である。","note":"到達する","exp":""}],"1427":[{"type":"歴史遺物","name":"カック・シフの武具","rank":"3","desc":"テオティワカンの将軍で、ムトゥプルを勢力下に置くことに関わった、カック・シフが使用していたといわれる武具。","note":"火の眠る場所","exp":"506"}],"2327":[{"type":"財宝","name":"枕草子","rank":"4","desc":"平安時代に清少納言が著した随筆。四季折々の自然や、宮中での行事、人間模様などが題材となっている。\n機知に富んだ内容がつづられており、筆者の優れた感性が随所に表れている。","note":"四季折々の味わい","exp":"690"}],"2334":[{"type":"歴史遺物","name":"縄文土器","rank":"1","desc":"日本で発見された、縄目の模様が特徴的な土器。強度が低く、壊れやすい。\n土器を焼く技術が未発達だった時代に作られたものと思われる。","note":"古代の道具の地図","exp":"150"}],"5912":[{"type":"海洋生物","name":"オオホモラ","rank":"4","desc":"深海に生息する大型のカニ。一番後ろの脚が甲羅の上側に曲がっており、この脚で貝殻などを背負って身を守るという。","note":"","exp":"680"}],"7018":[{"type":"鳥類","name":"シュモクドリ","rank":"3","desc":"アフリカ南部の草原や水辺に生息する鳥。全身は褐色の羽毛で覆われている。頭部が鐘を叩く撞木のように見えることが名の由来とされる。巣作りには数千本もの枝を使い、完成までに一カ月以上かかるという。","note":"","exp":""}],"2681":[{"type":"美術品","name":"高麗仏画","rank":"3","desc":"高麗時代に多く描かれた仏教画。\nこの時代は、阿弥陀如来や楊柳観音、地蔵菩薩が流行したらしく、よく見かける。","note":"朝鮮の宗教画","exp":"530"}],"1296":[{"type":"植物","name":"シンビジューム","rank":"2","desc":"ギリシャ語で「船」と「形」の意。船に似た唇弁の形にちなむ。中心を包むように、たくさんの色の花を咲かせる。","note":"愛を感じる花","exp":"330"}],"3650":[{"type":"地理","name":"タイミル半島","rank":"4","desc":"北極海に大きく突き出た半島。半島の中央を山脈が走り、その東西の低地を河が流れる。永久凍土であるが、人が生活していた形跡がある。","note":"北東航路の目印","exp":"790"}],"1721":[{"type":"海洋生物","name":"カウアイ","rank":"1","desc":"アオテアロアの近海に生息する魚。スズキとサケの合いの子のような姿をしている。大きいものは全長で90cm程になる。身は厚く脂がのっていて美味。","note":"釣り","exp":"160"}],"5089":[{"type":"港・集落","name":"タマタブ","rank":"1","desc":"マダガスカル島の東部に位置する街。島は山がちで、耕作の規模は小さい。しかし鉱山資源が豊富で、特に宝石の鉱脈が豊かである。","note":"到達する","exp":"80"}],"5756":[{"type":"地理","name":"コンクリーション","rank":"5","desc":"巨大な球場の岩石。生物の死体の周りに様々な物質が集まり、このような形を形成したようだ。なぜそのような現象が起こるのかは不明である。","note":"「球場」は「球状」の間違いかもしれませんが、原文まま。<br/>→修正されました。","exp":"1400"}],"720":[{"type":"美術品","name":"受胎告知（アンジェリコ）","rank":"1","desc":"フラ・アンジェリコ作の祭壇画。鮮やかな色彩で描かれたこの絵は作者の敬虔な信仰心を如実に表している。アンジェリコの名は通称で、穏やかな修道僧であった彼を「天使のようだ」と表現したものだそうだ。","note":"清楚な絵","exp":"100"}],"1529":[{"type":"虫類","name":"オオツチグモ","rank":"1","desc":"赤と黒の毛が生えた巨大なクモ。敵から身を守るとき、腹部の毛を逆立てる。","note":"巨大なクモの地図","exp":"105"}],"6482":[{"type":"小型生物","name":"ファイアサラマンダー","rank":"5","desc":"ヨーロッパの比較的高地で見られる、まだらが黄色いイモリ。毒腺を持っており、そこから発せられる毒が火を思わせることから、四大元素の火を司る精霊サラマンダーの名を冠している。","note":"","exp":"1000"}],"2978":[{"type":"鳥類","name":"ハクトウワシ","rank":"5","desc":"新大陸に生息する大型のワシ。広げると成人男性の背丈ほどにもなる立派な翼を持つ。\n濃茶色の羽毛とは対照に頭部が白いことが特徴。新大陸の先住民はこのワシを聖なる鳥として敬い、衣服や飾りにその羽を付けるなどして親しんでいる。","note":"畏怖と勇壮の大翼<br/><br/>発見時経験値1210　発見物カード経験値605","exp":"1210"}],"591":[{"type":"中型生物","name":"クロキツネザル","rank":"2","desc":"オスは黒、メスは赤や茶色、灰色の被毛をしている。ともに、耳に長い房毛がある。木々の間で果実などを食べる。","note":"黒い毛の生物","exp":"210"}],"1706":[{"type":"美術品","name":"トレドの風景","rank":"2","desc":"エル・グレコ作の風景画。風景画は絵画としての価値をあまり認められないものだが、この絵が素晴らしいことは誰の目にも明らかだろう。彼は誰の依頼によるものでもなく、自分の意思によってこの絵を制作した。暗く明るい、不思議な絵だ。","note":"風景画の地図","exp":"240"}],"69":[{"type":"中型生物","name":"インドレイヨウ","rank":"1","desc":"インドのレイヨウ。ウシに似ているがウシよりほっそりしている。ねじれた大きな角を持つ。","note":"インドの動物の地図","exp":"116"}],"1000":[{"type":"小型生物","name":"フクラガエル","rank":"2","desc":"主に地中に棲み、降雨のあとに姿を見せる。追いつめられると、体をぷくっと膨らませ、地面の中に入る。","note":"膨らんだ体","exp":"240"}],"3433":[{"type":"レリック","name":"ナスレッディン・ホジャ","rank":"","desc":"トルコに実在したといわれる、裁判官にして哲学者である賢者。多くの小話の主人公となっており、ユーモアに溢れる人物である。","note":"","exp":""}],"3432":[{"type":"レリック","name":"ハーメルンの笛吹き男","rank":"","desc":"ハーメルンの街から消えた笛吹き男と子供の伝承。\n伝承が示すものについては疫病など諸説あるが、東方への移民が真実らしい。","note":"","exp":""}],"5385":[{"type":"宗教遺物","name":"ビブリオテーケー","rank":"1","desc":"世界の起源からトロイ戦争までのギリシャ神話を系統立ててまとめた書物。ローマ神話の影響を受ける前の古いギリシャ神話が記されている。","note":"発見物カード:95","exp":"190"}],"6604":[{"type":"植物","name":"ヒルギダマシ","rank":"3","desc":"東アフリカや東南アジアの熱帯地域沿岸にマングローブ林として見られる常緑樹。塩分に強いため、乾燥して土壌の塩分濃度が高い紅海沿岸でも自生できると言われる。","note":"","exp":"500"}],"6547":[{"type":"虫類","name":"ディノポネラ","rank":"5","desc":"南米の熱帯雨林に生息する巨大なアリ。非常に獰猛な性格で、強力な顎と毒針を使ってさまざまな生物に襲いかかるといわれる。最強とされるパラポネラと同じか、それ以上に危険なアリといえよう。","note":"追究クエスト","exp":"1500"}],"2009":[{"type":"歴史遺物","name":"エストレラ号","rank":"2","desc":"ノッサ・セニョーラ・ダ・エストレラ号。\n大西洋のアセンション島北西で難破したポルトガルの東インド貿易船。","note":"サルベージ","exp":"280"}],"6413":[{"type":"歴史遺物","name":"ヴェルギナの黄金副葬品","rank":"4","desc":"","note":"マケドニアの遺跡の中<br/><br/>ゲーム内のlogより<br/>ヴェルギナの黄金の副葬品からヴェルギナの黄金副葬品<br/>へ修正しました","exp":""}],"6613":[{"type":"財宝","name":"プスケント","rank":"5","desc":"古代エジプトのファラオのみが身につけることを許された、紅白の冠。ファラオの二重冠とも呼ばれ、上エジプト、下エジプトの二つの冠を組み合わせて作られている。","note":"レガシー美の叡智　上","exp":"1800"}],"6591":[{"type":"歴史遺物","name":"竜骨車","rank":"5","desc":"低地から高地へと水をくみ上げるための揚水機。水田に水を引くために中国で発明された木製の農機具で、回転しながら移動する板が水桶の中の水を掻き揚げる。竜の骨格を思わせる見た目が、その名の由来だという。","note":"レガシー伝説の王都バビロン　右下","exp":"2250"}],"5857":[{"type":"財宝","name":"バラフォン","rank":"5","desc":"西アフリカ一帯で演奏される楽器。木琴の下に瓢箪を敷き詰めた独特な形状をしている。瓢箪の中には蜘蛛の巣やコウモリの羽が貼り付けてあり、振動を増幅させる効果がある。","note":"","exp":"1340"}],"7022":[{"type":"虫類","name":"ミカヅキツノゼミ","rank":"5","desc":"中南米の森林に生息するツノゼミの一種。植物の汁を主食とする。名のとおり、後方へ弓なりに伸びる三日月形の角が特徴。雌雄で角の形状が異なる。","note":"","exp":""}],"1498":[{"type":"虫類","name":"ウズマキタテハ","rank":"1","desc":"羽の裏面には、数字のような渦巻状の模様が入っている。色は、赤や水色など、まちまちである。","note":"奇妙な模様のチョウの地図","exp":"130"}],"2115":[{"type":"歴史遺物","name":"マルティネンガ号","rank":"3","desc":"ヴェネツィアの貿易船の一隻。イスタンブールからの帰路の途中、ボスポラス海峡付近で沈没した。","note":"サルベージ","exp":"490"}],"6208":[{"type":"大型生物","name":"バーバリライオン","rank":"5","desc":"アフリカ北部のアトラス山脈を中心に生息しているライオン。別名アトラスライオン。通常のライオンよりひと回り大きいうえ、たてがみが非常に黒く胴まで達する。その特異な容貌のため、古代から戦利品や見世物として乱獲されたという。","note":"王者の風","exp":"1350"}],"7034":[{"type":"大型生物","name":"ヤクート馬","rank":"4","desc":"シベリア東部に古くから生息する馬。極寒にも耐えられるよう、体毛は厚く長く密集している。体高は低く、短い四肢とがっしりした胴体が特徴。ひづめを使って雪を掘り、草を探して食べる。","note":"","exp":""}],"6260":[{"type":"歴史遺物","name":"カラフ","rank":"2","desc":"アイルランドに古代から伝わる獣皮船の一種で、カエサルやプリニウスなどの著作にも記述がある。船体にオークの樹皮でなめした革を張り、獣脂を塗りつけているのが特徴。\n一説ではブレンダンの航海に使われたのも同種の船だという。","note":"","exp":"310"}],"5605":[{"type":"海洋生物","name":"シノノメサカタザメ","rank":"2","desc":"インド洋とその周辺に生息する海洋生物。見た目や泳ぎ方はサメに似ているが、エイの一種とされる。頭部が幅広く扁平なのが特徴。","note":"","exp":"210"}],"6277":[{"type":"鳥類","name":"アゾレスウソ","rank":"2","desc":"アゾレス諸島のサン・ミゲル島東部にのみ生息してる鳥で、現地の住民からは「プリオロ」と呼ばれている。島の森林地帯を中心に生息しているが、ここ最近は移民たちの開拓の影響で数が減っているという。","note":"","exp":"340"}],"3152":[{"type":"財宝","name":"ライオンとクピドのカメオ","rank":"3","desc":"ロレンツォが収集していたカメオの一つ。ライオンと天使が彫られている。","note":"ロレンツォの収集品","exp":"540"}],"6416":[{"type":"宗教遺物","name":"魔王・ラーヴァナのレリーフ","rank":"5","desc":"ラーマーヤナに登場する魔王・ラーヴァナのレリーフ。羅刹の王であり、10の頭と20の腕を持っていたとされるラーヴァナと、ラーマ王子を助ける猿の神の軍勢が合戦をする場面を彫り込んだもののようだ。","note":"","exp":""}],"5696":[{"type":"天文","name":"トゥバン","rank":"4","desc":"りゅう座を構成する星の一つ。かつては北極星だったが、歳差運動の影響で北極星ではなくなった。","note":"クエスト「もう一つの北極星」<br/>発見物カード:315","exp":"630"}],"2895":[{"type":"財宝","name":"京劇服","rank":"4","desc":"「京劇」と呼ばれる中国の芸能で着用する衣装。民衆の間で発展した演劇「戯曲」が都で人気を博し、「京劇」と呼ばれるようになった。演目の題材には、三国志演義や水滸伝など、大衆に人気が高かったものが多い。","note":"芸能の新しい流れ","exp":"800"}],"3843":[{"type":"地理","name":"イーグルリッジ・ブラフ","rank":"3","desc":"北米西岸にある山の絶壁。岩壁ばかりでなく緑豊かな場所でもある。ハクトウワシの生息地でもあり、先住民からは聖地とあがめられている。","note":"絶壁の聖地","exp":"480"}],"745":[{"type":"美術品","name":"聖母子像","rank":"2","desc":"作者不詳の木像。シナノキで作られた聖母子像である。かつて南ドイツの教会にあったと伝えられる。聖母は足の下に三日月を踏んでおり、黙示録の「太陽をまとい、月を踏みしく」と表される女を指していると思われる。","note":"聖母子像","exp":"230"}],"6490":[{"type":"宗教建築","name":"在りし日のアルテミス神殿","rank":"5","desc":"エフェソスに建てられた大理石造りの巨大神殿。女神アルテミスを祀る。破壊や炎上で失われるたびに、より壮麗に再建されてきた。エフェソスのアルテミスは小アジアの大地母神の影響を受け、ギリシャ本土とは異なる姿や性格をもつ。","note":"レガシー　女神信仰の地エフェソス　中央","exp":""}],"6584":[{"type":"港・集落","name":"ヴィシャーカパトナム","rank":"1","desc":"インドの東海岸に位置する港湾都市仏教遺跡が数多く存在し、古代より仏教徒の巡礼が行われているマウリヤ朝のアショーカ王の庇護を受けて繁栄のちの統治者の変遷も、その街並みに面影を残している。","note":"(3801, 4068)","exp":"193"}],"6364":[{"type":"植物","name":"アスチルベ","rank":"1","desc":"主にアジアで咲く花。多年生植物で初夏に開花する。茎に沿ってふわふわとした花穂を咲かせる。花の色は赤、ピンク、白など。寒さに強く、湿った土で育ちやすい。","note":"","exp":"150"}],"2826":[{"type":"財宝","name":"辟邪像","rank":"4","desc":"読みは、「へきじゃぞう」。魔除けに使われる獣像。重慶の遺跡で発見された。\n辟邪とは、悪霊を追い払うと信じられた伝説上の獣のこと。","note":"ダンジョン","exp":"740"}],"6059":[{"type":"港・集落","name":"ガボン","rank":"1","desc":"アフリカ中部、大西洋のギニア湾に面する地域。豊かな森林に恵まれ、大型の哺乳類が多く生息している。様々な鉱物資源の産出地としても有名","note":"到達する","exp":"73"}],"6582":[{"type":"港・集落","name":"ヤンブー","rank":"1","desc":"紅海に面した港町。古代から地中海世界とエジプトなどを結ぶ。香辛料、香料の中継交易港として栄えた。街の北東は急峻な山々が広がっており、その景観は幻想的である。","note":"(1776, 3895)","exp":"172"}],"2482":[{"type":"史跡","name":"熱蘭遮城","rank":"4","desc":"読みは「ゼーランディアじょう」。ネーデルラント人が台湾島に築城した城砦。\n石材で築かれた堅固な城で、大量の船が停泊できる大きな港を擁していた。","note":"王城の過去","exp":"720"}],"1863":[{"type":"財宝","name":"金とトルコ石のペンダント","rank":"5","desc":"金とトルコ石を用いた簡素な作りのペンダント。トルコ石は神聖なものとして扱われていたので、このペンダントも儀式用に作られたのかもしれない。","note":"儀式と、お守りと","exp":"1100"}],"802":[{"type":"海洋生物","name":"ホラガイ","rank":"1","desc":"40cmにもなる、大きな巻貝。インドや東洋では、この貝殻を笛として使うそうだ。低い大きな音が出て、遠くまで聞こえるという。","note":"大きな貝の地図","exp":"59"}],"1102":[{"type":"大型生物","name":"キリン","rank":"2","desc":"アフリカのサバンナ地帯に生息する、背の高い動物。首が非常に長く、頭の高さは5mを超える。ほかの動物が食べられない高い枝の葉を食べているようだ。体には独特の模様があり、頭には短い2本の角がある。","note":"「首の長い動物の地図」<br/>発見物カード:155","exp":"310"}],"3187":[{"type":"地理","name":"ベルアイル海峡","rank":"3","desc":"北米大陸のラブラドル半島とテラ・ノヴァの間に位置する海峡。幅は平均して18km、最大でも60kmという非常に狭い海峡である。海流も強く、霧や強風などの悪天候にも見舞われる場所であり、航海の難所とされる。","note":"危険な海峡","exp":"530"}],"3380":[{"type":"史跡","name":"ラガシュ","rank":"3","desc":"古代メソポタミアにおいて栄えた、シュメール人の都市の一つ。隣国・ウンマの王であるルガルザゲシの征服によって衰退した。","note":"ウルに並ぶ都市国家","exp":"510"}],"2966":[{"type":"小型生物","name":"ワタオウサギ","rank":"2","desc":"尾が白く、綿のようになっていることからこの名がついたウサギ。逃げ足が速く、敵に襲われた時はジグザグに走り、その速度は時速30km以上にも及ぶ。","note":"クエスト「高速の毛玉」<br/>発見物カード:125","exp":"250"}],"6632":[{"type":"鳥類","name":"アフリカツリスガラ","rank":"4","desc":"アフリカ原産の鳥。樹木に袋状の柔らかい巣を作ることが名前の由来。捕食者を欺くため、本当の入口とは別に、本物より本物らしい見せかけの入口を作る。まさに天敵が多い鳥の知恵である。","note":"","exp":"660"}],"1540":[{"type":"歴史遺物","name":"アチャ","rank":"2","desc":"石に顔料を塗布したもの。古代の球技「トラチトリ」に用いられたらしい。","note":"競技道具の地図","exp":"245"}],"3673":[{"type":"歴史遺物","name":"古代エジプトの医学書","rank":"4","desc":"ヒエラティックと呼ばれる書体でパピルスに記された医学書。ミイラ製作で知識を得たためか、古代エジプトの医療技術は非常に優れていたといわれ、ギリシャやローマの文献でも紹介されている。","note":"ダンジョン","exp":"780"}],"6275":[{"type":"伝承","name":"ロードス島の巨像","rank":"5","desc":"太陽神ヘリオスへの感謝の証として建造された大彫像。建造後、数十年後に地震によって倒壊したとされる。彫像の大きさは、像の親指を腕で抱えることはほとんどできず、指はあらゆる彫像よりも大きいとされる。","note":"伝承航路(リヴァイアサン)","exp":"1660"}],"5656":[{"type":"小型生物","name":"シャベルカナヘビ","rank":"4","desc":"ナミブ砂漠に生息しているトカゲ。砂漠の熱砂から身を守るため、脚を交互に持ち上げて休憩する習性がある。","note":"","exp":"680"}],"1886":[{"type":"歴史遺物","name":"サンタ・マリア号","rank":"4","desc":"探険家クリストバル・コロン一回目の航海で旗艦を務めたナオ。\n大西洋横断後の1492年クリスマスイブに、イスパニョーラ島の暗礁に乗り上げ、航行不能に陥った。","note":"サルベージ","exp":"636"}],"136":[{"type":"鳥類","name":"クジャク","rank":"2","desc":"オスの尾羽が非常に美しい、大型の鳥。飼われているクジャクの様子を見ると、ニワトリにかなり近いようだ。オスは尾羽だけでなく全身の羽が鮮やかで美しいが、メスはやや地味でかわいらしい。","note":"クエスト「クジャク牧場計画」<br/>発見物カード:180","exp":"360"}],"601":[{"type":"宗教遺物","name":"アヴェスター","rank":"1","desc":"ゾロアスター教の聖典である。原典はアレクサンドロス大王によって焼かれたが、その後再び編纂（へんさん）され、ササン朝の国教にされた。拝火教ともいい、死後の裁判、および終末の最後の審判などがある。","note":"再生された聖典","exp":"190"}],"1464":[{"type":"歴史遺物","name":"鄭和艦隊の船首像","rank":"4","desc":"鄭和が乗っていた明の船の船首像。記録では鄭和の船は宝船といわれる巨大なもので、その大きさはかのコロン提督やガマ艦隊の船とは比べ物にならないほどだという。この船首像を見る限り、その話はあながち嘘でもないようだ。","note":"クエスト「鄭和の船の大きさ」<br/>発見物カード:372","exp":"744"}],"3793":[{"type":"天文","name":"カペラ","rank":"4","desc":"ぎょしゃ座で最も明るい1等星で、冬のダイヤモンドの一角である黄色い星。星座図では御者が抱える雌山羊の心臓に位置する。古代バビロニアで暦を決めるのに利用されたといわれる。","note":"発見物カード:325","exp":"650"}],"5396":[{"type":"地理","name":"エトナ山","rank":"1","desc":"シチリア島北東部にある、ヨーロッパ最大の火山。非常に活発で、何度も噴火が記録されている。ギリシャ神話の怪物テュポンが封印された場所ともいわれている。","note":"","exp":"200"}],"6538":[{"type":"伝承","name":"サラマンダー","rank":"5","desc":"火の精。四大元素のうち、火をつかさどるとされる精霊。破壊と創造の二つの性質を備える。炎に包まれた女性の姿で現れるといわれるが、定かではない。その体内には恐ろしい毒があるが、上手く加工できれば強力な薬になるらしい。","note":"","exp":"1060"}],"1763":[{"type":"美術品","name":"ガッタメラータ将軍騎馬像","rank":"1","desc":"ガッタメラータとは12世紀後半から13世紀前半にかけて活躍した傭兵隊長である。ヴィスコンティ家との戦いでヴェネツィアを勝利に導くなど数々の軍功を上げた。この青銅像はその功績を讃え、ドナテッロによって作成されたものである。","note":"英雄の像の地図","exp":"140"}],"864":[{"type":"歴史遺物","name":"ピトハナ王の冠","rank":"4","desc":"ピトハナ王は息子のアニッタ王と共に、ヒッタイトの伝説上の高祖である。神の力を借りて、諸都市を支配下に置いたとされる。","note":"伝説の王","exp":"780"}],"5275":[{"type":"レリック","name":"クレタ聖刻文字の印章","rank":"","desc":"","note":"2016/06/04<br/>発見時経験値2410　発見物カード経験値なし","exp":"2410"}],"6799":[{"type":"史跡","name":"オファの防塁","rank":"5","desc":"ブリテン島に8世紀ごろに築かれたという土塁。小国が林立していた七王国時代、ウェールズからの侵攻と、領土防衛のため、マーシア国の王、オファが築いたとされる。","note":"発見物カード:420","exp":"840"}],"6716":[{"type":"虫類","name":"ハナカマキリ","rank":"2","desc":"東南アジアに生息するカマキリ。熱帯雨林を住処とする。その姿を活かしてランの花に擬態し、寄ってきた他の昆虫を食べて過ごす。","note":"クエスト「忍び寄る鋭い花」<br/>発見物カード:160","exp":"320"}],"5623":[{"type":"史跡","name":"ターヌムの岩絵群","rank":"2","desc":"ターヌムスヘーデという街で発見された、岩石線画の刻まれた平面岩。青銅器時代から鉄器時代にかの地で暮らした、人々の生活をうかがい知ることができる貴重なもの。","note":"太古の絵画","exp":"360"}],"147":[{"type":"歴史遺物","name":"ゲイボルグ","rank":"5","desc":"ケルト神話の英雄・クーフーリンが、影の国の女王・スカアハから授かった魔槍。クーフーリン自身も、誓約を破ったためこの槍に貫かれて命を落としたという。","note":"ゲイボルグ","exp":"1196"}],"1234":[{"type":"大型生物","name":"ピューマ","rank":"5","desc":"がっしりとした体と長い尾、そして金色の目を持つ。様々な環境に適応し、高い身体能力でネズミやウサギなどを捕食する。","note":"［勅命］[未知なる危険]","exp":"910"}],"1817":[{"type":"財宝","name":"金の腕","rank":"1","desc":"副葬用に作られたといわれている、金細工の腕。腕に鳥や獣のような模様、甲に戦士の模様があるなど、細工は非常に細かい。金細工の深い歴史の中で、技術が研ぎ澄まされた形跡がうかがえる。","note":"精巧な金細工の地図","exp":"160"}],"6287":[{"type":"鳥類","name":"ケレル","rank":"2","desc":"アオテアロア全土に生息しているハトの一種で、別名ウッドピジョン。半神半人の英雄マウイがこの鳥によく変身したという伝説が残る。体が大きく、果実を丸呑みするほど食欲旺盛だが、発酵が進んだ果実を食べて酔うこともあるとか。","note":"優雅な大食らい","exp":"320"}],"6879":[{"type":"植物","name":"ゴーストオーキッド","rank":"5","desc":"カリブ周辺にのみ分布するランの一種。葉を持たず木に着生して育つという珍しい特徴を持つ。6月から8月にかけて白い花を咲かせるが、開花している時季以外に発見することは至難の業である。","note":"発見物カード:605","exp":"1210"}],"5080":[{"type":"港・集落","name":"スラバヤ","rank":"2","desc":"ジャワ島北東岸に位置する街。マジャパヒト王国の支配下にあり、ヒンドゥー文化の黄金期を築いた。","note":"到達する","exp":"323"}],"2069":[{"type":"鳥類","name":"カンムリシロムク","rank":"3","desc":"バリ島の北西部にのみ生息する。羽毛は白く翼と尾羽の先端部のみ黒い。目の周囲は化粧をしたように鮮やかな青色でとても美しい。木の洞の中に枯れ草や小枝で巣を作り生活をする。","note":"青く化粧した鳥","exp":"500"}],"2604":[{"type":"宗教遺物","name":"媽祖像","rank":"3","desc":"読みは「まそぞう」。道教の女神像で、航海や漁業の守護神として信仰を集めている。\n大陸からの移民が台湾島に到着した際も、媽祖に感謝したといい、広く信奉されている。","note":"船乗りたちを見守る像","exp":"500"}],"930":[{"type":"史跡","name":"パフォス","rank":"1","desc":"キプロスの丘の上にある、古代ローマの遺跡である。建物跡やモザイクの壁画などが数多く残る。キプロスは、多くの文明が交錯した土地である。","note":"美の女神に捧げられた街","exp":"135"}],"2417":[{"type":"宗教遺物","name":"ジェド柱","rank":"2","desc":"「永遠の安定」を象徴する柱。古代エジプトの神・オシリスの背骨ともいわれる。\n再生の力を意味し、壁画や護符という形で表現されている。","note":"ダンジョン","exp":"385"}],"5035":[{"type":"港・集落","name":"カッファ","rank":"1","desc":"黒海北岸にある街。古くより交易都市として栄え、13世紀にはジェノヴァが黒海沿岸の拠点として支配。最近になってオスマントルコが占領した。トルコ絨毯も流通している。","note":"到達する","exp":"45"}],"2512":[{"type":"海洋生物","name":"ハナゴンドウ","rank":"2","desc":"温帯や熱帯の海に生息する生き物。他の生物などと衝突することで皮膚に引っかき傷が残る。\n傷が付いた個所は、花が咲いているように見えるため、ハナゴンドウ（花巨頭）と呼ばれる。","note":"傷だらけの海洋生物","exp":"320"}],"3784":[{"type":"天文","name":"宵の明星","rank":"1","desc":"夕暮れ時に西の空に明るく輝く惑星。古代ギリシャではヘスペロスと呼ばれた。","note":"視認","exp":"150"}],"2903":[{"type":"宗教遺物","name":"鎗金経箱","rank":"3","desc":"読みは「そうきんきょうばこ」。仏教の経典を収めるための箱。鎗金とは、漆器の装飾技法の一つ。この箱には経典が説く極楽の世界が描かれている。","note":"美装された経箱","exp":"520"}],"1546":[{"type":"地理","name":"クラレンス海峡","rank":"2","desc":"オーストラリア北部、アーネムランドとバサースト島、メルヴィル島の間にある海峡。熱帯の気候であり、付近は年間通して暑く、熱帯特有の暴風雨の被害も受けやすい。","note":"クエスト「眼前にある海峡」<br/>発見物カード:160","exp":"320"}],"1192":[{"type":"宗教遺物","name":"テスカトリポカ像","rank":"4","desc":"アステカ神話における夜の神。その名は「濁った鏡」という意味である。ケツアルコアトルとともに世界を作ったといわれるが彼を追い払い、一人で世界を治めるようになった。非常に美しい男の姿をしていたといわれる。","note":"アステカの夜の神","exp":"612"}],"5534":[{"type":"気象・現象","name":"月虹","rank":"1","desc":"通常の虹とは異なり、夜間の月の光によって生じる虹。月光は太陽光よりも弱いため、白みがかって見える。通常の虹と同様、降雨後の発生が多い。","note":"発見時経験値180　発見物カード経験値90","exp":"180"}],"1284":[{"type":"宗教遺物","name":"般若経","rank":"2","desc":"はんにゃきょう。多くの仏教経典の総称。般若とはサンスクリット語でプラジューナー、「悟りの智慧」を意味する。","note":"［勅命］[[ジャワ思想調査","exp":"340"}],"6412":[{"type":"史跡","name":"冥王の門","rank":"4","desc":"アポロン神殿の近くにある洞窟。「死の息」が吐き出され、中に入るものの命を奪うことから「冥王の門」や「地獄の門」と呼ばれる。足を踏み入れるとだんだんと苦しくなり、めまいがしてくるという。","note":"追究クエスト　発見物カード：370","exp":"740"}],"2253":[{"type":"地理","name":"ポンペイ島","rank":"3","desc":"「石積みの上」という意味を持つ小島。マングローブに覆われており、島の中央には山がそびえている。\n森の奥には、建築物のような岩が見える。","note":"クエスト「未発見の小島」<br/>発見物カード:235","exp":"470"}],"1781":[{"type":"美術品","name":"画家・彫刻家・建築家列伝","rank":"2","desc":"ジョルジョ・ヴァザーリによって記された芸術家の列伝。133人もの芸術家の生涯が綴られている。著者自身も絵画に建築にと多彩な才能を発揮した人物で芸術家の評価面においても信頼性が高い。美術史における一級の資料である。","note":"優れた芸術家たちの本","exp":"300"}],"3304":[{"type":"植物","name":"タイサンボク","rank":"3","desc":"北米の中南部を原産地とする花木。初夏に白い花を咲かせる。葉の表面は光沢がある緑色だが、裏は細かい毛に覆われており、茶色がかっている。","note":"モクレンに似た花木","exp":"500"}],"6639":[{"type":"財宝","name":"琥珀の埋葬品","rank":"5","desc":"琥珀をふんだんに使用して作った首飾り。ハルシュタット文明時代の墓から発掘された副葬品の一つ。貴族の持ち物ではないかと考えられる。","note":"レガシー商の叡智・財貨の交易路　右下","exp":""}],"1690":[{"type":"虫類","name":"キプリスモルフォ","rank":"5","desc":"強烈に輝く青い羽は、空飛ぶ宝石と言っても過言ではない。前羽から後羽にかけての白い帯も、華やかさを添えている。","note":"幻のチョウ","exp":"1020"}],"1487":[{"type":"虫類","name":"コロリンデシロチョウ","rank":"1","desc":"鮮やかな黄色が差した前羽が美しい。また、白い羽には、黄色で縁取られた黒い斑点が一つずつある。","note":"白いチョウの地図","exp":"80"}],"954":[{"type":"宗教遺物","name":"仏像","rank":"2","desc":"仏教で信仰されるさまざまな仏の姿を表した像である。仏は悟りを開いた釈迦をモデルにするので、衣だけの質素な姿が基本である。また、手足に法輪の模様があるなどの三十二相がある。","note":"仏教の開祖","exp":"290"}],"5271":[{"type":"歴史遺物","name":"祭壇のレリーフ","rank":"2","desc":"コパン遺跡で見つかった石製のレリーフ。コパンの歴代16人の王の姿が彫られている。初代から16代へ権威の象徴たる笏が手渡される様子を表す。","note":"コパン川北岸　再調査報酬","exp":"360"}],"593":[{"type":"鳥類","name":"シチメンチョウ","rank":"3","desc":"オスが1mを超える大型の鳥。頭部に羽がなく垂れ下がった肉があり独特の容貌である。興奮したりすると羽がない部分の色が変わる。ニワトリの仲間のようで、飼いやすく食用になる。","note":"黒くておいしい鳥","exp":"528"}],"5404":[{"type":"天文","name":"りゅうこつ座","rank":"3","desc":"全天で2番目に明るい星、カノープスを含む星座。ギリシャ神話に登場するアルゴ船の竜骨に例えられる。","note":"「天文学者の観測記録」<br/>発見物カード:220","exp":"440"}],"6215":[{"type":"歴史遺物","name":"カーリバンガンの印章","rank":"2","desc":"モヘンジョ・ダロ北東の地域で見つかる筒形の印章。インダス遺跡で見つかる印章に酷似している。特に牛の姿が刻まれており、この地域においても牛が重要な存在であったことがうかがえる。","note":"古代インドの遺物の地図","exp":"260"}],"2075":[{"type":"地理","name":"マラッカ海峡","rank":"2","desc":"マレー半島と、スマトラ島の間に横たわる海峡。東西交易において重要な通過点となるが海峡の幅は狭く、その上水深が非常に浅い。さらに、暗礁や浅瀬も多いため、航行には細心の注意が必要だ。","note":"勅命クエスト「[香料諸島方面進出の要衝」<br/>勅命代替クエスト「東国へ続く狭き道」<br/>発見物カード:160","exp":"320"}],"5539":[{"type":"気象・現象","name":"火球","rank":"2","desc":"流星が通常より明るく輝きながら移動する現象。発生後、稀に地表で残骸らしきものが発見される。","note":"紅海　セイラ南東　(1972.4235付近)<br/>星空　日没後すぐ　海面変化","exp":"150"}],"1707":[{"type":"宗教遺物","name":"ウィツィロポチトリ像","rank":"2","desc":"アステカの戦いの神であり太陽神でもある。東より現れ夜の闇を打ち消し、西にて没するが、また東より復活する。太陽の運行そのものであると、神話では伝えられている。","note":"メソアメリカの像の地図","exp":"220"}],"5096":[{"type":"港・集落","name":"ディヴ","rank":"1","desc":"アラビア海に面したインド西部の街。古代から存在したが、一度廃墟となり近郊に再建された。農業が盛んで各種作物が流通するほかエメラルドや生糸なども扱われている。","note":"到達する","exp":"173"}],"6864":[{"type":"天文","name":"セギヌス","rank":"3","desc":"うしかい座のガンマ星で、3等星。名は「うしかい座」を意味するギリシャ語が翻訳を経ることで変化した言葉と言われる。アラビア語で「守護者」を意味するハリスという別名もある。","note":"発見物カード:270","exp":"540"}],"451":[{"type":"美術品","name":"聖母戴冠（アンジェリコ）","rank":"1","desc":"フラ・アンジェリコ作の祭壇画の一部。名前は「天使のような」という意味で、死後にそう呼ばれるようになったという。非常に敬虔な修道士で、壁画や祭壇画を多く製作した。当時最先端の技術だった遠近法が取り入れらた作風。","note":"教会の宗教画の地図","exp":"40"}],"6026":[{"type":"歴史遺物","name":"ヒュパティアの著作","rank":"4","desc":"ローマ帝国末期の女性ヒュパティアの著作の断片。彼女は学術都市アレクサンドリアで優れた学者として活動したとされるが、暴徒化したキリスト教徒に殺され、その著作のほとんどが失われた。","note":"","exp":"720"}],"5745":[{"type":"地理","name":"クーンブ・アイスフォール","rank":"5","desc":"巨大な氷塊が散在する危険地帯。チョモランマに登頂する経路の一つであり登頂を目指すものは避けて通れない。ヒトに似た足跡が点々と残っているが、いったい誰の、いや、なんの足跡なのだろうか。","note":"","exp":"1510"}],"3696":[{"type":"虫類","name":"ドクイトグモ","rank":"2","desc":"中南米に生息する、強力な毒グモ。解毒薬はなく、自然に治癒するまで痛みに耐えるしかないという。","note":"毒グモの地図","exp":"340"}],"5196":[{"type":"港・集落","name":"長崎","rank":"2","desc":"九州北西部に位置する街。海岸線が複雑に入り組んでいるため、古くから港湾都市として発展してきた。\n東アジアやヨーロッパ諸国との交易も盛んな街である。","note":"到達する","exp":"350"}],"886":[{"type":"海洋生物","name":"イモガイ","rank":"1","desc":"一見ただの巻貝だが、猛毒を持つ。近くを通りかかった魚に向かって毒針を飛ばし、殺してエサにする。人間が刺されると高確率で死亡する。","note":"毒貝の地図","exp":"64"}],"557":[{"type":"歴史遺物","name":"トラヤヌス帝のレリーフ","rank":"1","desc":"トラヤヌス帝は五賢帝の一人で、ローマ帝国最大の版図を築いた。このレリーフは、戦勝記念に作らせたものと言われる。","note":"古代ローマ皇帝のレリーフ","exp":"70"}],"1235":[{"type":"宗教遺物","name":"鏡","rank":"2","desc":"黒曜石の平らな面を磨いて作った鏡。メソアメリカのシャーマンたちが、神々の国との交信するために用いたという。","note":"黒い大きな石","exp":"220"}],"3656":[{"type":"財宝","name":"イパーチー写本","rank":"3","desc":"15世紀に編纂された、『原初年代記』の写本のひとつ。\n原本だけでなく、その後に編纂された書物からも情報が追加されているようだ。","note":"別の原初年代記","exp":"550"}],"4974":[{"type":"美術品","name":"テセウスとミノタウロスの像","rank":"4","desc":"ギリシャ神話に登場する英雄テセウスがミノタウロスと戦う様を表した像。テセウスはアテネの危機を救うためクレタ島のクノッソス宮殿にある迷宮ラビュリントスに向かい、ミノタウロスを討伐したという。","note":"","exp":"740"}],"1947":[{"type":"化石","name":"二本足の小さなトカゲの骨","rank":"2","desc":"全長40cm程のトカゲの骨のような石。ただし後足が異様に長い。これほど後足が長い生物なら、四本足よりも、後足二本のみで移動したほうが早いのではないだろうか。","note":"奇妙な石の地図","exp":"220"}],"4850":[{"type":"史跡","name":"テペ・ガウラ","rank":"4","desc":"古代メソポタミアの考古遺跡。新石器時代から高アッシリア時代まで、幅広の年代の住居が残っている。また、ギリシア建築やイタリア建築にみられる付け柱とアーキボルトで裝飾された世界最古の神殿がある。","note":"ダ・ヴィンチ氏からのおつかい<br/><br/>発見時経験値760　発見物カード経験値380","exp":"760"}],"5545":[{"type":"海洋生物","name":"フレームエンゼルフィッシュ","rank":"2","desc":"太平洋の中部や西部に生息する魚。岩礁やサンゴ礁に住む。体は鮮やかで濃いオレンジ色をしており、黒い縦縞が入っている。","note":"","exp":"220"}],"4795":[{"type":"宗教遺物","name":"カナロア像","rank":"2","desc":"ハワイやポリネシアで広く知られる四大神の一柱。海神であるほかに魔法と冥界の神であるともいう。イカやタコの姿で現されることが多い。タンガロアとも呼ばれる。","note":"オセアニアの神像の地図","exp":"339"}],"7011":[{"type":"天文","name":"ロタネブ","rank":"5","desc":"いるか座で最も明るい4等星。アルファ星のスアロキンと同じく、天文学者のニコロ・カチャトーレのラテン語名「ベナトル」を逆から綴り名づけられた。","note":"ペルシャ湾視認","exp":""}],"5901":[{"type":"植物","name":"デス・カマス","rank":"5","desc":"新大陸の西部に分布する有毒植物。名前のとおり毒性が強く、少量でも口にすると臓器不全などに陥り死亡することがある。カマスという食用の植物に非常に似ているため、特に注意が必要。","note":"","exp":"1400"}],"613":[{"type":"中型生物","name":"オオヤマネコ","rank":"1","desc":"ヤマネコとしては大型で、体に斑点があり耳の先に飾り毛がある。かなり広い範囲で観察される。","note":"「山猫の地図」<br/>発見物カード:14","exp":"28"}],"6966":[{"type":"歴史遺物","name":"フロール・デ・ラ・マール号","rank":"4","desc":"名は「海の花」という意味を持つ、ポルトガルの商船。莫大な量の黄金とダイヤモンドをはじめとした宝石を積載していたが、ポルトガルへの帰還中、嵐によりマラッカ海峡で沈没した。","note":"","exp":""}],"5214":[{"type":"歴史遺物","name":"マニオの巨石","rank":"1","desc":"マニオと呼ばれる森の中にある高さ6.5mほどの巨大な立石。列石から離れ、ひっそりと佇む巨石にはただならぬ存在感と神秘性を感じる。","note":"","exp":""}],"492":[{"type":"歴史遺物","name":"ハトシェプスト女王の胸飾り","rank":"3","desc":"トトメス2世の妻で、古代エジプト初の女性ファラオ・ハトシェプストの胸飾り。彼女はファラオでいる間、男装していたという。","note":"古代エジプトの女王","exp":"484"}],"6345":[{"type":"地理","name":"ダマーヴァンド山","rank":"2","desc":"アジア最高峰の火山。美しい峰を持つ火山であることから、火を尊ぶゾロアスター教の聖典に登場し、山の地下深くに三頭竜アジ・ダハーカを幽閉したとされている。","note":"","exp":"270"}],"6551":[{"type":"歴史遺物","name":"ルーン文字の刀剣","rank":"5","desc":"ロンドン近くのテムズ川で発見された刀剣。ルーン文字の銘文や幾何学的な文様が刻まれたその刀身は、どこか神秘的で威厳のようなものを感じさせる。","note":"追究クエスト","exp":"1050"}],"5049":[{"type":"港・集落","name":"グアム","rank":"2","desc":"マリアナ諸島の最南端に位置するグアム島の街。高温多湿の常夏で年中海水浴ができる。また、マゼランは世界周航の折、この地を訪れている。","note":"到達する","exp":"370"}],"5994":[{"type":"地理","name":"ランズエンド岬","rank":"1","desc":"ブリテン島南西端の岬である。意味は英語で「地の果て」。細長い岬で対岸が見えないため、このように呼ばれるのだろう。","note":"地の果ての岬","exp":"20"}],"6685":[{"type":"宗教建築","name":"パドマナーバスワーミ寺院","rank":"5","desc":"インド南部トリバンドラムにあるヒンドゥー教の寺院。ヴィシュヌ神を祀っている。地下に莫大な宝が眠るといわれている。開かずの扉があり、ナーガの封印が施されているため選ばれし者が呪文を唱えなければ開けられないという。","note":"","exp":"1100"}],"5216":[{"type":"宗教遺物","name":"十字架の首飾り","rank":"2","desc":"キリスト教でよく見られる十字架の首飾り。かつてこの地に逃れた人々が身につけていたものだと思われる。太陽の光が届かないこの地下都市で中の人々はなにを祈っていたのだろうか。","note":"","exp":""}],"7008":[{"type":"海洋生物","name":"トラフザメの幼魚","rank":"3","desc":"トラフザメの幼魚は成魚と異なり、体色が黒く、白い縞模様がはっきり入っている。成長するにつれて体色は薄くなり、縞模様は斑点模様へと変化する。","note":"","exp":""}],"3692":[{"type":"歴史遺物","name":"ボナ・コンフィデンタ号","rank":"5","desc":"ロシア皇帝のイヴァン4世がイングランドに派遣した大使船団のうちの一隻。スカンジナビア半島の北西で沈没した。","note":"サルベージ","exp":"950"}],"5791":[{"type":"宗教遺物","name":"ジャブダルの像","rank":"5","desc":"蛇の神の像。シベリア地方に暮らすエヴェンキ民族の神話に登場する創造神のひとつ。マンモスの神が岩を積み上げて大陸を作り、この神が這いずり回って平らにしたという。","note":"蛇の創生神話","exp":"1370"}],"2667":[{"type":"財宝","name":"高麗青磁","rank":"2","desc":"高麗時代に多く作られていた青磁のつぼ。\nまるでひすいのような色合いが美しく、名品として扱われている。","note":"伝統ある青磁","exp":"380"}],"5291":[{"type":"史跡","name":"タッシリ・ナジェール","rank":"3","desc":"サハラの中央部にある台地状の山脈。侵食によってできた印象的な奇岩が並ぶ。洞窟内にはウシの群れやワニが描かれた岩がある。大昔の付近の様子を描いたと思われるが、現在の砂漠からは信じがたい風景である。","note":"","exp":"550"}],"487":[{"type":"宗教遺物","name":"リグ・ヴェーダ","rank":"2","desc":"ヒンドゥー教の聖典の一つ。神々への賛歌（リチュ）をまとめたもので、祭事にホートリ祭官が詠唱し、神々を招くといわれる。","note":"ホートリ祭官の聖典","exp":"390"}],"1443":[{"type":"中型生物","name":"カンガルー","rank":"5","desc":"最大の大きさを誇る有袋類。その大きさはワラビーの倍以上で、一度の跳躍で8m以上も移動する。群れで生活しオス同士はケンカをする。その際、太い尾で体を支えながらの蹴りが大きな武器となる。","note":"追跡再び","exp":"910"}],"2546":[{"type":"中型生物","name":"キョン","rank":"3","desc":"台湾島や中国東部に分布するイヌに似た鳴き声が特徴的な小型のシカ。目の近くに臭腺があり、閉じた目のように見えることから、四つ目鹿とも呼ばれる。","note":"四つ目鹿<br/><br/>発見時経験値480　発見物カード経験値240<br/>文化貢献度35","exp":"480"}],"6473":[{"type":"歴史遺物","name":"テオファネスの年代記","rank":"2","desc":"ビザンツ帝国の修道士テオファネスが9世紀初頭にまとめたとされる年代記。ロードス島の巨像の最期について記述がある。ギリシャ語で書かれ、のちにラテン語訳も作られた。現存しない当時の歴史書の引用もあり、貴重なものとされる。","note":"","exp":"280"}],"925":[{"type":"財宝","name":"ペルシャ風のつぼ","rank":"1","desc":"ペルシャ独特の文様が描かれた美しいつぼ。イスラム教では生き物の姿を描くことを避けるため、植物の文様が多い。","note":"美しいつぼの地図","exp":"57"}],"909":[{"type":"植物","name":"デージー","rank":"1","desc":"小さな花弁がびっしりと集まって咲く植物。分解して調べてみると花弁の一つ一つにおしべとめしべがあった。","note":"白い花の地図","exp":"11"}],"5473":[{"type":"中型生物","name":"オオアルマジロ","rank":"2","desc":"南米のサバンナや熱帯雨林に生息する動物。体長が70～100cmで、アルマジロの中で一番大きいといわれる。\n東部と背中は皮膚が硬質化した鱗甲板で覆われおり、他の部分も全部が硬い毛で覆われている。","note":"鎧に覆われた動物の地図<br/><br/>発見時経験値210　発見物カード経験値105","exp":"210"}],"2702":[{"type":"史跡","name":"昌徳宮","rank":"2","desc":"景福宮の離宮。\n他の宮は、威厳を示すため、人為的に地形を作って建てられることが多いが、この離宮は自然の地形に合わせて建てられている。","note":"もうひとつの宮殿","exp":"300"}],"5390":[{"type":"美術品","name":"サイクロプス像の頭部","rank":"1","desc":"ギリシャ神話に登場する単眼の巨人、サイクロプスの石像の頭部。ミュケナイ文明の遺跡には大きな石材を用いたものが多く、サイクロプスが積んだという伝説もある。","note":"","exp":""}],"1457":[{"type":"鳥類","name":"アカクサインコ","rank":"1","desc":"全身が鮮やかな赤で、頬と羽が青色の鳥。非常に目立つため、木の洞など安全な場所に巣を作る。","note":"赤い鳥の地図","exp":"140"}],"3942":[{"type":"天文","name":"わし座","rank":"1","desc":"ゼウスがトロイの王子ガニュメデスをさらう際、変身したワシが天に昇った姿とされる。星座図ではガニュメデスが姿を変えたとされるみずがめ座を、横から狙うワシの姿で描かれる。","note":"クエスト「ゼウスのしもべ」<br/>発見物カード:190","exp":"190"}],"405":[{"type":"中型生物","name":"ウンピョウ","rank":"4","desc":"全身に雲を浮かべたような模様と長い牙が特徴。樹上での生活に慣れており、通常は単独で行動する。","note":"危険な雲","exp":"720"}],"3168":[{"type":"財宝","name":"プラトンの手引き","rank":"3","desc":"ソクラテスの弟子プラトンが書いた哲学書。コジモの侍医であるマルシリオ・フィチーノによりラテン語に翻訳され、フィレンツェに広まった。","note":"思想の議論","exp":"480"}],"1856":[{"type":"地理","name":"ワイナピチュ","rank":"5","desc":"マチュピチュの北側にそびえる峰。マチュピチュが「年老いた峰」を意味するのに対し、ワイナピチュは「若い峰」を意味している。同様にマチュピチュには太陽神を奉る神殿があり、ワイナピチュには月の神を奉る神殿があるという。","note":"危険な若い峰","exp":"1110"}],"5866":[{"type":"天文","name":"みずへび座","rank":"5","desc":"南天の星座の一つ。16世紀に作られた。うみへび座と同じくラテン語で「水蛇」を意味する単語で名づけられたが、みずへび座は男性系、うみへび座は女性形という違いがある。\n\n※男性系と女性形の表記は原文ママ","note":"クエスト「うみへびとみずへび」<br/>発見物カード:700","exp":"1400"}],"2823":[{"type":"歴史遺物","name":"高句麗王碑文","rank":"2","desc":"高句麗の王、長寿王の手によって建てられたとされる石碑。石碑には長寿王の父親である第19代高句麗王・広開土王の業績が記されている。","note":"国王の石碑","exp":"330"}],"5465":[{"type":"海洋生物","name":"トゥクナレ","rank":"1","desc":"アマゾン川や、その支流で生息する魚。\n尾びれの付け根にある目玉模様からピーコックバスとも呼ばれる。\n現地では食用としてよく利用されている。","note":"経験　:120<br/>カード:60","exp":"120"}],"280":[{"type":"歴史遺物","name":"セレウコス1世の大理石像","rank":"1","desc":"アレクサンドロス大王の参謀にして、セレウコス朝シリア王国の建国者、セレウコス1世の大理石像。","note":"ヘレニズムの王","exp":"65"}],"5700":[{"type":"化石","name":"海の生物の化石","rank":"5","desc":"チョモランマで発見された、海の生物の模様を含んだ石。山の上でこのような石が多数見つかる理由は、いまだ解明されていない。","note":"2017.02.07新規追加","exp":"950"}],"6777":[{"type":"財宝","name":"納め太刀","rank":"4","desc":"木製の大太刀。大山詣りに使われた。源頼朝が刀を奉納した故事に由来し、願い事を書いた木太刀を神社に奉納する行事。商売繁盛、勝負運のご利益があるという。江戸からの参拝客で宿場町が繁盛するという。","note":"","exp":"800"}],"645":[{"type":"地理","name":"コスメル島","rank":"1","desc":"カリブ海西部に浮かぶ島。非常にサンゴ礁が美しい島で、熱帯魚もよく見られる。海の透明度は30mを超え、この世の天国のようだ。","note":"書きかけの地図","exp":"180"}],"3592":[{"type":"レリック","name":"太陽神アテン","rank":"","desc":"アテン神信仰がもたらした自由で写実的なアマルナ美術は、固定化されつつあった古代エジプト芸術に新たな息吹を吹き込んだ。","note":"","exp":""}],"2565":[{"type":"鳥類","name":"オウチュウ","rank":"2","desc":"台湾島や中国などの、農耕地や市街地に生息する黒い鳥。長い尾の先が、逆Ｙ字のように割れているのが特徴である。","note":"尾が割れた鳥の地図","exp":"260"}],"1642":[{"type":"地理","name":"セブ島","rank":"5","desc":"ルソン島とミンダナオ島の中間にある南北に細長い島。西回りで周航中のマゼランが、この島を拠点として活動した。マゼランはセブ島の東に位置するマクタン島の首長・ラプラプと交戦し、命を落とした。","note":"旅の終わり","exp":"1170"}],"6344":[{"type":"歴史遺物","name":"インディオの書簡","rank":"2","desc":"北米の先住民族がまとめた書簡。アンデス文明やインカ帝国についての歴史、植民政策に関する記録や考えが多くの挿絵とともに記されている。","note":"","exp":"260"}],"374":[{"type":"美術品","name":"レースを編む女","rank":"4","desc":"ヤン・フェルメール作の絵画。縦が24cm足らずの小さな絵画でありながら、一心にレースを編む女性が見事に描かれている。女性の手元は精密に、それ以外はあえて不明瞭に描くことで緊張感を出している。","note":"画商が描いた絵画","exp":"624"}],"2773":[{"type":"宗教遺物","name":"カタコンベの石版","rank":"2","desc":"カタコンベの奥深くで見つかった謎の石版。文字が刻まれているようだが、表面の傷みが激しいため、解読は不可能なようだ。","note":"ダンジョン","exp":"330"}],"6838":[{"type":"美術品","name":"パッツィの聖母","rank":"3","desc":"ルネサンス期イタリアの彫刻家ドナテッロの作。大理石に幼いキリストを抱く聖母マリアが彫られている。薄い繊細な彫り込みで、陰影の効果を利用し、奥行きや質感を表現している。","note":"発見物カード:205","exp":"410"}],"5151":[{"type":"港・集落","name":"マスカット","rank":"1","desc":"ペルシャ湾とアラビア海の間に位置する街。古代から重要な港で、交易の中心地として栄え続けてきた。この地方独特の農産物のほかに、鉱石や武器も流通している。","note":"到達する","exp":"129"}],"1418":[{"type":"歴史遺物","name":"ヤシュ・ヌーンアインのレリーフ","rank":"2","desc":"テオティワカンがムトゥプルを勢力下に置いた際に、送り込まれたといわれている王のレリーフである。非常に大きなもので、一面にびっしりと描かれている。","note":"少年王の軌跡","exp":"210"}],"5798":[{"type":"宗教遺物","name":"仏歯","rank":"5","desc":"釈迦の歯とされている遺物。数ある仏舎利の中でも重要視されており、特に犬歯には強い力があるとして信仰されているようだ。","note":"仏舎利の一種","exp":"1360"}],"2653":[{"type":"鳥類","name":"キタタキ","rank":"3","desc":"朝鮮半島から中国、インドまで、広く生息するキツツキの一種。\n巨大な枯れ木に営巣する。頭頂部と頬の赤い羽毛が特徴的。また、上半身は黒、下半身は白と鮮やかな配色も目を引く。","note":"巨大な身体と声","exp":"460"}],"573":[{"type":"地理","name":"紅海","rank":"1","desc":"アラビア半島とアフリカの間に横たわる海域である。旧約聖書の出エジプト記にも記述がある。イスラエルの民を率いたモーゼが杖を差し出すと、紅海が二つに割れ、渡れたと伝えられる。","note":"紅い海","exp":"200"}],"2679":[{"type":"美術品","name":"安堅の水墨画","rank":"2","desc":"朝鮮の画家・安堅による水墨画。\n朝鮮王・世宗の三男である安平大君が夢に見たという桃源郷が、淡墨で描かれている。\n安堅は、この桃源郷をたった三日で描き上げたという。","note":"朝鮮の絵画を追え","exp":"310"}],"6114":[{"type":"財宝","name":"トンコリ","rank":"3","desc":"ロシア極東から日本の北部にかけての少数民族、樺太アイヌの間に伝わる五弦琴。平たい形状で先端が細くなっている。樺太アイヌの慣習に従って、楽器の各部分を人体の各部になぞらえて呼ぶという。","note":"","exp":"600"}],"3760":[{"type":"天文","name":"おうし座","rank":"4","desc":"黄道十二星座の1つ。ゼウスがエウロペに近づくために変身した牡牛とされる。古代メソポタミアでは天の牡牛と呼ばれていた。1等星アルデバランは牡牛の目にあたる。","note":"天の牡牛","exp":"720"}],"5047":[{"type":"港・集落","name":"クチン","rank":"2","desc":"カリマンタン島の中部西岸に位置する街。北東にあるブルネイを本拠地とするブルネイ王国の支配下にある。クチンは現地の言葉でネコを意味する。","note":"到達する","exp":"328"}],"1960":[{"type":"宗教遺物","name":"仏舎利","rank":"5","desc":"「ぶっしゃり」。仏教の開祖である釈迦（しゃか）の遺灰だと伝えられるもの。仏教における最高の聖遺物である。語源はサンスクリット語で「身体」を意味する「シャリーラ」である。","note":"仏教における聖遺物","exp":"1027"}],"1444":[{"type":"鳥類","name":"キーウィ","rank":"3","desc":"60cmほどの体に長いくちばしを持つ鳥。そのくちばしを使って、地中のミミズや昆虫を探す。口笛のような鳴き声から、その名が付けられた。","note":"毛のかたまり","exp":"462"}],"1942":[{"type":"宗教遺物","name":"インカ王族のミイラ","rank":"4","desc":"インカ帝国では、王族の遺体をミイラ化し、死後もその権威を保った。そのためインカ帝国では王への反乱は少なかったようだ。ミイラは生前と同様に衣服をまとい、食事が供せられ、他の王のミイラとの交流も行ったという。","note":"クエスト「インカ王族の眠り方」<br/>発見物カード:360","exp":"720"}],"722":[{"type":"歴史遺物","name":"金とラピスラズリの牡山羊","rank":"2","desc":"古代メソポタミアで作られた王族の副葬品。木像に、金やラピスラズリ、貝などで装飾が施されている。当時の豊かさがしのばれる。","note":"生と死の感覚","exp":"320"}],"5854":[{"type":"化石","name":"巨大な草食動物の化石","rank":"5","desc":"非常に巨大な四足歩行型の動物の骨。ユーラシア大陸の全域で化石が発見されており、研究が進められている。生態は謎に包まれているが、犬歯より切歯が発達しているため草食だったと思われる。","note":"","exp":"1420"}],"6054":[{"type":"財宝","name":"プロコピオスの戦史","rank":"3","desc":"東ローマ帝国の名将ベリサリウスに仕えた書記官であるプロコピオスの著作。\n当時の皇帝であったユスティニアヌス1世の治世や皇后テオドラの女傑ぶり、武将としてのベリサリウスの活躍などが記されている。","note":"","exp":"540"}],"3665":[{"type":"歴史遺物","name":"トトメス3世の年代記","rank":"5","desc":"古代エジプトの領土を大きく広げたファラオトトメス3世の事績を記したレリーフ。トトメス3世は度々シリア方面に遠征し、ミタンニ王国などと争い、戦利品や貢物をアメン神殿に寄進したという。","note":"ダンジョン","exp":"1080"}],"91":[{"type":"歴史遺物","name":"エジプトの壁画","rank":"1","desc":"古代エジプトの神殿や墓所などでよく見られる壁画。多くは美しく彩色された神聖文字で神やファラオの栄光を讃える内容である。","note":"エジプトの壁画の地図","exp":"33"}],"554":[{"type":"歴史遺物","name":"アウレリアヌス帝の兜","rank":"1","desc":"ローマ帝国衰退期の皇帝・アウレリアヌス帝の兜。名君でパルミラを始めとする反乱勢力をよく抑え、厳格な統治を行った。遠征中に暗殺されたという。","note":"古代ローマの復興者","exp":"95"}],"1013":[{"type":"歴史遺物","name":"隠者ピエールの杖","rank":"1","desc":"11世紀末、民衆十字軍の中でも最大規模の集団を率いた修道士ピエールの杖。2万人以上の民衆軍は統率が取れず、トルコ軍に敗れて瓦解した。","note":"クエスト「民衆による十字軍」<br/>発見物カード:30","exp":"60"}],"1977":[{"type":"小型生物","name":"バンディクート","rank":"1","desc":"ネズミのような外見で長い鼻を持つ有袋類。夜行性で、昆虫を捕食する。","note":"ネズミに似た動物の地図","exp":"135"}],"3184":[{"type":"地理","name":"ガスペ半島","rank":"2","desc":"セントローレンス川河口の南側に位置する半島。\n半島の南岸部では、古代の化石が多く発掘されている。","note":"書きかけの地図","exp":"260"}],"6939":[{"type":"天文","name":"シェアト","rank":"5","desc":"ペガスス座のベータ星白で、赤く輝く2等星。秋の四辺形を構成する星の1つ。名はアラビア語で「すね」を意味する。","note":"発見物カード:700","exp":"1400"}],"3627":[{"type":"植物","name":"ムラサキツユクサ","rank":"4","desc":"北米原産の多年草。主に夏に花を咲かせる。花は3花弁で、青っぽい紫色をしている。花に込められた言葉は、「ひとときの幸せ」。","note":"後悔のその先","exp":"720"}],"6030":[{"type":"財宝","name":"ブラヌス写本","rank":"2","desc":"ドイツのベネディクト会修道院に所蔵されていた中世の写本。ラテン語を始め、ヨーロッパ各地の古語で記された聖歌や世俗詩などが収められている。特に世俗詩は、文学的なものから風刺、性や酒、賭博といった内容のものまで多岐にわたる。","note":"ふさわしからぬ写本","exp":"370"}],"3826":[{"type":"植物","name":"ジンジャーリリー","rank":"3","desc":"夏の終わり頃に白い花を咲かせる植物。\n強いがすっきりとした芳香で香料としてもよさそうだ。","note":"夏の終わりの香り","exp":"500"}],"6162":[{"type":"財宝","name":"ピサ海図","rank":"2","desc":"13世紀にピサで製作されたといわれる最初期の羅針儀海図。港や海岸線を写実的に描いた航海用の地図であり、14世紀までの間にかけて盛んに製作された。他の羅針儀海図の例に漏れず、地球が球体であることを考慮していない作りが特徴。","note":"","exp":"240"}],"5639":[{"type":"気象・現象","name":"水上竜巻","rank":"3","desc":"洋上で発生する竜巻。強力な突風に加え、不規則な水の動きを生み出すために、まれに、船がまき込まれて沈没するといった災害も発生している。","note":"ラスパルマスの西側にある島の西端。<br/>曇り限定らしい。","exp":"519"}],"5528":[{"type":"気象・現象","name":"ハブーブ","rank":"3","desc":"アフリカ北部の砂漠地帯などで発生する巨大な砂嵐。ときには都市ひとつをのみ込むほどの大きさになる。移動が速く、発見した際には屋内への迅速な避難が求められる。","note":"サハラの川沿いの向こう側に砂嵐があられる現象。<br/>川沿いの場所は砂嵐が起きません。","exp":"220"}],"1481":[{"type":"財宝","name":"水晶髑髏","rank":"5","desc":"総水晶製のドクロ。いつ、どこで作られたのか、全くの謎に包まれている。水晶は硬いため、研磨が難しいとされている。もし、この技術が既に失われているとしたら、非常に残念なことだ。","note":"死者の見る夢","exp":"1183"}],"2246":[{"type":"小型生物","name":"ヨウガントカゲ","rank":"2","desc":"ガラパゴス諸島の島々でよく見られる小型のトカゲ。島ごとに見た目が少しずつ違う。\n雄のほうが体が大きく雌は喉の周りが鮮やかな赤色をしているのが特徴である。","note":"真っ赤な顔のトカゲ","exp":"140"}],"546":[{"type":"歴史遺物","name":"宝石細工の装身具","rank":"1","desc":"さまざまな宝石をあしらった装身具。古代文明では、宝石には不思議な力が備わっていると考えられ、護符の意味もあった。","note":"古代の宝石細工の地図","exp":"67"}],"549":[{"type":"歴史遺物","name":"古代のレバノン杉","rank":"1","desc":"古代の中近東からペルシャにかけてよく使われていた木材。質がよく、建造物や船などに多用されていた。乱伐のため、現在ではほとんど見られない。","note":"古代ペルシャ遺物の地図","exp":"35"}],"5328":[{"type":"地理","name":"オカヴァンゴ川","rank":"2","desc":"アフリカ南西部の乾燥地帯を流れる川。海に流れ込まない内陸河川で、下流で巨大な湿地を形成する。流域の生物にとっては貴重な水源となっている。","note":"","exp":""}],"5231":[{"type":"財宝","name":"星界の報告","rank":"2","desc":"ガリレオ・ガリレイが出版した最初の書籍。望遠鏡の仕組みや作成方法から月を始めとした天体観測の結果が記されている。美しい文体でも知られ、ガリレオの詩才を遺憾なく発揮した一作である。","note":"クエスト「ガリレオの著作」<br/>発見物カード:180","exp":"360"}],"1747":[{"type":"財宝","name":"ワレル・ダンマタ","rank":"2","desc":"ペグー朝・ワレル王が編さんした、インドシナ最古の法典。非常に分かりやすく整えられた文章で現在にも影響を及ぼしている。","note":"古代の法典の地図","exp":"315"}],"2426":[{"type":"鳥類","name":"タンチョウ","rank":"2","desc":"東アジアの湿原に生息する鳥。一部は人里近くで越冬する。\nほっそりとした白地の体に、黒と赤の二色が映えている。その上品な姿は、東洋の美術品にも多く見られる。","note":"気品ある鳥の地図","exp":"270"}],"2530":[{"type":"小型生物","name":"セマルハコガメ","rank":"1","desc":"淡水付近に生息する、甲羅が大きなドーム状に盛り上がっているカメ。背甲と腹甲の隙間を完全に閉じることができる。頭部の色は褐色や暗緑色など、多くの種類が存在する。","note":"黄色いカメの地図","exp":"200"}],"5905":[{"type":"美術品","name":"大聖堂のステンドグラス","rank":"5","desc":"とある聖人の生涯を描いた一連のステンドグラス。その数は何十とあり、聖堂の内側を飾っている。","note":"","exp":"1370"}],"2708":[{"type":"財宝","name":"百済王の勾玉","rank":"3","desc":"百済の遺跡で発見された勾玉（まがたま）。豪華な装飾が施されているため、とても目を引く。","note":"ダンジョン","exp":"500"}],"5008":[{"type":"地理","name":"クレタ島","rank":"2","desc":"エーゲ海の南に位置する、ギリシャ地方最大の島。クレタ文明が栄え、クノッソス宮殿など多くの遺跡が残っている。","note":"「書きかけの地図」<br/>発見物カード:155","exp":"310"}],"4816":[{"type":"海洋生物","name":"ヌタウナギ","rank":"2","desc":"ウナギのような体をした魚だが、目らしきものがほとんど見あたらない。エラ穴が七つあり、ヤツメウナギの仲間と思われる。襲われるとヌタと呼ばれる粘液を出して身を守る。","note":"釣り","exp":"350"}],"64":[{"type":"宗教遺物","name":"ウシャス像","rank":"1","desc":"古代インドの女神の像である。真紅の衣と金色のヴェールをまとった、暁の女神。リグ・ヴェーダでもっとも美しいとされ、太陽神・スーリヤの妻である。","note":"インドの女神像の地図","exp":"150"}],"1906":[{"type":"宗教遺物","name":"七十人訳聖書","rank":"3","desc":"ヘブライ語からギリシャ語に訳された聖書の総称。アレクサンドロス大王の遠征によってヘブライ語を習得していないユダヤ人が増加したため、聖書のギリシャ語訳が始まったと言われている。","note":"万人のための聖書","exp":"600"}],"465":[{"type":"宗教遺物","name":"アレス像","rank":"1","desc":"ギリシャ神話の軍神の像である。ローマ神話ではマルス。美と愛の女神・アフロディテの愛人で、間に何人かの子をもうけている。","note":"軍神の像","exp":"90"}],"5016":[{"type":"港・集落","name":"アビジャン","rank":"1","desc":"象牙海岸沿岸の港。周辺地域の産物が集まり栄えている。ヤシや木材のほか、象牙が産物として扱われている。","note":"到達する","exp":"68"}],"1578":[{"type":"植物","name":"ブルー・オーキッド","rank":"4","desc":"青紫色の大きな花。太陽を好み、砂漠でも花を咲かせる。","note":"愛しき妻へ","exp":"624"}],"3745":[{"type":"天文","name":"北斗七星","rank":"2","desc":"7つの星がひしゃくの形を作る、北斗星の目印として有名な星列。2等星が6つ、3等星1つと明るい星が多く、見つけやすい。世界各地で様々な神話が作られている。","note":"クエスト「北極星とひしゃく」<br/>発見物カード:185","exp":"370"}],"6700":[{"type":"地理","name":"東尋坊","rank":"5","desc":"","note":"追究クエスト","exp":""}],"1448":[{"type":"中型生物","name":"フクロオオカミ","rank":"5","desc":"オオカミに似た肉食の有袋類。カンガルーやウォンバットなど大型の哺乳類を捕食する。","note":"袋を持った捕食者","exp":"936"}],"7029":[{"type":"地理","name":"ダードル・ドア","rank":"4","desc":"ブリテン島南部の海岸にある、アーチ状の巨大な石灰岩。長い時間をかけて海水が岩を侵食し、このような形になったと考えられている。遠景では、巨大なドラゴンが海の水を飲んでいる姿に見える。","note":"","exp":""}],"3164":[{"type":"地理","name":"モナドノック","rank":"4","desc":"北米にある平坦な山。「モナドノック」とは平坦な山を意味する、北米の先住民の言葉に由来しているという。","note":"クエスト「山の意味」<br/>発見物カード:335","exp":"670"}],"3733":[{"type":"歴史遺物","name":"王の弔文","rank":"4","desc":"古代エジプトのファラオ・ラムセス2世が妻のネフェルタリに贈った弔文。深い悲しみの言葉が綴られており、ラムセス2世の愛の深さが読み取れる。","note":"ダンジョン","exp":"680"}],"6185":[{"type":"伝承","name":"燃える柴","rank":"5","desc":"神がみずからの領域を示すために、時折人に見せるという現象。創世記ではケルビムに持たせたという「回る炎の剣」、出エジプト記では「燃える柴」と神の使いに関する記述があり、神が示す境界線として炎が用いられる例は多い。","note":"禁域に関する伝承","exp":"1480"}],"4955":[{"type":"天文","name":"ペガスス座","rank":"3","desc":"ギリシャ神話に登場する天馬・ペガサスが天に上った姿とされる星座。比較的明るい星が多く、ヨーロッパでは秋の代表的な星座とされる。","note":"クエスト「天満の誕生とその後」<br/>発見物カード:255","exp":"510"}],"1780":[{"type":"歴史遺物","name":"市民冠","rank":"2","desc":"古代ローマの報奨制度のひとつで、ローマ市民の命を救ったものが与えられる冠。他の栄誉で与えられる冠は金であったが、最高位である市民冠はオークの葉で作られていた。この栄誉に預かったもののみ金属製の市民冠を作ることが許された。","note":"ローマ市民を救った証","exp":"350"}],"1532":[{"type":"歴史遺物","name":"鄭和の航海誌","rank":"2","desc":"明の提督・鄭和の航海誌。鄭和は七度航海を行い、アフリカからキリンを持ち帰るなどした。この航海誌は散り散りになったものの一部で、内容を全て把握することはできない。","note":"鄭和の航海誌 / 香料諸島方面進出の指標(勅命クエ)","exp":"360"}],"2425":[{"type":"海洋生物","name":"イトウ","rank":"3","desc":"日本最北部の河川に棲む淡水魚。サケのように海へ降る。\n日本の淡水域に生息する魚類の中で最も大きくなるといわれ、魚はいうまでもなく、ヘビやネズミまでも食べてしまう。","note":"釣り","exp":"510"}],"2871":[{"type":"海洋生物","name":"ワラスボ","rank":"1","desc":"中国や朝鮮などに生息する、細長く青紫色の体をした生物。\n生まれたばかりのころは正常な目を備えているが、成長と共に退化し、皮膚の下に埋もれてしまう。","note":"不気味な魚の地図","exp":"190"}],"5610":[{"type":"天文","name":"いて座の鳥型の星雲","rank":"4","desc":"いて座にある散光星雲のひとつ。不規則な形をしている。明るい星雲であり、比較的観測しやすい。","note":"発見物カード:355","exp":"710"}],"1592":[{"type":"植物","name":"マリーゴールド","rank":"1","desc":"強い香りのする、黄色い花を咲かせる。その鮮やかな花は、染料としても用いられる。","note":"黄色い花の地図","exp":"100"}],"6202":[{"type":"史跡","name":"マダラの騎士像","rank":"4","desc":"ブルガリア北東部にある、マダラ高原の崖に刻まれた巨大なレリーフ。周りに足場のない高さに刻まれているという特色がある。周囲に古いギリシャ語の銘文があるため、かつてこの地を支配したブルガール人が作ったという説がある。","note":"草原の民の足跡","exp":"630"}],"6507":[{"type":"財宝","name":"シリンダーオルゴール","rank":"2","desc":"ゼンマイを巻くことで音楽を再生することができる自動演奏装置。回転するシリンダーに埋め込まれたピンが櫛歯を弾くことによって音を出す。シリンダーを入れ替えることで様々な曲を演奏することが可能。","note":"","exp":"350"}],"1465":[{"type":"歴史遺物","name":"古代の釣り針","rank":"3","desc":"沿岸に居住していた先住民族が使っていたと思われる釣り針。木を研いで作られており、海水の中で使用したため腐食が激しいが、状態よく残っているものもある。彼らは木をうまく利用してきた民族といえよう。","note":"南の大陸における暮らしぶり","exp":"473"}],"5839":[{"type":"美術品","name":"クラダリング","rank":"5","desc":"アイルランドのクラダ村出身の若者が作った指輪。ハート、両手、王冠がデザインとして使われている。","note":"","exp":"1410"}],"6219":[{"type":"財宝","name":"北方民族文化誌","rank":"1","desc":"16世紀のスウェーデン人司教、オラウス・マグヌスが記した北欧文化地誌。北欧各地の生活文化・自然・伝承などの情報が記されている。全22巻で情報量も多く、挿絵として481点の木版画が添えられている。","note":"","exp":"200"}],"1358":[{"type":"大型生物","name":"マレーバク","rank":"4","desc":"白と黒の二色に染まった体色が特徴。沼沢地の水辺でいろいろな植物を食べる。子供には白い縞模様がある。","note":"釈迦の乗る動物","exp":"624"}],"5829":[{"type":"財宝","name":"ギガス写本","rank":"5","desc":"ラテン語で書かれた聖書の写本。確認されている限り世界最大の写本であり、悪魔が製作に手を貸したとの噂もある。","note":"","exp":"1470"}],"2249":[{"type":"海洋生物","name":"ベニイワガニ","rank":"2","desc":"ガラパゴス諸島の海岸でよく見られる真っ赤なカニ。岩から岩へ飛び移ったり、前へ歩いたりと、通常のカニとは異なる行動をとる。海岸の岩に張り付いた海藻をハサミで取って食べる。","note":"クエスト「軽快に動くカニ」<br/>発見物カード:115","exp":"230"}],"6870":[{"type":"歴史遺物","name":"古代エジプトのかつら","rank":"5","desc":"古代エジプトにて着用されていたかつら。着用者の身分を示すほか照り付ける日航から頭を守るため、日常的に身につけられていたと考えられる。","note":"発見物カード:615","exp":"1230"}],"92":[{"type":"宗教遺物","name":"ラーの眼","rank":"1","desc":"エジプトの遺跡で見つかる、大きな目の形のまじない。太陽神ラーの眼を指すが、ラーの一部ではなくセクメト女神を表すとも言われる。","note":"エジプトの壁画の地図","exp":"97"}],"1784":[{"type":"地理","name":"パリニャス岬","rank":"1","desc":"南米大陸最西端の岬。赤道に近く、また付近を流れる寒流の影響を受けて乾燥し、不毛地帯となっている。","note":"「書きかけの地図」<br/>発見物カード:75<br/>","exp":"150"}],"5489":[{"type":"植物","name":"グアバ","rank":"2","desc":"中南米などの熱帯、亜熱帯地域で見られる低木。\nグアバの実は紀元前から中米の先住民の間で食用とされていたが、16～17世紀に東南アジアに伝わるとグアバの葉を茶葉として使うようになった。","note":"アマゾン奥地再調査報酬の発見物「アサイー」が前提の可能性大。","exp":""}],"6255":[{"type":"宗教建築","name":"創設者の礼拝堂","rank":"4","desc":"バターリャ修道院の敷地内に作られた礼拝堂のひとつで、ポルトガル初のパンテオンでもある。ジョアン１世と王妃フィリパの墓のそばにペドロ王子とエンリケ航海王子、異郷で捕虜として死んだフェルナンド王子たちの棺が安置されている。","note":"","exp":"700"}],"6217":[{"type":"虫類","name":"ペルーオオムカデ","rank":"2","desc":"熱帯雨林に生息するムカデ。ギガスオオムカデという別名の通り、ムカデの中でもひときわ巨大である。昆虫類やヘビを食べるほか、洞窟の天井からぶら下がって、飛んできたコウモリを空中で捕らえることもあるという。","note":"","exp":"260"}],"6631":[{"type":"小型生物","name":"ホッキョクウサギ","rank":"5","desc":"北極圏などに生息するウサギ。極寒地に適応するため、体は厚い毛皮に覆われている。夏は褐色、灰色、冬は白色と、季節ごとに毛が生え変わる。これは、周囲に身を溶け込ませ天敵から隠れるためだという。","note":"追求クエスト","exp":""}],"3722":[{"type":"地理","name":"アルタイ山脈","rank":"3","desc":"シベリア西部からモンゴルにかけて広がる山脈。古代から人が住んでいたとされ、岩に刻まれた絵が多数残っている。","note":"書きかけの地図","exp":"429"}],"5636":[{"type":"鳥類","name":"メガネウ","rank":"1","desc":"カムチャッカ半島の東方にあるベーリング島に生息している大型の鳥。目の周りには羽毛がなく、白い皮膚が露出している。","note":"","exp":"190"}],"5723":[{"type":"気象・現象","name":"カプチーノコースト","rank":"2","desc":"強い風や波などにより海中のプランクトンなどが撹拌され、細かな泡が生じる現象。世界各地で観測できるが、大規模なものは非常に珍しい。","note":"2017.02.07新規追加","exp":""}],"5600":[{"type":"港・集落","name":"オマハ","rank":"2","desc":"北米大陸中西部の街。ゴールドラッシュの発生以降、開拓と東西の往来の拠点として急激に発展した。","note":"","exp":"244"}],"1951":[{"type":"植物","name":"スマトラオオコンニャク","rank":"5","desc":"人の背丈をゆうに越え地上3m、直径1.5mまでに成長する巨大な花。生息地は、スマトラ島やインドネシアなどの熱帯雨林。花は数年に一度、数日だけ咲く。また、花の異臭から別名「死体の花」とも呼ばれている。","note":"大輪の花","exp":"1170"}],"3384":[{"type":"史跡","name":"チョガ・ザンビール","rank":"5","desc":"古代エラム人が築いた宗教的中心地の遺構。連結した壁で三層に仕切られており、その最も内側にはジッグラトが建てられている。保存状態がかなり良いという特徴がある。","note":"クエスト「旧約聖書の逸話の元」<br/>発見物カード:530","exp":"1060"}],"2961":[{"type":"海洋生物","name":"アリゲーターガー","rank":"4","desc":"北米に生息する、最大で3mにもなる大型淡水魚。魚類や、エビなどの甲殻類を捕食する。水鳥や、小型哺乳類を襲うこともあるが、人を襲うことはあまりない。","note":"ワニか、魚か<br/><br/>発見時経験値720　発見物カード経験値360","exp":"720"}],"6481":[{"type":"歴史遺物","name":"カレスの巨像設計図","rank":"5","desc":"ロードス島の巨像のものと思われる設計図。巨像は鉄枠に青銅の板を張り付けて作られ、安定のため足の内部には石材が使用されたらしい。建造を指揮したとされるカレスの作と思われるが、彼は巨像の完成前に亡くなったという伝承もある。","note":"レガシー　港湾都市ロードス　左下","exp":""}],"54":[{"type":"美術品","name":"ニコラス・クラッツァーの肖像","rank":"2","desc":"息子のほうのハンス・ホルバイン作の絵画。極めて写実的な画法が彼の特徴である。モデルのニコラスはイングランドの宮廷に仕えた天文学者で、そのためこの肖像画にも天文学で用いる道具が描かれている。","note":"イングランドの絵画","exp":"230"}],"6888":[{"type":"中型生物","name":"変色したシャムネコ","rank":"3","desc":"寒さで一部の毛色が濃くなったシャムネコ。熱帯気候のシャム原産のため、寒さに弱く、顔や耳、尻尾、手足など体温が下がりやすい部位の毛色は、温度が低いと濃くなるという特徴がある。","note":"発見物カード:280","exp":"560"}],"5954":[{"type":"中型生物","name":"アザラシ","rank":"1","desc":"世界中の広い海域に生息する動物。皮下脂肪が非常に厚いため、海水の冷たさに耐えられるようだ。魚をとるために海に潜り、素晴らしい速度で泳ぐ。陸上での活動は苦手だ。","note":"黒い瞳の海獣","exp":"33"}],"6531":[{"type":"財宝","name":"アーミラリー天球儀","rank":"5","desc":"複数の金属輪を接続した天球儀。輪はそれぞれ赤道、子午線、緯線などを示す。当初は地球の周囲を回る天体の動きを表していたが、のちに太陽が中心に置かれた。望遠鏡の登場以前は広く使われ、知性の象徴とされていたらしい。","note":"レガシー星の叡智　左下","exp":"1500"}],"1652":[{"type":"地理","name":"ルーウィン岬","rank":"3","desc":"オーストラリア大陸の南西端にある岬。インド洋と南氷洋を一望できる景勝地である。周辺の土地は、乾燥地帯の多いオーストラリア大陸西部にありながら緑が豊かで、鉱物資源にも恵まれている。","note":"南西端を目指せ","exp":"440"}],"2675":[{"type":"史跡","name":"武寧王陵","rank":"4","desc":"百済25代王、武寧王の陵墓。\n武寧王は百済の国力を回復するため、中国や日本と密接な関係を築き上げたという。","note":"百済の都の名残","exp":"700"}],"2613":[{"type":"歴史遺物","name":"諸葛弓弩","rank":"5","desc":"読みは「しょかつきゅうど」。明代に発明された連発式の弩。\n弓の上部に矢を十本収納することで連射を可能にした。三国時代の軍師・諸葛亮にちなんだ名前と思われる。","note":"思い出した一言","exp":"1170"}],"1639":[{"type":"地理","name":"パラオ諸島","rank":"2","desc":"ミンダナオ島の東に位置する諸島。ごく小さい島々で構成されているため、農業には適していない。諸島の住人は散在する小島の位置を正確に把握しており各島の間には物資の交流があるようだ。","note":"太平洋横断航路計画","exp":"370"}],"3553":[{"type":"レリック","name":"アラジンと魔法のランプ","rank":"","desc":"アラジンのランプや指輪に宿る魔人は、イスラム教誕生以前の時代に神に準じる存在で、崇拝の対象だったといわれる。","note":"","exp":""}],"1731":[{"type":"財宝","name":"パパラチア","rank":"5","desc":"桃色とも橙色とも取れない不思議な色のサファイヤ。セイロン島のごく限られた場所からしか産出しない。パパラチアとはサンスクリット語で「蓮の花」という意味で、これはその蓮をモチーフにした非常に繊細なデザインのイヤリングである。","note":"永遠に散らぬ花<br/><br/>発見時経験値1209　発見物カード経験値604","exp":"1209"}],"2428":[{"type":"財宝","name":"鹿皮製の鞠","rank":"2","desc":"蹴鞠（けまり）に用いられた鞠。\n蹴鞠とは、中国から日本に伝来した遊戯である。数人が鞠を地面に落とさないよう交互に蹴り続けるもので、貴族や武士に好まれた。","note":"球技好きからの調査依頼","exp":"340"}],"3805":[{"type":"海洋生物","name":"グリーンモレイ","rank":"4","desc":"大西洋の西部などの浅い海に生息するウツボの一種。大型で、全長が2mを超えることもある。身体は黄褐色で模様はなく、体色と海中の色の兼ね合いで鮮やかな緑色に見える。","note":"緑色の巨大魚","exp":"800"}],"5877":[{"type":"天文","name":"こうま座","rank":"5","desc":"明るい星がなく、全天でも最小に近い星座。トレミー48星座の一つだが、誰が制定したのかは定かではなく、元となる神話も伝わっていないという謎に包まれた星座である。","note":"クエスト「神話なき星座」<br/>発見物カード:690","exp":"1380"}],"6617":[{"type":"歴史遺物","name":"聖イシュトヴァーンの王冠","rank":"5","desc":"ハンガリーの初代国王イシュトヴァーン1世が、ローマ教皇から与えられた王冠。ハンガリー王国の権力を象徴する。金で出来た冠には複数のエナメル画が描かれ、宝石や真珠などの飾りもほどこされている。","note":"レガシー美の叡智　下","exp":"1800"}],"220":[{"type":"鳥類","name":"マメハチドリ","rank":"5","desc":"とても小さな鳥。体を水平に保ち、空中で静止するように飛びながら、長いくちばしで花蜜を吸う。オスはなわばりを守るために見張りをすることが多い。","note":"とても小さな宝石","exp":"936"}],"6878":[{"type":"小型生物","name":"ジュウジメドクアマガエル","rank":"3","desc":"南米に生息するカエルの一種。青白い体に暗褐色の縞模様が特徴。樹上性で、虫などを食べる。毒を持ち、身の危険を感じた時には、皮膚から白く粘つく毒液を分泌する。","note":"発見物カード:280","exp":"560"}],"2000":[{"type":"美術品","name":"リュートを弾く道化師","rank":"2","desc":"フランス・ハルス作の単身人物画。ハルスは様々な人々の表情を描写した作品を数多く発表している。風俗画の主流であったカラヴァッジョ派の明暗法の影響は少なく、道化の表情を生き生きと描き出している。","note":"笑いの画家","exp":"300"}],"6528":[{"type":"気象・現象","name":"川霧","rank":"2","desc":"川を覆うように発生する蒸気霧と呼ばれる霧の一種。寒冷地でよく見られ、水温が周囲の気温より高い状態で川の水が蒸発し、その後冷たい空気に冷やされることで、霧となる。","note":"","exp":""}],"5409":[{"type":"宗教遺物","name":"ネイト像","rank":"2","desc":"ネイトは戦いと織物を司る古代エジプトの女神。織り機へ横糸を通す道具｢杼（ひ）｣を頭上に乗せ、弓矢を持つ姿で描かれる。ライオンの頭を持つ姿で描かれることもある。","note":"","exp":""}],"6155":[{"type":"中型生物","name":"スコグカッテル","rank":"2","desc":"北欧に生息する猫の一種。「森の猫」を意味する名で呼ばれ、北欧神話にもそれらしき猫の伝承があるという。今ではありふれた種類だが、11世紀にビザンツ帝国の領域からヴァイキングが持ち込んできた長毛猫が先祖だという説もある。","note":"","exp":"270"}],"1936":[{"type":"宗教遺物","name":"ミクトランテクトリ像","rank":"4","desc":"ミクトランテクトリとはアステカの神話における冥府の主のことである。血まみれの骸骨や歯をむき出しにした姿など、どれも恐ろしい姿として描かれる。","note":"アステカの冥府に眠る神","exp":"620"}],"3938":[{"type":"天文","name":"ベガ","rank":"1","desc":"夏の大三角の一角を構成する、こと座で最も明るい星。白く輝く1等星で、竪琴の装飾としてつけられた宝石にあたるとされる。","note":"「明るい星の観測記録」<br/>発見物カード:55","exp":"110"}],"3227":[{"type":"歴史遺物","name":"白銀の兜","rank":"5","desc":"ランス・オ・メドーに遺されたヴァイキングの兜。\n白銀で装飾されており一般の戦士の持ち物ではないと思われる。\n近くに白銀の産地があるか、あるいは交易で手に入れたものなのだろうか。","note":"帰らぬ理由、通じぬ想い","exp":"950"}],"2341":[{"type":"宗教遺物","name":"空海の錫杖","rank":"3","desc":"読みは、「くうかいのしゃくじょう」。日本の仏僧である空海が所持していた杖。\n揺らすと、上部の環が互いに触れ合い、音を立てる。この音には、煩悩を消し去るなどのさまざまな効果があるといわれている。","note":"聖人の杖","exp":"530"}],"1226":[{"type":"歴史遺物","name":"ヤハゥ・テ・キニチ2世の装飾品","rank":"2","desc":"カラコル王の装飾品。ヤハゥ・テ・キニチ2世は、星の戦争でムトゥプルに攻め込んだ王である。","note":"優越王を狙う者","exp":"360"}],"6791":[{"type":"天文","name":"アンサー","rank":"5","desc":"こぎつね座で最も明るい星。キツネの頭にあたるところに\n位置し、名前はラテン語でガチョウを意味する。これわこ\nぎつね座がかつてがちょうをくわえたきつね座と呼ばれた\nことに由来する。","note":"視認","exp":""}],"239":[{"type":"財宝","name":"バアルの宝玉","rank":"1","desc":"聖書のソロモン王が、悪魔や精霊72体を封じ込めたという宝玉の一つ。この宝石にはバアルが封じられているという。真偽の程は不明だ。\n宝玉はよく見ると傷があり、「遠浅の海」と彫られている。","note":"バアルの宝玉","exp":"100"}],"6804":[{"type":"史跡","name":"テオドシウスの城壁","rank":"5","desc":"5世紀初頭に、東ローマ帝国皇帝テオドシウス2世によって建設された大城壁。イスタンブール旧市街の西側を囲み、コンスタンティノープル陥落の際も、破られることはなかったため、難攻不落の城壁と謳われた。","note":"発見物カード：465","exp":""}],"2889":[{"type":"大型生物","name":"ターキン","rank":"2","desc":"中国南西部に生息している、湾曲した大きな角が特徴の動物。\n夏は大規模な群れを形成するが、冬には小規模な群れへと分散する習性を持つ。","note":"角のある大型獣の地図","exp":"280"}],"2003":[{"type":"宗教遺物","name":"チムー王族の黄金飾り","rank":"5","desc":"アンデス山脈の北側でインカ帝国以前に栄えていた、チムー王国王族の副葬品。その高度な冶金の技術は、帝国以前から伝わるものだった。","note":"クエスト「失われた文化」<br/>発見物カード:260","exp":"520"}],"5586":[{"type":"史跡","name":"バッファロー・ジャンプ","rank":"3","desc":"正式名称は「ヘッド・スマッシュト・イン・バッファロー・ジャンプ」。北米北西部にある崖。周辺の草原に生息するアメリカバイソン（バッファロー）を追い込んで狩る場所として、古来より利用されており、古い矢尻なども見つかっている。","note":"","exp":"490"}],"1507":[{"type":"小型生物","name":"トッケイ","rank":"1","desc":"水色の体にオレンジ色の水玉模様があるトカゲ。鳴き声は「トッケイ」と聞こえる。大型の虫やネズミなどを食べる。","note":"奇妙なトカゲの地図","exp":"135"}],"6360":[{"type":"史跡","name":"クセルクセス門","rank":"2","desc":"中東の遺跡ペルセポリスにある巨大な門。人面有翼獣神像が門の両側に配置されている。クセルクセス1世により建設されたが、この門をはじめとする大規模な建築事業によって国の財政は傾き、国家の衰退にさえ繋がったとされる。","note":"","exp":"260"}],"5828":[{"type":"財宝","name":"マンモスの牙の笛","rank":"5","desc":"マンモスの牙で作られた笛。現存する中では世界最古の管楽器である。","note":"","exp":"1600"}],"5011":[{"type":"港・集落","name":"アカプルコ","rank":"2","desc":"太平洋に面した、山脈ふもとの街。一年を通して気温が高い、常夏の気候である。銀を用いた交易が盛んなためヨーロッパへ向かう輸送船の往来が跡を絶たない。","note":"到達する","exp":"300"}],"3761":[{"type":"天文","name":"プレアデス星団","rank":"4","desc":"おうし座にある青白い星が集まった星団。プレアデスとはギリシャ神話に登場する巨人アトラスの娘でアルテミスに仕える7人姉妹である。古代ギリシャでは独立した星座として扱われていた。東洋では昴と呼ばれる。","note":"クエスト「美しい星の集まり」<br/>発見物カード:385","exp":"770"}],"2673":[{"type":"歴史遺物","name":"三国遺事","rank":"2","desc":"高麗の高僧・一然が編さんしたといわれる、全五巻の歴史書。\n三国史記とは違い、故事や伝承、仏教についても記されている。","note":"歴史と神話の書","exp":"330"}],"5363":[{"type":"植物","name":"ヒヤシンス","rank":"2","desc":"西アジア原産の草花。オスマントルコで栽培された。\nギリシャ神話ではアポロンの寵愛を受ける美青年ヒュアキントスの血から生まれたとされる。","note":"","exp":"300"}],"504":[{"type":"財宝","name":"オデュッセイア","rank":"1","desc":"ホメロス作の叙事詩。トロイの木馬の立案者であるオデュッセウスが、トロイ戦争のあと神の怒りに触れ、苦労のすえに故郷に帰り着くまでを語るもの。","note":"クエスト「古代ギリシャ最高の叙事詩」<br/>発見物カード:30","exp":"60"}],"1759":[{"type":"歴史遺物","name":"ナイロメーター","rank":"1","desc":"ナイル川の至る所に設置された、水位計測施設。ナイル川は一年に一度大氾濫を起こし、下流の農業に大打撃を与えるため、氾濫をいち早く察知する必要があった。ただし氾濫には、上流の肥沃な黒土を下流に運ぶという働きもあったという。","note":"水位計測器の地図","exp":"180"}],"1668":[{"type":"宗教建築","name":"ホツ・マツア王のモアイ","rank":"2","desc":"ラパ・ヌイの伝説上の王であるホツ・マツア王の像。王は賢者ハウマカの見た夢を信じ、航海の旅に出て、やがてこの地にたどり着いた。この像自体がどんな意味を持って建てられているのかはよく分からない。","note":"ラノ・ララクの調査","exp":"350"}],"277":[{"type":"地理","name":"ホルムズ海峡","rank":"1","desc":"ペルシャ湾南東部にある海峡。古代からひんぱんに船が行き来するため、すぐそばにホルムズという街がある。","note":"ペルシャの海峡","exp":"200"}],"213":[{"type":"財宝","name":"伯爵令嬢の指輪","rank":"1","desc":"悲運に見舞われたある伯爵令嬢の指輪。希少価値の高い大きな青水晶が使われている。内側には、出自を証明する刻印がされている。","note":"とある令嬢の指輪","exp":"75"}],"5031":[{"type":"港・集落","name":"カイエンヌ","rank":"2","desc":"南米大陸北東沿岸に位置する港町。年間を通じて温暖だが、雨量が多い。","note":"到達する","exp":"242"}],"807":[{"type":"大型生物","name":"ナイルワニ","rank":"2","desc":"ナイル川流域で多く見られるワニ。大きい個体で6mを超え、非常に凶暴で危険。古代エジプトでは神の使いとして崇拝されていたという話だ。川底で待ち伏せ、獲物を襲う。","note":"大河に潜む獣","exp":"250"}],"1645":[{"type":"地理","name":"アオテアロア","rank":"4","desc":"ニューギニア島の南東にある島。南北に巨大な島がふたつあるが、特に北の島をアオテアロアと呼ぶ。アオテアロアとは、先住民であるマオリ人の言葉で、「長く白い雲のたなびく地」という意味である。","note":"長く白い雲","exp":"624"}],"3262":[{"type":"中型生物","name":"ラーテル","rank":"5","desc":"アフリカからアジア西部および南部まで、広く分布する生物。サバンナや草原などに生息する。皮膚が厚く伸縮性に富んでおり、特に背中は肉食動物の牙も通さない。コブラなどのヘビの毒に対して耐性があり、捕食対象とすることもある。","note":"闘士の二つ名<br/><br/>発見時経験値820　発見物カード経験値410","exp":"820"}],"5538":[{"type":"気象・現象","name":"流星雨","rank":"4","desc":"火球が一定の短時間に複数出現する現象。流星雨には放射点が存在するため、夜間にそれが天頂近くに上る場所でのみ観測できる。","note":"視認R7でスキル不足表示。<br/>視認R8で発見確認。","exp":"315"}],"1855":[{"type":"財宝","name":"ウミナの魂","rank":"5","desc":"インカ皇帝・パチャクティが所持していたというダチョウの卵大のエメラルド。アンデス北部を征服した際に現地の民に授けたといわれている。現在はチブチャ民族の重要な祭具として、ソモンドコの奥深くに眠っている。","note":"女神の魂","exp":"1230"}],"6323":[{"type":"虫類","name":"ツマジロスカシマダラ","rank":"3","desc":"中南米に生息し、ガラスのように透明な羽を持つチョウ。美しい見た目とは裏腹に、自身の体重の40倍の重さのものを運ぶ力がある。植物から抽出した毒素を体内に溜め込んでいるため、有毒。雄はこの毒をフェロモンとしても使う。","note":"","exp":"600"}],"4815":[{"type":"財宝","name":"春望","rank":"","desc":"","note":"楽山大仏 （深層隠し部屋）","exp":""}],"355":[{"type":"歴史遺物","name":"アレクサンドロス大王の石棺","rank":"2","desc":"巨大な版図を築き上げながら志半ばに倒れたアレクサンドロス大王の石棺。全面を、遠征の様子の精緻なレリーフがおおっている。","note":"英雄の死","exp":"280"}],"5819":[{"type":"財宝","name":"般若経の貝葉写本","rank":"5","desc":"ヤシの葉で作られた般若経の写本。貝葉とは貝多羅葉の略であり、南アジアや東南アジアの筆記媒体として用いられた。","note":"","exp":"1410"}],"3005":[{"type":"化石","name":"植物模様のある石","rank":"2","desc":"妙な模様や起伏がある石。シダ植物の葉のようにも見えるが…。\n古代の植物が石化したのだろうか？","note":"奇妙な石の地図","exp":"220"}],"2528":[{"type":"美術品","name":"俵屋宗達の屏風絵","rank":"1","desc":"江戸時代の絵師・俵屋宗達によって描かれた屏風絵。\n伝統的な大和絵の技法に加え、独特の技法と構図が取られている点が特徴的である。","note":"華やかな屏風絵の地図","exp":"180"}],"241":[{"type":"美術品","name":"バベルの塔","rank":"1","desc":"ピーテル・ブリューゲル（父）作の絵画。建築中のバベルの塔を描いている。特に大型ではないのに、建築に携わる人や工具が非常に緻密に描かれている。本来はバビロンにあった塔だが、欧州の街をモデルに描いている。","note":"クエスト「バベルの塔の絵画」<br/>発見物カード:85","exp":"170"}],"82":[{"type":"歴史遺物","name":"牛頭のある女王のリラ","rank":"2","desc":"ウル王墓のプ・アビ女王の墓から発見されたリラ。牛頭の装飾には金が使われている。ラピスラズリや貝などもふんだんに使用されており、当時の豊かさを物語っている。","note":"ウルの栄華","exp":"390"}],"3424":[{"type":"レリック","name":"オジェ・ル・ダノワ","rank":"","desc":"多くの武勲詩の主人公で、シャルルマーニュに仕えたとされる騎士。デンマークではホルガー・ダンクスの名で親しまれている。","note":"","exp":""}],"1888":[{"type":"歴史遺物","name":"シャガス号","rank":"3","desc":"正式名称は、ラス・シンク・シャガス号。\nポルトガルの東インド貿易船の一隻。\nインドからの帰路の途中、アゾレス諸島付近でイングランド海賊に襲われ、沈没した。","note":"サルベージ","exp":"451"}],"6447":[{"type":"財宝","name":"公妃の香り付き革手袋","rank":"5","desc":"フランスのグラース地方で作られた貴婦人用の手袋。皮革のにおいを消すために香料を染みこませてあり、芳香を放つ。中でもオレンジの花の精油の香りは、ネロラの公妃が好んだとされ、ネロリと呼ばれるようになったという。","note":"","exp":""}],"5095":[{"type":"港・集落","name":"ディリ","rank":"2","desc":"ティモール島の東部北岸に位置する街。ティモール島は古くから白檀の産地として知られ多くの交易船が来航している。近年は、ヨーロッパの交易船の来航が目立つようだ。","note":"到達する","exp":"310"}],"5059":[{"type":"港・集落","name":"サロニカ","rank":"1","desc":"テッサロニキともいい古代マケドニアの首都だった街。ビザンツ帝国の領土だったが、15世紀中ごろからオスマントルコの支配下に入った。農作物のほか、大理石や香料が流通している。","note":"到達する","exp":"20"}],"2539":[{"type":"植物","name":"アイギョクシ","rank":"2","desc":"台湾島の山中にのみ生息する貴重な植物。\nこの果実から、アイギョクと呼ばれるお菓子が作られている。","note":"お菓子の原材料","exp":"330"}],"5697":[{"type":"財宝","name":"シャーマンたちの貨幣","rank":"4","desc":"シャーマン岩周辺の水底に沈んでいた貨幣。岩に奇跡を起こす力があると信じたシャーマンたちは、貨幣を岩の周辺に投げ入れ、なんらかの儀式を行っていたようだ。","note":"","exp":"700"}],"818":[{"type":"財宝","name":"大理石の女性像","rank":"1","desc":"大理石の女性像。丸みのあるラインがとても美しい。あまり古いものではないようだ。","note":"大理石の女性像の地図","exp":"108"}],"5393":[{"type":"天文","name":"みなみのさんかく座","rank":"2","desc":"ケンタウルス座の近くにある星座。2等星と3等星が三角形を成すため見つけやすい。オランダのプランシウスによって初めて星座図に掲載された。","note":"「天文学者の観測記録」<br/>発見物カード:140","exp":"280"}],"1307":[{"type":"虫類","name":"ゴホンツノカブト","rank":"1","desc":"突き上げるように生えた一本の長い角と、短い四本の角を持つ虫。長い肢をもち、羽の部分は茶色っぽい色をしている。","note":"角のある虫の地図","exp":"120"}],"1904":[{"type":"宗教遺物","name":"聖骸布","rank":"2","desc":"キリストの遺体を包んだとされる亜麻布。布にははっきりと傷ついた男性の姿が見て取れる。驚くべきことに、この傷が聖書にあるキリストの受難とぴたりと符号している。","note":"聖なる亜麻布","exp":"230"}],"1496":[{"type":"宗教遺物","name":"イェリング石碑","rank":"2","desc":"10世紀にデンマーク王であるハーラル青歯王によって建立された石碑。石碑にはハーラル青歯王のデンマーク統一とノルウェー獲得、さらにデーン人をキリスト教に改宗させた偉業がルーン文字によって記されている。","note":"統一と教化","exp":"230"}],"950":[{"type":"化石","name":"背びれのあるドラゴンの骨","rank":"2","desc":"背中に板状の突起が並んだ、大型の動物の骨のような石。こんな生物がどこかにいるのだろうか？　もしいたとしたら、それこそ悪魔の化身のように、凶暴なのに違いない。","note":"風変わりなドラゴン","exp":"300"}],"3683":[{"type":"地理","name":"ウランゲリ島","rank":"4","desc":"チュクチ海に浮かぶ小島。\n極北の動物が多く生息し、夏の間は渡り鳥も訪れる。","note":"クエスト「極北の生物調査地」<br/>発見物カード:325","exp":"650"}],"5908":[{"type":"宗教建築","name":"ヤサヴィ廟","rank":"5","desc":"12世紀に活躍したイスラム教の聖者、アフマド・ヤサヴィの墓が納められた廟。造営した人物が途中で死んだため、未完成である。","note":"","exp":"1370"}],"2981":[{"type":"海洋生物","name":"ヘラチョウザメ","rank":"2","desc":"北米に生息するチョウザメの仲間。鼻先が突出しているのが特徴的だが、機能的にはよくわかっていない。キャビアと呼ばれる、卵を塩漬けにしたものは珍味として多くの人に愛されている。","note":"川に棲むサメの地図","exp":"240"}],"1616":[{"type":"宗教遺物","name":"テオティワカンの副葬品","rank":"1","desc":"メキシコ中央高原に花開いたテオティワカンの副葬品。マヤやアステカの各地でもこれと同じ様式の副葬品が見つかることから、古代この地は非常に強い影響度を誇っていたのだろう。","note":"メソアメリカの遺物の地図<br/><br/>発見物カード:100","exp":"200"}],"6659":[{"type":"大型生物","name":"シベリアビッグホーン","rank":"5","desc":"シベリア北東部に生息する野生のヒツジ。別名ユキヒツジ。後ろへ大きく湾曲した双角が特徴。標高の高い山岳地帯に棲む。蹄の底が特殊な形状をしており断崖絶壁を一気に駆けられる。","note":"追究クエスト<br/>発見物カード:750","exp":"1500"}],"5598":[{"type":"気象・現象","name":"竜巻","rank":"2","desc":"地上から上空の雲まで突風が渦巻き状に発生する現象。風は建物などを破壊するほど協力になることもある。ただ、そのほとんどが局地的なものであり、発生時間もかなり短い。","note":"","exp":"250"}],"6446":[{"type":"宗教建築","name":"サンタ・マリア・ノヴェッラ教会","rank":"2","desc":"フィレンツェにある教会。のちのフランス王妃がフィレンツェから嫁いだ際に持参した香水「王妃の水」は、この教会の修道士たちによって作られたとされる。ヨーロッパの香水文化はここから始まったといえるだろう。","note":"","exp":"280"}],"6449":[{"type":"財宝","name":"三足の蛙の香炉","rank":"5","desc":"蛙をかたどった香炉。日本では武人も香道をたしなんでおり、この香炉も天下統一を目前にした武将が所有していたという。この武将が反乱で暗殺される前夜、香炉の蛙が鳴き声を上げたという伝説がある。","note":"","exp":"2550"}],"35":[{"type":"地理","name":"アラビア半島","rank":"1","desc":"ペルシャ湾と紅海にはさまれた広い半島。ほとんどが砂漠におおわれており、自然環境は非常に厳しい。しかしイスラム勢力をはじめとして、非常に栄えている地域でもある。","note":"アラビア航路の確保","exp":"200"}],"6729":[{"type":"宗教建築","name":"バイヨン","rank":"5","desc":"アンコール遺跡の中央付近にある寺院跡。名はクメール語で「美しい塔」の意味。石材の質や積み方が統一されておらず、何代にも渡り王の命令で少しずつ建てられていったと見られる。中央の四面像など、塔の各所に掘られた人面像が有名。","note":"","exp":"1210"}],"803":[{"type":"地理","name":"ミシシッピ川","rank":"3","desc":"北米大陸を縦断する大河。流域に住むオジブウェ民族の言葉で「大きな川」を意味するミシシッピという名で呼ばれるように、その流れは地の果てまで続くようである。","note":"クエスト「大きな川という名の川」<br/>発見物カード:235","exp":"473"}],"6190":[{"type":"史跡","name":"ギョベクリ・テペの石柱群","rank":"2","desc":"現地の言葉で「太鼓腹の丘」の意味を持つ遺構。巨大な石柱がいくつも円を描くように並べられており、動物のようなレリーフが彫られた石柱も時折見られる。かなり大昔のものと思われるが、誰が何のために造ったのかは分からない。","note":"","exp":"350"}],"5058":[{"type":"港・集落","name":"サマライ","rank":"2","desc":"ニューギニア島南東に位置する街。高温多湿の熱帯雨林気候。年中多雨で年間を通じて気温の年較差は少ない。","note":"到達する","exp":"370"}],"997":[{"type":"財宝","name":"東方見聞録","rank":"1","desc":"13世紀終わりごろ、元朝のフビライに仕えたマルコ・ポーロの口述を記録した本。この中に、黄金の国ジパングが登場する。","note":"冒険者のバイブル","exp":"55"}],"6137":[{"type":"財宝","name":"白銀の燭台","rank":"1","desc":"銀は金属の中でも特に白く輝くものだが、この燭台はひときわ白く輝いている。銀に混ぜる金属の種類と割合に秘密があるというが、解明することはできないだろう…。","note":"神秘的な燭台","exp":"100"}],"6297":[{"type":"史跡","name":"ワカ・プクヤーナ","rank":"1","desc":"リマにある古代遺跡。日干しレンガを縦に積み重ねた、大きなピラミッドがある。かつて辺り一帯を治めていた宗教都市であり、数々の祭事が行われていたとされる。","note":"","exp":"200"}],"2415":[{"type":"宗教遺物","name":"ハトホル像","rank":"2","desc":"古代エジプトの神の一つ。諸神の母と呼ばれる他にも、天空の神や死者の守護神といった多様な面を持ち合わせている。","note":"ダンジョン","exp":"365"}],"6918":[{"type":"財宝","name":"彫刻が施されたガラスの器","rank":"3","desc":"江戸時代に安閑天皇陵古墳で発見したと言われる、ガラスの椀。ササン朝時代に作られたといわれ、ガラスの表面には、円形の文様が規則的に彫られている。","note":"","exp":""}],"2404":[{"type":"地理","name":"屋久島","rank":"4","desc":"九州の南部にある島。1000mを超える山々を有し、雨が多い。\nその豊かな自然が多様な生物を育んでいる。東洋のガラパゴスともいえる島である。","note":"東の果てのガラパゴス","exp":"650"}],"2087":[{"type":"宗教遺物","name":"チョコ・カリャ像","rank":"5","desc":"アンデス神話に登場する、畑と水路の女神。水の神パリアカカの妻であるチョゲ・スソが神格化したものと思われる。","note":"クエスト「畑の女神盗難事件」<br/>発見物カード:530","exp":"1060"}],"2815":[{"type":"歴史遺物","name":"史記","rank":"2","desc":"古代から漢代までを記した歴史書。\n初めは「太史公書」と名付けられたが、のちに「史記」と呼ばれるようになったという。","note":"古代史の資料","exp":"370"}],"1552":[{"type":"地理","name":"エア半島","rank":"1","desc":"オーストラリア南東部に属する半島。近海ではクジラやサメがよく観測される。他にもアシカやアザラシ、イルカなども多数生息しているようだ。","note":"書きかけの地図","exp":"110"}],"6357":[{"type":"財宝","name":"ニュルンベルク年代記","rank":"4","desc":"ドイツ南東部にある都市ニュルンベルクで出版された本。金属で活字を作り、紙に刷るという活版印刷の技術により広く出版された。この本では世界史を七つの年代に区分し、多くの挿絵と共に解説している。","note":"クエスト「世界の歴史に迫る」<br/>発見物カード:350","exp":"700"}],"1365":[{"type":"美術品","name":"荘厳の聖母","rank":"2","desc":"アンブロージョ・ロレンツェッティ作の祭壇画。ロレンツェッティが生涯に手がけた荘厳の聖母の一作。彼が描いた聖母子画の中で、特に評価が高い。互いに視線を交ぜ合わせる聖母子の姿は深い愛を感じさせる。","note":"荘厳の聖母","exp":"220"}],"3824":[{"type":"財宝","name":"コンクパール","rank":"5","desc":"コンクガイから採れる真珠の一種。主に柔らかいピンク色で、色のむらや細かい模様を持つものもある。","note":"コンクガイが生む真珠<br/><br/>発見時経験値1250　発見物カード経験値625","exp":"1250"}],"6406":[{"type":"宗教建築","name":"キュロス2世の墳墓","rank":"5","desc":"アケメネス朝ペルシャの初代国王であり大帝国を築いたキュロス2世の墓と伝わる遺跡。切石を階段状に積んだ基壇の上に、石造りの巨大な家型墓室が載っている。のちにこの形に倣ったと思われる巨大建築が造られた。","note":"","exp":""}],"2709":[{"type":"歴史遺物","name":"炉形土器","rank":"1","desc":"火鉢のような形をしている土器。伽耶時代によく使用されたといわれる。\n土器製作技術が発達するにつれ大型化し、三角や半円形などの多様な文様が描かれるようになったという。","note":"大きな土器の地図","exp":"180"}],"1455":[{"type":"地理","name":"サハラ","rank":"2","desc":"アフリカ大陸北部を覆う広大な砂漠。アラビア語で「荒れた土地」を意味する。各所で土器などが出土することから、古くからこの砂漠で暮らす民がいたことがうかがえる。またラクダを用いたキャラバンによる交易が発達している。","note":"大砂漠","exp":"220"}],"1156":[{"type":"小型生物","name":"マタマタ","rank":"2","desc":"ごつごつした甲羅と平たい頭部を持つ。川や池の底に生息し、先の尖った鼻のおかげで水面に上がらずに呼吸できる。","note":"ごつごつしたカメ<br/><br/>発見時経験値260　発見物カード経験値130","exp":"260"}],"1328":[{"type":"地理","name":"ティモール島","rank":"3","desc":"小スンダ列島の中でも最東部に位置する島。雨が少なく、農業に向いている土地とは言い難い。\nしかし、高価な香料である白檀を産するようだ。","note":"クエスト「列島の東端」<br/>発見物カード:235","exp":"473"}],"1321":[{"type":"地理","name":"モルッカ海峡","rank":"2","desc":"セレベス島の北部の東側に横たわる海峡。複雑な地形を生かして、かなり古くから海賊が活動しているようだ。","note":"クエスト「モルッカ海追加調査」<br/>発見物カード:160","exp":"320"}],"5254":[{"type":"天文","name":"ちょうこくしつ座","rank":"5","desc":"フランスの天文学者ラカーユによって制定された星座。ラカーユはケープに滞在し、南天の観測を行った。広さの割に明るい星が少なく探しにくい。","note":"クエスト「フランスで作られた星座」<br/>発見物カード:410","exp":"820"}],"1962":[{"type":"宗教遺物","name":"儀式用土器","rank":"2","desc":"アンデスの神殿で、神器として使われていたという土器。トウモロコシの酒・チチャを注いでいたのだろうか。","note":"アンデスの儀式道具の地図","exp":"220"}],"6395":[{"type":"気象・現象","name":"地吹雪","rank":"2","desc":"一度降り積もった雪が強風により吹き上げられる現像。空に吹き上げられた雪で視界が悪くなり、時には太陽を隠すほどにもなる。強い地吹雪に巻き込まれると、方向感覚を失ってしまう場合がある。","note":"ヒマラヤ山脈周辺、北西の果からわずか上方、二またで分れる道で右の崖。夜に出るよう。","exp":"330"}],"1641":[{"type":"地理","name":"太平洋","rank":"5","desc":"マゼラン海峡を抜けたマゼランが、「大西洋とは比べ物にならない穏やかな海だ」といったことから名づけられた海。\nその広さは、マゼランが航海した当時の予測よりはるかに広大である。","note":"マール・パシフィコ","exp":"1053"}],"5289":[{"type":"小型生物","name":"ヒガシグリーンマンバ","rank":"3","desc":"アフリカ南東部に生息するヘビ。体が細長く、3mを超える個体もいるという。体の色は明るい緑で、常緑樹にいることが多い。ブラックマンバに比べるとおとなしく、毒も弱いが、それでもかなりの猛毒を持つ。","note":"","exp":"490"}],"1518":[{"type":"地理","name":"キンバリー台地","rank":"2","desc":"オーストラリア北西部にある台地。内陸は渓谷や切り立った山々になっており、海岸線も複雑である。","note":"大陸北西岸の基礎調査","exp":"340"}],"2959":[{"type":"地理","name":"ナンタケット島","rank":"1","desc":"北米の沖合いに浮かぶ小さな島。一年を通して気温が低く、冬は雪が積もる。周辺の海域ではクジラの目撃情報が多い。","note":"書きかけの地図","exp":"110"}],"5899":[{"type":"史跡","name":"兵馬俑坑","rank":"5","desc":"巨大な陵墓。副葬品として、兵馬俑と呼ばれる将兵や馬などを象った人形が大量に埋められている。あまりに規模が大きいため、いまだ全容を把握する者は存在しない。","note":"","exp":"1510"}],"5155":[{"type":"港・集落","name":"マニラ","rank":"2","desc":"ルソン島の南部に位置する港町。マレー人の集落が存在し、交易が盛んに行われた。16世紀後半、イスパニア人レガスピにより占領される。","note":"到達する","exp":"360"}],"835":[{"type":"地理","name":"モルジブ諸島","rank":"2","desc":"インドの南西に分布する島々。1000を超える島が南北に散らばっている。土地はそれなりに肥沃で、ココヤシなどの栽培に向くと思われる。","note":"地上の楽園","exp":"320"}],"1471":[{"type":"小型生物","name":"オポッサム","rank":"1","desc":"腹の部分に子育て用の袋を持つ動物。ネズミのような外見をしていて、毛のない尻尾を木に巻きつけてぶら下がる。危険を感じると死んだふりをする。","note":"袋のある動物の地図","exp":"190"}],"6265":[{"type":"財宝","name":"狼の牧者に関する報告書","rank":"5","desc":"ロシアや東ヨーロッパで広く伝わっている、聖ゲオルギイに関する伝承を集めた報告書。三十頭の狼を引き連れた「狼の牧者」ゲオルギイの説話が収められており、現地の古い信仰とキリスト教の伝承が習合する過程がまとめられている。","note":"","exp":"1290"}],"2967":[{"type":"史跡","name":"サーペント・マウンド","rank":"5","desc":"北米東部にある、ヘビのような形をした丘。丘の周りは堀があり、陵墓のようでもあるが不明な部分も多い。\nヘビの形は星座に関係しているのかもしれない。","note":"丘か、陵墓か","exp":"1120"}],"6496":[{"type":"歴史遺物","name":"記録抹消刑の記録","rank":"5","desc":"ある者が記録抹消刑を受けたという記録。有名になりたいがためにエフェソスのアルテミス神殿に放火し、焼失させた男は、処刑ののちあらゆる記録から名前を抹消された。しかし、他国の歴史家がその名を書き残してしまい、今に伝わる。","note":"レガシー女神信仰の地エフェソス　右上","exp":"1650"}],"3626":[{"type":"歴史遺物","name":"ローマ建国史","rank":"3","desc":"四散した資料や文献から再編纂された、ローマ建国史。\n原本とされるリヴィウスの著書は100巻以上あるので、まだまだ足りてはいないようだ。","note":"ローマの歴史書の地図","exp":"490"}],"3845":[{"type":"小型生物","name":"バンクーバーマーモット","rank":"1","desc":"北米西岸の一部の島に生息するリスの一種。掘った巣穴の中で生活し、冬は冬眠する。","note":"まんまるネズミ","exp":"200"}],"872":[{"type":"歴史遺物","name":"ユスティニアヌス帝の王杖","rank":"1","desc":"ユスティニアヌス帝はビザンツ帝国の皇帝で衰退しかかっていた帝国を再興した。ローマ法大全の編纂（へんさん）、ソフィア大聖堂の建設など、功績は数多い。","note":"東ローマの皇帝","exp":"100"}],"3302":[{"type":"財宝","name":"ケルズの書","rank":"4","desc":"8世紀頃に製作された聖書の手写本。ケルト文様による豪華な装飾が施されており、書物とは思えない美しさである。\nマタイ、マルコ、ヨハネ、ルカの四福音書が収められている。","note":"世界でもっとも美しい本","exp":"740"}],"5810":[{"type":"宗教遺物","name":"マニ車","rank":"2","desc":"筒状の仏具。外側にマントラが刻まれ、中には経文が納められている。チベット仏教でよく使われ、一回転させると中の経文を一度読んだのと同じだけの功徳を得られるという。","note":"","exp":"390"}],"6063":[{"type":"美術品","name":"聖クリストフォロス像","rank":"2","desc":"西ヨーロッパで伝えられている聖人、聖クリストフォロスを描いた絵。幼児の姿をしたキリストを背負った男性の姿で描かれ、水難や嵐、あらゆる旅の危険から守る聖人として、広く崇敬されている。","note":"","exp":"210"}],"2808":[{"type":"財宝","name":"永楽大典","rank":"2","desc":"天文・地誌・陰陽などのさまざまな書を原本で収集した書類。明代以前の貴重な文献まで網羅している。\nしかし、二万巻以上に及ぶ膨大な書物となったため、一部しか写本になっていない。","note":"貴重な書物の地図","exp":"260"}],"3045":[{"type":"植物","name":"アメリカフヨウ","rank":"2","desc":"陽光が当たる場所を好む、北米原産の植物。丈はおよそ1mまで成長し、20cm程度の大輪の花を咲かせる。","note":"大きな花の地図","exp":"210"}],"102":[{"type":"地理","name":"フエルテベントゥラ島","rank":"1","desc":"カナリア諸島の東部に浮かぶ島。カナリア諸島の中でアフリカ大陸に最も近い。島のほとんどが乾燥しており、南部にはプエルト・ブランカと呼ばれる美しい白い砂浜が続く。","note":"カナリア諸島の大きい島","exp":"40"}],"1178":[{"type":"宗教遺物","name":"ヴァジュラ","rank":"5","desc":"ヒンドゥーの神・インドラの武器。悪龍・ヴリトラを倒すために、ダディーチャという仙人の骨から作られたものである。金剛杵ともいう。","note":"魔神を貫く武器","exp":"1222"}],"2842":[{"type":"地理","name":"三清山","rank":"2","desc":"道教の名山の一つ。道教の三大神が並んで座っているように見えることから、この名が付いたとされる。","note":"［勅命］[[現地の信仰と山の関係調査","exp":"310"}],"566":[{"type":"歴史遺物","name":"パピルスの巻物","rank":"1","desc":"古代エジプトの書物。パピルスの茎を打ち伸ばした紙片に、古代エジプトの神聖文字・ヒエログリフが記されている。","note":"古文書の地図","exp":"14"}],"356":[{"type":"宗教遺物","name":"ラクシュミー像","rank":"2","desc":"インド神話の女神の像である。ラクシュミーは幸福と富をもたらす女神で、ヴィシュヌ神の妃だとされる。","note":"英雄神の妻","exp":"310"}],"2792":[{"type":"大型生物","name":"ジャイアントパンダ","rank":"5","desc":"主に中国南西部に生息する動物。白と黒に、はっきりと分かれた体毛が特徴。尾は、あまり成長しないため、目立たない。\n群れや家族を形成せず単独で行動する。","note":"酒場マスターの悩み事","exp":"830"}],"1233":[{"type":"大型生物","name":"バク","rank":"2","desc":"頭から肩にかけて生えるたてがみが特徴。泳ぎが得意で、襲われると水中へ逃げ込む。木の葉や果実、水草などを食べる。","note":"危険への対処","exp":"380"}],"3642":[{"type":"歴史遺物","name":"吸血鬼伝説","rank":"4","desc":"ヨーロッパ各地に伝わる、人間の血を糧とする化け物の伝説をまとめた書物。埋葬された死者が夜中になると墓場から這い出して街を徘徊し、人間を襲うという。元はスラブ地方につたわる民話だったようだ。","note":"死にきれない者の伝承","exp":"640"}],"5228":[{"type":"史跡","name":"フォロの浴場","rank":"1","desc":"古代ローマの都市であるポンペイにあった公共の浴場。脱衣場やさまざまな温度の浴室が設けられている。","note":"","exp":"170"}],"928":[{"type":"植物","name":"シラカバ","rank":"1","desc":"幹が白い落葉樹。暖かな地方では見かけないが、寒冷地ではよく群生している。シラカバの林は大変美しい。","note":"美しい木の地図","exp":"11"}],"2954":[{"type":"鳥類","name":"アオカケス","rank":"2","desc":"北米東部に住む鳥。頭頂部や背面、尾羽が、青い羽毛で覆われている。頭頂部には冠羽と呼ばれるものがあり、勇ましく見える。","note":"甲高い声の青い鳥","exp":"330"}],"4861":[{"type":"天文","name":"ペルセウス座の二重星団","rank":"4","desc":"ペルセウス座にある星団。無数の星が集まったものが二つ並んで見える。肉眼でも、そのぼんやりとした光を見てとれる。","note":"ペルセウス座の二重星団","exp":"740"}],"6530":[{"type":"史跡","name":"ティコ・ブラーエの壁面四分儀","rank":"5","desc":"天体の高度を観測する機器で、巨大な目盛り付きの真鍮板が壁面に設置されている。ティコ・ブラーエが建設したウラニボリ天文台にあった。真鍮板近くに接眼孔、正対する壁面上部に対物孔があり、これらを通して目視で観測する。","note":"レガシー星の叡智　下","exp":"2550"}],"5124":[{"type":"港・集落","name":"ピサ","rank":"1","desc":"古代ローマの時代に開拓された、古い街。ピサの斜塔があることで有名。イタリア諸都市の中で最初に都市国家の宣言をした。主な産物は高級織物や大理石像などである。","note":"到達する","exp":"12"}],"1035":[{"type":"中型生物","name":"バーバリシープ","rank":"1","desc":"岩山に住む、羊と山羊の中間のような動物。1頭のオスと複数のメスで群れを作る。","note":"野生の羊の地図","exp":"13"}],"68":[{"type":"宗教遺物","name":"インドラ像","rank":"2","desc":"古代インドの神話で、もっとも有名な神の像である。雷や嵐をつかさどる軍神で、漆黒の悪龍・ヴリトラを打ち倒した。ヒンドゥーでは地位が下がり、三大神の下に位置づけられている。","note":"インドの闘神","exp":"310"}],"5248":[{"type":"化石","name":"ウマのようなゾウの骨","rank":"1","desc":"動物の頭部の骨。顔が長く、ウマに似ているが、ゾウのような牙も持っている。","note":"","exp":"160"}],"5761":[{"type":"宗教遺物","name":"テルマ","rank":"2","desc":"チベット仏教に伝わる聖典群。パドマサンバヴァらが後世のために様々な場所に隠した霊的な宝物とされる。","note":"2017.02.07新規追加","exp":""}],"1730":[{"type":"財宝","name":"ブルーフレイム","rank":"5","desc":"まばゆいばかりの見事な輝きを持つサファイヤ。大きさは1000カラット近くあり、並みの研磨技術ではこのような輝きは出せないという。吸い込まれるような美しいブルーで品質も最高クラスだ。","note":"いまだ見ぬ青","exp":"804"}],"887":[{"type":"海洋生物","name":"ゴンズイ","rank":"1","desc":"ドジョウやナマズに似た海水魚。背中に毒針を持つ。釣り上げたときにうっかり握ると大変なことになる。幼魚は群れて生活するため成魚より危険である。","note":"毒魚の地図","exp":"21"}],"2045":[{"type":"財宝","name":"七説話","rank":"2","desc":"ルーミーの著書。\nイスラムの説話をまとめたものと思われる。ルーミーは詩の形式で多くの著書を残しており、この話は散文形式で書かれている。","note":"多才な詩人、トルコ語が無くてもアラビア語で可","exp":"260"}],"5129":[{"type":"港・集落","name":"フランクフルト","rank":"1","desc":"神聖ローマ帝国の中心都市として発展した、ドイツ中西部に位置する街。名前の由来は5世紀にフランク王国がマイン川を渡る地点として選んだためとされる。バルトロメウス大聖堂は皇帝選挙の地と定められ、戴冠式も執り行われている。","note":"到達する","exp":"25"}],"1700":[{"type":"歴史遺物","name":"戦士の墓","rank":"5","desc":"ベイルートの郊外に埋もれていた墓。墓碑銘は刻まれているが、浸食のため読めなくなっている。周囲に錆びた武具が埋まっていたことから戦士の墓ではないかと思われる。","note":"アイン・ジャールートの戦い","exp":"1144"}],"1581":[{"type":"中型生物","name":"アシカ","rank":"2","desc":"アザラシに似た、黒い体毛の動物。生息地が温暖なので、アザラシよりスマートな体をしている。近い種類なのだろうか？","note":"褐色の海獣<br/><br/>発見時経験値220　発見物カード経験値110","exp":"220"}],"5185":[{"type":"港・集落","name":"堺","rank":"2","desc":"大阪湾に面した、交易の盛んな港街。商人たちの集まる、自由な気風の土地である。\nこの街の優れた経済構造に、日本の有力者も注目しているようだ。","note":"到達する","exp":"360"}],"630":[{"type":"小型生物","name":"カメレオン","rank":"3","desc":"50cm程度のトカゲ。まわりの色に合わせて体色を変えられる。興奮したときも変わるようである。樹上で生活しカエルのように舌を伸ばして昆虫類を捕らえる。足の指が2本ずつ向かい合っており、木にしがみつくのに便利なようだ。","note":"七変化するトカゲ","exp":"473"}],"411":[{"type":"小型生物","name":"ツメガエル","rank":"2","desc":"アフリカ南部に生息する、独特の姿をしたカエル。黒い爪があり、目が小さく埋まっていて、一般的なカエルとはかなり異なった容姿をしている。暑さが厳しい時期は、土に潜って夏眠する。","note":"奇妙なカエル","exp":"220"}],"3764":[{"type":"天文","name":"月面","rank":"1","desc":"古代から人類はさまざまな形を月の表面の模様に見出してきた。アリストテレスは月は完全な球体であるとしたが、ガリレオは望遠鏡で月を観測し、月の表面が滑らかでなく、凸凹があることを明らかにした。","note":"月の表面","exp":"100"}],"5884":[{"type":"海洋生物","name":"ホテイエソ","rank":"2","desc":"鱗のない体が特徴的な深海魚。長細い全身は真っ黒で、大きな口が上向きについている。下顎の先端からは長い髭が生えており、この髭や顎の周りを発光させることで、餌となる魚を誘い出すという。","note":"","exp":"380"}],"6139":[{"type":"宗教遺物","name":"ハデス像","rank":"1","desc":"ギリシャ神話の冥府の神の像。ハデスは冥府を治める厳格な神であると同時に、鉱物や宝石をつかさどる富の神としても知られる。","note":"冥府の王","exp":"90"}],"1689":[{"type":"海洋生物","name":"タンバキー","rank":"2","desc":"黒い魚体の魚。大きさは1mほどもある。ピラニアの仲間のようだ。","note":"釣り","exp":"250"}],"5718":[{"type":"気象・現象","name":"火山砕屑物","rank":"2","desc":"火山から噴出された石や泥などの総称。噴火後、空から舞い落ちることがある。火山弾などの場合、周囲に深刻な被害をもたらす可能性がある。","note":"2017.02.07新規追加","exp":"320"}],"2454":[{"type":"虫類","name":"オオムラサキ","rank":"3","desc":"東アジア各地に分布するチョウ。雄は、光沢のある青紫色の羽を持つ。\n飛翔能力に長け、近くにいれば羽ばたく音が聞こえるほどである。","note":"着物の意匠","exp":"460"}],"306":[{"type":"鳥類","name":"カワセミ","rank":"2","desc":"宝石のように輝く青い羽と、長くて鋭いくちばしが特徴。自分の見張り場所から水中に飛び込み、すばやく魚を捕らえる。まれに、空中で静止した状態から飛び込むこともある。","note":"ヨーロッパの宝石","exp":"355"}],"2489":[{"type":"地理","name":"蘭嶼島","rank":"2","desc":"台湾島の南東沖に浮かぶ離島。\n海水の浸食でできた大きな洞窟や、変わった形の岩など、見どころが多い。","note":"クエスト「島の手掛かり収集」<br/>発見物カード:190","exp":"380"}],"5613":[{"type":"化石","name":"頭頂部が丸いトカゲの骨","rank":"2","desc":"北米西部で見つかった巨大なトカゲのような生物の骨。頭頂部が、厚さ25cmあまりのドーム状の骨に覆われているのが特徴。","note":"","exp":""}],"5867":[{"type":"天文","name":"おうし座の星雲","rank":"5","desc":"星の爆発によって生まれたと思われる星雲。その爆発を目撃したと思われる記録が数百年前の世界各地に残っているため、その規模の大きさがうかがえる。","note":"クエスト「星の炎上」<br/>発見物カード:715","exp":"1430"}],"5880":[{"type":"天文","name":"北方七宿玄武","rank":"5","desc":"中国星座において、天の赤道を28に分割した二十八宿のうち北方の七宿をまとめたもの。みずがめ座やペガスス座などが含まれる。","note":"クエスト「残りの守護神獣」<br/>発見物カード:685","exp":"1370"}],"1446":[{"type":"中型生物","name":"コアラ","rank":"2","desc":"生涯のほとんどをユーカリの木の上で過ごす有袋類。子はある程度まで成長すると、親の背中につかまって過ごす。ユーカリの葉を主食とする。","note":"親の背で","exp":"330"}],"3377":[{"type":"地理","name":"ザグロス山脈","rank":"4","desc":"ホルムズの近くから、トルコの周辺までに及ぶ巨大な山脈。山脈内にはかつて栄えた王朝の遺跡が残る。\n伝説にある、洪水を免れることができた船はこの山脈のどこかに存在しているともいわれているが、真相は不明だ。","note":"古代伝承の山脈","exp":"700"}],"2098":[{"type":"財宝","name":"ディレム銀貨","rank":"2","desc":"ササン朝時代に製造された銀貨。\n表面に「右向きの王の胸像」、裏面には礼拝に使用された「聖なる火」が刻まれている。","note":"異国の古代通貨","exp":"250"}],"3850":[{"type":"地理","name":"スカン・グアイ","rank":"3","desc":"北米沿岸の島にある、先住民が暮らす村。彼らが作るトーテムポールには、シャチなどの海洋生物が模様として刻まれ、海に向けて立てられる。高さ10mにもなる巨大なトーテムポールもある。","note":"自然への敬意","exp":"460"}],"2849":[{"type":"美術品","name":"李迪の静物画","rank":"3","desc":"南宋の宮廷画家・李迪が描いた、花の絵画。花鳥画の中でも特に高評価を得たもののようだ。","note":"李迪の最高傑作","exp":"470"}],"5998":[{"type":"歴史遺物","name":"隠者ピエールの杖","rank":"1","desc":"11世紀末、民衆十字軍の中でも最大規模の集団を率いた修道士ピエールの杖。2万人以上の民衆軍は統率が取れず、トルコ軍に敗れて瓦解した。","note":"クエスト「民衆による十字軍」<br/>発見物カード:30","exp":"60"}],"1811":[{"type":"海洋生物","name":"ナイルアロワナ","rank":"2","desc":"ナイル川に生息するアロワナ。口が小さく黒鉄色の魚体が特徴である。","note":"釣り","exp":"250"}],"6801":[{"type":"歴史遺物","name":"ケダー・マーチャント号","rank":"3","desc":"インドの商船。1698年にウィリアム・キッドに略奪され、「アドベンチャー・プライズ」と名を変えて彼の船となる。キッドが捕らえられると、手下により船は焼き払われ、サントドミンゴより東のカタリーナ島付近で沈没したとされる。","note":"サルベージ<br/>発見物カード:265","exp":"583"}],"1274":[{"type":"美術品","name":"カピトリーノの雌狼","rank":"5","desc":"ローマ建国神話に登場するロムルス・レムス兄弟が狼の乳を飲む姿をかたどった青銅像。双子の像はアントニオ・デル・ポッライウォーロが最近付け加えたものだが、狼の像はエトルリア時代のものである。","note":"血塗られた建国者","exp":"1157"}],"1196":[{"type":"宗教建築","name":"チャックモール","rank":"2","desc":"チャックモールとは、「赤いジャガー」という意味。マヤの人々はこの像の腹部に生贄の心臓を乗せて、神に祈っていたという。","note":"生贄の像","exp":"230"}],"83":[{"type":"歴史遺物","name":"エクスカリバー","rank":"5","desc":"アーサー王伝説に登場する聖剣。アーサー王が湖の精霊から授かったと言われる。剣は鉄をも切り裂き、鞘は持ち主の傷を癒し不死にするという。","note":"エクスカリバー","exp":"1235"}],"6079":[{"type":"財宝","name":"袞龍袍","rank":"3","desc":"中国の歴代王朝において、皇帝が公の場に出る際にまとっていた宮廷用の服で「こんりゅうほう」と読む。幸福や長寿を祈る吉祥文様が全身にあしらわれ、特に皇帝だけが許された5本指の龍の刺繍が9カ所に入っている。","note":"","exp":"510"}],"1113":[{"type":"中型生物","name":"チンパンジー","rank":"1","desc":"黒くて人間よりひとまわり小さなサル。群れで生活し、かなり高い知能を持つようだ。道具を使う個体もおり、もしかしたら人間にかなり近い動物なのかもしれない。","note":"中型のサルの地図","exp":"185"}],"2764":[{"type":"宗教遺物","name":"洞窟のような墓地","rank":"2","desc":"地下に作られた墓地。カタコンベとも呼ばれローマにある教会のものが最初といわれる。シラクサにもいくつかのカタコンベがあり、大きいものは天然の洞窟を思わせる、入り組んだ構造が特徴的である。","note":"ダンジョン","exp":"240"}],"6648":[{"type":"伝承","name":"九尾の狐","rank":"5","desc":"東アジアに伝わる九本の尾の霊獣。優れた君主の治世を表す瑞獣とされている。一方で、絶世の美女に化け人をたぶらかす悪意ある個性も持ち合わせている。","note":"","exp":"1660"}],"121":[{"type":"宗教遺物","name":"ヘルメス像","rank":"1","desc":"ギリシャ神話の神像。ローマ神話ではメルクリウスやマーキュリーという。商人や羊飼いの守護神である一方、盗賊の神でもある。","note":"ギリシャの神像の地図","exp":"30"}],"1697":[{"type":"大型生物","name":"オランウータン","rank":"5","desc":"現地語で「森の人」を意味する。オスは成長するにつれて頬袋が大きくなり、あご髭が生えてくる。生活のほとんどが樹上で、食事・睡眠に加えて繁殖も樹上で行う。","note":"鳥の羽が運ぶもの","exp":"1228"}],"5270":[{"type":"歴史遺物","name":"パカル王のレリーフ","rank":"2","desc":"パレンケ王パカルが描かれたレリーフ。母サク・クックから王冠を受け取る姿を表す。わずか12歳で即位したパカル王は周囲の期待に応え、当時危機に瀕していたパレンケを見事に復興させた。","note":"マヤ低地　再調査報酬","exp":"380"}],"5015":[{"type":"港・集落","name":"アデン","rank":"1","desc":"アラビア半島の南端にある、歴史ある良港。中国・インドとイスラム・ヨーロッパ諸国の重要な交易中継点。乳香をはじめとする何種類もの香料や、コーヒーなどが産物。","note":"到達する","exp":"127"}],"5690":[{"type":"財宝","name":"カザンの大皿","rank":"3","desc":"金の大皿。「カザン」は「大皿」という意味である。かつてタタール人の王女が川に金の大皿を落としたことから、その地をカザンと呼ぶようになったという伝説がある。","note":"2017.02.07新規追加","exp":"460"}],"1237":[{"type":"宗教遺物","name":"ジャガー像","rank":"2","desc":"ジャガーは、メソアメリカでは力強きものの象徴として、神のように崇め奉られていた。非常に獰猛でどの動物よりも強く、生物界の頂点に立つと考えられている。","note":"俊足で獰猛な動物の像","exp":"290"}],"1882":[{"type":"財宝","name":"金細工の耳飾り","rank":"2","desc":"本国に届けられるはずだった、金で作られた耳飾り。この地域独特の細工が施されているため、ヨーロッパでの価値は高いだろう。","note":"［勅命］[[失踪した調査隊の追跡調査","exp":"310"}],"6633":[{"type":"宗教遺物","name":"ルターの95か条論題","rank":"5","desc":"マルティン・ルターによって提起された、カトリック教会に対する批判論文。教会の贖宥状販売による腐敗を看過できず、ルターが当地教会の門に貼りつけた。その影響は大きく西ヨーロッパ諸国のキリスト教分裂の原因となった。","note":"","exp":"830"}],"6841":[{"type":"中型生物","name":"クビワペッカリー","rank":"2","desc":"北米、南米に広く生息するイノシシに似た動物。適応能力が高く、森林や砂漠、山などにも生息している。全身の体毛は褐色か黒色。喉元から背中にかけて帯状に白い毛が生えており、首輪をしているように見えるため、この名がついた。","note":"発見物カード:195","exp":"390"}],"3774":[{"type":"天文","name":"おひつじ座","rank":"4","desc":"黄道十二星座の1つ。ボイオティア王の子、プリクソスとヘレを救うためにゼウスが遣わした黄毛の牡羊が天に昇った姿とされる。後にその毛皮を求めてイアソンがアルゴ船で探検に出た。","note":"天に輝く羊","exp":"790"}],"5713":[{"type":"気象・現象","name":"紅雪","rank":"2","desc":"雪や氷が赤く色付く現象。この現象に言及した記録は古くから存在するが、その原因などについて確たる情報はない。一説には酸化物が関係しているとされている。","note":"地図上の北部にいると南東方向とでるが、実際は南西の先っちょで視認","exp":"270"}],"1351":[{"type":"宗教遺物","name":"高僧の衣","rank":"5","desc":"ある徳の高い仏教僧の衣をはぎれにして縫いつけた法衣。仏教僧は財産を持つことを禁止されており、法衣すらそれにあたる。法衣は在家からの喜捨や先輩僧からの譲渡でまかなう。","note":"志を継ぐ者たち","exp":"1144"}],"3194":[{"type":"地理","name":"パラティーノの丘","rank":"2","desc":"ローマに位置する丘の一つ。古代ローマ時代の神殿や住居の跡があり、ローマの数ある丘の中でも最も歴史が古いと見られている。","note":"書きかけの地図","exp":"210"}],"5624":[{"type":"史跡","name":"スヴァネティの塔","rank":"3","desc":"コーカサス山脈の谷間にある、スヴァネティ地方の村々で見られる不思議な塔。建てられた年代によって、形状が少しずつ異なる。","note":"秘境に立つ塔","exp":""}],"3323":[{"type":"地理","name":"プレーリー","rank":"2","desc":"北米の中央部に広がる広大な草原。自生している草の丈は長めである。肥沃な土壌で、耕作に向いている。","note":"書きかけの地図","exp":"300"}],"3830":[{"type":"財宝","name":"式盤","rank":"5","desc":"東洋の占いの一種である式占で用いられる道具。円形の天盤と、方形の地盤で構成されている。二つの盤には文字や記号が記され、それらの配置を見ながら操作して、占いに必要な情報を得る。","note":"東洋の占い道具","exp":"1130"}],"1544":[{"type":"地理","name":"シャーク湾","rank":"2","desc":"オーストラリア西部に広がる湾。湾内の海水は塩分が非常に高いため、ある種の藻しか生息できない。\n他にも白色の貝殻のみで構成された砂浜があるなど、狭い地域でありながら、特異な環境が各所に見られる。","note":"奇怪な風景","exp":"330"}],"2270":[{"type":"宗教建築","name":"ナントゥワス","rank":"5","desc":"ナンマドール遺跡で最も立派な建造物。「首長の口の中」という名を持つ。神聖な場所であり、参道は高貴な者用と一般人用に分けられている。","note":"島の儀式","exp":"930"}],"5836":[{"type":"気象・現象","name":"レッドスプライト","rank":"4","desc":"雷雲からさらに上空に向けて発生する発光現象。特に赤いものをこのように呼称する。ただ、発生場所の見えにくさや発光時間の短さから観測例が少なくその詳細は謎に包まれている。","note":"夜　晴れ　書いている内容とは違いよく現れます。","exp":"650"}],"3291":[{"type":"地理","name":"スケリッグ・マイケル","rank":"3","desc":"アイルランドから西の沖合いにある孤島。\nアイルランドの言葉で「ミカエルの岩」を意味する。島自体が傾斜の激しい岩山であり、山頂付近には修道院がある。過去、ヴァイキングの襲来にも耐えたという。","note":"巡礼前の下調べ","exp":"500"}],"679":[{"type":"宗教遺物","name":"死海文書","rank":"5","desc":"死海写本とも言われる大量の旧約聖書の写本である。紀元前に存在した、ユダヤ教の一派であるクムラン宗団のものと思われる。ごく初期の聖書そのものであり、宗教学上の価値は計り知れない。","note":"信じるものたちの記録","exp":"1118"}],"6070":[{"type":"伝承","name":"世界の果て","rank":"3","desc":"カナリア諸島の南方にあるボジャドール岬。かつての船乗りたちにとって、その岬の先は未知の海域だった。溶岩が噴出する煮えたぎった魔の海…そんな迷信は、エンリケの勇敢な部下が岬越えを達成するまで船乗りたちを縛り続けた。","note":"伝承","exp":"420"}],"98":[{"type":"歴史遺物","name":"カエサルの黄金の杯","rank":"2","desc":"クレオパトラ7世からユリウス・カエサルに贈られたという、黄金の杯。エジプトはナイル川から砂金が取れたため、金が豊富だったといわれる。","note":"カエサルとクレオパトラ","exp":"250"}],"1988":[{"type":"海洋生物","name":"タマカイ","rank":"1","desc":"南太平洋およびインド洋に分布する、体長数メートルにも達する巨大なハタ。","note":"釣り","exp":"160"}],"2368":[{"type":"鳥類","name":"ウミネコ","rank":"1","desc":"日本近海に生息する海鳥。カモメの一種だが季節に合わせた大移動はしない。\n「ミャア、ミャア」と鳴く声がネコによく似ている。","note":"白い海鳥の地図","exp":"100"}],"6483":[{"type":"史跡","name":"ジンバブエ遺跡のアクロポリス","rank":"5","desc":"アフリカ南方にある石造の建造物群「ジンバブエ遺跡」。その遺跡は「大囲壁」と「谷の遺跡」、そして北側の丘にある「アクロポリス」と大きく3つの区域に分けられる。","note":"追究クエスト","exp":"1080"}],"5747":[{"type":"植物","name":"シベリアヒナゲシ","rank":"2","desc":"シベリアから極東地域に分布しているケシの一種。白や黄色の花を咲かせる。寒さに非常に強く、シベリアの冬も越せる。他のケシと同様、有毒性を持つ。","note":"","exp":""}],"2485":[{"type":"宗教遺物","name":"顕戒論","rank":"3","desc":"読みは、「けんかいろん」。日本の仏僧・最澄が著した書。\n平安時代における仏教制度の不平等性を批判し、自らの仏教思想の正当性を説いている。","note":"最澄という僧を知る","exp":"440"}],"3183":[{"type":"地理","name":"カボット海峡","rank":"1","desc":"北米北東部の沿岸に位置する海峡。幅はおよそ11kmであり、大西洋からセントローレンス湾内に進入できる海峡としては最も広い。","note":"書きかけの地図","exp":"140"}],"5587":[{"type":"史跡","name":"スウェット・ロッジ","rank":"4","desc":"北米の先住民族の間で広く使用されている、儀式用の小屋。薬草の香りを含んだ蒸気で室内を満たし、心身の浄化を行う。","note":"","exp":""}],"361":[{"type":"歴史遺物","name":"純金の小箱","rank":"5","desc":"ヴェルギナ遺跡から見つかった純金製の箱。表面にはマケドニアの紋章と見られる太陽の紋章が刻まれている。中には骨が入っており高貴な人物の遺骨と思われる。","note":"王家の紋章","exp":"816"}],"6816":[{"type":"歴史遺物","name":"サーチェ・リマーニ沈没船","rank":"3","desc":"11世紀ごろの商船。ビザンティン帝国とファティーマ朝でガラスなどの交易を行っていたとみられる。ロードス島に近いトルコ南西部のサーチェ・リマーニ湾付近で沈没した。","note":"サルベージ<br/>発見物カード:225","exp":"495"}],"6701":[{"type":"中型生物","name":"メインクーン","rank":"5","desc":"家猫の一種。寒冷地に生息するため、長い体毛を持つ。体調は1m以上もあるが、温順な性格のため、ジェントルジャイアントと呼ばれている。知能が高いと言われ、器用に前足で物を持ち上げたり、戸を開けたりする。","note":"","exp":""}],"1036":[{"type":"中型生物","name":"ムフロン","rank":"1","desc":"羊に似た動物。羊と同じような角があり、家畜の羊の祖先ではないかと思われる。非常に警戒心が強く、近づくのは難しい。","note":"「野生の羊の地図」<br/>発見物カード:6","exp":"12"}],"6980":[{"type":"宗教建築","name":"ビビハニム・モスク跡","rank":"5","desc":"サマルカンドの統治者であるティムールが、妃ビビ・ハニームの名をつけたとされるモスク跡。かつては世界最大規模とされ、屋根や壁には東西文化の融合を示す青いタイルがふんだんに使われていたという。","note":"発見物カード:700","exp":"1400"}],"718":[{"type":"歴史遺物","name":"ギルガメシュ叙事詩","rank":"5","desc":"古代メソポタミアの叙事詩。人類最古の文学と言える。ギルガメシュ王の冒険譚が語られているが、その中には洪水伝説の原型と思われる部分がある。","note":"星の宿る場所","exp":"1066"}],"6581":[{"type":"大型生物","name":"アラビアヒョウ","rank":"5","desc":"アラビア半島の山岳地帯に生息するヒョウの亜種。他の種と同様に夜行性。毛色は灰色がかった明るい色に、黒の斑点模様が際立ち、大変美しい。","note":"","exp":"500"}],"1587":[{"type":"史跡","name":"ウルル","rank":"5","desc":"オーストラリアの先住民アボリジニにウルルと呼ばれている、一枚岩でできた巨大な岩。アボリジニにとっては聖地である。ウルルには精霊が宿っていると考えられ、儀式の際は多くのアボリジニたちが集まる。","note":"砂漠の向こうの聖地","exp":"1027"}],"1345":[{"type":"鳥類","name":"ヤシオウム","rank":"1","desc":"熱帯雨林や、開けた森林などに生息する鳥。黒色の羽で覆われ、頬の部分には赤い皮膚が見える。頭頂部には長い冠羽がある。大きく丈夫なくちばしで、ヤシの実の固い殻なども割って食べることができる。","note":"黒い鳥の地図","exp":"140"}],"458":[{"type":"財宝","name":"金細工の甲冑","rank":"1","desc":"地金に金で装飾を施した甲冑。金は強度がないので、装飾、もしくは祭典用であろう。","note":"金細工の甲冑の地図","exp":"71"}],"652":[{"type":"地理","name":"マルタ島","rank":"1","desc":"イタリア半島とシチリア島の南に浮かぶ島。イタリアと北アフリカの間にあることから、支配勢力がしばしば変わった。先史時代から人が住んでいたようである。","note":"書きかけの地図","exp":"20"}],"1018":[{"type":"歴史遺物","name":"ハンニバルの大理石像","rank":"1","desc":"ハンニバルはカルタゴの将軍で、共和制ローマを攻めて功績があった。一時はイタリア半島まで攻め込んだが、ザマの戦いで大スキピオに敗れた。","note":"名将軍の采配","exp":"120"}],"6606":[{"type":"歴史遺物","name":"トゥシュトラの小像","rank":"5","desc":"先古典期後期に製作され、アヒルのような嘴と翼を持つ卵形の怪人像。ラ・モハーラの遺跡で発見されたものと\n同じ文字が彫られている。胸から腹にかけて長期暦の日付が刻まれ\nていることでも知られる。","note":"","exp":"1180"}],"6962":[{"type":"植物","name":"シロタエギク","rank":"2","desc":"地中海沿岸が原産の植物。日当たりの良いところに生えている。葉は白い繊毛で覆われ、寒さに強く、冬でも美しい姿を保つ。初夏には黄色い小さな花を咲かせる。","note":"","exp":""}],"6586":[{"type":"大型生物","name":"ガウル","rank":"4","desc":"インドなどに生息するウシ。現存するウシの中で最も大きいといわれている。草食性で普段は温厚だが、その巨躯からトラを倒すこともある。","note":"","exp":"690"}],"6842":[{"type":"地理","name":"メグナ川","rank":"5","desc":"ベンガル地方の東部を流れ、ベンガル湾へと注ぐ川。ガンジス川、ブラマプトラ川と合流し、広大な三角州を形成している。","note":"発見物カード:440","exp":"880"}],"5475":[{"type":"海洋生物","name":"クロカイマン","rank":"2","desc":"南米大陸中央部に生息する大型のワニ。全長は4～6mほどまで成長する。身体の色が黒いのが特徴。非常に獰猛で人間を襲うこともあるようだ。","note":"黒いワニの地図<br/><br/>発見時経験値270　発見物カード経験値135","exp":"270"}],"1958":[{"type":"歴史遺物","name":"祭事用の仮面","rank":"2","desc":"高貴な人の副葬品として、もしくは祭礼用の道具として用いられたと思われる仮面。メソアメリカではこういった仮面が多く見られ、材質は石・粘土・貝殻や宝石など、さまざまである。","note":"メソアメリカの祭器の地図","exp":"390"}],"6753":[{"type":"海洋生物","name":"ブラックマンタ","rank":"5","desc":"メラニズム現象によって黒色素が溜まり、黒化したオニイトマキエイ。発生の原因などについては、未だ究明されないままである。各地で目撃が報告されているが、ニューカレドニア島の近くでは遭遇率が高いようだ。","note":"追究クエスト<br/>発見物カード:780","exp":"1560"}],"2698":[{"type":"歴史遺物","name":"鴨形土器","rank":"2","desc":"動物をかたどってある土器。古代朝鮮の弁韓時代のものとされる。カモやウマのような動物から、家や船の形をしたものまであり、種類は実に豊富である。主に死者と共に墓に納めるために作られたらしい。","note":"鉄の国の歴史","exp":"370"}],"6616":[{"type":"財宝","name":"九鼎","rank":"5","desc":"古代中国における王権の象徴。伝説によれば中国最古の王朝「夏」の始祖である禹が、九つの州に命じて集めさせた青銅で鋳造したという。鍋釜のような三本足の金属器具で、祭器として使われた。","note":"レガシー美の叡智　左下","exp":"3150"}],"5760":[{"type":"地理","name":"死の領域","rank":"5","desc":"呼吸ができないほど空気が薄くなる高度。チョモランマほどの高山になれば、その苛酷さは命を落とすほど。登頂間近の登山者たちが、空気の薄さに倒れることも多いに違いない。","note":"高山の危険","exp":"1340"}],"6883":[{"type":"地理","name":"ロフォーテン諸島","rank":"3","desc":"ノルウェー海に連なる島群。氷河に削られた岩山が並ぶ。北極圏に位置しているが、気候は比較的温暖。そのためか、多くの海鳥が生息している。","note":"発見物カード:330","exp":"660"}],"1995":[{"type":"海洋生物","name":"プレコストムス","rank":"2","desc":"南米アマゾン川に生息する淡水ナマズ。吸盤状の口で、岩や流木に生えたコケを食べる。様々な体型や体色、斑紋の種類があり、独特の美しさを持つ。見た目によらず美味。","note":"釣り","exp":"360"}],"1728":[{"type":"財宝","name":"妖精のささやき","rank":"5","desc":"2000カラットをゆうに超える、巨大なオパール。透明感があり中まで美しくきらめいているのが見える。この石には妖精がすんでいて持ち主を気に入ると願いを叶えてくれるという伝説があるそうだ。","note":"妖精が住む宝石<br/><br/>発見時経験値1170　発見物カード経験値585","exp":"1170"}],"824":[{"type":"地理","name":"グレートフィッシャーバンク","rank":"1","desc":"北海中央付近の、広い浅瀬である。古くからよい漁場だったので、この名がある。","note":"誰でも釣れる浅瀬はないか","exp":"70"}],"5170":[{"type":"港・集落","name":"ランバイェケ","rank":"2","desc":"インカ帝国が栄える以前に繁栄していた文化の中心地。一年を通して温和な気候に恵まれているため、過ごしやすい。","note":"到達する","exp":"270"}],"3177":[{"type":"鳥類","name":"アメリカコガラ","rank":"2","desc":"北米の北部に生息する小鳥。\n危険に敏感で、危険度によって鳴き声を使い分け、他種の鳥にも知らせているらしい。","note":"小さな鳥の地図","exp":"230"}],"1515":[{"type":"宗教遺物","name":"観世音菩薩像","rank":"4","desc":"読みは、かんぜおんぼさつぞう。阿弥陀如来の脇侍としてそばに安置されることも多い。全てを救い、全てをかなえるといわれていることから、多くの顔と多くの腕を持つ非人間的に表現されることも多い。基本は一面ニ臂である。","note":"観世音菩薩像","exp":"624"}],"3175":[{"type":"地理","name":"ファーヴェル岬","rank":"2","desc":"グリーンランドの最南端に位置する岬。\nグリーンランドは大部分が氷雪に覆われた土地だが、夏にはこうした岬などの沿岸部で大地を目にすることができる。","note":"書きかけの地図","exp":"240"}],"6500":[{"type":"歴史遺物","name":"ゼウスの錫杖の金鷲像","rank":"2","desc":"オリンピアの巨大なゼウス像が手に持つ錫杖についていたとされる金の鷲の像。この彫像は世界の七不思議の一つに数えられている。鷲はゼウスの象徴であり、ゼウスが鷲に変身した神話も伝わっている。","note":"","exp":"280"}],"3150":[{"type":"宗教建築","name":"ノートルダム大聖堂","rank":"2","desc":"聖母マリア崇拝に基づいて建立されたキリスト教の聖堂。「ノートルダム」とはフランス語で「我らの貴婦人」という意味であり、イエスの母・マリアを指す。同名の聖堂がフランス語圏の各地に建てられている。","note":"聖母に捧ぐ大聖堂","exp":"400"}],"5573":[{"type":"天文","name":"しぶんぎ座流星群","rank":"1","desc":"しぶんぎ座の方角から飛び出すように現れる流星群。年に一度、数時間だけ活発な動きを見せる。","note":"「天文学者の観測記録」<br/>発見物カード:95","exp":"190"}],"5091":[{"type":"港・集落","name":"ダブリン","rank":"1","desc":"アイルランド最大の都市である。かつてヴァイキングが砦を築き、その後城が築かれた。ダブリンという名は「黒い水たまり」という意味である。産物は豚の加工品やウイスキーのほか、石炭や石墨を産出する。","note":"到達する","exp":"22"}],"5834":[{"type":"財宝","name":"ドンブラ","rank":"5","desc":"カザフ地方でよく演奏される木製の弦楽器。二本の弦を指で弾いて音を鳴らす。単独で弾いたり、叙事詩を歌う伴奏として用いられたりする。","note":"","exp":"1340"}],"5369":[{"type":"歴史遺物","name":"ナルメル王のパレット","rank":"5","desc":"浮き彫りが施された盾状の黒い石。大きさから儀式用と思われる。浮き彫りの中には、敵と戦うナルメル王とおぼしき人物がある。","note":"","exp":""}],"572":[{"type":"地理","name":"インド洋","rank":"2","desc":"インドとアフリカに接する、広大な海域。インドからアフリカへの交易路である。インドの南部にはひたすら海原が広がるばかりである。","note":"広大な海原","exp":"260"}],"2001":[{"type":"美術品","name":"音楽の稽古","rank":"3","desc":"フェルメール作。彼はこの作品で透視図法による構図の歪みを克服しようとした。楽器に向かう女性は、上部の鏡では隣の男性のほうへ顔を向けているように見える。ヴァージナルには「音楽は喜びの伴侶、悲しみの薬」と書かれている。","note":"フェルメールの試行錯誤","exp":"510"}],"190":[{"type":"鳥類","name":"ホウオウジャク","rank":"5","desc":"自分の体長ほどの、長い尾を持った鳥。ただし、メスはオスの半分くらいの長さである。","note":"その驚くべき姿","exp":"910"}],"2617":[{"type":"歴史遺物","name":"月形石柱","rank":"5","desc":"台湾島の古代文化の集落があった場所に残されていた、厚さ20cmほどの柱。\n祭祀用の石であったとの説や、建築物の壁であったという説など、諸説ある。","note":"大地にたたずむ石柱","exp":"1210"}],"3629":[{"type":"レリック","name":"イタリアの盾","rank":"","desc":"ハンニバルの恐るべき用兵を、戦略で封じ込めた知将ファビウス。だが、ローマの勝利を見ることなく没したという。","note":"","exp":""}],"3617":[{"type":"大型生物","name":"ホッキョクグマ","rank":"4","desc":"北極圏などに生息する全身が白いクマ。\n他のクマよりも頭部が小さく、首が長い。基本的には陸上で活動するが、まれに泳ぐ姿も見られる。","note":"クエスト「氷の地のクマ」<br/>発見物カード:365","exp":"730"}],"2339":[{"type":"歴史遺物","name":"弥生土器","rank":"1","desc":"日本で発見された、薄くて堅い土器。模様や装飾が控えめで、実用的な外観を持つ。\n調理や貯蔵など多岐に渡って使われ、用途に合わせて多様な形のものが作られている。","note":"古代の道具の地図","exp":"140"}],"5341":[{"type":"海洋生物","name":"ハダカイワシ","rank":"2","desc":"夜になると海面近くまで上がってくる深海魚で、体の表面に発光器を持つ。鱗がはがれやすく、網などで船に上げるとほとんど残っていないため、この名がついた。","note":"","exp":"320"}],"2486":[{"type":"歴史遺物","name":"金銅製の骨蔵器","rank":"2","desc":"飛鳥時代以降に作られた骨蔵器の一つ。金銅製の器の中に、遺骨が納められている。\n蓋や本体に銘文が刻まれており、故人を偲ぶことができる。","note":"優れた官人の軌跡","exp":"310"}],"5802":[{"type":"史跡","name":"ドゥッガ","rank":"5","desc":"北アフリカに残るローマ、ビザンツ時代の遺跡。「防衛する」を意味する「トゥッガ」という言葉が名前の由来だとされる。神殿や浴場、劇場があった形跡もあり、当時の繁栄が窺える。","note":"","exp":"1400"}],"6270":[{"type":"鳥類","name":"ステラーカケス","rank":"1","desc":"カナダから北米西岸にかけて生息する鳥で、山岳地帯に多く見られる。\n雑食性で果実や虫、鳥の卵などを食べる。頭に黒く立派な冠羽を生やしているが、首から下の羽毛は鮮やかな青で、鳴き声はやや騒がしい。","note":"","exp":"130"}],"6015":[{"type":"財宝","name":"マビノギオン","rank":"2","desc":"ウェールズに古くからある伝承を一冊にまとめた写本。\n古い神話を元にしたといわれる「マビノギ四枝」や、アーサー王伝説の原型とされる「アルスルの宮廷の三つのロマンス」などが収められている。","note":"","exp":"360"}],"6737":[{"type":"天文","name":"ミルファク","rank":"5","desc":"ペルセウス座で最も明るい星。黄白色に輝いて見える。名前はアラビア語で「ひじ」を意味する。かつては「わき腹」を意味するアルゲニブの名で呼ばれていた。","note":"発見物カード:560<br/>北大西洋","exp":"1120"}],"2929":[{"type":"財宝","name":"雷切","rank":"4","desc":"落ちてきた雷を切り、持ち主の身を守ったといわれる日本の刀。名匠の手により造り出された、切れ味抜群の名刀である。刀身には雷を切ったらしき痕跡が残っている。","note":"雷を切り裂く刃","exp":"660"}],"5710":[{"type":"天文","name":"アルゴ座","rank":"5","desc":"ギリシア神話に登場するアルゴ船をモチーフをした星座。あまりに巨大な星座だったためいくつかに分割されてしまった。","note":"※説明文の「モチーフ『を』した」は、原文ママです。","exp":"1300"}],"2097":[{"type":"宗教遺物","name":"ダニエル書補遺","rank":"5","desc":"最古の推理小説ともいわれる、カトリックの正典の一部。「アザルヤの祈りと三人の若者の賛歌」「スザンナ」「ベルと竜」の3つの短編からなる。著者は不明。","note":"貴族のわがまま","exp":"820"}],"6330":[{"type":"宗教建築","name":"エレファンタ寺院","rank":"2","desc":"インド洋の北西部に浮かぶエレファンタ島にある寺院。岩山を削って作られ、ヒンドゥー教のシヴァ神が祀られている。島に作られていた石像は銃の練習台に使われたため、損傷が激しい。","note":"壊れた寺院の地図","exp":"320"}],"5626":[{"type":"宗教遺物","name":"クマン人の石像","rank":"1","desc":"黒海やカスピ海の北部に広がる草原地帯に居住していた遊牧民族が作った石像。先祖をかたどったものではないかといわれている。","note":"","exp":"150"}],"3914":[{"type":"天文","name":"ガリレオ衛星","rank":"2","desc":"木星の周囲を回る四つの衛星を指す。ガリレオ衛星は5等星から6等星程度の明るさで、単独であれば肉眼でも見えるはずだが、木星があまりに明るいために見られない。","note":"「木星の観測記録」<br/>発見物カード:120","exp":"240"}],"6944":[{"type":"天文","name":"フム・アル・サマカー","rank":"3","desc":"うお座のベータ星。青白く輝き、西の魚の口部分に位置している。名はアラビア語で「魚の口」を意する。","note":"発見物カード:250","exp":"500"}],"5631":[{"type":"財宝","name":"ロシアンカーフ","rank":"4","desc":"18世紀頃にロシアで生産されていた皮革。トナカイの皮をなめした後に型押しし、木から抽出した油などを塗って仕上げてある。型押しで出来た小さな菱形の凸凹と、独特の仕上げ材の香りが特徴。","note":"","exp":"710"}],"3174":[{"type":"地理","name":"ロングレンジ山脈","rank":"1","desc":"北米北東部沿岸の、テラ・ノヴァ西部に位置する山脈。北米大陸の東側に横たわるアパラチア山脈の北端にあたる。","note":"書きかけの地図","exp":"140"}],"3632":[{"type":"美術品","name":"イコノスタシス","rank":"2","desc":"イコンで覆われた壁。聖堂内の各所に配置される。\n配置される位置によって、イコンに描かれる絵柄も異なる。","note":"豪華な壁の地図","exp":"380"}],"2018":[{"type":"宗教遺物","name":"神官の首飾り","rank":"2","desc":"神官のみが着けることを許されるという首飾り。細工が細かく、美術的価値も高いが、信仰的要素が大きい。","note":"［勅命］[[黄金郷の信仰","exp":"310"}],"6290":[{"type":"地理","name":"ハレマウマウ火口","rank":"5","desc":"ハワイ島にあるキラウエア火山の火口。ハワイ神話にて、火山の女神「ペレ」が住む所とされている。","note":"","exp":"1060"}],"3648":[{"type":"美術品","name":"銅の手桶","rank":"5","desc":"12世紀頃に作製されたらしい銅製の桶。\nこの桶が作製されたであろう地域の名前と、年代が刻まれているが持ち主は不明だ。","note":"壺の正体","exp":"820"}],"254":[{"type":"財宝","name":"孔雀石の小箱","rank":"1","desc":"ハンブルクの工房で作られた、宝石細工の美しい小箱。職人が、娘を助けてくれた恩人に報いるために丹念に作った、真の宝だ。","note":"ハンブルクのマイスタージンガー","exp":"150"}],"5366":[{"type":"財宝","name":"大イノシシの牙","rank":"4","desc":"巨大なイノシシの牙。古代のイノシシ狩りの戦利品と思われる。\nギリシャ神話のカリュドーンのイノシシ狩りのエピソードではイノシシ狩りが伴う危険と名誉が描かれている。","note":"神話における狩り<br/><br/>発見時経験値690　発見物カード経験値345","exp":"690"}],"5939":[{"type":"史跡","name":"シエガ・ベルデの岩絵遺跡群","rank":"2","desc":"ポルトガル北部のコア渓谷からイスパニア西部のシエガ・ベルデにかけて広がる遺跡。数千に及ぶ線刻画で動物や人などが描かれている。二万年前から存在していると見られ、この地域の野外にある古代の岩絵としては最大規模である。","note":"","exp":"210"}],"3725":[{"type":"財宝","name":"色あせた海賊旗","rank":"5","desc":"ある海賊船の旗のようだ。海賊旗は海賊たちにとって乗組員を識別するためのものであり誇りでもあるという。","note":"海賊の象徴","exp":"1190"}],"1506":[{"type":"化石","name":"魚の形をした石","rank":"1","desc":"二匹の魚がつながっているように見える石。魚がこのような状態になるにはどれほどの月日が必要なのか。","note":"魚の石の地図","exp":"110"}],"6619":[{"type":"宗教遺物","name":"ベケットの聖遺物箱","rank":"2","desc":"イングランド教会の聖人トマス・ベケットの遺物が入っていたとされる製遺物箱。外側には、ベケットが騎士に襲われ殉死する場面が描かれている。","note":"","exp":"360"}],"5264":[{"type":"天文","name":"リギル・ケンタウルス","rank":"2","desc":"ケンタウルス座にある1等星。ケンタウルス座の足にあたる位置にあり、星の名も「ケンタウロスの足」を意味する。","note":"「明るい星の観測記録」<br/>発見物カード:115","exp":"230"}],"2537":[{"type":"小型生物","name":"ムクカジカガエル","rank":"2","desc":"主に台湾島に生息するカエル。口の端から両目、両目から背中の間に三角模様を持つ。\n環境に応じて、淡い褐色から黒褐色まで体色を変化させる。","note":"「三角模様のカエルの地図」<br/>発見物カード:120","exp":"240"}],"2501":[{"type":"地理","name":"雪山山脈","rank":"1","desc":"台湾島を南北に走る山脈。多くの古道が発見されている。\n中には、先住民のタイヤル民族が使用している通路もあるようだ。","note":"民族調査の手助け","exp":"180"}],"1979":[{"type":"大型生物","name":"ビクーニャ","rank":"2","desc":"アンデスの高地に生息する褐色の動物。姿はラクダに似ているが、体長が1.5mと小柄で、首の付け根から白くて長い髭のような毛が生えている。細くてとても柔らかな体毛は希少価値が高く、珍重されている。","note":"グアナコに似た動物","exp":"360"}],"1562":[{"type":"地理","name":"サンホルヘ湾","rank":"1","desc":"南米南東岸にある半円形の湾。西からの強い風と寒流により、気温は年中低温である。大陸側には、荒涼とした低温地帯が広がっている。","note":"書きかけの地図","exp":"90"}],"2901":[{"type":"植物","name":"ウンナンサクラソウ","rank":"2","desc":"中国南部で見つかった淡い紫色や桃色の花を咲かせる植物。\n長い期間、花が咲いており、香りも良い。\n春を告げる花という意味で、報春花とも呼ばれる。","note":"街娘のための花探し<br/><br/>発見時経験値280　発見物カード経験値140","exp":"280"}],"1664":[{"type":"植物","name":"ウツボカズラ","rank":"3","desc":"袋がいくつもある植物である。袋の中には液体がたまっていて、中に落ちた虫が溶けてしまった。養分にしているのだろうか。これが巨大化したら、人間が溶かされるのでは…。","note":"虫取り草","exp":"462"}],"1310":[{"type":"地理","name":"マール山脈","rank":"1","desc":"南米南部東岸にある山脈。海からの風をさえぎるようにそびえ立っている。","note":"書きかけの地図","exp":"190"}],"2896":[{"type":"地理","name":"武夷山","rank":"2","desc":"茶葉が採れる木が自生する、暖かな気温を保つ山。\n宋代の遺跡や、朱子学の開祖が使用した書院などが残っている。","note":"書きかけの地図","exp":"230"}],"5300":[{"type":"中型生物","name":"イボイノシシ","rank":"1","desc":"サハラ以南のアフリカで見られる動物。見た目がイノシシに似ており、目の下と頬に一対ずつのイボがあることからこの名がついた。尻尾を立てて全力疾走する姿はなんとも言えない愛嬌がある。","note":"","exp":"130"}],"1803":[{"type":"大型生物","name":"ヨーロッパバイソン","rank":"1","desc":"欧州の深い森に棲む、大型の陸上動物。ウシに似ているが、体高が2m弱とウシよりも大きい。草原や水辺の多い場所、丘陵などで見られる。太古から狩猟の対象となっていた。長年の狩猟と森林伐採により、数が減少している。","note":"牛に似た生物","exp":"200"}],"6829":[{"type":"大型生物","name":"ベンガルトラ","rank":"5","desc":"インドに生息する大型の肉食獣。夜行性で、森林や草原を中心に活動する。茶褐色の体毛に独特の黒い縞模様を持つ。体毛が白く変異した白変種はホワイトタイガーと呼ばれ、各地で神の使いとして崇められた。","note":"追究クエスト<br/>発見物カード:475","exp":"950"}],"2790":[{"type":"化石","name":"首と尾の長いドラゴンの骨","rank":"2","desc":"重慶付近で見つかった細長い生物の骨。首と尾の長さが目立つ。\n泳ぎに適していそうな手と足を持っているが足の大きさから、陸地を歩いていたのかもしれない。","note":"ドラゴンの妙な特徴","exp":"250"}],"5848":[{"type":"美術品","name":"ササン朝の水晶の壺","rank":"5","desc":"12世紀のフランス王ルイ7世が、王妃アリエノールより贈られたとされる壺。ササン朝時代に作られたと思われる水晶の壺に、フランスで金細工を施した金具が加えられ、現在の形になった。","note":"","exp":"1330"}],"5373":[{"type":"史跡","name":"グイマーのピラミッド","rank":"5","desc":"カナリア諸島のテネリフェ島にある、長方形の階段状ピラミッド。積み上げられた石には加工が施されているが誰がなんの目的で作ったかは謎である。","note":"","exp":""}],"1442":[{"type":"中型生物","name":"ワラビー","rank":"2","desc":"太い尾と大きな後ろ足を持つ有袋類。袋に子を入れ、一度の跳躍で数mも移動する。夜間に果実などを食べ、大きな群れで生活する。","note":"追跡せよ","exp":"325"}],"6120":[{"type":"植物","name":"リュウケツジュ","rank":"5","desc":"竜血と呼ばれる樹脂を分泌する樹木で、幹の一定の高さから無数の枝を伸ばしているのが特徴的。インド洋にあるソコトラ島産の竜血が古代より有名だが、アフリカのカナリア諸島周辺にも竜血が採れる近縁種があるらしい。","note":"","exp":"970"}],"331":[{"type":"宗教遺物","name":"ロンギヌスの槍","rank":"5","desc":"イエスがゴルゴタの丘で処刑された際に、死亡を確認するために突き刺されたという槍。ロンギヌスというのは刺した兵士の名。本物かどうか、証明する手立てはない。","note":"ロンギヌスの槍","exp":"1040"}],"5652":[{"type":"天文","name":"ポンプ座","rank":"2","desc":"ラカーユが制定した南天の星座のひとつ。真空のポンプをモデルにしている。","note":"クエスト「続・科学の星座」<br/>発見物カード:190","exp":"380"}],"6045":[{"type":"歴史遺物","name":"七部法典","rank":"2","desc":"カスティーリャ王アルフォンソ10世の時代に編纂された法律書。古代ローマやビザンツ帝国の法典、教会法などを下敷きとして作られ、これによって先代に統合された旧レオン王国との習慣の不一致をなくすことに成功した。","note":"","exp":""}],"5174":[{"type":"港・集落","name":"リマ","rank":"2","desc":"ヨーロッパ人がインカ帝国調査の足掛かりとして作った開拓地。数多くの航海士がこの街を訪れ、交易の拠点ともなっている。","note":"到達する","exp":"265"}],"2288":[{"type":"宗教建築","name":"階段のレリーフ","rank":"4","desc":"コパン王朝の歴史が絵文字で記されているという巨大な階段。\n川の氾濫に巻き込まれたためか損傷が酷く、段差がちぐはぐになっている。描かれている絵文字を解読するには手間がかかりそうだ。","note":"クエスト「刻まれた歴史」<br/>発見物カード:315","exp":"630"}],"5143":[{"type":"港・集落","name":"ホバート","rank":"2","desc":"オーストラリア南部の島、ヴァン・ディーメンズ・ランドの南岸にある街。ダーウェント川の河口に位置し、立地条件の良さから、漁業基地としての機能を持つに至った。","note":"到達する","exp":"380"}],"3547":[{"type":"レリック","name":"プレステ・ジョアン","rank":"","desc":"オン・ハンの率いたケレイト族にはキリスト教徒が多かったという。それゆれにプレステ・ジョアンの伝説に取り込まれたのだろう。","note":"","exp":"3050"}],"3691":[{"type":"海洋生物","name":"アカシマシラヒゲエビ","rank":"2","desc":"カリブのサンゴ礁域に生息するエビの一種。背中にある一本の白い筋と、それを挟む二本の赤い筋が、鮮やかな縞模様になっている。","note":"鮮やかな色のエビの地図","exp":"320"}],"770":[{"type":"歴史遺物","name":"骨角器","rank":"1","desc":"「こっかくき」。動物の骨や角を削って作った先史時代の道具。骨は刃物にできないが、矢じりや槍、針にはよい。また、護符や装飾品などにもよく用いられた。","note":"先史時代の史跡の地図","exp":"26"}],"5514":[{"type":"地理","name":"タプー島","rank":"3","desc":"アンダマン海に面したパンガー湾にある海食柱。石灰岩でできており、長い時間をかけて雨や波に浸食され、今の形となった。","note":"","exp":""}],"2802":[{"type":"小型生物","name":"キノガーレ","rank":"2","desc":"中国南部に生息する、カワウソのような姿をした動物。\n白くて長いひげは、口の周りから目の後ろまでびっしりと生えている。","note":"ヒゲまみれの顔","exp":"320"}],"5629":[{"type":"天文","name":"けんびきょう座","rank":"2","desc":"ラカーユが制定した南天の星座のひとつ。科学実験などに使われる顕微鏡の形を表している。","note":"クエスト「科学の星座」<br/>発見物カード:175","exp":"350"}],"6489":[{"type":"美術品","name":"大理石の彫刻円柱","rank":"5","desc":"巨大な白大理石の円柱の一部。エフェソスにあった巨大神殿の柱とされる。側面は神話を題材にした見事な浮彫りが施されている。鮮やかな着色がされていたようだが、年月が経て薄れたのに加え、故意に落とされた形跡もある。","note":"レガシー女神信仰の地エフェソス　右下","exp":"2550"}],"5141":[{"type":"港・集落","name":"ペグー","rank":"2","desc":"ベンガル湾の東岸に位置する街。東南アジアに住む民族のひとつ、モン人により建造された街であり、ペグー朝の首都でもある。","note":"到達する","exp":"303"}],"908":[{"type":"植物","name":"スノードロップ","rank":"1","desc":"別名、マツユキソウ。白い花弁の可憐な花をつける。雪が解けるころに咲くため、春を告げる花だとされる。","note":"白い花の地図","exp":"49"}],"584":[{"type":"財宝","name":"ターコイズの護符","rank":"2","desc":"巨大なターコイズをはめ込んである護符。ターコイズはさまざまな文明で護符とされていた。","note":"豪華な宝石細工の地図","exp":"240"}],"6875":[{"type":"大型生物","name":"ジャワサイ","rank":"4","desc":"東南アジアやインドの密林に生息する、サイの一種。他のサイと比べて小柄で。皮膚がたるんで重なっており鎧のように見える。オスと比べて、メスは角が発達しにくい。","note":"発見物カード:350","exp":"700"}],"5590":[{"type":"海洋生物","name":"スベスベマンジュウガニ","rank":"3","desc":"インド洋から太平洋西部にかけて分布する小型のカニ。滑らかで丸い甲が特徴。毒を持っており、その成分や量は生息場所によって異なる。","note":"クエスト「お菓子のようなカニ」<br/>発見物カード:275","exp":"530"}],"5329":[{"type":"歴史遺物","name":"チョンゴニの岩絵","rank":"2","desc":"アフリカ南東部の広い範囲にある洞窟や岩に描かれた絵。特に狩人が描かれた絵は非常に古く、長く儀式の場として用いられてきたようである。","note":"","exp":""}],"3303":[{"type":"地理","name":"ビュート","rank":"4","desc":"巨大な柱のような形状の地形。テーブル状の台地であるメサが、さらに浸食されて孤立したもの。北米の西部で多く見られる。","note":"そそり立つ岩柱","exp":"680"}],"154":[{"type":"大型生物","name":"ヒトコブラクダ","rank":"1","desc":"背中のコブが一つのラクダ。家畜として飼われ、乗用や荷役などに使われる。砂漠地帯では必要不可欠な動物である。","note":"コブのある動物の地図","exp":"11"}],"3545":[{"type":"レリック","name":"カール・マルテル","rank":"","desc":"カール・マルテルがトゥール・ポワティエ間の戦いに敗れていたら、ヨーロッパの歴史はどうなっていただろうか。","note":"","exp":""}],"2710":[{"type":"海洋生物","name":"カムルチー","rank":"2","desc":"朝鮮半島から中国まで広範囲に分布する、肉食系の大型淡水魚。水草の多い池や沼に生息する。\n大きな口と、鋭い歯を持っている。","note":"大きな魚の地図","exp":"230"}],"3267":[{"type":"中型生物","name":"アザワク","rank":"4","desc":"西アフリカに生息する犬。足や尾が細長いながらも、筋肉は発達しているらしく、身体能力は高い。","note":"砂漠の狩猟犬","exp":"620"}],"5147":[{"type":"港・集落","name":"ポルトベロ","rank":"2","desc":"中米、南米との交易の中継地としての役割を果たす、カリブ海に面する港町。ポルトベロとは「美しい港」という意味である。","note":"到達する","exp":"244"}],"5005":[{"type":"天文","name":"レア","rank":"5","desc":"タイタンに次いで発見された土星の衛星。土星の衛星の中ではタイタンに次いで大きい。","note":"発見物カード:410","exp":"820"}],"6937":[{"type":"天文","name":"マルカブ","rank":"2","desc":"ペガスス座のアルファ星。白く輝く2等星。秋の四辺形を構成する星の1つ。名はアラビア語で「馬の肩」を意味する。","note":"発見物カード:130","exp":"260"}],"3000":[{"type":"地理","name":"アウター・バンクス","rank":"2","desc":"北米東端に並ぶ半島および砂州の連なり。南北に500km以上も延びている。この周辺海域は二つの海流がぶつかるため、航海は困難を極める。","note":"「書きかけの地図」<br/>発見物カード:130","exp":"260"}],"3743":[{"type":"歴史遺物","name":"元朝秘史","rank":"5","desc":"モンゴルの歴史書。著者は不明。\nチンギス・ハンの生き様を中心に、後継者であるオゴデイの治世にも一部触れている。","note":"元朝の歴史書","exp":"1200"}],"2554":[{"type":"財宝","name":"北投石","rank":"3","desc":"台北で産出される鉱石の一種。薬石として高い医療効果が期待されており、あらゆる疾病に有効であるといわれている。","note":"ダンジョン","exp":"510"}],"2969":[{"type":"植物","name":"ウェルウィッチア","rank":"5","desc":"ナミブ砂漠に生息する巨大な植物。葉の幅は約1.5mで、その長さは3～4mにも及ぶ。寿命が大変長く、数百年は生きるといわれる。","note":"奇想天外な植物","exp":"1190"}],"3200":[{"type":"鳥類","name":"パフィン","rank":"5","desc":"北米東岸の北部やヨーロッパ北部の沿岸で見られる海鳥。繁殖期になると目の周りにツノのような模様が現れることから、「ツノメドリ」とも呼ばれる。一見ペンギンのような容姿をしているが、飛ぶことができる。","note":"空飛ぶペンギン","exp":"820"}],"6976":[{"type":"化石","name":"鳥のような足跡のある石","rank":"2","desc":"鳥の足跡に似た痕跡がある化石。四本の指の跡がはっきりと見てとれるが、果たしてどのような姿をしていたのだろうか？","note":"発見物カード:130","exp":"260"}],"3645":[{"type":"史跡","name":"アルタイ山脈の岩刻絵群","rank":"5","desc":"ザナドゥの周辺で見られる、岩に刻まれた動物たちの絵。羊や馬、ヤギなどの動物や、動物を追う狩人の姿が描かれている。古代の人々の生活の様子を垣間見れる貴重な遺跡。","note":"山壁の絵","exp":"830"}],"1783":[{"type":"地理","name":"ブエナベントゥラ湾","rank":"1","desc":"パナマの南、南米の北西岸に位置する湾。湾の南部にはマングローブの林が存在する。南からの冷たい海流は、湾の以南で西に流れを変えるため、水温は比較的高い。","note":"「書きかけの地図」<br/>発見物カード:70","exp":"140"}],"2735":[{"type":"歴史遺物","name":"瞻星台","rank":"2","desc":"読みは、「せんせいだい」。新羅時代の末期に建てられたといわれる塔のようなもの。\n言い伝えでは、これは天文台であるらしく、占星術などに使われていたという。","note":"謎の塔の歴史","exp":"350"}],"7015":[{"type":"天文","name":"カウス・アウストラリス","rank":"3","desc":"いて座で最も明るい2等星。ケンタウロスが構える弓の南側に位置し、「弓」を意味するアラビア語と「南」を意味するラテン語を組み合わせて名づけられた。","note":"バミューダ諸島沖視認","exp":""}],"5852":[{"type":"美術品","name":"鳥のカリグラフィー","rank":"5","desc":"鳥の形をしたカリグラフィー。意味のある言葉で構成されているが象徴性が強く、文字として読むことは困難である。","note":"","exp":"1360"}],"5099":[{"type":"港・集落","name":"トリポリ","rank":"1","desc":"紀元前から栄えた古い街。時代によって、さまざまな名で呼ばれていた。十字軍の時代、十字軍の攻撃を避けるため、旧市街を放棄して内陸寄りに新しい街が築かれたという。産物は農作物のほか、繊維や医薬品である。","note":"到達する","exp":"36"}],"352":[{"type":"歴史遺物","name":"ツタンカーメン王の黄金のマスク","rank":"5","desc":"古代エジプトのツタンカーメン王の墳墓から出土した、純金のマスク。ラピスラズリなどで豪華な装飾が施されている。その上には、矢車菊の花束が添えられていた。","note":"永遠の矢車菊","exp":"1131"}],"6504":[{"type":"虫類","name":"クジャクグモ","rank":"4","desc":"オーストラリアの特定の地域に生息されるとされるクモ。オスは腹部にあるきれいでカラフルな腹膜を広げ、踊るようにメスに求愛行動をとる。","note":"","exp":"760"}],"5346":[{"type":"天文","name":"トリトン","rank":"5","desc":"海王星の衛星。太陽系でも屈指の大きさを誇る。\n海王星の自転方向と逆に公転しているのが特徴。\nそのため、次第に公転速度が落ちていき、遠い将来には海王星にぶつかると考えられる。","note":"発見物カード:655","exp":"1310"}],"78":[{"type":"美術品","name":"行列寓意図飾杯","rank":"1","desc":"「ぎょうれつぐういずしょくはい」。ヴェネツィアの工房で作られたという器。瑠璃色のガラス器にエマイユが施されている。ガラスのエマイユ技術は、ヴェネツィアで多用された。これほどの作品はヴェネツィアでなければ作れないだろう。","note":"ヴェネツィアのガラス細工","exp":"105"}],"3196":[{"type":"中型生物","name":"ニューファンドランド","rank":"4","desc":"北米北東部沿岸の、テラ・ノヴァを原産とする犬。\n大型で寒さに強く体力もある上に、泳ぎが得意であるため、漁師の作業を手伝うなど漁業犬として活躍する。","note":"漁師の相棒","exp":"680"}],"2615":[{"type":"財宝","name":"鄭氏の印","rank":"4","desc":"「鄭氏」と刻まれた金属製の印。\n鄭氏が貿易の際に認印として使用していたものと思われる。","note":"鄭成功についての再調査","exp":"800"}],"2076":[{"type":"歴史遺物","name":"鄭和の航海誌","rank":"2","desc":"明の提督・鄭和の航海誌。鄭和は七度航海を行い、アフリカからキリンを持ち帰るなどした。この航海誌は散り散りになったものの一部で、内容を全て把握することはできない。","note":"鄭和の航海誌 / 香料諸島方面進出の指標(勅命クエ)","exp":"360"}],"2441":[{"type":"宗教遺物","name":"プタハ像","rank":"2","desc":"古代エジプトの神の一つ。職人の守護神。闇や冥界の神とも呼ばれる。アブ・シンベル神殿の至聖所は、この像にのみ光が当たらない構造になっている。","note":"ダンジョン","exp":"300"}],"5065":[{"type":"港・集落","name":"サントメ","rank":"1","desc":"ギニア湾に浮かぶサントメ島の街。熱帯に適したサトウキビやココナツの栽培が行われている。また、近海ではサンゴなども採れるようだ。","note":"到達する","exp":"70"}],"3751":[{"type":"天文","name":"デネボラ","rank":"3","desc":"獅子の尾という意味の名を持つ、白く輝くしし座の2等星。星座図では、文字どおり獅子の尾にあたる場所に位置する。アルクトゥルス、スピカとともに春の大三角を構成し、他の星座の目印となる。","note":"クエスト「獅子の尾」<br/>発見物カード:255","exp":"510"}],"6728":[{"type":"財宝","name":"アウロス","rank":"5","desc":"古代ギリシャの木管楽器。本体は二本に分かれ、両手でそれぞれの指孔を押さえて演奏する。ギリシャ神話に登場する女神アテナが発明したという伝説がある。","note":"楽の叡智・心に響く楽器　左上","exp":""}],"1840":[{"type":"財宝","name":"シャクンタラー","rank":"2","desc":"「マハーバーラタ」をモチーフとして描かれた戯曲。グプタ朝時代にカーリダーサによって作られた。","note":"指輪が繋ぐ物語","exp":"280"}],"570":[{"type":"財宝","name":"光のフルート","rank":"2","desc":"エジプトの王家に伝わる財宝。達人が演奏すれば人の心を惑わし争いを終結させてしまうという。ラムセス2世が建てたというアブ・シンベル神殿から発見された。","note":"光のフルート","exp":"370"}],"2518":[{"type":"植物","name":"ヒイラギナンテン","rank":"1","desc":"台湾島や中国南部などに分布する、乾燥に強い低木。筒状に集まった、小さくて黄色い花を咲かせる。\n葉の縁がギザギザになっており、先端は硬い針状である。","note":"植物の生息地図","exp":"100"}],"1534":[{"type":"海洋生物","name":"アオザメ","rank":"2","desc":"外洋に生息し、高速で泳ぎ獲物を捕らえる。人喰いザメとしても恐れられる。","note":"釣り","exp":"250"}],"4826":[{"type":"財宝","name":"高粱酒","rank":"","desc":"","note":"紅毛城（上層隠し部屋）","exp":""}],"2517":[{"type":"鳥類","name":"キンバネホイビイ","rank":"1","desc":"台湾島の山岳地に生息する鳥。金色の翼と、はっきりとした眉が特徴である。人懐こく、数も多いため、見かけられる機会は多い。","note":"金色の鳥の地図","exp":"140"}],"1299":[{"type":"小型生物","name":"ロリス","rank":"2","desc":"樹上で生活する動物。夜行性で目が丸く、尾はほとんどない。サルともそのほかの動物ともつかない、不思議な姿をしている。普段の動作はかなり緩やかだが、エサを捕らえる一瞬だけは驚くほど素早い。","note":"動きの遅いサル","exp":"340"}],"3884":[{"type":"宗教遺物","name":"ココペリの壁画","rank":"4","desc":"北米の先住民であるホピ民族が岩壁に描いた神の絵。ココペリは豊穣の神であり、笛を吹いて豊作や子宝をもたらすとされる。","note":"先住民の笛の追加調査","exp":"660"}],"1303":[{"type":"虫類","name":"シボリアゲハ","rank":"5","desc":"輝くような色彩と、後羽にある三本の尾に似た突起が神秘的なチョウ。黒い羽には波紋のような白模様があり後羽が赤い。","note":"謎めいた模様","exp":"910"}],"1655":[{"type":"地理","name":"メキシコ湾流","rank":"5","desc":"カリブ海・メキシコ湾などを流れる暖かい海流で、カリブを抜けて東進している。この暖流はヨーロッパまで届くほどの大きな流れであるようだ。","note":"流れ着いた積荷","exp":"1027"}],"1898":[{"type":"歴史遺物","name":"バルバリーゴの貿易船","rank":"1","desc":"ニコロ・バルバリーゴが指揮していたガレー商船団の一隻。\nアレクサンドリアを出発しクリスマスのヴェネツィアへ向かう途中ウルボ島付近で沈没。","note":"サルベージ","exp":"120"}],"898":[{"type":"虫類","name":"ダイオウサソリ","rank":"2","desc":"尾の先端に毒を持った大型の虫。毒があるといっても人間を死に至らしめるほど強くはなく、せいぜいしびれさせる程度である。全身が硬いこうらで覆われている。","note":"熱帯の王","exp":"270"}],"1939":[{"type":"歴史遺物","name":"ヴィッテ・レーオ号","rank":"2","desc":"白い獅子を意味する、ネーデルラントの東インド貿易船の一隻。\n東アジアで香料を積んで帰国する途中、ポルトガルのキャラック船に襲撃され、セントへレナ島沖で沈没した。","note":"サルベージ","exp":"390"}],"4801":[{"type":"宗教遺物","name":"カマプアア像","rank":"2","desc":"ハワイ神話に登場する半人半神の英雄。普段は美男子であるが、獰猛なブタや、魚に変身することができる。火山の女神ペレと結婚、子を儲けるが、ペレと争うことも多い。","note":"ハワイの変わった神","exp":"370"}],"7021":[{"type":"宗教遺物","name":"マツヤの彫刻","rank":"2","desc":"インド神話のヴィシュヌ神がマツヤと呼ばれる魚に変身した姿が象られた彫刻。世界を呑み尽くす大洪水を予言し、人類の祖先と全ての動植物を救った場面を表しているという。","note":"","exp":""}],"2807":[{"type":"財宝","name":"中秋帖","rank":"1","desc":"東晋時代の書家・王羲之の息子、王献之による作品。\n作品の冒頭が「中秋」で始まることから、この名で呼ばれる。\n行書を羅列した教則本である。","note":"古書の地図","exp":"180"}],"2989":[{"type":"鳥類","name":"ロジアテ・スプーンビル","rank":"1","desc":"鮮やかな桃色の羽毛を持つ鳥。平たいクチバシですくうように魚を獲る。","note":"桃色の鳥の地図","exp":"200"}],"1997":[{"type":"海洋生物","name":"ルリハタ","rank":"2","desc":"鮮やかな体色をもつハタの仲間。","note":"釣り","exp":"220"}],"6912":[{"type":"美術品","name":"清明上河図","rank":"5","desc":"せいめいじょうがず。北宋の宮廷画家である張択端が12世紀に描いた風俗画。長さ5mを越える画巻には、清明節で賑わう都の光景が描かれている。精緻な筆致から、当時の人々の活気に満ちた豊かな生活が窺える。","note":"","exp":""}],"1489":[{"type":"小型生物","name":"ツノガエル","rank":"1","desc":"幅の広い口と目の上にある角状の突起物が特徴。体の一部を地中に埋め、獲物を待ち伏せする。繁殖期には、ウシのような声で鳴いてメスを求める。","note":"角のあるカエルの地図","exp":"105"}],"1291":[{"type":"宗教遺物","name":"ナーガ上の仏陀","rank":"5","desc":"とぐろを巻いた蛇の上に、座禅を組む仏陀の像。蛇はムチャリンダといい、瞑想に入った仏陀を七日の間風雨から守ったといわれる。","note":"仏陀を護る蛇","exp":"1014"}],"1694":[{"type":"大型生物","name":"ハナブトオオトカゲ","rank":"4","desc":"体長が4mを超える大型のトカゲ。体は細身だが体長が長く、尾が体の2/3を占める。\n樹上に棲み、かつ獰猛な性格から、生息地では森のワニと呼ばれている。","note":"森に棲むドラゴン","exp":"624"}],"73":[{"type":"地理","name":"マダガスカル島","rank":"1","desc":"南アフリカの東沖に位置する巨大な島。標高3000m近い山々があり気候は多様だ。他の場所から切り離されているせいか特有の動植物が多い。","note":"インド洋の大きな島","exp":"150"}],"5504":[{"type":"港・集落","name":"マンチェスター","rank":"1","desc":"ブリテン島西部に位置する街。1世紀頃、古代ローマ帝国軍が築いた前哨砦「マンクニウム」を起源とする。18世紀末から、蒸気機関を用いた綿織物工業が盛んになり、急成長を遂げる。","note":"座標　16164,2271","exp":"15"}],"5149":[{"type":"港・集落","name":"ポートロイヤル","rank":"2","desc":"カリブ海のほぼ中央に位置する港街。立地が良く、多くの船が停泊できたため、バッカニア海賊の拠点となる。街は海賊だらけだが、秩序は保たれているようだ。","note":"到達する","exp":"250"}],"5601":[{"type":"港・集落","name":"サクラメント","rank":"2","desc":"北米大陸の西部に位置する街。開拓民の居留地として起こり、ゴールドラッシュを機に、開拓と交易の拠点として目覚しい発展を遂げた。","note":"","exp":"330"}],"2042":[{"type":"財宝","name":"医学全書","rank":"2","desc":"アル・ラージーが著した医学知識についての百科事典。\nギリシャやアラビア、インドの医学の集大成に、著者の経験と意見を加えてあるようだ。外科医療道具についても記されている。","note":"希少な医学書","exp":"360"}],"1504":[{"type":"虫類","name":"ホソバオオゴマダラ","rank":"1","desc":"大型で飛び方が優雅な美しいチョウ。森林の水辺に生息する。","note":"斑模様のチョウの地図","exp":"140"}],"1016":[{"type":"歴史遺物","name":"ビストゥン碑文","rank":"2","desc":"「ひぶん」。ビストゥン山の断崖に彫り込まれた巨大な碑文。アケメネス朝ペルシャのダレイオス1世の戦勝記念に作られたものだという。","note":"名君の記録","exp":"210"}],"5584":[{"type":"気象・現象","name":"渦潮","rank":"2","desc":"特定の海峡などで発生する渦型の潮流。最大で直径20mほどのものも見られる。どの海でも観測できるものではないことから、海中の地形などが影響していると思われる。","note":"堺の目の前で発見<br/>晴れの夕方から日没まで。晴れの夕方でもでないときあり。","exp":"390"}],"5599":[{"type":"地理","name":"エルバート山","rank":"2","desc":"北米大陸西部に位置するロッキー山脈の最高峰。その標高はおよそ4400mに及ぶ。","note":"","exp":"250"}],"3616":[{"type":"地理","name":"タイガ","rank":"4","desc":"シベリア地方に広がる針葉樹林。\nどうやら地域によっては樹林の種類が異なるらしく、遠くから見ると色が違って見える。","note":"凍土の森林","exp":"650"}],"2900":[{"type":"地理","name":"黄山","rank":"4","desc":"道教や仏教の修行の場として多くの寺院が建てられている杭州付近の山。多数の文人が訪れ、水墨画や漢詩など独特の文化を生み出した。","note":"天空の大海","exp":"630"}],"3750":[{"type":"天文","name":"春の大三角","rank":"4","desc":"春の大曲線を構成する2つの1等星、うしかい座のアルクトゥルスとおとめ座のスピカ、しし座の2等星のデネボラを結んで描く三角形。さまざまな星座を見つける目印となる。","note":"春のトライアングル","exp":"670"}],"5265":[{"type":"天文","name":"ハダル","rank":"2","desc":"ケンタウルス座にある1等星で、足にあたる位置にある。星の名はアラビア語で「大地」を意味する。","note":"「明るい星の観測記録」<br/>発見物カード:130","exp":"260"}],"5030":[{"type":"港・集落","name":"オポルト","rank":"1","desc":"ポルトワインの産地として有名な港。オポルトとは「港」の意味でポルトガル建国時はこの地方が国土の中心であった。名産のワインのほか、漁業と塩の生産が盛んである。","note":"到達する","exp":"4"}],"6317":[{"type":"鳥類","name":"ジュウニセンフウチョウ","rank":"3","desc":"東南アジアなどに生息する鳥。雄のみ、お尻から細い針金状の尾羽が12本生えている。繁殖期になると、この尾羽を雌の顔にかすめるようにして求愛する。","note":"","exp":"480"}],"5581":[{"type":"気象・現象","name":"太陽柱","rank":"3","desc":"日没や日の出の際に、太陽の上方に光の柱のようなものが見える現象。色は太陽と同じオレンジや赤色で観測される。","note":"","exp":"600"}],"6442":[{"type":"歴史遺物","name":"ウルのロイヤルゲーム","rank":"2","desc":"メソポタミアの古代都市ウルにおいて、王や貴人たちによって遊ばれたという盤面遊戯。一説には、世界最古の盤面遊戯の一つといわれている。ルールは双六やバックギャモンに近く、それらの源流とされている。","note":"","exp":"400"}],"6259":[{"type":"歴史遺物","name":"ギリシャ詞華集","rank":"2","desc":"10世紀のビザンツ帝国の文学者、コンスタンティノス・ケファラスが編纂したギリシャ語詩選集。紀元前から当時までのおよそ300人にわたる詩人の短い詩を4500篇ほどまとめており、長い間、優れた詩選集の代名詞的な書とされてきた。","note":"","exp":"270"}],"3619":[{"type":"小型生物","name":"ソレノドン","rank":"2","desc":"ハイチなど、カリブの熱帯雨林に生息する夜行性の動物。\n体長は30cm程度で、鼻が細く伸びているのが特徴。狭い所に鼻を差し込み、獲物の昆虫などを捕える。","note":"鼻の長い動物の地図","exp":"340"}],"6065":[{"type":"宗教建築","name":"メンフィスの遺跡","rank":"2","desc":"古代エジプトの宗教都市のひとつとされたメンフィスの遺構。プタハ神を主神とするこの地はかつて「白き壁」と称されており、下エジプト最大の都市であったという。","note":"カード経験190","exp":"380"}],"3662":[{"type":"歴史遺物","name":"カノプス壷","rank":"3","desc":"古代エジプトでミイラを作る際に心臓の次に重要とされた臓器を保存したといわれる壷。ホルスの息子と呼ばれる四柱の神々の姿をかたどっている。","note":"ダンジョン","exp":"450"}],"6402":[{"type":"宗教建築","name":"在りし日のギザのピラミッド","rank":"5","desc":"ギザの地にそびえる巨大なピラミッド。クフ王の墓と伝わる。膨大な数の四角い石を人力で積み上げた。表面は磨いた白い大理石で覆われて輝いている。建設中は周囲に労働者たちの住宅が並び、食物や麦酒も支給されていたという。","note":"レガシー：砂漠に栄えた巨石文明","exp":"4000"}],"2805":[{"type":"鳥類","name":"ガビチョウ","rank":"2","desc":"中国南部から東南アジアまで、広い範囲で生息している鳥。地上を走ることが多く、高く飛ぶことがない。\n眼の周りにある眉状の模様が特徴的で、「画眉鳥」と書く。","note":"歌う鳥","exp":"310"}],"5374":[{"type":"植物","name":"アカツメクサ","rank":"2","desc":"ヨーロッパ原産の草で、ピンクの花をつける。\n牧草やハーブとして利用され、土壌を肥沃にする効果もある。","note":"","exp":"240"}],"1776":[{"type":"地理","name":"パナマ地峡","rank":"2","desc":"中米にある地峡。最も狭い場所はカリブ海から太平洋まで64kmしかない。運河の建設も夢ではない距離だが、山がちで降水量が多い上に、密林に覆われている。加えて高熱を発する病に冒される地域でもあるため建設は容易ではないだろう。","note":"クエスト「北と南を分かつ場所」<br/>発見物カード:110","exp":"220"}],"914":[{"type":"中型生物","name":"ワオキツネザル","rank":"2","desc":"長い尾が白と黒のしま模様になっている。昼行性で、5～30頭の群れで集団生活をする。群れの全員が木の枝に集まって、ひなたぼっこや毛づくろいをしたりする。","note":"白と黒の縞模様","exp":"205"}],"5086":[{"type":"港・集落","name":"ソコトラ","rank":"1","desc":"アデンの東に浮かぶ島である。歴史は古く、軍事的に重要な場所。","note":"到達する","exp":"124"}],"453":[{"type":"美術品","name":"洗礼者ヨハネ","rank":"2","desc":"レオナルド・ダ・ヴィンチ作の絵画。洗礼者ヨハネを描いている。「あの方は栄え、私は衰えなければならぬ」という言葉からくる、上を指差したポーズをとっている。不自然なような、不思議な微笑みを浮かべている…。","note":"教会の宗教画の地図","exp":"215"}],"2878":[{"type":"歴史遺物","name":"爵","rank":"2","desc":"読みは「しゃく」。殷周時代の酒器で、祭器としても使用された。三つの脚は天・地・神を表すといわれる。\nこの爵にはトウテツと呼ばれる怪異な獣が描かれている。","note":"古代の酒器の地図","exp":"280"}],"2865":[{"type":"植物","name":"シュウカイドウ","rank":"1","desc":"主に中国に生息する植物。夏の終わりから秋にかけて、紅色の花を咲かせる。\n日陰や湿り気を好み、さまざまな場所で咲いているのが見られる。","note":"日陰に咲く花の地図","exp":"90"}],"5988":[{"type":"地理","name":"クリミア半島","rank":"1","desc":"黒海の北部に張り出している半島。北東の囲まれた海域はアゾフ海という。半島の南部は温暖で過ごしやすい。14世紀の黒死病の大流行は、ここから始まったのだそうだ。","note":"黒死病の歴史","exp":"180"}],"1308":[{"type":"鳥類","name":"セイラン","rank":"3","desc":"人によく慣れ、飼育も容易な鳥。オスとメスは大変仲がよく、オスは長い尾羽を立てて揺らしメスを誘う。その姿は見るものを魅了する。","note":"無数の瞳","exp":"462"}],"5507":[{"type":"港・集落","name":"カッターロ","rank":"1","desc":"アドリア海の東側に位置する街。街並みなどにヴェネツィアの影響がうかがえる。","note":"座標　852,3030","exp":"17"}],"5176":[{"type":"港・集落","name":"ルアンダ","rank":"1","desc":"ごく最近開拓されたばかりの街。十分な水深と、輸送が容易な地形に恵まれた、優れた交易港である。農作物と木材、宝石が豊富に流通する。","note":"到達する","exp":"73"}],"3741":[{"type":"地理","name":"グリーンランド氷床","rank":"5","desc":"グリーンランドの大部分を覆う、巨大な氷の塊。雪が積もって固まり、その上にまた雪が積もるのを繰り返した結果、厚い層をなしたものである。","note":"クエスト「氷の大地」<br/>発見物カード:645","exp":"1290"}],"5608":[{"type":"地理","name":"オンタリオ湖","rank":"2","desc":"北米大陸北東部に位置する湖のひとつ。湖の南西には巨大な滝がある。北東からはセントローレンス川が流れ出ている。","note":"","exp":""}],"6143":[{"type":"財宝","name":"カタロニア地図","rank":"4","desc":"アラゴン王太子からフランス王シャルル6世へ贈られた地図。ユダヤ人製図家のクレスケス父子によって作成された。マルコ・ポーロやフランシスコ会修道士フリア・オドリックなどの情報を元に作成されたといわれる。","note":"クエスト「異邦へのまなざし」<br/>発見物カード:325","exp":"650"}],"1497":[{"type":"財宝","name":"ルイスのチェス駒","rank":"2","desc":"セイウチの牙に精巧な彫刻を施したチェスの駒。その形状から12世紀のノルウェーまたはスウェーデンで制作されたものと思われる。","note":"遊戯にも贅沢を","exp":"330"}],"5521":[{"type":"天文","name":"ほ座","rank":"2","desc":"南天の星座のひとつ。この星座とりゅうこつ座の一部を結ぶと十字を成すため、他の星座と間違われやすい。","note":"「天体学者の観測記録」<br/>発見物カード:160","exp":"320"}],"1946":[{"type":"化石","name":"トカゲの卵のような石","rank":"1","desc":"両手のひらに乗る程の卵状の石。すぐ近くにトカゲの骨を思わせる石があるせいか、まるでトカゲの卵のように見える。","note":"奇妙な石の地図","exp":"160"}],"1469":[{"type":"財宝","name":"ゲレロの装束","rank":"2","desc":"アギラールと共に遭難したイスパニア人。彼と同様にとらわれの身となるが、やがて彼らと共に暮らし、マヤ人の娘を娶った。コルテスの招集にも応じず生涯マヤ人として祖国の兵と戦ったという。これは、そのときの戦装束のようだ。","note":"マヤ人になったイスパニア人","exp":"270"}],"1087":[{"type":"宗教遺物","name":"玄奘三蔵の旅行手形","rank":"4","desc":"中国の唐からインドに留学した、玄奘三蔵という僧侶の旅行手形。玄奘三蔵はインドから657部に及ぶ膨大な経典を祖国まで持ち帰り全てを翻訳したといわれている。","note":"東国より僧来たる","exp":"744"}],"3590":[{"type":"レリック","name":"桃源郷","rank":"","desc":"武陵の山中にひそかに存在するという桃源郷。俗世に疲れ、隠遁した詩人、陶淵明の心は、かの地で癒やされたのだろうか。","note":"","exp":""}],"5274":[{"type":"レリック","name":"ポセイドンの怒り","rank":"","desc":"","note":"","exp":""}],"4839":[{"type":"宗教建築","name":"マルウィヤ・ミナレット","rank":"2","desc":"アッバス朝の第8代カリフ、ムウタスィムがサーマッラーに建設した貴重な螺旋式のミナレット。絵画などに描れたバベルの塔の外見はこの塔をモデルにしたものが多い。","note":"クエスト「バベルのモデル」<br/>発見物カード:190","exp":"380"}],"320":[{"type":"美術品","name":"ヒワの聖母","rank":"2","desc":"ラファエロ作の絵画。同じ題材の絵が複数あるため、この絵は通称でこう呼ばれる。由来は、左の聖ヨハネが小鳥のヒワをつれているからである。","note":"ラファエロの名画","exp":"240"}],"6456":[{"type":"史跡","name":"蛇の頭が置かれた神殿階段","rank":"5","desc":"「チチェンイッツァ」の神殿にある階段の再下段にはマヤの最高神であるククルカンの頭部の彫刻がある。春分の日と秋分の日には、ピラミッドの影が階段に映り、うねったククルカンの胴体のように見える神秘的な現象が見られるという。","note":"追究クエスト","exp":""}],"1630":[{"type":"鳥類","name":"ケア","rank":"3","desc":"森林限界近くの高山に生息する鳥。オリーブのような緑色の羽に覆われているが、翼の裏はきれいなオレンジ色をしている。とても人懐っこい性格をしている。","note":"人を恐れぬ生物<br/><br/>発見時経験値462　発見物カード経験値231","exp":"462"}],"1926":[{"type":"植物","name":"エーデルワイス","rank":"1","desc":"欧州の山脈に自生する高山植物。星型に開く白い花びらは繊毛で覆われているため、雪がかぶっているように見える。枯れてもあまりしおれずに、清らかな白い花が残る。希少なため現地では高貴な花として愛されている。","note":"高原の白い花の地図","exp":"150"}],"2655":[{"type":"虫類","name":"マドタテハ","rank":"2","desc":"朝鮮地域に生息するタテハチョウの一種。前羽の先端部分に、切り抜かれたような穴が開いているのが特徴。\nそのさまが窓のようであることから名付けられた。","note":"穴開き羽の奇跡","exp":"260"}],"3775":[{"type":"天文","name":"てんびん座","rank":"4","desc":"黄道十二星座の1つ。正義の女神アストライアが持つ、正邪を量る天秤だとされる。てんびん座には「北の爪」「南の爪」とさそり座に由来するような名の星があるため、元々はさそり座の一部であったと考えられる。","note":"夜空の秤","exp":"790"}],"5257":[{"type":"地理","name":"ベッラ島","rank":"1","desc":"シチリア島沿岸の小さな島。シラクサの北に位置する。周囲の海の透明度や湾の形状もあいまって、美しい景観となっている。","note":"","exp":"100"}],"343":[{"type":"歴史遺物","name":"医師の誓い","rank":"1","desc":"ギリシャの医聖ヒポクラテスが誓いを刻んだ石板。その誓いは、医学に生涯を捧げるという崇高なものである。当代きっての名医パレが所蔵していたもので彼自身も同時代の医学者たちに多大な影響を及ぼした。","note":"クエスト「医師の誓い」<br/>発見物カード:95","exp":"190"}],"574":[{"type":"地理","name":"マンデブ海峡","rank":"2","desc":"紅海とアデン湾を区切る海峡。島があるためもっとも狭いところでは25km程度の幅しかない。海上交易上、非常に重要な海峡で、すぐそばにはアデンという街が栄えている。","note":"紅海の透明度を守る海峡","exp":"220"}],"1800":[{"type":"財宝","name":"シャールカの髪飾り","rank":"2","desc":"シャールカとはボヘミアの伝説に語られる女性。恋人の裏切りに遭い、男たちに復讐するが最後は再び愛に揺れる。ボヘミアの古い言い伝えでは「髪の長い女は癇癪持ちである」と言われておりシャールカの伝説と通じるところがある。","note":"ある女傑の物語","exp":"340"}],"5006":[{"type":"地理","name":"キクラデス諸島","rank":"2","desc":"エーゲ海の中央部にある島々。古代ギリシャの宗教の中心だった島を他の島々が囲むように位置し、名前の由来になっている。島の数は220以上ある。","note":"","exp":"250"}],"4848":[{"type":"鳥類","name":"オニアオサギ","rank":"2","desc":"南アフリカから西アジアにかけて生息する鳥類。サギ科最大の種であり、体長約1.5ｍ、翼長は２ｍにもと達する。","note":"巨鳥の夢","exp":"250"}],"3734":[{"type":"宗教遺物","name":"古びた天秤","rank":"5","desc":"太陽神ラーの天秤。\n古代エジプトの「死者の書」によると、アヌビスが死者の罪の重さを量り、魂の行く末を見定めるために用いたらしい。","note":"ダンジョン","exp":"830"}],"6113":[{"type":"史跡","name":"赤壁","rank":"5","desc":"後漢末期に華北を平定した曹操が、孫権・劉備の連合軍に\n敗走したと伝えられる場所。連合軍が曹操軍を焼き討ちし\nたとも、疫病の蔓延した曹操軍が船を焼いて撤退したとも\nいわれているが、真相は不明である。","note":"","exp":"820"}],"2536":[{"type":"地理","name":"太魯閣峡谷","rank":"2","desc":"淡水の南東に広がる、大理石が浸食されて築かれた大峡谷。\n周囲に連なる山々は、3000mを超える高さを誇る。\n大自然が作り上げた断崖が見どころ。","note":"書きかけの地図","exp":"290"}],"5859":[{"type":"美術品","name":"レーマンの彫刻ガラス","rank":"5","desc":"ボヘミアのガラス職人レーマンが作ったガラス細工。ガラスに彫刻が施されており、宝石のように美しい。","note":"","exp":"1370"}],"832":[{"type":"歴史遺物","name":"クレオパトラの胸飾り","rank":"4","desc":"クレオパトラ7世が使っていたという、豪華な胸飾り。彼女はエメラルドを特に好んだと伝えられ、この胸飾りにも大粒のエメラルドがいくつも使われている。","note":"知的美女","exp":"756"}],"5242":[{"type":"天文","name":"天王星","rank":"5","desc":"土星の外側を巡る惑星で、最大等級は5.6等星と肉眼で見ることも不可能ではない。惑星と認識されるまで20回以上も恒星として観測されていた。公転軸に対して自転軸が大きく傾いており、ほぼ横倒しになっている。","note":"クエスト「消えた星を探せ」<br/>発見物カード:535","exp":"1070"}],"4823":[{"type":"海洋生物","name":"ステラーカイギュウ","rank":"2","desc":"カムチャッカ半島の東にある島の周辺に生息する巨大な海洋生物。人を警戒せず、傷ついた仲間を守ろうとする習性があり、このままでは絶滅してしまいそうだ。","note":"巨大な海獣の地図","exp":"370"}],"6882":[{"type":"宗教建築","name":"龍門石窟","rank":"5","desc":"北魏の時代に造営が始まった石窟寺院。山崖を掘って造られた石窟に数々の仏像が刻まれている。造営は王朝が変わっても続けられたという。","note":"発見物カード:775","exp":"1550"}],"6715":[{"type":"植物","name":"ハナビラタケ","rank":"2","desc":"カラマツなど、針葉樹の根元に自生する花のようなきのこ。湿度が高く、霧が出る場所を好む。清らかな香りと爽やかな食感を持つ。希少なきのこであるため「幻のきのこ」とも呼ばれる。","note":"クエスト「枯れ葉の下」<br/>発見物カード:105","exp":"210"}],"2239":[{"type":"地理","name":"ガラパゴス諸島","rank":"4","desc":"赤道直下に位置する、複数の島々から成る火山群島。他では見られないような動物がたくさん生息しているようだ。","note":"クエスト「迷い込んだ島の調査」<br/>発見物カード:375","exp":"750"}],"2442":[{"type":"宗教遺物","name":"戦勝の碑","rank":"4","desc":"古代エジプトのファラオであるラムセス2世が、戦勝の記念として残した碑。\nカデシュの戦いをはじめ、数多くの戦争にあけくれた人物に似つかわしい遺物である。","note":"ダンジョン","exp":"640"}],"5739":[{"type":"気象・現象","name":"積乱雲","rank":"2","desc":"垂直方向に著しく発達した巨大な雲。雲の下では激しい嵐や雷雨などが発生することもある。夏場での観測情報が多い。","note":"メキシコ湾　メリダとヴェラクルスの間の砂浜海岸線　日中","exp":""}],"3156":[{"type":"史跡","name":"フォロ・ロマーノ","rank":"3","desc":"古代ローマの政治・経済・宗教の中心地だったとされる遺跡。広場や議事堂、神殿などの遺構が並び、隆盛を極めた古代ローマの有様をうかがい知れる。","note":"古代遺跡の歩き方","exp":"540"}],"5789":[{"type":"宗教建築","name":"ディヴリーイの大モスクと病院","rank":"5","desc":"モスク、病院、霊廟が併設された建築物。当時の王の命令でモスクが建造される際、その妻が病院の併設を願ったという。扉口や柱、壁などに多くの精密な模様が刻まれており、当時の建築技術の高さが窺い知れる。","note":"イスラム建築に魅せられて","exp":"1360"}],"3888":[{"type":"財宝","name":"トルコ石の装身具","rank":"2","desc":"トルコ石の欠片を繋ぎ合わせて作られた装身具。北米の南西部ではトルコ石がよく採れ、加工や取引が盛んだった。先住民の間では、トルコ石には特別な力か備わっているとされる。","note":"先住民族の装身具の地図","exp":"240"}],"6299":[{"type":"史跡","name":"アルハンブラ宮殿","rank":"5","desc":"イスパニアの古都、グラナダ郊外の丘の上にある宮殿。かつてこの地を支配したムーア人が9世紀に建てた砦に由来するという。レコンキスタ後に神聖ローマ皇帝カール5世の避暑地となり、イスラムの要素を排除する方針で改築された。","note":"","exp":"1290"}],"1565":[{"type":"歴史遺物","name":"香炉","rank":"1","desc":"アステカの土地で見つかった土器製の香炉。祭祀道具に用いたのだろうか。","note":"メソアメリカの遺物の地図","exp":"150"}],"5701":[{"type":"地理","name":"ランタン谷","rank":"1","desc":"ヒマラヤ山脈にある谷の1つ。春はシャクナゲが、夏は高山植物が谷の周辺に咲き誇り、谷を囲う秀峰と共に絶景と称されている。","note":"","exp":"170"}],"5126":[{"type":"港・集落","name":"ファマガスタ","rank":"1","desc":"地中海東部、キプロス島東岸に位置する街である。シェークスピアの悲劇「オセロー」の舞台だといわれる。温暖な地中海性気候で農業が盛ん。銅鉱山もある。","note":"到達する","exp":"35"}],"2881":[{"type":"地理","name":"武陵源","rank":"3","desc":"独特の石柱が立ち並ぶ絶景地。\nその柱は3000本を超えるといわれる。\n地元には漢王朝の皇帝がここに住み、崩御したという伝説がある。","note":"天に花を捧げる女","exp":"520"}],"6153":[{"type":"宗教建築","name":"トマールの修道院","rank":"2","desc":"12世紀テンプル騎士団によって建造された修道院。騎士団解体後はキリスト騎士団の総長となった航海王子エンリケが回廊を増築し、その後1世紀近くの間、さまざまな建築様式で増設された。","note":"クエスト「騎士団の命脈」<br/>発見物カード:125","exp":"250"}],"6935":[{"type":"植物","name":"ツクモグサ","rank":"2","desc":"日本固有の高山植物。花びらのように見える薄い黄色のがく片は、外側が白い産毛に覆われている。外輪は4cmほど。晴れた日にしか開花せず、自生域も限られているため、その姿を目にするのは貴重とされる。","note":"発見物カード:115","exp":"230"}],"6897":[{"type":"小型生物","name":"冬毛のイイズナ","rank":"5","desc":"毛色が真っ白に生え替わったイイズナ。夏毛は腹部を除いて茶色だが、冬になると白く生え変わり、雪の中では見分けがつかないほどになるという。","note":"","exp":""}],"2866":[{"type":"植物","name":"ブンカンカ","rank":"1","desc":"主に中国で見られる植物。白い花を咲かせるが、日がたつにつれ、中心部から次第に薄い紅色に色が変化する。","note":"黄色と赤の花の地図","exp":"130"}],"5593":[{"type":"気象・現象","name":"雹","rank":"2","desc":"空から小さな氷晶が降り注ぐ現象","note":"カリカット北","exp":"340"}],"274":[{"type":"小型生物","name":"コブラ","rank":"3","desc":"大型で非常に強い毒をもつヘビ。かまれるとまず助からないといわれている。大型のものは5mを超え、鎌首を持ち上げると成人男性の顔の高さにまでなる。威嚇（いかく）するときに、頭部を横に広げる独特の姿勢をとる。","note":"ヘビを食べる毒蛇","exp":"539"}],"512":[{"type":"歴史遺物","name":"古代の金貨","rank":"1","desc":"金やその合金で作られた、古代の貨幣。金ははるか昔から貴重なものとされていた。","note":"古代の貨幣の地図","exp":"14"}],"1259":[{"type":"歴史遺物","name":"オルメカの巨大頭像","rank":"4","desc":"メソアメリカ文化の中でも古い部類とされるオルメカの巨大頭像。小さなものは成人女性の身長くらい、大きなものはその倍くらいあり、数多く見つかる。","note":"海を渡るアフリカ人","exp":"636"}],"5572":[{"type":"天文","name":"はちぶんぎ座","rank":"2","desc":"ラカーユが制定した南天の星座のひとつ。天体観測に用いる八分儀をかたどっている。","note":"「天文学者の観測記録」<br/>発見物カード:155","exp":"310"}],"3375":[{"type":"植物","name":"オオウイキョウ","rank":"4","desc":"中東に分布する植物。草丈は約2mで、茎の先に黄色の花を付ける。樹脂から作られる精油は、香料や薬として利用される。","note":"聖書にまつわる香","exp":"690"}],"1569":[{"type":"鳥類","name":"エミュー","rank":"2","desc":"体高が2mにもなる大きな鳥。翼はきわめて小さく飛ぶことができない。全身が灰褐色の毛で覆われている。","note":"南東の大陸にすむ大型生物<br/><br/>発見時経験値320　発見物カード経験値160","exp":"320"}],"6635":[{"type":"歴史遺物","name":"銀製コショウ入れ","rank":"5","desc":"ローマ帝国期のコショウ入れ。貴婦人をかたどった形をしている。当時、コショウは貴重品であり、コショウ入にも金箔が施されていたという。","note":"発見物カード750","exp":"1500"}],"6985":[{"type":"虫類","name":"オオナガトゲグモ","rank":"4","desc":"東南アジアの熱帯雨林に生息しているクモ。赤や黄などの鮮やかな警告色の体が特徴で、雌は大きな弓形のトゲを持つ。このトゲで捕食者から身を守っていると考えられる。雄は雌に比べて非常に小柄である。","note":"","exp":""}],"905":[{"type":"植物","name":"アイリス","rank":"1","desc":"紫や青紫の豪華な花が咲く植物。園芸種に適していると思われる。","note":"白い花の地図","exp":"51"}],"3735":[{"type":"歴史遺物","name":"ラムセス2世の壁画","rank":"5","desc":"古代エジプトのファラオであるラムセス2世の、カデシュの戦いでの活躍を描いた壁画。戦車を駆り弓を構えるその姿から、王の勇敢さがうかがえる。","note":"ダンジョン","exp":"1050"}],"371":[{"type":"植物","name":"チェリー","rank":"1","desc":"春に薄桃色の花が咲く落葉樹。葉と花を同時につけ、花が終わったあとの実はサクランボとして食用になる。","note":"果物がなる木の地図","exp":"19"}],"6420":[{"type":"小型生物","name":"冬毛のオコジョ","rank":"5","desc":"オコジョの毛が冬になり純白に生えかわった状態。古い言い伝えでは純潔の象徴ともされている。それゆえにアーミンと呼ばれる冬毛のオコジョの毛皮や、毛皮で作られた服は、貴族や王族に好まれた。","note":"","exp":""}],"77":[{"type":"美術品","name":"ヴェールの女","rank":"2","desc":"ラファエロ作の、女性の肖像画。ラファエロの恋人に貴族の婚礼衣装を着せた姿だとも言われている。多忙なラファエロは弟子に手伝わせることが多かったが、この絵は一人で描きあげたという。","note":"ヴェールをかぶった女の肖像","exp":"310"}],"1513":[{"type":"宗教遺物","name":"釈迦牟尼仏像","rank":"3","desc":"しゃかむにぶつぞう。仏教の開祖である釈迦（しゃか）の像。釈迦は名門の家に生まれたが、のちに出家した。生まれ出たときに二本の足で歩き、言葉を発したといわれる。","note":"釈迦牟尼仏像","exp":"506"}],"5513":[{"type":"美術品","name":"文様入りの手編み籠","rank":"3","desc":"アフリカ西部で作られる手編みの籠。色鮮やかな文様が編み込まれており、芸術的価値もある。","note":"西アフリカの綺麗な籠<br/><br/>発見時経験値470　発見物カード経験値235","exp":"470"}],"5529":[{"type":"気象・現象","name":"バイオルミネセンス","rank":"2","desc":"夜などに、海洋生物の発光で海が輝いて見える現象。発光する生物の種類は多く、魚類以外にも甲殻類やクラゲなどの発光が確認されている。","note":"夜　7590,5600で視認","exp":"250"}],"6684":[{"type":"港・集落","name":"ヨーテボリ","rank":"1","desc":"スカンジナビア半島のイェータ川河口の街。\n貿易の拠点として繁栄している。グスタフ2世アドルフによって作られオランダ様式の建築物が並ぶ。ヨーテボリは「ゴートの都市」という意味。","note":"オスロとコペンハーゲンの間<br/>535，2077","exp":"40"}],"5627":[{"type":"地理","name":"ヴォルガ川","rank":"1","desc":"ロシア西部を流れる、全長3500km以上にも及ぶ川。流域は肥沃であり、麦などが多く栽培される。","note":"","exp":"180"}],"906":[{"type":"植物","name":"カスミソウ","rank":"1","desc":"白い花が群れて咲く植物。これだけでも可憐で愛らしい花だが、花束に加えるととても見栄えがするだろう。","note":"白い花の地図","exp":"12"}],"495":[{"type":"歴史遺物","name":"エジプト文字の石板","rank":"1","desc":"エジプトの古代象形文字・ヒエログリフが記された石板。鳥や獣、体の一部などが文字になっている。いったい何が書かれているのだろうか。","note":"古代エジプト遺物の地図","exp":"36"}],"2079":[{"type":"小型生物","name":"マーラ","rank":"2","desc":"南米の草原に生息するネズミ。ぴょんぴょん飛び跳ねて移動する。オスとメスは常に行動を共にし、一生つがいのままである。\nまた、オスはメスに対して、とても従順である。","note":"［勅命］[[新大陸西岸方面の動物探索","exp":"310"}],"149":[{"type":"歴史遺物","name":"ケルトの神像","rank":"1","desc":"ケルト文明で信仰されていた神の像。青銅製で、頭部が大きく手足が小さい、独特の形状をしている。","note":"ケルト遺物の地図","exp":"30"}],"498":[{"type":"宗教遺物","name":"ヘラ像","rank":"1","desc":"ギリシャ神話の女神の像。ヘラは最高神・ゼウスの妻で、結婚をつかさどる女神である。ローマ神話では、ジュノーという。嫉妬深いことで知られ、ゼウスの愛人や子供を迫害する逸話が多い。","note":"古代ギリシャの神像","exp":"60"}],"1782":[{"type":"美術品","name":"犀","rank":"2","desc":"アルブレヒト・デューラー作の木版画。デッサンしたかのように細部まで緻密に描かれているが、デューラー自身は犀を一度も見たことがない。ゆえに、この木版画はデューラーの並外れた想像力と表現力を証明する一枚ともいえるだろう。","note":"人並みはずれた想像力","exp":"290"}],"6686":[{"type":"海洋生物","name":"シロイルカ","rank":"5","desc":"別名ベルーガ。ベーリング海やアラスカなど北半球の高緯度海域に生息する。前頭部から多種多様な鳴き声を発生させ、餌の探知や仲間と交流に使用している。その鳴き声の美しさから「海のカナリア」とも呼ばれる。","note":"","exp":"1040"}],"3643":[{"type":"財宝","name":"サモワール","rank":"3","desc":"ロシアの湯沸かし器。円筒の外側に水を、中心部に火種を入れて湯を沸かす。ふたの上に茶器を置けば、保温の効果も得られる。寒い地域ならではの道具。","note":"芸術的な実用品","exp":"520"}],"2377":[{"type":"虫類","name":"ヒグラシ","rank":"2","desc":"東アジアの薄暗い林に生息する、カナカナカナ…、と鳴くセミ。\n日暮れ時によく鳴くことから、日を暮れさせるセミとして名付けられた。","note":"日暮れの情趣を醸す声","exp":"250"}],"2418":[{"type":"宗教遺物","name":"アメン像","rank":"4","desc":"古代エジプトの神の一人。アメン＝ラーとしてラー神と一体化し、エジプト神の中心として存在した。テーベにおける大気の神でもあり、カルナック神殿の主神として祭られている。","note":"ダンジョン","exp":"640"}],"5070":[{"type":"港・集落","name":"シエラレオネ","rank":"1","desc":"アフリカ西海岸の街。年間を通じて気温が高く、熱帯性の農業が盛んである。また、近郊にはダイヤモンドの大規模な鉱脈があるようだ。","note":"到達する","exp":"72"}],"2059":[{"type":"地理","name":"イーストラ半島","rank":"1","desc":"トリエステの南に位置する半島。ポレチュと呼ばれる古代ローマ時代の市街地が存在している。ポレチュには、ローマ時代に建設された聖堂や神殿が崩壊することなく残っているという。","note":"古代の街調査の下調べ","exp":"180"}],"2038":[{"type":"大型生物","name":"ナイルオオトカゲ","rank":"2","desc":"トカゲのような生物だが、体長がヒトより大きい個体も存在する。どうやら肉食らしく、ワニの卵や幼生すらも食べてしまうという。名前にナイルとあるがナイル川周辺以外でも目撃情報が寄せられている。","note":"［勅命］[[運河開通場所に潜むもの","exp":"310"}],"2845":[{"type":"財宝","name":"関帝詩竹","rank":"5","desc":"三国時代の英傑・関羽が、君主である劉備に自身の忠誠心を伝えるために書いた詩。\n竹の絵で文面を隠すことで、他者に内容を気付かれることを防いだという。","note":"読めない手紙","exp":"820"}],"3891":[{"type":"天文","name":"かみのけ座","rank":"3","desc":"古代エジプトでプトレマイオス朝の王妃ベレニケが女神アフロディテに捧げた髪の毛とされる。ベレニケの髪の毛は美しさで名高く、喜んだ女神アフロディテはこれを天に上げたといわれる。","note":"クエスト「古代エジプトの星座」<br/>発見物カード:300","exp":"600"}],"5021":[{"type":"港・集落","name":"アンコナ","rank":"1","desc":"ヴェネツィアの南に位置する街。古代ローマ時代から港町として栄えた。12世紀にはローマ教皇から自由都市の特許を得ている。","note":"到達する","exp":"21"}],"5235":[{"type":"中型生物","name":"キンイロジャッカル","rank":"2","desc":"黄色から薄金色の体毛をもつジャッカルの仲間。北アフリカから東南アジアまで広く分布しており、生息地域によって外見が多様に変化する。","note":"","exp":"250"}],"2841":[{"type":"美術品","name":"毛益の絵画","rank":"2","desc":"南宋時代の画家・毛益が描いた、花と動物の絵。吉祥図であると思われる。\n古い絵画でありながらほとんど色あせていない。","note":"古の絵画の地図","exp":"210"}],"2374":[{"type":"海洋生物","name":"チンアナゴ","rank":"1","desc":"浅い海の底に生息する魚。チンという犬に顔が似ていることから、この名が付いた。\n群れになって砂の中から頭をのぞかせ、潮が流れてくる方向に顔を向けている姿がよく見られる。","note":"イヌ顔の魚の地図","exp":"130"}],"6252":[{"type":"歴史遺物","name":"グラゴル文字の石碑","rank":"3","desc":"東ヨーロッパ最古の文字と言われるグラゴル文字で記された石碑。グラゴル文字は９世紀にテサロニキ出身の聖職者キュリロスとメトディオスによってギリシャ文字をもとに考案され、キリル文字の原型になったとされている。","note":"","exp":"540"}],"1182":[{"type":"歴史遺物","name":"古代マヤ人の頭蓋骨","rank":"2","desc":"マヤの地の至るところで発掘される頭蓋骨。歯にひすいを埋めた跡があったり、扁平だったりと不気味なところがある。","note":"消えた古代人","exp":"270"}],"1323":[{"type":"地理","name":"カマウ半島","rank":"2","desc":"ヤーデインの西にある半島。古来より北方との交易の要衝として栄えてきた地域である。広大な湿地帯のため、農業を行うには高い灌漑技術が要求される。","note":"巨大な湿地帯","exp":"270"}],"1286":[{"type":"宗教遺物","name":"華厳経","rank":"2","desc":"けごんきょう。仏教経典のひとつ。仏陀の悟った世界について書かれている。","note":"古い法典の地図","exp":"240"}],"517":[{"type":"歴史遺物","name":"銀の装身具","rank":"1","desc":"銀で作られた装身具。単なる装身具ではなく護符など、特別な目的で作られた物が多いようである。","note":"古代の銀細工の地図","exp":"71"}],"2542":[{"type":"地理","name":"清水断崖","rank":"3","desc":"台湾島の東側に連なる2000m級の高い山々からできた崖。\n延々と絶壁が続いているため、近寄る者はあまりいない。","note":"台湾島東岸の地理調査<br/><br/>発見時経験値440　発見物カード経験値220","exp":"440"}],"2379":[{"type":"植物","name":"フクジュソウ","rank":"2","desc":"山林に生育する植物。初春に黄金色の花を咲かせる。\n蜜を作らず、その代わりに陽光を集めて暖かい場所を作ることで、虫を寄せて受粉する。","note":"雪溶かす花","exp":"270"}],"563":[{"type":"地理","name":"チグリス川","rank":"2","desc":"ペルシャを流れる大河で、ユーフラテス川と合流する。この流域は非常に古くから文明が栄えていたようで、独特の遺物が発見されるそうだ。いまは乾燥地帯だが、昔は豊かな土地だったのかもしれない。","note":"古代文明を育てた川","exp":"250"}],"2361":[{"type":"植物","name":"ヒノキ","rank":"2","desc":"日本と台湾に生育する常緑針葉樹。乾燥した場所でよく育つ。\n材は耐久性が高く、かつ光沢と芳香があるため、高級建築材として名高い。","note":"高級木材の調査","exp":"340"}],"5876":[{"type":"天文","name":"きりん座","rank":"5","desc":"北天の星座で、北極点の近くにある。一年を通して観測できる地域もあるが、目立つ星はなく知名度も低い。元となっているのは中国の神獣である麒麟ではなく、アフリカに生息するキリンである。","note":"クエスト「伝説の霊獣」<br/>発見物カード:705","exp":"1410"}],"507":[{"type":"歴史遺物","name":"古代の衣服","rank":"1","desc":"古代の衣類。地域によって素材や染色、縫製が異なる。それぞれの類似点から文化の伝達などがわかる。","note":"古代の衣服の地図","exp":"9"}],"5285":[{"type":"大型生物","name":"アダックス","rank":"3","desc":"コルク抜きのような形状の角が特徴の動物。砂漠の気候に適応しており、強烈な日差しに耐えられる分厚い皮膚や、砂に埋まりにくい幅広の蹄を有する。また、水を飲まずに一カ月以上、生き延びられる。","note":"","exp":"550"}],"1485":[{"type":"植物","name":"ポインセチア","rank":"1","desc":"苞（ほう）と呼ばれる赤い葉の中央に、小さな黄色い花を付ける。花よりも、葉に特徴のある植物である。","note":"赤い葉の植物の地図","exp":"45"}],"6981":[{"type":"港・集落","name":"サマルカンド","rank":"2","desc":"シルクロードの要衝として栄えた都市。東西を結ぶ中継地として古くから交易と文化の交流が行われ、これにより生まれた青いタイルは、多くのモスクや霊廟を飾り、青の都とも呼ばれている。","note":"","exp":""}],"3158":[{"type":"地理","name":"グリーンランド","rank":"5","desc":"アイスランドの北西に位置する島。氷床と万年雪に阻まれ、島の細部は確認不能。\n沿岸部の、氷がないほんの一部でのみ居住できる。しかしヴァイキングは、この地を「緑の国」と名づけて移住者を募った。","note":"「最果て」に迫る","exp":"1100"}],"2863":[{"type":"歴史遺物","name":"感震計","rank":"5","desc":"後漢時代の発明家・張衡が発明した銅で作られた感震計。揺れを感じると、震源地と反対側の玉が落ちるようになっている。1000kmほど離れた場所で発生した地震も感知できたようだ。","note":"地震の多い地域","exp":"980"}],"3416":[{"type":"植物","name":"イチイ","rank":"2","desc":"ヨーロッパの庭園でよく見られる針葉樹。赤い実は食用になるが、種に毒がある。イングランドやアイルランドでは教会によく植えられている。","note":"ハムレットの毒","exp":"230"}],"2052":[{"type":"虫類","name":"サスライアリ","rank":"4","desc":"サバンナなどに生息し定住せずに食料を求めて放浪する。他のアリに比べ、頭が大きく、目は退化している。\n100万匹近い集団で行動し、行く手を遮る動物を襲い、骨になるまで食べ尽くす。","note":"放浪アリ","exp":"680"}],"6986":[{"type":"海洋生物","name":"トラフザメ","rank":"3","desc":"インド洋から太平洋にかけて、浅い水深のサンゴ礁に生息しているサメ。全体的に平たい姿をしており、丸く横長の顔と長い尾びれが特徴。背中に黒い斑点模様がある。おとなしい性格で、人間を襲うことはめったにないという。","note":"","exp":""}],"5293":[{"type":"鳥類","name":"ケープハゲワシ","rank":"4","desc":"アフリカ南部に生息する大型の鳥。木の枝を組み合わせて断崖に巣を作る。巣作りに適した地形が少ないため、同じ場所に巣が集中したり、数世代にわたって同じ場所に巣が作り続けられたりすることもある。","note":"","exp":"680"}],"919":[{"type":"歴史遺物","name":"スパルタ兵の墓碑","rank":"2","desc":"テルモピレーの戦いでペルシャ軍に殲滅（せんめつ）されたスパルタ兵を悼（いた）んで建てられた墓碑。裏切った兵がペルシャ軍に道を教えたため挟撃にあい全滅したという。","note":"悲劇の追悼","exp":"230"}],"2749":[{"type":"地理","name":"漢拏山","rank":"2","desc":"済州島のほぼ中央に位置する火山。山の頂上には様々な伝説が残る湖もあるそうだ。\n記録によると、高麗時代に噴火があったようだ。","note":"［勅命］[[災害の事前観測","exp":"380"}],"1968":[{"type":"虫類","name":"ユカタンビワハゴロモ","rank":"5","desc":"ユカタン半島に生息する昆虫。羽を広げた姿はガに似ているが、体の質感はセミに近い。異様に大きな頭が特徴で、横から見るとワニの顔のように見える。","note":"空飛ぶワニ<br/><br/>発見時経験値820　発見物カード経験値410","exp":"820"}],"481":[{"type":"財宝","name":"勇王の王冠","rank":"1","desc":"イベリア半島北部にあるナバラ王国は、かつてイベリアでもっとも栄えていた。これは、初期の王家の王冠だと思われる。古いながらも丁寧で精巧な細工が施されている。","note":"古き時代の王","exp":"90"}],"59":[{"type":"美術品","name":"象牙の笛","rank":"2","desc":"アフリカで作られた、象牙製の笛。素朴で独特の彫刻が施されており、象牙本来の美しいカーブが生かされている。装飾品ではなく、実用にされていたと思われる。","note":"インドのゾウ使い","exp":"360"}],"6426":[{"type":"鳥類","name":"夏羽のライチョウ","rank":"4","desc":"夏羽に生え変わったライチョウ。褐色を帯びている。羽の生え変わりは一ヶ月ほどで行われる。あまり飛ばずに歩いて移動する。暑い日などは熱気を避けるためか、木々や洞窟、雪の中に隠れることもあるという。","note":"","exp":""}],"5527":[{"type":"気象・現象","name":"モーニンググローリー","rank":"2","desc":"世界各地で朝などに観測される巨大な帯状の雲。大きなものでは幅1000kmを越える。稀に複数発生するが、その発生原因などは不明である。","note":"アラフラ海　グルートアイランド島（カカドゥ東の巨大な湾の西側にある島）付近　晴天・午前","exp":"195"}],"6451":[{"type":"財宝","name":"オスマン帝母の金銀香炉","rank":"5","desc":"古くから中東で使われた、手持ちの柄が付いた香炉。オスマン帝国のスルタンの母君が聖地の寺院へ奉納するために送った品という。鉄製で金銀の豪華な象嵌が施されている。","note":"","exp":""}],"6146":[{"type":"中型生物","name":"ガボンアダー","rank":"3","desc":"アフリカの中南部に生息するヘビ。最大2ｍになるという。毒牙は長いもので5cmを超え、ヘビの中で最長。大人しい性質のようだが、致死性の猛毒を有するため、下手に刺激しないほうが賢明だろう。","note":"","exp":"520"}],"6542":[{"type":"史跡","name":"ボイン渓谷の羨道墳","rank":"5","desc":"アイルランドにある、先史時代の羨道墳。特定の時期のみ日光が差し込むその構造は、天文学的要素を用いて造られたものと考えられる。冬至に対応した遺跡以外にも、春分に対応して造られたとみられる、ノウスと呼ばれる遺跡がある。","note":"追究クエスト<br/>発見物カード:575","exp":"1150"}],"6953":[{"type":"海洋生物","name":"ヒロオウミヘビ","rank":"5","desc":"青い体色と黒の縞模様が特徴的なウミヘビ。尾が広く、平らな形をしていることからこの名がついた。捕食の際に海に潜る以外は陸上で生活する。性格は穏やかだが非常に強い毒を持つ。琉球では燻製にされ、薬膳料理の食材として使われる。","note":"","exp":""}],"7001":[{"type":"宗教遺物","name":"シャマシュの剣","rank":"5","desc":"メソポタミア神話に登場する、太陽神シャマシュが持つ武器。刃がのこぎり状をしている剣とされ、シャマシュの力の象徴ともいわれる。シャマシュは太陽神のみならず、正義と法の神としても長く崇拝された。","note":"レガシー法の叡智・正義の象徴 左上","exp":""}],"1704":[{"type":"宗教遺物","name":"契約の箱","rank":"5","desc":"旧約聖書に登場する契約の箱とされているもの。下部の四脚や上面に乗せられた二体のケルブなど聖書の記述と一致している。だが、納められていたはずの十戒が見つからないため、真偽のほどは定かではない。","note":"想いの行き着くところ","exp":"1248"}],"4842":[{"type":"天文","name":"うみへび座","rank":"4","desc":"ギリシャ神話に登場する怪物・ヒュドラが天に上げられたとされる星座。ヘラクレスと、その従者であるイオラオスによって退治されたといわれる。","note":"クエスト「勝負の行方」<br/>発見物カード:315","exp":"630"}],"6175":[{"type":"史跡","name":"ヒエラポリス・パムッカレ","rank":"5","desc":"古代ローマの都市のひとつであったヒエラポリスの遺跡。ローマより前に栄えたペルガモン王国の時代から温泉地として名高い一方で共同墓地も数多く存在している。アポロン神殿の近くに「冥王の門」と呼ばれる洞窟があるという。","note":"","exp":"990"}],"6251":[{"type":"歴史遺物","name":"プリニウスの博物誌","rank":"2","desc":"古代ローマの政治家・博物学者であった大プリニウスの著作で、全37巻にわたって地理・天文・歴史・自然を網羅している。世界七不思議とされた建造物についても述べられているほか、各地で見聞きした怪物などについての記録もある。","note":"","exp":"310"}],"5883":[{"type":"中型生物","name":"アルパカ","rank":"5","desc":"南米などに生息するラクダの仲間。非常に高品質の毛を収穫できるため、古来から優秀な家畜として利用されてきた。ただ、威嚇する際に非常に臭い唾液を吐き出す習性があるため注意が必要。","note":"","exp":"1400"}],"5348":[{"type":"天文","name":"ピーコック","rank":"4","desc":"くじゃく座で最も明るい星で、２等星。\n名はオスのクジャクを意味する。","note":"発見物カード:340","exp":"680"}],"6834":[{"type":"鳥類","name":"ゴイサギの幼鳥","rank":"5","desc":"ゴイサギの幼鳥は、褐色の翼に白い羽が反転のように入る。これが星のように見えるため「ホシゴイ」とも呼ばれる。成鳥とは外見が異なり、別の鳥と誤解されることもあるという。","note":"追究クエスト<br/>発見物カード:440","exp":"880"}],"6680":[{"type":"史跡","name":"ディオクレティアヌス宮殿","rank":"5","desc":"皇帝ディオクレティアヌスが帝位を退いたのち暮らした宮殿。アドリア海に面した港町スプリトに建てられた。高さ20ｍ以上の強固な城壁で囲まれている。こういった軍事施設としての側面と、宮殿としての豪奢さを持ち合わせている。","note":"","exp":"1080"}],"5153":[{"type":"港・集落","name":"マッサワ","rank":"1","desc":"アフリカ北東部の街。紅海に面しており、「紅海の真珠」とも呼ばれる。非常に歴史の古い地域で、初期のキリスト教の名残が多くある。豆や穀類を中心とした農作物のほか、この地方が原産のコーヒーが流通している。","note":"到達する","exp":"126"}],"1470":[{"type":"財宝","name":"ジャヤヴァルマン7世の頭部","rank":"2","desc":"アンコール王朝の王ジャヤヴァルマン7世の像の頭部。心無い破壊に遭い頭から下は壊されてしまった。この王は勇猛果敢で知られ、王朝に多くの勝利をもたらしたが、アンコール・トムを建設するなどの信心深い一面も見られる。","note":"時代の守護者","exp":"330"}],"5299":[{"type":"小型生物","name":"クロクビコブラ","rank":"4","desc":"アフリカ中部に生息する毒ヘビ。頭の後ろが黒いことが、名前の由来とされる。背面は暗褐色。攻撃の際に敵の目を狙って毒液を飛ばすことがあり、その飛距離は3mにも達する。毒も強力で、咬まれた部位が壊死(えし)するほどである。","note":"","exp":"700"}],"6880":[{"type":"虫類","name":"ニコヤカヒメグモ","rank":"5","desc":"ハワイ諸島にのみ生息する珍しいクモ。体長はおよそ5mmで、細長い脚と半透明の黄色い体を持つ。人間の笑顔を思わせる変わった模様から、その名が付いた。","note":"発見物カード:730","exp":"1460"}],"5748":[{"type":"地理","name":"アンガラ川","rank":"2","desc":"バイカル湖から流れ出す唯一の川。湖の南西端から北に向かって流れ、複数の川と合流したうえで最終的には北極海に流れ込む。","note":"2017.02.07新規追加","exp":""}],"5302":[{"type":"鳥類","name":"ホオカザリヅル","rank":"2","desc":"アフリカ南部の湿原に生息するツル。頭が白く、体は暗い色の羽毛で覆われる。顔は特徴的に、頬の下部からトカゲ状の肉が垂れている。また、くちばしの付け根から顔にかけては羽毛がなく、赤い地肌が露出している。","note":"発見時経験値230　発見物カード経験値115","exp":"230"}],"5362":[{"type":"宗教建築","name":"サトゥルヌス神殿","rank":"2","desc":"サトゥルヌスとはローマ神殿の農耕神で、ギリシャ神話のクロノスにあたる。ローマのサトゥルヌス神殿は共和政時代に国有財産や公文書の保管庫としても用いられた。","note":"","exp":"380"}],"5272":[{"type":"レリック","name":"滅びし国の物語","rank":"","desc":"","note":"","exp":""}],"3011":[{"type":"歴史遺物","name":"クローヴィス尖頭器","rank":"3","desc":"先史時代、クローヴィス文明で使用されていたと思われる石器。独特の浅い溝が基部に施されている。マンモスやバイソンの狩猟に広く用いられていたようだ。","note":"人類の歴史","exp":"490"}],"1301":[{"type":"中型生物","name":"テングザル","rank":"2","desc":"ボルネオ島に生息するサル。オスは大きく垂れ下がった鼻を持つ。水辺を好み、足には水かきがある。","note":"島に棲むサル","exp":"320"}],"5619":[{"type":"海洋生物","name":"タカアシガニ","rank":"5","desc":"東アジアの深海に生息するカニの一種。脚が非常に長く、成長したオスが鋏足を広げると4m近くに達することがある。","note":"","exp":"990"}],"1180":[{"type":"財宝","name":"マインエンゲル","rank":"5","desc":"レスカトールが使っていたギター。彼は人気闘牛士を辞めて、ミカエラのギタリスタになった。弦が多く複雑な音が出せる分、かなりの技巧がなければ扱うことは難しいだろう。","note":"遠い約束<br/><br/>発見時経験値949　発見物カード経験値474","exp":"949"}],"6654":[{"type":"中型生物","name":"グラウンドホッグ","rank":"5","desc":"リス科最大級の動物。別名ウッドチャック。北米の森林地帯周辺に生息する。複雑なトンネル網を構築し、巣とする。トンネルを掘る際、土をほぐしてくれるので、農家からは益獣として親しまれている。気性は荒い。","note":"","exp":"1150"}],"3677":[{"type":"海洋生物","name":"クリオネ","rank":"5","desc":"寒流域に生息する海洋生物。半透明の体で、内臓が見えている。\n海中をふわふわと漂うように泳ぐさまは幻想的だ。ギリシャ神話の女神が名前の由来とされている。","note":"氷海の天使","exp":"1350"}],"6566":[{"type":"大型生物","name":"スマトラサイ","rank":"5","desc":"インドネシアの熱帯雨林に生息するサイ。他のサイと比べると小柄で、全身に長い体毛が生えているのが特徴。角は2本あり、薬や工芸品目的で狩猟されることもあるという。","note":"追究クエスト","exp":"1550"}],"2545":[{"type":"鳥類","name":"ルリチョウ","rank":"5","desc":"台湾島にのみ生息する鳥。体長は30cmほどあるが、尾は短い。\n脚とくちばしががっしりとしているのが特徴である。","note":"船乗りの言い争い","exp":"930"}],"110":[{"type":"地理","name":"バハマ諸島","rank":"2","desc":"カリブ海のキューバ島の北に点在する島々。属する島は700にもなるが、人が住めそうな島は50もない。この北には北米大陸が広がっている。","note":"カリブへの足がかり","exp":"360"}],"1903":[{"type":"歴史遺物","name":"ひすいの盃","rank":"1","desc":"ひすいで作られた大型の盃。これだけ大きなものを作れるということはひすいの産出が豊富だったのであろう。","note":"メソアメリカの盃の地図","exp":"190"}],"3890":[{"type":"天文","name":"アンドロメダ座","rank":"2","desc":"エチオピアの王女アンドロメダが死後に天に昇った姿とされる。アンドロメダはペルセウスとの間に六人の子をもうけ、長子ペルセスはペルシャ王家の祖となったといわれる。","note":"クエスト「エチオピアの王女」<br/>発見物カード:185","exp":"370"}],"2496":[{"type":"美術品","name":"市中風俗絵巻","rank":"2","desc":"都に住む人々の様子を描いた日本の絵巻物。人々の服装や街並み、祭りの光景などが、克明かつ生き生きと描き出されている。美術品であると同時に、描かれた当時の文化を示す貴重な史料でもある。","note":"人々の暮らしの調査法","exp":"260"}],"4957":[{"type":"天文","name":"ミザールとアルコル","rank":"2","desc":"ミザールは北斗七星のひしゃくの柄の先から2番目にあたる星。アルコルはミザールのすぐ脇にある4等星。昔からこの2つの星が見分けられるか否かが視力の検査に利用されてきた。","note":"クエスト「兵士の条件」<br/>発見物カード:125","exp":"250"}],"3881":[{"type":"歴史遺物","name":"サン・ダガー","rank":"5","desc":"北米の内陸部にある、岩を重ねて作られた装置。天体観測に使われたとみられる。重ねられた岩の隙間から差す太陽光が、短剣状の形となって岩壁に映る仕組みとなっている。岩壁側には、夏至などの際の光の位置を示す模様が刻まれている。","note":"壁画に差す光","exp":"940"}],"5909":[{"type":"天文","name":"西方七宿白虎","rank":"5","desc":"中国星座において、天の赤道を28に分割した二十八宿のうち西方の七宿をまとめたもの。おひつじ座やオリオン座などが含まれる。","note":"クエスト「杭州への再々調査依頼」<br/>発見物カード:730","exp":"1460"}],"5741":[{"type":"化石","name":"コブのある獣の化石","rank":"1","desc":"巨大なコブが頭蓋にある獣の化石。何のためのコブだったのかはわからないが、骨以外の器官が存在していたかもしれない。","note":"","exp":""}],"6498":[{"type":"宗教建築","name":"バールベックの巨石","rank":"5","desc":"パールベックの遺跡にある巨石。遺跡はローマの神々のうち三柱を祭った3つの神殿で構成されており、そのうちの1つ、ジュピター神殿の土台となっているのが「パールベックの巨石」と呼ばれる3つの巨石である。","note":"","exp":""}],"1275":[{"type":"地理","name":"モルッカ諸島","rank":"3","desc":"セレベス島東部に位置する諸島。\n長らく不明であった香辛料・クローブの原産地がこのモルッカ諸島であったため、香料諸島とも呼ばれる。","note":"クエスト「根源地を探せ」<br/>発見物カード:240","exp":"484"}],"6066":[{"type":"財宝","name":"プロコピオスの秘史","rank":"4","desc":"東ローマ帝国の名将ベリサリウスに仕えた書記官であるプロコピオスの著作。　「戦史」とは真逆の内容であり、ユスティニアヌス1世と皇妃、ベリサリウスとその妻らの醜聞や批判が辛辣に綴られている。","note":"","exp":"740"}],"2384":[{"type":"小型生物","name":"ヤマネ","rank":"2","desc":"日本にのみ生息する、6～8cmのネズミのような小動物。集団で冬眠し、その期間は半年近くにも及ぶ。\n敵に襲われると尻尾の毛を残して逃げるが、抜けた毛が再生することはない。","note":"小さな毛玉","exp":"270"}],"2434":[{"type":"財宝","name":"べっこうの櫛","rank":"2","desc":"べっこう製の櫛。\n素材のべっこうを生かしながら、細かな装飾も施されている。\n日本の女性は髪を梳くためだけでなく、髪飾りとしても使用するらしい。","note":"ダンジョン","exp":"360"}],"166":[{"type":"宗教建築","name":"ブリハディーシュヴァラ寺院","rank":"2","desc":"破壊神シヴァを祀る南インドの寺院。チョーラ朝のラージャラージャ1世が建てたとされる。ヴィマーナと呼ばれる非常に大きな本堂を持つ。","note":"シヴァに献じられし寺院","exp":"300"}],"1218":[{"type":"財宝","name":"花酔いの石","rank":"5","desc":"巨大な蛍石の原石。これだけ大きなものはなかなか見ることができない。蛍石の中には、太陽光にあてると発光するものがあるが、これは非常に強く発光する。見るものに軽い酩酊感を与えるためこの名がついたようだ。","note":"花酔い","exp":"1144"}],"3698":[{"type":"中型生物","name":"ミクロメリクス","rank":"3","desc":"シベリアジャコウジカの亜種とされる動物。生態はジャコウジカとほぼ同じであるが、あまり姿を見ることがない。","note":"珍しいシカの地図","exp":"540"}],"5181":[{"type":"港・集落","name":"ワンガヌイ","rank":"2","desc":"アオテアロアの南岸に位置する街。古くからマオリ人が居住し、交易の拠点であった。ワンガヌイとはマオリ人の言葉で「大きな港」を意味する。","note":"到達する","exp":"380"}],"5715":[{"type":"気象・現象","name":"砂竜巻","rank":"2","desc":"砂漠地帯で発生する竜巻。多く砂を舞い上げるため、通常の竜巻とは色が異なって見える。また、大規模な砂竜巻は、小さな街をのみ込むほどの大きさになるという。","note":"アフリカ北岸より奥地　サハラ　斜め岩付近<br/>日中","exp":""}],"5307":[{"type":"小型生物","name":"サバクトゲオアガマ","rank":"2","desc":"サハラに棲む草食のトカゲ。全長が40cmを超えるものもいる。トゲのある鱗に覆われた太い尾を持ち、身を守る際にはこの尾で攻撃することがある。昼間に活動するが、あまり暑さが厳しいと穴に隠れてしまうようだ。","note":"","exp":"280"}],"6110":[{"type":"伝承","name":"不死鳥の復活","rank":"5","desc":"フェニックスはその見た目や特徴から、不死鳥や火の鳥とも呼ばれている。また「復活する」という特徴がキリストの復活とも結び付けられ、多くの人々から象徴的な存在として重要視された。そのため、伝承の生物の中でも高い認知度を持つ。","note":"","exp":"970"}],"6138":[{"type":"美術品","name":"御者の像","rank":"1","desc":"デルフォイ遺跡で発見された御者の青銅像。競技会で優勝した御者の功績を讃えるために奉納されたものであろう。均整の取れたすばらしい像である。","note":"古代ギリシャの傑作","exp":"130"}],"5240":[{"type":"史跡","name":"アルテミス神殿跡","rank":"4","desc":"紀元前から紀元3世紀ごろにかけて存在した神殿。女神アルテミスを奉った総大理石の神殿であったが、放火や破壊に遭い、現在は原型を留めていない。世界七不思議の一つ。","note":"神殿の真実","exp":"640"}],"6266":[{"type":"中型生物","name":"オウゴンヤマネコ","rank":"2","desc":"中国南部、インド、ネパールからスマトラ島にかけて生息している中型のネコで、中国では「彪（ひょう）」と呼ばれている。\n主に毛皮が珍重されており、骨に薬効があるという噂もあるが、その真偽は不明である。","note":"","exp":"220"}],"643":[{"type":"地理","name":"オレンジ川","rank":"1","desc":"アフリカ南部を東西に流れる大河。流域には豊富な鉱脈があると思われるが、途中に大きな滝があって水運は難しそうだ。","note":"書きかけの地図","exp":"120"}],"6358":[{"type":"地理","name":"ジャイアンツ・コーズウェー","rank":"2","desc":"アイルランド北東部にある海岸。溶岩が冷えて固まってできた石柱がいくつも並ぶ。石柱は六角柱の形をしたものが多い。伝承では、アイルランドの巨人が戦いに行く際に作ったともいわれる。","note":"","exp":"370"}],"772":[{"type":"歴史遺物","name":"先史時代の焚き火跡","rank":"1","desc":"人間が火を使った跡。火は人間の文化的営みの象徴であり、これがあれば人間が何らかの活動を行っていたと推測できる。","note":"先史時代の史跡の地図","exp":"19"}],"4971":[{"type":"宗教建築","name":"メテオラ","rank":"2","desc":"ピンドス山脈麓の岩山群の上に建てられた修道院。修道僧が祈りに専念できるよう、俗世から隔絶された場所に建てられた。ギリシャ語で「宙に浮く」という意味の「メテオロス」という言葉が名に由来している。","note":"","exp":"210"}],"2700":[{"type":"財宝","name":"暗行御史の変装道具","rank":"3","desc":"暗行御史（あんこうぎょし）とは、朝鮮王朝において地方官の監察を秘密裏に行った国王直属の官吏。派遣された地で変装し、内偵を行う。\nより多くの情報を入手するため、さまざまな変装道具を使用する。","note":"正義の使者を舞うために","exp":"470"}],"1789":[{"type":"宗教遺物","name":"ククルカン像","rank":"1","desc":"ククルカンとは、アステカの神・ケツアルコアトルのマヤ語名。また、高地のある民族にはクグマッツとも呼ばれる。チチェンイッツァで特に崇められた神である。","note":"メソアメリカの像の地図","exp":"200"}],"1128":[{"type":"財宝","name":"ガラスの香水瓶","rank":"5","desc":"装飾がふんだんに施された、豪華なガラス製の香水瓶。ふたには二羽の鷲の頭が彫られている。\n底には「いつか乗り越えるべき大きなもの。その剣は重く、その心はフランドルの土より広く優しい」とある。","note":"瓶詰めの思い出<br/><br/>発見時経験値1014　発見物カード経験値507","exp":"1014"}],"6077":[{"type":"美術品","name":"ネフェルティティの胸像","rank":"3","desc":"古代エジプトのファラオであったアメンホテプ4世の妃、ネフェルティティをモデルにしたとされる彫刻像。発掘された職人の工房跡では同型の彫像がいくつも出土しており、弟子たちの教育や練習を目的として作られたという説がある。","note":"","exp":"480"}],"1069":[{"type":"宗教遺物","name":"カーリー像","rank":"4","desc":"インド神話の女神の像である。三大神のシヴァの妻の一人である。黒い肌にドクロをつなげた首飾りを下げた姿で描かれる。殺戮と破壊をつかさどる女神である。","note":"殺戮の女神","exp":"624"}],"515":[{"type":"歴史遺物","name":"金の装身具","rank":"1","desc":"金で作られた装身具。形や使い方が文明によってさまざまで、古代文明の交流や流通を知る手がかりになる。","note":"古代の金細工の地図","exp":"74"}],"1676":[{"type":"歴史遺物","name":"クペの木槍","rank":"5","desc":"クペの名を冠した、木の槍。クペとは、ハワイキよりアオテアロアに移住してきたといわれる、マオリの祖先である。クペがアオテアロアを発見してから、多くのハワイキの民が移住してきた。","note":"クペの木槍","exp":"1040"}],"2381":[{"type":"植物","name":"ツキヨタケ","rank":"2","desc":"広葉樹の枯れ木に群生する毒キノコ。誤って食べてしまうと、視界が青くなるような幻覚症状を引き起こしてしまう。\n日本では古くから毒キノコとして知られており、今昔物語にも登場する。","note":"極東の鬼火","exp":"320"}],"5505":[{"type":"港・集落","name":"ビルバオ","rank":"1","desc":"イベリア半島北部に位置する街。古くから商業の中心地であり、19世紀に入ると工業も発達してきた。","note":"座標　16051,2942","exp":"16"}],"618":[{"type":"宗教遺物","name":"ソコ像","rank":"2","desc":"西アフリカのギニア湾沿岸に住む、ヌペ人の神話における創造神の像である。この地域には多くの民族が住み、古代から栄えている。各民族の神話には互いの影響が見られ、興味深い。","note":"死をくれた神","exp":"250"}],"430":[{"type":"海洋生物","name":"シャチ","rank":"1","desc":"10m近い体長の、クジラの仲間。特徴のある模様と人間の身長より大きな背びれを持つ。かなり大きな群れで目撃されることもある。鳴き声で仲間と連絡をしているようだ。","note":"巨大で凶暴なイルカ","exp":"200"}],"6264":[{"type":"歴史遺物","name":"メンダーニャの航海誌","rank":"3","desc":"１６世紀のイスパニア人探検家アルバロ・デ・メンダーニャ・デ・ネイラが南米やオセアニアを回った時に残した記録。財宝を求めて航海を続け、ソロモン諸島を発見するが、財宝を見つけることはできなかったという。","note":"","exp":"480"}],"5038":[{"type":"港・集落","name":"カリカット","rank":"1","desc":"インド西岸にある大都市。中国～南インド～アラビア交易で栄え、富裕な商人が多い。香辛料や茶、染料、宝石など、ヨーロッパで高く売れる商品が流通している。","note":"到達する","exp":"180"}],"6437":[{"type":"歴史遺物","name":"ネイピアの骨","rank":"5","desc":"スコットランドのジョン・ネイピアが17世紀初めに発明した計算器具。ラブドロジーとも呼ばれる。九九の表が組み込まれて掛け算を簡単にできるほか、応用として複数桁同士の掛け算や割り算、平方根を求める計算なども可能。","note":"レガシー　数の叡智・世界の計算機　左下","exp":""}],"5029":[{"type":"港・集落","name":"オデッサ","rank":"1","desc":"黒海に面している港湾都市。さまざまな物資が集散する貿易港である。","note":"到達する","exp":"40"}],"450":[{"type":"美術品","name":"受胎告知（マルティーニ）","rank":"1","desc":"シモーネ・マルティーニ作の祭壇画。製作当時は複数の絵からなる大規模なものだったという。この時代の宗教画としては人物が表情豊かで、新しい時代の到来を思わせる。","note":"教会の宗教画の地図","exp":"40"}],"3897":[{"type":"天文","name":"おおいぬ座","rank":"2","desc":"どんな獲物をも捕まえる運命と定められた猟犬ライラプスが空に上げられた姿とされる。誰にも捕まらない運命を持った狐を追ったライラプスは、大神ゼウスによって石に変えられ、天にあげられたといわれる。","note":"クエスト「猟犬の伝説」<br/>発見物カード:120","exp":"240"}],"1342":[{"type":"小型生物","name":"メガネザル","rank":"4","desc":"メガネのように大きな瞳が特徴のサル。目を動かせないかわりに、首を真後ろまで回転できる。","note":"大きな瞳","exp":"636"}],"5255":[{"type":"歴史遺物","name":"オロシーバ兄弟のカヌー","rank":"2","desc":"かつてこの遺跡を作ったオロシーバ兄弟が島へ渡るのに使ったとされるカヌー。損傷の具合から、その後も島々を行き来するために使用され続けたと思われる。","note":"","exp":""}],"3809":[{"type":"宗教遺物","name":"ブードゥー教の十字架","rank":"5","desc":"ブードゥー教の儀式で用いられる十字架。死や墓場を司る神であるバロン・サムディの象徴でもある。","note":"ブードゥー教の神","exp":"510"}],"1799":[{"type":"美術品","name":"ネーデルラントの諺","rank":"1","desc":"ピーテル・ブリューゲル（父）の作。ネーデルラントに伝わる諺を90種以上描きこんでいる。例えば右下の粥をこぼしている男性がいる。これは「こぼした粥は器に戻らない」つまりは取り返しのつかないことを意味する諺である。","note":"文字のない格言集","exp":"110"}],"5625":[{"type":"宗教建築","name":"エチミアジン大聖堂","rank":"3","desc":"アルメニアの大主教がキリスト降臨のビジョンを見て建てさせたという世界最古の教会。","note":"","exp":"470"}],"5734":[{"type":"中型生物","name":"バイカルアザラシ","rank":"5","desc":"バイカル湖周辺にのみ生息するアザラシ。淡水のみに棲む珍しい種で、バイカル湖の生態系の頂点に立つとされる。獲物を探すための大きな目を有する。","note":"2017.02.07新規発見<br/><br/>意外なことに！？大型生物でも海洋生物でもなく、中型生物。","exp":""}],"2795":[{"type":"史跡","name":"万里の長城","rank":"5","desc":"全長6000km以上にも及ぶ堅固な大城壁。\n秦の始皇帝が、国の北側に建造された城壁をつなぎ合わせて造ったのが始まりである。","note":"華北の建造物調査","exp":"1190"}],"6987":[{"type":"歴史遺物","name":"有刺利器","rank":"2","desc":"伽耶時代に作られた鉄器。板状に延べた鉄の側面を囲むように鳥形の装飾が取り付けられている。その独自の形状から葬儀などの儀式に使用されたと考えられる。","note":"","exp":""}],"1925":[{"type":"鳥類","name":"コクチョウ","rank":"1","desc":"黒いハクチョウ。渡り鳥であるハクチョウとは違い、同じ場所で一生を過ごす。巣は、湖沼などの水辺に作る。主にオーストラリアやアオテアロアに生息する。","note":"黒い鳥の地図","exp":"180"}],"3769":[{"type":"歴史遺物","name":"カエサル彗星のコイン","rank":"4","desc":"カエサル暗殺後に現れた彗星をかたどったコイン。カエサルの後継者オクタヴィアヌスが鋳造させた。ローマ市民はこの星を見てカエサルの魂が天に帰るのだと信じたと、スエトニウスは記している。","note":"古代の大彗星","exp":"610"}],"1768":[{"type":"宗教遺物","name":"アクリャの調理用具","rank":"3","desc":"アクリャとは、インカ帝国の宗教行事に従事していた女性たちである。容姿端麗な10歳に満たない少女から選ばれ、家柄・血筋は関係なかった。アクリャの作る生産品は、インカ帝国の経済の根本を支えていた。","note":"ある巫女の物語","exp":"530"}],"6641":[{"type":"財宝","name":"ドン・キホーテ","rank":"2","desc":"イスパニアの作家ミゲル・セルバンテスの小説。騎士物語に憧れすぎて自らを騎士だと妄想してドン・キホーテと名乗る男の冒険譚。批判精神に富み、騎士道に代表される古き慣習への諷刺が読み取れる。","note":"","exp":"360"}],"6435":[{"type":"歴史遺物","name":"黒と赤の算木","rank":"5","desc":"算盤（そろばん）普及前に東アジア全域で使われていた。木片を並べて計算する器具。中世日本では、正の数を表す赤色と負の数を表す黒色の二色の算木を用いた。格子が描かれた布や板製の算盤（さんばん）上に並べて計算した。","note":"レガシー　数の叡智・世界の計算機　下","exp":""}],"3641":[{"type":"歴史遺物","name":"ゲル","rank":"4","desc":"遊牧民が用いる、木と布でできた移動式の住居。ザナドゥ内で見られる。円形に組んだ骨組みの上に布をかける仕組みで、分解と組み立てが簡単に行える。","note":"遊牧民たちの住居","exp":"730"}],"6301":[{"type":"財宝","name":"トゥアレグのペンダント","rank":"5","desc":"サハラ西部の遊牧民族であるトゥアレグ民族が身に着ける装身具。銀でできている。家系や出身地によってさまざまな形があり、親から子へ代々受け継がれる。砂漠で方角を示すコンパスをかたどっているとされる。","note":"","exp":"1130"}],"5324":[{"type":"地理","name":"マカディカディ塩湖","rank":"1","desc":"アフリカ南部の乾燥地帯にある、世界屈指の広さを誇る塩類平原。いくつかの川が流れ込んでおり、雨季の間のみ水が溜まって塩湖になる。水と塩、草を求めてさまざまな種類の動物が集まる。","note":"経験値修正","exp":"190"}],"6593":[{"type":"史跡","name":"在りし日のバビロンの大城壁","rank":"5","desc":"新バビロニア王国の王ネブカドネザル2世が首都バビロンの街を守るために建造させた大城壁。街を取り囲む城壁は、青い彩釉レンガや数多のレリーフが施された絢爛豪華な造りで、北部にはイシュタル門とよばれる壮麗な門が備わる。","note":"レガシー伝説の王都バビロン　上","exp":"4000"}],"6977":[{"type":"地理","name":"ヒリアー湖","rank":"2","desc":"オーストラリア南西部のルシェルシェ諸島に位置する塩湖。季節や天候にかかわらず湖水は鮮やかなピンク色を保ち、白い砂に囲まれた湖面は洋上からも確認することができる。","note":"発見物カード:190","exp":"380"}],"5533":[{"type":"気象・現象","name":"環水平アーク","rank":"4","desc":"太陽の下の薄い雲に虹色の光の帯が重なって見える現象。他の光学現象とは異なり、円形ではなく水平な帯状で現れる。","note":"北米大陸東岸（上陸地点）　日中？　晴天？　南東の浜辺の南の端付近　視認R9以上必要かも？<br/>経験値は冒険職で７６０と登録してあるのを修正してあるようですね。","exp":"380"}],"3908":[{"type":"天文","name":"しし座流星群","rank":"2","desc":"しし座の方角から飛び出してくるように見える流星群。1833年に大出現し、北米東部では眠っている人が流星の明るさで目が覚めるほどだったといわれる。","note":"発見物カード:120","exp":"240"}],"5515":[{"type":"財宝","name":"ヴァリハ","rank":"3","desc":"マダガスカルの伝統的な竹製の楽器。東南アジアの各地に似た楽器があり、東南アジアからマダガスカルへの移住に伴って持ち込まれた楽器が起源と推測される。","note":"","exp":"470"}],"6098":[{"type":"地理","name":"コリント地峡","rank":"1","desc":"バルカン半島とペロポネソス半島をつなぐ、幅わずか7kmの地峡。この地域は平地が少なく乾燥気味で、オリーブ栽培や牧畜が盛んである。","note":"ギリシャ近海の地形","exp":"70"}],"1963":[{"type":"財宝","name":"インカ戦士の棍棒","rank":"2","desc":"インカ戦士の一般的な武器。持ち手には彩色された家畜の毛が巻きつけられ、先端には石がくくりつけられている。","note":"戦士の証<br/><br/>発見時経験値330　発見物カード経験値165","exp":"330"}],"647":[{"type":"地理","name":"ソコトラ（地理）","rank":"1","desc":"アデンの東に浮かぶ島である。歴史は古く、軍事的に重要な場所。","note":"書きかけの地図","exp":"190"}],"5620":[{"type":"財宝","name":"メシエカタログ","rank":"5","desc":"フランスの天文学者であるシャルル・メシアが作成した、天体についての書籍。星雲や星団など、あらゆる天体の目録となっている。","note":"クエスト「天体一覧」<br/>発見物カード:515","exp":"1030"}],"5762":[{"type":"気象・現象","name":"セントエルモの火","rank":"3","desc":"悪天候での航海時に、船のマストの先が発光する現象。時代や地域によって他の名で呼ばれることもある。発光現象が2つ同時に起こると、悪天候が収まるという伝承もある。","note":"2017.02.07新規追加","exp":""}],"688":[{"type":"地理","name":"アガラス岬","rank":"2","desc":"アフリカ最南端の岬。喜望峰はここから数十km北西にある。本来なら、こちらを喜望峰とするべきではないか？","note":"真の最南端","exp":"230"}],"813":[{"type":"財宝","name":"フリードリヒ1世の鎧","rank":"2","desc":"フリードリヒ1世は、「赤髭王」と呼ばれた神聖ローマ皇帝。第3回十字軍に従軍したがキリキア付近で渡河中に落馬し、溺死した。","note":"大帝の追憶","exp":"360"}],"3937":[{"type":"天文","name":"アルタイル","rank":"1","desc":"わし座で最も明るい星で白く輝く1等星。夏の大三角の一角を構成する。名はアラビア語で「飛翔する鷲」を意味する。","note":"「明るい星の観測記録」<br/><br/>発見物カード:35","exp":"70"}],"6992":[{"type":"海洋生物","name":"オウサマペンギンの幼鳥","rank":"5","desc":"茶色の幼綿羽が全身を覆っているオウサマペンギンの幼鳥。孵化直後は灰色の短い毛に覆われているが、成長と伴にふわふわとした茶色の毛に換羽する。親のそばを離れずに育ち、数カ月親と同じ見た目になる。","note":"","exp":""}],"3730":[{"type":"歴史遺物","name":"蒙古字韻","rank":"5","desc":"モンゴルの文字であるパスパ文字を、東アジアの言語で解説したとされる書物。作者は不明。多くの写本が作られたと思われる。","note":"文字資料収集","exp":"960"}],"1210":[{"type":"地理","name":"ダリエン湾","rank":"1","desc":"カリブ海南方の湾。コロン提督が訪れ、以後イスパニア人の手によって港が建造された。天然の良港として知られる。","note":"クエスト「新大陸西岸への道」<br/>発見物カード:60","exp":"120"}],"6418":[{"type":"中型生物","name":"産毛のアザラシ","rank":"4","desc":"アザラシは、世界中の広い海域に生息している。その中でも、海氷上に生息する種の子供は、白色の産毛を持って生まれるといわれ、とても可愛らしい姿をしている。","note":"追究クエスト「アザラシの追加調査」<br/>発見物カード:385","exp":"770"}],"5139":[{"type":"港・集落","name":"ベンガジ","rank":"1","desc":"古代ギリシャ時代に建設された都市が起源。街の名は、街の繁栄に貢献した人物に由来する。","note":"到達する","exp":"19"}],"29":[{"type":"地理","name":"喜望峰","rank":"2","desc":"アフリカ南部の岬。周囲の気象が荒く、ディアスはこれ以上の航海を断念した。ディアスは「嵐の岬」と名づけたが、その後ポルトガル王によって喜望峰と改められた。","note":"アフリカの南端","exp":"235"}],"1028":[{"type":"中型生物","name":"ジャッカル","rank":"1","desc":"犬やキツネに似た、肉食動物。キツネよりやや大きい。体色は何種類かあるようだ。","note":"野生の犬の地図","exp":"59"}],"3823":[{"type":"海洋生物","name":"コンクガイ","rank":"5","desc":"ピンクガイとも呼ばれる巻貝。殻の内側の淡いピンク色が特徴である。カリブ海全域に生息し、食用としても重宝されている。","note":"桃色の理由","exp":"1100"}],"6552":[{"type":"植物","name":"ムキタケ","rank":"5","desc":"広葉樹の枯れ木に群生するキノコ。毒はなく滑らかな触感とくせのない味わいで、よく食用にされる。ただし、毒キノコのツキヨタケとよく似ているため、採取時にはくれぐれも注意が必要である。","note":"追究クエスト","exp":"1500"}],"2664":[{"type":"財宝","name":"踊り子の扇子","rank":"2","desc":"朝鮮の踊りで使用される扇子。\n華やかで美しい装飾が施されているものから質素な柄のものまで、種類は幅広い。","note":"珍しい舞","exp":"260"}],"2973":[{"type":"海洋生物","name":"メガマウス","rank":"5","desc":"太平洋やインド洋の比較的暖かい海に生息しているサメ。巨大な体躯をしているが、目撃例が少ないため、これが大人なのか子供なのかはわからない。大きな口で、あらゆるものを吸い込むようにして食事をするようだ。","note":"波間にたゆたう銀の怪火","exp":"1160"}],"393":[{"type":"大型生物","name":"ローンアンテロープ","rank":"2","desc":"オス、メスともに特徴的な角とたてがみを持つ。乏しい草でも生き延び、オス1匹にメス複数匹、または若いオス同士の群れで行動する。","note":"クエスト「角とたてがみを持つ動物」<br/>発見物カード:130","exp":"260"}],"6839":[{"type":"植物","name":"ディエテス・ビコロル","rank":"2","desc":"南アフリカに生息するアヤメの一種。薄黄色の花びらに黒褐色の丸い模様が3つあるのが特徴。花数は多くつくが、花は1日ほどでしおれてしまう。乾燥に強く、日光が少なくても育つ。","note":"発見物カード:140","exp":"280"}],"1185":[{"type":"地理","name":"マゼラン海峡","rank":"5","desc":"マゼランが、太平洋に出るために航行したことから、その名がついた海峡。非常に狭く、地形も複雑であるため航海の難所として有名である。","note":"エル・パソ","exp":"1040"}],"6709":[{"type":"天文","name":"アルタルフ","rank":"4","desc":"かに座で最も明るい星で、４等星。カニの脚の先に位置している。名はアラビア語で「終わり」を意味する。","note":"発見物カード:355","exp":"710"}],"1686":[{"type":"海洋生物","name":"アマゾンカワイルカ","rank":"2","desc":"アマゾン川に生息するイルカ。体色はピンクや灰色のまだらで、毛のはえた長いくちばしを持っている。カニやカメなどを食べる。","note":"川に棲むイルカの地図","exp":"255"}],"6831":[{"type":"鳥類","name":"ルリサンジャク","rank":"5","desc":"南米の中南部に生息する鳥。頭と胸、翼が黒く、腹と尾羽の先が乳白色ときれいに分かれている。目の上に人の眉毛のような青い眉斑があり、愛嬌のある表情に見える。","note":"発見物カード:455","exp":"910"}],"1683":[{"type":"歴史遺物","name":"ひすいの仮面","rank":"5","desc":"パレンケ遺跡から見つかった石棺の中に納められていた。パレンケ最盛期の王・パカルのものではないかといわれているが、くわしくは不明。顔面部はひすいでできており、白目は貝、黒目は黒曜石でできている。","note":"復讐の宴","exp":"1222"}],"781":[{"type":"歴史遺物","name":"アウグストゥスの宝玉","rank":"1","desc":"オクタヴィアヌス・アウグストゥス帝を彫った巨大なカメオ。女神と並んで座り、王冠を戴いている。アウグストゥスはカエサルの養子で、ローマ初代皇帝になった人物。","note":"尊厳者","exp":"160"}],"5190":[{"type":"港・集落","name":"浦項","rank":"2","desc":"読みは「ポハン」。\n朝鮮半島東岸に位置する。街の近くには、美しい山が広がる。","note":"到達する","exp":"355"}],"2721":[{"type":"海洋生物","name":"キコウライケツギョ","rank":"3","desc":"地元では「ファンソガリ」と呼ばれる魚。\n「ソガリ」とはコウライケツギョの意味らしい。本来、コウライケツギョは褐色の個体らしく、黄色の個体は珍しいとのこと。","note":"紛れ込んだ魚","exp":"550"}],"6865":[{"type":"天文","name":"かみのけ座の散開星団","rank":"3","desc":"かみのけ座の中にある星団。数多くの星が、後頭部にあたる位置に広く散らばっている。望遠鏡だけでなく肉眼でも、星々の形を捉えられる。","note":"マダガスカル沖で視認","exp":""}],"5823":[{"type":"中型生物","name":"ヒガシダイヤガラガラヘビ","rank":"4","desc":"乾燥した森林地帯に生息する巨大な毒蛇。ダイヤのような菱形模様が特徴的で、大きいものでは全長240㎝にも達する。","note":"","exp":"700"}],"4788":[{"type":"地理","name":"カリフォルニア半島","rank":"1","desc":"太平洋とカリフォルニア湾を隔てる半島。砂漠などの乾燥地帯が続いている。長い間、島だと誤解されていた。","note":"書きかけの地図","exp":"200"}],"6334":[{"type":"小型生物","name":"角怪","rank":"4","desc":"東アジアの山間部に生息するカエル。雄のみ口の周りにトゲ状の突起があり、その大きさを比べることで雄同士の優劣を決めているようだ。","note":"クエスト「トゲのあるカエル」<br/>発見物カード:315","exp":"630"}],"1916":[{"type":"財宝","name":"宝飾甲冑","rank":"1","desc":"金銀宝石で飾り立てられた甲冑。重さ、強度ともに、まったく実用的ではない。貴族が贅を凝らして作ったものである。","note":"きらびやかな甲冑の地図","exp":"140"}],"1004":[{"type":"地理","name":"ロングアイランド","rank":"3","desc":"北米大陸の東部にある細長い島。かなり大きな島で、長さは200km近い。住んでいる民族はアルゴンキンというそうだ。","note":"北米沿岸の調査","exp":"528"}],"3231":[{"type":"歴史遺物","name":"金銀の光弓","rank":"5","desc":"金や銀で彩られたきらびやかな大弓。見た目の美しさに反してかなり重く、操るには相当な筋力が必要。\nヴァイキングは海戦で弓を活用しており、弓の名手の存在が、戦いの勝敗を分けることもあったという。","note":"ヴァイキングの戦地","exp":"1210"}],"4799":[{"type":"財宝","name":"オロ","rank":"2","desc":"ハワイ島で身分ある限られた人物だけが使える波乗り用の板。木製で非常に長く、6m以上あることもあり、非常に重い。他の住人は、より短い板で波乗りを楽しんでいるようだ。","note":"オセアニアの競技","exp":"360"}],"635":[{"type":"大型生物","name":"ヒョウ","rank":"4","desc":"サバンナなどで見られる大型の猛獣。独特の模様があり、美しいが危険な動物だ。木の上で待ち伏せて狩りをするようだ。捕らえた獲物は木の上に引きずりあげて、ハイエナなどに奪われないようにしている。","note":"樹上の狩人","exp":"612"}],"5018":[{"type":"港・集落","name":"アルギン","rank":"1","desc":"エンリケ航海王子により商館が建設された、西アフリカの街。農業が盛んなほか、鉱物資源が豊富なようだ。","note":"到達する","exp":"60"}],"5833":[{"type":"財宝","name":"ショファール","rank":"5","desc":"雄のヒツジの角から作られた角笛。旧約聖書にも登場する。","note":"","exp":"1370"}],"5046":[{"type":"港・集落","name":"クガリ","rank":"2","desc":"オーストラリアの東岸に位置する街。先住民の言葉で天国を意味する。南北100kmにも及ぶ砂浜や、森林地帯の内陸部に世界で最も透明度の高い湖を有するなど、天国の名を冠するに相応しい場所である。","note":"到達する","exp":"365"}],"2380":[{"type":"虫類","name":"オジロサナエ","rank":"2","desc":"日本の特産種である、小型で細身のトンボ。山地や丘陵地の渓流に生息する。\n雄の尾部の先が白いことから、この名が付いた。","note":"小さなトンボ","exp":"240"}],"2597":[{"type":"美術品","name":"源氏物語絵巻","rank":"4","desc":"源氏物語を題材とした日本の絵巻物の一つ。文と絵を交互に楽しめるように構成されている。物語文の後に、物語の一場面を描いた絵が添えられている。","note":"絵で楽しむ恋物語","exp":"640"}],"543":[{"type":"歴史遺物","name":"古代人の骨","rank":"1","desc":"古代遺跡から出土した人骨。出土したときの状況から、当時の様子がうかがわれる。","note":"古代の墳墓の地図","exp":"13"}],"6979":[{"type":"歴史遺物","name":"ウルグ・ベク天文表","rank":"3","desc":"サマルカンドの君主であり天文学者でもあったウルグ・ベクと、彼が招致した学者たちによって編纂された天文表。1000を超える星の位置などが記されており、その高い精度は後世の天文学に大きな影響を与えた。","note":"発見物カード:250","exp":"500"}],"5543":[{"type":"気象・現象","name":"虹","rank":"1","desc":"大気中に半円状の光の帯が発生する現象。5から7色ほどの複数の色の帯で構成される。雨の降った後に発生しやすいが、その関連性は不明である。","note":"","exp":"75"}],"5594":[{"type":"気象・現象","name":"漁火光柱","rank":"4","desc":"洋上などで光の柱が空に浮いているように見える現象。\n発生要因など詳細はわからないが、柱の方向には街や漁船などがあることから、それらの明かりが何らかの形で影響しているのかもしれない。","note":"アゾレスの浜辺やや東側で視認<br/>夜間に晴れが条件","exp":"380"}],"454":[{"type":"植物","name":"ストレリチア","rank":"2","desc":"アフリカに咲く花。横に吹き出すような花の姿が鳥のくちばしや尾羽のようで美しい。栽培できれば観賞用として人気が出そうだが、アフリカの植物なので難しいかもしれない。","note":"極楽鳥花","exp":"210"}],"2529":[{"type":"植物","name":"タイワンモクゲンジ","rank":"2","desc":"主に台湾島に生息する黄色い花を咲かせる植物。桃色の房状の果実は花と見間違うほど小粒である。\n秋を告げる木ともいわれる。","note":"一味違う街路樹","exp":"360"}],"2608":[{"type":"財宝","name":"タタラ船","rank":"4","desc":"蘭嶼島に住む台湾島先住民に伝わる、伝統的な船。ゴンドラの形をしており、不安定。\n友人同士で出漁するために使う。","note":"蘭嶼の変わった船","exp":"650"}],"2041":[{"type":"財宝","name":"歴史叢書","rank":"2","desc":"三部四十巻からなる、歴史家ディオドロスの著書。一巻から五巻が各国の神話をまとめたものであり、十一巻から二十巻が年代史という構成である。それ以外の巻は行方不明のようだ。","note":"歴史書にある生涯","exp":"370"}],"951":[{"type":"美術品","name":"キリスト磔刑","rank":"1","desc":"「たっけい」。エル・グレコ作の絵画。イエスが十字架に架けられた情景で、左右対称の構図の中でイエスが白い体をよじって天を仰いでいる。彼の宗教画は光輪を描かないなど定石を無視したところがあるため、初期には認められなかった。","note":"風変わりな宗教画","exp":"185"}],"5347":[{"type":"地理","name":"トリスタン・ダ・クーニャ諸島","rank":"2","desc":"南大西洋に浮かぶ火山島。16世紀の始めに島を発見した探検家の名に由来する。補給港や避難港としての利用が期待される。","note":"セントヘレナとアセンションどちらかか両方かが前提かも。","exp":"330"}],"5551":[{"type":"植物","name":"ヒドノラ・アフリカーナ","rank":"3","desc":"アフリカ南部の乾燥地帯に生息する植物。光合成するための葉がないため、他の植物の根に寄生し、養分や水分のすべてを奪って生きる植物である。","note":"","exp":"600"}],"3602":[{"type":"地理","name":"ジャマイカ海峡","rank":"2","desc":"ジャマイカ島の北東にある海峡。この周辺は小島が多く、海賊たちの格好のねぐらとなっている。航海の際には警戒が必要。","note":"書きかけの地図","exp":"220"}],"5589":[{"type":"気象・現象","name":"フロストフラワー","rank":"3","desc":"寒冷地方の湖面に発生する数cmほどの氷晶。名前は「霜の花」を意味する。湖の氷から発生した水蒸気が凍結したものと考えられる。条件さえ揃えば、川や水たまりなど、湖以外でも観測できる。","note":"","exp":"598"}],"1843":[{"type":"小型生物","name":"ハダカデバネズミ","rank":"2","desc":"無毛で大きな前歯を持つネズミ。大人の個体でも哺乳類の赤ちゃんに似た姿をしている。地下に巣穴を作り集団で生活。出産する雌と多数の労働する雄とに役割が分かれており、ひとつの社会を作っている。東アフリカの乾燥地帯に生息。","note":"毛のないネズミ","exp":"300"}],"3322":[{"type":"中型生物","name":"コヨーテ","rank":"3","desc":"北米に生息するイヌの一種。「コヨーテ」とは、ナワトル語で「歌うイヌ」という意味であり、よく遠吠えをすることに由来する。姿はオオカミに似ているが、体長は約1mでオオカミより小型である。","note":"歌うイヌ<br/><br/>発見時経験値500　発見物カード経験値250","exp":"500"}],"6369":[{"type":"気象・現象","name":"霧氷","rank":"2","desc":"濃霧が樹木などに付着して凍りつく現象。冬の山でよく見られ、凍り方によって「樹氷」「粗氷」「樹霜」などと呼び分けられる。空気を多く含んでいるため白く、触れると簡単に壊れるほどもろい。","note":"","exp":"270"}],"4982":[{"type":"地理","name":"エーゲ海","rank":"4","desc":"バルカン半島とアナトリア半島に挟まれた内海。多くの島がある。エーゲ海周辺は古代ギリシャ最古の文明であるエーゲ文明の発祥の地で、古くから繁栄している海域である。","note":"","exp":"630"}],"1245":[{"type":"鳥類","name":"ジャノメドリ","rank":"2","desc":"熱帯林の川辺に生息する用心深い鳥。巣に敵が近づくと、目玉模様のある翼を前に広げて威嚇する。","note":"珍しい翼","exp":"265"}],"5814":[{"type":"植物","name":"チャーガ","rank":"5","desc":"シベリア霊芝とも呼ばれるキノコ。煎じて飲むと病気の治療に役立つといわれる。シラカバの樹皮に生えるが、かなり珍しいようだ。","note":"シベリア地方","exp":"830"}],"5474":[{"type":"植物","name":"ブラジルナッツの木","rank":"4","desc":"アマゾン川流域原産の高木。油脂分を多く含む実がなる。殻が大きく重いため、収穫の際には注意が必要。","note":"","exp":"760"}],"3803":[{"type":"小型生物","name":"ポリミータ","rank":"5","desc":"キューバ島の一部の地方に生息するカタツムリの一種。軟体部分は紺色で、個体ごとにさまざまな色の殻を持っている。","note":"生けるトンボ玉","exp":"1330"}],"3306":[{"type":"植物","name":"シロツメクサ","rank":"2","desc":"ヨーロッパを原産地とする植物。春から秋にかけて白い花を咲かせる。痩せた土地でもよく育つ上に、根付いた土地の地味を豊かにする働きを持つ。","note":"農夫の娘の親孝行","exp":"340"}],"1640":[{"type":"地理","name":"ドレイク海峡","rank":"5","desc":"イングランドの提督、フランシス・ドレイクが発見したといわれる海峡。近海は波が高く強風が止まないため、航海の難所として知られる。さらに、冬は海が氷に覆われる。","note":"第二の世界周航","exp":"923"}],"1873":[{"type":"財宝","name":"チブチャの民の黄金衣装","rank":"5","desc":"黄金の国伝説の元になったといわれる民族の衣装。酋長が金粉を体にまとい、湖に飛び込む儀式を行うといわれている。これだけ金づくしの生活をしていれば、「黄金の人間が住む黄金の国がある」と思われても仕方がないだろう。","note":"いつも二人で","exp":"820"}],"129":[{"type":"宗教遺物","name":"聖母のステンドグラス","rank":"1","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40"}],"6695":[{"type":"天文","name":"アクルックス","rank":"5","desc":"みなみじゅうじ座で最も明るい星。十字架の下部にあたる。最も南に輝く1等星である。\nみなみじゅうじ座（クルックス）のアルファ星であることから、アクルックスと命名された。","note":"発見物カード:455","exp":"910"}],"7020":[{"type":"小型生物","name":"セイブシシバナヘビ","rank":"5","desc":"小型のヘビ。北米大陸の内陸部に分布し、乾燥した草原や砂漠に生息している。ブタに似た上向きの鼻が特徴。身体は黄褐色で、黒い斑点模様が入っている。牙から分泌される微毒性の唾液で、獲物を痺れさせる。","note":"","exp":""}],"2872":[{"type":"美術品","name":"王蒙の風景画","rank":"2","desc":"元代の画家・王蒙が描いた絵画。うねるようにそそり立つ山々が、緻密かつ壮大に表現されており、見る者を圧倒する。","note":"黄公望の弟子","exp":"350"}],"6183":[{"type":"鳥類","name":"バミューダミズナギドリ","rank":"5","desc":"バミューダ海域に生息している鳥で、上面は灰褐色、下面は白い体色をしている。鳴き声がとても恐ろしく鋭いことや、バミューダ海域が船乗りに「悪魔の海域」と呼ばれていたことなどから、悪魔の使いのように恐れられているらしい。","note":"","exp":"1270"}],"4882":[{"type":"天文","name":"ペルセウス座流星群","rank":"4","desc":"ペルセウス座の方角から、飛び出してくるように見える流星群。一年のうち約一カ月、出現する。流れる星の数が多く、光も強いことが多いため、観測しやすい","note":"発見物カード:320","exp":"640"}],"5554":[{"type":"財宝","name":"プーンギー","rank":"2","desc":"インド発祥の楽器。\nひょうたんの先から息を吹き込むことで音を出すことができる。また、蛇使いが蛇を操る際にも演奏される。","note":"インドの民族楽器","exp":"350"}],"1055":[{"type":"史跡","name":"カルナック巨石群","rank":"1","desc":"先史時代の巨石群。4000を超える巨石が立ち並ぶが、なんのために並べたのか、まったく謎である。付近には巨石遺構が多く、墓のようなものもある。","note":"列をなす巨石","exp":"95"}],"2998":[{"type":"史跡","name":"ジョギンズの化石の崖群","rank":"4","desc":"不思議な石が多く見られる崖。もともとは、ただの石崖だったが、潮の浸食により、動物の骨が石化したものが多く見つかるようになった。","note":"太古の崖","exp":"800"}],"707":[{"type":"海洋生物","name":"ジュゴン","rank":"4","desc":"海に住む大型の動物。アザラシなどと違い、陸に上がることはないようだ。海面に出て子供に乳を与えている姿が目撃され、人魚と間違われたこともある。","note":"人魚の正体","exp":"708"}],"5635":[{"type":"鳥類","name":"シロハヤブサ","rank":"2","desc":"北米大陸の高山帯や、ユーラシア大陸の北部などに生息する鳥。\n全長は50cmあまりで、翼を広げると幅が1mを超える。","note":"","exp":"250"}],"2359":[{"type":"史跡","name":"安土城","rank":"5","desc":"五層七階の天守を備えた日本の城郭。その壮麗な姿は、築城主の勢威を物語る。\n火災が起こって以来、天守は使用されていない。","note":"クエスト「覇業の残光」<br/>発見物カード:560","exp":"1120"}],"3635":[{"type":"地理","name":"ベーリング海峡","rank":"5","desc":"ユーラシア大陸東端と北米大陸西端の間にある海峡。\n夏を除いて流氷に覆われており、航海は困難を極める。","note":"クエスト「北東航路東端調査」<br/>発見物カード:505","exp":"1010"}],"3738":[{"type":"大型生物","name":"ジャコウウシ","rank":"4","desc":"グリーンランドなどの極北の陸地に生息するウシの一種。体長は2m程度で、柔らかい下毛の上に硬くて長い毛が生えている。","note":"極北の地のウシ","exp":"750"}],"5103":[{"type":"港・集落","name":"ドーバー","rank":"1","desc":"ブリテン島南東に位置する街。ドーバー海峡に面している。フランスとの争いの最前線でヴァイキングの時代に防衛のための城が築かれた。","note":"到達する","exp":"15"}],"1590":[{"type":"歴史遺物","name":"無紋鉢","rank":"1","desc":"紋様のない鉢。アステカで見られる鉢は多くが土器のようだ。","note":"メソアメリカの鉢の地図","exp":"150"}],"2498":[{"type":"美術品","name":"雪舟の山水画","rank":"4","desc":"室町時代の禅僧・雪舟の筆による水墨画。\nどっしりとした安定感のある構図と、力強い筆使いが特徴。","note":"名画の奪還","exp":"620"}],"1243":[{"type":"地理","name":"オリノコ川","rank":"2","desc":"南米北東岸に河口を持つ大きな川。調査は進んでいないが、かなり長大な川であると思われる。河口付近は、いくつもの支流に分かれている。","note":"大河の調査","exp":"330"}],"6585":[{"type":"歴史遺物","name":"青い彩釉レンガ","rank":"2","desc":"伝承にある都市バビロンで使われていたと思われる古代の彩釉レンガ。釉薬がほどこされたレンガは耐久性に優れ、表面にはまだ青い光沢が残っている。","note":"","exp":"280"}],"1634":[{"type":"海洋生物","name":"ブルーマーリン","rank":"5","desc":"クロカジキ。外洋性でカジキの種類の中で最も大きくなるという。","note":"釣り","exp":"910"}],"3654":[{"type":"鳥類","name":"ライチョウ","rank":"2","desc":"北極海の沿岸や、ユーラシア北部の高山帯などに分布する鳥。羽毛の色が、夏は褐色、冬は白に変化する。","note":"着替える鳥","exp":"380"}],"5894":[{"type":"鳥類","name":"ヒメコンドル","rank":"2","desc":"中南米に生息する大型の鳥。鳥類にしては珍しく嗅覚が発達しており、餌である動物の死がいを遠くから探すことができる。","note":"","exp":"350"}],"6569":[{"type":"歴史遺物","name":"アルトナ石碑","rank":"5","desc":"キリスト教が広がり始めた頃、スウェーデンで作られたとされる石碑。表向きはキリスト教への改宗を示す石碑だが、片側には古来信仰されていた北欧神話のトールとヨルムンガンドが戦う様子が刻まれている。","note":"追究クエスト<br/>発見物カード:750","exp":"1500"}],"3771":[{"type":"天文","name":"木星","rank":"3","desc":"黄道をおおよそ12年かけて一巡りするため、ローマ神話のユピテルを始め、高位の神の名をつけられることが多い。中国では歳星と呼ばれ、道教において天刑星の名で神格化されている。","note":"クエスト「逆行する惑星」<br/>発見物カード:260","exp":"520"}],"6125":[{"type":"地理","name":"ハーフーン岬","rank":"2","desc":"アフリカ最東端に位置する岬。古代から交易拠点の一つとして栄えており、「エリュトゥラー海案内記」にもそれらしき記述が見られる。古代の遺跡が残っており、遺物が見つかることもあるという。","note":"クエスト「文献調査」<br/>発見物カード:195","exp":"390"}],"1158":[{"type":"鳥類","name":"メガネフクロウ","rank":"2","desc":"目を縁取る白い羽毛が眼鏡のように見える。止まり木から、地面や葉むらにいる獲物に一気に襲いかかり捕食する。","note":"メガネをかけた生物","exp":"275"}],"3684":[{"type":"地理","name":"チュクチ山脈","rank":"2","desc":"チュクチ半島の根元に広がる大きな山脈。近辺には他にも山脈が走り、周辺全体が山がちであるということが分かる。","note":"書きかけの地図","exp":"390"}],"1355":[{"type":"宗教遺物","name":"不空成就如来","rank":"4","desc":"ふくうじょうじゅにょらい。仏教における如来のひとり。名前には「空しいことはなにもなく、成し遂げることことこそ大事」という意味がある。","note":"不空成就如来像","exp":"720"}],"5835":[{"type":"中型生物","name":"サイベリアン","rank":"3","desc":"シベリアの名を冠する猫。丸みを帯びた体は長い毛に覆われ、その名前のとおり、極寒のシベリア地方に適応している。","note":"","exp":"480"}],"823":[{"type":"中型生物","name":"コビトカバ","rank":"5","desc":"西アフリカの限られた地域にしかいない、小さなカバ。カバの子供かと思われたが、同じ大きさの個体ばかりなので違う種類だと思われる。体色もカバよりかなり濃い。水の中にいることは少なく、森や湿地にいる。","note":"水が嫌いなカバ","exp":"1040"}],"1708":[{"type":"大型生物","name":"バンテン","rank":"1","desc":"体長2mほどのウシ。体色は白や茶色など様々で、オスの角は70cmほどにもなる。家畜としても飼育されている。","note":"牛に似た動物の地図","exp":"110"}],"2255":[{"type":"中型生物","name":"ゾウガメ","rank":"2","desc":"甲羅の直径が1mを超す大型リクガメ。岩のような姿をしている。\n長生きで、百年以上生きるものも多い。近隣に天敵がいないせいか人が近づいても警戒しない。","note":"クエスト「島の生物調査」<br/>発見物カード:180","exp":"360"}],"3324":[{"type":"歴史遺物","name":"アントニヌスの長城","rank":"2","desc":"ローマ帝国の時代に、皇帝アントニヌス・ピウスの命により築かれた防塁。長さは約60kmであり、二年という短い期間で建設された。","note":"ローマ帝国の防塁の地図","exp":"320"}],"5413":[{"type":"植物","name":"イェルバ・マテ","rank":"1","desc":"南米に生息する植物。葉は茶葉として加工され、広く飲用されている。成長には長い年月を要するが、その分、収穫も数十年間続けて行えるという。","note":"茶葉にする植物の地図（パラグアイ川上流再調査報酬）","exp":""}],"1453":[{"type":"宗教遺物","name":"黒曜石のナイフ","rank":"4","desc":"黒曜石でできた小型のナイフ。神々に捧げる生贄の心臓を生きたままえぐったといわれている。強度はないが、鋭利で切れ味は良い。","note":"第5の世界","exp":"648"}],"6084":[{"type":"歴史遺物","name":"アマルナ文書","rank":"2","desc":"古代エジプトの外交文書アメンホテブ4世がファラオだった時代のもの。近隣諸国のエジプトが支配する国の高官たちからファラオに宛てた外交文書籍が多くその大半は当時の公用語であったアッカド語で\n書かれている","note":"古代エジプト遺物の地図","exp":"300"}],"6630":[{"type":"鳥類","name":"コンゴクジャク","rank":"3","desc":"アフリカの熱帯雨林に生息するクジャク。雌雄は体色こそ異なるものの他の違いはさほど見られず、いずれも鮮やかな飾り羽はない。果実や昆虫を主食とする。","note":"追究クエスト<br/><br/>ログ見るとコンゴクジャクのようですので替えました<br/>2022/11/10","exp":""}],"1359":[{"type":"虫類","name":"コーカサスオオカブト","rank":"5","desc":"三本の長い角を持つ大きな虫。10cmを超える体はがっしりとしており、光沢が強い。爪は鋭く、好戦的である。","note":"手のひらの戦士<br/><br/>発見時経験値923　発見物カード経験値461","exp":"923"}],"5582":[{"type":"植物","name":"サトウカエデ","rank":"2","desc":"北米原産の落葉高木。樹液を煮詰めるとメープルシロップとなる。材質は硬く、工芸品などに利用される。","note":"","exp":"290"}],"2716":[{"type":"海洋生物","name":"チョウセントゲドジョウ","rank":"1","desc":"朝鮮周辺に生息する淡水魚。\n白地に黒縞の模様が入った、美しいドジョウである。","note":"縞模様のある魚の地図","exp":"180"}],"1479":[{"type":"宗教遺物","name":"バロンの仮面","rank":"5","desc":"ジャワ島東のバリ島に伝わる、神獣バロンをかたどった仮面。バロンはバリ島では疫病を防ぐ神として信仰されている。バリでは仮面をご神体として、大切にほこらで管理している。","note":"終わりなき善と悪の戦い","exp":"1053"}],"3788":[{"type":"天文","name":"カストル","rank":"4","desc":"ふたご座で2番目に明るい星。星座図では、双子のうち、兄の頭に位置する。名はイアソン探検隊に参加した双子のカストルに由来する。カストルとポルックスの2つの星は、多くの地域で一組に扱われ、物語が作られた。","note":"視認","exp":"650"}],"715":[{"type":"歴史遺物","name":"クフ王の王杖","rank":"2","desc":"金やラピスラズリをふんだんに使った、豪華な王杖。クフ王は、エジプト最大である、ギザの第1ピラミッドを建造したファラオである。","note":"世界七不思議の主","exp":"300"}],"3528":[{"type":"レリック","name":"海賊女王テウタ","rank":"","desc":"古代ローマの時代にアドリア海の海賊を束ねていたという伝説の女王。ローマとの戦いに敗れ、その姿は歴史の闇に消えている。","note":"","exp":""}],"2382":[{"type":"海洋生物","name":"ネコザメ","rank":"2","desc":"日本付近の暖かい海に生息するサメ。その名前は、どことなくネコに似た顔に由来する。気性はおとなしく、人間を襲うことはほとんどない。","note":"変わったサメの調査","exp":"300"}],"2383":[{"type":"鳥類","name":"ルリカケス","rank":"3","desc":"日本南方の小島に生息する、色鮮やかなカラス。瑠璃色の翼、白いくちばし、赤褐色の胴体が特徴。\n美しい外見に反して、鳴き声はしわがれており、うるさい。","note":"極東の青い鳥","exp":"440"}],"214":[{"type":"財宝","name":"ドイツ騎士団長の剣","rank":"1","desc":"ドイツ騎士団は、十字軍時代の三大騎士団の一つ。紋章は白地に黒十字。プロイセン地方の開拓に貢献した。独自の領土を持つ。","note":"ドイツを開拓した騎士団","exp":"140"}],"1924":[{"type":"植物","name":"チュパチュパ","rank":"1","desc":"真っ直ぐな茎の先に、明るい赤やオレンジの管状の花が咲く植物。ツタのように、地面や壁を這って成長する。育ちが早く、温暖な地域では越冬する。","note":"這う花の地図","exp":"140"}],"3229":[{"type":"歴史遺物","name":"ヴァイキングの鉄釘","rank":"2","desc":"ランス・オ・メドーの作業場らしき跡地から発見された鉄製の釘。ヴァイキングの船などに用いられていたものと見られる。1000年代にヴァイキングによって鉄文化が北米にもたらされたことを示す遺物である。","note":"鍛冶場に残る物","exp":"400"}],"418":[{"type":"化石","name":"不気味な花の石","rank":"1","desc":"気味の悪い植物のような模様がある石。形がぐにゃぐにゃしていて筋が入っている。こんな花は見たことがないが、どこかに生えているのだろうか？","note":"奇妙な石の地図","exp":"30"}],"526":[{"type":"歴史遺物","name":"青銅の武具","rank":"1","desc":"古代の青銅でできた武具。青銅は加工が容易なので古代文明でもよく用いられたが、柔らかいため武具には向かない。","note":"古代の青銅具の地図","exp":"36"}],"6508":[{"type":"財宝","name":"蝋管式蓄音機","rank":"5","desc":"蝋でできた管に刻まれた溝を針でなぞり、振動を拾い上げることで音を再生する自動演奏装置。振動は針とつながったサウンドボックスと呼ばれる振動版へ伝わることで音となりその音がホーンを通して拡大される仕組みになっている。","note":"","exp":"1120"}],"615":[{"type":"鳥類","name":"キエリボタンインコ","rank":"5","desc":"赤いくちばしと、目を縁取る白い模様が特徴的。活動する時間のほとんどをつがいで過ごす。種子や果実などを主食とする。","note":"思い出に残ったもの","exp":"1144"}],"5832":[{"type":"美術品","name":"田舎風陶器","rank":"5","desc":"パリッシーという人物が作り上げた陶器。小さな動物や植物の立体的な浮き彫りが施されており、さながら陶器の上に田舎の風景が再現されているかのようである。","note":"","exp":"1340"}],"2126":[{"type":"財宝","name":"サントゥール","rank":"3","desc":"クルミ製の箱に鋼鉄製の弦を張り、それをメスラブと呼ばれる軽量の木の棒で叩いて演奏する打弦楽器。澄んだ音で聞く者を魅了するようだ。","note":"弦なのに叩く<br/><br/>発見時経験値500　発見物カード経験値250","exp":"500"}],"897":[{"type":"小型生物","name":"ミーアキャット","rank":"2","desc":"アフリカ南部に生息する、猫ほどの大きさの動物。集団で巣穴に住んでおり、器用に立ち上がってまわりを警戒する習性がある。","note":"二本足で立ち上がる猫","exp":"210"}],"2044":[{"type":"美術品","name":"アダムとエヴァ","rank":"2","desc":"楽園を背景に、男女と動物を描いた彫刻銅版画。デューラーの四大銅版画のうち最も早く制作された。テーマは「原罪」。\nウィトルウィウスの人体比例を用いてあり、古代彫刻の理想的形態が提示されている。","note":"描かれた理想","exp":"300"}],"1809":[{"type":"美術品","name":"サリエラ","rank":"5","desc":"豪華な彫刻が施された金細工の塩入れ。ルネッサンス期を代表する彫刻家ベンベヌート・チェリーニの作。その豪華さと精緻を極めた彫刻によって、「彫刻のモナリザ」と呼ばれている。","note":"盗まれた金細工の彫刻","exp":"1170"}],"2864":[{"type":"地理","name":"長江","rank":"4","desc":"古くから中心的な交通路として利用されてきた杭州北部を流れる大河。この流域では稲作が盛んである。\n下流部は「揚子江」とも呼ばれる。","note":"杭州付近の地理調査","exp":"650"}],"3544":[{"type":"レリック","name":"最後のローマ人","rank":"","desc":"ホノリウス帝の命令で刑場の露と消えた勇将スティリコ。西ローマ帝国の滅亡はこの時に決定づけられたといえよう。","note":"発見時経験値3340","exp":"3340"}],"834":[{"type":"歴史遺物","name":"死者の街","rank":"2","desc":"ネクロポリスともいい大規模な集団墓地のこと。形態や埋葬方法は文明により異なるが、死者の街の造営は複数の文明で見られる。","note":"地下への入口の地図","exp":"340"}],"5517":[{"type":"天文","name":"ちょうこくぐ座","rank":"5","desc":"ラカーユが制定した南天の星座。彫刻の際に使用される道具が題材にされている。明るい星がなく、並びも特徴的とは言えないため、発見する際は南中したオリオン座を基準に南東を探すことで発見できる。","note":"クエスト「芸術が題材の星座」<br/>発見物カード:415","exp":"830"}],"751":[{"type":"虫類","name":"アオマダラヤンマ","rank":"1","desc":"ヨーロッパの水辺でよく見られる。体が大きく、自分のなわばりを守るために他のオスを攻撃することもある。","note":"青いトンボの調査","exp":"150"}],"3748":[{"type":"天文","name":"スピカ","rank":"3","desc":"おとめ座で最も明るく輝く、青白い星。名は「穂先」を意味し、星座図では、女神が持つ麦穂の先に位置する。アルクトゥルスとともに夫婦星と呼ばれることがあり、アルクトゥルスは男性を、スピカは女性を象徴する。","note":"空に輝く穂先","exp":"510"}],"6043":[{"type":"天文","name":"ふうちょう座","rank":"5","desc":"南天の星座の一つ。南天の星図作成に尽力した航海者ペーテル・ケイセルらの残した観測記録を元に制定され、同時代に南半球で発見されたフウチョウの名をつけられた。「ウラノメトリア」には誤植で「インドのミツバチ座」と記載された。","note":"クエスト「南の鳥は南の空に」<br/>発見物カード:490","exp":"980"}],"5783":[{"type":"歴史遺物","name":"アイスマン","rank":"5","desc":"アルプス山脈で発見されたミイラ。雪の下で凍り漬けになっていたため、非常に良好な状態を保っている。発見時、周囲に彼の持ち物と思われる道具などがいくつかあった。","note":"氷漬けの男","exp":"1400"}],"1907":[{"type":"歴史遺物","name":"バイバルスの槍","rank":"3","desc":"マムルーク朝のスルタンである、バイバルスのものといわれている槍。バイバルスは、十字軍やモンゴル軍との数々の戦いに勝利し、内政の基盤を作るなど功績は大きい。バイバルス自身も優れた軍人で、特に馬術に秀でていたという。","note":"隻眼の虎","exp":"530"}],"948":[{"type":"財宝","name":"エターナルスター","rank":"5","desc":"100カラットをゆうに超える、巨大なダイヤモンド。大きなダイヤは色がついているものが多いが、これはまったくの無色である。内包物もほとんどなく、奇跡ともいえるダイヤモンドだ。","note":"不滅の星<br/><br/>発見時経験値1105　発見物カード経験値552","exp":"1105"}],"413":[{"type":"化石","name":"巨大な卵の形の石","rank":"1","desc":"まるで卵のような、奇妙な石。殻もあり、本当に卵のようだ。しかし、こんなに大きな卵を産む生物はいない。ドラゴンの卵だとでもいうのだろうか。","note":"奇妙な石の地図","exp":"28"}],"3772":[{"type":"天文","name":"土星","rank":"4","desc":"ヨーロッパではローマ神話の農耕神、サトゥルヌスに由来する名で呼ばれる惑星。約30年で黄道を一巡りする。ガリレオは望遠鏡で土星を観測したが、その形状に頭を悩ませたと伝えられている。","note":"耳のある星","exp":"710"}],"2524":[{"type":"小型生物","name":"ジャコウネズミ","rank":"1","desc":"台湾島や中国など、広い地域に分布するネズミ。市街地や農耕地に生息する。\n子が、親の尾や別の子の尾をくわえ、連なって移動する姿が見られる。","note":"灰色のネズミの地図","exp":"110"}],"1068":[{"type":"宗教遺物","name":"ヴィシュヌ像","rank":"3","desc":"インド神話三大神の一人の像である。10もの化身（アヴァターラ）をもつが、4本の腕を持つ男性として描かれることが多い。世界の均衡が崩れると、さまざまな姿で現世に現れると伝えられる。","note":"始まりにいる神","exp":"484"}],"5208":[{"type":"歴史遺物","name":"信楽のつぼ","rank":"2","desc":"美しい信楽焼のつぼ。土の色が温かみを感じさせる。古来より信楽の土は焼き物に適しているとされ、茶人や文化人に茶陶信楽として重宝された。","note":"","exp":""}],"6578":[{"type":"財宝","name":"ダルシマー","rank":"5","desc":"ラテン語で「甘美な旋律」を意味する言葉が由来といわれる打弦楽器。台形の箱に金属の弦を張り、ハンマーと呼ばれる小槌の棒で叩いて演奏する。","note":"追求クエスト「打弦楽器の追加調査」 発見物カード:600","exp":"1200"}],"1617":[{"type":"美術品","name":"タラのブローチ","rank":"4","desc":"8世紀にアイルランドで作られたブローチ。金の準環状ブローチで宝石と共にケルト文様が彫り込まれている。僧衣などのマントを留めるために使われた。アイルランド金細工の至宝といわれている。","note":"職人好みの装飾品","exp":"612"}],"6425":[{"type":"中型生物","name":"夏毛のホッキョクギツネ","rank":"4","desc":"夏毛になったホッキョクギツネ。厳しい寒さに耐えるために冬場は厚い毛で覆われるが、夏場は灰色や褐色の毛に生え変わるという。小動物や鳥や魚。アザラシの死骸などさまざまなものを食べ、エサが乏しくなる冬でも冬眠しない。","note":"","exp":""}],"5308":[{"type":"大型生物","name":"シロオリックス","rank":"2","desc":"サハラ周辺に生息し、後ろに反った長い角が特徴の草食動物。大きな群れで季節ごとに南北に移動する。乾燥に強く、水を飲まなくても長期間生き続けられるが、水が豊富であればよく飲むという。","note":"","exp":"280"}],"6634":[{"type":"歴史遺物","name":"ポイティンガー図","rank":"5","desc":"ローマ帝国の時代の地図。当時の道路や河川などが描かれている。原図はすでに散逸したが、アウクスブルクのポイティンガーによる写本が伝わっている。","note":"レガシー商の叡智・財貨の交易路　中央","exp":""}],"6907":[{"type":"宗教遺物","name":"四分律","rank":"3","desc":"仏教の聖典「律典」の一種。全60巻、僧侶と尼僧の戒律が、数多く記されている。唐代の僧侶・道宣により教えが広がる。その後、道宣の弟子筋である鑑真の渡来により、日本にも教えが伝わった。","note":"","exp":"660"}],"5458":[{"type":"中型生物","name":"ペッカリー","rank":"2","desc":"中南米に生息するイノシシに似た生物。5～15頭ほどの群れで生活する。肉食獣に襲われると、群れの中の一頭が犠牲となる間に他の仲間が逃げるという習性がある。","note":"","exp":"280"}],"2688":[{"type":"歴史遺物","name":"古代の鉄塊","rank":"2","desc":"朽ちかけた鉄の塊。\n伽耶時代、鉄の延べ棒は、貨幣として使われていたらしい。","note":"伽耶の記録","exp":"210"}],"1847":[{"type":"歴史遺物","name":"貝殻","rank":"1","desc":"インカの主な街は高地にあり、海とは縁遠いものだった。しかしチャスキの活躍により高地にも新鮮な海産物が届けられた。また、貝を食したあとの貝殻は美しく彩色され、このような装飾品にもなった。","note":"精巧な加工の地図","exp":"150"}],"6422":[{"type":"大型生物","name":"獰猛なグリズリー","rank":"4","desc":"心のない人間によって見世物にされていた大型のクマ。獰猛な姿をしているという。しかし、クマは逃げ出してしまった。いつ街に戻り、人々を襲いはじめてもおかしくないだろう。","note":"","exp":""}],"6588":[{"type":"歴史遺物","name":"地理学","rank":"2","desc":"紀元前のギリシャの学者で、「地理学の父」と呼ばれるエラトステネスが編纂した地理学の書物。その時期の地理学の最高水準であるといわれている。","note":"","exp":""}],"522":[{"type":"歴史遺物","name":"古代の石材","rank":"1","desc":"古代文明の石造建築に用いられた石材。中には巨大なものもあり、どうやって運んだり積んだりしたのかは謎である。","note":"古代の集落の地図","exp":"17"}],"240":[{"type":"歴史遺物","name":"アッバースの剣","rank":"2","desc":"ウマイヤ朝を倒してアッバース朝を興したアブー・アル・アッバースが使っていた剣。アッバース朝はモンゴルのフラグに滅ぼされるまで、約5世紀の間存続した。","note":"バグダッドを建設した人物","exp":"290"}],"3173":[{"type":"大型生物","name":"アメリカグマ","rank":"3","desc":"北米の温帯および亜寒帯地域に分布する。性格は比較的穏やかだが動作は素早く、木登りを得意とする。","note":"クエスト「クマ調査の協力依頼」<br/>発見物カード:225","exp":"450"}],"2280":[{"type":"史跡","name":"コパン遺跡","rank":"5","desc":"大雨による川の氾濫で発見された、マヤの大都市遺跡。他のマヤ遺跡には見られない独特の石像彫刻や壁画が見られ、彫刻技術の高さを感じさせる。","note":"クエスト「街の奥にあったもの」<br/>発見物カード:520","exp":"1040"}],"6510":[{"type":"宗教建築","name":"在りし日のオリンピアのゼウス像","rank":"5","desc":"古代ギリシャの年オリンピアの巨大なゼウス神像。表面は象牙と黄金で覆われ、黒檀の玉座は貴石で飾られていたという。このゼウス像に捧げる祭典として4年に1度開かれたオリンピア大祭では、さまざまな古代競技が競われていた。","note":"","exp":""}],"5882":[{"type":"地理","name":"化石の森","rank":"2","desc":"どんな理由か、多くの樹が宝石のようになっている。高々とそびえる樹はないが、森としか形容できない場所である。","note":"","exp":"1380"}],"1152":[{"type":"大型生物","name":"ピューマ","rank":"5","desc":"がっしりとした体と長い尾、そして金色の目を持つ。様々な環境に適応し、高い身体能力でネズミやウサギなどを捕食する。","note":"［勅命］[未知なる危険]","exp":"910"}],"999":[{"type":"財宝","name":"東方見聞録","rank":"1","desc":"13世紀終わりごろ、元朝のフビライに仕えたマルコ・ポーロの口述を記録した本。この中に、黄金の国ジパングが登場する。","note":"冒険者のバイブル","exp":"55"}],"1598":[{"type":"歴史遺物","name":"未知の生物の像","rank":"4","desc":"不思議な生き物をかたどった像。これが出土した地域の人も、ヨーロッパ人も、このような姿をした生き物は見たことがないという。すでに死に絶えてしまった生き物をかたどっているのだろうか？","note":"未知の生物の像","exp":"744"}],"2316":[{"type":"地理","name":"三清山","rank":"2","desc":"道教の名山の一つ。道教の三大神が並んで座っているように見えることから、この名が付いたとされる。","note":"［勅命］[[現地の信仰と山の関係調査","exp":"310"}],"93":[{"type":"歴史遺物","name":"プトレマイオス1世の王錫","rank":"2","desc":"プトレマイオス1世はアレクサンドロス大王の側近であった。大王亡き後エジプトのファラオとなり、ムセイオンを建設して学術の発展に大きく貢献した。","note":"エジプト最後の王朝","exp":"280"}],"3821":[{"type":"地理","name":"ピンクサンドビーチ","rank":"5","desc":"カリブ海のハーバー島にある浜辺。バハマ諸島のエルーセラ島北部に位置する。\n白い砂に赤みがかった貝殻やサンゴが砕けたものが混じっており、ピンク色に見える。","note":"桃色の浜辺<br/><br/>発見時経験値1180　発見物カード経験値590","exp":"1180"}],"125":[{"type":"美術品","name":"ネッソスにさらわれるディアネイラ","rank":"1","desc":"グイド・レーニ作の、ヘラクレスを題材とした連作の一枚。ヘラクレスの妻・ディアネイラが、ネッソスというケンタウロスにさらわれるシーンである。素晴らしい躍動感にあふれた作品だ。","note":"クエスト「ギリシャ神話が題材の絵」<br/>発見物カード:55","exp":"110"}],"6028":[{"type":"宗教建築","name":"ヴァラーム修道院","rank":"3","desc":"ラドガ湖に浮かぶ島、ヴァラーム島にある修道院。その歴史はロシアのキリスト教化以前にさかのぼるが、地理的な事情から何度も戦乱に巻き込まれ、荒廃した時期もあった。\n最近は復興しつつあるという。","note":"","exp":"520"}],"1269":[{"type":"美術品","name":"眠れるビーナス","rank":"4","desc":"ジョルジョーネ作。ヴェネツィアの貴族の結婚祝いに依頼されたもの。弟弟子のティツィアーノに影響を与え、後に同じ構図の絵が描かれている。静謐な空間で眠るヴィーナスからは、無垢の美しさが滲み出している。","note":"眠れる女神","exp":"720"}],"119":[{"type":"宗教遺物","name":"ヘスチア像","rank":"1","desc":"ギリシャ神話の炉の女神の像。ゼウスの姉で逸話こそ少ないものの古代ギリシャでは広く信仰されていた。ローマ神話ではウェスタという。","note":"ギリシャの女神像の地図","exp":"60"}],"5340":[{"type":"地理","name":"カメルーン山","rank":"2","desc":"アフリカ中部の沿岸にある火山。\n紀元前にカルタゴの航海者ハンノが\n噴火を記録した火山ではないかと考えられている。","note":"火山の記録<br/><br/>発見時経験値380　発見物カード経験値190","exp":"380"}],"5017":[{"type":"港・集落","name":"アムステルダム","rank":"1","desc":"ネーデルラント北部七州の中でも、海運で特に栄えている都市。かつてはイスパニアの支配下にあったが、圧政に反発して独立した。各種産業が発展しており、特に紡績と製鉄が盛ん。","note":"到達する","exp":"27"}],"6355":[{"type":"レリック","name":"古代の反射鏡","rank":"","desc":"アレクサンドリア大灯台の最上部付近に設置された反射鏡は太陽光線を集め反射させ、遥か遠くの船を焼くことが可能だったという。","note":"トレジャーハント「古地図にまつわる伝承」","exp":""}],"5936":[{"type":"植物","name":"死んだ草","rank":"4","desc":"アフリカ西岸で見つけた、枯れた草。「不死の植物」を探して見つけたものだが、むしろ死んでしまっているように見える…。","note":"","exp":"720"}],"3389":[{"type":"歴史遺物","name":"エヌマ・エリシュ","rank":"5","desc":"バビロニア神話における創世記叙事詩。数多くの神々の名が記されており、かつて栄えたバビロン帝国が他の都市に比べ優れているかが記されていると思われる。","note":"天地創造の叙事詩","exp":"1400"}],"1797":[{"type":"地理","name":"アスエロ半島","rank":"2","desc":"パナマ湾の西にある半島。半島の各所で他の地域とは異なった形状の土器や金細工が出土する。この地域は古くから人が住み、独自の文化を発展させていたようだ。","note":"書きかけの地図","exp":"220"}],"2371":[{"type":"虫類","name":"ギフチョウ","rank":"1","desc":"日本にのみ生息する、黄と黒のまだら模様が鮮やかなチョウ。\n夏に成熟した幼虫が、落ち葉の下でさなぎとなり、そのまま冬を越すという特徴がある。","note":"斑模様のチョウの地図","exp":"150"}],"1862":[{"type":"宗教遺物","name":"コノパ","rank":"2","desc":"南米の民族の多くが、自らの信仰する神に生贄を捧げるが、コノパは生贄となる動物をかたどった彫刻である。神に捧げられる生贄はリャマやアルパカなど土地の家畜が多く、コノパにはそれの骨や毛などを詰めたという。","note":"供物の彫像","exp":"230"}],"810":[{"type":"地理","name":"アゾレス諸島","rank":"1","desc":"イベリア半島南西端から西に1300kmほどに位置する諸島。これまでの航海技術では大陸を離れた航海が困難だったため、存在が認識されていなかった。年間を通して温暖なので、耕作に向いていると思われる。","note":"大西洋の真ん中","exp":"90"}],"394":[{"type":"大型生物","name":"サイ","rank":"1","desc":"鼻の上に角がある、大型の草食動物。4m近くなる個体もいる。群れを作る種類と単独で生活する種類があるようだ。","note":"角のある大型獣の地図","exp":"76"}],"6809":[{"type":"植物","name":"モニラリア","rank":"2","desc":"南アフリカに生息する多肉植物。モニラリア属の総称で、いくつかの種が存在する。葉は丸みを帯びて太く、長く伸びるとウサギの耳のように見える種もある。","note":"発見物カード経験値:156","exp":""}],"5205":[{"type":"歴史遺物","name":"クレタ文字の粘土板","rank":"2","desc":"古代クレタ文明で使われていた文字が刻まれた粘土板。クレタ島の広範囲で確認できる。象形文字を発展させたような文字だが、なにが書かれているかは読み取れない。","note":"","exp":""}],"6943":[{"type":"虫類","name":"ベニスカシジャノメ","rank":"5","desc":"中南米の熱帯雨林などに生息する蝶の一種。ガラスのように透明な羽を持ち、後翅の一部にのみ赤い鱗粉によって色がついている。花の蜜や、発酵した果実などを食す。","note":"発見物カード:710","exp":"1420"}],"659":[{"type":"小型生物","name":"レミング","rank":"1","desc":"ずんぐりしたネズミの仲間。背中に黒い筋がある。何年かごとに大発生し、集団で移動する性質がある。その際に川や海、谷にぶつかると、そのまま飛び込んで大量死することがある。","note":"小さい生物の地図","exp":"15"}],"10":[{"type":"財宝","name":"アスタロトの宝玉","rank":"1","desc":"聖書のソロモン王が、悪魔や精霊72体を封じ込めたという宝玉の一つ。この宝石にはアスタロトが封じられているという。真偽の程は不明だ。\n宝玉はよく見ると傷があり、「西」と彫られている。","note":"アスタロトの宝玉","exp":"100"}],"5455":[{"type":"歴史遺物","name":"マラジョ島の土器","rank":"3","desc":"アマゾン川河口に位置するマラジョ島で見つかった彩色土器。先住民が作った物とみられる。渦巻き模様など、幾何学的な文様が描かれている。","note":"渦巻き模様の土器","exp":"540"}],"1919":[{"type":"海洋生物","name":"ブラックマーリン","rank":"5","desc":"シロカジキ。太くて短いクチバシを持つ大型のカジキ。","note":"釣り","exp":"910"}],"5263":[{"type":"天文","name":"ケンタウルス座の球状星団","rank":"2","desc":"ケンタウルス座の馬の背にあたる位置にある星が球状に集まった星団。肉眼で見ることができ、星団とわかる以前にはケンタウルス座ω星と呼ばれていた。","note":"「天文学者の観測記録」<br/>発見物カード:150","exp":"300"}],"5781":[{"type":"地理","name":"死海","rank":"5","desc":"水中の塩分が非常に高い塩湖。流れ出る川がなく、流入する水より蒸発する水のほうが多いため、高い塩分濃度を保っている。魚が棲めない環境のため、死の湖と呼ばれている。","note":"","exp":"1380"}],"5886":[{"type":"大型生物","name":"フリージアン","rank":"5","desc":"欧州北西部が原産地とされる馬で、黒い体色と長い毛が特徴。力が強いため、荷物の牽引役や戦馬としても使用されてきた。","note":"","exp":"1330"}],"994":[{"type":"財宝","name":"東方見聞録","rank":"1","desc":"13世紀終わりごろ、元朝のフビライに仕えたマルコ・ポーロの口述を記録した本。この中に、黄金の国ジパングが登場する。","note":"冒険者のバイブル","exp":"55"}],"1615":[{"type":"植物","name":"エリデス","rank":"1","desc":"しだれ状に伸びた花茎に、小さい花を穂状につける。花はピンク、白、黄色などがある。芳香が強い。","note":"小さな花の地図","exp":"140"}],"3816":[{"type":"宗教遺物","name":"セミ像","rank":"3","desc":"カリブ地域に古くから居住するタイノ民族が作った石像。神と先祖の霊などを形づくっており、さまざまな姿のものがある。","note":"ある民族の像の地図","exp":"490"}],"1913":[{"type":"歴史遺物","name":"テ・ピト・クラ","rank":"1","desc":"「光のへそ」と呼ばれている場所。周りにモアイが立ち並ぶ中、白く滑らかな楕円の石がたたずんでいる。どんな意味があるのかは分からないが、神聖さを感じる。","note":"光のへその地図","exp":"170"}],"261":[{"type":"歴史遺物","name":"ラムセス2世の頭飾り","rank":"2","desc":"ラムセス2世は古代エジプトのファラオで、多数の建造物を作ったことで知られる。ラムセス2世の墓は墓泥棒に荒らされていたので所持品は珍しい。","note":"ファラオの装身具","exp":"220"}],"1017":[{"type":"財宝","name":"金とサファイヤのからくり時計","rank":"1","desc":"金とサファイヤで美しい細工を施したからくり時計。手のひらに乗るほどの大きさなのに定刻になると小さな人形が踊るからくりがしかけてある。","note":"名細工師の遺品","exp":"70"}],"1915":[{"type":"史跡","name":"アマルナの遺跡","rank":"2","desc":"古代エジプトのフォラオ、アメンホテプ4世の造営した都。彼の死後すぐにテーベへの遷都が行われ、まもなく住民がいなくなったという。古い言葉で「アテン神の地平」を意味する「アケトアテン」とも呼ばれる。","note":"他の神を知らず","exp":""}],"1023":[{"type":"地理","name":"ユーフラテス川","rank":"2","desc":"ペルシャを流れる大河である。チグリス川と並行して流れ、下流で合流する。この川の名は、聖書にも何度か登場する。黙示録では、この川のほとりに四人の天使がつながれているという。彼らは人間の三分の一を殺すために現れるそうだ…。","note":"黙示録に語られる大河","exp":"250"}],"6916":[{"type":"植物","name":"ゲイソリザ・ラディアンス","rank":"3","desc":"南アフリカに分布する球根植物。細長く平らな葉を持ち、花茎からは中心が赤く、外側は青紫色の花が咲く。その姿はワインを注いだ盃に例えられ、ワインカップとも呼ばれている。","note":"","exp":""}],"6210":[{"type":"歴史遺物","name":"世界の七つの景観","rank":"3","desc":"古代ギリシャの数学者フィロンの著作。当時の地中海世界に存在していた必見の建造物七つを紹介している。「世界七不思議」の元になったとされているが、彼が執筆時に居住していたアレクサンドリアにある大灯台は紹介していない。","note":"七不思議のはじまり","exp":"470"}],"5186":[{"type":"港・集落","name":"安平","rank":"2","desc":"読みは「アンピン」。台湾島の政治や軍事の中心地である街。\n船を停泊させるのに適した場所と判断され、大きな港になった。","note":"到達する","exp":"345"}],"3317":[{"type":"植物","name":"ムラサキバレンギク","rank":"4","desc":"北米東部から中南部にかけて生息する植物。夏から秋にかけて赤紫色の花を咲かせる。根には薬効があり、薬としても利用される。","note":"交易所店主からの協力依頼","exp":"700"}],"6852":[{"type":"美術品","name":"真珠の耳飾りの少女","rank":"3","desc":"別名「ターバンを巻いた少女」とも呼ばれるネーデルラントの画家フェルメールの作。青いターバンを巻いた少女が大きく描かれ、かすかに微笑んで見えることから「北のモナリザ」とも呼ばれる。","note":"発見物カード:240","exp":"480"}],"747":[{"type":"歴史遺物","name":"オドアケルの剣","rank":"1","desc":"オドアケルは、西ローマ帝国を滅ぼした、ゲルマン出身の将軍。西ローマの傭兵隊長であったが、西ローマ皇帝を追放してイタリア王を自称した。","note":"西ローマを滅ぼした者","exp":"95"}],"6291":[{"type":"植物","name":"サルスベリ","rank":"3","desc":"東アジアに分布する花木。長期にわたって花を咲かせるため、「百日紅」とも呼ばれる。幹が大きくなるに伴って新しい樹皮が表面に現れるため、すべすべとしているのが特徴。","note":"","exp":"600"}],"5394":[{"type":"海洋生物","name":"スルビ","rank":"3","desc":"パラグアイ川上流付近に生息するナマズの仲間。黒い縦縞が特徴の大きな魚で、その身はとても美味である。","note":"発見時経験値530　発見物カード経験値265","exp":"530"}],"5878":[{"type":"天文","name":"ベツレヘムの星","rank":"5","desc":"キリスト生誕を東方の三賢者に知らせたと伝えられる伝説の星。\n…なのだが、報告を仕上げて空を見上げると同じ星は二度と見つからなかった。自分が見たものが本当に伝説の星だったのか、確かめるすべはない。","note":"クエスト「クリスマスの星」<br/>発見物カード:725","exp":"1450"}],"2534":[{"type":"地理","name":"澎湖島","rank":"2","desc":"かつて鄭成功が台湾島へ向かう足掛かりとした島。\n海賊の影響で荒廃しているが、人類が古くから生活していたと思われる痕跡が数多く残されている。","note":"書きかけの地図","exp":"280"}],"6327":[{"type":"植物","name":"サジー","rank":"2","desc":"ユーラシア大陸に広く分布する植物。果実は栄養価が高いが、酸味がありそのままでは食べにくい。また幹や枝にトゲが多く、収穫は難しい。果実は鮮やかな橙色をしているため鑑賞目的で栽培されることもある。","note":"","exp":"330"}],"5191":[{"type":"港・集落","name":"淡水","rank":"2","desc":"読みは「ダンスイ」。台湾島の北部に位置する街で、近くを大きな川が流れている。鄭成功がネーデルラント人を追い出してできた街である。","note":"到達する","exp":"340"}],"917":[{"type":"歴史遺物","name":"エビ・イル像","rank":"2","desc":"メソポタミア文明の石像。材質はアラバスターで、柔らかな印象を受ける。この文明の像は、大きな目とウェーブのかかった髭が特徴である。","note":"半透明の白い像","exp":"380"}],"2695":[{"type":"歴史遺物","name":"花郎世記","rank":"3","desc":"読みは、「かろうせいき」。新羅の金大門が記したという書物。\n花郎とは、新羅時代に存在した、文武に長けた青年達のこと。戦時の際には先頭に立ち、国のために戦ったという。","note":"本当に必要なもの","exp":"530"}],"5105":[{"type":"港・集落","name":"ナッソー","rank":"2","desc":"フロリダ半島の南、西インド諸島北部ニュープロビデンス島の街。西インド諸島と呼ばれるのは、15世紀末、クリストバル・コロンの航海により発見されたがインドと誤認されたため。","note":"到達する","exp":"226"}],"2487":[{"type":"財宝","name":"瑠璃珠の首飾り","rank":"2","desc":"台湾島先住民の一部に家宝として代々伝えられていた首飾り。\n瑠璃珠には神聖な力が宿ると信じられ、病気治療の儀式にも使用される。","note":"集落の痕跡","exp":"310"}],"99":[{"type":"歴史遺物","name":"カエサルの剣","rank":"3","desc":"ユリウス・カエサルの剣。ガリア地方を平定しているときに、身につけていたものだとされる。ポンペイの遺跡跡から発掘され、刀身にはケルトの財宝に関する文言が記載されていた。","note":"カエサルの剣","exp":"440"}],"6646":[{"type":"宗教建築","name":"台南孔子廟","rank":"5","desc":"台湾島最古の孔子廟。「鄭氏諸葛」の異名を持つ軍師・陳永華によって建てられた。学校として教育を行う役割も併せ持っている。正門前には台湾島初の学校という意味の「全臺首學」の題字が掲げられている。","note":"","exp":"830"}],"2671":[{"type":"歴史遺物","name":"三国史記","rank":"2","desc":"古代朝鮮の歴史がつづられた歴史書。新羅、百済、高句麗の歴史が50巻に渡って記されている。\n高麗の儒学者により、二年ほどかけて編さんされたという。","note":"朝鮮三国歴史語り","exp":"340"}],"767":[{"type":"財宝","name":"ピジョンブラッド","rank":"3","desc":"最上級のルビー。ハトの血のような、鮮やかな紅色のものをいう。ルビーは大きな石が見つかりにくく、大粒のピジョンブラッドは大変な値打ちがある。","note":"赤い宝石の鉱脈の地図","exp":"580"}],"1300":[{"type":"海洋生物","name":"グラスキャットフィッシュ","rank":"3","desc":"体色を透明にすることで外敵から身を守っている魚。はっきりと見えるのは、骨、目、消化器官だけである。","note":"透明な魚","exp":"451"}],"1555":[{"type":"鳥類","name":"ゴシキセイガイインコ","rank":"1","desc":"鮮やかな色合いの鳥。外観は多様で、群れで騒々しく鳴く。","note":"鮮やかな色の鳥の地図","exp":"160"}],"732":[{"type":"美術品","name":"聖ヒエロニムスとライオン","rank":"2","desc":"バルトロメオ・ベラーノ作の青銅像。聖ヒエロニムスがライオンの足に刺さったトゲを抜いている姿である。青銅像は、通常は鋳型（いがた）を使って複製できるが、この作品は蝋型で作られた1点物で、複製品がない。","note":"聖者と獣の青銅像","exp":"300"}],"3644":[{"type":"宗教遺物","name":"ヴェレスの木像","rank":"2","desc":"スラブ神話に登場する神の像。ヴェレスは家畜や富を司る神とされ庶民の崇拝を受けた。死者の霊魂にも関係したとされる。「イーゴリ遠征物語」内では、伝説の大詩人がヴェレスの孫とされている。","note":"スラブ地方の木像の地図","exp":"330"}],"1247":[{"type":"中型生物","name":"ナマケモノ","rank":"3","desc":"のろのろと動きの遅い動物。糞をするときなどは地上に降りるが、それ以外は、ほとんどの時間を木の上で過ごす。木の葉や芽、虫を食べる。","note":"動きの遅い生物<br/><br/>発見時経験値473　発見物カード経験値236","exp":"473"}],"1588":[{"type":"地理","name":"レヴェーク岬","rank":"3","desc":"オーストラリアの北西にある岬。南部は砂漠化している。南南西に伸びる海岸線は100kmに及び、青い海と白銀の砂浜が美しい。","note":"砂漠の東端","exp":"462"}],"5339":[{"type":"天文","name":"海王星","rank":"5","desc":"天王星の軌道の揺れから存在が予測された惑星。\n大きさは天王星とほぼ同じだが、より深い青色をしている。","note":"クエスト「揺れる天王星」<br/>発見物カード:575","exp":"1170"}],"3294":[{"type":"地理","name":"バレン高原","rank":"4","desc":"アイルランド西部に広がる台地。アイルランドの言葉で「不毛な大地」を意味する。その名の通り、古代の岩がむきだしで転がり、荒野のようである。そのため、人間の手が及ばず、珍しい植物や古代史跡が多く見られる。","note":"不毛の高原","exp":"690"}],"6428":[{"type":"財宝","name":"アゾット剣","rank":"5","desc":"錬金術師パラケルススが所有していたといわれる剣。柄頭には、宝石でも石でもない正体不明の物質が組み込まれ、表面に「Azoth」という文字が刻まれていたといわれる。","note":"追究クエスト　発見物カード:560","exp":"1120"}],"285":[{"type":"歴史遺物","name":"マーリンの杖","rank":"5","desc":"アーサー王伝説に登場する魔法使い・マーリンの杖。マーリンはアーサーを育て、王になってからも補佐した人物。湖の精霊に自分の魔法の秘密を教え、捕らわれた。","note":"マーリンの杖","exp":"1118"}],"6913":[{"type":"海洋生物","name":"サーカスティックフリンジヘッド","rank":"5","desc":"北米西岸などに生息する魚。雄は縄張りを脅かす魚に対し、色鮮やかで巨大な口を開けて威嚇する。また、雄同士が開けた口を押しつけ合って戦うこともあるという。雌は雄より小さく、口の色は淡い。","note":"","exp":""}],"1573":[{"type":"大型生物","name":"クロコダイル","rank":"4","desc":"細長い口先が特徴的なワニ。体長は2.5mほどで、地上をすばやく動くことができる。","note":"南東の大陸にすむワニ","exp":"624"}],"6999":[{"type":"宗教遺物","name":"マアトの羽根を持つトト","rank":"5","desc":"古代エジプト神話における死後の審判を主題とした工芸品。トキは死者の生前の行いを記録する知恵の神トトの化身とされる。くちばしにくわえた羽根は真理と秩序の女神マアトのもので、死者の罪を量るために用いられるという。","note":"","exp":""}],"6288":[{"type":"史跡","name":"古蜀の遺跡","rank":"5","desc":"紀元前に栄えていた古蜀文化の遺跡。長江の上流に位置する。非常に広大な遺跡で、縦目仮面の他にも貴重な物が眠っていると思われる。","note":"","exp":"1230"}],"1975":[{"type":"小型生物","name":"デグー","rank":"4","desc":"ネズミをひと回り大きくしたような、リスに似た動物。多彩な鳴き声で仲間と交流する姿は、歌を歌っているように見える。警戒心がないのか、人によくなれる。寒冷なアンデス高地の、岩場や断崖に生息する。","note":"歌うネズミ","exp":"740"}],"5875":[{"type":"天文","name":"東方七宿青龍","rank":"5","desc":"中国星座において、天の赤道を28に分割した二十八宿のうち東方の七宿をまとめたもの。おとめ座やさそり座などが含まれる。","note":"クエスト「中国の天文学」<br/>発見物カード:710","exp":"1420"}],"6812":[{"type":"財宝","name":"テーベの小箱","rank":"5","desc":"プラチナ装飾の施された純金製の小箱。古代エジプトのテーベ王朝の遺跡で見つかった。現存するなかでは、プラチナを使った最古のものとされる。","note":"発見物カード経験値　475","exp":""}],"1725":[{"type":"歴史遺物","name":"チャンシッター王の盃","rank":"2","desc":"パガン王朝の王で、アノーヤター王の跡を引き継いでシュエジゴンパゴダの建設に尽力した。シュエジゴンパゴダには釈迦（しゃか）の遺骨や遺髪、歯などが収められているという。シュエジゴンパゴダの完成をこの盃で祝ったのだろうか。","note":"意志を継いだもの","exp":"230"}],"1466":[{"type":"財宝","name":"水太鼓","rank":"4","desc":"男子が成人する際に行われる儀式で使用される楽器。地面に穴を掘り水を張って、そこへこの太鼓を沈めて上下させることで音を変える。","note":"変わった打楽器","exp":"624"}],"862":[{"type":"宗教遺物","name":"スーリヤ像","rank":"3","desc":"インド神話の太陽神の像である。スーリヤは暁の女神であるウシャスを妻とする。スーリヤは全身が光り輝いているため、朝日となって姿を表すと、暁であるウシャスは目がくらみ、姿を隠してしまうという。","note":"天翔ける太陽","exp":"440"}],"5633":[{"type":"天文","name":"ケレス","rank":"2","desc":"火星の軌道の外側にある小惑星帯に位置する天体。惑星と似た軌道で動くが、惑星より小さい天体のようだ。","note":"「天文学者の観測記録」<br/>発見物カード:115","exp":"230"}],"1597":[{"type":"財宝","name":"バロック真珠のペンダント","rank":"1","desc":"変形真珠に、彫刻的で豪華なデザインを組み合わせたペンダント。自然物、動物、神話をテーマにした図案が多い。バロックの名称は「歪んだ真珠」というポルトガル語に由来する。","note":"憧れの輝き","exp":"110"}],"6794":[{"type":"天文","name":"シェリアク","rank":"3","desc":"こと座のベータ星。3等星であり、星の回転により明るさが変わる食変光星。名はアラビア語の「琴」が由来とされている。","note":"","exp":""}],"6750":[{"type":"天文","name":"バタフライ星団","rank":"5","desc":"さそり座にある散開星団。さそりの尾にあたる位置の前端にある。羽を広げた蝶に似ていることから名付けられた。","note":"","exp":""}],"5932":[{"type":"財宝","name":"ツィンク","rank":"2","desc":"角笛から発展した金管楽器で、リコーダーのように指で穴をふさいで音を調整する。ドイツや北欧では「ツィンク」、それ以外の地域では「コルネット」と呼ばれ、ヨーロッパ全域で広く親しまれている楽器の一つである。","note":"","exp":""}],"2703":[{"type":"財宝","name":"守人の帽子","rank":"3","desc":"朝鮮の両班が着用する特別な帽子。\n両班は文官と武官に分かれるが、この帽子は武官のものである。","note":"ある武人の証明","exp":"470"}],"1964":[{"type":"財宝","name":"ケーナ","rank":"3","desc":"竹やアシ、動物の骨など様々な材料で作られる縦笛。インカにおいて儀式に音楽は欠かせず、楽器は祭具としての側面も強い。構造は単純だが演奏は非常に難しい。","note":"新大陸の祭事笛","exp":"480"}],"3721":[{"type":"地理","name":"ゴビ砂漠","rank":"5","desc":"モンゴルに広がる広大な砂漠地帯。\nゴビとは、モンゴル語で「乾いた土地」の意味であり、その名のとおり、乾いた風が吹きつける。","note":"黄色の風の故郷","exp":"980"}],"6332":[{"type":"財宝","name":"シグロス銀貨","rank":"3","desc":"アケメネス朝ペルシャにて発行された銀貨。表には弓と槍を持って狩りを行う王の姿が刻印され、王の権威を表している。","note":"","exp":"500"}],"2877":[{"type":"宗教遺物","name":"折れた剣の欠片","rank":"3","desc":"高句麗初代王・朱蒙が息子の類利に残したとされる剣の欠片。\n父を知らずに育った類利は、ある時、母から「隠された剣を探し出せれば我が子だ」という父の言葉を伝えられる。類利は見事に剣を探し当て、高句麗二代王となったという。","note":"父と子の証","exp":"470"}],"5048":[{"type":"港・集落","name":"グァテマラ","rank":"2","desc":"太平洋に面した中米の港街のひとつで、コーヒーの産地として知られる。沿岸の熱帯低地と、内陸の高原地帯では気温の差が激しい。","note":"到達する","exp":"295"}],"5115":[{"type":"港・集落","name":"バレンシア","rank":"1","desc":"古代ローマ時代から栄えた街。イスラム勢力に支配された時期があるため、イスラム文化とヨーロッパ文化が共存している。農作物が豊富に流通するほか、近くにある鉱山から辰砂（しんしゃ）が採れる。","note":"到達する","exp":"11"}],"2349":[{"type":"財宝","name":"源氏物語","rank":"4","desc":"紫式部によって書かれた長編小説。平安時代の宮廷を舞台としている。\n華やかな貴族の生活と複雑な人間関係をつづった、情趣溢れる恋愛小説である。","note":"さまざまな恋の形","exp":"750"}],"5846":[{"type":"天文","name":"さいだん座","rank":"3","desc":"神々に生贄を捧げる祭壇をかたどった星座。ギリシャ神話の最高神ゼウスとその兄弟たちが、父クロノスの打倒を誓った祭壇とも言われている。","note":"","exp":"490"}],"5655":[{"type":"地理","name":"黒砂漠","rank":"4","desc":"サハラ東部に位置する砂漠。玄武岩で覆われており、全体的に黒く見える。黒いピラミッドのような山が点在している。","note":"","exp":"690"}],"419":[{"type":"中型生物","name":"シマウマ","rank":"1","desc":"体全体に黒と白のしま模様がある動物。馬を小さくしたような体つきをしている。多数の群れで生活しているようだ。","note":"奇妙な模様の動物の地図","exp":"34"}],"1327":[{"type":"地理","name":"シャム湾","rank":"2","desc":"ヤーデインの西に広がる巨大な湾。水深が浅く、大河が流れこむために塩気は薄い。沿岸にはマングローブの林が見られ、格好の漁場となっているようだ。","note":"ヤーデイン西の巨大湾","exp":"270"}],"6732":[{"type":"財宝","name":"サンポーニャ","rank":"5","desc":"南米アンデス地方の伝統的な管楽器。竹または葦などでさまざまな長さの管を作り、それを束ねて製作する。ナスカ文化の遺跡などから出土していることから、インカ帝国以前の古代アンデス文明が起源といわれる。","note":"楽の叡智・心に響く楽器　左下","exp":""}],"4802":[{"type":"海洋生物","name":"トビイカ","rank":"3","desc":"暖かい海に住むイカの一種。敵に襲われたり、驚いたときに足を広げて翼の代わりとし、漏斗から海水を吹いて空を飛ぶことがある。 その距離が数十ｍに及ぶという。","note":"海面を飛ぶ生物の調査","exp":"460"}],"6618":[{"type":"歴史遺物","name":"ジャムシードの杯","rank":"5","desc":"ゾロアスター教の神話に登場する、伝説の王ジャムシードの杯。多くのペルシャ文学に登場し、ペルシャ帝国の王位継承の象徴とされた。未来を占えるという伝説がある。","note":"レガシー美の叡智　中央","exp":"1800"}],"1520":[{"type":"史跡","name":"アッピア街道","rank":"2","desc":"共和制ローマ時代に造られた、ローマからイタリア半島南東岸に延びる街道。ローマ街道の中でもっとも歴史が古く、もっとも美しいといわれている。","note":"すべての道はローマに通ず","exp":"230"}],"1188":[{"type":"鳥類","name":"サンショクウミワシ","rank":"2","desc":"その名の通り、濃い茶と黒の羽毛、白い頭と胸、黄色の嘴（くちばし）が目立つ。魚を主食としているが、まれにカモなどをおそうこともある。頭を後ろにそらせてかん高い大きな鳴き声を上げる。","note":"鳥を襲う鳥","exp":"270"}],"6433":[{"type":"歴史遺物","name":"インカのユパナ","rank":"5","desc":"インカ帝国で使用されていたという計算用器具。凹みの中に小石や粒を入れ、法則にそって移動させることにより計算する。複雑な計算を素早く行い、ヨーロッパ人を驚かせたと伝わるが、詳しい使用法は不明のようだ。","note":"","exp":""}],"6455":[{"type":"気象・現象","name":"多重渦竜巻","rank":"2","desc":"複数の竜巻が、一つにまとまってできる竜巻群。大型のものは、広範囲に甚大な被害を与える場合がある。大きな竜巻の周りを、小さな竜巻が取り巻くような構造を有することも多い。","note":"コロラド高原北西のとんがり岩付近","exp":"140"}],"3779":[{"type":"天文","name":"フォーマルハウト","rank":"5","desc":"ヨーロッパの秋の夜空でひときわ目立つ1等星。アラビア語で「大魚の口」という意味のファム・アル・フートが名の由来で、みなみのうお座の口の位置にある。ヨーロッパ北部では、南国へのあこがれを誘う星とされる。","note":"視認","exp":"810"}],"1332":[{"type":"地理","name":"カリマタ海峡","rank":"1","desc":"カリマンタン島の西に横たわる海峡。遠浅で波は穏やか。近年はこのあたりに、海賊の報告が多く寄せられている。","note":"書きかけの地図","exp":"160"}],"2350":[{"type":"歴史遺物","name":"漆紙文書","rank":"2","desc":"読みは「うるしがみもんじょ」。紙に漆が染み込み、土の中でも腐らずに残ったもの。\n漆液は、保存時に紙蓋で容器を密閉する必要がある。だが、当時の日本では紙が貴重だったため、不要になった文書を蓋として用いていた。","note":"土中に眠る塊","exp":"360"}],"3265":[{"type":"財宝","name":"コラ","rank":"4","desc":"西アフリカ一帯に伝わる弦楽器。弦の数は21本で、親指と人差し指で爪弾いて音を出す。音楽家はこのコラを用い、歴史や情報を弾き語ることにより伝統を紡いできたようだ。","note":"歴史を奏でる者たち<br/><br/>発見時経験値740　発見物カード経験値370","exp":"740"}],"5556":[{"type":"地理","name":"シェルビーチ","rank":"5","desc":"オーストラリア大陸西岸のシャーク湾に面した海岸。小さな白い貝殻が堆積して浜をなしている。","note":"","exp":"990"}],"5042":[{"type":"港・集落","name":"カレー","rank":"1","desc":"ドーバー海峡に面する北フランスの街。過去に幾度もイングランドとフランスの争いの種となり、頑強な要塞都市となった。産物は加工食品のほかに香料、高級織物などがある。","note":"到達する","exp":"7"}],"6615":[{"type":"歴史遺物","name":"草薙剣","rank":"5","desc":"日本における三種の神器の一つ。ヤマトタケルが東国の征伐に赴く際、敵が火攻めした草をこの剣でなぎ払ったことから、「草薙剣」の名が与えられたという説がある。これが本当の草薙剣なのかは分からない。","note":"レガシー美の叡智　左上","exp":"3150"}],"6768":[{"type":"宗教建築","name":"聖ヨハネ大聖堂","rank":"2","desc":"16世紀後半、ヨハネ騎士団長カシエールにより、マルタの首都ヴァレッタに建てられた礼拝堂。マルタ島特産の石灰岩を使用しており堂内には歴代の騎士団長が埋葬されている。","note":"発見物カード　経験値:140","exp":"280"}],"3911":[{"type":"天文","name":"オリオン座の馬の頭のような星雲","rank":"2","desc":"オリオン座の三ツ星の東端の星からやや南にある星雲。明るい雲の手前に馬の頭のような形の黒い雲が見える。","note":"「天文学者の観測記録」<br/>発見物カード:155","exp":"310"}],"5012":[{"type":"港・集落","name":"アゾレス","rank":"1","desc":"大西洋の中央に位置する火山島の街。15世紀前半、ポルトガルによって発見されて以来、ヨーロッパ列強各国からの移住者が、多くいる。新大陸への遠洋航海における足がかりとなっている。","note":"到達する","exp":"110"}],"2516":[{"type":"中型生物","name":"タイワンザル","rank":"1","desc":"台湾島に生息しているサル。全身は灰褐色で四肢の先端が黒い。尾は比較的長くて太い。","note":"尾が長いサルの地図","exp":"130"}],"1175":[{"type":"財宝","name":"エル・カミーノ・レアル","rank":"5","desc":"「エル・カミーノ・レアル」とは、スペイン語で「王道」という意味。真紅のフラメンコ衣装で、カール5世がミカエラを思ってデザインした。これを手放したということは、カール5世は過去との決別を決意したのだろうか…。","note":"王の道へ…<br/><br/>発見時経験値1222　発見物カード経験値611","exp":"1222"}],"1002":[{"type":"小型生物","name":"クサリヘビ","rank":"1","desc":"頭部が三角形をしている猛毒のヘビ。多くの種類がおり、熱帯から北極圏近くまで広く生息する。卵ではなく子を産む。","note":"北欧の毒蛇の調査","exp":"150"}],"3883":[{"type":"天文","name":"大彗星","rank":"2","desc":"19世紀にはいくつかの彗星が観測された。中でもゴールドラッシュと同時期に現れた彗星は非常に明るく、各地に観測の記録が残る。","note":"発見物カード:110","exp":"220"}],"1722":[{"type":"鳥類","name":"モア","rank":"5","desc":"アオテアロアの森に棲む飛べない鳥。見た目はダチョウに似ているが、両翼は見当たらない。中には体長4mという、鳥とは思えぬほど巨大なものもいる。以前はたくさんいたようだが、島に人が住むようになってから激減しているらしい。","note":"怪鳥再び","exp":"1222"}],"5737":[{"type":"宗教遺物","name":"古儀式派祈祷法本","rank":"2","desc":"ロシア正教会での古い祈祷様式を記した本。ロシア正教会での奉神礼改革を機に主流派から分離した諸教派を古儀式派と呼ぶ。","note":"バイカル湖周辺再調査地図","exp":""}],"3552":[{"type":"レリック","name":"アリババと盗賊","rank":"","desc":"アラビア語やペルシャ語ではアリババの「ババ」は「お父さん」という意味らしい。アリババは意外と年配だったのだろうか。","note":"","exp":""}],"1608":[{"type":"鳥類","name":"ナナイロインコ","rank":"1","desc":"頭と首は黄色く、胸へ行くにつれて朱色の羽毛へと変わっていく。背中は緑色で、翼と細く尖った尾は様々な色をしている。十数匹の群れで生活している。","note":"七色の鳥の地図","exp":"135"}],"2822":[{"type":"歴史遺物","name":"焼けた竹簡","rank":"2","desc":"雲台山郊外で見つかった焼け跡のある竹簡。炭化が進んでおり元の内容を解読することは不能。状態から焚書の名残りであると思われる。焚書に関しては、秦の始皇帝が、宰相・李斯の提案で行ったものが有名。","note":"地中に眠る竹簡","exp":"370"}],"594":[{"type":"地理","name":"ドナウ川","rank":"1","desc":"ヨーロッパを貫く大河で、黒海に注ぐ。全長は3000km近いともいわれる。古くから交易や軍事に使われ、流域には多くの都市が発展している。","note":"黒海へそそぐ川","exp":"180"}],"1558":[{"type":"地理","name":"スペンサー湾","rank":"1","desc":"オーストラリアの南岸エア半島の東に位置する鋭角にくぼんだ湾。湾の近郊には豊富な埋蔵量をもった銀鉱脈があるらしい。","note":"書きかけの地図","exp":"135"}],"1893":[{"type":"歴史遺物","name":"コロン提督の手記","rank":"2","desc":"ポルトベロに到達したコロン提督による報告書の一部。どうやら調査の途中で紛失してしまった物のようだ。","note":"［勅命］[[ある調査の追加調査","exp":"310"}],"6353":[{"type":"史跡","name":"太陽神の彫刻","rank":"2","desc":"ロードス島の巨像のモチーフになった太陽神ヘリオスの彫刻。古代ギリシャでは朝に太陽が昇り夜に沈むのは、ヘリオスが毎朝、太陽の戦車をひいて東から出発し、夜になると海に入り東へ戻るからと信じされていた。","note":"","exp":"300"}],"3197":[{"type":"海洋生物","name":"ダイオウイカ","rank":"5","desc":"巨大なイカの一種。全長は10m以上にもなるといわれる。深海に生息していると考えられており、生きている姿が見られるのは非常に稀である。","note":"クラーケンの伝説","exp":"990"}],"6343":[{"type":"史跡","name":"アッラーヴェルディ・ハーン橋","rank":"2","desc":"中東にある全長約300mの長い橋。「スィー・オ・セ橋」とも呼ばれる。33ものアーチがありイスラム建築様式のひとつであるサファヴィー建築の様式で造られている。","note":"","exp":"260"}],"346":[{"type":"財宝","name":"隠し財宝","rank":"2","desc":"貴金属や宝石などが詰められた箱。当時の貴族や金持ちが、戦争などに備えて隠したのだろうか。","note":"隠された財宝の地図","exp":"310"}],"1770":[{"type":"地理","name":"アタカマ砂漠","rank":"2","desc":"南米西岸中部を覆う南北に細長い砂漠。降雨は数十年に一度という地域もあり、世界でも有数の乾燥地帯といえるだろう。そのため樹木の姿を見ることはできないが、銅や銀、そして硝石と豊富な鉱物資源を有している。","note":"細長い砂漠","exp":"210"}],"1891":[{"type":"歴史遺物","name":"コンセイサウン号","rank":"2","desc":"正式名は、ノッサ・セニョーラ・ダ・コンセイサウン号。\nポルトガルの東インド貿易船で、王室の財宝をインドに輸送していた。チャゴス諸島付近で沈没。","note":"サルベージ","exp":"310"}],"4949":[{"type":"宗教建築","name":"キプロス島の壁画聖堂群","rank":"2","desc":"キプロス島の山岳地帯にある聖堂群。木や石の外壁に切妻屋根という簡素な外観の造りだが、内壁や天井にはビザンツ様式のフレスコ画が華麗に描かれている。","note":"フレスコ画の研究<br/><br/>発見時経験値220　発見物カード経験値110","exp":""}],"2922":[{"type":"財宝","name":"百済王の太刀","rank":"4","desc":"百済の遺跡で発見された環頭太刀。\n柄には、龍の装飾がある。きっと百済王が使用していたのだろう。","note":"百済王の軌跡","exp":"800"}],"6049":[{"type":"歴史遺物","name":"兵士の群像","rank":"1","desc":"ビブロスのオベリスク神殿から出土した、青銅製の兵士像。エジプトからの贈呈品と思われる。エジプトは、ミイラ作成や建材用にレバノン杉を輸入しており、大量の供物をしてビブロス王の機嫌をとっていたという。","note":"銅細工の地図","exp":"150"}],"1874":[{"type":"宗教遺物","name":"黄金の筏","rank":"5","desc":"チブチャ民族の儀式に使われる黄金製の筏。族長は、月夜の晩に全身金粉を塗って黄金の筏から湖に飛び込むという儀式を行う。","note":"黄金の筏","exp":"1070"}],"6998":[{"type":"宗教遺物","name":"テミスの天秤","rank":"5","desc":"ギリシャ神話の女神テミスの像がかつて左手に持っていたとされる天秤。正邪や善悪を量る道具とされ、正義や公平の象徴とされている。","note":"","exp":"900"}],"4349":[{"type":"海洋生物","name":"ノーザンパイク","rank":"3","desc":"カワカマスの一種で、淡水域または汽水域に生息する魚。北半球の高緯度の地域に、広く分布する。体長1mを超える大型肉食魚で、鋭い牙を持つ。","note":"釣り","exp":"480"}],"6392":[{"type":"地理","name":"ドーバーの白い崖","rank":"2","desc":"ドーバー海峡に面する白い崖。石灰岩でできているため白い。イングランドの玄関口だけでなく要塞としての役割もある。ブリテン島の通称である「アルビオン」は、ラテン語で白色を意味する言葉が語源であり、その由来はこの崖だとされる。","note":"","exp":"380"}],"581":[{"type":"財宝","name":"さびた宝剣","rank":"1","desc":"刃がさびついてしまった宝剣。宝石や金で装飾が施されている。刃はそれほどよいものではないので、装飾用だと思われる。","note":"豪華な武器の地図","exp":"53"}],"1336":[{"type":"地理","name":"スマトラ島","rank":"2","desc":"マレー半島の南に位置する島。マレー半島との距離は非常に近く、動植物も似通っているようだ。古くから東西交易の要衝として様々な商人が来航する島である。","note":"海峡の南の島","exp":"320"}],"3680":[{"type":"地理","name":"チェリュスキン岬","rank":"4","desc":"ユーラシア大陸最北端の岬。\n北東航路において、航海の重要な目印となるだろう。","note":"","exp":"650"}],"2595":[{"type":"地理","name":"金門島","rank":"2","desc":"かつて鄭成功の拠点となっていた島。\n貢糖と呼ばれる、砂糖とピーナッツを原料にした産物が有名。","note":"［勅命］[[献上品の産地調査","exp":"320"}],"6133":[{"type":"史跡","name":"東坡赤壁","rank":"2","desc":"北宋の文人である蘇軾が黄州に左遷された頃に「赤壁賦」前後作を作ったとされる場所。三国志で有名な赤壁から程近い場所にある。晩唐の詩人、杜牧が詩に詠んだことで、古戦場の赤壁と混同されたといわれる。","note":"","exp":"360"}],"6267":[{"type":"伝承","name":"龍神","rank":"5","desc":"中国や日本に伝わる霊獣。人里離れた山の中にある湖や淵の底に住み、水や雨を操るという。\n特に日本では白ヘビなどの姿になって人里に降りるという逸話が多く、神でありながら身近な存在ともいえなくもない。","note":"クエスト「ヘビに似た生き物の伝承」<br/>発見物カード:760","exp":"1520"}],"6736":[{"type":"天文","name":"ゴメイサ","rank":"5","desc":"こいぬ座を構成する星で、小犬の首辺りに位置する。名前はアラビア語で「小さな涙ぐんだもの」を意味する。","note":"発見物カード:410","exp":"820"}],"588":[{"type":"地理","name":"スカンジナビア半島","rank":"1","desc":"北海の北にある巨大な半島。西岸には独特の地形が続く。寒冷な気候で冬は厳しい。森林が多いため林業が盛んである。鉱山も多いという。","note":"黒い森の島","exp":"110"}],"2351":[{"type":"地理","name":"琉球","rank":"4","desc":"沖縄本島を始めとする諸島。琉球王の統治下にある。\n中国や日本との交流があり、船が頻繁に行き来する場所である。","note":"文化が集う島","exp":"700"}],"5663":[{"type":"気象・現象","name":"空中竜巻","rank":"2","desc":"渦巻の下端部分が空中にあり、地上や洋上に接していない現象。接点がないため、地上や洋上で被害が生じることはない。発生日時などの条件は、普通の竜巻とほぼ同じと思われる。","note":"南米南東岸やや北東","exp":"390"}],"857":[{"type":"歴史遺物","name":"ラバルナ王の剣","rank":"4","desc":"ラバルナ王はアナトリアを統一してヒッタイト王国を興した人物。ヒッタイトは鉄器の製造技術を独占して強国となったが、この王の治世ではまだ銅剣である。","note":"鉄の国","exp":"660"}],"103":[{"type":"地理","name":"テネリフェ島","rank":"1","desc":"カナリア諸島の中で一番大きな島である。長さは100km、幅は50km程度で土地はよく肥えている。しかし、標高3700mにもなるテイデ火山があり、定住には充分な調査が必要となるだろう。","note":"クエスト「カナリア諸島の調査」<br/>発見物カード:20","exp":"40"}],"3308":[{"type":"地理","name":"スカイ島","rank":"2","desc":"ブリテン島北部、西側にある島。\n名前の由来は古代ノルド語からとった説と、北欧神話の神・スカアハの名からとった説の両方がある。時に「霧の島」とも呼ばれる。","note":"書きかけの地図","exp":"250"}],"1335":[{"type":"地理","name":"チェンドラワシ湾","rank":"2","desc":"ニューギニア島北西にある湾。蓋をするような位置に島がある。海賊の襲撃に対する注意が必要だろう。","note":"書きかけの地図","exp":"220"}],"560":[{"type":"歴史遺物","name":"ルーン文字の石碑","rank":"1","desc":"古代の北欧で使われていたルーン文字で銘文が刻まれた石碑。多くは業績の記録や何がしかの記念碑。北欧では石碑の建立はひんぱんに行われていた。","note":"古代文字の遺物の地図","exp":"28"}],"6328":[{"type":"小型生物","name":"アフリカマイマイ","rank":"2","desc":"東アフリカなどに生息する最大級のカタツムリの一種。植物はもちろん砂や石まで食べるほどの雑食性。調理すれば食べられるが、直接触れたり、這った跡に触れたりすると寄生虫に感染する恐れがある。","note":"","exp":"320"}],"1996":[{"type":"海洋生物","name":"メガネモチノウオ","rank":"3","desc":"頭部にあるコブが最大の特徴。ベラの仲間で体長は1mを超える。","note":"釣り","exp":"528"}],"5262":[{"type":"天文","name":"オリオン座流星群","rank":"2","desc":"毎年十月下旬に見られる、明るい流星群。オリオン座の中でもふたご座に近い位置から飛び出るように見える。ハレー彗星が母天体とされる。","note":"「天文学者の観測記録」<br/>発見物カード:185","exp":"370"}],"6651":[{"type":"財宝","name":"クヌート大帝の硬貨","rank":"5","desc":"クヌートは、11世紀、ヴァイキングとも呼ばれたデーン人の王。イングランドのほかノルウェー、スウェーデンを征服し北海帝国を築いた。彼の肖像が刻まれた硬貨はヴァイキングの貿易の広まりと共に遠くまで流通した。","note":"","exp":"830"}],"2751":[{"type":"美術品","name":"李公麟の絵画","rank":"3","desc":"朝鮮の画家・李公麟によって描かれたトラの絵画。\n写実的でありながら、顔をこっけいに描かれたトラは、どこかかわいらしく親しみやすい雰囲気がある。","note":"さまざまな水墨画<br/><br/>発見時経験値440　発見物カード経験値220","exp":"440"}],"1787":[{"type":"地理","name":"タティオ間欠泉群","rank":"1","desc":"アタカマ砂漠内にある間欠泉。標高4500mの場所にある。熱湯が地中から噴出し、蒸気が空に登る様は、非常に幻想的だ。","note":"書きかけの地図<br/><br/>コピアポの門の外","exp":"200"}],"5093":[{"type":"港・集落","name":"チュニス","rank":"1","desc":"かつて古代都市・カルタゴがあった場所である。7世紀後半にイスラム勢力によって街が築かれた。その後、いくつかの独立王朝の首都とされ、国際色豊かな都市となった。産物は、農作物と麻生地のほか、高級染料が採れる。","note":"到達する","exp":"38"}],"2616":[{"type":"歴史遺物","name":"鶯歌石","rank":"4","desc":"読み方は、「おうかせき」。\n台北（タイペイ）の山にある巨石。瘴気を吐き、人々に害をもたらしていた怪鳥が鄭成功に撃ち落とされて石となったという伝説が残っている。","note":"淡水周辺の安全調査","exp":"620"}],"6385":[{"type":"財宝","name":"カール大帝の指輪","rank":"5","desc":"カール大帝を魅了したと噂される指輪。もともとはカール大帝の愛人のひとりが身につけていたとされる。指輪を身につけると不思議な魔力で、相手を魅了するという言い伝えがある。","note":"","exp":"980"}],"926":[{"type":"財宝","name":"金彩の水差し","rank":"1","desc":"金彩が施された豪華な水差し。凝った装飾がされているが、実用性もある。高貴な人の日用品だったのかもしれない。","note":"美しいつぼの地図","exp":"34"}],"309":[{"type":"財宝","name":"ラーマーヤナ","rank":"2","desc":"「マハーバーラタ」と並ぶ古代インドの大叙事詩。ヴィシュヌ神の化身・ラーマ王子と、彼の妻をさらった羅刹（らせつ）・ラーヴァナの戦いを描いたものである。","note":"ラーマとシーターの物語","exp":"230"}],"6388":[{"type":"植物","name":"ホウライショウ","rank":"2","desc":"中米などに分布する多年草。別名「モンテスラ」。成長に合わせて葉には穴が開く。その穴が連結し大きな切れ込みとなる。果実は食用にもなる。完熟していないものは口に強い刺激を与える。","note":"","exp":"210"}],"2241":[{"type":"小型生物","name":"ハナガエル","rank":"2","desc":"卵を口の中で育てる、変わったカエル。卵が成長すると、子ガエルが父親ガエルの口からはい出てくる。尖った頭と鼻が特徴。","note":"飼い主の心配","exp":"230"}],"2423":[{"type":"海洋生物","name":"クエ","rank":"1","desc":"ハタ科の魚の中でも大きくなる種で、1mを超えることもある。\n夜行性で、昼間は岩場に潜み、夜になると海底付近をゆったりと泳ぎながらエサとなる魚介類を探し求める。","note":"釣り","exp":"98"}],"1666":[{"type":"歴史遺物","name":"ハウマカの杖","rank":"5","desc":"ホツ・マツア王を、ラパ・ヌイへ誘った賢者ハウマカが使用した杖といわれている。彼は太陽の昇る方向へ飛んでいく夢を見て、たどり着いた島の美しさ、豊かさを知り、「我が王の治めるにふさわしい土地だ」と、王に移住を勧めたという。","note":"伝説の立証<br/><br/>発見時経験値1053　発見物カード経験値526","exp":"1053"}],"1629":[{"type":"美術品","name":"最後の審判（ミケランジェロ）","rank":"5","desc":"ミケランジェロのフレスコ画。巨大にして素晴らしい芸術作品である。描かれているのは最後の審判の様子。中央にイエスがおり、救われた者は左手から昇天し、罰を宣告された者は右手から地獄に落ちる。","note":"芸術か異端か","exp":"1118"}],"1760":[{"type":"歴史遺物","name":"白色紋様土器","rank":"1","desc":"白い土器のつぼに、幾何学の紋様が施されている。この白は石英を混ぜて出したものではないだろうか。","note":"メソアメリカの土器の地図","exp":"110"}],"5895":[{"type":"宗教遺物","name":"マニ石","rank":"1","desc":"お経やマントラが刻まれた石。チベット仏教が信仰されている地域で見られる。横を通る際には、右肩を石に向けて歩くのが良いとされている。","note":"","exp":"150"}],"4844":[{"type":"史跡","name":"ニネヴェ","rank":"4","desc":"アッシリア帝国が後期に首都を置いた都市。\nアッシリア中の書物が集められたアッシュールバニパルの図書館があったといわれる。","note":"王の図書館","exp":"780"}],"5462":[{"type":"鳥類","name":"オオホウカンチョウ","rank":"5","desc":"南米の熱帯雨林に生息する中型の鳥。頭にはカールしたような特徴的な冠羽が観られる。\n飛翔能力が弱いようで常に地上または低い木の上で生活している。","note":"","exp":"1080"}],"6445":[{"type":"財宝","name":"君主論","rank":"1","desc":"フィレンツェの外交官ニッコロ・マキャヴェリが執筆した政治思想書。道徳や宗教を排除した現実主義の視点で書かれ、君主には残酷さが必要と主張した。権謀術数の書として危険視され禁書指定を受けたが、現実主義的政治学の源流となった。","note":"","exp":""}],"5167":[{"type":"港・集落","name":"ヤーデイン","rank":"2","desc":"メコン川流域に建設された街。長くチェンラ王国の支配を受けてきた。川の上流にはチェンラ王国の古都があるといわれている。","note":"到達する","exp":"327"}],"3704":[{"type":"レリック","name":"シャーウッドの森の義賊","rank":"","desc":"シャーウッドの森に住んだとされる礼節深きアウトロー、ロビン・フッド。時代を超えて語り継がれ、人々に愛され続けている。","note":"義賊の弓<br/><br/>発見時経験値3030　発見時名声2420<br/>(合計名声2万超えによる名声半減のため、1210*2にしてあります)","exp":"3030"}],"2651":[{"type":"中型生物","name":"キバノロ","rank":"4","desc":"朝鮮半島から中国北部に分布するシカ。雌雄共にツノがなく、上あごの犬歯が発達して、長く伸びている。\n警戒心が強いためか、姿を見せることはめったにない。","note":"臆病な動物","exp":"640"}],"785":[{"type":"虫類","name":"アポロチョウ","rank":"3","desc":"後ろ羽に赤くて丸い斑紋がある。それが太陽に似ているからかはわからないが、太陽が照りつける間だけ活動する。山岳の乾燥した草原に棲む。","note":"太陽のチョウ","exp":"473"}],"3659":[{"type":"歴史遺物","name":"古代のアムフォラ","rank":"3","desc":"古代の地中海地域で広く使われた陶器の壷。二つの持ち手がついており、7世紀頃までワインやオリーブ油などの貯蔵や輸送に利用された。このアムフォラはカタコンベでの儀式に使うために持ち込まれたと思われる。","note":"ダンジョン","exp":"510"}],"70":[{"type":"地理","name":"インダス川","rank":"2","desc":"インド西部を流れ、アラビア海に注ぐ大河。下流域は小型船が行き来している。流域の灌漑（かんがい）用水でもあり、この川がなければ広大な土地が砂漠と化すだろう。","note":"インドの母なる川","exp":"270"}],"6861":[{"type":"天文","name":"ヴィンデミアトリックス","rank":"2","desc":"おとめ座のイプシロン星。３等星で、この星座の恒星の中ではポリマについで３番目に明るい。名はラテン語で「ぶどうを摘む女」を意味し、ギリシャ語を語源としている。","note":"発見物カード:155","exp":"310"}],"6590":[{"type":"海洋生物","name":"アズファー","rank":"2","desc":"紅海に生息する魚。別名アラビアンエンゼルフィッシュ。黒青から濃紫の体色が特徴で、明るい黄色の縦縞模様が入っている。","note":"","exp":"370"}],"1213":[{"type":"海洋生物","name":"マカロニペンギン","rank":"2","desc":"大きく目立つ金色の冠毛を持つ。くちばしはオレンジ色で、その周辺にピンクの縁取りがある。とても攻撃的である。","note":"セバルド島周辺の生物","exp":"280"}],"3868":[{"type":"海洋生物","name":"ミンククジラ","rank":"1","desc":"赤道よりも北の海で生息する小型のクジラ。外洋で生活し、広範囲を回遊する。","note":"小型のクジラの地図","exp":"190"}],"814":[{"type":"地理","name":"ニジェール川","rank":"1","desc":"西アフリカの中央部を流れる大河。大きく湾曲している。上流まで小型船で航行でき、この地方の重要な交通路である。上流には、数百年もの間栄えているトンブクトゥという都市があるというが、海洋を航行する船ではたどりつけないようだ。","note":"大帝国への道","exp":"120"}],"5218":[{"type":"歴史遺物","name":"カトパフォスのネクロポリス","rank":"1","desc":"アテネのパルテノン神殿と同じ建築様式で造られている地下墓地。王家の墓と呼ばれている。近年では住居として住み着く者が現れているようだ。","note":"パフォス郊外　再調査報酬","exp":""}],"5813":[{"type":"地理","name":"ボスジラ","rank":"2","desc":"ウスチュルト台地に存在する奇妙な形をした岩山。「白い谷」という意味。石灰に守られた白い層と、そうでない層とが存在する。","note":"","exp":"300"}],"5056":[{"type":"港・集落","name":"ゴア","rank":"1","desc":"インド西岸にある街。交易で栄えており、高価な香料や染料、宝石が産物として扱われている。また、鉄鉱石が豊富に産出する。","note":"到達する","exp":"175"}],"5907":[{"type":"宗教建築","name":"骸骨礼拝堂","rank":"5","desc":"大聖堂に併設された納骨堂。周辺の修道会墓地から集められた何千柱もの骸骨が、内装として用いられている。","note":"","exp":"1480"}],"4859":[{"type":"天文","name":"アルファルド","rank":"2","desc":"うみへび座の中で最も明るい星。アラビア語て゜「孤独なるもの」を意味する。うみへび座の心臓にあたる位置にあるため、ヘビの心臓という意味の「コル・ヒドラエ」という名で呼ばれることもある。","note":"「明るい星の観測記録」<br/>発見物カード:225","exp":"250"}],"5591":[{"type":"鳥類","name":"カタカケフウチョウ","rank":"4","desc":"ニューギニア周辺に生息するフウチョウの一種。オスの羽の色は黒く、胸や背中などに青みがかった飾り羽がある。メスへの求愛時には、それらの羽を広げて左右に飛び跳ねる。","note":"","exp":"800"}],"1044":[{"type":"化石","name":"巨大なサメの骨","rank":"2","desc":"10mを軽く超える、大型のサメの骨格。歯ははっきりと残っているが、それ以外は痕跡程度である。サメは骨が柔らかいからだろう。それはともかく、こんな巨大なサメの骨がなぜ陸地で発見されたのだろう？","note":"陸にあってはいけないもの","exp":"230"}],"1248":[{"type":"鳥類","name":"コウカンチョウ","rank":"2","desc":"頭部は赤、胸は白、背中は灰色の羽毛に覆われた鳥。地上に降りて植物の種子などをついばむ。水辺近くの開けた林に生息する。","note":"二つの美を持つ鳥","exp":"270"}],"5609":[{"type":"地理","name":"エリー湖","rank":"2","desc":"北米大陸北東部に位置する湖のひとつ。面積は広いが、水深は20m未満と浅い。下流は川を経て巨大な滝へと繋がっている。","note":"","exp":""}],"6438":[{"type":"歴史遺物","name":"関将軍の算盤","rank":"5","desc":"古代中国の算盤（スアンバン）。三國志で有名な武将・関羽が発明したという伝説があるが、それ以前の古代から仕様されていたという。串に珠を通した形式の算盤は後代の発明とされ、珠は楕円形で天（上段）に2珠、地（下段）に5珠ある。","note":"レガシー　数の叡智・世界の計算系　右下","exp":""}],"6352":[{"type":"歴史遺物","name":"太陽神が刻まれたコイン","rank":"2","desc":"古代ロードス島で製造されたコイン。島のシンボルである薔薇とともに厚い信仰をうける太陽神ヘリオスが刻まれたコインが数多く製造されたといわれる。","note":"","exp":"300"}],"6410":[{"type":"気象・現象","name":"アーチ雲","rank":"2","desc":"雲がアーチ状になっている現象。積乱雲から吹き出した冷たい空気と温かい空気が衝突した部分にできる。アーチ雲が発生した場合、強い突風や雷雨が発生することが多い。","note":"","exp":"320"}],"6952":[{"type":"鳥類","name":"フラミンゴの幼鳥","rank":"5","desc":"桃色ではなく、白い姿をしたフラミンゴの幼鳥。フラミンゴミルクと呼ばれる親から与えられる餌や、赤い色素を持つ甲殻類などを食べることで、徐々に鮮やかな色合いに変化していく。","note":"","exp":""}],"3193":[{"type":"地理","name":"グランドバンクス","rank":"4","desc":"テラ・ノヴァの南東沖に広がる、海底の台地群。寒流のラブラドル海流と暖流のメキシコ湾流がぶつかって潮目を形成しているため、好漁場として名高い。","note":"好漁場の噂","exp":"640"}],"6512":[{"type":"史跡","name":"ラニ・キ・ヴァヴ","rank":"2","desc":"インド北西部にある、巨大な階段状の井戸。「王妃の階段井戸」を意味する。11世紀ごろ亡き王を偲んだ王妃によって建てられたが、近くの河川の氾濫により埋もれていた。深さは七階層に及び、美しい彫刻が柱や壁を飾っている。","note":"","exp":"350"}],"6662":[{"type":"歴史遺物","name":"ペッパーレック","rank":"2","desc":"ポルトガルの交易船。インド産のコショウを積んでいた。インド航路開拓後、多くの交易商が香辛料を求めインドへ出航したという。ペッパーレックもその1隻だったのだろう。17世紀初頭、リスボン付近を流れるテージョ川の河口で難破。","note":"リスボン南西沖","exp":""}],"3414":[{"type":"地理","name":"エーレ海峡","rank":"1","desc":"コペンハーゲンのあるシェラン島とスカンジナビア半島の間の海峡で、最も狭いところでは幅が7kmほど。北海とバルト海を結ぶ交易の要衝である。","note":"北方の要衝","exp":"110"}],"5100":[{"type":"港・集落","name":"トルヒーヨ","rank":"2","desc":"カリブ海ホンジュラス湾に面した街で、クリストバル・コロンが4度目の航海で発見。「ホンジュラス」はスペイン語で「深み」を意味し、コロン提督が上陸の際、碇を下ろしたが海底まで届かなかったことに由来する。","note":"到達する","exp":"243"}],"2678":[{"type":"財宝","name":"高麗輿地志図書","rank":"2","desc":"読みは「こまよちしずしょ」。中国から訪れた使臣が、開城を訪れた際にまとめた書物とされる。\n記述では、その使臣は高麗の安和寺という寺院に立ち寄ったとのことだ。","note":"高麗の記録","exp":"270"}],"140":[{"type":"中型生物","name":"グリーンドラゴン","rank":"1","desc":"熱帯地方に生息する、大きな緑色の爬虫類。ドラゴンの幼生だという者もいるが、証明するには長い間育てなければならないだろう。恐ろしげな外見と裏腹に、草食性である。","note":"グリーンドラゴン","exp":"150"}],"3918":[{"type":"天文","name":"こぎつね座","rank":"4","desc":"夏の大三角の中央に位置する星座。17世紀にポーランドの天文学者ヘヴェリウスが設定した。明るい星がないため、目立たない星座である。","note":"クエスト「ポーランドで作られた星座」<br/>発見物カード:345","exp":"690"}],"5904":[{"type":"宗教遺物","name":"鉄王冠","rank":"5","desc":"イエスを十字架に打ち付けた釘を、再加工して取り付けた王冠。そのため鉄王冠と呼ばれ聖遺物とされている。","note":"","exp":"1410"}],"3646":[{"type":"大型生物","name":"蒙古牛","rank":"4","desc":"中央ユーラシアに生息するウシの一種。遊牧民に飼われ、放牧されていることが多い。体が小ぶりで、寒さに強いのが特徴。","note":"草原地帯での暮らし","exp":"800"}],"6836":[{"type":"美術品","name":"オレイテュイアを略奪するボレアス","rank":"5","desc":"ギリシャ神話の一幕を題材とし、17世紀初頭に描かれた油彩画。フランドル派の画家ルーベンスの作。古代ローマの詩人オウィディウスの『変身物語』を取材した内容で、ほぼ正方形の画板に描かれた構図は創意的で、迫力にあふれる。","note":"発見物カード:470","exp":"940"}],"5602":[{"type":"港・集落","name":"ボストン","rank":"2","desc":"北米大陸の北東部に位置する港街。\nイングランドのピューリタンが入植し、築いた街が起こりとなっている。","note":"カリブ海の入港許可があれば、上陸(発見)できます。","exp":"244"}],"3639":[{"type":"財宝","name":"カリブの景色","rank":"2","desc":"バハマ近辺で見られる淡い青色の石。まるでカリブ海を見ているような美しい青色は、見る者の心を安らげてくれる。","note":"カリブの鉱石の地図<br/><br/>発見時経験値380　発見物カード経験値190","exp":"380"}],"37":[{"type":"美術品","name":"アルノルフィニ夫妻の結婚","rank":"1","desc":"ヤン・ファン・エイク作。銀行家夫妻の結婚証明画と思われる。絵には宗教的な象徴が多く描かれ、幸せな結婚生活を祈念したものであろう。中央の凸面鏡やシャンデリアをはじめ、筆では不可能なほど細かく描き込まれている。","note":"ある夫妻の結婚証明","exp":"180"}],"421":[{"type":"小型生物","name":"巨大ヒキガエル","rank":"1","desc":"大型のカエル。体にイボのような突起が多くある。危険を感じると耳の後ろから白い毒液を出し、これが肌につくと痛がゆい。","note":"気味の悪い動物の地図","exp":"10"}],"5175":[{"type":"港・集落","name":"リューベック","rank":"1","desc":"かつて、ハンザ同盟の中心都市として、「ハンザの女王」と呼ばれた街。非常に繁栄していたが、近年はアムステルダムなどに押されて、かつての勢いはない。鉱山資源が豊富にあるほか、塩が特産である。","note":"到達する","exp":"33"}],"2318":[{"type":"地理","name":"漢拏山","rank":"2","desc":"済州島のほぼ中央に位置する火山。山の頂上には様々な伝説が残る湖もあるそうだ。\n記録によると、高麗時代に噴火があったようだ。","note":"［勅命］[[災害の事前観測","exp":"380"}],"2913":[{"type":"歴史遺物","name":"九十六文字の石版","rank":"3","desc":"びっしりと図形らしきものが彫られた石版。規則性があることから文字である可能性が高い。もしかしたらパレンケ王朝史が刻まれているのかもしれない。","note":"ダンジョン","exp":"470"}],"7023":[{"type":"植物","name":"ツチアケビ","rank":"5","desc":"日本の森林に分布する腐生植物。草丈は1m近くに及ぶこともある。全体は黄褐色で花は黄色。秋になると実が赤く熟し、茎も赤く変化する。乾燥させた果実は、民間薬として用いられる。","note":"","exp":""}],"2880":[{"type":"大型生物","name":"シフゾウ","rank":"5","desc":"中国北部から中央部にかけて生息している動物。ヒヅメはウシに、頭はウマに、角はシカに、体はロバに似ている。しかし、そのいずれとも異なるため「四不像」と呼ばれる。","note":"シカとウシとウマとロバ","exp":"1030"}],"5788":[{"type":"宗教建築","name":"スワヤンブナート","rank":"5","desc":"ネパール地方の仏教において重要な寺院のひとつ。寺院の中央には壮麗な仏塔がそびえ立つ。仏塔の壁面には、四方に「仏陀の目」が描かれ、森羅万象を見通すとされている。","note":"","exp":"1550"}],"6167":[{"type":"宗教遺物","name":"レゲンダ・アウレア","rank":"2","desc":"13世紀のジェノヴァ大司教であったドミニコ会士、ヤコブス・デ・ウォラギネによって記された聖人伝。「黄金伝説」とも呼ばれる。聖人たちの伝承のほかに主要な祭日についての記述もあり、分量としては旧・新約聖書にも匹敵するという。","note":"","exp":"320"}],"6770":[{"type":"中型生物","name":"プンサンゲ","rank":"4","desc":"豊山犬。朝鮮固有の犬種で読み方は「プンサンゲ」。古くから猟犬として使われた。自身より大きな相手にも怯まないという。力が強く、一度咬みつくと放さないことで有名。","note":"発見物カード：340","exp":"680"}],"1107":[{"type":"小型生物","name":"インドオオリス","rank":"3","desc":"体長よりも長い巨大なふさふさした尾が特徴で、機敏な動きで枝の間を跳び回る。果実や木の実、昆虫などが主食。後肢で木につかまり、尾でバランスをとりながら、前かがみになって食事をする。","note":"体よりも長い尾","exp":"451"}],"6988":[{"type":"鳥類","name":"繁殖期のトキ","rank":"2","desc":"東アジアに生息し、白い体と淡紅色の翼を持つトキは、繁殖期に頭から翼にかけて灰黒色に変わる。黒くなった首付近の分泌物を自ら塗りつけるためで、この体色は抱卵中に保護色となると考えられている。","note":"","exp":""}],"281":[{"type":"史跡","name":"カルタゴ遺跡","rank":"1","desc":"古代フェニキア人が造った都市国家の跡。第三次ポエニ戦争でローマに滅ぼされたといわれる。カエサルによって再建されたが、7世紀末に廃墟となった。","note":"ポエニ戦争の爪跡","exp":"110"}],"219":[{"type":"宗教遺物","name":"アンマ像","rank":"1","desc":"サハラの南に住むドゴン人の唯一神の像。アンマは星を作り、太陽と月を作った。さらに大地を作って自ら交わり、精霊を作ったといわれる。","note":"ドゴンの神話","exp":"180"}],"1149":[{"type":"地理","name":"メキシコ湾","rank":"2","desc":"フロリダ半島とユカタン半島の西奥に存在する湾。温かい海流で、ハリケーンといわれる嵐がよく発生する。","note":"新大陸東岸の調査","exp":"280"}],"6408":[{"type":"歴史遺物","name":"ペルシャのスフィンクス","rank":"5","desc":"古代ペルシャのスフィンクス像。人の顔、鷲の翼、獅子の体を持つという。エジプトのものとは異なり有翼である。ハリカルナッソスにもこのスフィンクス像がおかれていたのだろうか。","note":"","exp":""}],"809":[{"type":"大型生物","name":"トナカイ","rank":"1","desc":"寒冷地に生息する大型のシカ。オスは非常に大きな角を持つ。家畜として飼われているものもいる。","note":"大型のシカの地図","exp":"25"}],"939":[{"type":"虫類","name":"キベリタテハ","rank":"1","desc":"羽の周りを縁取る鮮やかな黄色と、その横に並んだ青がとても美しいチョウ。その美しさから、ある地方では美女と呼ばれるほどである。","note":"美女の舞い","exp":"155"}],"5804":[{"type":"海洋生物","name":"センジュエビ","rank":"3","desc":"深海に生息する小型のエビ。すべての脚にハサミがついており、一見するとすべての脚が手に見えることが名前の由来だと思われる。","note":"釣り発見物<br/>エディンバラの北","exp":"600"}],"2490":[{"type":"美術品","name":"雪舟の風景画","rank":"2","desc":"室町時代の禅僧・雪舟が描いた水墨画。\n見事な景観が、力強く自由な筆致で、開放感たっぷりに表現されている。","note":"風景画の地図","exp":"250"}],"1304":[{"type":"鳥類","name":"オオサイチョウ","rank":"4","desc":"非常に巨大な体躯をもつ鳥。羽音も大きく、他の動物の鳴き声をかき消すほどである。繁殖期になるとメスは巣穴にこもり、オスがメスとヒナの食料を単独で調達する。その過酷さは想像を絶し、まれに餓死するオスもいるようだ。","note":"轟音の主","exp":"720"}],"367":[{"type":"植物","name":"ロサ・フェティダ・ペルシアーナ","rank":"5","desc":"ペルシャ地方原産の黄色いバラ。「ペルシャンイエロー」とも呼ばれる。\n鮮明な黄色い花びらが幾重にも折り重なっている。その小さな葉には、芳香がある。","note":"黄色を追い求めて","exp":"1111"}],"3880":[{"type":"史跡","name":"タオス・プエブロ","rank":"2","desc":"北米の先住民であるプエブロ民族が築いた集落。建物は赤褐色のレンガで造られ、複数の階を持つ。","note":"積み重ねられたレンガの家","exp":"360"}],"3926":[{"type":"天文","name":"おおぐま座の丸い星雲","rank":"1","desc":"北斗七星のひしゃくの底にあたる部分にある星雲。丸い星雲の中にふたつの丸く暗い部分があり、フクロウの顔を思わせる。","note":"「天文学者の観測記録」<br/>発見物カード:95","exp":"190"}],"541":[{"type":"歴史遺物","name":"黄金の副葬品","rank":"1","desc":"墓に故人と共に納められた黄金の副葬品。多くの場合、死後の生活のためにと、生前使っていた物や豪華な物が納められる。","note":"古代の墳墓の地図","exp":"38"}],"1317":[{"type":"地理","name":"ビリトゥン島","rank":"2","desc":"マラッカ海峡東部に位置する島。古くから良質なスズの産地として知られている。そのため島でははるか北の国からもたらされた皿や器などが見つかる。","note":"海峡に横たわる島","exp":"220"}],"812":[{"type":"大型生物","name":"アフリカスイギュウ","rank":"3","desc":"大きな体と太い角が特徴。普段は50頭ほどの群れで行動するが、その群れ同士が集まって2000匹以上の巨大な群れを作ることもある。オスは、メスや地位を得るために争ったりする。","note":"大地の躍動<br/><br/>発見時経験値467　発見物カード経験値233","exp":"467"}],"6806":[{"type":"宗教建築","name":"クトゥブ・ミナール","rank":"5","desc":"インドのデリーにあるインド最古のミナレット。デリー・スルタン王朝を建国したアイバクが、デリーをイスラム都市として整備する中で着工した。石造りで、その美しさを称えられる。","note":"発見物カード:420","exp":"840"}],"6655":[{"type":"植物","name":"フクシア","rank":"2","desc":"中南米原産の植物。花が美しく鑑賞に供される。花が下を向いて咲く姿から「貴婦人のイヤリング」とも称される。","note":"","exp":"230"}],"6707":[{"type":"天文","name":"アクベンス","rank":"4","desc":"かに座のアルファ星。\nカニの左の爪にあたる場所に位置する。名はアラビア語で「爪」を意味する。","note":"発見物カード:400","exp":"800"}],"3682":[{"type":"中型生物","name":"ワモンアザラシ","rank":"2","desc":"流氷域に広く生息する小型のアザラシ。体型は丸い。\n背中側に黒と灰色の斑紋がある。","note":"丸いアザラシの地図","exp":"340"}],"1417":[{"type":"宗教遺物","name":"モザイクの円盤","rank":"2","desc":"ターコイズでできたモザイクの円盤。非常に高度な技術を用いて作られている。アステカでは、その色味を神聖なものとして、祭礼にターコイズを用いたようだ。","note":"メソアメリカの祭器の地図","exp":"290"}],"1740":[{"type":"宗教遺物","name":"神像付き台座","rank":"1","desc":"精霊堂に安置された台座。集会の際に叩いて音を出す。ニューギニアには大小さまざまな部族があり、そのほとんどが精霊信仰のための精霊堂を部族内に持っていた。","note":"祭礼用台座の地図","exp":"160"}],"3790":[{"type":"天文","name":"ベテルギウス","rank":"2","desc":"冬の大三角を構成する1等星で、オリオン座の左上に位置する赤い星。星座図では、オリオンの右肩にあたる。「ジャウザーの手」という意味のアラビア語が名前の由来のようだが、「ジャウザー」が何者なのかも分かっていない。","note":"視認","exp":"340"}],"3922":[{"type":"天文","name":"さんかく座","rank":"3","desc":"シチリア島の守護神で農業を司る女神ケレスがゼウスに頼んでシチリアの形を天に上げた星座とされる。小さい星座で明るい星はないが周囲に明るい星がなく見分けやすい。","note":"島の星座","exp":"470"}],"1860":[{"type":"歴史遺物","name":"骨製の笛","rank":"2","desc":"家畜の骨でできた笛。インカの祭りに使われているのだろうか。家畜用のリャマ、もしくはアルパカの骨だと思われる。","note":"珍しい笛","exp":"230"}],"4814":[{"type":"歴史遺物","name":"藩鎮帳","rank":"","desc":"","note":"楽山大仏 （中層隠し部屋）","exp":""}],"5567":[{"type":"地理","name":"ナヴァイオ海岸","rank":"1","desc":"ギリシャ地方のザキントス島にある入江。石灰岩の絶壁に囲まれた、透き通る青い海と白い砂浜が、箱庭のように美しい。","note":"","exp":"200"}],"3755":[{"type":"天文","name":"オリオン座","rank":"1","desc":"ヨーロッパでは冬の南の空に見られる星座。ギリシャ神話に登場する狩人オリオンが、サソリに刺されて死んだあとに天に昇った姿とされる。2つの1等星やオリオンのベルトと呼ばれる三ツ星があり、見つけやすい。","note":"クエスト「南の空の巨人」<br/>発見物カード:55","exp":"110"}],"5288":[{"type":"虫類","name":"サバクトビバッタ","rank":"2","desc":"サハラ周辺に生息するバッタ。風に乗って長距離を移動でき、ヨーロッパやインドに到達することもある。大発生すると、農作物に壊滅的な打撃を与えることがあるため、農民に恐れられている。","note":"","exp":"280"}],"1289":[{"type":"宗教遺物","name":"プラジューナーパーラミタ像","rank":"2","desc":"ジャヤヴァルマン7世の妃がモデルの像。頭部にアミターバ（阿弥陀如来）の化仏（けぶつ）が見られることから、仏像であることがうかがえる。","note":"英雄の妃","exp":"330"}],"6928":[{"type":"宗教遺物","name":"関聖帝君の像","rank":"5","desc":"中国の神像。三国時代の武将・関羽が「三国志演義」や民間伝承などにより神格化し、像が祀られるようになった。武運と財運の神として中国のみならず、東アジアで広く信仰を集め、多くの関帝廟が建てられたという。。","note":"発見物カード:610","exp":"1220"}],"3778":[{"type":"天文","name":"カシオペヤ座","rank":"2","desc":"北極星を見つける際の目印となる星座。高慢なエチオピア王妃カッシオペイアが天に昇った姿とされる。自らの美しさを自慢してポセイドンの怒りを買ったため、地に下りて休むことを許されないという。","note":"クエスト「エチオピア王妃の星座」<br/>発見物カード:185","exp":"370"}],"2960":[{"type":"海洋生物","name":"オオウミガラス","rank":"4","desc":"空を飛べない海鳥の一種。\n「ペンギン」と呼ばれるようになった、最初の生物であるともいわれているが、我々の知るペンギンとは生態が異なるようだ。","note":"北のペンギン","exp":"630"}],"3909":[{"type":"天文","name":"へびつかい座の新星","rank":"5","desc":"1604年にへびつかい座に現れた新星。最盛期には金星を除くどの星よりも明るくなった。ドイツの天文学者ヨハネス・ケプラーがくわしく研究したため、ケプラーの星と呼ばれることもある。","note":"発見物カード:470<br/>","exp":"940"}],"1636":[{"type":"地理","name":"フィジー諸島","rank":"2","desc":"バヌアツの東に位置する諸島。大小合わせて300を超える島々で構成されているが、最大の島は、南西に位置するヴィティレブ島である。ヨーロッパ人としては初めて、ネーデルラントのアベル・タスマンがフィジー諸島の北部を発見した。","note":"クエスtp「第二補給港候補地の選定」<br/>発見物カード:170","exp":"340"}],"5749":[{"type":"植物","name":"ワタゲトウヒレン","rank":"1","desc":"高山に生息するトウヒレンの一種。葉から生えた白い毛が、植物の大部分を覆っている。毛に覆われた内部の空間は、外より高温になっていて、寒い高山で植物の成長を助けているとされる。","note":"2017.02.07新規追加","exp":""}],"1986":[{"type":"海洋生物","name":"ストライパー","rank":"1","desc":"体に縞模様を持つスズキの一種で、淡水・汽水・海水に生息する。","note":"釣り","exp":"150"}],"2987":[{"type":"地理","name":"コッド岬","rank":"1","desc":"北米北部にある半島。全体が腕のような形をしており、夏は涼しく冬は暖かい。魚のタラがよく捕れることからケープ（岬）、コッド（タラ）と呼ばれるようになった。","note":"書きかけの地図","exp":"180"}],"26":[{"type":"宗教遺物","name":"ニャメ像","rank":"1","desc":"西アフリカで信仰されている至高神の像。広い範囲で信仰されているため、別名が多い。ニャメは最初地上で暮らしていたが、人間を疎んじて天空に上ったという。類似の神話は数多い。","note":"アフリカの神像の地図","exp":"170"}],"6156":[{"type":"伝承","name":"サンダーバード","rank":"5","desc":"雷を操るとされる巨大な鳥。雷を自在に落とす雷の精霊として、\n北米先住民の間で広く崇拝されている。人の言葉を理解したり、\nクジラを丸ごと食べたりするなど、地域によって伝わる伝承は\n異なっているようだ。","note":"","exp":"1330"}],"5071":[{"type":"港・集落","name":"シラクサ","rank":"1","desc":"シチリア島にある街。古代ギリシャの時代、アテナイに匹敵するほど栄えた。カルタゴに組してローマに滅ぼされて以降は、支配勢力が次々と変わった。産物は食品が中心だが、珍しい薬草が採れる。","note":"到達する","exp":"17"}],"1941":[{"type":"小型生物","name":"フクロシマリス","rank":"1","desc":"体に白黒の縞模様がある有袋類。ひどい臭いの液体をまき散らすことができる。果実などを食べる。","note":"リスに似た動物の地図","exp":"140"}],"1813":[{"type":"財宝","name":"黒太子のルビー","rank":"5","desc":"300カラットを超える宝石で、ルビーではなくスピネルである。黒い甲冑を身につけ軍神のような強さを誇ったイングランドの黒太子エドワードがカスティリヤ王国の内乱を支援したとき、報酬として得たものだといわれている。","note":"イングランド王国を護る宝石","exp":"1190"}],"1165":[{"type":"史跡","name":"パレンケ","rank":"5","desc":"深い森の中にたたずむマヤの古い遺跡。中心部にある宮殿のような建物の向かいには、なにやら壁にびっしりと刻まれた神殿がある。これを解読できれば、マヤについて深く知ることができるかもしれない。","note":"星の戦争","exp":"1183"}],"3916":[{"type":"天文","name":"デネブ","rank":"1","desc":"はくちょう座で最も明るい星で、名はアラビア語の「尾」に由来する。夏の大三角の一角を構成する1等星。","note":"明るい星の観測記録<br/><br/>発見物カード:90<br/>","exp":"120"}],"3515":[{"type":"レリック","name":"ランスロット","rank":"","desc":"円卓の騎士の中で最も優れた騎士ランスロット。湖の精に育てられたという「湖の騎士」はクラブのジャックのモデルといわれる。","note":"","exp":""}],"1918":[{"type":"鳥類","name":"フウチョウ","rank":"5","desc":"ニューギニア周辺に生息する鳥。オスは美しい飾り羽を持つ。繁殖期になるとオスは一カ所に集まって踊り、メスを誘う。メスはそれを見てつがいとなるオスを選ぶ。","note":"恋愛事情<br/><br/>発見時経験値936　発見物カード経験値468","exp":"936"}],"2965":[{"type":"地理","name":"マンモス・ケーブ","rank":"3","desc":"北米大陸に位置する、石灰岩の洞窟群。その全長は500kmをゆうに超える。石灰岩の層の上にはさらに砂岩の層が重なっており、非常に頑丈な洞窟である。","note":"大洞窟調査依頼","exp":"600"}],"6083":[{"type":"伝承","name":"ヴァルプルギスの夜","rank":"5","desc":"主に中欧や北欧で行われる行事。死者と生者との境界が曖昧になるという夜に、魔女たちが集会を開き、かがり火を囲んで悪魔を崇拝するとされるが、その真偽は定かではない。","note":"","exp":"1480"}],"664":[{"type":"歴史遺物","name":"アパダーナのレリーフ","rank":"2","desc":"アパダーナとはアケメネス朝ペルシャの大宮殿・ペルセポリスの謁見の間のことである。広大な大広間には、精巧なレリーフが一面に施されている。","note":"焼き尽くされた遺跡","exp":"240"}],"5073":[{"type":"港・集落","name":"ジェノヴァ","rank":"1","desc":"古代ローマ時代に基礎が築かれ、十字軍の時代に栄えた都市。かつてヴェネツィアと激しい勢力争いを繰り広げたが、近年は下り坂である。しかし、大都市にふさわしく、高級な商品が扱われている。","note":"到達する","exp":"15"}],"5365":[{"type":"財宝","name":"アトランティスの謎","rank":"1","desc":"ジョン・トラデスカントがアトランティス調査の一環でまとめた書物。アトランティスの神話から古代エジプトやギリシャの歴史、独自の視点によるアトランティス滅亡の解釈などが理路整然とまとめられている。","note":"","exp":"100"}],"5649":[{"type":"史跡","name":"ベニ・ハンマードの城塞","rank":"4","desc":"ハンマード朝の始祖が建造したという城塞都市。すでに廃墟と化して長いが、いまだ多くの史跡が残っている。","note":"クエスト「滅びた王朝」<br/>発見物カード:315","exp":"630"}],"6885":[{"type":"地理","name":"ヘラルド島","rank":"3","desc":"チュクチ海のウランゲリ島近くにある小島。無人島であり、北風が吹きすさぶ極寒の気候が特徴。島周辺の切り立った崖と、海氷により、船での上陸は非常に難しい。","note":"発見物カード:330","exp":"660"}],"3154":[{"type":"宗教建築","name":"サント・シャペル","rank":"2","desc":"パリのシテ島に建てられた、キリスト教の礼拝堂。数々の聖遺物が納められている。壮麗なステンドグラスが窓を覆う、ゴシック建築の輝かしさを表した建築物である。","note":"パリに建てられた宝石","exp":"340"}],"2112":[{"type":"歴史遺物","name":"ソレン号","rank":"3","desc":"ダンツィヒ沖で起きたポーランド・スウェーデン間の戦闘に参加した、スウェーデン艦隊の一隻。\nポーランド艦隊旗艦に襲われ、拿捕されそうになったため、自ら船を爆破し沈没した。","note":"サルベージ","exp":"451"}],"6754":[{"type":"宗教建築","name":"アンコナ大聖堂","rank":"5","desc":"アンコナの港全体を見渡せる丘、ドゥオーモ広場に建つ大聖堂。航海を守護する女神アフロディテを祀っていたギリシャ神殿の跡地に建てられたという。アンコナの守護聖人である聖キリアクスにちなみ、聖チリアコ大聖堂とも呼ばれる。","note":"","exp":"1170"}],"3904":[{"type":"天文","name":"カシオペヤ座の新星","rank":"4","desc":"1572年にカシオペヤ座に現れた新星。詳細な記録を残したデンマークの天文学者ティコ・ブラーエの名にちなみティコの星とも呼ばれることもある。ティコはこの星が位置を変えないことから、大気中ではなく、宇宙で起きる現象であると唱えた。","note":"発見物カード:355","exp":"710"}],"3903":[{"type":"天文","name":"いっかくじゅう座のバラ状の星雲","rank":"2","desc":"いっかくじゅう座の北にあるバラのような形をした星雲。天の川の中にある。肉眼では見られない。","note":"天文学者の観測記録","exp":"330"}],"5588":[{"type":"気象・現象","name":"ダイヤモンドダスト","rank":"3","desc":"太陽などの光源により極小の氷の粒が光り輝くように見える現象。発生には天候や気温、風向きなどが密接に関係しているため観測は困難である。","note":"ロッキー地方東のテーブル岩付近で現象は発見できるも、視認できず。テーブル岩の北方で視認できる。","exp":"530"}],"5158":[{"type":"港・集落","name":"マラッカ","rank":"2","desc":"イスラム教を国教とするマレー人の国であるマラッカ王国の首都。マラッカ王国は、シュリーヴィジャヤ王国の王子・パラメスワラがマジャパヒト王国の侵攻から逃れ、この地で建国したことに端を発する。","note":"到達する","exp":"309"}],"5157":[{"type":"港・集落","name":"マラガ","rank":"1","desc":"フェニキア人によって築かれ、支配勢力が変わりながら、発展を続けてきた街。イベリアにあるほかの街と同じく、イスラムと欧州の文化が融合した街並みである。農作物のほかに、サフランや辰砂（しんしゃ）、サンゴを産する。","note":"到達する","exp":"5"}],"5125":[{"type":"港・集落","name":"ピンジャラ","rank":"2","desc":"オーストラリアの南西端にほど近い街。街の名前は付近の低湿地帯を指す先住民の言葉が訛ったものである。\n南西オーストラリアの内陸部には、埋蔵量が豊富な鉄鉱石や金の鉱山が存在するため、それらの積み出し港として注目を集めている。","note":"到達する","exp":"370"}],"3319":[{"type":"地理","name":"ルイス島","rank":"2","desc":"ブリテン島北部。西側にある島。近辺の島の中では最大の面積を誇る。南部は別の名前でも呼ばれている。島には巨大な岩や石を使った史跡が残されているという。","note":"書きかけの地図","exp":"250"}],"1241":[{"type":"鳥類","name":"ショウジョウトキ","rank":"2","desc":"全身が鮮やかな赤色の鳥。長いくちばしを水草の間に差し込み、魚やかえるなどを捕らえる。夕暮れになると、水辺の木の上に作る巣に帰る。","note":"鮮やかな赤","exp":"265"}],"5392":[{"type":"史跡","name":"ディオニソス劇場","rank":"4","desc":"古代アテナイでディオニシア祭が開かれていた劇場。ディオニシア祭は悲劇の内容を競う祭りであったため、数多くのギリシャ悲劇がこの劇場で初めて上演された。","note":"","exp":"640"}],"5472":[{"type":"小型生物","name":"パカ","rank":"1","desc":"中南米に生息している体長60～80cmの動物。体は明るい赤茶色で、両脇には薄い点線が並んでいる。\nずんぐりとした体型だが、俊敏で泳ぎがうまい。","note":"発見時経験値120　発見物カード経験値60","exp":"120"}],"6246":[{"type":"美術品","name":"受胎告知（アンジェリコ）","rank":"1","desc":"フラ・アンジェリコ作の祭壇画。鮮やかな色彩で描かれたこの絵は作者の敬虔な信仰心を如実に表している。アンジェリコの名は通称で、穏やかな修道僧であった彼を「天使のようだ」と表現したものだそうだ。","note":"清楚な絵","exp":"100"}],"7033":[{"type":"中型生物","name":"アオザル","rank":"2","desc":"アフリカの熱帯雨林に生息するサル。体長より長い尻尾と、青灰色の体毛が特徴である。本来、食性生息域が近い種の共存は難しいが、アカオザルの群れと共に暮らすことも多いという。その理由は解明されていない。","note":"","exp":""}],"6605":[{"type":"財宝","name":"ターコイズマスク","rank":"5","desc":"アステカ文明の仮面。火の神を象ったものではないかといわれているがくわしくは不明。顔の表面はターコイズで装飾され、目には真珠、歯には貝殻が使われている。","note":"","exp":"1300"}],"2096":[{"type":"中型生物","name":"ヘルマンリクガメ","rank":"1","desc":"ヨーロッパ南部に生息するリクガメ。\n乾燥した平原に生息し雑食だが、主に植物の葉や果実を食す。\n諸説あるが、イソップ寓話「ウサギとカメ」のモデルのカメといわれている。","note":"ウサギに勝つカメ","exp":"110"}],"6941":[{"type":"天文","name":"ハマル","rank":"2","desc":"おひつじ座のアルファ星。この星座の中では最も明るい2等星で、羊の頭に当たるところに位置する。名はアラビア語で「子羊」を意味する。","note":"マディラ沖 視認","exp":""}],"5449":[{"type":"植物","name":"イペー","rank":"3","desc":"直径60cm～1m程度の比較的大きな木で、中南米に分布している。強度が非常に高く、20～30年経過しても劣化しない。また、防腐性、防虫性に優れた成分も含んでおり、外装や家具の素材として広く使用される。","note":"","exp":"540"}],"534":[{"type":"歴史遺物","name":"象嵌青銅器","rank":"1","desc":"「ぞうがん」青銅器。象嵌細工を施した青銅器。貴金属や宝石と、高度な技術が必要となるためか、王族の副葬品や、裕福な貴族の調度品などとして出土する。","note":"古代の道具の地図","exp":"104"}],"5838":[{"type":"財宝","name":"メンドーザ写本","rank":"5","desc":"樹木の繊維を使って作られた絵文書。いまだ謎の多いアステカ文明について記述されている。","note":"","exp":"1410"}],"5083":[{"type":"港・集落","name":"セウタ","rank":"1","desc":"紀元前にフェニキア人によって築かれたと伝えられる街。その後イスラムの支配下にあったが、15世紀初めにポルトガルが奪った。バジルなどが作られているほか、近海でサンゴが採れる。","note":"到達する","exp":"6"}],"1637":[{"type":"地理","name":"アンダマン海","rank":"2","desc":"アンダマン諸島の東側に位置する海。透明度が高く、極彩色のサンゴや魚が数多く見られる。\n海域には数多くの島が点在し、モーケン人と呼ばれる海の民が島々を移動しながら暮らしている。","note":"クエスト「海の楽園」<br/>発見物カード:135","exp":"270"}],"2953":[{"type":"化石","name":"穴の開いたドラゴンの骨","rank":"4","desc":"新大陸北部で発見された、耳に大きな穴が開いたドラゴンの骨。穴は聴力を増すためのものだろうか。それとも別の用途で開いているのだろうか。","note":"襟付きドラゴンの調査<br/><br/>発見時経験値700　発見物カード経験値350","exp":"700"}],"89":[{"type":"宗教遺物","name":"バステト像","rank":"1","desc":"古代エジプトの、猫の姿、もしくは猫の頭部を持つ女神の像。猫はヘビを捕らえることから益獣として珍重されやがて神として崇拝されるようになった。バステトは猫の守護神であり、愛の女神でもあるという。","note":"エジプトの女神像の地図","exp":"80"}],"6555":[{"type":"地理","name":"在りし日のファロス島","rank":"5","desc":"ファロス島のかつての姿。航海の守護神ともされた女神イシスを祀る神殿がある。島の沖合にはアレクサンドリアの大灯台が建てられその巨大さを近くで体感できる。夜には灯台の最上部に巨大な炎が灯されていた。","note":"レガシー『英知の灯アレクサンドリア』真上","exp":""}],"578":[{"type":"歴史遺物","name":"チャンドラグプタ王の剣","rank":"2","desc":"グプタ朝第3代、別名「超日王」と呼ばれるチャンドラグプタ2世の剣。軍事力と政略結婚により、インドをほぼ統一した。","note":"豪華な衣装の来歴","exp":"360"}],"501":[{"type":"財宝","name":"ヒストリアイ","rank":"1","desc":"古代ギリシャの歴史家・ヘロドトスが記した史書。古代ペルシャとの戦争を中心に書かれており、ヨーロッパとアジア世界を常に対立するものと定義している。","note":"古代ギリシャの歴史書<br/><br/>発見時経験値120　発見物カード経験値60","exp":"120"}],"6051":[{"type":"美術品","name":"生神女就寝のイコン","rank":"2","desc":"正教会で伝えられているイコンの一つで、生神女マリアが亡くなった時の出来事を描いている。\nマリアの永眠を祝う習慣は東方から始まったとされ、西ヨーロッパでは「聖母被昇天」として定着した。","note":"","exp":""}],"7016":[{"type":"財宝","name":"青い点状装飾のガラス器","rank":"5","desc":"伽耶時代の古墳群から発掘された透明なガラスの器。表面には青い点状の装飾が施されている。5世紀後半頃に作られ、東西の交易を通じて新羅経由で伝来したと考えられる。","note":"","exp":"1200"}],"3189":[{"type":"地理","name":"スピア岬","rank":"2","desc":"北米北東部沿岸の、テラ・ノヴァ南東部に位置する岬。しばしば北米地域の最東端とみなされる。大西洋に臨む岬であり、季節によってはクジラが泳ぐ姿を眺められる。","note":"書きかけの地図","exp":"240"}],"520":[{"type":"歴史遺物","name":"ガラスの破片","rank":"1","desc":"古代に用いられたガラス器の破片。文明により、色や透明度、加工技術に違いがある。","note":"古代の集落の地図","exp":"9"}],"1553":[{"type":"地理","name":"フロレス海","rank":"1","desc":"セレベス島の南に広がる海。水温が高く、塩気の強い海水のため独特の海洋生物が見られる。また、この地域の小島にも変わった生物が多く、興味深い。","note":"「書きかけの地図」<br/>発見物カード:65","exp":"130"}],"5177":[{"type":"港・集落","name":"ルン","rank":"2","desc":"バンダ諸島の西部に存在するルン島の街。ナツメグの産地であり、交易の中心として注目されている。","note":"到達する","exp":"350"}],"1290":[{"type":"宗教遺物","name":"ロケシュヴァラ像","rank":"4","desc":"アンコール朝後期に作られた青銅製の仏像。ジャヤヴァルマン7世の治世後、大乗仏教は民衆の支持を失ったため、この銅像は、化仏（けぶつ）と持物（じぶつ）を削り取られてシヴァに改変されている。","note":"アンコール朝の終焉<br/><br/>発見時経験値612　発見物カード経験値306","exp":"612"}],"1561":[{"type":"財宝","name":"石斧","rank":"1","desc":"斧の頭部に石を用いた武器。古代から世界各地で見られる。ニューギニアでは金属器が使用されておらず、闘争の際は、石や骨、木で作られた武器を使用している。","note":"石斧の地図","exp":"120"}],"6721":[{"type":"財宝","name":"快雪時晴帖","rank":"2","desc":"東晋時代の書家・王羲之による作品。全文28字。彼が引退し、俗世のいざこざから離れた後、友人あての手紙として書かれた。行書体の作品において最高峰とされている。","note":"","exp":""}],"1604":[{"type":"歴史遺物","name":"アノーヤター王の剣","rank":"4","desc":"アノーヤター王はミャンマー人による最初の王朝・パガン王朝を開いた創始者である。国を興してからも他地域を制圧し領土を拡大。支配下に置いた地域から仏典を持ち帰り、おびただしいまでの寺院を建設する。","note":"偉大なる王の墓","exp":"744"}],"58":[{"type":"大型生物","name":"インドゾウ","rank":"3","desc":"インドに生息するゾウである。体重は5tにもなり、体高は3mに達する。おとなしく力が強いので、古くから飼いならされて運搬などに使役されてきた。オスには大きな牙があるがメスにはないようだ。","note":"インドのゾウ","exp":"506"}],"6333":[{"type":"海洋生物","name":"リュウグウノツカイ","rank":"5","desc":"太平洋・インド洋・大西洋などの深海に生息する魚類。正面から見ると、体に厚みがないのが分かる。神秘的な銀色の体と赤いヒレが特徴的だが、死ぬと体色が失われる。腹のヒレで食物を探す。食用にした記録もあり、美味だという。","note":"","exp":"1230"}],"223":[{"type":"化石","name":"幼いドラゴンの骨","rank":"1","desc":"見たこともない、巨大な骨。なかば石化している。この大きさは既知の生物ではないだろう。ドラゴンの骨ではないかと思われるが、ドラゴンにしては小さい。子供の骨だと推測される。","note":"ドラゴンの骨を探せ","exp":"75"}],"3848":[{"type":"歴史遺物","name":"トーテムポール","rank":"2","desc":"北米西岸の先住民の手で作られた木の彫刻。一族の歴史などに関係する動物や人が模様として刻まれ、家の柱や墓などとして立てられた。傷んでも修繕されず、朽ちて地に還されるのは、自然から生まれ自然に還るという彼らの考え方に基づく。","note":"装飾された支柱","exp":"210"}],"1329":[{"type":"地理","name":"ニューギニア島","rank":"4","desc":"ティモール島のさらに東に位置する島。大陸と見紛う程の大きさである。中央には高い山脈がそびえ、高地と低地の気温差が大きい。島内の場所によって、人々の言語と文化が異なる。","note":"クエスト「太陽の昇る場所」<br/>発見物カード:300","exp":"624"}],"6612":[{"type":"歴史遺物","name":"ジョワユーズ","rank":"5","desc":"ローランの歌で登場するシャルルマーニュが所持している聖剣。後にフランスにおいては国王の王権を象徴する剣となった。国王の戴冠式にも使われたことがある。","note":"レガシー美の叡智　右下","exp":"2650"}],"6652":[{"type":"天文","name":"こじし座","rank":"2","desc":"小さなライオンの姿を表した星座。しし座の頭と、おおぐま座の足下にはさまれた位置にある。暗い星で形成されており、あまり目立たない。ドイツの天文学者・ケプラーが設定した。","note":"「天文学者の観測記録」<br/>発見物カード:140","exp":"280"}],"5337":[{"type":"天文","name":"や座","rank":"2","desc":"ギリシャ神話の愛の神エロスがゼウスに放った黄金の矢が天に上った姿とされる。ゼウスはこの矢によってトロイの王子ガニュメデスに心を奪われた","note":"クエスト「星と愛の詩」<br/>発見物カード:175","exp":"370"}],"2840":[{"type":"美術品","name":"黄公望の水墨画","rank":"1","desc":"元代末期の画家・黄公望が描いた水墨画。\n墨の濃淡でさまざまな風景を描き表しており絵の全長は6m以上にも及ぶ。","note":"水墨画の地図","exp":"160"}],"2372":[{"type":"鳥類","name":"トキ","rank":"1","desc":"東アジアに分布している鳥。全身ほぼ白色だが、翼と尾羽の裏側はとき色と呼ばれる淡紅色を帯びている。\n威嚇をする際は、後ろ頭の羽を冠のように立てる。","note":"赤い顔の鳥の地図","exp":"130"}],"1699":[{"type":"歴史遺物","name":"ゼルバベルの粘土板","rank":"5","desc":"楔形文字で書かれた粘土板。石板ではないので長期保存用に書かれたものではないと思われる。粘土板には、ユダ王国の王族でイェルサレム神殿の再建を指揮したゼルバベル王の名前が見られる。","note":"バビロン捕囚","exp":"949"}],"5484":[{"type":"海洋生物","name":"タライロン","rank":"3","desc":"アマゾン川や、その支流で生息する魚。古代魚の風貌に似ていることから淡水の古代シーラカンスと呼ばれている。","note":"アマゾン川上流から南西の支流奥。釣りR10+1で発見。<br/>経験:480 カード:240","exp":"480"}],"2873":[{"type":"宗教遺物","name":"太平青領書","rank":"2","desc":"道教の経典の一つ。張角が得たことから、彼が起こした太平道の経典となった。\n別名、太平経。","note":"宗教書の地図","exp":"300"}],"2452":[{"type":"鳥類","name":"ヤマドリ","rank":"4","desc":"日本の本州以南の山林に生息する鳥。雄は、翼で胸を叩いて音を出す。\nその長い尾羽は、物事の長いことの例えとして、文学作品などの中で用いられてきた。","note":"話題を呼ぶ羽飾り","exp":"610"}],"5161":[{"type":"港・集落","name":"メリダ","rank":"2","desc":"熱帯雨林に覆われたユカタン半島の北西端に位置する街。その昔マヤ文明が栄えていたという。","note":"到達する","exp":"252"}],"3190":[{"type":"地理","name":"ラブラドル海流","rank":"5","desc":"グリーンランド南西岸から北米大陸北東岸に沿って南下する寒流。濃霧が発生しやすく、気温が上がる春先はグリーンランド方面から氷山が流れてくるためこの海域の航行には危険が伴う。","note":"霧と氷が漂う海","exp":"920"}],"5448":[{"type":"財宝","name":"アトランティスの真実","rank":"3","desc":"ジョン・トラデスカントが中心となってまとめた、アトランティス調査に関する書物。解読不能の古代文字で書かれた石版を解読し、得た情報などが記載されており、学術価値は高い。","note":"","exp":""}],"5258":[{"type":"海洋生物","name":"ウミヒゴイ","rank":"3","desc":"体長50cmに達することもある魚で、鮮やかな体色が特徴。死んだり驚いたりすると体色が変化し、それゆえに古代ローマ人に珍重されていた。ヒメジの仲間で、身は白身で美味。","note":"","exp":"600"}],"5368":[{"type":"宗教遺物","name":"セラピス像","rank":"4","desc":"セラピスはギリシャ神とエジプト神を習合した神。プトレマイオス朝エジプトやローマ帝国で広く信仰された。頭には計量用のカップを乗せている。","note":"ギリシャとエジプトの神","exp":"660"}],"902":[{"type":"宗教遺物","name":"シヴァ像","rank":"4","desc":"インド神話のシヴァ神の像。破壊と再生、踊りをつかさどる神で、三大神の一人である。ほかにも多くの妻を持ち、シヴァにまつわる神話は豊富にある。","note":"破壊神の像","exp":"624"}],"1905":[{"type":"歴史遺物","name":"金角湾の鎖","rank":"1","desc":"ビザンツ帝国がコンスタンティノープル攻防戦において、オスマン軍船の進入を拒むために張った太い鎖。オスマン軍はこれを破ることはできず、軍船を陸路で運ぶという奇襲を持ってビザンツ帝国に大打撃を与えた。","note":"海を塞いだ鎖","exp":"200"}],"2793":[{"type":"財宝","name":"唐三彩","rank":"3","desc":"唐代に焼成された色彩豊かな陶器。\n主に、貴族の副葬品として使われていた。\n人形や家財などをかたどったものが多く作られている。","note":"三彩の伝来","exp":"510"}],"3169":[{"type":"財宝","name":"ヘルメス文書","rank":"2","desc":"コジモが入手し、マルシリオ・フィチーノがラテン語に翻訳した書物。東ローマ帝国で編集されたが、元々はエジプトで作成された哲学書のようだ。","note":"東ローマの書物の地図","exp":"230"}],"4968":[{"type":"天文","name":"アルナイル","rank":"2","desc":"つる座で最も明るい星で、名はアラビア語で「尾の光り輝くもの」という意味を持つ。かつてはみなみのうお座の一部だった。","note":"「天文学者の観測記録」<br/>発見物カード:220","exp":"240"}],"1808":[{"type":"美術品","name":"キリストの洗礼","rank":"1","desc":"ダ・ヴィンチの師であるアンドレア・デル・ヴェロッキオの手による絵画。だが、この絵で背景と一番左下の天使はダ・ヴィンチが描いたとされる。師ヴェロッキオは、その天使のあまりの美しさに驚愕し、以後絵画は描かなくなったという。","note":"師弟の絵","exp":"100"}],"1538":[{"type":"歴史遺物","name":"浮き彫り装飾鉢","rank":"1","desc":"レリーフが彫られた広口の鉢。土器でできている。この絵にはなにか物語があるのだろうか。","note":"メソアメリカの鉢の地図","exp":"110"}],"4805":[{"type":"地理","name":"アリューシャン列島","rank":"2","desc":"北米大陸のアラスカ半島からカムチャッカ半島に延びる列島。ベーリング海と太平洋の境となっている。","note":"","exp":"290"}],"4953":[{"type":"財宝","name":"レフカラレース","rank":"2","desc":"キプロス島のレフカラ村で作られた、麻布のレース。レフカラの文化とヴェネツィアの技術が融合して、素朴でありながら上品なデザインとなっている。","note":"おしゃれなテーブルクロス<br/><br/>発見時経験値370　発見物カード経験値185","exp":"370"}],"1777":[{"type":"宗教遺物","name":"神官の首飾り","rank":"2","desc":"神官のみが着けることを許されるという首飾り。細工が細かく、美術的価値も高いが、信仰的要素が大きい。","note":"［勅命］[[黄金郷の信仰","exp":"310"}],"6128":[{"type":"宗教遺物","name":"天国への階梯","rank":"5","desc":"7世紀の東ローマの修道士ヨアンネス・クリマコスが著した、修道士向けの教導書。「クリマコス」はギリシャ語ではしごを意味し、書名の「階梯」に由来した添え名。修道者としての心構えを三十段の階梯に見立てて説いている。","note":"","exp":"1100"}],"6386":[{"type":"伝承","name":"ペリの羽衣","rank":"","desc":"ペルシャに伝わる精霊ペリが持つとされている羽衣。この羽衣をまとうと鳩の姿になれるといい、ペリが下界で水浴びを楽しんでいたところ、人間の男に羽衣を奪われ、強引に妻にされてしまった伝承がある。","note":"","exp":"1150"}],"1794":[{"type":"地理","name":"ボスポラス海峡","rank":"3","desc":"ヨーロッパとアナトリア半島の間にある二つのうち、北側の海峡。コンスタンティノープルの攻防では、流れの速い海峡部から砲撃をするために、金角湾を巡る激戦が繰り広げられた。トルコ軍は両岸に二つの城砦を建設し攻略の糸口とした。","note":"栄枯盛衰の狭き海","exp":"490"}],"806":[{"type":"歴史遺物","name":"アレクサンドロス大王の剣","rank":"4","desc":"マケドニアの王にして地中海からペルシャまでの巨大な版図を築いた、アレクサンドロス大王の剣。東西の技巧を凝らした、まさに王者の剣である。","note":"大王の逸話","exp":"720"}],"6289":[{"type":"大型生物","name":"インドサイ","rank":"4","desc":"インド東北部の草原に生息しているサイ。\n頭部には一本の角があり。体皮は鎧のように堅固でひだ状に折れ曲がっている。\n角に薬効があると信じられ、よく狩られているが、その巨体に体当たりされて死ぬ人も多いようだ。","note":"","exp":"620"}],"3849":[{"type":"大型生物","name":"シロアメリカグマ","rank":"5","desc":"成人男性ほどの背丈を持つクマ。北米に広く生息する黒い体毛のクマの亜種にあたる、白い個体を指す。一部の先住民からは、「精霊のクマ」と呼ばれている。","note":"精霊のクマ<br/><br/>発見時経験値1100　発見物カード経験値550","exp":"1100"}],"1516":[{"type":"宗教遺物","name":"阿弥陀如来","rank":"4","desc":"あみだにょらい。仏教における、如来のひとり。名前にはサンスクリット語で「無量光」「無量寿」という意味があり、世界中を妙なる光で包むといわれている。","note":"阿弥陀如来像","exp":"624"}],"5344":[{"type":"地理","name":"デ・ノローニャ諸島","rank":"2","desc":"サンロケ岬沖に浮かぶ島々で、20の火山島からなる。\n美しい自然に恵まれている。","note":"","exp":"350"}],"3634":[{"type":"宗教遺物","name":"ペルーンの木像","rank":"4","desc":"ペルーンは、スラブ神話の主神。名前は「打つ（者）」という意味の古いスラブ語に由来し、雷や嵐を司る神とされている。対立する神を、稲妻の矢で射て退けた神話から、戦勝をもたらす神として戦士たちに崇拝された。","note":"スラブ神話の考察","exp":"720"}],"6257":[{"type":"財宝","name":"聖ブレンダンの航海","rank":"2","desc":"正式名は「大修道院長聖ブレンダンの航海」という。クロンファートのブレンダンという修道士が七年の歳月をかけてアイルランドから西方にある「約束の地」へ渡航するまでを描いており、数百年間にわたってヨーロッパ諸国で広く読まれた。","note":"","exp":"310"}],"3697":[{"type":"地理","name":"ブルーマウンテン山脈","rank":"2","desc":"ジャマイカ東部に存在する山脈。標高が2000メートル以上あるとされ、遠目では山脈全体が青っぽく見える。","note":"書きかけの地図","exp":"370"}],"6475":[{"type":"歴史遺物","name":"ロードスの商船","rank":"5","desc":"ロードスの港に出入りした商船。軍船とは違い、櫂や漕ぎ手は配置せず、より多くの荷を積めるようになっている。ギリシャとエジプトの中ほどに位置するロードス島は古来より東地中海の貿易路の要所だった。","note":"レガシー・港湾都市ロードス　下","exp":"2475"}],"5752":[{"type":"海洋生物","name":"ストーンスコーピオンフィッシュ","rank":"4","desc":"太平洋の東部に生息するカサゴの一種。毒を持つトゲが背ビレにあるが、体色が岩礁に酷似しているため、誤って手などを刺される者も多い。","note":"","exp":"720"}],"946":[{"type":"海洋生物","name":"アンコウ","rank":"1","desc":"かなり深い海に住む、大型の魚。平べったく巨大な口を持ち、頭から生えている枝のような突起でエサをおびきよせるらしい。","note":"不気味な魚の地図","exp":"97"}],"5885":[{"type":"地理","name":"クヴァルケン群島","rank":"1","desc":"バルト海に位置する群島。かつて存在した氷河が融解することで地形が変化し、複雑に隆起している。","note":"","exp":"130"}],"805":[{"type":"植物","name":"ボダイジュ","rank":"1","desc":"大きく育つ落葉樹。各地で見かけるが、地方によって微妙に異なるようにみえる。西洋ではハーブとして葉を使うこともある。インドでは、仏陀がこの木の下で悟りを開いたと伝えられているそうだ。","note":"大きな木の地図","exp":"13"}],"1677":[{"type":"鳥類","name":"スミレコンゴウインコ","rank":"5","desc":"全身を覆う濃い青色の羽毛、目の周りとくちばしの付け根の黄色い皮膚の配色が美しい。熱帯林の周縁部やヤシ林に生息し、ヤシの実を主食とする。","note":"約束した空の色","exp":"828"}],"3870":[{"type":"中型生物","name":"ゼニガタアザラシ","rank":"1","desc":"太平洋、大西洋の北部に生息するアザラシ。体表に、中央がくり貫かれた円のような模様を持つ。岩場や岩礁で生活する。","note":"沿岸のアザラシの地図","exp":"200"}],"3906":[{"type":"レリック","name":"サンジェルマン伯爵","rank":"","desc":"豊富な知識と錬金術で知られたサンジェルマン伯爵。彼は本当に不死で、研究を続けているのだろうか。","note":"","exp":""}],"2346":[{"type":"宗教遺物","name":"岩戸の注連縄","rank":"3","desc":"読みは「いわとのしめなわ」。注連縄とは、わら製の縄に紙垂を付けたもの。魔除けや神が降りる場である拠り代として使われる。\n日本神話では天照大神が岩戸から引き出された際、二度と中へ入らぬよう注連縄で岩戸の入口を塞いだという。","note":"不思議な場所の調査","exp":"460"}],"5820":[{"type":"地理","name":"ブラマプトラ川","rank":"1","desc":"ヒマララ山脈の周辺を流れる川。ブラフマーの息子（プトラ）と呼ばれ、ガンジス川との合流地点で巨大な三角州を形成する。","note":"","exp":"190"}],"2589":[{"type":"美術品","name":"合戦絵巻","rank":"2","desc":"ある武家の来歴がまとめられた、日本の絵巻物。合戦の描写が主軸となっている。\n鮮やかな色彩で描き出された光景は、武士の活躍を目の当たりにさせると共に、戦の凄惨さをも物語っている。","note":"軍記物語にまつわる絵","exp":"370"}],"5154":[{"type":"港・集落","name":"マディラ","rank":"1","desc":"イベリア半島から南西の島にある街。近年発見され、農業を中心に発展を始めている。緯度が低くて高温多湿なので、サトウキビが栽培されている。また、ワインの製造にも向いた気候である。","note":"到達する","exp":"24"}],"1349":[{"type":"小型生物","name":"トビトカゲ","rank":"2","desc":"腹部の両脇に張られた皮膜で、木から木へ滑空するトカゲ。皮膜は骨で支えられている。","note":"空飛ぶトカゲ<br/><br/>発見時経験値220　発見物カード経験値110","exp":"220"}],"5570":[{"type":"財宝","name":"チャフチャス","rank":"2","desc":"アンデス地方の伝統的な楽器。マイチルという植物の実や、リャマの爪などが複数付いている。手や足首に装着し、振って音を出す。","note":"リマ北の地図　財宝鑑定・開錠・探索","exp":"280"}],"3420":[{"type":"財宝","name":"ガリレイのリュート","rank":"4","desc":"ガリレオの父、ヴィンチェンツォはリュート奏者として、彼独特の音楽理論を展開させていたという。不協和音すら操るという、彼のリュートはごく普通の物にも見えるが…。","note":"父のリュート","exp":"630"}],"1454":[{"type":"財宝","name":"モクテスマ2世の杖","rank":"2","desc":"アステカ皇帝・モクテスマ2世のものといわれている杖。彼は変革や支配強化を進めるなど、アステカの新たな道を模索する一方、イスパニア人コルテスをケツアルコアトルの再来と信じている。","note":"アステカの皇帝<br/><br/>発見時経験値230　発見物カード経験値115","exp":"230"}],"5117":[{"type":"港・集落","name":"パタニ","rank":"2","desc":"イスラム教を国教とするマレー人の国であるパタニ王国の首都。\nマレー王朝の中でもいち早くイスラム化を果たした。","note":"到達する","exp":"328"}],"3801":[{"type":"大型生物","name":"ヒガシグリーンランドカリブー","rank":"3","desc":"グリーンランドの東部に生息するトナカイの一種。小規模の群れで移動しつつ、苔などを食べて暮らしている。","note":"島にすむカリブーの地図","exp":"530"}],"408":[{"type":"史跡","name":"カッパドキア","rank":"2","desc":"長い間、風雨にさらされた奇岩がそびえたつ地域。かつて迫害を避けた人々が岩をくりぬいて作った街が残っている。","note":"奇岩の宗教都市","exp":"350"}],"6405":[{"type":"史跡","name":"円形劇場","rank":"5","desc":"古代ギリシャ風の野外劇場。ハリカルナッソスの背後の丘を掘り込む形で建造された。マウソロス王の時代に建てられたと伝わる。客席最前列の中央には、ギリシャの神ディオニソスの祭壇が置かれている。","note":"","exp":""}],"6835":[{"type":"鳥類","name":"ゴイサギ","rank":"4","desc":"世界各地に生息しており、湿地や河川、湖などの水辺で見ることができる。顔から腹が白く、頭から背中は灰色が買った紺色。夜行性で魚や虫などを食べ、昼は樹上などから動かない。成鳥には、後頭部に白く長い冠羽が生えている。","note":"発見物カード:400","exp":"800"}],"509":[{"type":"歴史遺物","name":"古代の荷車","rank":"2","desc":"一度に大量の荷物を運ぶためのもの。車輪が発明された文明で使われる。車輪がない文明では、コロが使われていたようだ。","note":"古代の荷車の地図","exp":"230"}],"7009":[{"type":"地理","name":"ペインテッド・ヒルズ","rank":"5","desc":"北米大陸の西部に位置する丘陵。斜面には赤や橙、黒などの色の異なる地層が幾重にも重なり、縞模様となって浮かぶ。この周辺にはさまざまな動植物の化石が眠っているという。","note":"※経験値は推定値です。修正ヨロ。","exp":"2155"}],"996":[{"type":"財宝","name":"東方見聞録","rank":"1","desc":"13世紀終わりごろ、元朝のフビライに仕えたマルコ・ポーロの口述を記録した本。この中に、黄金の国ジパングが登場する。","note":"冒険者のバイブル","exp":"55"}],"2424":[{"type":"海洋生物","name":"ヤガラ","rank":"1","desc":"口の長さと形が特徴的な細長い体の魚。\n体は赤いが身は白く、外見からは想像できないほど美味である。\n見た目のせいか、獲れても逃がされることが多いらしい。","note":"釣り","exp":"130"}],"415":[{"type":"化石","name":"草模様の石","rank":"1","desc":"シダによく似た植物の模様がある石。シダとはいっても、非常に大きい。なぜ、葉が石になるのだろうか？　それとも、人為的なものなのだろうか？","note":"奇妙な石の地図<br/>アフリカ南岸に上陸","exp":"48"}],"6050":[{"type":"宗教建築","name":"聖カタリナ修道院","rank":"3","desc":"シナイ山のふもとにある修道院。ビザンツ帝国の初期に建造され、古代の写本や聖像破壊運動より前の時代のイコンが残っていることで名高い。十字軍が滞在して以来、重要な巡礼地の一つとされているようだ。","note":"","exp":"490"}],"6723":[{"type":"海洋生物","name":"ザトウクジラ","rank":"5","desc":"体長１３ｍから１５ｍ程、大型のクジラ。普段は極圏地帯に生息しているが、夏の間は熱帯海域に移動、オキアミなどを捕食する。捕食の際、複数のクジラが泡を放出、円型の泡壁を形成し、獲物を一箇所に集中させる独特な狩りが特徴となっている。","note":"慈愛に満ちた生物<br/>発見物カード:520","exp":"1040"}],"571":[{"type":"虫類","name":"ホタル","rank":"1","desc":"腹部が光る小型の昆虫である。森の中で、ほうぼうが点滅している様子は大変美しい。なぜ腹が光るのかは不明だ。","note":"光る虫","exp":"20"}],"1774":[{"type":"地理","name":"デセアド岬","rank":"2","desc":"南米大陸南西岸にある岬。この周辺の地形は氷河によって造成されたフィヨルド地形であり、他の地域と大きく異なる。","note":"［勅命］「新大陸西岸進出への道標」<br/>リマ冒険「南米地形調査」","exp":"310"}],"3647":[{"type":"宗教遺物","name":"ダジボーグのレリーフ","rank":"4","desc":"スラブ神話に登場する太陽神の像。「イーゴリ遠征物語」内では、ロシア側の人々はダジボーグの孫とされた。","note":"スラブの太陽神","exp":"650"}],"1867":[{"type":"財宝","name":"金のナイフ","rank":"3","desc":"トゥミと呼ばれるナイフ。ケチュア語で「半円の刃」という意味である。この形のナイフはほとんど持ち手が神像になっており、一般生活用ではなく、儀式用に作られたと見られる。","note":"古のナイフ<br/><br/>発見時経験値490　発見物カード経験値245","exp":"245"}],"553":[{"type":"史跡","name":"レプティス・マグナの遺跡","rank":"1","desc":"ローマのセプティミウス・セウェルス帝が建造した大都市の遺構。大理石をふんだんに使った施設跡が並び、当時の興隆が見えるようだ。","note":"古代ローマの都市跡","exp":"105"}],"6956":[{"type":"史跡","name":"ビームベートカーの岩陰遺跡群","rank":"5","desc":"インド中部の森の中に位置する岩陰遺跡群。数百に及ぶ岩窟と壁画が残されているが、正しい数はわかっていない。古いものは動物や狩人、時代が浅いものは幾何学模様など、さまざまなものが鮮やかに描かれている。","note":"","exp":""}],"1814":[{"type":"財宝","name":"神曲","rank":"2","desc":"イタリアの詩人、ダンテ・アリギエーリの長編叙事詩。地獄編、煉獄編、天国編の三部から成る。主人公はダンテ自身であり、地獄、煉獄を遍歴し、ついには天界に至るという内容。イタリア古典文学の代表作ともいえる一作である。","note":"ダンテの長編叙事詩","exp":"280"}],"1921":[{"type":"海洋生物","name":"セミホウボウ","rank":"2","desc":"美しく大きな胸びれを持つ魚。その胸びれで滑空するように泳ぐ。","note":"釣り","exp":"350"}],"4965":[{"type":"天文","name":"かんむり座","rank":"2","desc":"ギリシャ神話の酒神・ディオニソスがその妃アリアドネに贈った冠の天に上がった姿とされる星座。アリアドネはクレタ王ミノスの娘でテセウスのミノタウロス退治に協力した。","note":"クエスト「ミノス王の娘」<br/>発見物カード:175","exp":"370"}],"6982":[{"type":"中型生物","name":"キルクディクディク","rank":"","desc":"東アフリカに生息するレイヨウの一種。小柄かつ細身な体躯ながら脚力に優れ、非常に足が速い。一度つがうと生涯離れず、雌雄で協力して縄張りを守りながら暮らす。甲高く、独特な警戒声が名前の由来とされている。","note":"経験値705＋352","exp":"705"}],"5726":[{"type":"地理","name":"イエローバンド","rank":"2","desc":"チョモランマにある3つの地層の内の1つ。\n地層からは複数の化石が見つかっている。この化石を研究すると、過去の付近の様子を探れるだろう。","note":"2017.02.07新規追加","exp":"250"}],"2855":[{"type":"歴史遺物","name":"漢書","rank":"2","desc":"前漢時代について記した歴史書。\n皇帝など、人物ごとに焦点を当てて書かれているのが特徴である。","note":"勉強に必要な頼み事","exp":"260"}],"2796":[{"type":"美術品","name":"顧愷之の訓画","rank":"3","desc":"東晋の画家・顧愷之によって描かれた訓画。道徳書を絵画で表現したものである。\n教育のためか、後世において摸本が複数作成されたようだ。","note":"幼い子供のお勉強","exp":"540"}],"1537":[{"type":"地理","name":"バンカ島","rank":"1","desc":"マラッカ海峡東部に位置する島。この海域の島々と同様、島の周囲には美しいサンゴ礁が広がっている。","note":"書きかけの地図","exp":"110"}],"366":[{"type":"植物","name":"アステリスカス","rank":"2","desc":"整った円をした黄色い花。その形は、太陽のようでもあり、コインのようでもある。","note":"黄色く美しい円","exp":"275"}],"2342":[{"type":"歴史遺物","name":"土偶","rank":"2","desc":"日本で発見された、人の形をしている土製の焼き物。奇異な形状だが、どこか女性らしさが漂う。\n一部、故意に壊されたような痕跡があるが、目的は不明だ。","note":"あやしい人形","exp":"390"}],"1551":[{"type":"地理","name":"タスマン海","rank":"1","desc":"オーストラリアの南東に横たわる海。付近には暖流が流れているため、沿岸の気温は暖かく過ごしやすいが、暴風地帯でもある。","note":"書きかけの地図","exp":"135"}],"6954":[{"type":"宗教建築","name":"ウナス王のピラミッド","rank":"4","desc":"古代エジプトの王、ウナスのピラミッド。規模は小さく、石材の持ち出しや、風化などにより、大半が崩れている。内部には死者の書の基礎となった「ピラミッド・テキスト」と呼ばれる最古の葬送碑文が刻まれている。","note":"発見物カード:350","exp":"700"}],"4841":[{"type":"宗教遺物","name":"イェルサレム第二神殿の欠片","rank":"2","desc":"バビロン捕囚によって破壊されたソロモンの神殿に代わり、イェルサレムに建設されたユダ人の神殿の欠片。\nヘブライ語で「放浪の場所へ」と銘打たれている。","note":"信仰の光","exp":"310"}],"6710":[{"type":"天文","name":"プラエキプア","rank":"5","desc":"こじし座で最も明るい星。約4等星の暗い星で、小ライオンの尻に位置する。ラテン語で「主要なもの」を意味する名だが、今ではこの名称自体があまり使われなくなった。","note":"発見物カード:450","exp":"900"}],"927":[{"type":"財宝","name":"浮き彫りのつぼ","rank":"1","desc":"表面に美しいレリーフを施したつぼ。実用品ではなく、飾るためのものだろう。","note":"美しいつぼの地図","exp":"22"}],"5842":[{"type":"財宝","name":"封神演義","rank":"5","desc":"明代に書かれた文学作品。殷周革命時代を舞台に多くの神仙が活躍する物語。民間信仰に大きな影響を与えた。","note":"","exp":"1340"}],"6157":[{"type":"伝承","name":"海坊主","rank":"5","desc":"夜の海に現れ、船を破壊するとされる怪物。主には黒い坊主頭\nの巨人だとされる。伝承によって様々な形、大きさがあり、\n行動も異なる。海坊主が現れた後は、天候が荒れ、船が沈む\nなどの怪異が起きるといわれている。","note":"","exp":"1480"}],"6649":[{"type":"史跡","name":"扶蘇山城","rank":"5","desc":"百済の都城。白馬川の南にある扶蘇山に築かれた。三忠祠には、百済最後の王・義慈王に仕えた三大忠臣の位牌と肖像画が祀られている。","note":"クエスト「百済文化の宝庫」 発見物カード:415","exp":"830"}],"723":[{"type":"宗教建築","name":"カルナック・ルクソール神殿","rank":"2","desc":"歴代のファラオたちが次々に増改築を繰り返した神殿群。複数の神殿があり、数多くの神像やファラオの像、大石柱が立ち並ぶ様は壮観である。","note":"生者の街","exp":"290"}],"6256":[{"type":"史跡","name":"ベルレンガの要塞","rank":"1","desc":"リスボンの北にあるベルレンガ・グランデ島に建てられた砦。正式名は「サン・ジョアン・バプティスタ要塞」という。海上防衛のために修道院の遺構を利用して築かれ、しばしばバルバリア海賊などの標的となった。","note":"","exp":"110"}],"5309":[{"type":"小型生物","name":"リンカルス","rank":"4","desc":"アフリカ南部に生息するヘビ。毒を持つ上、危険を感じると敵の目に向けて毒液を吐いて飛ばす習性がある。死んだふりを得意とするため、無用心に近づくのは危険だろう。","note":"","exp":"770"}],"6347":[{"type":"歴史遺物","name":"ソストラトスの碑文","rank":"2","desc":"大灯台の建設に携わったソストラトスは、秘密裏に大灯台の礎石に自身の名前がはいった碑文をいれ、その上をモルタルで覆い統治者プトレマイオスの名を刻むという仕組みを施したことで後世に名を残したとされる。","note":"","exp":"300"}],"502":[{"type":"歴史遺物","name":"ギリシャ文字の石板","rank":"1","desc":"ギリシャ文字が刻まれた石板。長く残すための銘文が刻まれているのだろう。","note":"古代ギリシャ遺物の地図","exp":"14"}],"128":[{"type":"宗教遺物","name":"聖母のステンドグラス","rank":"1","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40"}],"2600":[{"type":"美術品","name":"鳥獣人物画","rank":"2","desc":"擬人化された動物が描かれている、日本の絵巻物の一部。\n当時の庶民の生活の様子が、動物の姿を借りて生き生きと表現されている。","note":"・人のような動物","exp":"340"}],"5068":[{"type":"港・集落","name":"ザダール","rank":"1","desc":"ヴェネツィア近郊の街である。かつてはダルマチア国の首都であった。アドリア海に面した温暖な気候である。","note":"到達する","exp":"21"}],"2302":[{"type":"歴史遺物","name":"赤く染まった骨","rank":"5","desc":"膨大な数の副葬品とともに発見された人骨で赤く染められている。副葬品が豪華なことや埋葬後も儀式が行われていた形跡があることから、コパン王朝の創始者またはその関係者のものである可能性も考えられる。","note":"異なる壁画の意味","exp":"1060"}],"1596":[{"type":"歴史遺物","name":"タコの絵のアムフォラ","rank":"2","desc":"クレタ島の遺跡で見つかった壷。アムフォラとは壷の種類の名前で酒や油の運搬や保存に使われた。\n絵は、しなやかな線の洗練された様式で描かれている。タコなどの海の生物は、海に囲まれた島民にとって食や富の象徴であった。","note":"ミノス王の時代の面影","exp":"220"}],"5090":[{"type":"港・集落","name":"ダバオ","rank":"2","desc":"ミンダナオ島の南岸に位置する街。ミンダナオ島は気候が安定しているため、農業に最適な土地である。さらにダバオは海側に山脈を持つため、嵐の影響を受けにくい。","note":"到達する","exp":"354"}],"4860":[{"type":"天文","name":"みずがめ座の丸い星雲","rank":"2","desc":"みずがめ座にある環状の星雲。天体望遠鏡では、あまり明るくはないが、大きく見える。","note":"「天文学者の観測記録」<br/>発見物カード:155","exp":"310"}],"3944":[{"type":"天文","name":"こと座の環のような星雲","rank":"1","desc":"こと座にある星雲。中心部がやや暗く、色の違ういくつかの環があるように見える。","note":"「天文学者の観測記録」<br/>発見物カード:100","exp":"200"}],"5910":[{"type":"天文","name":"南方七宿朱雀","rank":"5","desc":"中国星座において、天の赤道を28に分割した二十八宿のうち南方の七宿をまとめたもの。ふたご座やかに座などが含まれる。","note":"クエスト「最後の守護神獣」<br/>発見物カード:665","exp":"1330"}],"6315":[{"type":"伝承","name":"モケーレ・ムベンベ","rank":"5","desc":"中央アフリカの熱帯雨林に生息しているとされる幻の巨大生物。長い首と尾を持つ一方、四本の脚は短い。水辺によく姿を現すとされている。","note":"アフリカの巨大生物に関する伝承","exp":"1080"}],"6249":[{"type":"地理","name":"ゴロンゴーザ山","rank":"2","desc":"ソファラの西にあり、住民の間では神が住んでいたといわれる山。山の周辺には人が踏破しきれないほどの大自然が広がり、未発見の動物や植物も多数生息しているとみられる。","note":"","exp":"250"}],"6589":[{"type":"海洋生物","name":"ソハールタング","rank":"2","desc":"紅海やペルシャ湾海域に生息する魚。魚体は楕円形で頭が小さく、尾に短剣のような鋭い棘がある。鮮やかな色の珊瑚礁に棲む。","note":"紅海で発見。セイラ付近。アデンからスエズへの委任航海中","exp":"340"}],"1468":[{"type":"宗教遺物","name":"ドゥワラパラ像","rank":"3","desc":"ブリハディーシュヴァラ寺院の入り口に立つ一対の石像。高さが4mもあり、一枚岩から削り出されたもので、寺院の門番である。","note":"寺院の守護者","exp":"517"}],"6609":[{"type":"大型生物","name":"クチジロジカ","rank":"5","desc":"中国固有のシカで、チベットや周辺地域にある高原に生息する。唇や下顎、喉が白い体毛で覆われているのが特徴。オスは大きな角を持つ。袋角は貴重な薬材として用いられる。","note":"文化貢献度50","exp":"830"}],"3577":[{"type":"史跡","name":"ヘイアウ","rank":"1","desc":"積み石で囲んだ一帯で聖域とされる。ハワイ島の随所に散在する。精霊や神々への祈りを捧げる場所であるらしく、祭神によって呼び方も異なる。","note":"クエスト「石囲いの聖地」<br/>発見時経験値182　発見物カード経験値91","exp":"182"}],"774":[{"type":"中型生物","name":"シタツンガ","rank":"4","desc":"湿地、沼などに生息する。尖った蹄、ねじれた長い角が特徴で、水中および陸上の植物を食べる。食事中は、肩まで水中に浸かっていることもある。","note":"尖った蹄","exp":"612"}],"5118":[{"type":"港・集落","name":"パナマ","rank":"2","desc":"北米と南米の境に位置する港街。「魚が豊富な場所」という意味の名のとおり、漁業が盛んである。街の周辺に広がる熱帯雨林には、様々な生物が生息している。","note":"","exp":"290"}],"2387":[{"type":"海洋生物","name":"カブトガニ","rank":"4","desc":"東アジアから東南アジアにかけて、一部の沿岸域に生息する生物。これとよく似た模様を持つ石もあるという。","note":"クエスト「未確認海洋生物」<br/>発見物カード:310","exp":"620"}],"3618":[{"type":"海洋生物","name":"ハーフバードパウト","rank":"2","desc":"北極海などの北の海の底に生息する魚。体長は20cm程度で、うろこがないのが特徴。胸びれを使って、海底を這うように泳ぐ。","note":"釣り","exp":"340"}],"6361":[{"type":"気象・現象","name":"白い嵐","rank":"2","desc":"冷えて重くなった空気が雲から一気に吐き出される現象。災害をもたらすほど強烈な突風が地上に吹きすさぶ。積乱雲の中に蓄えられた冷たい空気が、上昇気流の衰えによって地上へと急降下することで発生する。","note":"サンフランシスコの南　２分程度　10531,3347<br/>昼間　曇り空","exp":"370"}],"205":[{"type":"美術品","name":"スキピオ伝のタペストリー","rank":"1","desc":"ジュリオ・ロマーノの原画をもとに織られた連作タペストリーの一枚である。内容は、古代ローマ時代のカルタゴ戦争を舞台に、スキピオの事績を追うものである。","note":"タペストリーの地図","exp":"70"}],"1058":[{"type":"歴史遺物","name":"楔形文字の石板","rank":"1","desc":"「くさびがたもじ」。楔形文字が刻まれた石板。楔形文字は古代メソポタミアを中心として用いられた。石板に刻んだということは、長期間残す目的で作られたのだろう。","note":"楔文字の遺物の地図","exp":"64"}],"6893":[{"type":"宗教建築","name":"大雁塔","rank":"5","desc":"西安の寺院内に建てられた四角いレンガ造りの仏塔。インドから持ち帰った経典や仏像を保管するため、玄奘三蔵が皇帝に願い出て建立されたという。","note":"","exp":""}],"1703":[{"type":"宗教遺物","name":"ソロモンの指輪","rank":"5","desc":"古代イスラエルの王であり、ダヴィデの子ソロモンが持っていたといわれる指輪。この指輪をすると動物たちと会話ができるといわれている。","note":"ソロモンの見た夢","exp":"1196"}],"5714":[{"type":"地理","name":"チョモランマ","rank":"3","desc":"何物をも拒む急峻さを持つ、巨大な山。神ならぬ身である人間が、その頂を制覇するのは、いつになるだろうか。","note":"2017.02.07新規追加","exp":""}],"548":[{"type":"史跡","name":"ペルセポリス遺跡","rank":"2","desc":"アケメネス朝ペルシャのダレイオス1世が着工した、ペルシャの大宮殿跡。広大な敷地に多数の石柱や独特の石像、すばらしいレリーフが残る。","note":"古代ペルシャの大宮殿","exp":"220"}],"6439":[{"type":"気象・現象","name":"尾流雲","rank":"2","desc":"雨や雪、あられなどが雲から落下する途中で蒸発する時に発生する雲の一種。雲の下に、薄い筋状や柱状の靄が尾のようにぶら下がって見える。広い地域で観測される。","note":"視認ランク７では不足、１１で観測できたため、必要な視認ランクは８から１１の間です。<br/><br/>R10で発見できました。<br/><br/>曇りの日が少ないため、かなり待つことになりがちです。","exp":"340"}],"1449":[{"type":"中型生物","name":"タスマニアンデビル","rank":"5","desc":"肉食の有袋類。昆虫から小型の哺乳類、大きいものはワラビーまで捕食する。しばしば餌の奪い合いをし、興奮すると皮膚の部分が紅潮する。","note":"悪魔と呼ばれる生物","exp":"923"}],"3258":[{"type":"地理","name":"アトラス山脈","rank":"3","desc":"北アフリカ沿岸、アルジェからカサブランカ付近まで続く山脈。標高が高い部分は積雪が見られる。\n山脈の名称は、ゼウスの命令により西の天界を支えることとなったギリシャ神話に登場する神・アトラスが由来となっている。","note":"クエスト「巨神の山脈」<br/>発見物カード:230","exp":"460"}],"564":[{"type":"歴史遺物","name":"海の民の鎧","rank":"2","desc":"ヒッタイトを滅ぼし、古代エジプトを苦しめた正体不明の古代民族「海の民」が使っていたと思われる鉄の鎧。製鉄技術は、ヒッタイトしか持っていなかったはずだが…。","note":"古代民族の武具","exp":"270"}],"48":[{"type":"地理","name":"サンヴィセンテ岬","rank":"1","desc":"イベリア半島の南西端にある岬。大西洋に突き出しており、よく航海の目安にされる。","note":"イベリア半島の南西端","exp":"20"}],"297":[{"type":"美術品","name":"聖家族","rank":"3","desc":"ミケランジェロ作の絵画。ほかの画家の作品に比べて肉体や衣服が立体的に感じるのは、彼が彫刻を得意とするからだろう。聖母にさほど聖性が感じられないのは、彼の所属している宗派の教義によるものだと思われる。","note":"ミケランジェロの絵画","exp":"495"}],"448":[{"type":"美術品","name":"象牙の聖櫃","rank":"2","desc":"「せいひつ」。作者不明の、象牙でできた高さ30cmほどの聖櫃。自宅での礼拝などに使われたのではないだろうか。左右の板はたためるようになっている。中央の聖母子像は完全な像ではなく、浮き彫りである。","note":"教会の祭器の地図","exp":"245"}],"6862":[{"type":"天文","name":"ズベン・エス・カマリ","rank":"2","desc":"てんびん座のベータ星で、この星座の中では最も明るい3等星。\n青白い星であるが、肉眼では緑色に見える唯一の恒星として知\nられている。名はアラビア語で「北の爪」を意味し元々はさそ\nり座の爪にあたる部分であった名残りと言われている。","note":"発見物カード:195","exp":"390"}],"5032":[{"type":"港・集落","name":"カイロ","rank":"1","desc":"もとはビザンツ帝国の要塞であったが、10世紀にイスラム勢力が都市を築いた。それ以来エジプト地域の中心地として栄えている。特色のある農作物のほか綿生地が流通する。","note":"到達する","exp":"48"}],"6112":[{"type":"虫類","name":"ニシキオオツバメガ","rank":"5","desc":"マダガスカルにのみ生息するガの一種。成虫はガとしては珍しい昼行性。黒を基調とし、緑や黄で彩られた羽は虹や宝石のように美しく、世界を探してもこれより美しいガは見つからないかもしれない。","note":"","exp":"950"}],"3687":[{"type":"中型生物","name":"シベリアジャコウジカ","rank":"5","desc":"麝香の元となる匂いを分泌する、シカに似た小柄の動物。角は持たない。雄は上あごの犬歯が発達した大きめの牙を持つ。","note":"シベリアの麝香","exp":"950"}],"2859":[{"type":"植物","name":"カエンタケ","rank":"2","desc":"中国や日本に分布する猛毒のキノコ。腐敗した木々のそばに生育する。\n真っ赤なカサの色と炎のような形から、この名が付いた。","note":"燃えるキノコ","exp":"380"}],"1985":[{"type":"海洋生物","name":"ジャウー","rank":"2","desc":"人食いナマズとも言われる、貪欲で巨大なナマズ。","note":"釣り","exp":"240"}],"3776":[{"type":"天文","name":"やぎ座","rank":"5","desc":"黄道十二星座の1つ。星座図では上半身が山羊、下半身が魚の姿で描かれることが多い。怪物テュポンの出現に驚き、山羊頭の神パンが化けた姿とされる。明るい星がないため、黄道十二星座の中では見つけるのが難しい。","note":"クエスト「ヤギと魚の星座」<br/>発見物カード:550","exp":"1100"}],"2838":[{"type":"宗教遺物","name":"論語","rank":"2","desc":"春秋時代の思想家・孔子の言行を、弟子達が記録した書物。全20編で構成される。\n科挙の出題科目にもなっており、儒教でも重要な書物である。","note":"科挙の勉強","exp":"240"}],"3253":[{"type":"地理","name":"オシュン・オショグボ聖林","rank":"4","desc":"西アフリカに位置する聖なる森。ヨルバ民族の神話における豊穣の女神・オシュンが住むとされる。","note":"聖なる木立","exp":"690"}],"6719":[{"type":"財宝","name":"編鐘","rank":"5","desc":"複数の鐘からなる打楽器。春秋戦国時代に登場し、明代には金の編鐘も制作された。吊り下げられた何点もの鐘はそれぞれ音の高さが異なる。権力を象徴するものであり、宮廷の儀式で用いられた。","note":"楽の叡智・心に響く楽器　中央","exp":""}],"2750":[{"type":"小型生物","name":"コウライリス","rank":"2","desc":"朝鮮半島の森林地帯に生息するリス。耳の先端にある、長い毛房が特徴的。\n木の芽や木の実を食べる習性は、他のリスと変わらない。","note":"大きくなく小さくなく","exp":"270"}],"5797":[{"type":"歴史遺物","name":"ネロの杯","rank":"5","desc":"しっかりとした作りの杯。暴君ネロがよく毒殺に用いたという噂がある。毒がしみこむはずもないが、使用するのはやはり抵抗があるだろう。","note":"暴君の杯","exp":"1340"}],"1157":[{"type":"財宝","name":"エルナン・コルテスの銃","rank":"2","desc":"エルナン・コルテスが本国から持ち込んだといわれる銃。彼はケツアルコアトル神と間違えられ、アステカの首都テノチティトランに入れた。そのおかげでアステカが非常に高度な軍事力を持つことを知った。","note":"コンキスタドール・コルテス","exp":"330"}],"1864":[{"type":"歴史遺物","name":"貫頭衣","rank":"2","desc":"アルパカやリャマなどの毛、鳥の羽を用いて作った一枚布。長方形に縫い、中央に穴を開け、そこから顔を出すように着る。胴の部分に腰紐を巻き、腕を出す。彩色は、赤、青、緑、黄などの原色で、非常に派手である。","note":"巫女の織った服","exp":"280"}],"1745":[{"type":"財宝","name":"アベラム民族の胸飾り","rank":"5","desc":"部族間闘争の際に身に着ける胸飾り。羽毛や木の葉、貝、獣の牙などで、雄雄しく飾り立て、自らの誇りの高さを周知させるという。","note":"それぞれの誇り","exp":"910"}],"3660":[{"type":"歴史遺物","name":"アルキメデスの大理石像","rank":"3","desc":"古代ギリシャ・ローマ時代に『てこの原理』を始めとする優れた業績を残した数学者・物理学者アルキメデスの大理石像。アルキメデスはシラクサの出身でかつてはシラクサの門の側にその墓が建っていたといわれる。","note":"ダンジョン<br/><br/>発見時経験値510　発見物カード経験値255","exp":"510"}],"1612":[{"type":"宗教遺物","name":"ケルト十字の石柱","rank":"2","desc":"アイルランドの遺跡に多く残る十字架。円環が付いた大きな石造りの十字架で、ケルトの紋様が全体に刻まれている。十字に円環が付くようになったのは、キリスト教がケルトに伝わった際、両文化が融合したためといわれている。","note":"聖書が刻まれた十字架","exp":"220"}],"1340":[{"type":"地理","name":"スールー諸島","rank":"2","desc":"カリマンタン島の北東岸にある諸島。古くからイスラム教を国教とする王国が成立し、周囲の島々を支配下に置いていた。近年はイスパニアがマニラを拠点として活動し始めたため、海賊を支援し、抵抗しているようだ。","note":"最重要監視海域","exp":"360"}],"17":[{"type":"歴史遺物","name":"青銅の装飾","rank":"2","desc":"アナトリア半島から出土した、青銅製の装飾品。なにに使ったのかは不明だ。アナトリアに興ったヒッタイトはやがて製鉄の技術を発見する。","note":"アナトリア半島の青銅器","exp":"360"}],"2624":[{"type":"地理","name":"卑南渓","rank":"2","desc":"台湾島東部を流れる川の一つ。\n卑南とは、先住民である卑南民族の頭目を意味する。\n複雑に削られた川の地形が、中国の黄山に似ていることから「小黄山」とも呼ばれる。","note":"［勅命］[[調査における水場の確保","exp":"340"}],"3892":[{"type":"天文","name":"いっかくじゅう座","rank":"4","desc":"冬の大三角にかかる位置にある星座。一角獣は額の上に一本の角を持つ、馬に似た動物とされる。この星座を誰が設定したかは諸説があって定かではない。","note":"ドイツで作られた星座","exp":"660"}],"3191":[{"type":"史跡","name":"ランス・オ・メドー","rank":"5","desc":"新大陸北部、テラ・ノヴァにある史跡。北欧のヴァイキングが移住した場所と考えられている。いくつかの建物が良い状態で残っておりこれらは作業場として使われたと考えられている。","note":"悪夢を醒ます夢","exp":"1270"}],"6081":[{"type":"天文","name":"カメレオン座","rank":"2","desc":"南天星座の一つ。南天の星図作成に尽力した航海者ペーテル・ケイセルらの残した観測記録を元に制定され、同時代に南半球で発見されたカメレオンの名をつけられた。","note":"「航海士の観測記録」<br/>発見物カード:150","exp":"300"}],"1519":[{"type":"財宝","name":"ディジュリドゥ","rank":"4","desc":"オーストラリア先住民が儀式の際に演奏する木笛。「イダキ」「マゴ」など地方によって呼び方が違う。シロアリによって中を食い開けられた、特定のユーカリを使う。筒の端に唇を当てて唇の振動で音を出す。","note":"不思議な奏法","exp":"636"}],"6673":[{"type":"天文","name":"シェダル","rank":"4","desc":"カシオペア座で最も明るいオレンジ色の星。エチオピアの王妃カシオペヤの胸にあたり、アラビア語で「胸」を意味する。","note":"発見物カード:355","exp":"710"}],"5192":[{"type":"港・集落","name":"漢陽","rank":"2","desc":"読みは「ハンヤン」。「漢水より北の大地」という意味がある。\n百済時代の都があったため歴史は古く、遺物が多く発見される。","note":"到達する","exp":"370"}],"2742":[{"type":"財宝","name":"申聞鼓","rank":"3","desc":"（しんぶんこ）朝鮮王宮の門前に置かれている太鼓。民が王に謁見を願うときに叩かれるという。\n両班の衣服と似た配色の派手な彩色が施されており、目を引く。","note":"沈黙の太鼓","exp":"460"}],"5184":[{"type":"港・集落","name":"ヴェラクルス","rank":"2","desc":"街の名前はスペイン語で「真の十字架」の意味。16世紀初頭、エルナン・コルテスが上陸し、メキシコ湾における貿易の表玄関となっている。","note":"到達する","exp":"256"}],"6135":[{"type":"地理","name":"チャシコツ岬","rank":"3","desc":"日本北部にある岬で、現地の地名「ウトロ」に由来するウトロチャシという砦跡がある。現地の言葉で砦や集会場を「チャシ」、その跡を「チャシコツ」と呼ぶ。初めは聖域や集会場だったものが、後に砦の機能も持つようになったようだ。","note":"","exp":"490"}],"1531":[{"type":"虫類","name":"カスリタテハ","rank":"1","desc":"深く濃い青に、水色の斑模様が入った羽を持つ。飛ぶときに「カチカチ」という音を発する。","note":"斑模様のチョウの地図","exp":"130"}],"3740":[{"type":"史跡","name":"セルメルミュート","rank":"5","desc":"グリーンランドで最も古く、最も大きな集落の跡。大きな遺構などはなく、一見すると単なる渓谷のようだ。","note":"グリーンランドの居住跡","exp":"1050"}],"558":[{"type":"歴史遺物","name":"ウルのスタンダード","rank":"2","desc":"ウル王墓から出土した用途不明の箱。軍旗や楽器の一部ではないかなどと言われている。戦争の図と、その反対に平和の図が描かれており、貝殻やラピスラズリのモザイクで飾られている。","note":"古代交易路の証","exp":"370"}],"2484":[{"type":"宗教遺物","name":"鳥居","rank":"2","desc":"神社へと続く参道に配置された、門の一種。この鳥居に見られる赤い色は、厄除けの意味を持つとされている。日本では、こうした鳥居によって、聖域と俗界が区分されている。","note":"神社跡の調査依頼","exp":"330"}],"5863":[{"type":"美術品","name":"ラブサヨン","rank":"5","desc":"特徴的な形をした、黒い壺。マレー半島で作られる伝統的な工芸品で、地元の人々に愛されている。","note":"","exp":"1340"}],"2727":[{"type":"宗教建築","name":"石窟庵","rank":"5","desc":"新羅時代の仏教遺跡。内部はドーム状になっているが、洞窟を掘ったのではなく、石材を積み上げ、その上に土を盛って建築されたという。新羅の石造建築技術は、かなり高かったようだ。","note":"造られた洞窟","exp":"1130"}],"5206":[{"type":"歴史遺物","name":"トトメス1世のオベリスク","rank":"1","desc":"古代エジプトのファラオであるトトメス1世がアメン・ラーのために建立したとされる高さ22mのオベリスク。中心にトトメス1世、両脇にラムラス4世による碑文が刻まれている。","note":"","exp":""}],"1217":[{"type":"植物","name":"リュウゼツラン","rank":"1","desc":"大きく厚い葉を放射状につけ、数mにも伸びた茎に花を咲かせる植物。根はテキーラの原料となる。その繊維はロープなどを作る際にも利用される。","note":"テキーラの原料","exp":"135"}],"459":[{"type":"小型生物","name":"キンイロアデガエル","rank":"5","desc":"捕食者に対し有毒だと警告するために鮮やかな色をしている。地上で活動し、卵も地上に産む。","note":"金色の生物","exp":"1105"}],"227":[{"type":"歴史遺物","name":"プリアモス王の財宝","rank":"5","desc":"ギリシャ神話に登場する、トロイの最後の王の財宝。プリアモス王の息子・パリスのために戦争が起き、トロイはギリシャに滅ぼされた。","note":"トロイ王家の財宝","exp":"936"}],"5019":[{"type":"港・集落","name":"アルジェ","rank":"1","desc":"西暦980年に、イスラム勢力によって建設された街。近年、バルバリア海賊に占領され、拠点となった。紡績や鉱業のほか、農業が盛んである。","note":"到達する","exp":"42"}],"839":[{"type":"小型生物","name":"トビネズミ","rank":"1","desc":"長く発達した後ろ足で飛び跳ねるネズミ。耳が長く鼻が短く、目がとても大きい。","note":"跳ねるネズミの地図","exp":"56"}],"6755":[{"type":"美術品","name":"桃鳩図","rank":"5","desc":"桃の枝に止まる鳩が描かれた中国絵画。宋の皇帝であった徽宗の作と伝わる。絵の右上に痩金体という珍しい書体で記された「大観丁亥御筆」の款記と「天水」の花押があり、さらに「御書」の朱文印が押されている。","note":"","exp":""}],"248":[{"type":"歴史遺物","name":"バルムンク","rank":"5","desc":"北欧の伝説の英雄ジークフリードが愛用したといわれる剣。所有する者に英雄としての栄光と、壮絶な最期をもたらすとされる。霧深き最果ての地で発見された。","note":"バルムンク","exp":"1183"}],"373":[{"type":"美術品","name":"ゴルゴタの丘","rank":"1","desc":"アンドレア・マンテーニャ作の祭壇画。ゴルゴタの丘ではりつけにされるキリストを描いたもので、ほぼ完成された遠近法を用いている。衣服や武具、馬具など、緻密な考証がされている点も評価できる。","note":"画期的な絵画技法","exp":"95"}],"3777":[{"type":"天文","name":"うお座","rank":"5","desc":"黄道十二星座の1つ。2匹の魚がリボンで結ばれた姿で描かれる。怪物テュポンに襲われた女神アフロディテとその子エロスが、魚に変化して逃げた姿だとされる。明るい星がなく、黄道十二星座の中では見つけにくい星座である。","note":"クエスト「双魚宮の調査」<br/>発見物カード:550","exp":"1100"}],"1475":[{"type":"財宝","name":"天女の舞衣","rank":"4","desc":"伝統あるアプサラダンスでアプサラ役が着る衣装。踊り子の服の色は、赤・青・緑・白とあるのだが、アプサラ役の衣装は白と決まっている。精緻な刺繍と豪華な装飾が踊り子を天女のように見せるのだろう。","note":"アプサラの舞","exp":"732"}],"1955":[{"type":"植物","name":"フクロユキノシタ","rank":"1","desc":"オーストラリアのみに生息。小瓶にふたが付いた形の葉を複数付けている。この瓶の形の葉の中に落ちた虫は、しばらくすると溶けてなくなってしまう。\nこの植物は虫から養分を吸収しているのかもしれない。","note":"虫を捕まえる植物の地図","exp":"110"}],"2558":[{"type":"鳥類","name":"ミカドキジ","rank":"5","desc":"台湾島の、標高が高い山地にのみ生息する希少な鳥。体長は約70cmと大型で、長い尾が特徴である。","note":"台湾島の鳥調査再び","exp":"930"}],"1571":[{"type":"小型生物","name":"エリマキトカゲ","rank":"2","desc":"オーストラリアに生息するトカゲ。体長は、長い尾を含めると1mにも達する。首を覆う襟が特徴で、敵に遭遇したときなどに広げ、口を大きく開けて威嚇する。そして、相手がひるんだ隙に二足走行で逃げる。","note":"二本足で走るトカゲ","exp":"330"}],"6387":[{"type":"伝承","name":"金色姫","rank":"5","desc":"養蚕の始まりとされる伝承。継母に忌み嫌われた金色姫は何度も捨てられるが、最後にとある夫婦に救われた。結局病で命を落とした金色姫は蚕となり、繭から糸を紡ぐ技術を夫婦に伝えたという。","note":"金色に関する伝承","exp":"1120"}],"6331":[{"type":"歴史遺物","name":"チンチョロ文化のミイラ","rank":"5","desc":"南米のチンチョロ文化のミイラ。エジプトのミイラよりも古いと見られている。小さな子供をミイラ化したものは特に手の込んだ防腐処理が行われている。チンチョロ文化では権力者のみならず庶民もミイラ化の対象となったという。","note":"","exp":"1140"}],"637":[{"type":"美術品","name":"アルペの聖体器","rank":"1","desc":"北フランスのリムザン地方リモージュ出身の細工師・G.アルペが作ったという、祭礼用の器。モンマジュール修道院院長の墓室に納められていたが、あまりに美しいためマルセイユの教会に移されたと伝えられる。","note":"クエスト「修道院長の副葬品」<br/>発見物カード:25","exp":"50"}],"1872":[{"type":"歴史遺物","name":"歴代酋長の衣服","rank":"4","desc":"南米大陸に数多く存在している部族のうち、ある部族の酋長が酋長に就任する際に着る衣服だという。インカ帝国は広大な土地を治めたが、征服地域に統治機能が残っていれば自治を認めたため、部族の特色は失われにくかった。","note":"合理的統治戦略","exp":"720"}],"3756":[{"type":"天文","name":"シリウス","rank":"2","desc":"太陽を除くと、全天で最も明るい恒星。冬の大三角を構成する星の1つで、おおいぬ座に属する。ナイル川の氾濫時期を知らせる星として古代エジプトで重視された。名はギリシャ語の「焼き焦がすもの」に由来する。","note":"クエスト「南の空に輝く星」<br/>発見物カード:165","exp":"330"}],"5451":[{"type":"小型生物","name":"キンカジュー","rank":"3","desc":"長い尾を持つサルのような生き物。生活の大半を樹上で過ごす。移動する際は長い尾を枝に巻きつけるなどして器用に木々の間を移動する。また、夜行性であるため天敵となる存在はあまりいないようである。","note":"人懐っこい動物<br/><br/>発見時経験値600　発見物カード経験値300","exp":"600"}],"6262":[{"type":"伝承","name":"雪姫","rank":"5","desc":"夜の雪山に現れるという、若い娘の姿をした雪の化身。\n山に入った者の前に現れて生き肝を食らったり、凍死させたりするなどの言い伝えが残っている。一方で、人間と結ばれて子を成し、最期まで夫に添い遂げたという話もある。","note":"","exp":"1340"}],"6690":[{"type":"天文","name":"テーブルさん座","rank":"","desc":"南天にある星座。おもに南半球で見ることができる。フランスの天文学者ラカーユがケープタウンのテーブル山をモチーフとして、星座の名前として設定した。","note":"「天文学者の観測地図」<br/>発見物カード:190","exp":"380"}],"1879":[{"type":"歴史遺物","name":"水晶の水差し","rank":"1","desc":"ファーティマ朝のカリフに贈られた、水晶の水差し。水晶だとは信じられないほど薄く加工され、精緻な彫刻が施されている。イスラムの高度な技術を窺い知ることができる。","note":"精巧な加工の地図","exp":"160"}],"704":[{"type":"鳥類","name":"ヨウム","rank":"3","desc":"全身が灰色で、尾の先が赤い、地味なインコである。しかし、非常に知能が高いようで、よく教えると物まねではなく簡単な会話が可能だという。飛ぶ様子はたどたどしい。","note":"人の言葉を話す鳥","exp":"462"}],"2835":[{"type":"財宝","name":"大唐西域記","rank":"4","desc":"唐僧・玄奘が、西域やインドの仏教遺跡、生活などを記録した見聞録。\n全12巻に及び、後世に大きな影響を与えている。","note":"唐僧玄奘の旅行記","exp":"610"}],"2111":[{"type":"歴史遺物","name":"フラメンゴ号","rank":"2","desc":"ポルトガルの東インド貿易船の一隻。\nインドからの帰路、喜望峰沖の嵐は切り抜けたが、サントメ沖で難破し、沈没した。","note":"サルベージ","exp":"310"}],"5830":[{"type":"財宝","name":"集史","rank":"1","desc":"イル・ハン国の王の命により編纂された歴史書。主にモンゴル帝国の発展について記されているが、その他の民族の歴史も集められているため、「集史」と呼ばれる。","note":"","exp":""}],"1779":[{"type":"歴史遺物","name":"シュメールの戦車","rank":"2","desc":"古代メソポタミアの都市国家シュメールで発明された戦車。四輪で車輪に輻がなく、ろばが牽く車体に乗った御者が槍を振り回して戦う。","note":"古代メソポタミアの遺物","exp":"360"}],"5888":[{"type":"海洋生物","name":"ボウズイカ","rank":"5","desc":"主に太平洋に生息するイカの一種。胴が太いため、タコと間違われることもある。深海に棲むため、眼球が大きく発達している。味はタコに近いという。","note":"","exp":"1340"}],"6908":[{"type":"鳥類","name":"ルリオーストラリアムシクイ","rank":"5","desc":"オーストラリア南東部などに生息する小型の鳥。仲間意識が強く、群れで活動し、子育てや危機対応は共同で行う。雑食性で、昆虫を中心に植物の小さな種子や花、果実などを食べる。","note":"","exp":"580"}],"5751":[{"type":"地理","name":"ワイベン島","rank":"5","desc":"オーストラリアの北方のアラフラ海に位置する島の一つ。周囲の海には真珠貝が多く生息している。","note":"2017.02.07新規追加","exp":"1380"}],"5524":[{"type":"気象・現象","name":"ハロ","rank":"4","desc":"太陽や月に薄い雲がかかり、環状の光の帯が発生する現象。発生原因は虹に近いと考えられるが、いまだ解明はされていない。","note":"発見時経験値740　発見物カード経験値370","exp":"740"}],"167":[{"type":"中型生物","name":"アカシカ","rank":"1","desc":"温帯～亜寒帯まで、広い地域で見られる動物である。オスには大きな角があり、メスは小柄である。","note":"シカの群れの地図","exp":"10"}],"1657":[{"type":"地理","name":"氷河","rank":"1","desc":"山間部に堆積した雪が長い年月をかけて融解と凍結の反復、または自重による圧縮で氷となったものが氷河である。氷河は非常にゆっくりとした速度ながら下方に移動している。","note":"書きかけの地図","exp":"110"}],"6640":[{"type":"歴史遺物","name":"ポンペイラクシュミー","rank":"5","desc":"ポンペイの遺跡で発見された、象牙で掘られた女性の小像。その造形から、ヒンドゥー教の美と豊穣の女神ラクシュミーではないかといわれる。インドでも同様の小像が発見されたため、この小像はインド・ローマ貿易の裏付けとなった。","note":"発見物カード1,350","exp":"2700"}],"1009":[{"type":"史跡","name":"ポンペイ遺跡","rank":"1","desc":"ヴェスヴィオ火山の大噴火によって一瞬で滅びた、古代ローマの都市。火山灰に埋もれていたため当時の生活の様子が生々しく残る。","note":"埋もれたローマ遺跡","exp":"100"}],"2603":[{"type":"宗教遺物","name":"厳島装飾経","rank":"4","desc":"厳島神社に納められた装飾経のうちの一つ。意匠を凝らした、華やかな装飾経で、有力者の戦勝や繁栄の祈りが込められている。","note":"装飾経の追加調査","exp":"710"}],"2248":[{"type":"海洋生物","name":"ガラパゴスペンギン","rank":"3","desc":"熱帯地域に生息する、珍しいペンギン。他のペンギンより小さく、体長は35cmほど。前屈みをしているような姿勢が特徴である。\nガラパゴス諸島にのみ生息している。","note":"バルディ頭取の興味","exp":"480"}],"7028":[{"type":"宗教遺物","name":"三匹の魚とスイレンを描いた浅鉢","rank":"3","desc":"アマルナ時代のエジプトで作られた、青い陶器製の鉢。三輪のスイレンと一つの頭を共有する三匹の魚の姿が描かれている。これはエジプト神話の創造神たちである、アメン、ラー、プタハを表しているという。","note":"","exp":""}],"6421":[{"type":"植物","name":"紅葉したサトウカエデ","rank":"5","desc":"サトウカエデが秋頃に黄色や赤に紅葉した状態。木の高さは30メートルを超えるといわれる。群生域で、特徴的な形をした葉が一面に広がる景観は素晴らしいという。","note":"追究クエスト「サトウカエデの追加調査」<br/>発見物カード:445","exp":"860"}],"6503":[{"type":"史跡","name":"オリンピアのフィリペイオン","rank":"5","desc":"オリンピアに建てられた大理石の円形建築。マケドニア王フィリッポス2世が戦勝の記念にゼウス神に捧げた。王の死後、子のアレクサンドロス大王が完成させた。王家の人々の黄金と象牙の像が立ち並んでいたと伝わる。","note":"レガシー競技の聖地オリンピア　上","exp":"2970"}],"6169":[{"type":"小型生物","name":"アスプコブラ","rank":"4","desc":"アフリカ大陸から、アラビア半島にかけて生息しているコブラの一種。危険な毒蛇として畏怖の対象とされるだけでなく、ネズミを捕食する農業の守り神として昔から信仰の対象にもなっていた。","note":"","exp":"660"}],"2732":[{"type":"歴史遺物","name":"金銅製の香炉","rank":"4","desc":"百済王の墓と思われる場所から発見された大型の香炉。\n龍とハチと鳳凰の装飾が施されており、百済の工芸技術の高さがうかがえる。","note":"朝鮮香炉の歴史","exp":"620"}],"6171":[{"type":"財宝","name":"棺に入った動物ミイラ","rank":"4","desc":"末期王朝期のエジプトの神殿周辺で作られていた動物のミイラ。元来は貴人たちが自分の愛玩した動物や家畜たちの死後の楽園での復活を願ったものだったがこの時代には形骸化し、単なる縁起物として扱われることが多かったという。","note":"","exp":"660"}],"257":[{"type":"歴史遺物","name":"ヒッタイト法典","rank":"3","desc":"ヒッタイト王国の法典である。200カ条から成り、粘土板二枚に楔（くさび）形文字で記される。","note":"ヒッタイトの古文書","exp":"528"}],"5874":[{"type":"天文","name":"イータカリーナ星雲","rank":"5","desc":"りゅうこつ座にある星雲。他の星雲と比べて巨大なものに分類されるが、喜望峰など南方の高緯度地域でしか観測できないため、知名度は高くない。ラカーユによって発見されたとされる。","note":"クエスト「巨大星雲」<br/>発見物カード:650","exp":"1370"}],"410":[{"type":"宗教遺物","name":"聖母の衣服","rank":"2","desc":"聖母マリアが身につけていたとされる衣服の切れはし。絵画で描かれるものと同じ赤色に染められている。真贋（しんがん）のほどは定かでない。","note":"奇蹟の衣","exp":"290"}],"3167":[{"type":"史跡","name":"コンスタンティヌスの凱旋門","rank":"2","desc":"帝政ローマ時代、戦争後の凱旋記念のために作られた門。コンスタンティヌス帝が正帝のマクセンティウス帝の勝利を祝って、作ったといわれている。","note":"つぎはぎの門","exp":"330"}],"6749":[{"type":"天文","name":"さそり座の球状星団","rank":"5","desc":"さそり座の背にあたる位置にある星が球状に集まった星団。肉眼でも見ることができる。","note":"","exp":""}],"4951":[{"type":"歴史遺物","name":"リュトン","rank":"3","desc":"古代の器の一種。底部に小さな穴が空いており、そこから酒を他の容器に注ぎ分けるという。リュトンから注がれる酒には、神聖な力が宿ると信じられており、主に儀式で使われていたようだ。","note":"","exp":"500"}],"1318":[{"type":"地理","name":"テルナーテ島","rank":"2","desc":"貴重な香辛料であるクローブを産する島。島には、このクローブの交易により莫大な富を得たテルナーテ王国が存在する。隣島のティドレ王国とは敵対関係にあり、各国が動向をうかがっている。","note":"クエスト「富を生む小島」<br/>発見物カード:165","exp":"330"}],"3264":[{"type":"史跡","name":"トゥウェイフルフォンテーン","rank":"5","desc":"西アフリカに位置する遺跡。2000点を超える線画が岩石に描かれている。主にゾウやキリンなどの動物が描かれており、中には人間の足型なども見られる。","note":"岩壁の絵","exp":"970"}],"5563":[{"type":"天文","name":"ろくぶんぎ座","rank":"4","desc":"ヘヴェリウスが制定した星座。火災で焼けてしまった、彼の愛用の六分儀が名前の由来である。","note":"クエスト「夜空の六分儀」<br/>発見物カード:325","exp":"650"}],"1895":[{"type":"歴史遺物","name":"サント・ラファエル号","rank":"1","desc":"ヴァスコ・ダ・ガマの兄パウロ・ダ・ガマが指揮したキャラック。インドへの航路開拓の帰路、壊血病による深刻な船員不足に直面したため、モンバサ南岸で破却された。","note":"サルベージ","exp":"200"}],"5107":[{"type":"港・集落","name":"ナント","rank":"1","desc":"ローマ時代から存在する、歴史ある街。ロワール川に近く、昔から交通と交易の要衝として栄えた。農作物や織物を産するほか、香料が重要な産物である。","note":"到達する","exp":"10"}],"3537":[{"type":"レリック","name":"エルドラド(輝く丘)","rank":"","desc":"新大陸の密林の奥に隠された、黄金と宝石に満ちあふれた神殿。住人によって秘密が守られているため、訪れることは難しい。","note":"","exp":""}],"5799":[{"type":"宗教建築","name":"バールベック","rank":"5","desc":"ローマの三神を祭る三つの神殿で構成されている遺跡。名前の由来はフェニキアの神であり、時代の変遷を目の当たりにするようだ。","note":"","exp":"1450"}],"5121":[{"type":"港・集落","name":"パレンバン","rank":"2","desc":"スマトラ島南部北岸にある街。東西交易に権勢を振るったシュリーヴィジャヤ王国の首都があった。","note":"到達する","exp":"310"}],"1130":[{"type":"財宝","name":"闘牛場チケット","rank":"2","desc":"かつてバレンシアで、人気闘牛士レスカトールが登場した際、あまりに混雑したため配られた整理券。\n急きょ作られたもののようだが、レスカトールの肖像が描かれており、貴婦人たちを熱くさせたという。","note":"レスカトール<br/><br/>発見時経験値330　発見物カード経験値165","exp":"330"}],"3313":[{"type":"地理","name":"グレートプレーンズ","rank":"4","desc":"北米の中西部に位置する、台地状の平原。丈の短い草が広く自生している。雨量が少なく乾燥した気候である。","note":"目指すは自由の大平原","exp":"730"}],"5800":[{"type":"歴史遺物","name":"クレオパトラの真珠","rank":"5","desc":"クレオパトラの耳飾りについていた真珠。当時、世界最大といわれたものの一つ。対となる真珠は酢に溶かして飲まれたとされるが、あまりに大きく溶かす際にはかなり苦労したことだろう。","note":"世界最大の贅沢","exp":"1400"}],"5245":[{"type":"歴史遺物","name":"青銅の儀礼用剣","rank":"1","desc":"アクロポリスと呼ばれる丘の近辺で見つかった儀礼用の青銅剣。首長の権威を象徴する道具と見られる。首長が政治と共に祭祀を行っていたのだろうか。","note":"","exp":"168"}],"1806":[{"type":"財宝","name":"サロメのヴェール","rank":"2","desc":"聖書の一節に登場する王女のヴェールといわれるもの。このヴェールを使った美しい舞の褒美に、「預言者ヨハネの首」と答えたという。","note":"ヨハネの首を求めた娘","exp":"350"}],"6168":[{"type":"歴史遺物","name":"エーリンナの詩","rank":"2","desc":"古代ギリシャの女流詩人エーリンナの詩の写し。エーリンナは詩の女神の召使と称され、サッフォーの友人または弟子ともされるが、真偽は不明。若くして死んだ友人バウキスへの追憶と嘆きが、英雄叙事詩の韻律をもって綴られている。","note":"","exp":"330"}],"3255":[{"type":"鳥類","name":"ハゴロモヅル","rank":"2","desc":"南アフリカに生息するツルの一種。体長は約100cmで、体色は青みがかった灰色である。胸と尾の羽が長く、特に尾の方は地面まで届くほどの長さを持つ。ほっそりとした優美な立ち姿が特徴的な鳥である。","note":"優美な立ち姿","exp":"400"}],"3867":[{"type":"天文","name":"こいぬ座","rank":"2","desc":"ギリシャ神話の忠犬マイラが天に昇った姿とされる。マイラは、酒神ディオニソスからワイン作りを教わったため、非業の死を遂げた主と娘の墓を死ぬまで守り続けたという。","note":"クエスト「ワインの作法」<br/>発見物カード:150","exp":"300"}],"6161":[{"type":"歴史遺物","name":"長信宮灯","rank":"3","desc":"宮女の姿をかたどった燭台。漢代の中山王劉勝夫妻の墳墓から発見された副葬品の一つでもある。油を燃やして明かりにする。青銅製の像の内部は空洞であり、煙や煤を外に出さないように工夫されている。","note":"","exp":"460"}],"1232":[{"type":"地理","name":"パタゴニア","rank":"3","desc":"南米南部に位置する半島の一帯を指す。マゼランが上陸した際に、この土地に住む民族を「パタゴン」と名づけたことから、「パタゴニア」と呼ばれるようになった。","note":"果てなき荒野","exp":"495"}],"1602":[{"type":"海洋生物","name":"オウムガイ","rank":"4","desc":"鎧姿の人の顔に似た形をしている生物。\n数十もある触手を使ってエサを捕食する。口と思われる場所から水を噴出して、水中を移動する。","note":"美しい巻貝","exp":"624"}],"2515":[{"type":"植物","name":"シマトネリコ","rank":"4","desc":"台湾島やインドに生息する、小さくて白い花を咲かせる植物。特有の芳香を持ち、葉には光沢が見られる。\n秋になると小さな実を付ける。","note":"病弱な母への贈り物","exp":"660"}],"6465":[{"type":"虫類","name":"脱皮したチリアンコモン","rank":"5","desc":"「チリアンコモン」の脱皮直後のとても美しい姿。過酷な地に生息しているため丈夫で強いクモで、毒を持つが比較的おとなしい性質ということもあり、飼育しやすい生物といわれる。脱皮前などしばしば長期的に拒食する性質があるという。","note":"","exp":"1680"}],"1601":[{"type":"虫類","name":"タテヅノカブト","rank":"1","desc":"上下対になった長い角と、きわめて長い前足が特徴。えさ場での争いでは、この前足を振り回して相手を追い払う。","note":"足の長い虫の地図","exp":"180"}],"6743":[{"type":"地理","name":"サオナ島","rank":"3","desc":"イスパニョーラ島のサントドミンゴから南東にある島。コロンブスの２回目の航海で発見されたという。サンゴ礁に囲まれており、鳥類や海洋生物が数多く生息している。透き通るような海と白い砂浜が美しい。","note":"","exp":"1080"}],"1805":[{"type":"財宝","name":"アラベスクの水筒","rank":"1","desc":"マムルーク朝時代に作られた、聖地巡礼者用の水筒。水筒は巡礼者にとって必需品でありながら、工芸品としても素晴らしい。","note":"凝った装飾の地図","exp":"110"}],"1729":[{"type":"財宝","name":"エンジェルハート","rank":"5","desc":"100カラット以上ある巨大なルビー。ルビーは1カラット以上の石が非常に少ないため、この大きさだけでとてつもない価値がある。そのうえ素晴らしい色をしているため、「天使の心臓」と名づけられた。","note":"血色の宝石<br/><br/>発見時経験値1053　発見物カード経験値526","exp":"1053"}],"6628":[{"type":"気象・現象","name":"蜃気楼","rank":"4","desc":"東アジア西部・黄河河口付近。\n水平線の下にあるはずの風景が見える現象。海面上の温度差で光線が屈折することにより発生するといわれる。中国では霊獣の「蜃」が「気」を吐き「楼」閣を出現させるという伝説が残っている。","note":"","exp":"680"}],"1281":[{"type":"歴史遺物","name":"鄭和艦隊の羅針盤","rank":"2","desc":"鄭和は明国に仕える軍人である。永楽帝の命により七度アフリカ方面まで長期航海した。当時は羅針盤の技術も発展段階であり、中国のものは磁石を水に浮かべて使った。","note":"大航海時代の先駆け","exp":"330"}],"3667":[{"type":"宗教遺物","name":"チャスカ像","rank":"4","desc":"アンデス神話に登場する夜明けと夕暮れ、金星の女神の像。若い女性と花を守護するといわれる。","note":"ダンジョン","exp":"700"}],"337":[{"type":"歴史遺物","name":"ヴェルギナの宝物","rank":"4","desc":"アレクサンドロス大王の父・フィリッポス2世のものと思われる墓地から出土した副葬品の数々。装身具や青銅の武具など。","note":"偉業の先駆者","exp":"684"}],"5923":[{"type":"美術品","name":"金細工の版画","rank":"2","desc":"金細工の技術を用いて製作された、当時最先端の版画。ドイツで発明され、細やかな線が用いられているのが特徴。\n印刷技術の普及と共にヨーロッパに広く伝播し、美術史において重要な役割を果たすこととなった。","note":"","exp":""}],"3386":[{"type":"宗教遺物","name":"ニンメシャルラ","rank":"5","desc":"アッカド王国の初代の王・サルゴンの娘であり、ウルの神官でもあるエンヘドゥアンナが著した詩。相次ぐ反乱で国が乱れる中、イナンナ神に助けを求めて記されたとみられる。","note":"メソポタミアの文学者<br/><br/>発見時経験値820　発見物カード経験値410","exp":"820"}],"2366":[{"type":"植物","name":"ヒガンバナ","rank":"1","desc":"東アジアに広く分布する、放射状に花弁を開かせる花。マンジュシャゲとも呼ばれる。毒があり、害虫よけのために植えられることも多い。","note":"火のような花の地図","exp":"100"}],"1920":[{"type":"海洋生物","name":"アマゾン淡水エイ","rank":"2","desc":"アマゾン川に生息する小型の淡水エイ。尾には毒棘を持つ。","note":"釣り","exp":"340"}],"5140":[{"type":"港・集落","name":"ベンゲラ","rank":"1","desc":"大西洋に面し、アフリカ南西に位置する街。近くを流れる海流の影響で、近郊の土地は乾燥している。","note":"到達する","exp":"73"}],"5312":[{"type":"小型生物","name":"レインボーアガマ","rank":"2","desc":"頭から背にかけてが赤色や黄色、背から尾の先までが青色や紫色の奇妙なトカゲ。昼行性で岩場などの開けた場所に生息している。","note":"","exp":""}],"6132":[{"type":"財宝","name":"プサルテリウム","rank":"2","desc":"薄い台形の共鳴箱に24本の弦を張った楽器。指や羽根、ばちで演奏する。古代ギリシャの楽器プサルテリオンが中東からヨーロッパへと伝わったものと考えられる。ビンゲンのヒルデガルトも、師である修道女から演奏法を習っていた。","note":"","exp":"240"}],"5389":[{"type":"財宝","name":"古代エジプトの儀式用剣","rank":"2","desc":"ケペシュと呼ばれる鎌形の剣を儀式用にしたもの。ケペシュは湾曲した刀身の内側に刃があり、相手の盾に引っかけて攻撃するが、儀式用には刃がついていない。","note":"","exp":""}],"537":[{"type":"歴史遺物","name":"土器","rank":"1","desc":"粘土を練って成形し、焼いた器。強度はないが、製作が容易で目的に応じた形にできることから、多くの古代文明で見られる。","note":"古代の道具の地図","exp":"20"}],"7032":[{"type":"地理","name":"ウォルマダニー","rank":"2","desc":"オーストラリア北西部に位置する岬。沿岸沿いに鮮やかな赤色の断崖が広がっており、白い砂浜と青い海との対比が独特かつ美しい景観を生み出している。","note":"","exp":""}],"6018":[{"type":"地理","name":"バージェス頁岩","rank":"5","desc":"北米大陸西部にある堆積層のひとつ。なんらかの生物の骨と思われる、奇妙な石が多数発見されている。","note":"","exp":"950"}],"3320":[{"type":"財宝","name":"リンディスファーンの福音書","rank":"2","desc":"マタイ、マルコ、ヨハネ、ルカによる福音書をまとめた手写本。ケルズの書同様に装飾写本であるが、ラテン語で書かれている。\n制作当時は宝石や貴金属で装丁されていたがヴァイキングによって失われたらしい。","note":"装飾された写本の地図","exp":"340"}],"6484":[{"type":"宗教建築","name":"トゥールーンの螺旋型ミナレット","rank":"5","desc":"カイロにあるイブン・トゥールーン・モスクに建てられた螺旋型のミナレット。同じ螺旋型のミナレットは、世界に3つしか現存しないといわれ、マルウィヤ・ミナレットと共にとても貴重な建造物とされている。","note":"追究クエスト","exp":""}],"1305":[{"type":"大型生物","name":"マレーグマ","rank":"5","desc":"1.5mほどと、クマの中では小型。首の周りの皮膚が緩んでおり、捕食者に背後から襲われたときでも体をくねらせて逃れ、反撃に転じることができる。","note":"子供ほどの小さなクマ","exp":"923"}],"6660":[{"type":"小型生物","name":"アフリカウシガエル","rank":"2","desc":"サハラ砂漠より南のアフリカに生息するカエル。体長20cm以上になるものもある。虫以外に、小動物、鳥までも捕食する。","note":"","exp":"230"}],"5217":[{"type":"歴史遺物","name":"古代マケドニアの金装飾","rank":"2","desc":"金の薄板で飾り付けられた豪華な装飾品。ナラの葉をかたどっている。立体的な装飾はとても繊細で古代マケドニアの技術力がうかがえる。","note":"マケドニア地方　再調査報酬","exp":""}],"5471":[{"type":"鳥類","name":"シロキツツキ","rank":"1","desc":"パンタナル湿原でよく見られるキツツキの一種。\n垂直な木の幹に止まることができるが、キツツキ特有のドラミングをすることはない。","note":"発見時経験値120　発見物カード経験値60","exp":"120"}],"1170":[{"type":"財宝","name":"マリンチェの首飾り","rank":"4","desc":"マリンチェとはコルテスの妻となったアステカ人女性。ナワトル語とマヤ語に通じ、コルテスの通訳として協力した。これは西洋風のデザインで、コルテスが本国から持ち込んだネックレスを贈ったものだと思われる。","note":"コルテスが連れた娘","exp":"612"}],"628":[{"type":"中型生物","name":"トムソンガゼル","rank":"1","desc":"鹿に似た小型の動物。大型の群れを作る。角はあるが短い。全個体に角があるので、オスメス共に角があるのだろう。","note":"鹿に似た動物の地図","exp":"64"}],"1459":[{"type":"小型生物","name":"フクロアリクイ","rank":"1","desc":"アリを餌とする、有袋類。大きな爪のある前足でアリの巣を壊す。","note":"アリを食べる動物の地図","exp":"160"}],"646":[{"type":"地理","name":"サントメ島","rank":"1","desc":"西アフリカ中央部のギニア湾に浮かぶ島。赤道が近い、熱帯雨林気候の島。","note":"書きかけの地図","exp":"105"}],"1737":[{"type":"財宝","name":"輝ける星","rank":"5","desc":"丸く磨き上げられた中に、白い星が見えるルビー。太陽光にあてると浮かび上がるその星は、遠い空の星を封じたものなのかもしれない…。","note":"人を選びし宝石","exp":"1040"}],"6487":[{"type":"宗教遺物","name":"ナラシンハ像","rank":"5","desc":"獣にも人にも殺せぬアスラ族のヒラニヤカシプを討伐するために、ヴィシュヌ神が化身した姿。獅子の頭と人の体を持ち、獣でも人でもない存在としてヒラニヤカシプを討った。ノラシンガは、ナラシンハが元となり伝わったものといわれる。","note":"追究クエスト","exp":""}],"303":[{"type":"美術品","name":"バベルの塔（小）","rank":"1","desc":"ピーテル・ブリューゲル（父）作の、もう一枚のバベルの塔の絵。大きな絵と違い、建築の様子は描かれていない。なぜか全体が強い赤で描かれており、神の怒りで砕かれる前触れを思わせる。","note":"クエスト「もう一枚のバベルの塔」<br/>発見物カード:85","exp":"170"}],"5165":[{"type":"港・集落","name":"モンペリエ","rank":"1","desc":"マルセイユ近郊の小都市。古くから大学があり、特に医学の研究が盛んである。ノストラダムスもモンペリエ大学で医学を修めた。","note":"到達する","exp":"19"}],"705":[{"type":"財宝","name":"セイレーンの竪琴","rank":"4","desc":"歌声で船乗りをまどわせる妖怪・セイレーンのものだという竪琴。金や宝石を多く使った豪華な竪琴であるが、本当にセイレーンのものかどうかは確かめようがない…。","note":"人を惑わせる竪琴","exp":"696"}],"1614":[{"type":"歴史遺物","name":"ラームカムヘーン王碑文","rank":"1","desc":"スコータイ王ラームカムヘーンが書いたとされる碑文。スコータイの当時をしのばせる内容が書かれている。口語で読みやすいので、多くの人に広まった。","note":"英雄の碑文の地図","exp":"140"}],"830":[{"type":"海洋生物","name":"アカウミガメ","rank":"1","desc":"熱帯から温帯にかけて生息する、大型のウミガメ。甲羅は赤褐色。大きな個体では体重が300kgを超える。","note":"暖かな海の大きなカメ","exp":"140"}],"3717":[{"type":"大型生物","name":"フタコブラクダ","rank":"4","desc":"背中のコブが二つのラクダ。ヒトコブラクダと比べ四肢が短く、移動や運搬以外にも様々な用途で重宝されいるという。","note":"コブが二つのラクダ<br/><br/>発見時経験値740　発見物カード経験値370","exp":"740"}],"1494":[{"type":"美術品","name":"デルフトの小道","rank":"2","desc":"フェルメール作の風景画。生涯のほとんどを過ごした故郷デルフトを描いたといわれる。レンガの継ぎ目や扉に付けられたかんぬきなど、細部にわたって写実的に描き込まれている。まるで目に映った情景を切り取ったかのようだ。","note":"生き続ける風景","exp":"280"}],"2019":[{"type":"地理","name":"デセアド岬","rank":"2","desc":"南米大陸南西岸にある岬。この周辺の地形は氷河によって造成されたフィヨルド地形であり、他の地域と大きく異なる。","note":"［勅命］「新大陸西岸進出への道標」<br/>リマ冒険「南米地形調査」","exp":"310"}],"6013":[{"type":"美術品","name":"愛に囚われし心の書","rank":"2","desc":"15世紀フランスの王族ルネ・ト・アンジューガ書いた騎士道物語の装画写本。「愛」いとり憑かれた「心」か囚われの身となった意中の女性を救出するべく旅に出るという内容。美麗な装画と詩で貴夫人たちに人気があるという。","note":"","exp":"345"}],"5650":[{"type":"天文","name":"らしんばん座","rank":"5","desc":"ラカーユが制定した南天の星座のひとつ。羅針盤をかたどっているとされる。この星座の近くにはとも座とほ座があり、それらの位置関係から船のマストにあたるともいわれる。","note":"クエスト「航海に欠かせない星座」<br/>発見物カード:475","exp":"970"}],"2317":[{"type":"地理","name":"金門島","rank":"2","desc":"かつて鄭成功の拠点となっていた島。\n貢糖と呼ばれる、砂糖とピーナッツを原料にした産物が有名。","note":"［勅命］[[献上品の産地調査","exp":"320"}],"910":[{"type":"植物","name":"マドンナリリー","rank":"1","desc":"筒状の美しい花が咲く植物。香りが強い。白いユリは、キリスト教の祭礼で使われる。花粉が服につくと、なかなか取れない。","note":"白い花の地図","exp":"43"}],"1746":[{"type":"財宝","name":"バヒネモ戦士の盾","rank":"5","desc":"ニューギニア島に住むバヒネモ民族が、他部族との闘争の際に使用する盾。かの島には多くの部族が存在し、その間で闘争が絶えなかった。描かれた絵やペイントは、敵対する相手を威圧する。それぞれ民族・部族で描かれるものは違うという。","note":"ニューギニアに住む人々","exp":"910"}],"3269":[{"type":"地理","name":"カラハリ砂漠","rank":"2","desc":"アフリカ南部に大きく広がる砂漠。砂は暗赤褐色であり、水場は少ない。浅い窪地が多く半草原地帯ともいえ、生息動物も多い。","note":"クエスト「荒野の砂漠」<br/>発見物カード:195","exp":"390"}],"6687":[{"type":"歴史遺物","name":"イスタンブールのルーン銘文","rank":"5","desc":"ビザンツ帝国時代にて帝都・コンスタンティノープルに大聖堂が建てられた。その欄干にルーン文字の銘文が残る。\n傭兵として派遣された「ヴァイヤーグ隊」というヴァイキングの末裔が刻んだとされる。","note":"","exp":"1150"}],"6665":[{"type":"歴史遺物","name":"万暦号","rank":"3","desc":"明の貿易船。明代は貿易が盛んで、万暦号も海上貿易に従事していた。陶磁器や茶、シルクなどの交易品を積んでいたと考えられる。マレーシア沖で沈没した。","note":"","exp":""}],"6650":[{"type":"財宝","name":"ヴィーナ","rank":"5","desc":"南インドの伝統的な弦楽器。インド神話に登場する女神・サラスバティーも弾いていたと伝わる。","note":"楽の叡智・心に響く楽器　下","exp":""}],"2499":[{"type":"美術品","name":"狩野元信の風景画","rank":"3","desc":"室町時代の絵師・狩野元信によって描かれた障壁画の一つ。\n唐絵に大和絵の様式を取り入れることで、それまでにない大きな画面の構成が可能となっている。","note":"当代一流の絵画とは","exp":"470"}],"1268":[{"type":"美術品","name":"ウルビーノのビーナス","rank":"4","desc":"ティツィアーノ作。前面に横たわるヴィーナスの視線はこちらに向けられ見る者を挑発するようである。足元で丸まる子犬は従順と貞節を、手に持つバラは愛を象徴している。貴族の館の洋服ダンスを探る侍女が、女神を世俗的に感じさせる。","note":"美の基準","exp":"720"}],"2267":[{"type":"宗教建築","name":"ナンマドール遺跡","rank":"5","desc":"ポンペイ島に存在する謎の建築物。人力では運べそうにない巨大な石が積み上げられ、城壁となっている。\n潮が満ちていないと訪れることができないため「海上都市」とも呼ばれている。","note":"積み石の都","exp":"930"}],"2355":[{"type":"地理","name":"恐山","rank":"2","desc":"東北北部にある山。「山」と呼ばれるが、山そのものの名ではないらしい。\n地元の人々からは信仰の対象として崇められ人間の魂は死後、この山へ行くと伝えられている。","note":"誰もが登る山","exp":"350"}],"3014":[{"type":"史跡","name":"カホキアの土塁","rank":"4","desc":"ミシシッピ川流域に住む人々が築いた、巨大な土塁。土塁の上には身分の高い人物が住んだといわれる。最大のもので、規模はおよそ縦300m、横250m、高さ30mにも及ぶ。","note":"巨大な丘","exp":"640"}],"5695":[{"type":"史跡","name":"ムスタンの洞窟群","rank":"5","desc":"ネパール地方の、とある断崖に掘られた謎の洞窟群。仏教壁画が存在し、宗教的施設だった可能性がある。しかしいまだ解明されていない謎も多く、なんのために掘られたのかを断定することはできない。","note":"2017.02.07新規追加","exp":"1110"}],"544":[{"type":"歴史遺物","name":"石棺","rank":"1","desc":"死者を埋葬する際に使われた石の棺。高貴な人物の棺には精巧なレリーフや彫刻が施されている。","note":"古代の墳墓の地図","exp":"30"}],"6901":[{"type":"美術品","name":"牛乳を注ぐ女","rank":"3","desc":"ネーデルラントの画家フェルメールが描いた油彩絵画。一人の女性が牛乳を器に注ぐ様子が描かれている。厚みのある色彩と柔らかな陰影表現が、絵画全体に静謐な印象を生んでいる。","note":"","exp":""}],"6797":[{"type":"歴史遺物","name":"瀛涯勝覧","rank":"4","desc":"鄭和の航海に随行した馬歓によって書かれた文書。「えいがいしょうらん」と読む。鄭和の航海の航路、寄港した国々の風土などが詳細に記録されている。鄭和を研究する上で、最も重要な文献の一つとされる。","note":"追究クエスト<br/>発見物カード:320","exp":"640"}],"2705":[{"type":"地理","name":"済州海流","rank":"1","desc":"朝鮮半島と済州島の間を流れる海流。\n暖流の対馬海流とつながっているため、海流上に浮かぶ島の気候は暖かい。","note":"書きかけの地図","exp":"140"}],"3621":[{"type":"歴史遺物","name":"ラヴレンチー写本","rank":"3","desc":"14世紀に修道士ラヴレンチーにより転写された、『原初年代記』の写本。\n一部の年代の記録が除かれているが、理由は不明である。","note":"過去が抜け落ちた書物","exp":"550"}],"2040":[{"type":"宗教遺物","name":"アヌケト像","rank":"2","desc":"ナイル川に増水をもたらすといわれている女神の像。\nパピルスの杖と羽つきの冠をかぶったこの女神の恩恵で、エジプトは古代から栄えていたのだろう。","note":"［勅命］[[運河開通を見つめる像","exp":"310"}],"2861":[{"type":"海洋生物","name":"ヨウスコウワニ","rank":"3","desc":"長江の下流域に生息する、体長150cmほどのワニ。河川や湿地など人間の生活環境に近い場所に棲むが、穏やかな性格のため人間を襲うことは少ない。","note":"沙悟浄の原型","exp":"460"}],"4804":[{"type":"財宝","name":"石貨","rank":"4","desc":"ダバオの北東にある島で使われているという石製の巨大な貨幣。大きいなものは直径3mに及ぶ。 その重さから動かすことはできないが、儀礼の際に讓られると所有者だけが変わるようになっている。","note":"巨大な貨幣","exp":"700"}],"471":[{"type":"歴史遺物","name":"コンモドゥス帝の剣","rank":"1","desc":"コンモドゥス帝は、最後の五賢帝マルクス・アウレリウスの息子。暴帝で自らコロッセウムに剣闘士として参加するなどしたという。","note":"血に飢えた暴君","exp":"115"}],"2483":[{"type":"宗教遺物","name":"達谷窟","rank":"3","desc":"読みは「たっこくのいわや」。平安時代の武官・坂上田村麻呂が、戦勝を記念して東北地方に建てた堂。建物の半分が崖に埋まり込んだような、独特の外観を持つ。毘沙門天が祀られている。","note":"崖に埋もれた堂","exp":"520"}],"5825":[{"type":"天文","name":"かんししゃメシエ座","rank":"4","desc":"フランスの著名な天文学者であるシャルル・メシエをモデルとした星座。フランスはともかく、他の国で定着するのであろうか…。","note":"","exp":"690"}],"1627":[{"type":"鳥類","name":"オカメインコ","rank":"2","desc":"長い冠羽と眼の下にあるオレンジ色の毛が特徴の鳥。冠羽は状況により立ったり寝たりする。","note":"珍しい鳥はいないか<br/><br/>発見時経験値320　発見物カード経験値160","exp":"320"}],"6212":[{"type":"歴史遺物","name":"マルス号","rank":"4","desc":"スウェーデンで建造された軍艦。バルト海でデンマーク、ドイツと激しい戦闘を行った際に大砲が暴発し、そのまま沈没した。","note":"サルベージ","exp":"650"}],"4836":[{"type":"鳥類","name":"ワライフクロウ","rank":"2","desc":"忍び笑いや口笛のような変わった鳴き声が特徴の鳥。かつては特に珍しくなかったが、生息環境の変化によってか急速に数を減らしており、絶滅が心配される。","note":"変わった鳥の地図","exp":"290"}],"5604":[{"type":"天文","name":"ろ座","rank":"1","desc":"ラカーユが制定した星座のひとつ。フラスコを加熱する炉をモデルとしている。","note":"「天文学者の観測記録」<br/>発見物カード:75","exp":"150"}],"5388":[{"type":"レリック","name":"ポセイドン神殿に眠る宝","rank":"","desc":"","note":"","exp":"2410"}],"6595":[{"type":"宗教建築","name":"ボジャナコンダ","rank":"2","desc":"ヴィシャーカパトナムから少し離れた丘の上にある仏教遺跡。岩を切り出して作られた岩窟がいくつかあり、内部には座する仏像が祀られている。隣接する丘の上にはリンガラコンダという仏教遺跡もある。","note":"","exp":"350"}],"1277":[{"type":"地理","name":"ルソン島","rank":"2","desc":"東南アジアでも特に北東に位置している島。インド、アラブとの交易で栄えた。山がちな島ではあるが、農作物は多様で豊かである。","note":"イスパニア縁の地","exp":"330"}],"143":[{"type":"歴史遺物","name":"クレオパトラの香水瓶","rank":"2","desc":"絶世の美女と伝えられるクレオパトラ7世が使っていた香水瓶。古代エジプトでは、さまざまな香油や香水が使われていたという。","note":"クレオパトラの化粧","exp":"300"}],"1295":[{"type":"小型生物","name":"ヒヨケザル","rank":"5","desc":"首から手足、尾まで皮膜に覆われたサル。\n指先にある皮膜を使って木から木へ滑空し、時には100m以上もの距離を飛ぶ。","note":"空飛ぶネコ<br/><br/>発見時経験値949　発見物カード経験値474","exp":"949"}],"3694":[{"type":"財宝","name":"スコモローフの仮面","rank":"5","desc":"ロシアで活動する芸人たちを、「スコモローフ」と呼ぶ。彼らはこの仮面を被り、楽器を奏でて詩を歌い、人々に娯楽を提供していたという。","note":"師匠が遺した物","exp":"1110"}],"2598":[{"type":"宗教遺物","name":"曼荼羅図","rank":"3","desc":"読み方は、「まんだらず」。古代インドを起源とする、日本の宗教絵画の一つ。\n曼荼羅とは、仏教の世界観を表現したものである。この図では、阿弥陀如来を中心とした極楽浄土の様子が描かれている。","note":"仏界の絵図","exp":"480"}],"3762":[{"type":"天文","name":"みずがめ座","rank":"5","desc":"黄道十二星座の1つ。オリンポス十二神に不死の酒ネクタルを給仕するガニュメデスの姿とされる。古代メソポタミアでは水の神エンキにつながる、水が流れ出る壷を持った男の姿で描かれ、偉大なるものという意味のグラと呼ばれていた。","note":"クエスト「宝瓶宮の調査」<br/>発見物カード:510","exp":"1020"}],"1622":[{"type":"宗教建築","name":"ギザのスフィンクス","rank":"2","desc":"ギザのピラミッドの側に鎮座する巨大な像。ファラオの顔とライオンの体をもつ。古代エジプトでは、ファラオの偉大さを体現した存在とされる。\n一方、ギリシャ神話では、女性の顔と獅子の体、鷲の翼をもつ怪物とされている。","note":"神か怪物か","exp":"230"}],"3541":[{"type":"レリック","name":"もう一人のジャンヌ","rank":"","desc":"ブルゴーニュ軍の旗を奪ってボーヴェを救った勇敢な少女は、奇しくもラ・ピュセルと同じジャンヌという名だったという。","note":"ジャンヌ・アシェットの斧　入手","exp":""}],"2799":[{"type":"化石","name":"カメのようなドラゴンの骨","rank":"1","desc":"カメのような体格をした生物の骨で、泉州近辺で見つかった。\n腹部が大きく膨れており、甲羅を背負っているように見える。","note":"不気味な形の骨の調査","exp":"200"}],"3924":[{"type":"天文","name":"さんかく座の渦巻星雲","rank":"2","desc":"さんかく座から少し西にある、渦巻きの形をした星雲。淡く広がっているため、肉眼で見ることは難しいといわれる。","note":"天文学者の観測記録<br/>発見物カード:120","exp":"240"}],"1717":[{"type":"海洋生物","name":"ノコギリザメ","rank":"2","desc":"目から口先までが細長く、縁に大小の突起がノコギリ状に付いているサメ。主に暖かい海の海底に生息し、泥中に細長い口先を潜らせてエサを採る。攻撃的な外見の割に、性格はおとなしい。身は大変美味。","note":"釣り","exp":"260"}],"650":[{"type":"地理","name":"ポーク海峡","rank":"2","desc":"セイロンとインドの間にある海峡。セイロンは特産物が多く交易が盛んなので、この海峡は船の行き来がとても多い。","note":"書きかけの地図","exp":"260"}],"5640":[{"type":"気象・現象","name":"カタトゥンボの灯台","rank":"3","desc":"マライボ湖の周辺で見られる、雷を伴う激しい嵐。しかし、落雷の音は聞こえず無音だという。この雷の光は、近隣の航海士に灯台の代わりとしても活用されているようだ。","note":"曇りの夕方から夜間にかけて出現。","exp":"583"}],"6115":[{"type":"伝承","name":"ケサラン・パサラン","rank":"4","desc":"動物なのか植物なのか不明、生態も不明、名前の語源も判然としないという、謎の生物。その毛玉のような外見と、所有者に幸福が訪れるという噂だけが、伝承として伝えられている。","note":"","exp":"630"}],"1897":[{"type":"歴史遺物","name":"アン号","rank":"1","desc":"ペロポネソス半島沖で難破した貿易船。\nヤッファに巡礼者を送り届けた後、イングランドへの帰路で難破した。","note":"サルベージ","exp":"130"}],"1231":[{"type":"小型生物","name":"チスイコウモリ","rank":"2","desc":"血液のみを餌にするコウモリ。眠っている動物に噛み付き、傷口から流れ出る血液をなめとる。昼間は洞窟などに身を潜め、闇夜になると餌を求めて活動する。","note":"闇夜に舞い降りる影<br/><br/>発見時経験値205　発見物カード経験値102","exp":"205"}],"258":[{"type":"財宝","name":"ピンクダイヤ","rank":"3","desc":"ピンク色のダイヤモンド。透明度が高く、色が美しいほど高い価値がある。","note":"ピンクの宝石の鉱脈の地図","exp":"590"}],"831":[{"type":"美術品","name":"モーゼ","rank":"1","desc":"ミケランジェロ作の大理石像。ユリウス2世の墓のために作られた像の一つである。十戒の石板を抱え、緊張した表情で遠方を見つめている。","note":"男性像の地図","exp":"120"}],"5512":[{"type":"財宝","name":"アイオロスの球","rank":"5","desc":"世界最古といわれる蒸気機関。アレクサンドリアのヘロンなどが記述を残している。熱を加えると、蒸気を噴射して回転する。","note":"最古の蒸気機関","exp":"1020"}],"1488":[{"type":"鳥類","name":"ヒオウギインコ","rank":"1","desc":"熱帯林に生息する鳥。興奮したり驚いたりすると、頭部全体の羽を扇状に逆立てる。","note":"扇のある鳥の地図","exp":"135"}],"5871":[{"type":"海洋生物","name":"ヨウジウオ","rank":"5","desc":"日本近海に生息する、細長い口と体が特徴の魚。細長い体は海藻などの隙間に隠れるためのものと思われる。雄が雌の代わりに出産を行う特徴がある。食用には向かない。","note":"","exp":"1360"}],"162":[{"type":"海洋生物","name":"サンゴ","rank":"1","desc":"熱帯の海で広く見られる美しい生物。一見植物のようだが、近くでよく見ると、ごく小さいイソギンチャクのようなものがびっしりと並んでいる。地元の人間に聞くと、ゆっくり成長するそうだ。","note":"サンゴの採れる海域の地図","exp":"15"}],"87":[{"type":"歴史遺物","name":"死者の書","rank":"1","desc":"古代エジプトで埋葬の際に一緒に棺に入れられた、死者のための呪文書。これを死者に持たせれば、死後のオシリス神の審判で無罪になると考えられた。","note":"エジプトの古文書の地図","exp":"34"}],"6805":[{"type":"地理","name":"オプティミスティチナ洞窟","rank":"3","desc":"黒海北西にある巨大な洞窟群。世界で最も長い石膏洞窟とされる。洞窟同士が複雑につながっており、「洞窟の迷路」とも呼ばれる。洞窟内の温度は一定に保たれ、鍾乳石や色づいた巨大な水晶など、美しく神秘的な地下世界が広がる。","note":"発見物カード：205","exp":""}],"3318":[{"type":"史跡","name":"ハドリアヌスの長城","rank":"5","desc":"ローマ帝国の時代に、皇帝ハドリアヌスの命により築かれた防塁。帝国領土への、ケルト人の侵入を阻止することが目的とされる。\n10年もの歳月をかけ、110km余りの距離にわたって建設された。","note":"ローマ帝国の政策転換","exp":"950"}],"6513":[{"type":"財宝","name":"オリーブ冠","rank":"5","desc":"オリンピア大祭で各競技の優勝者に与えられた冠。特別なオリーブの若木を編んで作られている。参加者は、この冠と名誉だけを賞品として競い合った。その精神に敵対していたペルシャ人たちも感嘆したと伝わる。","note":"レガシー競技の聖地オリンピア　左下","exp":"2145"}],"6068":[{"type":"鳥類","name":"キタヒメキンメフクロウ","rank":"1","desc":"北米に生息するフクロウで、その名のとおり小さな体と金色の目が特徴。人里の近くでも見られ、低木や藪を住みかにする。ネズミを捕らえて食べるため、人々の間では益鳥とされてるようだ。","note":"","exp":"190"}],"6647":[{"type":"伝承","name":"ケルベロス","rank":"5","desc":"ギリシャ神話に登場する、冥府の番犬。三つの頭を持ち一つが眠っている間、他二つの頭が見張りにつく。冥府の入口を固く守り、亡者の冥界からの逃走を決して見逃さないという。","note":"冥府の番犬の伝承","exp":"990"}],"484":[{"type":"宗教遺物","name":"ダルマの石柱","rank":"4","desc":"ダルマとは、古代インドのサンスクリット語で「法」を意味する。宇宙の法則、真理のことであるが、仏教では根本的概念とされた。この石柱は仏教に帰依したアショーカ王が、領土に建てたものだとされている。","note":"古代インドの「法」","exp":"684"}],"2718":[{"type":"虫類","name":"ウスリーオオカミキリ","rank":"1","desc":"主に朝鮮半島に生息する、大型のカミキリムシ。大きなものは10cmを超える。\nアカシデという木に寄生し、夏に見られる。","note":"珍しい虫の地図","exp":"170"}],"2560":[{"type":"鳥類","name":"サンケイ","rank":"5","desc":"台湾島に生息する大型の鳥。雄の体長は、約70cmほどある。\n警戒心が強く、めったに姿を現さない。","note":"台湾島の鳥調査をもう一度","exp":"1250"}],"952":[{"type":"美術品","name":"キリストの復活","rank":"2","desc":"ジェルマン・ピロン作の大理石像。処刑後、復活したキリストの姿を表したもの。本来は数体の彫像からなる作品のはずだが、未完成のままだという。","note":"復活したイエスの彫刻","exp":"290"}],"5879":[{"type":"地理","name":"ロンブク氷河","rank":"1","desc":"ヒマラヤ山脈のふもとに流れる氷河。この氷河を遡上していくことで、遥かチョモランマの高みまでたどりつける...。かもしれない。","note":"","exp":"140"}],"6519":[{"type":"植物","name":"ヒスイカズラ","rank":"5","desc":"ルソン島に自生するツル植物。ひすいのような美しい青緑色の花を咲かせる。上向きの爪のような形の花が多数付いている。ひすい色の花は他に類を見ないという。ごく限られた地域ににのみ自生しているらしい。","note":"","exp":"1000"}],"3018":[{"type":"歴史遺物","name":"アデナのパイプ","rank":"1","desc":"北米のオハイオ川近辺で見つかった、古代のパイプ。紀元前の農耕文化の遺物とされる。タバコが吸われていた事実を示すものとしては、かなり古いといえる。","note":"古代のパイプの地図<br/><br/>発見時経験値150　発見物カード経験値75","exp":"150"}],"1115":[{"type":"中型生物","name":"ホッキョクギツネ","rank":"4","desc":"鼻を除いた体全体が密な毛で覆われている。ホッキョクギツネには二つの毛色があり、冬毛は雪や氷に溶け込むような純白、夏毛は冬の厚さの半分で灰色をしている。","note":"白いコート","exp":"648"}],"5790":[{"type":"歴史遺物","name":"細石刃","rank":"1","desc":"打製石器の一種。柄になるものと組み合わせられ、交換できる穂先として用いられた。世界各地の広い範囲で出土しているようだ。","note":"","exp":""}],"510":[{"type":"歴史遺物","name":"貝貨","rank":"1","desc":"貨幣として扱われた、タカラガイなどの殻。古代文明の多くで使われ、各地の遺跡から出土する。","note":"古代の貨幣の地図","exp":"13"}],"2722":[{"type":"海洋生物","name":"シュリ","rank":"4","desc":"朝鮮の河川に生息する淡水魚。\nつがいの片割れが死ぬと、自分もそのあとを追って死ぬという、不思議な習性を持つ。","note":"朝鮮の美しい魚","exp":"690"}],"3509":[{"type":"レリック","name":"アーサー","rank":"","desc":"吟遊詩人たちに愛される、イングランドの伝説の王、アーサー。アーサーが眠るアヴァロンを再び訪れることはあるのだろうか。","note":"","exp":""}],"5508":[{"type":"港・集落","name":"ルアーブル","rank":"1","desc":"フランス北部の港湾都市。セーヌ川の河口に位置する。貿易で栄えている。","note":"座標　16258,2576","exp":"16"}],"5085":[{"type":"港・集落","name":"セヴァストポリ","rank":"1","desc":"黒海に面し、クリミア半島に位置する港湾都市。","note":"到達する","exp":"42"}],"5130":[{"type":"港・集落","name":"フローニンゲン","rank":"1","desc":"ネーデルラント北部に位置する街。ネーデルラント内の数少ないハンザ同盟都市。","note":"到達する","exp":"12"}],"1214":[{"type":"海洋生物","name":"オウサマペンギン","rank":"3","desc":"大型のペンギン。水中に長時間潜ることができ、深いところで魚やイカなどを捕らえる。繁殖期には数千のつがいが集団となる。","note":"セバルド島のさらなる調査<br/><br/>発見時経験値500　発見物カード経験値250","exp":"500"}],"6775":[{"type":"宗教建築","name":"ロスキレ大聖堂","rank":"4","desc":"デンマークのシェラン島にある大聖堂。ロマネスクとゴシックの混合様式で、外壁はレンガ造りになっている。10世紀にハーラル青歯王が建てた木造の教会が始まりとされ、デンマーク歴代の王の棺が安置されている。","note":"発見物カード:380","exp":"760"}],"6152":[{"type":"海洋生物","name":"イワシクジラ","rank":"5","desc":"太平洋、大西洋、インド洋などに広く生息するクジラ。甲殻類や魚類などを食べる。他のクジラに比べて体が細長く、動きが敏捷であるせいか、広い海域に生息している割には目撃例が少ない。","note":"クエスト「魚かクジラか」<br/>発見物カード:620","exp":"1240"}],"6486":[{"type":"歴史遺物","name":"メデューサの彫刻","rank":"5","desc":"メデューサをかたどった大理石彫刻。門や建物の入り口上部に掲げたと考えられる。ギリシャ神話に登場するメデューサは蛇の髪と恐ろしい顔を持つ怪物とされるが、古代アナトリアでは大地の女神だったという説もある。","note":"レガシー女神信仰の地エフェソス　下","exp":"2700"}],"2571":[{"type":"中型生物","name":"バイカロク","rank":"3","desc":"台湾島に多く生息するシカ。梅の花に似た白い斑点が体にあることからバイカロク（梅花鹿）と呼ばれる。\n古来、角や鹿皮が珍重されており、狩猟の対象となっていた。","note":"鹿皮の持ち主","exp":"540"}],"6688":[{"type":"天文","name":"ドゥーべ","rank":"3","desc":"おおぐま座アルファ星で、おおぐま座で最も明るい２等星。北斗七星のひしゃくの先端にあたる。ベータ星メラクと合わせて北極星を探す手がかりとなる。","note":"発見物カード:275","exp":"550"}],"5463":[{"type":"地理","name":"パンタナル湿原","rank":"1","desc":"パラグアイ川上流に位置する広大な湿原。\n雨季には川が氾濫し、全体の八割近くが水没してしまうという。\n過酷な自然環境に見えるが、この大地の変化が豊かな土壌を育み、数多くの動植物の生態系を支えている。","note":"","exp":"60"}],"2053":[{"type":"歴史遺物","name":"オストラコン","rank":"4","desc":"文字や絵が描いてある陶器の破片。ギリシャ語で「陶片」の意味を持つ。独裁者を追放するための投票に用いられた。この制度により当時のアテネが衰退したとの見方もある。","note":"追放の欠片","exp":"660"}],"6963":[{"type":"史跡","name":"シリア北部の古代村落群","rank":"1","desc":"古代ローマ時代からビザンツ帝国時代にかけてシリア北部に存在した村落の遺跡。「忘れられた街」とも呼ばれる。豊かな農業生活を示す施設や、教会、防塁などが多く残されている。","note":"発見物カード:100","exp":"200"}],"1322":[{"type":"地理","name":"メコン川","rank":"3","desc":"ヤーデイン近郊を流れる大河。その水源ははるか北の山岳奥地らしいが、途方もなく長い川であり調査は難航するだろう。全般的に水深が浅く、遡上には向かない河川のようだ。","note":"怪奇が潜む川","exp":"462"}],"3012":[{"type":"歴史遺物","name":"ヘッドポット","rank":"3","desc":"北米のミシシッピ川付近で発見された人間の顔をかたどったつぼ。様々な表情のものがあるが、そのほとんどが顔に刺青のような文様が刻まれ、耳には穴が開けられている。","note":"顔をかたどるつぼ","exp":"540"}],"5887":[{"type":"大型生物","name":"ジプシーバナーホース","rank":"5","desc":"イングランド原産の馬で、小柄ながら力が強いため馬車などに古くから用いられてきた。たてがみや尾などの毛が長く、足首にも同様の毛が生えている。性格は比較的温厚。","note":"","exp":"1430"}],"5062":[{"type":"港・集落","name":"サンジョルジュ","rank":"1","desc":"西アフリカのギニア湾に面した街。この付近はオヨ王国やダホメー王国が栄え、交易も盛んである。内陸から運ばれてきた豊かな資源が流通している。","note":"到達する","exp":"79"}],"2870":[{"type":"海洋生物","name":"ミナミイシガメ","rank":"1","desc":"中国の広い地域に分布する夜行性のカメ。日中は水底の泥や穴の中で過ごす。\n他の個体に噛み付くなど、攻撃性の強い一面が見られる。","note":"小さなカメの地図","exp":"170"}],"3613":[{"type":"植物","name":"アキー","rank":"4","desc":"西アフリカが原産の樹木。赤い果実を実らせる。未熟な果実には毒があるため、原産地ではほとんど食べられないが、持ち込まれた先のジャマイカでは食材として好まれている。","note":"人気な毒の実","exp":"730"}],"1978":[{"type":"大型生物","name":"クアッガ","rank":"3","desc":"南アフリカの乾燥地域に生息。体の前半分にシマウマのような模様がある。腹部から後ろ半分は褐色で、四肢は白い。特徴的な鳴き声を模してその名が付いた。以前はサバンナを覆うほどの数がいたそうだが、開拓者の入植以降、減少している。","note":"半分だけがシマウマ<br/><br/>発見時経験値600　発見物カード経験値300","exp":"600"}],"3786":[{"type":"天文","name":"アルデバラン","rank":"3","desc":"おうし座で最も明るいオレンジ色の星。星座図では、牡牛の目にあたる。オリオンのベルトを成す3つの星を結んだ線を右に伸ばした位置にある。占星術では富の幸福の前兆とされる。冬のダイヤモンドの一角。","note":"視認","exp":"450"}],"3655":[{"type":"史跡","name":"リューリクの墓","rank":"5","desc":"『原初年代記』によると、リューリクはロシア帝国の基盤となる最初の国家を建設したという。元はヴァイキングであったようだ。彼は死ぬまで人々の指導者として、国家を統治したらしい。","note":"ロシアの始まり","exp":"1100"}],"2014":[{"type":"歴史遺物","name":"伝説のカヌー","rank":"5","desc":"ハワイキからアオテアロアに移住するために用いられたカヌーといわれている。相当古い状態で保存されているので、もしかすると本当にクペたちが移住するために乗ってきたカヌーかもしれない。","note":"伝説のカヌー","exp":"1196"}],"1836":[{"type":"宗教遺物","name":"エメラルド仏像","rank":"5","desc":"ひすい製の仏像。その来歴は、落雷で破壊された仏塔から出現したといわれているが定かではない。総ひすい製だが輝きがまるでエメラルドのようなので、やがてエメラルド仏と呼ばれるようになったという。","note":"神雷がもたらすもの","exp":"1144"}],"1819":[{"type":"財宝","name":"留めピン","rank":"1","desc":"女性のケープ、ショールなどを留める金製のピン。高貴な身分の人物が身に付けたピンは装飾も豊かで芸術性に富む。","note":"精巧な加工の地図","exp":"140"}],"159":[{"type":"海洋生物","name":"シュモクザメ","rank":"1","desc":"ハンマーのような、独特の頭部をしたサメ。性質は凶暴で、人が襲われることもある。目が両側に張り出しているため、他のサメより視野が広く、さらに危険だという。","note":"サメの生息地調査","exp":"30"}],"627":[{"type":"中型生物","name":"インパラ","rank":"1","desc":"ねじれた長い角を持った、鹿のような動物。角は鹿のように枝分かれしていない。群れで生活し、跳ねるように走る。","note":"鹿に似た動物の地図","exp":"57"}],"284":[{"type":"鳥類","name":"ホロホロチョウ","rank":"2","desc":"斑点のある羽と骨質のとさかが特徴。古くから食用として家禽（かきん）化された。自然界ではアフリカ熱帯域の開けた草原に生息しており、群れを作って生活している。","note":"ホロホロチョウの羽","exp":"340"}],"2509":[{"type":"鳥類","name":"ヤマムスメ","rank":"3","desc":"台湾島にのみ生息する大きな鳥。赤いくちばしと縞模様の長い尾、青い体が特徴的。飛ぶと、尾にある二枚の長い羽がひらひらと揺れる。","note":"ひらり揺れる尾羽","exp":"530"}],"6036":[{"type":"宗教建築","name":"アトス山の修道院群","rank":"4","desc":"サロニカの東にあるアトス半島とアトス山の一帯にある修道院群。規模の大きな修道院や修道士が独りで暮らす小屋が集まって成立している。生神女マリアが守護聖人だが女性の入山は認められておらず、男性しか立ち入ることができない。","note":"","exp":"750"}],"6105":[{"type":"宗教遺物","name":"フランシスコ・ボルハのロザリオ","rank":"3","desc":"イエズス会の第3代総長、フランシスコ・ボルハが生前持っていた簡素なロザリオ。彼はチェーザレ・ボルジアを大伯父に持ち、神聖ローマ皇帝カール5世のもとでひとかどの地位を得ていたが、そのような人物の所持品には到底見えない。","note":"クエスト「奇しき縁」<br/>発見物カード:235","exp":"470"}],"5069":[{"type":"港・集落","name":"ザンジバル","rank":"1","desc":"東アフリカに浮かぶ島にある街。アフリカとアラビア・インドとの交易の中継点として栄えている。農作物のほか、貴金属や宝石が産出する。","note":"到達する","exp":"76"}],"368":[{"type":"宗教遺物","name":"パルテノンのアテナ像","rank":"5","desc":"かつてパルテノン神殿に収められていた、アテナ像の一部。高さ10m以上の木像で、肌の部分はすべて象牙でおおわれ、衣服や装飾は金細工で埋め尽くされていたという。オスマンに支配された際に分解されて売り払われたと思われる。","note":"クエスト「乙女の部屋の守り手」<br/>発見物カード:550","exp":"1157"}],"533":[{"type":"歴史遺物","name":"彩文土器","rank":"1","desc":"「さいもんどき」。文様を描いた土器。多くの古代文明で作られ、色や文様にそれぞれ特徴がある。文様を研究すれば、文明間の交流が解明できると思われる。","note":"古代の道具の地図","exp":"27"}],"5250":[{"type":"天文","name":"ヘルクレス座","rank":"5","desc":"ギリシャ神話の勇者、ヘラクレスが死後に天に昇った姿といわれる星座。こと座とかんむり座の間にある、かなり大きな星座だが、あまり明るい星はない。","note":"クエスト「勇者の最後」<br/>発見物カード:465","exp":"930"}],"3006":[{"type":"地理","name":"モシ・オ・トゥニャ","rank":"4","desc":"アフリカ大陸の南部に位置する大滝。\nモシ・オ・トゥニャとは現地の言葉で「雷鳴轟く水煙」という意味である。その名のとおりに、水量が増える雨季には雷鳴のような水音を轟々と響かせる。","note":"轟く雷鳴","exp":"750"}],"263":[{"type":"地理","name":"ガスコーニュ湾","rank":"1","desc":"フランスの西部に広がるビスケー湾の、南東部である。イスパニアとフランスの国境に接している。","note":"フランス西部の湾","exp":"20"}],"789":[{"type":"宗教建築","name":"コナーラク太陽神寺院","rank":"2","desc":"太陽神スーリヤを祀る寺院。寺院全体がスーリヤの乗る馬車に見立てられている。ガンガ朝のナラシンハ・デーヴァ1世がイスラム教徒との戦いに勝利した記念に建造したと言われている。","note":"太陽神を祀る寺院","exp":"260"}],"6389":[{"type":"中型生物","name":"ハイイロギツネ","rank":"2","desc":"北米から南米にかけて生息するキツネ。灰色の体毛が特徴的。木登りが上手であり「キノボリギツネ」とも呼ばれる。夜行性で昼間は巣穴などで生活する。","note":"","exp":"250"}],"2410":[{"type":"宗教遺物","name":"トト像","rank":"3","desc":"古代エジプトの神の一つ。死者の審判において、アヌビスとともに死者の罪を量り、是非の判断を下す。死者の名前の一覧を持っており、神々の書記とも呼ばれる。ヒエログリフの発明者ともされる。","note":"ダンジョン","exp":"410"}],"1952":[{"type":"植物","name":"トパトパ","rank":"1","desc":"細長い茎先に、小さな巾着状の花が２つついている植物。南米大陸のパタゴニアに生息。","note":"袋状の植物の地図","exp":"140"}],"5731":[{"type":"宗教遺物","name":"三賢者の贈り物","rank":"5","desc":"東方の三賢者がイエス誕生を祝して送ったとされる贈り物。黄金、乳香、没薬であるとされ、三つそれぞれがイエスの王権、神性、受難を表している。","note":"2017.02.07新規追加","exp":"1440"}],"1632":[{"type":"中型生物","name":"レッサーパンダ","rank":"2","desc":"インドから東南アジアの山林に生息。褐色の体毛で、四肢や腹は黒く、顔には白い模様、尾はふさふさしていて輪状の縞がある。木登りが得意で、昼は樹上で寝ている。パンダの名称は、現地の言葉の「竹を食べる者」からきている。","note":"竹を食べる者","exp":"360"}],"6033":[{"type":"美術品","name":"ナンタケット・バスケット","rank":"1","desc":"北米にあるナンタケッタ島の漁民たちに伝わる籠細工。鯨油の樽を作る技術を応用した製法で作られている。左右対称の形状と、木材を編んでいるとは思えないほどの緻密な網目が特徴的。最初期は蓋のないバスケットが主だったという。","note":"北米の籠の地図<br/><br/>発見時経験値160　発見物カード経験値80","exp":"160"}],"3925":[{"type":"天文","name":"りょうけん座の渦巻星雲","rank":"4","desc":"りょうけん座にある渦巻き型の星雲。肉眼では見えないものの、望遠鏡で観測すると恒星との明確な違いに気がつく。","note":"「天文学者の観測記録」<br/>発見物カード:135","exp":"270"}],"6250":[{"type":"宗教建築","name":"サンティアゴ大聖堂","rank":"1","desc":"正式名は「サンティアゴ・デ・コンポステーラ大聖堂」といい、フランスからイベリア半島におよぶ「聖ヤコブの巡礼路」の終着点にあたる。\n伝承によればキリストの弟子である使徒ヤコブの遺体が安置されているという。","note":"","exp":"180"}],"5850":[{"type":"美術品","name":"アフリカの仮面","rank":"5","desc":"アフリカの民族が祭儀に用いる仮面。民族ごとに造形や意味合いが様々に異なる。","note":"","exp":"1340"}],"1665":[{"type":"宗教建築","name":"ラノ・ララク","rank":"3","desc":"ラノは「火山」、ララクは「地面を削る」という意味。火山のすそので像を作っていた場所。付近では作りかけの像がたくさん見られる。","note":"ハワイキを探して","exp":"484"}],"2791":[{"type":"虫類","name":"ヨコヅナサシガメ","rank":"2","desc":"中国から東南アジアにかけて分布する虫。大木の樹幹に集団で生息する。\n他の昆虫に細長い口を突き刺して体液を吸いとる。人間も刺される場合があり、注意が必要。","note":"鮮紅の虫探し","exp":"310"}],"763":[{"type":"植物","name":"カーネーション","rank":"1","desc":"ひだの多い花が咲く植物。よい香りがする。園芸用の植物として品種改良もされている。","note":"赤い花の地図","exp":"12"}],"3256":[{"type":"財宝","name":"ジャンベ","rank":"3","desc":"西アフリカ一帯で演奏されている楽器。ジェンベとも呼ばれる。\n鼓面の直径は約30cm、胴の深さは約60cmの、片面の太鼓である。\n両脚に挟んで素手で叩き、その手の形と叩く位置によって、高音から低音まで多様な音を出すことができる。","note":"対話する音色","exp":"500"}],"2682":[{"type":"地理","name":"済州島","rank":"2","desc":"朝鮮半島の南に位置する島。過去に独自の王朝があったとされる。朝鮮半島では見られない文化も存在するようである。","note":"火山のある島","exp":"340"}],"3773":[{"type":"美術品","name":"バイユーのタペストリー","rank":"3","desc":"フランス北部の街バイユーに伝わるタペストリー。70mに及ぶ布にノルマンディー公ウィリアムによるイングランド征服の様子が刺繍されている。彗星と思われる星を見て不安がるイングランドの人々も描かれている。","note":"彗星の記録","exp":"490"}],"2946":[{"type":"財宝","name":"青龍偃月刀","rank":"5","desc":"中国・後漢の武将、関羽が使ったといわれる長柄の武器。刃に大きな龍が刻み込まれている。偃月刀の形ができあがったのは明の時代で、実戦より演舞向きの武器だった。実際にこれを関羽が扱ったとは考えにくいが…。","note":"歴史小説における証明","exp":"1120"}],"5924":[{"type":"史跡","name":"エルミナ城","rank":"3","desc":"アフリカとの交易を保護する、という目的でポルトガルにより建設された城。かの地は黄金海岸と称されるほどの金の産出量を誇り、この城も交易において大きな役割を果たしていた。","note":"","exp":"600"}],"2362":[{"type":"鳥類","name":"ウグイス","rank":"4","desc":"東アジアに分布する小鳥。春先から夏にかけて魅力的な鳴き声を響かせるため、春を告げる鳥とも呼ばれる。\n声の美しさに反して、羽色は地味。警戒心が強いため、姿を見せることはなかなかない。","note":"美声の主","exp":"620"}],"38":[{"type":"歴史遺物","name":"カエサルの鎧","rank":"3","desc":"ユリウス・カエサルの鎧。刻まれた多くの傷は、ガリアを平定している際のものか、それともルビコン川を渡ってローマを占拠したときのものであろうか。","note":"アレクサンドリア戦役","exp":"440"}],"5815":[{"type":"気象・現象","name":"ウィル・オ・ウィスプ","rank":"4","desc":"夜の湖畔や墓場などに現れるという怪光。色は青、緑など複数の報告がある。名前は、悪行を重ねて死んだ男の魂が現世をさまよっているという伝承に由来している。","note":"","exp":"620"}],"5044":[{"type":"港・集落","name":"カーボヴェルデ","rank":"1","desc":"西アフリカのヴェルデ岬から西にある諸島。もとは無人島で、ヴェルデ岬にちなんで名づけられた。意味は「緑の岬」である。自然環境が厳しく、産業は漁業が中心である。周辺の海からサンゴが採れるようだ。","note":"到達する","exp":"69"}],"3842":[{"type":"大型生物","name":"ミュールジカ","rank":"2","desc":"北米西部に生息するシカ。ミュールとは英語でラバを表す単語で、耳がラバに似ているためこの名で呼ばれている。枝分かれする大きな角が特徴で、この角はオスしか生えない。","note":"立派な角を持つシカ","exp":"350"}],"2310":[{"type":"小型生物","name":"カエルクイコウモリ","rank":"2","desc":"中米の熱帯雨林に生息するコウモリで、その名のとおりカエルを捕食する。カエルの鳴き声で毒を持つか持たないかさえ判断してしまう能力は、頭より大きな耳のおかげだろう。","note":"［勅命］[[現地における生物の調査","exp":"310"}],"3601":[{"type":"地理","name":"グレートブルーホール","rank":"5","desc":"大昔からある、海に空いた穴だ。どうやら浅瀬の底が、その部分だけぽっかりと穴が空いたように深くなってしまっているため海の色が濃く見えてしまうのだろう。一体、この穴はどこまで繋がっているのだろうか…。","note":"海に潜む宝石","exp":"1050"}],"131":[{"type":"宗教遺物","name":"聖母のステンドグラス","rank":"1","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40"}],"3314":[{"type":"地理","name":"アイラ島","rank":"2","desc":"ブリテン島北部、西側にある島。海流の影響を受け、本島より気候が穏やかである。","note":"書きかけの地図","exp":"250"}],"757":[{"type":"財宝","name":"ブロンズの女性像","rank":"1","desc":"青銅の女性像。それほど古いものではないようだ。ギリシャ風の美しい像である。","note":"青銅の女性像の地図","exp":"57"}],"1775":[{"type":"地理","name":"パナマ湾","rank":"2","desc":"パナマ地峡の南部に広がる湾。地峡の北にはメキシコ湾・カリブ海が広がる。この地峡をうまく通り抜ける手段があれば、南北の往来が賑わうのだが…。","note":"クエスト「近場の漁場」<br/>発見物カード:150","exp":"300"}],"1206":[{"type":"鳥類","name":"オオハシ","rank":"4","desc":"黄色い大きなくちばしが特徴。大きいもので15cm以上にもなり、体重を支えきれない小枝の先の食物もとることができる。","note":"くちばしを巡る口喧嘩","exp":"744"}],"1480":[{"type":"地理","name":"フエゴ島","rank":"3","desc":"南米大陸南端に位置する島。フエゴとはスペイン語で「炎」を意味する。先住民のヤーガン人は、極寒の島であるにも関わらず半裸で生活していた。そのため、島では焚き火の火が絶えず、島の名の由来となっている。","note":"最果てに灯る火","exp":"484"}],"1155":[{"type":"歴史遺物","name":"貝の装飾品","rank":"2","desc":"マヤでは、貝で作られた装飾品が多く見られる。これはイヤリングのようである。","note":"きれいな貝の装飾品","exp":"250"}],"6381":[{"type":"歴史遺物","name":"クセルクセス王のつぼ","rank":"3","desc":"アケメネス朝ペルシャの王、クセルクセスの名が刻まれた壺。古代都市ハリカルナッソスがあった地で発見された。庶民が手に入れられるようなものではないため、この地を治めていた者が遺したものであろう。","note":"","exp":"440"}],"1566":[{"type":"地理","name":"カンペチェ湾","rank":"1","desc":"ユカタン半島と大陸に囲まれた海。天然の良港として古くから知られ、新大陸の住民たちとイスパニア人の間で長く制海権を取り合っていた。","note":"書きかけの地図","exp":"185"}],"3290":[{"type":"地理","name":"ネス湖","rank":"4","desc":"ブリテン島北部にある湖。湖の幅が約2kmであり、非常に細長い形状をしている。\n青黒く輝く水の色が特徴的。\n噂では、謎の生物が生息しているらしいが、真偽の程は不明。","note":"いわくつきの湖","exp":"620"}],"6735":[{"type":"天文","name":"エルナト","rank":"3","desc":"おうし座で2番目に明るい星で、北側の角の先端に位置する。名前の由来はアラビア語で「角で突くこと」。おうし座とぎょしゃ座の間にあるため、一時期ぎょしゃ座の星とされていたこともある。","note":"発見物カード:255","exp":"510"}],"1773":[{"type":"地理","name":"アタカマ塩湖","rank":"4","desc":"アタカマ砂漠にある広大な塩湖。湖岸の岩が塩で白く染まっている様は、まるで雪が積もっているかのようだ。この塩湖は、フラミンゴの羽休めの場所ともなっている。","note":"鳥が集う場所","exp":"620"}],"1549":[{"type":"地理","name":"ティウィ","rank":"1","desc":"オーストラリア北部にある島。ファン・ディーメン湾を越えるとアーネムランドがある。東のメルヴィル島、西のバサースト島のふたつを合わせてティウィと呼ぶ。ティウィ人が独特の文化を守って暮らしている。","note":"書きかけの地図","exp":"75"}],"1437":[{"type":"歴史遺物","name":"パカル王の盾","rank":"3","desc":"パレンケ王・パカルが所持していたといわれる盾。パカルは、カラクムルによって滅亡寸前にまで陥っていたムトゥプルを、奇跡的に復興させた。","note":"パレンケの王","exp":"440"}],"126":[{"type":"宗教遺物","name":"神統記","rank":"1","desc":"「しんとうき」。ヘシオドス著の、ギリシャ神話の系譜。カオスから世界の生成と神々の誕生、英雄たちの冒険譚を描く。これまでまとめられていなかったギリシャ神話をまとめたものである。","note":"ギリシャ神話の成り立ち","exp":"55"}],"5644":[{"type":"海洋生物","name":"エレファントノーズフィッシュ","rank":"2","desc":"ナイル川などに生息している魚。ゾウの鼻にたとえられる顔の突起はは下顎で、食物とする泥の中の生物を探すために進化した結果と思われる。そのため、捕食の動作が他の魚類と比べて遅い。","note":"","exp":""}],"5784":[{"type":"気象・現象","name":"火山雷","rank":"3","desc":"火山の噴火によって発生する雷。観測が困難なため、詳細な発生原因や過程は不明。ただし、各国の古い文献にも、その存在は記録されている。","note":"","exp":"540"}],"6060":[{"type":"港・集落","name":"イニャンバネ","rank":"1","desc":"アフリカの東海岸で古くから栄えた都市の一つ。かつては綿の一大産地だったが、象牙などの取引の拠点として発展した。温暖な気候で、カシューナッツをはじめ様々な作物が作られている。","note":"到達する","exp":"78"}],"2047":[{"type":"地理","name":"ケルチ海峡","rank":"2","desc":"黒海とアゾフ海を繋ぐ狭い海峡。\nかつて、この周辺にはボスポラス王国という古代都市が栄えていたという。","note":"歴史調査の下調べ","exp":"320"}],"4857":[{"type":"天文","name":"りゅう座の猫の目のような星雲","rank":"1","desc":"りゅう座にある、猫の目のような形の星雲。かなり複雑な構造をしているとみられる。","note":"「天文学者の観測記録」<br/>発見物カード:95","exp":"190"}],"2607":[{"type":"歴史遺物","name":"熱蘭遮城図","rank":"2","desc":"読みは「ゼーランディアじょうず」。熱蘭遮城を俯瞰して描いたと思われる絵図。\n誰が描いたものなのかは不明だが、きれいな状態で保存されていたようだ。","note":"城の俯瞰図の地図","exp":"290"}],"2697":[{"type":"宗教遺物","name":"金銅観音菩薩立像","rank":"1","desc":"朝鮮でよく見られる形状の菩薩像。\n木像に金銅を塗ったものや、鋳造で作られたものなど、さまざまな手法で作られたものがあるようだ。","note":"朝鮮の仏像の地図","exp":"100"}],"2747":[{"type":"美術品","name":"申師任堂の絵画","rank":"2","desc":"朝鮮の女性画家・申師任堂によって描かれた絵画。\n華麗な彩色と繊細な画風が目を引く。このように草と虫を題材にした絵は、朝鮮の画家達にとって楽しく描けるものだったようだ。","note":"派生の画家","exp":"280"}],"2013":[{"type":"歴史遺物","name":"インカの石壁","rank":"2","desc":"滑らかで、美しい形の石。これだけの大きさのものとなると、積み重ねや運搬の問題が出てくるだろうが、この石は規則正しく積み重ねられ、寸分の隙間も見られない。一体どうやって作り上げられたのだろう…。","note":"クエスト「インカにそびえる石の壁」<br/>発見物カード:180","exp":"360"}],"6517":[{"type":"鳥類","name":"エトピリカ","rank":"5","desc":"大きく美しいくちばしを持ち、夏期には目の上に特徴的な長い飾りが羽が生える海鳥。一見ペンギンのような容姿ををしているがペンギンではなく、飛ぶことができる。","note":"追究クエスト<br/>発見物カード:900","exp":"1800"}],"5001":[{"type":"中型生物","name":"ロシアンウルフハウンド","rank":"1","desc":"ロシアでオオカミ狩りの猟犬として飼育されている大型のイヌ。性格はおとなしく、知能も非常に高い。森林には野生種も生息する。","note":"コーカサス地方再調査報酬","exp":""}],"1527":[{"type":"植物","name":"コチョウラン","rank":"2","desc":"チョウが群がって飛んでいるように見えるほど、多くの花を咲かせる。密林の木々に張り付くように自生している。","note":"［勅命］[[香料諸島方面からの献上品","exp":"330"}],"3675":[{"type":"海洋生物","name":"キングサーモン","rank":"2","desc":"別名はマスノスケ。北太平洋に分布し、産卵の時は生まれ育った川を遡上するという習性を持つ。体長が大きく最大で1.5m程度にも及ぶ。身には脂肪分が多く、美味である。","note":"※釣り<br/>※発見物カード:140","exp":"280"}],"3782":[{"type":"天文","name":"冬のダイヤモンド","rank":"4","desc":"冬の大三角からベテルギウスを中心として範囲を広げ、6つの1等星を繋いで描いた六角形を、冬のダイヤモンドと呼ぶ。2等星のカストルを含めて呼ぶこともある。","note":"視認","exp":"770"}],"5267":[{"type":"歴史遺物","name":"レプティス・マグナのヴィーナス像","rank":"1","desc":"レプティス・マグナ遺跡内の大浴場に飾られていたと思われる大理石製の女神像。古代の人々は女神に見守られながらの入浴を楽しんでいたのだろうか。","note":"レプティス　再調査報酬","exp":""}],"146":[{"type":"小型生物","name":"クロテン","rank":"1","desc":"黒というよりは茶色の毛のテン。冬毛が大変美しく、毛皮はセーブルと呼ばれて珍重される。乱獲のせいか、近年はほとんど見られなくなったようだ…。","note":"クロテンの生息調査","exp":"90"}],"2968":[{"type":"植物","name":"サラセニア","rank":"4","desc":"筒状の葉を持つ食虫植物。筒自体が落とし穴のような構造をしており、これを利用して筒の底に溜まっている消化液まで虫を落とし、分解、吸収する。","note":"緑の落とし穴","exp":"660"}],"5060":[{"type":"港・集落","name":"サンアントニオ","rank":"2","desc":"南米東岸、ブエノスアイレスの南、サンマティアス湾に位置する温暖な港街。さらに南にはパタゴニアという乾燥地帯が広がる。","note":"到達する","exp":"270"}],"1220":[{"type":"財宝","name":"踊る炎","rank":"5","desc":"極めて強い遊色効果を持つオパール。まるで炎を封じ込めたかのようだ。アステカでは炎を司る禍の神・シウコアトル由来のものと考えられ、封印されていた。","note":"炎を下さい","exp":"816"}],"3789":[{"type":"天文","name":"ポルックス","rank":"4","desc":"ふたご座で最も明るい星。星座図では、双子のうち、弟の頭に位置する。名はイアソンの探検隊に参加した双子の片割れ、ポリュデウケスに由来する。冬のダイヤモンドの一角。","note":"視認<br/><br/>発見時経験値650　発見物カード経験値325","exp":"650"}],"6038":[{"type":"化石","name":"トゲだらけの虫の石","rank":"2","desc":"北米北西部のバージェス頁岩から見つかった奇妙な石。トゲだらけで、虫のように見えるが、その正体は定かではない。","note":"文化貢献度40","exp":"260"}],"6858":[{"type":"天文","name":"ザヴィヤヴァ","rank":"1","desc":"おとめ座のベータ星。4等星で、女神の左肩あたりに位置する。\nアラビア語で「一角」を意味する言葉が名前の由来とされる。","note":"","exp":"1380"}],"5827":[{"type":"財宝","name":"ソロモンの盾","rank":"5","desc":"ソロモン王が作った金の盾。大盾が200個、小盾が300個作られたが、エジプトのファラオに奪われたという。","note":"","exp":"1360"}],"580":[{"type":"財宝","name":"象嵌細工の甲冑","rank":"1","desc":"「ぞうがんざいくのかっちゅう」。金や銀の象嵌細工が施された甲冑。祭礼や装飾目的のものと思われる。","note":"豪華な甲冑の地図","exp":"125"}],"3674":[{"type":"歴史遺物","name":"サルコファガス","rank":"4","desc":"ローマのカタコンベで発見した、彫刻で装飾された石棺。イタリア半島ではエトルリア人の時代から裕福な人々の石棺を彫刻で飾る伝統があった。この石棺はキリスト教に改宗した裕福な人物のものと思われる。","note":"ダンジョン","exp":"630"}],"6774":[{"type":"海洋生物","name":"アルビノナマコ","rank":"5","desc":"まなまこの白変種。10万体のうち1体しかいないとされる希少な個体。原因は不明だが、遺伝子変異によりメラニン色素の合成が足りず、体表が白い。希少性から、白いナマコは幸運を呼ぶものとされている。","note":"追究クエスト<br/>発見物カード:590","exp":"1180"}],"6459":[{"type":"歴史遺物","name":"カルナの黄金鎧","rank":"5","desc":"インドの叙事詩、「マハーバーラタ」に登場する英雄カルナの鎧。カルナは産みの母の願いにより、鎧と耳環をつけ不死身の体で誕生したとされるが、宿敵アルジュナの父であるインドラ神の策略により、黄金の鎧を手放すことになった。","note":"","exp":"2530"}],"6730":[{"type":"財宝","name":"ティン・ホイッスル","rank":"5","desc":"6つの指穴があり、リコーダー同様の吹き口を持つ縦笛。アイルランド発祥とされ、伝統音楽で使用される。","note":"楽の叡智・心に響く楽器　右下","exp":""}],"6021":[{"type":"天文","name":"ねこ座","rank":"5","desc":"猫好きの、猫好きによる、猫好きのための星座。\n大の猫好きとしても有名なフランスの天文学者であるラランドが「星空への仕返し」として考案したということだが、呼び名としてはいまいち定着していないようだ。","note":"クエスト「かの姿を星空に」<br/>発見物カード:415","exp":"830"}],"2385":[{"type":"植物","name":"オトギリソウ","rank":"3","desc":"東アジアの草地や山野に自生し、夏に黄色の花を咲かせる植物。\n葉を食べてから日光に当たると、皮膚炎になる。一般的には生薬や傷薬として利用されることが多い。","note":"傷薬の素","exp":"460"}],"1491":[{"type":"小型生物","name":"カンガルーネズミ","rank":"1","desc":"非常に発達した後ろ足で跳ねるネズミ。ネズミとしては大きいほうである。","note":"跳ねるネズミの地図","exp":"60"}],"2405":[{"type":"中型生物","name":"ヤクシマザル","rank":"2","desc":"屋久島に生息する、小型のサル。体毛は粗くてやや長い。\n成長した雄の頭の毛は中心から左右に分かれている。","note":"屋久島のサルの調査","exp":"250"}],"341":[{"type":"財宝","name":"テッサロニケの腕輪","rank":"3","desc":"アレクサンドロス大王の義理の妹・テッサロニケ愛用の腕輪と見られる。この腕輪は太陽のようなモチーフがついた、豪華なものである。","note":"遺されたものたち<br/><br/>発見時経験値528　発見物カード経験値264","exp":"528"}],"6757":[{"type":"鳥類","name":"オオウロコフウチョウ","rank":"5","desc":"ニューギニアに生息するフウチョウの一種。翼を広げ、規則正しく左右に首を振る、求愛のダンスで知られている。雄の亜成鳥の姿が雌と非常に似ているため、雌のふりをして雄に近づき、間近で踊りを学ぶ習性がある。","note":"追究クエスト<br/>発見物カード:490","exp":"980"}],"6741":[{"type":"気象・現象","name":"毛状雲","rank":"3","desc":"巻雲または巻層雲の一種。毛のように細い、すじ状の雲。5000mを越える対流圏に発生する。強風で雲の形が変わりやすく、常に他の場所へ流れている。","note":"バンダ海　5902.5021<br/>晴れ　夕方　10秒くらい","exp":"450"}],"1059":[{"type":"歴史遺物","name":"楔形文字の粘土板","rank":"1","desc":"「くさびがたもじ」。楔形文字が刻まれた粘土板。日常的に用いられていたようで、大量に出土する。まとまって出土する場所は、おそらく図書館のような施設だったのだろう。","note":"楔文字の遺物の地図","exp":"60"}],"1008":[{"type":"化石","name":"トカゲのような鳥の骨","rank":"5","desc":"頭から体にかけてはトカゲのようで、腕が鳥の翼のような動物の骨である。なぜか石のように変化している。体のまわりには羽のような模様があり、全身に羽が生えていたと思われる。こんな動物は見たことも聞いたこともない。新種だろうか？","note":"魔物の骨","exp":"1118"}],"2055":[{"type":"財宝","name":"ナザールボンジュウ","rank":"2","desc":"ガラスなどを使って目をかたどったトルコのお守り。目はメデューサの目を表している。トルコでは、悪意は目から放たれると考えられ、持ち主の身に危険が迫ると、悪意を跳ね返して割れるという。","note":"クエスト「人を守護するメデューサの目」<br/>発見物カード:175","exp":"350"}],"6211":[{"type":"化石","name":"鯨骨","rank":"2","desc":"海岸に流れついたクジラの骨。クジラや大きな魚の死骸は、通常であれば海中に住んでいるさまざまな生き物によって分解されていくが、その過程で腐敗した死骸や骨格が海岸に打ち上げられることがあるという。","note":"海岸の怪物","exp":"270"}],"5552":[{"type":"史跡","name":"トゥルム遺跡","rank":"4","desc":"マヤ人が造った城塞都市の遺跡。\n13世紀から15世紀の間に、貿易で繁栄したマヤ文明最後の都市のひとつである。","note":"マヤ文明の港街","exp":"630"}],"1167":[{"type":"虫類","name":"ニジイロシジミタテハ","rank":"3","desc":"新大陸の南に生息する美しいチョウ。表と裏で模様の違う羽は、まるで宝石のように美しい。","note":"美しい羽のチョウ","exp":"484"}],"321":[{"type":"宗教建築","name":"アブ・シンベル神殿","rank":"3","desc":"古代エジプトのファラオ・ラムセス2世が建てた神殿。内外に多数の石像があるが、ほとんどはオシリス神の姿をした、ラムセス2世の像である。隣に小神殿がある。","note":"ラムセス2世の神殿","exp":"600"}],"596":[{"type":"中型生物","name":"カラカル","rank":"2","desc":"トルコ語で「黒い耳」という言葉に由来する名のとおり、飾り毛のある黒い耳が特徴。この毛により獲物の出す小さな音を聞き分けると言われている。ものすごい跳躍力で、小鳥などの獲物を叩き落して捕食する。","note":"黒耳の獣","exp":"260"}],"2847":[{"type":"財宝","name":"三国志演義","rank":"2","desc":"「三国志」を元に書かれた明代の歴史小説。魏、蜀、呉の三国の間で入り乱れる、軍事・政治闘争を描いた話。劉備と曹操の対立軸を中心に、物語が進んでいく。","note":"群雄割拠の物語","exp":"210"}],"2919":[{"type":"歴史遺物","name":"タイルの欠片","rank":"2","desc":"美しく彩色されたヨーロッパ製のタイルの欠片。元々は教会の回廊に使用されるはずのものだが、どうやら地下に紛れ込んでしまったようだ。","note":"ダンジョン","exp":"310"}],"2331":[{"type":"地理","name":"阿蘇山","rank":"1","desc":"九州の中央部に位置する、巨大なくぼ地内にある火山群。\nこのくぼ地は、過去の火山活動で地面が陥没してできたもののようだ。付近は湧き水が豊富で、平地では農業も行われている。","note":"書きかけの地図","exp":"160"}],"5480":[{"type":"海洋生物","name":"ヨロイナマズ","rank":"4","desc":"アマゾン川を中心とした熱帯地域に生息するナマズ。鱗が鎧のように硬いのが特徴。食用にもされており、見た目とは裏腹に非常に美味。","note":"アマゾン川河口より一本目の支流　奥で釣り<br/>経験　:640<br/>カード:320","exp":"640"}],"5173":[{"type":"港・集落","name":"リスボン","rank":"1","desc":"フェニキア人によって築かれた、古い街。イスラム勢力に支配された時期に大きく発展して、重要な港として栄えるようになった。西ヨーロッパでもっとも美しい街だとされる。良質の陶磁器が製造されている。","note":"到達する","exp":"31"}],"5793":[{"type":"歴史遺物","name":"ゴルディアスの荷車","rank":"5","desc":"ゴルディアスの結び目が柱に結びつけていた荷車。「解いた者がアジアの覇者となる」と予言された結び目が、剣で断たれて解かれたと聞けば、ゴルディアスはどう思うだろう。","note":"王の荷車","exp":"1380"}],"5559":[{"type":"鳥類","name":"ハワイガン","rank":"1","desc":"ハワイ近辺の島に生息する鳥。全長60cm前後まで成長する。現地では鳴き声から「ネネ」と呼ばれる。","note":"ハワイの鳥の地図<br/><br/>発見時経験値140　発見物カード経験値70　文化貢献度20","exp":"140"}],"266":[{"type":"地理","name":"アイリッシュ海","rank":"1","desc":"ブリテン島とアイルランドの間にある海域。それほど水深はないようで、穏やかである。","note":"ブリテン島西の調査","exp":"20"}],"6626":[{"type":"財宝","name":"交子","rank":"5","desc":"史上初の紙幣。北宋の四川にて発行された。はじめは、民間の交子舗が発行していた鉄銭の預かり手形だったが後に政府が発行するようになり、紙幣として流通するようになった。","note":"レガシー　商の叡智・財貨の交易路　上","exp":"2550"}],"3915":[{"type":"天文","name":"いて座の三つに裂けた星雲","rank":"2","desc":"いて座にある星雲。明るい雲が、黒い雲で三つに分かれているように見える。","note":"天文学者の観測記録<br/><br/>発見物カード:140<br/>","exp":"280"}],"6779":[{"type":"地理","name":"大山","rank":"2","desc":"別名「阿夫利山」。標高1252mの山頂からは相模湾を望める。古くから祈雨・止雨の神として信仰され、江戸時代になると大山参拝は江戸庶民の一大行事となった。","note":"発見物カード経験値：200","exp":"400"}],"2002":[{"type":"美術品","name":"花輪の聖母","rank":"4","desc":"ルーベンスとヤン・ブリューゲルの合作。ブリューゲルが花輪を、ルーベンスが人物を描いた。ブリューゲルは「花のブリューゲル」とも呼ばれるほど静物画に定評があり、各々が得意分野を生かした作品となっている。","note":"画家の適材適所","exp":"650"}],"6567":[{"type":"歴史遺物","name":"角杯","rank":"5","desc":"獣の角で作られた杯。儀式で用いられていたとされ、古代の神話にも登場する。酒場マスター曰く「角杯で飲む酒は気持ちが高揚し、最高に気分が上がる」とのことだ。","note":"追究クエスト","exp":"1100"}],"6759":[{"type":"植物","name":"エケベリア","rank":"2","desc":"ベンケイソウ科の多肉植物の一属。18世紀末スペインの探検隊により発見され、ヨーロッパ園芸にて一世を風靡した。名の由来は18世紀のメキシコの植物画家アタナシオ・エチェベリア。","note":"発見物カード:120","exp":"240"}],"6622":[{"type":"財宝","name":"三彩駱駝載楽俑","rank":"4","desc":"唐の時代に作られた陶器「唐三彩」の一つ。空を仰ぐラクダや胡人の男性楽団を表現した名作。美しい造形、華やかな釉薬、どちらを取っても「唐三彩」屈指の完成度である。","note":"","exp":"710"}],"5795":[{"type":"歴史遺物","name":"日本書紀","rank":"5","desc":"古代日本の歴史書。神話の時代における国の成り立ちから持統天皇の治世までを記述しており、異説の併記が特徴的である。","note":"","exp":"1370"}],"5290":[{"type":"中型生物","name":"ケヅメリクガメ","rank":"4","desc":"サハラ南部の乾燥地帯に生息する大型のリクガメ。後ろ足と尾の間に蹴爪(けづめ)のような突起があることからこの名がついた。リクガメとしてはかなり活発に動き回る。","note":"砂漠のカメ","exp":"680"}],"3415":[{"type":"レリック","name":"ピカトリクス","rank":"","desc":"「賢者の極み」と題される魔術と占星術に関するアラビア語の書物。\nヨーロッパでも翻訳され、広く流布しているという。","note":"","exp":""}],"1356":[{"type":"大型生物","name":"コモドドラゴン","rank":"5","desc":"最大のもので3mを超える大型のトカゲ。重くがっしりとした体に、長くて太い尾を持つ。巨体のわりにすばやい動きでシカやイノシシを捕食する。二股に分かれた舌は、まるで火を吐いているように見える。","note":"ドラゴンの子孫","exp":"1222"}],"7002":[{"type":"財宝","name":"文王の法冠","rank":"5","desc":"古代中国に伝わる一本角の神獣を模した冠。この神獣は正邪を見極め、悪を罰するとされた。伝説によればこの冠は楚の文王が創案し、以後法を司る官吏が正義の象徴として身につけるようになったという。","note":"","exp":""}],"1179":[{"type":"史跡","name":"チチェンイッツァ","rank":"4","desc":"ユカタン半島に花開いたマヤの遺跡。「チチェンイッツァ」とは、「泉のほとり」という意味らしい。非常に広大な土地に展開し、ピラミッド型神殿を中心に、聖なる泉、戦士の神殿、天文台などがある。","note":"水のない文明","exp":"624"}],"6958":[{"type":"歴史遺物","name":"ファイストスの円盤","rank":"5","desc":"ギリシャのクレタ島で見つかった粘土製の円盤。直径15cmほどで、両面には渦巻く独特の模様が型押しされたように並んでいる。焼けて固まっている状態で発見された。これは大噴火による火災が原因なのだろうか。","note":"発見物カード:540","exp":"1080"}],"1609":[{"type":"植物","name":"トケイソウ","rank":"1","desc":"時計のような形の花を咲かせる。花は10cmほどに成長し、毎日咲いてしぼむという性質を持つ。","note":"時計のような花の地図","exp":"175"}],"6896":[{"type":"小型生物","name":"イイズナ","rank":"5","desc":"北米やユーラシア大陸などに広く分布する、小型の肉食獣。可愛らしい見た目に反し、獰猛な気性を備える。行動は非常に敏捷で、自分よりも大きな獲物にも飛びついて捕食する。","note":"発見物カード:615","exp":"1230"}],"6910":[{"type":"小型生物","name":"クアッカワラビー","rank":"5","desc":"オーストラリア南西部に生息するカンガルーの仲間で、クオッカとも呼ばれる。笑っているように見える口角の上がった口元が特徴。草食性で、草葉や低木の芽などを食べる。","note":"","exp":""}],"871":[{"type":"地理","name":"ボスニア湾","rank":"1","desc":"バルト海北部の広大な湾。南北に長く、多数の川が流れ込む。そのためか塩分が薄く、冬になると凍ってしまうこともあるという。","note":"凍る海","exp":"80"}],"5900":[{"type":"大型生物","name":"マーコール","rank":"5","desc":"中央アジアに生息するヤギの仲間。長くねじれた一対の角と白く長い髭が特徴。主に高山地帯の草原や岩場で活動し、冬には標高の低い位置に移動する。一部の地域では角が薬用とされ、狩猟の対象になっている。","note":"","exp":"1430"}],"1820":[{"type":"財宝","name":"金の頭飾り","rank":"1","desc":"金とトルコ石を用いた凝った作りの頭飾り。儀式や祭事に用いたようだ。空色のトルコ石を頭に付けることで、邪悪な力を退散させようとしたのだろうか。","note":"金細工の地図","exp":"150"}],"6872":[{"type":"地理","name":"済州島の溶岩石柱","rank":"2","desc":"済州島の海岸線に並ぶ多角形の石柱。火山から噴出した溶岩が、海に流れ込む際に冷え固まって出来たものと考えられている。","note":"発見物カード:190","exp":"380"}],"6218":[{"type":"化石","name":"巨大な鳥の骨","rank":"2","desc":"密林で見つかった、非常に巨大な鳥の骨。翼を閉じた状態であっても、人間より体が大きい。頑丈そうで大きな足を持っていることから、大きな魚や動物を捕らえて食べていたのかもしれない","note":"","exp":"230"}],"5659":[{"type":"史跡","name":"ギルフ・ケビール","rank":"3","desc":"サハラ東部に位置する砂岩の台地。枯れ川がいくつも走っており、それに沿った岩壁には古代の人々が描いたとされる壁画が残されている。","note":"","exp":"460"}],"6414":[{"type":"美術品","name":"ミノタウロスの像","rank":"5","desc":"ギリシャ神話に登場する牛頭人身の怪物、ミノタウロスをかたどった像。ミノタウロスはミノス王の妻と白い牡牛との間に生まれた子だが、成長するに従って乱暴になり、誰の手にも負えなくなると、ミノス王命令により迷宮に閉じ込められた。","note":"追求クエスト　発見物カード:605","exp":"1210"}],"5187":[{"type":"港・集落","name":"杭州","rank":"2","desc":"読み方は、「ハンチョウ」。マルコ・ポーロが、美しく華やかな都市だと褒め称えたといわれている街。\n文明発祥地の一つで、寺や古跡が多く立ち並ぶ。","note":"到達する","exp":"345"}],"1626":[{"type":"鳥類","name":"モモイロインコ","rank":"2","desc":"オーストラリア全域に群れで生息する鳥。体は桃色、翼は灰色で尾は黒い。果物、昆虫などを採食する。","note":"桃色の鳥<br/><br/>発見時経験値280　発見物カード経験値140","exp":"280"}],"2072":[{"type":"財宝","name":"グンデル","rank":"2","desc":"ジャワ島に古くからある金属楽器。バチで金属の鍵盤を叩き、手で共鳴を適度に止めて、奏でる。ワヤン・クリの伴奏として演奏されることが多いが、祭礼や儀式でも演奏されるようだ。","note":"［勅命］[[未知の魅力","exp":"320"}],"3808":[{"type":"小型生物","name":"コキーコヤスガエル","rank":"5","desc":"サンフアンが位置する島を原産地とする小型のカエル。高くよく通る鳴き声が特徴的。","note":"音の正体","exp":"940"}],"6130":[{"type":"宗教遺物","name":"タルムード","rank":"2","desc":"モーセが伝えたもう一つの律法とされる「口伝律法」をまとめた書物集。「ミシュナー」や「ゲマーラー」などで構成されている。「未完の律法書」とも呼ばれ、ユダヤ教における信仰と生活面での規範の一つとなっている。","note":"","exp":"380"}],"5720":[{"type":"気象・現象","name":"反薄明光線","rank":"4","desc":"地平線近くの太陽が霧で隠れた際に見られる現象。雲の隙間から漏れ出た帯状の光が、太陽の反対側で収束して見える。","note":"2017.02.07新規追加","exp":"660"}],"182":[{"type":"地理","name":"ドンドラ岬","rank":"2","desc":"セイロン島最南端に位置する岬。島の人間もめったに近寄ることはないようだ。","note":"セイロン島の最南端","exp":"250"}],"5237":[{"type":"植物","name":"ネトル","rank":"1","desc":"成人の膝ほどの高さになる多年生の植物。菱形の葉と茎には刺毛があり、刺さると強い痛みを感じる。煎じて飲むと、血行を促進しケガや疲労の回復に繋がるといわれている。","note":"","exp":""}],"972":[{"type":"美術品","name":"最後の晩餐","rank":"2","desc":"レオナルド・ダ・ヴィンチ作。遠近法によって描かれ建物内部が奥に続いているように見える。周囲の弟子たちに比べてイエスがあっさりと描かれているのは、彼にありがちなことだが未完成なのだろう。","note":"崩れゆく名画","exp":"260"}],"2746":[{"type":"美術品","name":"申師任堂の屏風絵","rank":"2","desc":"朝鮮の女性画家・申師任堂によって描かれた屏風絵。\n安堅の影響を受け、精緻な画風である。人物や動物をあまり描かないのが特徴で、この屏風にも、草と虫を美しく描いている。","note":"繊細な屏風絵の地図<br/><br/>発見時経験値210　発見物カード経験値105","exp":"210"}],"1246":[{"type":"大型生物","name":"ボア","rank":"2","desc":"草原から森林まで幅広い環境に棲む大蛇。鳥や大型のトカゲを襲うとき、太い胴で獲物を窒息させてから丸ごと飲み込む。","note":"［勅命］[[新大陸進出の脅威","exp":"280"}],"5746":[{"type":"鳥類","name":"ソデグロヅル","rank":"1","desc":"全長およそ1mのツルの一種。翼の先が真っ黒なことが名前の由来になっている。止まって翼を畳むと黒い羽根がすべて隠れ、全身が真っ白に見える。","note":"","exp":""}],"1325":[{"type":"地理","name":"ミンダナオ島","rank":"2","desc":"東南アジアの中でも北東に位置する島。古くからアラブ商人との交流があり、イスラムの影響下にあるが、マゼランのセブ島上陸よりイスパニアの干渉も受けている。","note":"マニラ南の巨島","exp":"210"}],"375":[{"type":"大型生物","name":"エピオルニス","rank":"5","desc":"マダガスカル島に生息する巨大な鳥。高さが3mもあり、体重はなんと500kgを超える。10kgにもなる卵を砂地に産み、太陽熱を利用して孵化（ふか）させるようだ。羽毛や肉を目当てに狩られており、このままでは絶滅するかもしれない。","note":"怪鳥","exp":"1163"}],"1570":[{"type":"小型生物","name":"ハリモグラ","rank":"2","desc":"太くて固いトゲを持つモグラ。そのトゲで外敵から身を守る。地面を掘って体を沈め、背中のトゲしか見えなくなることもある。","note":"動く針の山","exp":"280"}],"3312":[{"type":"地理","name":"モハーの断崖","rank":"2","desc":"アイルランド南部、西側の海に面する断崖絶壁。アイルランドの言葉では「破滅の崖」を意味する。晴れた日の景色は絶景である。","note":"書きかけの地図","exp":"250"}],"1684":[{"type":"宗教遺物","name":"シペ・トテックのマスク","rank":"5","desc":"豊穣神シペ・トテック信仰に用いられたと思われる金のマスク。メソアメリカでも比較的新しい時代になると、金属を使用した遺物が見つかるが、これだけ精巧に、かつ大量の金でできたものとなると類を見ない。","note":"豊穣神の黄金の仮面","exp":"1183"}],"3901":[{"type":"天文","name":"オリオン座の傘のような星雲","rank":"1","desc":"オリオン座の三ツ星の南に連なる小三ツ星の中央にある星雲。星雲の中ではかなり明るいため、肉眼でも見られる。","note":"「天文学者の観測記録」<br/>発見物カード:60","exp":"120"}],"380":[{"type":"地理","name":"ラッカジブ諸島","rank":"2","desc":"インド南部の西に浮かぶ島々。40近い島からなる。少数だが人が住み、ヤシを栽培したり漁業をしたりして生活しているようだ。","note":"クエスト「海賊のたまり場」<br/>発見物カード:160","exp":"320"}],"1990":[{"type":"海洋生物","name":"ノコギリエイ","rank":"2","desc":"ノコギリのような吻を持つエイ。船底に穴を開け、溺れた人間を食べるとも言われているが…。","note":"釣り","exp":"350"}],"631":[{"type":"宗教遺物","name":"オシリス像","rank":"1","desc":"古代エジプトの死と復活の神の像。オシリスは弟のセトに殺されたが、妻のイシスと息子のホルスがセトを倒した。のちに、オシリスは冥府の王となったという。","note":"失われた冥府の神","exp":"110"}],"5991":[{"type":"海洋生物","name":"シャチ","rank":"1","desc":"10m近い体長の、クジラの仲間。特徴のある模様と人間の身長より大きな背びれを持つ。かなり大きな群れで目撃されることもある。鳴き声で仲間と連絡をしているようだ。","note":"巨大で凶暴なイルカ","exp":"200"}],"1416":[{"type":"歴史遺物","name":"四脚容器","rank":"1","desc":"四脚のついた器型の入れ物。犬のような頭のついた蓋がある。犬はマヤ王が死後の世界に旅立つ際に供についたといわれている。","note":"メソアメリカの容器の地図","exp":"150"}],"5294":[{"type":"小型生物","name":"ケープアラゲジリス","rank":"1","desc":"アフリカ南部の乾燥した地域に広く生息するリスの仲間。地面に巣穴を掘って生活する。樹上で生活するリスと違って食物を貯め込まず、一日の大半を食事に費やす。危険に気づくと、鳥のさえずりのような鳴き声で仲間に知らせる。","note":"","exp":"170"}],"3010":[{"type":"地理","name":"ナイアガラの滝","rank":"5","desc":"北米大陸きっての壮大さを誇る大滝。\nナイアガラ川の流れが二つの島によって三つに分かたれ、エリー湖からオンタリオ湖へ流れ込んだものである。絶えず巻き上がる水煙が、その荘厳な風景を引き立てる。","note":"怒涛の大瀑布<br/><br/>発見時経験値1100　発見物カード経験値550","exp":"1100"}],"6926":[{"type":"宗教遺物","name":"踊るシヴァ神の像","rank":"2","desc":"ヒンドゥー教のシヴァ神が踊っている姿をかたどった像。ナタラージャと呼ばれる。三つの目と四本の腕を持ち、その姿は世界の輪廻を表すと言われている。","note":"追究クエスト<br/>発見物カード:180","exp":"360"}],"3624":[{"type":"中型生物","name":"シベリアンハスキー","rank":"5","desc":"シベリアや北米の寒冷な地域で生育する大型犬。豊かな毛並みで寒さに強い。従順で頭が良く、体力にも優れているため、狩猟や運搬など、人間の活動の中で活躍している。","note":"伝説との出会い","exp":"950"}],"5985":[{"type":"小型生物","name":"モモンガ","rank":"1","desc":"頭から尾の先までが20cmあまりの、小型のリスの仲間。前足と後足の間に飛膜があり、木から木へ滑空する。黒い大きな目と長めの毛が愛らしい。","note":"小さな空飛ぶリス","exp":"30"}],"6020":[{"type":"中型生物","name":"永州の異蛇","rank":"2","desc":"えいしゅうのいだ。中唐の詩人・柳宗元の書いた「捕蛇者の説」に記述があるヘビ。植物を枯らし、人が噛まれればひとたまりもないほどの猛毒を持つ。難病に効く薬の原料になるともされ、租税の代わりに納められていた時代もあるという。","note":"税金代わり","exp":"300"}],"516":[{"type":"歴史遺物","name":"古代の金の器","rank":"1","desc":"金で作られたり、金めっきを施した器。実用品より、祭器や特別な用途に使われていたようである。","note":"古代の金細工の地図","exp":"39"}],"300":[{"type":"歴史遺物","name":"有翼人面獣身像","rank":"3","desc":"古代メソポタミア文明で作られていた、独特の石像。門の脇などに置かれ、守護の意味があったと考えられる。体は牡牛であったり獅子であったりする。","note":"メソポタミアの石像","exp":"506"}],"2964":[{"type":"海洋生物","name":"ラブカ","rank":"5","desc":"ウナギのような細長い姿をしたサメ。深海に棲むという情報もあるが、詳細は不明。沿岸で漁をしていると網にかかることがあるという。生態など、多くのことが不明のサメである。","note":"凶悪なウナギ","exp":"1030"}],"5944":[{"type":"地理","name":"ピコ島のブドウ畑","rank":"3","desc":"アゾレス諸島の一つ。不毛な火山島であったが、移住した修道士たちが溶岩の隙間にブドウを植え、溶岩の塊を積み上げて垣根を作って風から守ってきた。そうして開拓が進められた結果、独特な景観が形成された。","note":"クエスト「不毛の地に根付いたもの」<br/>発見物カード:200","exp":"400"}],"6493":[{"type":"宗教遺物","name":"玉座のキュベレ女神像","rank":"5","desc":"古代アナトリアの女神キュベレの座像。キュベレはフリュギアで崇拝された大地母神で、古代ギリシャやローマでも信仰された。城壁を模した冠をかぶり獣を従えた姿は、エフェソスのアルテミス神像との関連を思わせる。","note":"レガシー　女神信仰のエフェソス　左下","exp":""}],"1283":[{"type":"歴史遺物","name":"シンソープ女王の耳飾り","rank":"2","desc":"ペグー朝のシンソープ女王の耳飾り。シンソープ女王は自らの体重と等しい金箔を貼り付けてシュエジゴンパゴダを改修した。この耳飾りも、その力を誇示するように絢爛豪華できらびやかだが、女性らしい繊細さもうかがえる。","note":"ペグーの女王","exp":"280"}],"2884":[{"type":"中型生物","name":"キンシコウ","rank":"5","desc":"中国西部の寒い地域に生息するサル。橙色の長い体毛に覆われている。\n青白い顔や、潰れたような形の鼻が、大きな特徴である。","note":"王妃さまとサル","exp":"1040"}],"6376":[{"type":"気象・現象","name":"ダストデビル","rank":"2","desc":"地面から渦巻状に突風が立ち上る現象。温められた空気が上昇する際に強い横風を受けるなどで発生する。主に開けた場所で見られ、土や粉塵を巻き上げるが、竜巻とは異なり雲を伴わない。「つむじ風」とも呼ばれる。","note":"","exp":"300"}],"4962":[{"type":"天文","name":"へびつかい座の鳥形の星雲","rank":"2","desc":"へびつかい座といて座の中間にあり、鳥が羽を広げたような形状をしている星雲。小さな星がいくつも重なって見える。","note":"「天文学者の観測記録」<br/>発見物カード:165","exp":"330"}],"5941":[{"type":"地理","name":"聖アンデレ島","rank":"2","desc":"アフリカ西部を流れる川に位置する島。入植したヨーロッパ人が要塞を建造し、貿易拠点として発展した。その領有をめぐって様々な国が争い、所有国が変わるたびに名を変えた。","note":"","exp":"320"}],"998":[{"type":"財宝","name":"東方見聞録","rank":"1","desc":"13世紀終わりごろ、元朝のフビライに仕えたマルコ・ポーロの口述を記録した本。この中に、黄金の国ジパングが登場する。","note":"冒険者のバイブル","exp":"55"}],"6488":[{"type":"地理","name":"グレートサンディ砂漠のクレーター","rank":"5","desc":"オーストラリアの北西部に広がるグレートサンディ砂漠にある巨大なクレーター。隕石の衝突によって形成されたと考えられている。その全容を把握するには、高台から望む必要があるだろう。","note":"追究クエスト","exp":""}],"291":[{"type":"地理","name":"モーリシャス諸島","rank":"2","desc":"マダガスカル島の東に浮かぶ島々。無人島である。サンゴ礁に囲まれているが、土地は比較的肥沃で、耕作が可能だと思われる。熱帯性の気候と美しい海があいまって、楽園のようだ。","note":"マダガスカルの東","exp":"270"}],"6430":[{"type":"気象・現象","name":"ブルージェット","rank":"2","desc":"雷雲からさらに上空に向けて発生する発光現象。特に青いものをこのように呼称する。上向きの雷とよばれることもある。発光時間の短さや発生位置の高度などにより、観測例は少ない。","note":"インド西岸沖（3250、3990）辺り<br/>冒険経験310<br/>カード経験155<br/>視認スキル７か８が必要(６で足りず、８で観測成功のため)","exp":"310"}],"6808":[{"type":"海洋生物","name":"オオイカリナマコ","rank":"2","desc":"ナマコの一種。珊瑚礁の浅い海底に見られ、その細長い形状から蛇と間違われることがある。水を吸うと体長が伸び、3mを越えるという。先端には十数本の触手が生え、見た目を不気味に感じる者も少なくない。","note":"発見物カード:175","exp":""}],"2821":[{"type":"宗教遺物","name":"玉蝉","rank":"2","desc":"読み方は、「ぎょくせん」。蝉の形をした殷代の葬玉。\n古来、遺体の穴をすべて葬玉で塞いで埋葬すると、腐敗を防げると考えられていた。","note":"変わった形の遺物","exp":"340"}],"6747":[{"type":"伝承","name":"相柳","rank":"5","desc":"古代中国神話に伝わる怪物。人の頭を持ち、九つの山を喰らう大蛇として描かれる。四罪の一つに数えられる悪神の共工に仕えていた。『山海経』によると、夏王朝の初代君主である禹に退治されたという。","note":"","exp":""}],"5156":[{"type":"港・集落","name":"マラカイボ","rank":"2","desc":"カリブ海・大西洋につながる湾ともいえる塩分を含んだ南米最大の湖、マラカイボ湖に面した街。この湖では時折、音を出さない雷が発生することがある。","note":"到達する","exp":"241"}],"915":[{"type":"海洋生物","name":"シロナガスクジラ","rank":"2","desc":"大きなもので30mにもなる、巨大なクジラ。体色が白っぽいため、さらに大きく見える。口の様子からすると、小さなエビなどをこしとって食べているようだ。","note":"白鯨","exp":"220"}],"2050":[{"type":"財宝","name":"政治の書","rank":"2","desc":"セルジューク朝の名宰相、ニザーム・アルムルクが書いた書。スルタンに求められる帝王学を、逸話などを含めて分かりやすく書いている。","note":"名宰相の帝王学","exp":"270"}],"5468":[{"type":"鳥類","name":"イチモンジバト","rank":"1","desc":"パンタナル湿原でよく見られるハトの一種。\n羽をたたんでいると一文字の模様がはっきり見えるのが特徴。\nハトの名がついているが、実際はスズメほどの大きさだという。","note":"発見時経験値150　発見物カード経験値75","exp":"150"}],"2084":[{"type":"地理","name":"グレートビター湖","rank":"2","desc":"カイロとスエズの狭間にある、比較的大きな湖。この他にも、小中の湖が存在しているらしい。これらの湖は、スエズ運河の一部となるだろう。","note":"［勅命］[[運河開通場所の地形調査","exp":"310"}],"1287":[{"type":"宗教遺物","name":"女神柱","rank":"2","desc":"アンコール遺跡の柱に彫られた女神の像。\nダ・ヴィンチやラファエロの母子画に見られるような温かい微笑を称えている。しかし、アンコール遺跡は砂岩という脆い建材で作られている箇所が多くこの柱も例外ではない。","note":"女神の集う場所","exp":"280"}],"6610":[{"type":"宗教遺物","name":"グンデストルップの大釜","rank":"2","desc":"鉄器時代の後期に作られたと思われる銀器。ケルトの神々のさまざまな場面が描かれている。ヨーロッパ鉄器時代のものとしては、現存する最大の銀細工とされる。","note":"","exp":"350"}],"1550":[{"type":"地理","name":"グルートアイランド島","rank":"1","desc":"オーストラリアの北部にある島。オランダ語で「大きな島」を意味する。その名の通り、カーペンタリア湾に浮かぶ島の中で最大のものである。","note":"書きかけの地図","exp":"140"}],"5558":[{"type":"地理","name":"プナルウ黒砂海岸","rank":"2","desc":"ハワイ島にある、黒い砂浜。火山から噴出した溶岩が細かく砕けて黒い砂となり、堆積している。ウミガメの生息地としても有名。","note":"書きかけの地図<br/><br/>発見時経験値250　発見物カード経験値125　文化貢献度40","exp":"250"}],"1858":[{"type":"宗教遺物","name":"パチャママ像","rank":"2","desc":"先住民の言葉で「母なる大地」を表す女神。豊穣を司る神であり、万物の母とされる。キリスト教の浸透以降は聖母マリアと同一視され、信仰の対象となった。","note":"クエスト「アンデスの大地母神」<br/>発見物カード:115","exp":"230"}],"2743":[{"type":"財宝","name":"変わり前立て","rank":"2","desc":"日本のある武将が身につけたといわれる兜。前面に「愛」と書かれた立物（たてもの）をつけている。立物は本来大将しか身につけられず、形も決まっていたが、近年は下級兵士にも開放され、意匠も多様化している。","note":"ある大名の兜の地図","exp":"365"}],"1584":[{"type":"地理","name":"ヨーク岬半島","rank":"3","desc":"オーストラリア北東部に突き出た半島。北端のヨーク岬は、オーストラリアの最北の地である。東にサンゴ海、西にカーペンタリア湾が広がり、珍しい動物が数多く生息する。","note":"赤砂の荒野","exp":"484"}],"5750":[{"type":"地理","name":"マクドナルド諸島","rank":"5","desc":"オーストラリアの南西方向に位置する島々。岩で出来た小さな島であり、多数のアザラシやアシカなどが生息している。","note":"2017.02.07新規追加","exp":"1340"}],"1758":[{"type":"歴史遺物","name":"ゲクランの馬上槍","rank":"3","desc":"百年戦争初期に活躍したフランス軍人が使ったという槍。ゲクランは、ブルターニュ地方の城主の息子として生まれた。幼少期は戦争ごっこや馬上槍試合が好きな荒くれ者だったが、後に傭兵を用いた機動的な戦術でイングランド軍を翻弄した。","note":"荒くれ騎士の列伝","exp":"600"}],"2789":[{"type":"中型生物","name":"チャウチャウ","rank":"4","desc":"番犬や家畜として飼育されてきたイヌ。口の中や舌が青黒いため、黒舌犬と呼ぶ地域もあるようだ。\n唐の皇帝も飼育していたといわれている。","note":"ラウトゥの気になる子<br/><br/>文化貢献度45","exp":"790"}],"1535":[{"type":"歴史遺物","name":"彩文水がめ","rank":"1","desc":"インドシナ半島の内陸には多くの焼き釜があり、古くから焼き物が盛んだったという。これは形がなめらかで芸術品として優れている上、日用品としての使いやすさにも優れている。","note":"古代の土器の地図","exp":"110"}],"1949":[{"type":"植物","name":"カントゥータ","rank":"2","desc":"アンデスの高地に自生する樹木。寒冷で乾燥した過酷な環境にありながら、赤や黄などの鮮やかな色をした釣鐘状の花を咲かせる。現地では、「インカの聖花」とも呼ばれる。","note":"人々と共にある花","exp":"330"}],"6052":[{"type":"宗教遺物","name":"正教勝利のイコン","rank":"2","desc":"ビザンツ帝国で激化した聖像破壊運動が終わるきっかけとなった、第七全地公会（第2ニカイア公会議）の決定を記念するイコン。正教会では大斎期間（復活祭の前の四十日間）最初の日曜に祈念するようになったという。","note":"","exp":""}],"6039":[{"type":"化石","name":"巨大なカメの骨","rank":"2","desc":"全長約4m、全幅約5mという巨大なウミガメの骨。甲羅は骨で覆われておらず、皮か何かで覆われていたものと思われる。","note":"","exp":"340"}],"1935":[{"type":"小型生物","name":"ピグミーマーモセット","rank":"4","desc":"とても小さなサル。手のひらに乗る大きさにまでしか成長しない。川沿いの森を好み、主に樹液を摂取して生活している。鳥のような鳴き声をしている。","note":"手のひらに乗るサル","exp":"700"}],"911":[{"type":"鳥類","name":"ハクチョウ","rank":"1","desc":"優雅な長い首と美しい白い羽で知られる、大型の水鳥。渡り鳥で、半年ごとに移動する。灰色の個体も見かけるが、どうやら若鳥のようである。","note":"白い鳥の地図","exp":"13"}],"6758":[{"type":"財宝","name":"飛魚服","rank":"5","desc":"明代の特務機関、錦衣衛の制服。功績者に皇帝から下賜される装束\nの一つ。飛魚とは蟒蛇(うわばみ)にヒレが生え、尾が魚の形に似\nた霊獣で『山海経』に記された怪物が元といわれている。","note":"発見物カード：900","exp":"1800"}],"4856":[{"type":"天文","name":"エラキス","rank":"2","desc":"ケフェウス座に含まれる赤い星。その輝きの美しさから、後世には「ガーネットスター」と呼ばれた。","note":"「明るい星の観測記録」<br/>発見物カード:105","exp":"210"}],"5742":[{"type":"宗教遺物","name":"ファフニールの財宝","rank":"5","desc":"出所不明の財宝。誰が置いたのか、いつから置かれているのか、一切不明である。ファフニールが守っていた呪いの財宝ではないか、という噂を恐れ、盗賊さえ持ち去ろうとしない。","note":"2017.02.07新規追加","exp":""}],"6362":[{"type":"海洋生物","name":"ペンシルフィッシュ","rank":"1","desc":"南アメリカの川などで見られる淡水魚。細長い体と小さな口で水中の苔を食べる。体を斜めにしたまま水面近くを泳ぐ種がいるため、その姿を鉛筆にたとえて名付けられた。","note":"","exp":"140"}],"6269":[{"type":"宗教遺物","name":"アヴァクームの書簡","rank":"5","desc":"ロシア古儀式派の指導者のひとりであった司祭、アヴァクームが信徒に送った書簡のひとつ。\n彼は皇帝アレクセイらによる教会の改革に異議を唱えて15年間投獄されており、当時の口語で自伝や書簡を記していたという。","note":"","exp":"1030"}],"1147":[{"type":"大型生物","name":"ボア","rank":"2","desc":"草原から森林まで幅広い環境に棲む大蛇。鳥や大型のトカゲを襲うとき、太い胴で獲物を窒息させてから丸ごと飲み込む。","note":"［勅命］[[新大陸進出の脅威","exp":"280"}],"5853":[{"type":"美術品","name":"ザクロの陶器","rank":"5","desc":"ザクロの絵付けが施された磁器。ヨーロッパの人々の多くはザクロを知らなかったため、この絵付けをブルーオニオンと呼んだ。","note":"","exp":"1380"}],"6285":[{"type":"地理","name":"白砂漠","rank":"5","desc":"サハラ東部に位置する砂漠。白い石灰質の岩に覆われており、風で浸食された奇岩が立ち並んでいる。","note":"クエスト「髪飾りの謎」<br/>発見物カード:590","exp":"1180"}],"6557":[{"type":"鳥類","name":"メジロ","rank":"5","desc":"東アジアに分布する小鳥。鮮やかな緑色の羽と目の周りの白い輪が特徴で、同じ春を告げる鳥のウグイスとよく間違えられる。体を押し合うように枝に止まる習性があり、その姿はとても可愛らしい。","note":"追究クエスト","exp":"1600"}],"5725":[{"type":"財宝","name":"コムズ","rank":"1","desc":"ユーラシア大陸中央部の伝統的な弦楽器。独特な形状と木製のきめ細かな装飾が非常に美しい。","note":"2017.02.07新規追加","exp":""}],"6056":[{"type":"財宝","name":"聖母マリアのカンティガ集","rank":"5","desc":"カスティーリャ王アルフォンソ10世が自ら手がけたといわれる聖母賛歌集。\n彼の治世は軍事や内政で失敗続きだったが、文化事業においては多大な影響を残し、この歌集はその代表作とみなされている。","note":"","exp":""}],"749":[{"type":"地理","name":"カリブ海","rank":"2","desc":"北米大陸と南米大陸の間に広がる海域。多くの島が浮かんでおり、人々は豊かな自然に恵まれて暮らしている。欧州やアフリカ、インドとはまったく異なる生態系を持つ。","note":"西海域の治安","exp":"360"}],"5585":[{"type":"天文","name":"とも座","rank":"5","desc":"ラカーユが制定した南天の星座のひとつ。ギリシャ神話に登場するアルゴ船の船尾部分にたとえられる。","note":"発見物カード:410","exp":"820"}],"6887":[{"type":"財宝","name":"開元通宝","rank":"5","desc":"唐代に発行された円形方孔の貨幣。中央の穴を囲うように「開元通宝」という文字が刻まれているが、正しい文字の並びは不明。後世および周辺諸国の貨幣に大きな影響をもらたしたといわれている。","note":"発見物カード:220","exp":"440"}],"5989":[{"type":"天文","name":"フォボス","rank":"3","desc":"火星の衛星。もっとも内側の軌道を公転している第一衛星である。徐々に火星に接近しており遠い未来には衝突が予想されている。","note":"アイスランド海盆　19世紀<br/>発見物カード:235","exp":"470"}],"651":[{"type":"地理","name":"ボニファシオ海峡","rank":"1","desc":"ジェノヴァの南に浮かぶ、コルシカ島とサルデーニャ島の間にある海峡。ナポリからバルセロナに向かうときはこの海峡を通ると近いだろう。","note":"書きかけの地図","exp":"20"}],"2769":[{"type":"宗教遺物","name":"大聖堂の地下墓所","rank":"2","desc":"大聖堂の地下に作られたカタコンベ。イタリア半島をはじめ、ヨーロッパの教会ではいくつかのカタコンベが見つかっている。フランスでもボルドーなど数箇所に存在することが確認された。","note":"ダンジョン","exp":"280"}],"5003":[{"type":"天文","name":"タイタン","rank":"4","desc":"ガリレオ衛星に次いで発見された、土星の衛星。土星の衛星の中では最大で、惑星である水星をしのぐほど。","note":"ハワイ沖<br/>発見物カード:385","exp":"770"}],"5719":[{"type":"宗教遺物","name":"ブラギの竪琴","rank":"5","desc":"北欧神話の詩の神ブラギが奏でたという黄金の竪琴。天界から冥界まで響きわたり、川や木々もその音色に聞き惚れたという。","note":"北欧神話の芸術の神","exp":"1460"}],"2693":[{"type":"植物","name":"ヒロハハシドイ","rank":"2","desc":"朝鮮王朝の徳寿宮で珍重されている植物。\n薄い桃色の花が密集して咲く。","note":"王朝の花<br/><br/><br/>発見時経験値370　発見物カード経験値185","exp":"370"}],"1680":[{"type":"虫類","name":"ヘラクレスオオカブト","rank":"5","desc":"熱帯林の広範囲に生息する、体長ほどもある二本の長い角をもった大型の虫。羽は黄褐色をしていて、黒い斑点がある。","note":"力強い肢体","exp":"1001"}],"5061":[{"type":"港・集落","name":"サンクトペテルブルク","rank":"1","desc":"バルト海のフィンランド湾最東端に位置するロシア帝国の港街。\n街名は「聖人ペテロ」に由来する。演劇や美術、文学が盛んな文化都市として発展した。","note":"到達する","exp":"80"}],"3536":[{"type":"レリック","name":"ポトシ銀山","rank":"","desc":"スペイン語で「豊かな丘」を意味する「セロ・リコ」と呼ばれる銀鉱山。銀に魅せられた人々の想いが燻ぶる地である。","note":"","exp":""}],"360":[{"type":"歴史遺物","name":"アレクサンドロス大王の鎧","rank":"3","desc":"マケドニアの王にして地中海からペルシャまでの巨大な版図を築いた、アレクサンドロス大王の鎧。エジプトやペルシャの宝石を使った、豪奢な造りだ。","note":"王の還る地","exp":"506"}],"130":[{"type":"宗教遺物","name":"聖母のステンドグラス","rank":"1","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40"}],"6661":[{"type":"歴史遺物","name":"ウルブルン沈没船","rank":"2","desc":"紀元前13世紀、フェニキア文明圏の商船。カナンを始め東地中海の都市を巡り貿易を行っていたという。主な積荷は銅のインゴット。トルコの南岸付近にて沈没した。","note":"東地中海　ロードス島の北","exp":""}],"2737":[{"type":"史跡","name":"金庚信の墓","rank":"3","desc":"新羅の将軍・金庚信の墓。\n金庚信は花郎の出身で武烈王から厚い信頼を得た。新羅の三国統一に多大な功績を残したものの、統一目前で没し、ここに葬られた。","note":"花郎の将軍","exp":"540"}],"2809":[{"type":"植物","name":"シオン","rank":"3","desc":"中国、朝鮮など広い地域に生息する、秋に咲く薄紫色の花。その姿から「紫苑」と呼ばれる。\nシオンの根は漢方薬としても使われている。","note":"恋人に贈る花束","exp":"460"}],"708":[{"type":"財宝","name":"人魚の涙","rank":"3","desc":"直径2cmもの真珠。しかも純白で素晴らしい光沢を持っている。ほかの真珠とは明らかに格の違う美しさがあり人魚の涙だと信じられたのもうなずける。","note":"人魚の涙","exp":"495"}],"6556":[{"type":"宗教建築","name":"ケルアンのミナレット","rank":"5","desc":"角柱型のミナレット。イスラム教の聖地の一つ、北アフリカのケルアンに建てられた。最下段はウマイヤ朝の総督が728年に建造したと伝わる。その独特の形は、ローマ時代の灯台をモデルにしたと考えられる。","note":"レガシー『英知の灯アレクサンドリア』右下","exp":""}],"5511":[{"type":"歴史遺物","name":"マンクニウムの砦の石","rank":"2","desc":"ブリテン島の中西部で砦の建材に使用された石の欠片。古代ローマ帝国が築いた前哨陣地「マンクニウム」のものと見られる。","note":"クエスト「マンチェスターの起源」<br/>発見物カード:330","exp":"363"}],"272":[{"type":"宗教遺物","name":"アクスムの石柱","rank":"2","desc":"一枚岩から削り出した巨大な石柱が林立している。立っているもので最高25m、倒れているものでは33mのものがある。基部に石室があることから、墓だと思われる。","note":"クエスト「プレステ・ジョアンの石柱」<br/>発見物カード:105","exp":"210"}],"6837":[{"type":"美術品","name":"レウキッポスの娘たちの略奪","rank":"5","desc":"ギリシャ神話の一幕を題材とし、17世紀初頭に描かれた油彩画。フランドルの画家ルーベンスの作。「オレイテュイアを略奪するボレアス」の後に描かれた。ルネサンス期の絵画から学んだ、多くの技巧が凝らされているバロック絵画の傑作。","note":"追究クエスト<br/>発見物カード:480","exp":"960"}],"6917":[{"type":"史跡","name":"トルコの石灰華段丘","rank":"5","desc":"","note":"","exp":"1077"}],"6383":[{"type":"天文","name":"トレミー星団","rank":"2","desc":"さそり座にある恒星の集団。肉眼でも確認できるほど明るい星々。48星座を分類した、プトレマイオスことトレミーが記述を残していることから「トレミー星団」と呼ばれる。","note":"「天文学者の観測記録」<br/>発見物カード:145","exp":"290"}],"1420":[{"type":"歴史遺物","name":"トルテカの戦士像","rank":"3","desc":"中央アメリカで繁栄したといわれるトルテカ人の戦士の像。神殿の柱として造られたりもした。トルテカ人は戦闘色の強い民族だったという。","note":"古代の戦士たち","exp":"450"}],"5400":[{"type":"地理","name":"サントリニ島","rank":"1","desc":"クレタ島のカンディアから北北東にある小さな島である。中央に火山があり、はるか昔に大噴火を起こしたと伝えられている。伝説の古代文明・アトランティスがあったという説もある。","note":"古代文明の伝説","exp":"20"}],"6403":[{"type":"史跡","name":"ミンドスの門","rank":"5","desc":"カリアの王マウソロスがハリカルナッソスに築いた堅固な城門。アレクサンドロス大王の攻撃にも容易に落ちず防衛の要となった。しかし陥落後、ハリカルナッソスの市街地はアレクサンドロスの軍勢に破壊されてしまったという。","note":"レガシー：ハリカルナッソス","exp":"2250"}],"6713":[{"type":"宗教遺物","name":"持国天像","rank":"5","desc":"四天王に数えられ、東方の守護神とされている仏神の像。手には宝器として琵琶を持つ。","note":"","exp":"415"}],"6853":[{"type":"天文","name":"おおいぬ座散開星団","rank":"3","desc":"おおいぬ座の中にある星団。シリウスの南に複数の星が集まっているため目視も可能。精度の高い望遠鏡であれば星雲状の光の中に明るく輝く複数の星が確認できる。","note":"発見物カード:225","exp":"450"}],"6629":[{"type":"虫類","name":"ハグロトンボ","rank":"2","desc":"黒色のトンボ。体は黒く緑色の金属光沢がある。特徴的なのは翅で他のトンボのように透明でなく黒色をしている。動かし方も他と異なり、蝶のようにひらひら舞うように羽ばたいたり、翅を立ててとまったりする。","note":"「真っ黒な昆虫の地図」<br/>発見物カード:160","exp":"320"}],"5229":[{"type":"財宝","name":"アルマゲスト","rank":"3","desc":"２世紀後半にアレクサンドリアのクラウディオ・プトレマイオスが著した数学と天文学に関する専門書。古代ギリシャで発達した数学や天文学を知る上で欠かせない存在である。","note":"","exp":"470"}],"5758":[{"type":"海洋生物","name":"オームリ","rank":"1","desc":"バイカル湖に生息するサケに似た魚。産卵期には湖に流れ込む河川を遡上し、産卵すると湖に戻ってくる。食すと非常に美味である。","note":"2017.02.07新規追加<br/>ゴロミャンカ発見が前提の可能性有り","exp":"190"}],"1294":[{"type":"中型生物","name":"センザンコウ","rank":"2","desc":"ウロコがある哺乳類。危険を感じるとボールのように丸まって敵から身を守るようだ。とても長い舌を持っており、これでアリをなめとっている。アリしか食べないのだろうか？","note":"陸の魚","exp":"270"}],"1264":[{"type":"美術品","name":"怠け者の天国","rank":"3","desc":"ピーテル・ブリューゲル（父）作。農民のいる情景を好んで描き、「農民ブリューゲル」と呼ばれる。この絵に描かれている僧侶や兵士、農民は、なにもせずに美食にありつき、ただ寝そべるだけである。","note":"怠惰な世界","exp":"473"}],"491":[{"type":"宗教遺物","name":"金のスカラベ","rank":"3","desc":"スカラベとはオオタマオシコガネのことで、動物のフンを転がして玉にし、卵を産みつける習性がある昆虫のことである。古代エジプトでは、フンを転がす姿が太陽の運行を連想させるとして信仰され護符に多用された。","note":"古代エジプトの護符","exp":"495"}],"5454":[{"type":"植物","name":"ガラナ","rank":"2","desc":"中南米などの地域で見られる植物。果実が赤く、熟すと黒い種子が現れる。この種子は滋養強壮に良いと信じられており、先住民の間では古くから重宝されてきた。","note":"","exp":"370"}],"956":[{"type":"鳥類","name":"ラケットヨタカ","rank":"2","desc":"翼の部分に、さらに長い羽が付いている。地面からかなりの高度を飛び、昆虫を主食とする。","note":"変わった鳥の話","exp":"220"}],"5102":[{"type":"港・集落","name":"ドゥアラ","rank":"1","desc":"大西洋のギニア湾に面する港町。広大な平地が広がるが、北西部には山岳地帯がそびえている。","note":"到達する","exp":"68"}],"6204":[{"type":"財宝","name":"ピッツィガーノの海図","rank":"5","desc":"15世紀ヴェネツィアの地図職人ツアン・ピッツィガーノが作成した羅針儀海図。ヨーロッパ大陸の西側洋上に奇妙な島が描かれており、まるで新発見の島であることを強調するかのようにそれぞれ赤と黒に塗られている。","note":"謎は細部に宿るか","exp":"1000"}],"6602":[{"type":"大型生物","name":"アモイトラ","rank":"5","desc":"中国南部の山地や森の奥深くに生息するという猛獣。トラの中では比較的小さい種だが、人を襲うこともあるため、注意が必要。","note":"","exp":"830"}],"3759":[{"type":"天文","name":"太陽黒点","rank":"4","desc":"太陽の表面に現れる黒い点のような模様。太陽の光が弱まる日没時などには、まれに肉眼でも確認できることがある。東洋の各地には太陽に住む烏の神話が伝わっているが、これらは黒点を見て作られた可能性がある。","note":"太陽のシミ","exp":"630"}],"535":[{"type":"歴史遺物","name":"青銅器","rank":"1","desc":"古代文明で使われていた青銅の器。青銅は加工が容易で扱いやすいため、多くの古代文明で用いられた。","note":"古代の道具の地図","exp":"29"}],"5743":[{"type":"宗教遺物","name":"女教皇ヨハンナの像","rank":"5","desc":"女教皇ヨハンナのものとされる像。とはいえ彼女が実在した確たる証拠はなく、この像が本当にヨハンナをモデルにしているかは不明。","note":"女教皇の伝説<br/>2017.02.07新規追加","exp":"1450"}],"269":[{"type":"歴史遺物","name":"ブリューナク","rank":"5","desc":"ケルト神話四大秘宝の一つで太陽神・ルーの持ち物。光を放つ槍で同時に五人の敵を倒せるという。この槍をふるう姿からルーは「長き腕のルー」と呼ばれる。","note":"ブリューナク","exp":"1209"}],"903":[{"type":"鳥類","name":"ダチョウ","rank":"2","desc":"頭の高さが2.5mにもなる大型の鳥。体に比べて翼が小さく飛べないようだが、脚が非常に発達していて馬並みに走れる。蹴られれば人間など簡単に死ぬことだろう。","note":"馬のような鳥","exp":"260"}],"5007":[{"type":"小型生物","name":"ロシアデスマン","rank":"1","desc":"河川や湿地に生息するモグラ。泳ぎが得意で貝類なども捕食する。毛皮目的の乱獲で生息数が減っている。","note":"西シベリア平原<br/>コーカサス地方の再調査報酬","exp":""}],"5122":[{"type":"港・集落","name":"ヒバオア","rank":"2","desc":"マルキーズ諸島南部にあるヒバオア島の街。独特の山並みが特徴の火山島である。熱帯圏でありながら、冷涼な南赤道海流の影響を受け、年間を通じて温暖快適な気候である。","note":"到達する","exp":"300"}],"2910":[{"type":"財宝","name":"淡水語辞典","rank":"3","desc":"イスパニア人が編さんした、淡水で使用されていた言語の辞典。\n台湾島の先住民や移住民にカトリックを布教するために使われた。","note":"ダンジョン","exp":"460"}],"144":[{"type":"歴史遺物","name":"カエサリオンの大理石像","rank":"1","desc":"ユリウス・カエサルとクレオパトラ7世の間に生まれた、カエサリオンの大理石像。一時はカエサルの後継者と認められたが、クレオパトラの死後、殺されたという。","note":"クレオパトラの息子","exp":"100"}],"6554":[{"type":"化石","name":"角のような貝の化石","rank":"5","desc":"北米の金鉱掘りが、金脈を探している際に偶然見つけた化石。そのとてつもない大きさから、見つけた当人は竜の角の化石と言い張っているが…恐らく巨大な直角貝の化石と思われる。","note":"追究クエスト","exp":"1760"}],"5315":[{"type":"鳥類","name":"ハシビロコウ","rank":"3","desc":"アフリカ中部から南部にかけての湿地に生息する大型の鳥で、巨大なくちばしが特徴。動きがゆったりとしており、しばしば彫像のように動きを止める。獲物である魚に警戒されないようにするためだと考えられる。","note":"","exp":"540"}],"589":[{"type":"海洋生物","name":"ケープペンギン","rank":"1","desc":"頭からのどにかけて独特の模様があるペンギン。南アフリカに生息する。何羽いるのかわからないほどの大群で生息している。","note":"黒い水鳥の地図","exp":"39"}],"1441":[{"type":"小型生物","name":"フクロムササビ","rank":"2","desc":"滑空する有袋類。爪は長く、指は枝をしっかりとつかむように向かい合っている。大きな耳と前方に付いた目で距離を測り、暗闇でも100mを超える滑空を行う。","note":"違いを探る","exp":"320"}],"875":[{"type":"小型生物","name":"ブラックマンバ","rank":"2","desc":"アフリカに生息する、猛毒のヘビ。移動が速く、走る人間に追いつくほどだという。非常に危険な生物だといえるだろう。","note":"逃れられない毒蛇","exp":"270"}],"1347":[{"type":"虫類","name":"ダイオウヒラタ","rank":"3","desc":"がっしりとした体で、湾曲した太くて短いハサミが特徴の虫。とても凶暴である。","note":"学者の願い","exp":"451"}],"3531":[{"type":"レリック","name":"ヌマ・ポンピリウス","rank":"","desc":"古代地中海世界に覇を唱えたローマ帝国。その基盤を作ったのは、意外にもローマの外から招かれた賢王であった。","note":"","exp":""}],"6432":[{"type":"歴史遺物","name":"サラミスのアバカスタブレット","rank":"5","desc":"紀元前300年ごろの古代ギリシャで使用されていたという計算盤。現存する最古の線ソロバンとされる。テーブルくらいの大きさと厚みがある白い大理石の板で、表面に刻まれた線に沿って小石などの珠を置き、計算を行った。","note":"レガシー　数の叡智・世界の計算機　中央","exp":""}],"1923":[{"type":"海洋生物","name":"イワトビペンギン","rank":"1","desc":"目の上に黄色い飾り羽があるペンギン。群れで生活し、岩場を器用にジャンプしながら移動する。陸上での動作はにぶいが、水中では魚のように泳げる。","note":"凛々しい目つきの鳥","exp":"180"}],"2067":[{"type":"海洋生物","name":"ウツボ","rank":"1","desc":"温暖で浅い海に生息。細長でヒレが小さく、太いヘビのような姿をしている。近くに敵が来ると口を大きく開けて威嚇し、鋭い歯で噛みつくこともある。\n体の模様や色は決まっておらず、多彩であるようだ。","note":"不気味な魚の地図","exp":"60"}],"792":[{"type":"宗教遺物","name":"戴冠石","rank":"1","desc":"運命の石、リア・ファイルとも呼ばれる。真実の王が触れると叫び声をあげると伝えられる。伝説のアーサー王は石に刺さった剣を抜いて王となったが、剣が刺さっていたのがこの石だともいわれる。","note":"戴冠石","exp":"170"}],"4984":[{"type":"史跡","name":"ロードス騎士団の城塞都市","rank":"3","desc":"本拠地を奪われた聖ヨハネ騎士団がロードス島に築いた要塞都市。\n街全体を囲む高さ12mの城壁は、全長4kmに及び、敵国の攻撃を幾度となく撃退したという。","note":"ロードス島を再調査","exp":"540"}],"1878":[{"type":"宗教遺物","name":"ジャガー戦士の面","rank":"5","desc":"ジャガー戦士とは、アステカに見られた戦士である。貴族階級の精鋭のみがジャガー戦士たりえたという。この面には、名誉ある死を遂げた戦士に対する敬拝の意が込められているのだろうか。","note":"アステカの誇り高き勇者","exp":"1040"}],"6329":[{"type":"虫類","name":"アズチグモ","rank":"3","desc":"アジアに広く生息するクモ。つり上がったような形の目が特徴的。雌は体が白色でまだら模様があり、周囲の環境に合わせて体色が変化する。また雄の三倍ほど大きい。雄の体は褐色で雌には似ていない。","note":"","exp":"480"}],"6318":[{"type":"虫類","name":"ブルーアーガス","rank":"3","desc":"東南アジアなどの温暖な地域に生息する美しいチョウ。前後の羽それぞれにある大きな二対の目玉模様が特徴。雄の羽は青いが雌の羽は茶褐色で、目玉模様も雄より大きい。","note":"","exp":"500"}],"6600":[{"type":"宗教遺物","name":"シヴァとパールヴァティーの石像","rank":"4","desc":"インド神話の創造と破壊の神シヴァと、妻であるパールヴァティーを模した石像。パールヴァティーはシヴァの膝に座り、足元には彼らを象徴する神聖な動物がいる。","note":"","exp":""}],"3633":[{"type":"宗教遺物","name":"ある聖人の生涯記","rank":"3","desc":"後に聖人となったキエフ大公国の人物の生涯を記した書物。年代記者ネストルの著書とされ、『原初年代記』にも記述が見られる。","note":"ある聖人たちの記憶","exp":"480"}],"6172":[{"type":"歴史遺物","name":"オクシリンコス・パピルス","rank":"3","desc":"エジプト中部のオクシリンコスで発見された数千点に及ぶ\nパピルス文書のひとつ。文書の大部分は公文書や裁判記録\nなどだが、プラトンなど古代ギリシャ哲学者や詩人の著作\n当時の信仰に関係する文献や聖歌の楽譜などもある。","note":"クエスト「思わぬ出どころ」<br/>発見物カード:265","exp":"530"}],"5933":[{"type":"財宝","name":"ジョゼの父への脅迫状","rank":"1","desc":"くしゃくしゃになった紙束。かろうじて「娘の命……船……王族……殺……」といった単語が読み取れる。細かい状況まではわからないが、これは脅迫状のたぐいだろうか。","note":"","exp":"113"}],"3309":[{"type":"財宝","name":"ダロウの書","rank":"2","desc":"アイルランド、及びブリテン島で制作された最古の福音書写本。ケルズの書同様に豪華な装飾が施されている。文字は「島の文字」と呼ばれる独特の書体で書かれている。","note":"装飾された写本の地図","exp":"340"}],"4950":[{"type":"地理","name":"オリンポス山","rank":"1","desc":"サロニカの南西にあるギリシャ最高峰の山。山麓と海が近く、ヨーロッパの中で最も比高のある山でもある。ギリシャ神話では、オリンポス十二神と呼ばれる神々が住まう山とされている。","note":"","exp":"140"}],"1605":[{"type":"宗教遺物","name":"カニシカ王の舎利容器","rank":"3","desc":"クシャーナ朝に最盛期をもたらしたカニシカ王の遺骨が納められたとされる容器。青銅製の容器のふたには仏陀梵天、帝釈天の三尊像が据えられている。この像は、ガンダーラ地方で作られた仏像の様式の中でも最初期のものである。","note":"御姿を形に","exp":"484"}],"2713":[{"type":"虫類","name":"モンクロベニカミキリ","rank":"2","desc":"朝鮮半島及び、日本を含む東アジア圏に分布する、派手な外見のカミキリムシ。\n黒の模様で染められた赤い羽が目立つ。","note":"赤と黒の虫の地図","exp":"210"}],"222":[{"type":"財宝","name":"ドラゴンの牙","rank":"2","desc":"ドラゴンの牙だと伝えられる物。黒光りした巨大な牙で、これが本当にドラゴンのものなら体長は100mを超えるだろう。本物かどうかは確かめようがないが見ていると勇気がわいてくるようだ。","note":"ドラゴンの牙","exp":"370"}],"1260":[{"type":"美術品","name":"ラオコーン（腕伸ばし）","rank":"5","desc":"ラオコーンはトロイの神官で、トロイの木馬を防ごうとした人である。ギリシャに肩入れするアテナが放った大蛇に襲われ、二人の子と共に命を落とした。","note":"トロイ戦争のてん末","exp":"923"}],"1076":[{"type":"美術品","name":"キリスト降架","rank":"4","desc":"ルーベンス作の祭壇画の一枚。処刑されたイエスを、母マリアたちが十字架から降ろす光景である。誇張された肉体とポーズ、劇的な光の使い方など、それまでの絵画とは一線を画している。","note":"王の画家にして画家の王","exp":"780"}],"11":[{"type":"財宝","name":"アスモダイの宝玉","rank":"1","desc":"聖書のソロモン王が、悪魔や精霊72体を封じ込めたという宝玉の一つ。この宝石にはアスモダイが封じられているという。真偽の程は不明だ。\n宝玉はよく見ると傷があり、「アトランティス」と彫られている。","note":"アスモダイの宝玉<br/><br/>発見時経験値100　発見物カード経験値50","exp":"100"}],"2984":[{"type":"海洋生物","name":"オオカミウオ","rank":"2","desc":"比較的寒い地域の海に生息する魚。鋭く強靭な歯で貝やカニの甲羅などを割って食べる。おとなしく、こちらがいたずらをしなければ噛みつかれることはない。","note":"釣り","exp":"310"}],"819":[{"type":"財宝","name":"大理石の男性像","rank":"1","desc":"大理石の男性像。ギリシャ時代の作風を模倣したもので、肉体美をよく表している。","note":"大理石の男性像の地図","exp":"108"}],"2422":[{"type":"海洋生物","name":"オオウナギ","rank":"1","desc":"通常のウナギの倍以上にまで成長することがある魚。\nただし、ウナギとは別種で、ややずんぐりとした体形と斑模様により見分けられる。","note":"釣り","exp":"200"}],"1034":[{"type":"大型生物","name":"イノシシ","rank":"1","desc":"ずんぐりした体に短く鋭い牙を持つ動物。気性が荒く、人間が襲われることもある。豚の祖先だと思われる。","note":"野生の豚の地図","exp":"36"}],"947":[{"type":"海洋生物","name":"フクロウナギ","rank":"2","desc":"深海に生息していると思われる、奇妙な姿の魚。ヘビのように細長い体に、とてつもなく大きな口をしている。尾の先は発光するようだ。","note":"不気味な魚の地図","exp":"295"}],"1845":[{"type":"財宝","name":"アラビアの家具","rank":"2","desc":"幾何学模様や花柄模様のアラベスクがびっしりと施された、最高級の調度家具。クッション部分の中綿も外生地も最高級品で、イスラム文化の高度な工芸技術を感じることができる。","note":"イスラム世界が描かれた家具","exp":"330"}],"7007":[{"type":"美術品","name":"レパントの海戦の寓意","rank":"3","desc":"パオロ・ヴェロネーゼ作の油彩画。絵画の下部にはレパントの海戦が、上部には聖母のもとに集った聖人が連合艦隊に祝福を与える様子が描かれている。聖母の前に跪く女性は、ヴェネツィアの擬人像とされる。","note":"","exp":""}],"755":[{"type":"財宝","name":"コーンフラワーブルー","rank":"3","desc":"最上級のサファイヤ。矢車菊のような美しい青色をしているため、こう呼ばれる。限られた地域でしか採れないという。","note":"青い宝石の鉱脈の地図","exp":"530"}],"1120":[{"type":"財宝","name":"呪われた指輪","rank":"3","desc":"見る者を魅了する、素晴らしい細工が施された指輪だ。しかし、これまで所有したすべての者が、悲惨な運命に見舞われている。何か恐ろしい呪いがかかっているとしか考えられない…。","note":"サンジョルジュの数奇な宝石","exp":"506"}],"6537":[{"type":"伝承","name":"ノーム","rank":"5","desc":"土の精。四大元素のうち、土をつかさどるとされる精霊。ヒゲを貯えた小さな老人のような姿で、豊かな土壌を好むらしい。埋蔵物を探知する能力を持ち、貴金属や財宝を容易に掘り出せる。非常に賢く器用で、細工品を作るのが得意だという。","note":"","exp":"1060"}],"2952":[{"type":"地理","name":"セントローレンス川","rank":"3","desc":"北米内陸から東岸へと流れ出る大河。川幅がとても広く、川の途中には大小様々な島が浮かぶ。","note":"大陸の内側へ","exp":"540"}],"2245":[{"type":"中型生物","name":"リクイグアナ","rank":"3","desc":"体長1mほどの、大型のトカゲ。黄褐色の体に太い尾が特徴。草食性で、主にサボテンを食べる。性質はおとなしい。","note":"サボテンの下で","exp":"490"}],"6529":[{"type":"歴史遺物","name":"デンデラの天体図","rank":"5","desc":"プトレマイオス朝エジプトで建設された、デンデラのハトホル神殿天井にあるレリーフ。ギリシャと同じ黄道十二宮の星座などがエジプト風の絵柄で表されている。天体の位置が異なるのは神殿建設当時の星を反映しているのかもしれない。","note":"レガシー星の叡智　右上","exp":"1500"}],"5298":[{"type":"小型生物","name":"サハラツノクサリヘビ","rank":"4","desc":"サハラに棲む毒へビ。目の上にある2本の角状の突起が特徴。突起がないものもいる。背には斑紋があり、砂の中に隠れて獲物を待ち伏せする。斜めに進む独特の動きで砂地を素早く移動できる。","note":"","exp":"740"}],"5123":[{"type":"港・集落","name":"ヒホン","rank":"1","desc":"ボルドーの西、ビスケー湾南岸にある小都市である。発祥は古代ローマ軍の軍営地だという。","note":"到達する","exp":"24"}],"3757":[{"type":"天文","name":"さそり座","rank":"4","desc":"黄道十二星座の1つ。女神ヘラの命で傲慢なオリオンを殺した、サソリが天に昇った姿とされる。天の川にS字を描き、アンタレスを始めとして明るい星が多く、見つけやすい星座である。","note":"天に輝くサソリ","exp":"650"}],"6733":[{"type":"中型生物","name":"キットギツネ","rank":"5","desc":"北米大陸の砂漠に生息する小型のキツネ。雑食で小型哺乳類、昆虫や果実などを食べる。自分で巣穴を作る以外に他の動物の古巣も利用する。","note":"発見個所　北米西岸　ジェノヴァ新規地図","exp":""}],"6726":[{"type":"地理","name":"ピトン","rank":"5","desc":"カリブ海のセントルシア島にある二つの小さな火山。標高の高いものがグロピトン山、低いものがプチピトン山とされ、双子の山と呼ばれている。","note":"","exp":""}],"5094":[{"type":"港・集落","name":"テルナーテ","rank":"2","desc":"テルナーテ王国の首都で、モルッカ諸島北部に位置するテルナーテ島にある。近年、同島で産出される高価な香辛料を求め、ヨーロッパ人が進出。街を建造するに至った。","note":"到達する","exp":"350"}],"6460":[{"type":"地理","name":"ヴァッレ・デル・ボーヴェ","rank":"5","desc":"シチリア島火山、エトナ山の東斜面にある大きなくぼ地。エトナ山はヨーロッパで最も高い活火山だが、標高が頻繁に変わるほど火山活動が活発だとされる。このくぼ地ができた原因も噴火なのか、大規模な山崩れや陥没なのか、諸説ある。","note":"追求クエスト<br/>発見物カード500","exp":"1000"}],"5351":[{"type":"海洋生物","name":"メンダコ","rank":"3","desc":"深海に棲むタコの一種で通常のタコと違って吸盤が一列しかない。\n水から出すと体が潰れてしまうほど柔らかい。\n身は非常に塩辛い上に臭いがきつく、食用には向かない。","note":"","exp":"440"}],"6223":[{"type":"小型生物","name":"コビトイノシシ","rank":"1","desc":"インド北東部からヒマラヤ山脈南部にかけて生息するイノシシ。その名の通りイノシシの仲間の中では最小とされる。全身が褐色や黒褐色の体毛で覆われ、湿気の多い草地を好むという。体が小さいため、天敵も多いと推測される。","note":"小さなイノシシの地図","exp":"200"}],"5414":[{"type":"宗教遺物","name":"ポセイドン像","rank":"1","desc":"ギリシャ神話の海神の像。ポセイドンは多くの愛人を持ち、その子供にはポリュフェモスなど、凶暴な怪物が多い。有名なメデューサもポセイドンの愛人でその子供がペガサスである。","note":"海神の像","exp":"60"}],"2701":[{"type":"宗教遺物","name":"酒泉石","rank":"4","desc":"朝鮮の神話に登場する不思議な石。\nこの石の窪みに水を注いでおくと、いつの間にか酒に変わっているという。","note":"王子の心残り","exp":"650"}],"2899":[{"type":"中型生物","name":"アルガリ","rank":"2","desc":"中国を中心に、主に高原地帯に生息する、体長120cm前後の大型のヒツジ。\n雌雄共に角を持ち、雄の角は1mを超すほどの長さにまで成長する。","note":"大きなヒツジの地図","exp":"250"}],"6448":[{"type":"歴史遺物","name":"ハンガリー王妃の水","rank":"5","desc":"中世ヨーロッパで作られていたローズマリーの薬酒。香りが良く、香水としても用いられた。病身の老いたハンガリー王妃が服用したところ、病が癒えただけでなく美しく若返ったため、他国の王子から求婚されたとの伝説が語り継がれている。","note":"","exp":"1650"}],"5109":[{"type":"港・集落","name":"ハワイ","rank":"2","desc":"絶海の島にある街。太平洋のほぼ中心に位置する。4～8世紀ごろにポリネシアから人が移住してきたと推測される。火山が多く、島の地質は凝固した溶岩から成る。","note":"到達する","exp":"320"}],"6158":[{"type":"宗教遺物","name":"貧者の聖書","rank":"2","desc":"聖書中に出てくる出来事を抜粋して描いた木版印刷。13世紀中頃に東南ドイツ・オーストリアで成立すると、活版印刷の普及に伴ってヨーロッパ中に広がった。当時の教会で主流であった予型論に基づいて制作された。","note":"","exp":"210"}],"1093":[{"type":"地理","name":"ピノス島","rank":"2","desc":"キューバ島西部の南に浮かぶ島。名はスペイン語で「松」の意味。比較的、大きな島だ。キューバ島は耕作に向いているので栄えているが、ピノス島はあまり人がいないようだ。","note":"クエスト「キューバ近辺の島」<br/>発見物カード:180","exp":"365"}],"2367":[{"type":"植物","name":"ヒメハマナデシコ","rank":"1","desc":"海岸の砂浜や岩場に生育する、日本固有の植物。紅紫色の可憐な花を咲かせ、潮風に耐えつつ岩肌を彩る。","note":"浜辺に咲く花の地図","exp":"150"}],"2994":[{"type":"鳥類","name":"シロフクロウ","rank":"4","desc":"大型のフクロウ。真っ白な羽毛が美しい。\n高所にはあまり生息しておらず、寒冷地帯の草原でよく見られる。","note":"白の叡智","exp":"780"}],"5759":[{"type":"地理","name":"エオリア諸島","rank":"5","desc":"シチリア島の北方に位置する島々。火山活動によって出来た諸島であり、中でもストロンボリ島は盛んに噴火している。","note":"2017.02.07新規追加","exp":"1400"}],"2117":[{"type":"宗教遺物","name":"宣教師の遺品","rank":"2","desc":"異国の地で教えを広めようとしていた宣教師の遺品。ヨーロッパでは見慣れた物だ。","note":"［勅命］[[現地における思想についての調査","exp":"310"}],"1452":[{"type":"宗教建築","name":"太陽の石","rank":"5","desc":"アステカは、天文学に長けており、独自の暦を持っていた。この石板によれば、世界は5回の変遷を経験し、それぞれある原因で滅亡したとある。石板によると、現在の世界は地震で滅亡するらしい。","note":"血と心臓を求める理由","exp":"1027"}],"5232":[{"type":"美術品","name":"アポクシュオメノス","rank":"2","desc":"古代ギリシャ彫刻に見られる身体を拭う人を模した彫象。手にはなにか道具のようなものを持つ。なぜこのような姿勢を模したのかは不明だが、独特な魅力をかもし出している。","note":"","exp":"350"}],"6337":[{"type":"宗教遺物","name":"踊る人の石碑","rank":"2","desc":"南アメリカ周辺で発見された石碑。踊っているような人々の絵が刻まれている。踊っているのではなく、捕虜となった人が拷問を受けている姿だという説が主流となっている。","note":"","exp":"260"}],"5188":[{"type":"港・集落","name":"江戸","rank":"2","desc":"近年急速に発展してきている、太平洋沿岸の街。入り江を埋め立てて住宅地を造成するなど、有力者の主導の下で計画的な街づくりが進められている。","note":"到達する","exp":"375"}],"5034":[{"type":"港・集落","name":"カサブランカ","rank":"1","desc":"アフリカ大陸の北西に位置する小都市。かつてはベルベル人の王朝があり、交易都市として非常に栄えていた。15世紀中ごろ、ポルトガルによって破壊されたため、そのころの面影は残っていない。","note":"到達する","exp":"26"}],"4806":[{"type":"財宝","name":"笙","rank":"3","desc":"竹を主な材料として作られた楽器。吸っても吹いても同じ音が出るため、息継ぎの必要はない。側面に複数の穴が設けられており、押さえ方を変えて様々な音を出す。","note":"紅毛城（中層隠し部屋）","exp":""}],"5098":[{"type":"港・集落","name":"トリエステ","rank":"1","desc":"ヴェネツィアからほど近い街。アドリア海の最奥に位置し、古代ローマ時代から港町として栄えてきた。冬季には、ボラと呼ばれるすさまじい強風が吹き荒れる。","note":"到達する","exp":"17"}],"6111":[{"type":"財宝","name":"白氏文集","rank":"2","desc":"中唐の文人である白居易文集。はくしぶんしゅうと読む。\n生前から多作の詩人として知られ、身分問わず広く読まれた。\n彼の詩は日本や新羅にも早くに伝わったが、偽作の民間\n流布本も多く出回ったという。","note":"現在は｢はくしもんじゅう」の読み方が一般的ですが、平安時代～明治時代までは｢はくしぶんしゅう｣と読まれていました。。。","exp":"380"}],"1727":[{"type":"財宝","name":"恒久なる星々","rank":"5","desc":"オーストラリアでのみ見つかる、黒いオパール。地が黒であるためさらに遊色が映える。月のない夜に輝く幾千の星を思わせる美しさで、見ていると月のない夜に一人たたずんだときに空に吸い込まれてしまうような、あの感覚に陥る。","note":"恒久なる星々","exp":"1183"}],"3160":[{"type":"小型生物","name":"アメリカミンク","rank":"4","desc":"北米の川や湖の周辺に生息する動物。こげ茶色の上質な毛並みを持つ。ヨーロッパミンクよりひと回り大きい。","note":"新天地の魅惑の毛皮","exp":"630"}],"2974":[{"type":"鳥類","name":"イヌワシ","rank":"5","desc":"北米大陸に広く生息する、大型の鳥。\n翼を広げると2m以上にもなる。全身が暗褐色の羽毛で覆われているが、後頭部は光沢のある黄色い羽毛で覆われている。シカやキツネを襲うこともある。","note":"強き者の証明","exp":"810"}],"6032":[{"type":"化石","name":"顎が大きな魚の頭骨","rank":"5","desc":"強靭な顎を持つ、巨大な生物の頭骨。非常に重厚な骨で覆われている。魚のようであるが、体の後部の骨は見つかっていない。","note":"","exp":"990"}],"2668":[{"type":"鳥類","name":"クロツラヘラサギ","rank":"3","desc":"朝鮮半島北西部でよく見られるサギの一種。全身の羽毛は白く、顔とくちばしだけが真っ黒なため、その部分が目立つ。\n夏になると、首が黄色く変化し、後頭部から黄色の冠羽が生えてくる。","note":"黒い顔の渡り鳥","exp":"510"}],"90":[{"type":"宗教遺物","name":"ホルス像","rank":"1","desc":"エジプトの神の像。ホルスはオシリスとイシスの息子で、天空の神である。セトに殺害された父の敵を、母の助けにより果たした。隼の姿、もしくは隼の顔をした姿で表される。","note":"エジプトの天空神","exp":"110"}],"225":[{"type":"歴史遺物","name":"トリスタンの剣","rank":"2","desc":"イングランドの騎士トリスタンのものといわれる剣。彼の墓と思われる場所から発見された。トリスタンはイゾルデ姫との悲恋物語で知られる。","note":"トリスタンの剣","exp":"350"}],"6014":[{"type":"宗教遺物","name":"生神女マリアの裏衣","rank":"5","desc":"正教会において、生神女と呼ばれる聖母マリアが生前着ていたとされる簡素な衣服。裏衣は「うちごろも」と読む。ビザンツ帝国時代にコンスタンティノープルの教会に納められており、そこで起こったという奇蹟が正教会には伝えられている。","note":"『生神女』は『しょうしんじょ』と読む。","exp":"830"}],"61":[{"type":"財宝","name":"マハーバーラタ","rank":"2","desc":"インド最古の書物の一つである。十万の詩からなる、大規模な叙事詩。バーラタ人の戦争を語ったもので、神や神の子、仙人が登場して活躍する。","note":"インドの古代叙事詩","exp":"230"}],"4963":[{"type":"天文","name":"つる座","rank":"4","desc":"16世紀にオランダの航海者ペーテル・ケイセルとフレデリック・デ・ハウトマンが作った星座。かつては北にある、みなみうお座の一部だった。","note":"クエスト「ネーデルラントで作られた星座」<br/>発見物カード:345","exp":"690"}],"1539":[{"type":"歴史遺物","name":"三脚容器","rank":"1","desc":"三脚がついた円筒形の容器。材質は土器や陶器が多く、金属のものはまず見られない。細かな彫刻が施されているものが多い。","note":"メソアメリカの容器の地図","exp":"110"}],"3017":[{"type":"歴史遺物","name":"鳥人の銅板","rank":"4","desc":"独特の装飾を施された銅製の板。翼を持った人物の姿が打ち出されている。\n北米のエトワー川近辺で、身分の高い人物の副葬品として墳墓に納められていた。","note":"銅板に刻まれた有翼人","exp":"660"}],"6739":[{"type":"海洋生物","name":"ナンヨウマンタ","rank":"3","desc":"世界で二番目に大きいとされるエイの一種。オニイトマキエイに似ており、よく間違われるが、背中にある曲線状の白い模様や口元の色などで区別できる。インド洋、太平洋の熱帯・亜熱帯海域に広く分布している。","note":"カード経験:250","exp":"500"}],"712":[{"type":"小型生物","name":"バシリスク","rank":"4","desc":"全長70cm程度のトカゲである。体長の半分以上は尾で、後肢がよく発達しており、2本足で走る。足の指、特に中指が非常に長く、水面を駆け抜けることができる。","note":"水上を走るトカゲ","exp":"720"}],"1583":[{"type":"鳥類","name":"オウギバト","rank":"3","desc":"ニューギニア島、および周辺の小島に生息する。70cmを超える大きなハトで、飛行能力はなく、数mほど飛び上がれるだけである。","note":"美しい頭","exp":"451"}],"2353":[{"type":"財宝","name":"風信帖","rank":"1","desc":"読みは「ふうしんじょう」。空海が最澄に宛てて送った書状。\n日本に残る唐風の名筆である。空海は能書家としても名高く、この書状は彼の最高傑作と評されている。","note":"能書家の書状の地図","exp":"190"}],"5531":[{"type":"気象・現象","name":"ブラックスモーカー","rank":"3","desc":"海底火山などと同様、海底から高温の熱水が噴出する現象。熱水に含まれる亜鉛や鉄などが海水と反応し、黒く変色する。","note":"","exp":"260"}],"2336":[{"type":"歴史遺物","name":"縄文人の住居跡","rank":"1","desc":"日本に残る、古代人の住居跡。地面を掘って床とし、そこに柱を立ててある。\nこの辺りはかつて集落だったのか、周囲には同じような跡がいくつか見られる。","note":"古代の集落の地図","exp":"190"}],"3622":[{"type":"歴史遺物","name":"ピョートル1世の手形","rank":"4","desc":"ロシア皇帝ピョートル1世が遺した手形。海軍創設のため、自ら船大工に弟子入りしてかなづちを振るったという彼の手は、皇帝のものとは思えぬ屈強さがうかがえる。","note":"ロシア皇帝徹底調査","exp":"790"}],"16":[{"type":"歴史遺物","name":"石の鏃","rank":"1","desc":"やじり。石器時代のもので、どの文明にも見られる形状である。どこも同じような狩猟法であったということであろうか。","note":"アナトリア半島の狩猟生活","exp":"160"}],"5279":[{"type":"天文","name":"ちょうこくしつ座の渦巻星雲","rank":"3","desc":"ちょうこくしつ座のやや北にある渦巻き星雲。明るい星雲であるが、ヨーロッパではあまり高度が上がらないため観測が難しい。","note":"「天文学者の観測記録」<br/>発見物カード:220","exp":"440"}],"6955":[{"type":"虫類","name":"レッドフラットバークビートル","rank":"1","desc":"北米に生息する赤い甲虫。体長は15mm程度。非常に平らな体をしており、樹皮の下に潜んで木材を食べる他の小さな虫を補食する。また、極寒の地に適応しており、幼虫は生存が不可能な低温にも耐えるという。","note":"発見物カード:75","exp":"150"}],"5840":[{"type":"美術品","name":"信貴山縁起絵巻","rank":"5","desc":"平安時代の巻物。異時同図法で時間の経過を表現している点が特徴的。四大絵巻物の一つと称される。","note":"","exp":"1370"}],"1887":[{"type":"歴史遺物","name":"ヒローナ号","rank":"3","desc":"正式名称は、ラ・ヒローナ号。イングランド侵攻に出発したイスパニア艦隊の一隻。\n艦隊はイングランド海軍に敗北。ヒローナ号は敗走中にアイルランド沖で岩礁に激突し、沈没した。","note":"サルベージ","exp":"462"}],"1869":[{"type":"植物","name":"ノートロ","rank":"4","desc":"寒冷な風の大地、南米パタゴニアを代表する花。雪原や植物相の少ない土地で見る機会が多いためか、真紅の花が特に印象深い。連なる茎状の花が特徴。","note":"風の大地に咲く花","exp":"620"}],"695":[{"type":"宗教遺物","name":"クリシュナ像","rank":"3","desc":"インド神話のヴィシュヌ神の、第8の化身といわれる英雄の像。マハーバーラタという叙事詩に登場し、五王子を補佐して導く。他にも、クリシュナにまつわる神話は数多い。","note":"神の化身","exp":"484"}],"3685":[{"type":"地理","name":"バイカル湖","rank":"3","desc":"ロシア南東部とモンゴル北部の間に位置する巨大な湖。多くの河川が流入するため、水量が豊富で生物の生息数も多い。","note":"書きかけの地図","exp":"480"}],"3737":[{"type":"植物","name":"モスキャンピオン","rank":"4","desc":"コケマンテマとも呼ばれる植物。高山帯や寒冷な土地に分布する。地面を這って成長し、1cm程度の小さなピンク色の花を咲かせる。","note":"極寒の地に咲く花","exp":"680"}],"775":[{"type":"大型生物","name":"カバ","rank":"1","desc":"水辺に生息する、大型の動物。ずんぐりとした体に太く短い足が特徴である。頭、特に口がとても大きい。それに対して目や耳は小さく、独特の容貌をしている。","note":"川に潜む巨大生物","exp":"200"}],"6911":[{"type":"鳥類","name":"ルリオーストラリアムシクイの雄","rank":"5","desc":"雄のルリオーストラリウアムシクイ。通常期は雌と同じ灰色や茶褐色の姿をしているが、繁殖期になると鮮やかな青色の羽へ換羽する。花を使った求愛行動を行うことでも知られている。","note":"","exp":"630"}],"1877":[{"type":"財宝","name":"黄金郷の長衣","rank":"2","desc":"黄金郷と思われる地に潜入した勇敢な冒険者が持ち帰ったローブ。良質な生地から作られ高い技術を有していることがわかる。","note":"［勅命］[[黄金郷の財宝探索","exp":"310"}],"5212":[{"type":"歴史遺物","name":"武寧王の誌石","rank":"2","desc":"百済の武寧王が崩御した際の記録が描かれた石碑。当時百済は高句麗に攻められて衰退していたが、寧東大将軍とも呼ばれる武寧王は高句麗を破って梁王朝へ属し、百済を強国にした。","note":"公州北　陸地再調査報酬","exp":""}],"5724":[{"type":"地理","name":"カラ・ボガス・ゴル湾","rank":"2","desc":"カスピ海で最も大きな湾。カスピ海から流れ込んだ水が湾から外に流出しないため、カスピ海と比べて塩分濃度が高くなっている。そのため、カスピ海から流れてきた魚はすぐに死んでしまうという。","note":"2017.02.07新規追加","exp":""}],"5338":[{"type":"地理","name":"トリニダード島","rank":"2","desc":"南米大陸の北に浮かぶ島。南側にサーペントス・マウス、北側にドラゴンズ・マウスと呼ばれる海峡があり、熱帯の自然の美しさが感じられる島である。","note":"大きな島の地図","exp":""}],"2119":[{"type":"財宝","name":"ズルナ","rank":"4","desc":"オスマントルコの伝統的な木管楽器。\n非常に大きい音を出す楽器で、軍楽や祭礼時の舞踊の伴奏に用いられる。室内での演奏には適さない。","note":"迫りくる音色","exp":"740"}],"3379":[{"type":"植物","name":"ナツメヤシ","rank":"4","desc":"中東や北アフリカに分布する木。樹高は15mを超え、3m程度の葉を付ける。\n栄養価の高い実がなることなどから、メソポタミアやエジプトなどの地域で古代より重宝されてきた。","note":"砂漠で命を繋ぐもの","exp":"700"}],"4866":[{"type":"歴史遺物","name":"ボルシッパ碑文","rank":"3","desc":"ボルシッパの最盛期を築いたネブカドネザル２世の碑文。彼がどのようにしてナブー神を祀る「七層の神殿」を「尊いラピスラズリのレンカ」で修復したのかが刻まれている。","note":"クエスト「古代の建築指南書」<br/>発見物カード:270","exp":"540"}],"1842":[{"type":"宗教遺物","name":"精霊の仮面","rank":"5","desc":"ニューギニアの精霊は儀式を完了した成人男性でないと見ることができないといわれている。そのため、この仮面を身につけて、女性や子供に精霊が降臨していることを伝える。","note":"精霊喪失","exp":"1040"}],"1659":[{"type":"地理","name":"プレンティ湾","rank":"1","desc":"アオテアロアの北部にある湾。東西に岬を持ち、波は穏やかで、魚も豊富に獲れる。","note":"書きかけの地図","exp":"110"}],"157":[{"type":"地理","name":"コンゴ川","rank":"1","desc":"アフリカの大河。大西洋に注ぐ。河口の規模からして相当な流域面積があると思われる。内陸の探検へのルートとして有望だが、気候が厳しく困難である。","note":"コンゴ王国の玄関","exp":"90"}],"6404":[{"type":"史跡","name":"ネレイドモニュメント","rank":"5","desc":"リュキアに建てられた大理石の記念堂。海神の娘ネレイドたちの流麗な彫像が、古代ギリシャ式の石柱の間に立ち並ぶ。この形式はハリカルナッソスにあった建築物に影響を受けたといわれる。","note":"","exp":"2850"}],"680":[{"type":"宗教遺物","name":"聖十字架","rank":"4","desc":"イエスが処刑されたときにはりつけられたとされる十字架の一部。聖十字架にはさまざまな伝説があり、アダムの墓に植えられた原罪の木が、数奇なめぐり合わせで用いられたともいわれる。","note":"クエスト「信仰の象徴」<br/>発見物カード:350","exp":"732"}],"2427":[{"type":"鳥類","name":"ヤンバルクイナ","rank":"2","desc":"沖縄本島北部の森林地域にのみ生息する鳥。翼が小さく、飛ぶことはできない。\nその代わりに脚が発達し、茂みの中を走り回れる。","note":"飛べない鳥の地図","exp":"260"}],"1989":[{"type":"海洋生物","name":"ターポン","rank":"5","desc":"大きなニシンのような見た目に、銀色に輝く魚体をもつ。凶暴な大魚である。","note":"釣り","exp":"816"}],"6876":[{"type":"海洋生物","name":"ムラサキカムリクラゲ","rank":"2","desc":"世界中の深海に生息する、クラゲの一種。円盤状の傘の周りに、20本を超える長い触手を持つ。外敵に襲われそうになると体から強い光を放ち、その光で外敵にとっての敵を呼び集めるという珍しい習性を持つ。","note":"","exp":""}],"496":[{"type":"歴史遺物","name":"ロゼッタストーン","rank":"3","desc":"ナイルのほとりで発見された玄武岩でできた石碑。古代エジプト神聖文字と民衆文字、ギリシャ文字で書かれている。内容は祭事の制定を告知するもの。","note":"クエスト「古代エジプト語の研究」<br/>発見物カード:225","exp":"456"}],"888":[{"type":"海洋生物","name":"ミノカサゴ","rank":"1","desc":"温暖な海で見られる、扇のようなヒレを持つ魚。背ビレと胸ビレが特に大きい。このヒレの先端には毒針があり人間が刺されると死ぬこともある。","note":"毒魚の地図","exp":"35"}],"822":[{"type":"宗教遺物","name":"アタルヴァ・ヴェーダ","rank":"2","desc":"ヒンドゥー教の聖典の一つ。呪詞を集めたもので、初期には聖典とされていなかった。民間に根ざした内容で、悪魔をはらう呪文から髪を生やす呪文まで、幅広い。","note":"ブラフマン祭官の聖典","exp":"390"}],"518":[{"type":"歴史遺物","name":"古代の銀の器","rank":"1","desc":"銀で作られた器。実用品より、祭器や特別な用途に使われていたようである。","note":"古代の銀細工の地図","exp":"37"}],"6924":[{"type":"中型生物","name":"オットセイ","rank":"3","desc":"アシカに似た哺乳類。全身を覆う体毛はアシカよりきめ細かく、柔らかでつやがある。また、前足と頭の両側にある耳はアシカよりも大きい。海岸に生息し、魚やタコなどを捕食する。","note":"","exp":""}],"743":[{"type":"財宝","name":"聖王の鎧","rank":"2","desc":"聖王と呼ばれたルイ9世の鎧。ルイ9世は第7回、第8回の十字軍に従軍したが、チュニスでペストにかかり、陣没した。","note":"聖人になった王","exp":"220"}],"2836":[{"type":"財宝","name":"西遊記","rank":"4","desc":"「大唐西域記」を元に書かれた明代の小説。唐僧・三蔵法師が孫悟空、猪八戒、沙悟浄を供に従え、天竺へ経を取りに行くという物語である。","note":"再びたどる玄奘の足跡","exp":"630"}],"5138":[{"type":"港・集落","name":"ベルゲン","rank":"1","desc":"スカンジナビア半島の南西部にある街。フィヨルドに近い高緯度地域だが、気候は比較的温暖である。寒冷地でも育つ農作物が栽培されるほか、塩や石材、木材などが豊富に産出する。","note":"到達する","exp":"44"}],"2234":[{"type":"地理","name":"ニューブリテン島","rank":"1","desc":"ニューギニア島の東にある大きな島。熱帯雨林に覆われた地形であるが、火山帯に属しており、ニューギニア島とはまた違った印象である。火山付近の海は煮え湯のように沸き立つという。","note":"沸き立つ海","exp":"150"}],"1271":[{"type":"美術品","name":"聖ウェロニカ","rank":"1","desc":"ロベルト・カンビンの作品。油彩による着色方法を使用した最初期の画家の一人。この作品は聖女ウェロニカがイエスの顔をぬぐい、その顔が布に浮かび上がった様子を表現している。","note":"教会の宗教画の地図","exp":"110"}],"6840":[{"type":"小型生物","name":"エボシカメレオン","rank":"3","desc":"アラビア半島南部に生息するカメレオンの一種。海沿いの山地に広がる森林にすむ。体の大部分は緑色で、黒や黄色の文様があるが、周囲の様子などに合わせて変化する。烏帽子のようにとがった頭が特徴。","note":"発見物カード:220","exp":"440"}],"2376":[{"type":"中型生物","name":"ニホンマムシ","rank":"2","desc":"日本全国で見られる、太くて短い体型の蛇。毒を持ってはいるが、性格はそれほど荒くはない。\n滋養強壮効果があるため、皮や身が、薬などに用いられる。","note":"医者が探す毒蛇","exp":"330"}],"5896":[{"type":"中型生物","name":"チベットスナギツネ","rank":"5","desc":"中央アジアに生息するキツネの仲間。草原や岩の下の隙間などに巣を作って生活する。長い鼻面と細い目が特徴的な顔は、ぼーっとしているように見えることがある。","note":"","exp":"1360"}],"290":[{"type":"中型生物","name":"フォッサ","rank":"5","desc":"マダガスカル島に生息する最強の肉食獣。主に単独行動をとり、昼夜を問わず、追跡か待ち伏せで狩りをする。体は筋肉質で、木登りが得意。","note":"マダガスカルの王者","exp":"923"}],"5189":[{"type":"港・集落","name":"泉州","rank":"2","desc":"読み方は、「チュワンチョウ」。かつて海上貿易の拠点として繁栄した街。\n晋末に中原から多くの移民が流入したため、中原の技術や文化が伝わっている。","note":"到達する","exp":"340"}],"6983":[{"type":"宗教遺物","name":"テミス像","rank":"3","desc":"ギリシャ神話の法と秩序を司る女神テミスを表したとされる像。紀元前の作とされ、左手にあったと考えられる天秤は長い年月のうちに失われている。かけた右腕に剣を持っていたかどうかは定かでない。","note":"","exp":""}],"634":[{"type":"歴史遺物","name":"ディオニソスの館のモザイク画","rank":"1","desc":"ポンペイの秘儀荘と呼ばれる建物の内部で発見されたモザイク画。ディオニソスを崇拝する宗派に入るための儀式を描いたものであるといわれている。","note":"クエスト「酒の神の館」<br/>発見物カード:55","exp":"110"}],"840":[{"type":"海洋生物","name":"イルカ","rank":"1","desc":"温暖な海でよく見かける大型の魚。なぜか水中で息ができず、背中にある穴で空気呼吸するようだ。魚ではないのかもしれない。","note":"跳ねる魚の地図","exp":"27"}],"137":[{"type":"海洋生物","name":"マッコウクジラ","rank":"1","desc":"20m近くにもなる、大型のクジラ。頭部が大きく、口には硬い歯が並んでいる。巨大なイカと戦っている姿が目撃されたこともあるという。船を襲ったりはしないようだ。","note":"クジラの生態調査","exp":"50"}],"21":[{"type":"宗教遺物","name":"ヨルバ王国の神官の仮面","rank":"5","desc":"西アフリカ中央部で栄えているヨルバ人の仮面。これは、託宣（たくせん）を行う高位の神官の物である。ヨルバ人は木工や青銅細工に優れ、この仮面にも精巧な細工が施されている。","note":"アフリカのシャーマン","exp":"962"}],"6922":[{"type":"天文","name":"モサラー","rank":"2","desc":"さんかく座のアルファ星。3等星で、二等辺三角形の頂点に位置する。名はアラビア語で「三角の頭」を意味する。","note":"発見物カード:195","exp":"390"}],"2689":[{"type":"地理","name":"金剛山","rank":"3","desc":"東西南北に峰が連なっている山々。\n朝鮮王朝初期の政治家である鄭道伝の、その父親が十年間、修行のためこの山々にこもっていたらしい。","note":"大陸の山","exp":"530"}],"1675":[{"type":"財宝","name":"ポイ","rank":"2","desc":"編みこんだ亜麻に冠毛を詰めた球に紐をつけた道具。マオリ人独特の踊り「ハカ」で女性が用いる。また、このポイ自体も多産を意味する縁起のよいものとされている。","note":"太古の舞踊","exp":"280"}],"713":[{"type":"大型生物","name":"スイギュウ","rank":"1","desc":"左右に延びた巨大な角を持つウシ。水辺で生活する。小規模な群れと、1000頭を超える大規模な群れがある。大規模な群れはメスと子供のようだ。","note":"水辺に住む牛の地図","exp":"26"}],"6869":[{"type":"天文","name":"イザル","rank":"3","desc":"うしかい座のイプシロン星。2等星の連星であり、この星座の中で2番目に明るい。牛飼いの腰の辺りに位置しており、名も「腰紐」を意味するアラビア語が由来とされている。","note":"","exp":"530"}],"74":[{"type":"地理","name":"コモロ諸島","rank":"1","desc":"マダガスカル島の北端とアフリカ大陸の間にある諸島。中世からアラブの勢力が進出していた。気温が高く、雨季と乾季があるため森林は少ない。独特の動植物が見られる。","note":"インド洋の島","exp":"150"}],"1451":[{"type":"美術品","name":"サモトラケのニケ","rank":"5","desc":"サモトラケ島で出土した大理石片を組み上げて作った、美しいニケ像。腕と頭部が失われているが、かえって翼の美しさが引き立っている。","note":"風をはらむトルソ","exp":"1215"}],"6192":[{"type":"史跡","name":"カタ・ジュタ","rank":"2","desc":"地元の言葉で「多くの頭」という意味の岩山で、ウルルと同じく現地人たちの聖地の一つでもある。夜間にさまざまな儀式が行われており、罪人を罰する刑場としての役割も果たしているようだ。","note":"","exp":"370"}],"2354":[{"type":"歴史遺物","name":"菅公の御霊廟","rank":"2","desc":"読みは「かんこうのごれいびょう」。菅公とは、菅原道真のことを指す。\n恨みを抱いて死んだとされる道真は、かつては祟りをもたらすと恐れられていた。現在は学問の神として祀られている。","note":"学問の神","exp":"390"}],"1492":[{"type":"大型生物","name":"ヘラジカ","rank":"5","desc":"とても大きな体をしていて、オスの体重はメスの倍ほどもある。オスには特徴のある角があり、それを使って力比べをしたり、外敵を追い払ったりする。食物については、草より木の枝葉を好んで食べる。","note":"巨人の手のひら","exp":"936"}],"3640":[{"type":"財宝","name":"馬頭琴","rank":"5","desc":"弦楽器の一種。先端部分が馬の頭の形をしていることから、この名がある。ウマの尾毛を100本束ねた弦が2本張られており、弓を用いて演奏する。四角い共鳴箱から響く音色は奥行きがある。","note":"大地の音色","exp":"950"}],"1339":[{"type":"地理","name":"セレベス島","rank":"2","desc":"カリマンタン島の東に位置する、複雑な形をした島。全体的に山がちで、カリマンタン島以西と異なる多種多様な生物が生息する。\n島に暮らす人々の文化は場所によって大きく異なる。","note":"それぞれの岬に","exp":"330"}],"6527":[{"type":"史跡","name":"チャンキーヨの太陽観測塔","rank":"5","desc":"南米北西部の沿岸砂丘にある古代遺跡。紀元前4世紀ごろに建設されたとされる。13基の石造りの塔が丘の尾根に一列に並んでいる。かつてはかなりの高さがあったようだ。太陽がどの塔の位置から昇るかを観測し、日付を割り出したという。","note":"レガシー星の叡智　上","exp":"2700"}],"20":[{"type":"鳥類","name":"テンニンチョウ","rank":"4","desc":"オスが長い尾を持つ、アフリカの小鳥。尾が長くなるのは繁殖期だけのようだ。オスは羽が白と黒、くちばしが赤と目立つ色だが、メスは茶色で地味だ。オスはメスの気を引くため、メスのまわりで独特の飛び方をする。","note":"アフリカにしかいない小鳥","exp":"756"}],"5387":[{"type":"宗教遺物","name":"アルゴナウティカ","rank":"2","desc":"ギリシャ神話の英雄イアソンが王位継承の条件としてコルキスにあるという金羊毛皮を求める物語。全ギリシャから集まった50人の勇士が巨大な船アルゴ号に乗り組み、各地で冒険を繰り広げる。","note":"発見物カード:150","exp":"300"}],"2706":[{"type":"歴史遺物","name":"石獣","rank":"2","desc":"百済時代の遺跡に置かれていた謎の獣の像。その姿はまるで、遺跡を守っているかのようだ。","note":"ダンジョン","exp":"210"}],"6689":[{"type":"中型生物","name":"カニクイイヌ","rank":"","desc":"低木林や湿原などに生息する犬の仲間。乾季になると低地へ、雨季になると高地へ移動する。乾季は小型の脊椎動物やカニ、雨季は昆虫を食べる。体毛は粗く、胴は灰褐色または黄廃色で、背筋に鮮明な黒線がある。","note":"","exp":"800"}],"5313":[{"type":"地理","name":"ウニアンガ湖群","rank":"1","desc":"サハラ砂漠に点在する湖。それぞれ大きさや深さ、水面の色合いが異なる。降雨量は少ないが、地下からの湧き水が豊富なため枯れることがないようだ。","note":"","exp":"150"}],"2335":[{"type":"歴史遺物","name":"埴輪","rank":"1","desc":"読みは「はにわ」。日本で作られた素焼の焼き物。人や馬、家をかたどったものの他、円筒形のものもある。\n有力者の墓の周りや、墓室内に置かれる場合が多い。","note":"葬送用の焼き物の地図","exp":"140"}],"1738":[{"type":"財宝","name":"孔雀の胸飾り","rank":"5","desc":"虹色に美しく輝く巨大なオパールの周りに、真珠などの宝石をふんだんにあしらった胸飾り。職人が、本物のクジャクに負けないようなものを作ろうとしたのだろう。","note":"思い出を胸に<br/><br/>発見時経験値1222　発見物カード経験値611","exp":"1222"}],"1254":[{"type":"地理","name":"カトチェ岬","rank":"2","desc":"ユカタン半島の最先端にある岬。新大陸へ夢を追い求めたヨーロッパ人が、カリブの無慈悲な嵐によって流れ着くことが多いのが、この岬だ。","note":"嵐に近い場所","exp":"280"}],"2728":[{"type":"宗教建築","name":"仏国寺跡","rank":"4","desc":"新羅時代に建立されたといわれる仏教寺院の跡地。\n石垣で固めた盛土の上に、三区域に分かれた伽藍（がらん）が配置されていたらしい。\n朝鮮王朝四代王・世宗の時代に破壊されてしまったという。","note":"焼け跡に見る歴史","exp":"650"}],"6462":[{"type":"海洋生物","name":"威嚇模様のヒョウモンダコ","rank":"5","desc":"暖かい海に生息する小型のタコ。興奮すると全身に、とても美しい青い輪状の模様が浮き出る。毒腺を持った口でかまれると死亡する危険があるほか、食べたり触ったりするだけでも毒を受ける可能性があるという。","note":"追究クエスト「ヒョウモンダコの追加調査」発見物カード：600","exp":"1200"}],"3636":[{"type":"財宝","name":"合成弓","rank":"5","desc":"複数の材料を使用して作られた小型の弓。木や竹を主として作られるが、そこに動物の骨や金属板を張り合わせることにより、射程と破壊力を増加させた。弓職人が製造法を秘しているため、詳細な製造法は分からない。","note":"モンゴルの弓技術","exp":"1180"}],"4851":[{"type":"レリック","name":"空中庭園","rank":"","desc":"砂嵐に隠された古の都バビロン。美しき庭園と巨大な塔のある、かの都は今も本当に存在するのだろうか。","note":"","exp":""}],"2972":[{"type":"海洋生物","name":"ウバザメ","rank":"3","desc":"大きなものでは12mほどにもなるサメ。比較的寒い海に生息することが多い。大きな体に似合わず、性格はおとなしく人を襲うこともない。むしろ沿岸に現れ、簡単に捕らえられてしまうこともある。","note":"クエスト「おっとりしたサメ」<br/>発見物カード:240","exp":"480"}],"5079":[{"type":"港・集落","name":"ストックホルム","rank":"1","desc":"13世紀中ごろ、スウェーデンのビルイェル・ヤールによって築かれた都市。14の島を橋でつないだ構成になっている。鉱物が豊富な土地柄である。","note":"到達する","exp":"47"}],"358":[{"type":"海洋生物","name":"タカラガイ","rank":"1","desc":"古代では貨幣の替わりに使われたという、美しい艶をもつ貝。温暖な海でよく見られる。","note":"艶のある貝の地図","exp":"10"}],"6957":[{"type":"中型生物","name":"アルビノのアライグマ","rank":"5","desc":"全身が真っ白なアライグマ。通常は灰褐色の体毛を持つが、遺伝子変異により、毛色は白く、赤みを帯びた目や鼻を持った個体がごく稀に生まれる。綿毛のような毛並みは非常に神秘的である。","note":"発見物カード:615","exp":"1230"}],"1560":[{"type":"財宝","name":"スリットドラム","rank":"1","desc":"中身をくりぬいた木を叩いて音を出す楽器。世界のどこでも見られる。ニューギニアのスリットドラムは祭りの演奏や仲間への合図に用いられるようだ。","note":"変わった太鼓の地図","exp":"150"}],"727":[{"type":"大型生物","name":"インドガビアル","rank":"5","desc":"細長い吻（ふん）が特徴。繁殖期になるとオスはメスを集めてハーレムをつくる。陸地に上がることはあまりなく、主に魚をエサとしている。","note":"聖なる川に棲む者","exp":"910"}],"1623":[{"type":"美術品","name":"ユディト","rank":"3","desc":"ジョルジョーネ作の絵画。旧約聖書「ユディト記」を題材とした。ユディトの右手には剣足元には敵将ホロフェルネスの首。ユディトの表情や、色彩、タッチからは、臨場感は微塵も感じられないが、神聖さや静寂な空気が醸し出されている。","note":"ジョルジョーネのユディト","exp":"539"}],"3044":[{"type":"植物","name":"チランジア","rank":"3","desc":"北米南部から中南米にかけて生息する植物。葉から水分を吸収するため乾燥に強く、根を持たない。多くの種が存在し、その姿は多様である。","note":"根無し草<br/><br/>発見時経験値530　発見物カード経験値265","exp":"530"}],"6583":[{"type":"港・集落","name":"マナーマ","rank":"1","desc":"ペルシャ湾に浮かぶ、バーレーン島北東の都市。その立地から、海上交通の拠点として栄えた。近海で採れる真珠は非常に高品質であり、ヨーロッパでも珍重される。","note":"(2300, 3825)","exp":"175"}],"108":[{"type":"地理","name":"セントマリー岬","rank":"2","desc":"マダガスカル島最南端に位置する岬。そこに広がる砂丘は、島に生息する巨大生物が卵を孵（かえ）す場所として利用している。","note":"カリカットへの道標","exp":"220"}],"5614":[{"type":"化石","name":"胴が扁平なトカゲの骨","rank":"2","desc":"幅広な胴を持つ、巨大なトカゲのような生物の骨。胴は甲冑のように骨で覆われている。","note":"","exp":""}],"5891":[{"type":"気象・現象","name":"ケーララの赤い雨","rank":"2","desc":"インド南部で発生した赤い雨。色は黄や緑の場合もあるという。その発生原因は不明であり、人体への影響もわかっていない。","note":"カリカット北<br/>入り口から北に進み最初の三叉路の少し東側で観測。","exp":"360"}],"684":[{"type":"中型生物","name":"インドリ","rank":"4","desc":"マダガスカルの森に、数kmにわたって響き渡るほどの声で鳴く。その声は、仲間とコミュニケーションをとる手段だと思われる。若葉や果実、花などを食べる。","note":"森のコーラス","exp":"630"}],"1889":[{"type":"歴史遺物","name":"サン・パウロ号","rank":"2","desc":"ポルトガルの頑丈な大型船で、東インド貿易船の一隻。\nインドへ向かう途中、マダガスカルの東を回る航路をとったが、途中嵐に遭い、スマトラ島西岸沖まで流され、難破した。","note":"サルベージ","exp":"320"}],"6535":[{"type":"気象・現象","name":"同期発光現象","rank":"3","desc":"ホタルの群れに見られる発光現象。始めはバラバラに発光していたホタルの群れが、徐々にシンクロしていき、最後には同じ周期で発光するようになる。この現象には謎が多く、くわしいことはまだ分かっていない。","note":"文化貢献度35<br/><br/>夏？<br/>結構長い。鯖CCしても間に合います。","exp":"480"}],"5128":[{"type":"港・集落","name":"フィレンツェ","rank":"1","desc":"製造業と交易、金融業により発展した街。金融業で有名になったメディチ家をはじめ、多くの商人と職人が集いその結びつきを強くしている。古代ローマ時代、フロレンティアと名づけられたことから現在の街名となったといわれている。","note":"到達する","exp":"38"}],"2435":[{"type":"財宝","name":"天下布武の印","rank":"4","desc":"「天下布武」の四文字が刻まれた印章。近世の日本では、文書上の署名の代わりにこうした印が用いられた。\n使用者の政治思想を表しているとされるが、詳細は不明である。","note":"ダンジョン","exp":"690"}],"6184":[{"type":"伝承","name":"見えざる街","rank":"5","desc":"世界中に広く伝わる、この世のどこかにあるという見えない街。戦乱に巻き込まれて滅びた、神の力によって海や湖の底に沈められた…などといった伝承が数多く残されているが、それを実際に見た者や戻ってきた者の話はついぞ聞かない。","note":"理想郷に関する伝承","exp":"1660"}],"605":[{"type":"美術品","name":"薬剤師の肖像","rank":"1","desc":"フランソワ・クルーエ作の肖像画。モデルは彼の友人でピエール・キュートという。イタリアとフランドルの影響を受けた、自然で非常に写実的な絵画だ。","note":"細密な人物画","exp":"190"}],"212":[{"type":"宗教遺物","name":"テンプル騎士団長の甲冑","rank":"1","desc":"テンプル騎士団は、十字軍時代の三大騎士団の一つ。非常に強大であったが、14世紀初めにフィリップ4世に弾圧されて解散した。この甲冑はエディンバラで保管されていたもので、団長であったモレーのものと伝えられている。","note":"テンプル騎士団長の甲冑","exp":"100"}],"354":[{"type":"財宝","name":"テオドラの舞衣装","rank":"3","desc":"ビザンツ皇帝・ユスティニアヌス1世の妃である、テオドラの舞衣装。テオドラは庶民出身で、皇妃になる前は踊り子などをしていたそうだ。ユスティニアヌス1世は、彼女と結婚するために法律を変えた。","note":"英傑たる皇妃","exp":"430"}],"5851":[{"type":"美術品","name":"レースグラスのゴブレット","rank":"5","desc":"レース模様のガラスで作られたゴブレット。ヴェネツィアのガラス製法は門外不出であり他のどの国であろうと同じものを再現することはできないだろう。","note":"","exp":"1360"}],"6390":[{"type":"化石","name":"頭が扁平なトカゲの骨","rank":"2","desc":"北米東部で見つかった大きなトカゲのような生物の骨。頭骨が平たいのが特徴。骨には鋭い歯がついている。","note":"","exp":"340"}],"5406":[{"type":"天文","name":"りゅうこつ座の花のような星雲","rank":"2","desc":"りゅうこつ座にある散光星雲。オリオン星雲より四倍ほど大きく明るいが、天の南極に近い場所にあるため、南半球の緯度が高い地域行かないと見ることが難しい。","note":"「天文学者の観測記録」<br/>発見物カード:165","exp":"330"}],"1812":[{"type":"海洋生物","name":"シビレナマズ","rank":"1","desc":"発電するナマズ。小さな丸い目に円筒形の体と、愛らしい姿をしているが、強力な電気を発して小魚やカニなどを麻痺させて食べる性質を持つ。北アフリカの、ナイル川や湖などの淡水域に生息。","note":"釣り","exp":"60"}],"5137":[{"type":"港・集落","name":"ベニン","rank":"1","desc":"アフリカ西部に位置する港町。西アフリカ全域と大規模な交易を行うなど、商業の中心地として発展した。","note":"到達する","exp":"64"}],"1801":[{"type":"地理","name":"テワンテペク湾","rank":"1","desc":"中米のテワンテペク地峡南部に広がる湾。この沿岸では、古代から多くの文明が栄えたという。","note":"書きかけの地図","exp":"160"}],"1595":[{"type":"地理","name":"サンゴ海","rank":"2","desc":"オーストラリアの東岸に位置する海域で、サンゴが発達し、非常に美しい海である。数えられないほど無数の島が存在し、ウミガメや渡り鳥の繁殖地にもなっている。","note":"実在する楽園","exp":"280"}],"6009":[{"type":"財宝","name":"ガルス陶器","rank":"3","desc":"「掻き落とし」と呼ばれる技法によって作られたイスラムの陶器。\n緑釉（りょくゆう）によって文様が彩られていることが特徴的である。","note":"アムステルダム地図","exp":""}],"5327":[{"type":"歴史遺物","name":"タドラルト・アカクスの岩絵","rank":"2","desc":"先史時代に描かれたと思われる壁画。馬に乗る人々や、キリン、ゾウ、ラクダなどが描かれており、大昔の付近の様子がうかがえる。タドラルトは現地の言葉で「山」を意味する。","note":"","exp":""}],"2760":[{"type":"宗教遺物","name":"ハッチャンイ","rank":"4","desc":"儒教を学んだ者や儒教を教授する者が着用する、朝鮮の衣服。\n朝鮮の儒教は宗教ではなく学問であるが、多くの人々が儒教を学びその理念に基づいて行動している。","note":"教えを説く者たちの証","exp":"660"}],"699":[{"type":"宗教建築","name":"羊頭のスフィンクス","rank":"1","desc":"カルナック神殿の参道に並ぶ羊の頭のスフィンクス。40体ある。羊は神殿に祭られているアメン神の聖獣。アメン神は古代エジプトの国家神である。","note":"神殿の守護","exp":"150"}],"3638":[{"type":"地理","name":"モンゴル高原","rank":"2","desc":"どこまでも続くかのような広大な草原地帯。降水量が少ないためか高原の中央部は砂漠になっている。","note":"書きかけの地図<br/><br/>発見時経験値390　発見物カード経験値195","exp":"390"}],"1456":[{"type":"植物","name":"ワトル","rank":"1","desc":"オーストラリアの沿岸から高地にかけて生息する木。トゲがあり、成長すると10mにもなる。","note":"大きな植物の地図","exp":"155"}],"404":[{"type":"小型生物","name":"ハイラックス","rank":"1","desc":"岩の多い所に住む、丸い体をした動物。別名はイワダヌキ。巣穴を掘って集団生活をしているようだが、非常に臆病なので生態はよくわからない。","note":"岩場の動物の地図","exp":"28"}],"913":[{"type":"大型生物","name":"ホワイトタイガー","rank":"5","desc":"黒い縞模様を除いた部分が真っ白な毛で覆われていて、鼻と唇はピンク色、瞳は澄んだ青をしている。インドでは「神の使い」として信じられている。","note":"白き神の使い","exp":"1209"}],"3157":[{"type":"地理","name":"メッシナ海峡","rank":"4","desc":"イタリア半島とシチリア島の間に位置する海峡。最も狭い箇所で幅3～4kmであり、潮流が速いことで知られる。","note":"スキュラとカリュブディス","exp":"700"}],"6336":[{"type":"宗教建築","name":"モンテ・アルバン遺跡","rank":"2","desc":"北米南部で栄えたサポテカ文化の中心地。山の頂上を平坦にして築かれた遺跡で、中には天体観測所や球技場まである。大きく発展したが、人口の減少と共に衰退したという。","note":"","exp":"370"}],"6807":[{"type":"虫類","name":"トビイロカゲロウ","rank":"5","desc":"日本などに広く生息する、カゲロウの一種。水のきれいなところを好んで繁殖し、幼虫は水底で成長する。羽化すると地上に出て、辺りを飛び回るが、成虫になって数日で命を落とし、儚いものの象徴とされる。","note":"発見物カード:455","exp":"910"}],"270":[{"type":"地理","name":"プリンシペ","rank":"1","desc":"アフリカ西岸に浮かぶ無人島。土壌が肥沃で農業に適すると思われる。年間を通じて非常に高温である。","note":"プリンシペの島","exp":"105"}],"6104":[{"type":"宗教遺物","name":"トマス・アクィナスの神学大全","rank":"2","desc":"ドミニコ会修道士で神学者のトマス・アクィナスが書いた神学書。当時哲学でのみ論じられていた「理性」で神の存在を証明するという手法で記され、彼の名声を確たるものとした。一方で、その思想を危険視する者もいたという。","note":"","exp":"380"}],"7013":[{"type":"天文","name":"ルクバト","rank":"5","desc":"いて座のアルファ星だが、星座を構成する星としては16番目に明るい4等星。ケンタウロスの前脚の膝の位置にあたり、アラビア語で「射手の膝」を意味する。","note":"北東太平洋視認","exp":""}],"4789":[{"type":"植物","name":"オヒアレフア","rank":"1","desc":"ハワイ島で伝統的な儀式を行う際に身につけられるレイに使われる花。火山の女神によって引き裂かれた恋人たちが身を変えた花だとの伝説が残る。","note":"悲恋の花","exp":"200"}],"6694":[{"type":"気象・現象","name":"つるし雲","rank":"3","desc":"レンズ雲の一種で、楕円や鉢状など、さまざまな形をしている。山岳の頂上から離れたところに出現する雲を指す。雨天の前兆をといわれている。","note":"昼間から夕方まで出現","exp":"520"}],"5861":[{"type":"財宝","name":"平家物語","rank":"5","desc":"日本の有力武士であった平家の興亡を描いた軍記物語。琵琶法師と呼ばれる盲目の僧が語り伝えている。","note":"","exp":"1410"}],"5881":[{"type":"虫類","name":"ヒョウガユスリカ","rank":"5","desc":"ヒマラヤ山脈の氷河に生息する蚊の一種。羽は退化しており、足で歩いて移動する。","note":"","exp":"1020"}],"1285":[{"type":"宗教建築","name":"アンコール遺跡","rank":"4","desc":"アンコール王朝の都市遺跡。スーリヤヴァルマン2世によって建設されたアンコール・ワットと、ジャヤヴァルマン7世によって建設された、アンコール・トムが有名である。","note":"悠久の微笑み","exp":"624"}],"4846":[{"type":"財宝","name":"バビロニアンハープ","rank":"4","desc":"古代バビロニアのハーフ。多くの遺跡の壁画や石版に描かれており主に宗教的な行事で用いられていたと考えられる。大型だが座ったまま弾くのは困難で、立って演奏される。","note":"バビロニアン・ロマンス","exp":"723"}],"5666":[{"type":"地理","name":"アルシェイのゲルタ","rank":"2","desc":"サハラ中南部に位置する渓谷。低地に流れ出た地下水が湿地を形成しており、ワニの生息地となっている。また、古より人間も利用してきた場所であり、古代の壁画も残されている。","note":"「書きかけの地図」<br/>発見物カード:105","exp":"210"}],"1621":[{"type":"鳥類","name":"アオコンゴウインコ","rank":"3","desc":"銀青色の頭と、細長い尾をした鳥。背の高い木のてっぺんで羽を休め、毎日同じ道筋を飛ぶ。種子、木の実などを食べる。","note":"青色に染まった鳥","exp":"495"}],"6934":[{"type":"鳥類","name":"非繁殖羽のブロンズトキ","rank":"4","desc":"非繁殖期のブロンズトキ。繁殖期とは異なり羽に光沢がなく、黒みがかった体色をしている。また、幼鳥も同様に体全体が暗い色である。","note":"発見物カード:325","exp":"650"}],"529":[{"type":"歴史遺物","name":"古代の石臼","rank":"1","desc":"穀物や豆類などを粉に挽くための、石で作られた臼。粉にすることで保存や調理が容易になる。世界各地の遺跡で出土する。","note":"古代の道具の地図","exp":"10"}],"4961":[{"type":"天文","name":"おとめ座の渦巻星雲","rank":"1","desc":"おとめ座にある渦巻き星雲。中央部が大きく膨らみ、どことなくメキシコの帽子ソンブレロを思わせる形をしている。","note":"天文学者の観測記録<br/>発見物カード:95","exp":"190"}],"2768":[{"type":"大型生物","name":"ナマケグマ","rank":"5","desc":"ずんぐりとした体と、力強い四肢を持つ。長くて粗い毛に覆われていて、爪は大きく、胸に独特の白い模様がある。果実などを食べて生活している。","note":"夢を結ぶ旅路は長く","exp":"1222"}],"3413":[{"type":"史跡","name":"サットン・フー","rank":"4","desc":"ブリテン島の東部にある、古代の墓所。棺の代わりに、船の中に遺体を納めてある。船には多くの副葬品も備えられており、古代の生活を今に伝えている。","note":"船の墓","exp":"700"}],"6073":[{"type":"伝承","name":"狐の嫁入り","rank":"5","desc":"日本という国においてキツネは人を化かす動物だ。そんなキツネが結婚式を挙げる時、彼らは盛大な提灯行列で祝うという。しかしその姿を人の目で捉えるのは難しく、不気味な火の玉が浮かんでいるだけに見えるのだと伝えられている。","note":"","exp":"1320"}],"6272":[{"type":"史跡","name":"カーリバンガン遺跡","rank":"5","desc":"インド西部にあるインダス文明の都市遺跡。古代には流れていた大河の左岸に築かれた都市だったという。\n焼きレンガを用いた区画が少なく、大半に日干しレンガを使っているのが、モヘンジョダロなどと大きく異なる点である。","note":"","exp":"960"}],"5276":[{"type":"レリック","name":"深海の歯車","rank":"","desc":"","note":"発見時経験値2440　発見物カード経験値なし","exp":"2440"}],"1293":[{"type":"鳥類","name":"オオハナインコ","rank":"3","desc":"雌雄によって全く異なる羽色をもつ鳥。オスは鮮やかな緑、メスは深い赤である。非常に賢く、気性も穏やかであるため、容易に飼育できる。","note":"不揃いなつがい","exp":"451"}],"503":[{"type":"歴史遺物","name":"古代ギリシャのつぼ","rank":"1","desc":"古代ギリシャ時代に作られたと思われるつぼである。ギリシャ神話のさまざまな場面が描かれている。","note":"古代ギリシャ遺物の地図","exp":"30"}],"612":[{"type":"海洋生物","name":"ヒョウモンダコ","rank":"2","desc":"暖かい海に生息する小型のタコ。成体でも10cm程度である。興奮すると、青い模様が浮き出て美しい。口に毒腺があり、かまれると死亡することもある。","note":"殺人ダコ","exp":"340"}],"2806":[{"type":"財宝","name":"阮","rank":"1","desc":"読みは「げん」。漢代に製作されたと思われる楽器。\n竹林の七賢の一人・阮咸が愛用したことから武則天が阮咸と名付けた。現在では阮と呼ばれているようだ。","note":"円形の楽器の地図","exp":"140"}],"632":[{"type":"歴史遺物","name":"エパメイノンダスの鎧","rank":"2","desc":"エパメイノンダスは、古代ギリシャ、テーベの政治・軍事家。新戦術を編み出し、スパルタの密集戦術を打ち破った。","note":"実在した理想郷","exp":"275"}],"3887":[{"type":"地理","name":"ホーステールフォール","rank":"5","desc":"北米南西部に位置する滝。冬から早春の間のみ、水が流れる。ごく稀に、夕日に照らされた滝の水がマグマのように赤く見えることがある。","note":"紅の滝","exp":"1170"}],"2562":[{"type":"虫類","name":"イシガケチョウ","rank":"5","desc":"主に東アジアに生息する、白地に黒の細かい筋模様が複雑に入った羽を持つチョウ。\n羽を水平に開いて止まる習性を持つ。人の気配に敏感で、近付くとすぐに逃げてしまう。","note":"地に張り付くチョウ","exp":"1030"}],"1051":[{"type":"財宝","name":"ろうかん","rank":"3","desc":"透明感のある、最上級の翡翠。明るい緑をしており、傷もない。このような石はめったに出ない。大変な価値がある。","note":"緑の宝石の鉱脈の地図","exp":"440"}],"5168":[{"type":"港・集落","name":"ラグーザ","rank":"1","desc":"イタリア半島の東対岸にある街。古代ローマ人が街を作って以来、支配勢力が変わりながらも交易港として栄えてきた。各種農業が盛んで、多くの農作物やその加工品が流通している。","note":"到達する","exp":"9"}],"6263":[{"type":"海洋生物","name":"キマユペンギン","rank":"2","desc":"アオテアロアの南島にあるフィヨルドを中心に生息するペンギン。マオリたちの間ではタワキと呼ばれる。\n頭部に長くて鮮やかな黄色の冠羽が生えており、キマユ（黄眉）ペンギンと呼ばれる由来になっている。","note":"おしゃれさん","exp":"330"}],"2329":[{"type":"財宝","name":"太平記","rank":"2","desc":"日本における南北朝の動乱を題材としている物語。軍記物であるため合戦の記述が多い。当時の社会の風潮に対し、批判的な立場が取られている。","note":"平和を願う軍記物語","exp":"360"}],"1917":[{"type":"植物","name":"カルセオラリア","rank":"1","desc":"袋状の花弁が特徴的な低木の植物。黄、赤、オレンジ、斑点の混じるもの等、様々な色の花が存在する。主に中南米の温暖な地域に広く分布。花の名前であるカルセオラリアはラテン語で「小さな靴」の意味。","note":"鮮やかな花の地図","exp":"150"}],"3165":[{"type":"地理","name":"アパラチア山脈","rank":"2","desc":"北米大陸の東部に位置する山脈。北東から南西に向かって延びており、その長さは2000kmを優に超える。山脈の西側は、石炭などの豊かな地下資源を有すると見られる。","note":"北米東部の地理調査","exp":"350"}],"5555":[{"type":"地理","name":"グリーンサンドビーチ","rank":"3","desc":"ハワイ島南端のカウにある砂浜海岸。砂が緑色に見えるのはカンラン石（ペリドットの原石）が混じっているからだとされる。","note":"","exp":"240"}],"4983":[{"type":"地理","name":"ロードス島","rank":"3","desc":"カンディアの北東に浮かぶ島。かつてロードスの港には、ギリシャ神話に登場する太陽神ヘリオスの巨像があったといわれている。","note":"発見時経験値540　発見物カード経験値270","exp":"540"}],"2819":[{"type":"美術品","name":"郭煕の風景画","rank":"2","desc":"北宋時代の宮廷画家・郭煕が描いた絵画。\n自然に通じていた郭煕は、四季や天候による景観の微妙な変化を、巧みな筆致で表現している。","note":"山水画の大家","exp":"360"}],"2720":[{"type":"植物","name":"正二品松","rank":"3","desc":"大きく枝を広げたマツの木。樹齢数百年といわれ、人々に慕われている。\n朝鮮王朝7代目国王・世祖がこの木のそばを通りかかった時、伸びていた枝が持ち上がって道を開けたという。","note":"王を敬う植物","exp":"520"}],"3754":[{"type":"天文","name":"かに座","rank":"5","desc":"黄道十二星座の1つ。化け蟹カルキノスが、兄弟のヒュドラを助けようとしてヘラクレスに踏み潰されたのを、女神ヘラが哀れんで天に上げた姿とされる。黄道十二星座の中では他と比べて明るい星がなく、目立たない。","note":"クエスト「巨蟹宮の調査」<br/>発見物カード:465","exp":"930"}],"5812":[{"type":"海洋生物","name":"ノウサンゴ","rank":"3","desc":"サンゴの一種。群体が半球状となり、人間の脳のように見えることから、この名がつけられた。","note":"発見物カード経験：300","exp":"600"}],"49":[{"type":"歴史遺物","name":"フラグの財宝","rank":"1","desc":"フラグはフビライ・ハンの弟で、中東を攻めてイル・ハン国を興した。この財宝はフラグの命令で隠してあったもののようだ。","note":"イル・ハン国の財宝","exp":"175"}],"124":[{"type":"宗教遺物","name":"ゼウス像","rank":"1","desc":"ギリシャ神話の最高神の像。ローマ神話ではジュピターという。天空の神で雷を操る支配神である反面、多情で人間の女に次々と手を出す逸話が多い。オリンピアの神殿が有名である。","note":"ギリシャ最高神の像","exp":"60"}],"6760":[{"type":"史跡","name":"ベルンの塔","rank":"5","desc":"16世紀、リスボンのベレン地区に建てられた塔。ヴァスコ・ダ・ガマのインド航路開拓の偉業を記念して建設されたもの。大航海時代の象徴ともいえる史跡である。","note":"","exp":""}],"2519":[{"type":"海洋生物","name":"コウタイ","rank":"1","desc":"台湾島や中国に分布している、体長30cmほどの魚。食用、薬用に用いられる。\n赤、茶、緑など、いろいろな体色の個体がいる。","note":"※不気味な魚の地図<br/><br/>※発見物カード100<br/>","exp":"200"}],"6849":[{"type":"天文","name":"クルサ","rank":"2","desc":"エリダヌス座のベータ星で、3等星。川の上流にあたる、北東の端に位置する。名はアラビアの伝承に登場する人物、ジャウザーの足元の足台が語源と言われている。","note":"発見物カード:180","exp":"360"}],"2711":[{"type":"植物","name":"キツネノカミソリ","rank":"1","desc":"朝鮮と日本の明るい森林に自生する植物。早春に葉を出して球根を太らせるが、夏になると葉を落としてしまうらしい。\nかわいらしい花を咲かせるが、有毒である。","note":"小さな花の地図","exp":"100"}],"2089":[{"type":"海洋生物","name":"カンディル","rank":"4","desc":"アマゾン川流域に生息する小型のナマズ。\n全長10cm程度。\n大型魚のエラに潜り、エラを食べたり、血を吸ったりする。エラ蓋には鋭いトゲがあり、かえしの役割をする。エラへの侵入を容易にするため頭部は平たくなっている。","note":"アマゾン川の吸血魚","exp":"680"}],"5215":[{"type":"歴史遺物","name":"掃叭石柱","rank":"2","desc":"「さっぱせきちゅう」と呼ばれる石柱。千年の石柱とも呼ばれる。高さ約6mと4mの2本の立石が並んでいる。現地に住むアミの人々の間では、民族発祥の地とされているようだ。","note":"","exp":""}],"5072":[{"type":"港・集落","name":"ジェッダ","rank":"1","desc":"アラビア半島の西岸に位置し、紅海に面した港町。イスラム教徒の聖地への巡礼の入口として古代より栄えてきた。","note":"到達する","exp":"127"}],"2494":[{"type":"美術品","name":"唐絵屏風","rank":"1","desc":"読みは「からえびょうぶ」。中国伝来の技法や画風で描かれた、日本の屏風。有力者の邸宅や宮中などで、調度品として用いられた。","note":"珍しい屏風絵の地図","exp":"130"}],"5178":[{"type":"港・集落","name":"ロッブリー","rank":"2","desc":"チャオプラヤ川流域の街。10世紀までラウォーと呼ばれていた。クメール系モン人たちの都市として知られた後に、アユタヤの重要都市として栄えた。","note":"到達する","exp":"332"}],"181":[{"type":"財宝","name":"スルタンの宝冠","rank":"2","desc":"イスラム勢力の君主であるスルタンが所有していたという宝冠。スルタンはいわゆる冠を着けないので、これはほかの勢力から納められた宝物なのだろう。","note":"スルタンの宝冠","exp":"240"}],"6751":[{"type":"天文","name":"ペガスス座の球状星団","rank":"5","desc":"ペガスス座にある球状星団で、ペガススの鼻先にあたる位置の前端にあるため、比較的探しやすい。","note":"","exp":""}],"6608":[{"type":"歴史遺物","name":"アルダシール1世のレリーフ","rank":"2","desc":"ペルシャ湾北岸にある巨岩に刻まれたササン朝時代の巨大なレリーフ。アフラマズダー神から王権の象徴を授受されるアルダシール1世が描かれている。","note":"レガシーテーマ　美の叡智・伝承のレガリア獲得","exp":"350"}],"2770":[{"type":"宗教遺物","name":"地下墓地の棺","rank":"3","desc":"カタコンベに安置されている棺。カタコンベでは、壁に穴を掘るといった独特な埋葬方法を用いることが多く、棺を利用して埋葬する場合も穴の中に置かれていることが多い。","note":"ダンジョン","exp":"440"}],"7027":[{"type":"大型生物","name":"コブウシ","rank":"5","desc":"背中に大きなコブを持つウシ。体毛は白や灰色であることが多く、長く垂れた耳と目立つ胸垂が特徴的である。暑さや熱病に強いことから、熱帯地方を中心に飼育されてきた。原産地のインドでは、神聖な動物として扱われている。","note":"","exp":""}],"6485":[{"type":"財宝","name":"翼型のグースリ","rank":"5","desc":"ロシアの伝統的な弦楽器。グースリは時代を経るごとに形状や弦の数に改良が加えられ仕様されたといわれる。きっとこの翼型のグースリもロシアの吟遊詩人たちとともに伝統を次の世代へ繋いでいくのだろう。","note":"追究クエスト","exp":""}],"5704":[{"type":"地理","name":"ワウ・アン・ナムス","rank":"4","desc":"サハラ中央部分に位置する古火山のカルデラ。直径は4km程度。周辺にはオアシスがあり、隊商の給水地点としても利用されている。","note":"2017.02.07新規追加","exp":"750"}],"3819":[{"type":"海洋生物","name":"ノボリエビス","rank":"2","desc":"大西洋沿岸部の岩礁域に生息する魚。体色は銀色や赤色で、ひれが長く、目が大きい。","note":"美しい魚の地図","exp":"370"}],"3390":[{"type":"歴史遺物","name":"ナラム・シンの石碑","rank":"4","desc":"メソポタミア文明南部のバビロニアのうち、北部地域のアッカド帝国を治めたとされるナラム・シンの石碑。\nナラム・シンは大規模な遠征を繰り返し帝国の領土を拡げ、自らを神とした。","note":"四方領域の王","exp":"740"}],"6772":[{"type":"海洋生物","name":"マナマコ","rank":"2","desc":"ナマコの一種。太平洋の西側沿岸の岩礁帯に広く生息している。干したものは東洋で高価な食材として流通し、華北の料理である魯菜の食材としても有名。","note":"発見物カード:150","exp":"300"}],"2268":[{"type":"歴史遺物","name":"シャカオ叩き台","rank":"3","desc":"シャカオとは、木の根を潰して作られた飲料のこと。\n人々はこの場所でシャカオを製造し、儀式に臨んだのだろう。","note":"遺跡に響く石音","exp":"490"}],"787":[{"type":"宗教遺物","name":"アポロン像","rank":"1","desc":"ギリシャ神話の神の像である。アポロンは予言をよくする神で、デルフォイの神託はアポロンのものとされる。音楽、弓、スポーツなどを得意とする美しい神である。太陽神・ヘリオスと同一視されることもある。","note":"太陽神の像","exp":"60"}],"488":[{"type":"宗教遺物","name":"サーマ・ヴェーダ","rank":"2","desc":"ヒンドゥー教の聖典の一つ。リグ・ヴェーダと同じく、神々への賛歌がまとめられたもので、詠唱を歌で行うウドガートリ祭官のためのものである。","note":"ウドガートリ祭官の聖典","exp":"390"}],"577":[{"type":"植物","name":"ダマスカスローズ","rank":"1","desc":"古くからダマスカス地方で品種改良されたバラの一種。バラの中でも特に香りが優れるといわれ、香料の原料として珍重される。質のよいバラの株は、大変な高値で取引される。","note":"高貴なる花","exp":"70"}],"1688":[{"type":"海洋生物","name":"ピラピチンガ","rank":"2","desc":"灰色の魚体を持つピラニアの仲間。雑食性で木の実などもよく食べるようだ。","note":"釣り","exp":"240"}],"5314":[{"type":"財宝","name":"リビアングラス","rank":"4","desc":"サハラの北東部で見つかる天然ガラス。古代エジプト時代から宝石として装身具などに使われてきた。火山のような高温の熱源がないこの地域で、ガラスがどのように生成されたかは不明である。","note":"","exp":"660"}],"1591":[{"type":"宗教遺物","name":"オポッサム像","rank":"2","desc":"オポッサムとは、腹に袋を持ち袋の中で子を育てる小型のねずみ。メソアメリカでは神格化され、多くの像が作られた。","note":"腹に袋を持つ動物の像","exp":"330"}],"1980":[{"type":"海洋生物","name":"カンムリブダイ","rank":"2","desc":"大きなくちばしを持ちフンを土煙のように撒き散らして泳ぐブダイの仲間。","note":"釣り","exp":"220"}],"5653":[{"type":"地理","name":"マヤベイ","rank":"3","desc":"アンダマン海上に浮かぶピピ諸島の一つ、ピピレイ島の名所。真っ白な砂浜と透き通る海が広がっている。","note":"","exp":"480"}],"377":[{"type":"海洋生物","name":"タイマイ","rank":"2","desc":"やや小型のウミガメ。上のくちばしがタカのように曲がっている。甲羅は東洋で細工に使われるという話だ。","note":"海に棲むカメの地図","exp":"250"}],"5":[{"type":"歴史遺物","name":"ダレイオス1世の兜","rank":"2","desc":"アケメネス朝ペルシャ第3代の王、ダレイオス1世の兜。近隣諸侯の反乱を制圧し、ペルシャを大国に育てた。ペルセポリスの建造を始めたのもこの王である。","note":"アケメネス朝の黄金時代","exp":"380"}],"1219":[{"type":"歴史遺物","name":"クック女王のイヤリング","rank":"4","desc":"クック女王とは、パレンケ王・パカルの母。パカルが王位に就ける年齢になるまで王座に座っていた。ひすいと黒曜石、陶器でできた女性らしいイヤリングである。","note":"パレンケの女王","exp":"768"}],"6636":[{"type":"財宝","name":"アウグストゥスの硬貨","rank":"5","desc":"インド南部の都市にて発掘された金貨。初代ローマ皇帝・アウグストゥスの肖像が彫られている。古代インドとローマ帝国の間に貿易があったことの証とされている。","note":"発見物カード1,125","exp":"2250"}],"1212":[{"type":"海洋生物","name":"巨大ピラルク","rank":"5","desc":"アマゾン川流域に生息するピラルクが巨大化したもの。体長は5mをゆうに超える。","note":"水中を走る船","exp":"1118"}],"5520":[{"type":"地理","name":"クリスマス島","rank":"1","desc":"ハワイの南に位置する世界最大級のサンゴ礁の島。イギリスの探検家クックがこの島に到達した日がクリスマスだったため、この名が付いた。","note":"「書きかけのちず」<br/>発見物カード:85","exp":"170"}],"5224":[{"type":"史跡","name":"ヌラーゲ","rank":"2","desc":"サルデーニャ島に見られる巨大な建造物。大きな石を塔のような形状に積み上げて作られている。先史時代に作られ、その数は当時2万ほどであったと見られている。","note":"","exp":"230"}],"744":[{"type":"美術品","name":"聖地で説教する聖エティエンヌ","rank":"1","desc":"ヴィットーレ・カルパッチオ作。聖エティエンヌの生涯を題材とした六枚の年代記絵画の一枚。描かれている街はイェルサレムで、エキゾチックで鮮やかな衣装や、石造りの美しい街並みが特徴的である。","note":"聖人の年代記絵画","exp":"75"}],"1486":[{"type":"虫類","name":"ツノゼミ","rank":"1","desc":"頭に付いた大きな角状の突起物は、皮膚を突き刺すほど硬い。ツノゼミは卵をアリに守ってもらい、そのお礼に蜜を与える。","note":"角のある虫の地図","exp":"130"}],"3263":[{"type":"鳥類","name":"ヘビクイワシ","rank":"4","desc":"アフリカ中部から南部にかけて分布するワシの一種。\n後頭部に長い冠羽が複数あり、それらが羽根ペンのように見えるため、「書記官鳥」と呼ばれることもある。","note":"知的なおしゃれ","exp":"630"}],"5597":[{"type":"気象・現象","name":"月柱","rank":"4","desc":"月の出、月の入りの際に、月の周囲に光の柱のようなものが見える現象。太陽柱とは異なり、光の形状は楕円に近い。月の光が強くなる半月以上のときに観測されることが多い。","note":"","exp":"700"}],"369":[{"type":"歴史遺物","name":"アントニヌス・ピウスの王錫","rank":"1","desc":"ローマ五賢帝の四人目アントニヌス・ピウス帝の王錫だと思われるもの。大理石と金、サンゴ、真珠などで作られた優雅なものだ。","note":"穏やかな皇帝","exp":"150"}],"2834":[{"type":"宗教遺物","name":"南海寄帰内法伝","rank":"4","desc":"読みは「なんかいききないほうでん」。\n唐僧・義浄が著した、インドの衣食住における戒律を伝える書物。衣の着方や飲食の決まりなどが細かく記されている。","note":"南海を旅した僧","exp":"650"}],"5113":[{"type":"港・集落","name":"バルセロナ","rank":"1","desc":"古代ローマ時代から、地中海貿易の拠点として栄えた街。製鉄技術が発達しており、大砲や銃が作られている。火器に関係する交易品が多く取引されているが、皮革製品の加工技術も有名である。","note":"到達する","exp":"13"}],"6720":[{"type":"財宝","name":"ディルハム銀貨","rank":"2","desc":"古代ペルシャで鋳造された銀貨。中東地域で広く流通し、イスラム帝国の勢力拡大と共に流通範囲をさらに広げた。表面には、イスラム教の信仰を表すアラビア文字が刻まれている。","note":"","exp":"448"}],"5525":[{"type":"天文","name":"レチクル座","rank":"4","desc":"ラカーユが制定した南天の星座のひとつ。レチクルとは、望遠鏡などを覗くと見えるレンズ上の十字の線のことである。","note":"発見物カード:365","exp":"730"}],"1849":[{"type":"地理","name":"段々畑","rank":"3","desc":"斜面の山すそに階段状に段組みされて作られた、緩やかな傾斜を持つ畑。アンデス山脈に属する高原での農作に見られる。","note":"知恵の耕地","exp":"500"}],"6159":[{"type":"小型生物","name":"タルバガン","rank":"5","desc":"モンゴルやロシアなどに生息するげっ歯類の一種。別名、シベリアマーモット。遊牧民たちが肉や毛皮を求めて狩り、「東方見聞録」にも記述が見られるという。ペストを媒介するとされ、接触には細心の注意を払う必要がある。","note":"","exp":"1200"}],"5665":[{"type":"天文","name":"ガニュメデスの脚の流星群","rank":"2","desc":"みずがめ座の右脚にあたる部分の方角から飛び出すように現れる流星群。年に一カ月程の間、活動が見られる。同じ時期に他の流星群の活動もあり、単体としての活動は目立ちにくい。","note":"「天文学者の観測記録」<br/>発見物カード:155<br/>","exp":"310"}],"5367":[{"type":"史跡","name":"プント国のレリーフ","rank":"4","desc":"プント国は、古代エジプトと同時代にあった国で金や香料、木材などの交易で栄えていたという。レリーフにはハトシェプスト女王が送り出したとされる船団が描かれている。","note":"","exp":"360"}],"1607":[{"type":"宗教遺物","name":"古代の岩絵","rank":"5","desc":"アボリジニたちが住んでいる洞窟などに描かれている岩絵。アボリジニが、この地に住み始めたはるか太古の時代から書き綴られている。アボリジニ独特の世界観、「ドリーミング」を伝える手段なのだという。","note":"精霊と人々の風景","exp":"936"}],"3631":[{"type":"史跡","name":"ザナドゥ","rank":"5","desc":"モンゴル高原南部の都市。元朝の皇帝が建設し、夏の間、都として政務を行った。\n『東方見聞録』では技術の粋を尽くした優美な都市と紹介され、多くの航海者の憧れの的となった。","note":"約束がくれた未来","exp":"1440"}],"267":[{"type":"地理","name":"シェトランド諸島","rank":"1","desc":"スコットランドの北に浮かぶ島々。かつてはヴァイキングの支配下にあったので、北欧に近い雰囲気がある。牧羊が行われており、小型で毛の長い牧羊犬が見られる。","note":"ブリテン北の群島","exp":"70"}],"226":[{"type":"史跡","name":"トロイ考古学地区","rank":"5","desc":"ホメロス作の叙事詩「イリアス」で語られるトロイの遺跡。別名はイリオス。トロイの木馬でギリシャ軍に城内に進入され、滅んだと伝えられる。","note":"トロイ","exp":"1027"}],"2591":[{"type":"財宝","name":"人獣型耳飾","rank":"2","desc":"台湾島先住民の集落から発掘された耳飾り。人間の頭に獣が乗っている形をしており、人間と聖なる動物との関わりを示すという。","note":"古代の装飾品の地図","exp":"380"}],"2557":[{"type":"地理","name":"八仙洞","rank":"1","desc":"海に面した断崖に形成された海食洞穴。\n洞穴数は十数個にも及び、台湾島の古代文化の一つである長浜文化の遺跡も存在する。","note":"断崖に臨む洞穴<br/><br/>発見時経験値180　発見物カード経験値90","exp":"180"}],"1134":[{"type":"美術品","name":"受胎告知（ダ・ヴィンチ）","rank":"2","desc":"レオナルド・ダ・ヴィンチ作の絵画。遠近法で描かれているが、マリアの右手など部分的に狂っている箇所もある。意図的だろうか。地面の花々は丁寧に描かれ、天使の翼は鳥のそれを解剖学的に研究したものである。","note":"教会の宗教画の地図","exp":"245"}],"7000":[{"type":"宗教建築","name":"グリトニルの館","rank":"5","desc":"北欧神話に登場する、裁きの神フォルセティの館。エッダでは、この館での裁きはすべての諍いを鎮め、神々と人間が認める最良の法廷であったとされる。館は金と銀で造られ、遠くからでもその輝きを見ることができたと伝わっている。","note":"","exp":""}],"2843":[{"type":"財宝","name":"長弓","rank":"3","desc":"古来から発達していた狩猟・戦争用の弓。全長が1.2ｍのものをロングボウと呼び、草原地帯の遊牧民が使っていたショートボウと区別する。クレシーの戦いでは、ロングボウ隊を山頂付近に配置し、騎兵隊を無力化させるという活躍を見せた。","note":"イングランドの強化弓","exp":"440"}],"5052":[{"type":"港・集落","name":"コチン","rank":"1","desc":"南インドの街。南国の穏やかな気候に恵まれており、独特の産物が見られる。インドらしい染料や織物のほか、南国系の香料や果物、宝石が産物として扱われる。","note":"到達する","exp":"174"}],"2665":[{"type":"財宝","name":"新羅の金冠","rank":"4","desc":"新羅時代のものと思われる金の冠。豪華な装飾と細工が目を引く。この時代は金が豊富だったのだろうか？","note":"新羅を研究するために","exp":"780"}],"764":[{"type":"植物","name":"シクラメン","rank":"1","desc":"大きな花弁の花が下を向いて咲く植物。ピンクや紅色があり、大変優雅で美しい。","note":"赤い花の地図","exp":"27"}],"1600":[{"type":"宗教遺物","name":"儀式用円筒杯","rank":"1","desc":"豪華な装飾・彩色がなされた円筒型の盃。儀式用に貴族や王が進呈したものと思われる。","note":"儀式用具の地図","exp":"150"}],"478":[{"type":"史跡","name":"ヴェルギナ遺跡","rank":"4","desc":"古代マケドニアの都・アイガイがあったとされる遺跡。マケドニア王のものと考えられる古墳がある。","note":"見果てぬ夢","exp":"612"}],"2715":[{"type":"植物","name":"レンギョウ","rank":"1","desc":"朝鮮から中国、日本にも生息する、繁殖力が強い植物。\n早春に黄色い花を咲かせ、花が散るころに鋭利な葉を出す。","note":"黄色い花の地図","exp":"110"}],"5712":[{"type":"歴史遺物","name":"紅茶箱","rank":"5","desc":"ボストン沿岸に沈んでいた、紅茶の入った木箱。茶の販売人と住民との間で争いだあったようだ。","note":"海の茶会","exp":"1400"}],"339":[{"type":"化石","name":"首の長いドラゴンの骨","rank":"3","desc":"首の長さが体と同じほどもある、巨大な生物の骨。全長は20mを超える。ただ、形は骨だが石のように変化している。本当にこんな生物がいるのだろうか？ドラゴンの骨にしては角や翼がなく、ほかの伝説で語られる生物なのかもしれない。","note":"異常なドラゴンの骨","exp":"506"}],"5526":[{"type":"気象・現象","name":"接線弧","rank":"4","desc":"太陽の周囲に弧状の光の帯が発生する現象。虹のように複数の色の帯で構成される。通常の虹と比べ目視は非常に困難であり、数年に一度観測できるかどうかである。","note":"発見時経験値800　発見物カード経験値400","exp":"800"}],"5757":[{"type":"地理","name":"スメル山","rank":"5","desc":"ジャワ島の東部にそびえる、島の最高峰。最も活発に活動する火山の一つで、非常に噴火が多い。その名は、古代インドの世界観において世界の中心にそびえている須弥山に由来する。","note":"2017.02.07新規追加","exp":"1340"}],"5076":[{"type":"港・集落","name":"ジャンビ","rank":"2","desc":"スマトラ島の中央部に位置する、ジャンビ人の街。熱帯雨林に覆われ、林業が盛ん。イスラムの影響を強く受けているが、郊外には仏教の建物も見られ、歴史や文化が混在している。","note":"到達する","exp":"350"}],"5249":[{"type":"宗教遺物","name":"碧霞元君像","rank":"2","desc":"読みは「へきかげんくんぞう」。七天女の一人、泰山玉女とも呼ばれる女神の像である。神々の中で最も心優しい女神とされ、泰山信仰で人気がある。","note":"雲台山西　再調査報酬","exp":""}],"595":[{"type":"地理","name":"クリミア半島","rank":"1","desc":"黒海の北部に張り出している半島。北東の囲まれた海域はアゾフ海という。半島の南部は温暖で過ごしやすい。14世紀の黒死病の大流行は、ここから始まったのだそうだ。","note":"黒死病の歴史","exp":"180"}],"1302":[{"type":"海洋生物","name":"スナメリ","rank":"3","desc":"イルカによく似た膨らんだ前頭部が特徴。主に沿岸部に生息し、河口や川の上流部でも見られる。","note":"浅瀬の王者","exp":"462"}],"2908":[{"type":"鳥類","name":"ソウシチョウ","rank":"3","desc":"中国南部やインド北部などに生息する小型の鳥。赤いくちばしと黄色い喉元が鮮やかである。\nつがいで行動することが多いため「相思鳥」という名前が付いたといわれる。","note":"想いにまつわる鳥探し<br/><br/>発見時経験値480　発見物カード経験値240","exp":"480"}],"2564":[{"type":"中型生物","name":"ヒャッポダ","rank":"5","desc":"台湾島や中国南部に生息する、毒を持つ危険なヘビ。このヘビに噛まれると、百歩歩くうちに死ぬと伝えられ、ヒャッポダ（百歩蛇）と呼ばれるようになった。","note":"山中の危険生物","exp":"990"}],"1154":[{"type":"歴史遺物","name":"黒曜石の剣","rank":"4","desc":"アステカの武器に多く見られる、黒曜石でできた剣。切れ味は鋭いが強度が低い。量産されていたのだろう。","note":"アステカ戦士の戦闘法","exp":"648"}],"513":[{"type":"歴史遺物","name":"古代の銀貨","rank":"1","desc":"銀で作られた、古代の貨幣。通常、銀は金に次ぐものとされるが、古代では金より採取量が少なく、金より珍重されていたという。","note":"古代の貨幣の地図","exp":"14"}],"279":[{"type":"財宝","name":"女王のブローチ","rank":"2","desc":"とある女王のものだと伝えられるブローチ。中央には珍しい紫のサファイヤがはめこまれている。まわりにびっしりと並ぶダイヤモンドとルビーが、美しさを引きたてている。","note":"ペルシャ寓話の語り部","exp":"320"}],"2010":[{"type":"歴史遺物","name":"ブエン・ヘスス号","rank":"3","desc":"フランシスコ・デ・イバラ船長の船で、イスパニアの新大陸貿易船の一隻。\nバルパライソ沖でネーデルラント海軍のオリヴァー・ヴァン・ノールト提督に襲撃され、沈没した。","note":"サルベージ","exp":"460"}],"5150":[{"type":"港・集落","name":"マカッサル","rank":"2","desc":"セレベス島の南部に位置する街。ゴワ王国、タッロ王国の時代に、交易中継港として栄えた。","note":"到達する","exp":"332"}],"5284":[{"type":"小型生物","name":"クロアシネコ","rank":"2","desc":"アフリカ南部のサバンナに棲む野生のネコ。小柄な見た目に反して獰猛で、自分よりも大きい相手を仕留めることもある。サバンナに住む人々によると、キリンの首を狙って襲いかかることさえあるという。","note":"","exp":"240"}],"4833":[{"type":"海洋生物","name":"サカタザメ","rank":"3","desc":"エイのような頭とサメのような体を持つ魚。サメと名がつくがエイの仲間に分類される。インド洋や太平洋の暖かい海に棲み、他の魚や甲殻類を餌とする。","note":"サカタザメ","exp":"470"}],"1881":[{"type":"宗教遺物","name":"鳥人の絵","rank":"5","desc":"ラパ・ヌイでは、マケマケという神の化身である鳥人（タンガタ・マヌ）信仰がある。\n鳥人は非常に強い霊力を持つとされ、儀式により鳥人の称号を得た者は、その一年間、島の全権を握ることができる。","note":"ラパ・ヌイの鳥人","exp":"1079"}],"556":[{"type":"歴史遺物","name":"ネルヴァ帝のブロンズ像","rank":"1","desc":"古代ローマ五賢帝の一人、ネルヴァ帝の像。前帝と血縁になく彼自身もトラヤヌスを養子にして後継者とした。以降、優れた人物を養子にして後継者とすることが続いた。","note":"古代ローマ五賢帝","exp":"90"}],"5728":[{"type":"大型生物","name":"カスピトラ","rank":"5","desc":"カスピ海周辺から東の高地にかけて生息するとみられるトラ。その骨には薬効があるとの噂があるが、その真偽は不明である。","note":"2017.02.07新規追加","exp":"970"}],"2906":[{"type":"小型生物","name":"コツメカワウソ","rank":"2","desc":"中国南部やインドネシアなどに分布する、とても小さなカワウソ。泳ぎに適した平たい体をしている。\n群れで生息し、人にもよく慣れる。","note":"長江に現れた小動物","exp":"240"}],"4975":[{"type":"史跡","name":"ティリンス遺跡","rank":"2","desc":"ペロポネソス半島の東部にあるミケナイ文明の遺跡。分厚く強固な城壁には大きな石材が使われており、ギリシャ神話のサイクルロプスが積んだともいわれている。またヘラクレスヘラクレスの出生地という逸言もある。","note":"クエスト「ヘラクレスの出生地」<br/>発見物カード:140","exp":"280"}],"5464":[{"type":"地理","name":"三日月湖","rank":"2","desc":"アマゾン川でよく見られる三日月形の湖。\n川が極端に蛇行してしまうと、真っ直ぐ流れようとする流水が新たな流路をつくる。そのため、蛇行部分が切り離されて三日月湖ができるといわれている。","note":"経験　:330<br/>カード:165","exp":"330"}],"1445":[{"type":"小型生物","name":"フクロギツネ","rank":"2","desc":"キツネに似た有袋類。樹上で生活し、植物の葉や花、鳥の卵などを食べる。","note":"寝床を借りに","exp":"320"}],"5352":[{"type":"海洋生物","name":"シギウナギ","rank":"3","desc":"細長い体と、長く突き出した顎が特徴の深海魚。\nこの顎を使い、甲殻類を補食していると考えられている。","note":"","exp":"480"}],"6176":[{"type":"海洋生物","name":"ブリモドキ","rank":"3","desc":"暖かい海に広く分布する大型魚で、特徴的な縦縞模様を持つ。船や流木などについて泳ぐ習性から、古代ギリシャでは「ポムピロス」と呼ばれ、船乗りたちが自分たちの帰路を導く魚だと信じていたという。","note":"","exp":"520"}],"6276":[{"type":"地理","name":"テルセイラ島","rank":"2","desc":"アゾレス諸島にある島のひとつ。発見当初は「ブラジル島」と呼ばれ、ピッツィガーノの海図にも描かれた。\n「英雄の港」を意味するアングラ・ド・エロイズモの港町があるほか、海賊に備えて数々の砦が築かれている。","note":"","exp":"210"}],"4811":[{"type":"歴史遺物","name":"古代の銅鏡","rank":"3","desc":"遺跡の中から発見された古い銅鏡。人やものを映すだけではなく、祭祀や呪術などにも使用されていたようだ。","note":"宋山里遺跡群 （上層隠し部屋）","exp":""}],"2289":[{"type":"歴史遺物","name":"古代のマノ","rank":"2","desc":"マノとは、トウモロコシをすりつぶす道具のこと。すりつぶされたトウモロコシは、こねられ、生地にして食される。古代より、この道具によって料理が作られていたものと思われる。","note":"クエスト「伝わる副葬品」<br/>発見物カード:145","exp":"290"}],"5026":[{"type":"港・集落","name":"エディンバラ","rank":"1","desc":"ブリテン島の北東に位置する、スコットランドの中心地。7世紀にスコットランド最初の王・エドウィンが城を築いた。街の名の由来は、このエドウィンと「城塞都市」を意味する「バラ」である。","note":"到達する","exp":"28"}],"5803":[{"type":"地理","name":"シャーマン岩","rank":"2","desc":"浜辺のシャーマン達の信仰の対象とされている岩山。その周辺で一日中祈りをささげ、翌日になっても凍死していなければ、潔白な人物であると認められることだろう。","note":"","exp":"250"}],"6494":[{"type":"宗教建築","name":"聖母晩年の家","rank":"5","desc":"聖母マリアが晩年を過ごしたという石壁の小さな家。アナトリア半島西部のエフェソスにある。老境のマリアを使徒の一人が世話をしていたとも伝わる。のちにエフェソスは公会議が開かれるなどキリスト教が盛んな土地となった。","note":"レガシー女神信仰の地エフェソス　左上","exp":"2805"}],"3844":[{"type":"大型生物","name":"グリズリー","rank":"3","desc":"北米に生息する大型のクマ。雑食で、木の実や植物の葉などを主に食べるが、ほかの動物も捕食する。巨体だが動きは俊敏で、足も速く泳ぎも得意。人を襲うこともあるため、注意が必要である。","note":"危険生物調査","exp":"520"}],"1948":[{"type":"植物","name":"アルストロメリア","rank":"3","desc":"南米アンデス山脈の寒い地域に生息。様々な色彩の花が存在する。華やかで花持ちが良く切花としても人気。別名「インカのユリ」。","note":"友に捧ぐ花<br/><br/>発見時経験値480　発見物カード経験値240","exp":"480"}],"6895":[{"type":"海洋生物","name":"ナガスクジラ","rank":"5","desc":"クジラの仲間の中ではシロナガスクジラの次に大きく、体長は20mを越える。背中から尾にかけては暗灰色で、腹は白く、いくつもの畝がある。下顎の左右で色が異なり、独特の模様を成す。遊泳速度は時速35kmに達することもあるという。","note":"発見物カード:605","exp":"1210"}],"860":[{"type":"地理","name":"セーシェル諸島","rank":"2","desc":"アフリカとインドの間に点在する諸島。島の数は100を超える。サンゴ礁が多くとても美しい島々だが、その半分は淡水が得られないため人が住めない。","note":"天国のような無人島","exp":"320"}],"5145":[{"type":"港・集落","name":"ホロ","rank":"2","desc":"15世紀半ば、このホロを中心にスールー王国というイスラム王国が誕生した。近年、イスパニアが同地域に進出しているが、スールー王国の強い抵抗に遭っている。","note":"","exp":"342"}],"3015":[{"type":"歴史遺物","name":"貝製の喉あて","rank":"1","desc":"北米のエトワー川付近の墳墓から発見された貝製の装飾品。\n幾何学的な文様を含んだ、独特な図が彫り込まれている。","note":"貝製の装身具の地図","exp":"140"}],"2744":[{"type":"美術品","name":"安堅の風景画","rank":"2","desc":"朝鮮の画家・安堅による水墨画。\n季節を表現した八つの風景が描かれている。早春と晩春、初夏と晩夏、初秋と晩秋、初冬と晩冬と、二つずつ対となっている。","note":"風景画の地図","exp":"210"}],"5860":[{"type":"天文","name":"北アメリカ星雲","rank":"4","desc":"はくちょう座の尾部にある散光星雲。形が北米大陸に似ていることから名付けられた。暗いため、肉眼での観測は困難である。","note":"発見物カード:350","exp":"700"}],"7031":[{"type":"海洋生物","name":"タテジマキンチャクダイの幼魚","rank":"3","desc":"タテジマキンチャクダイの幼魚。体は黒く、青と白の渦巻模様が見られる。成長にともない、背びれ側から黄色の縞模様が現れ、渦巻模様は徐々に消えていく。そのため、成魚と幼魚では見た目が大きく異なっている。","note":"","exp":""}],"5326":[{"type":"宗教遺物","name":"ニャミニャミ像","rank":"2","desc":"魚の頭と蛇の体を持つ神を模した像。現地の人々から信仰されており、ニャミニャミの怒りに触れた者には大いなる災いが訪れるという。","note":"","exp":"220"}],"524":[{"type":"歴史遺物","name":"古代の木材","rank":"1","desc":"古代文明の建造物に用いられた木材。木材は加工しやすいのでよく用いられるが、多くが腐食しているため、原型がわかりづらい。","note":"古代の集落の地図","exp":"12"}],"5634":[{"type":"地理","name":"青の洞窟","rank":"3","desc":"イタリア南部のカプリ島にある海食洞。特異な地形の入り口から光が差し込むことで、洞窟内部が青く輝いて見える。","note":"","exp":"480"}],"859":[{"type":"美術品","name":"創世記（美術品）","rank":"5","desc":"ミケランジェロ作の壮大な天井画。システィナ大聖堂の天井を埋め尽くしている。題材は旧約聖書の「創世記」で、アダムの創造や楽園追放、大洪水などの有名な逸話が、躍動感に満ちた素晴らしい筆致で描かれている。","note":"天井を埋め尽くす絵画","exp":"1053"}],"5537":[{"type":"気象・現象","name":"夜光虫","rank":"2","desc":"海に棲む小さな生物の発光で海が輝いて見える現象。波打ち際での目撃例が多いため、波の衝撃などが発生の要因と考えられる。","note":"","exp":"174"}],"5716":[{"type":"大型生物","name":"ヤク","rank":"4","desc":"高地に生息する牛のような動物。全身を長い毛でおおわれており、野生種は根の色が黒茶だが、家畜化されたものには白や赤が混ざるという。搾乳から荷物の運搬まで多くの用途に使われている。","note":"2017.02.07新規追加","exp":"690"}],"6174":[{"type":"鳥類","name":"ワタリガラス","rank":"4","desc":"「レイヴン」とも呼ばれ、 通常のカラスよりひと回り大きい。約聖書や北歐神話にも登場するほかロンドンでも飼育されており、「ロンドン塔からワタリガラスがいなくなるとイングランドは滅びる」と言い伝えられているそうだ。","note":"","exp":"650"}],"1653":[{"type":"地理","name":"バス海峡","rank":"3","desc":"オーストラリア大陸とタスマニア島との間にある海峡。幅が狭く水深が浅いため、船の難所として知られる。\nオーストラリア先住民は、この海峡が形成される過程を伝承によって語り継いでいる。","note":"島と陸との間に","exp":"473"}],"5490":[{"type":"海洋生物","name":"ヨシキリザメ","rank":"3","desc":"熱帯から温帯の海に広く分布するサメ。最大で4mほどになり人や船を襲うこともある。","note":"釣り発見物。南大西洋(16244,6205)","exp":"480"}],"511":[{"type":"歴史遺物","name":"古代インドの銀貨","rank":"1","desc":"古代インドで使われていた銀貨。古代インドの通貨は、ほとんどが銀であったという。円や角型のほか、はしを削って重量を調整した多角形のものもある。","note":"古代の貨幣の地図","exp":"175"}],"567":[{"type":"歴史遺物","name":"羊皮紙の古文書","rank":"1","desc":"羊の皮を薄く加工した羊皮紙で作られた本。安定性が高く保存によい。中世では本はすべて写本だったので、非常に高価で貴重な物だった。","note":"古文書の地図","exp":"23"}],"6742":[{"type":"歴史遺物","name":"モコロ","rank":"3","desc":"南アフリカにある広大な湿地帯で使われる小舟。アフリカに広く分布しているソーセージノキの幹を焼き、中をくり抜いて作られる。入り組んだ水路において、必要不可欠な移動手段。","note":"発見物カード:215","exp":"430"}],"3426":[{"type":"レリック","name":"エルドラド(財宝伝説)","rank":"","desc":"伝説のシボラの街といわれる、黄金と宝石に満ちあふれた神殿。水没しかけており、その美しさもいつか失われてしまうのだろうか。","note":"","exp":""}],"5402":[{"type":"天文","name":"カノープス","rank":"4","desc":"おおいぬ座のシリウスに次ぎ、全天で2番目に明るい星。白い星だが、北半球では南天の低い位置にあるため赤い色に見え、「南極老人星」と呼ばれる。","note":"発見物カード:330<br/>","exp":"660"}],"5955":[{"type":"財宝","name":"東方見聞録","rank":"1","desc":"13世紀終わりごろ、元朝のフビライに仕えたマルコ・ポーロの口述を記録した本。この中に、黄金の国ジパングが登場する。","note":"冒険者のバイブル","exp":"55"}],"271":[{"type":"宗教建築","name":"アクスム石柱群","rank":"1","desc":"かつて栄えたアクスム王国の遺跡。独特の様式の石柱は百本以上ある。現在見つかっているものの中ではもっとも高い石柱がある。基部には石室があるところから、王族などの墓だと思われる。","note":"プレステ・ジョアンの国","exp":"190"}],"5637":[{"type":"天文","name":"イアペトゥス","rank":"4","desc":"タイタン、レアに次いで大きな土星の衛星。\n表面が明るい部分と暗い部分にはっきり分かれており、状況によっては観測しづらい。","note":"リグリア海で発見。発見時、視認スキル、天文学スキルともに10。","exp":"800"}],"6367":[{"type":"宗教建築","name":"ジュガンティーヤ","rank":"2","desc":"地中海に浮かぶ島にある巨大な石で作られた神殿。伝承では巨人が石を運んで造り上げたとされる。かつては扉や天井が存在した痕跡もあり、奥の祭壇では動物が生贄として捧げられたという。","note":"","exp":"210"}],"6699":[{"type":"美術品","name":"黙示録の版画","rank":"5","desc":"アルブレヒト・デューラーの最も有名な木版画の一つ。「黙示録」と呼ばれる聖書の一説がモチーフとなっている。木版画の裏には黙示録の文章が印刷してあり、書籍として販売された。","note":"追究クエスト<br/>発見物カード:450","exp":"900"}],"2958":[{"type":"植物","name":"キングサリ","rank":"1","desc":"ヨーロッパ南部原産の植物。初夏にチョウのような形の黄色い花を房状に咲かせる。\n全体に毒があるため、注意が必要である。","note":"金の鎖","exp":"200"}],"2862":[{"type":"財宝","name":"長恨歌","rank":"4","desc":"唐代の玄宗皇帝と楊貴妃の逸話を歌った、長編の漢詩。時代が唐代ではなく漢代に変更されているなど、史実と異なる部分が多い。","note":"本を携えた男<br/><br/>発見時経験値660　発見物カード経験値330","exp":"660"}],"6463":[{"type":"宗教建築","name":"モンテ・アルバンの天文台","rank":"5","desc":"要地を支配するため丘の上に建設された、防衛能力を有する集落が元となったという「モンテ・アルバン」。遺跡には他とは毛色の異なる建造物、天文台があり、征服した地名などが刻まれた石板がはめ込まれている。","note":"","exp":""}],"365":[{"type":"財宝","name":"イエローダイヤ","rank":"3","desc":"黄色いダイヤモンド。透明度が高いものほど価値が高い。","note":"黄色い宝石の鉱脈の地図","exp":"555"}],"6457":[{"type":"財宝","name":"ハムサ","rank":"5","desc":"手をかたどり、その中央に目が描かれた、邪視から身を守るための護符。「ハムサ」とはアラビア語で数字の5を意味する。トルコのお守り「ナザール・ボンジュウ」はこの亜種だという説もある。","note":"追究クエスト<br/>発見物カード:520","exp":"1040"}],"1999":[{"type":"海洋生物","name":"オヒョウ","rank":"2","desc":"体長3mにもなる巨大なカレイ。北極海に生息する。","note":"釣り","exp":"240"}],"663":[{"type":"美術品","name":"エレクティオンの少女像","rank":"2","desc":"パルテノン神殿のそばに建つ、エレクティオン神殿のカリアティド（女像柱）。6体あり優雅な雰囲気を漂わせている。","note":"少女像の柱の地図","exp":"210"}],"5699":[{"type":"地理","name":"ヒマラヤ山脈","rank":"2","desc":"雪が住まいし地、という意味の名前を持つ山脈。世界有数の山脈の一つで非常に高い峰々と豊かな水源を持つ。巨大な山々は長きにわたって人々の移動を妨げてきたため、この山脈がなければ、周辺地域の歴史は大きく変わっていただろう。","note":"2017.02.07新規追加","exp":"340"}],"5183":[{"type":"港・集落","name":"ヴェネツィア","rank":"1","desc":"地中海最大の貿易都市として、非常に栄えている街。扱われている産物も、高価な物がほとんどである。しかし栄華の極みにあったこの街も、ほかの新興勢力に押されて傾きはじめているといわれる。","note":"到達する","exp":"30"}],"1726":[{"type":"財宝","name":"ワヤン・クリ","rank":"2","desc":"ジャワ島で古くから上演される伝統的な影絵芝居。革の人形を用いる。現地語でワヤンは影、クリは革を指す。「マハーバーラタ」や「ラーマーヤナ」が上演演目になるワヤン・クリ・プルウォが一般的だが、ジャワの伝説や昔話も上演される。","note":"ジャワの影絵芝居","exp":"270"}],"982":[{"type":"歴史遺物","name":"ネロ帝のブロンズ像","rank":"1","desc":"ネロは古代ローマの皇帝で、悪逆の皇帝として知られる。邪魔な血縁者を次々に葬ったが娯楽の提供に熱心だったため、民衆に人気があった。","note":"暴帝ネロの像","exp":"50"}],"2523":[{"type":"虫類","name":"テナガコガネ","rank":"2","desc":"台湾島付近や中国に生息するコガネムシ。雄は前脚がとても長い。繁殖能力が低いため、あまり見かけることができない。","note":"少年好みの虫探し","exp":"260"}],"1961":[{"type":"宗教遺物","name":"儀式用盃","rank":"2","desc":"アンデスの各農村部では、この盃を酌み交わし団結を誓う儀式が執り行われる。盃の底には二頭のウシが作られており、団結を誓い合った者たちの力をさらに高めるという。","note":"アンデスの儀式道具の地図","exp":"220"}],"3920":[{"type":"天文","name":"はくちょう座","rank":"1","desc":"ゼウスがスパルタの王妃レダの元に向かう際に変身した白鳥が天に昇った姿とされる。十字を描いている中心部は、北十字星と呼ばれることもある。","note":"クエスト「美女の伝説」<br/>発見物カード:90","exp":"180"}],"3941":[{"type":"天文","name":"こと座","rank":"2","desc":"ギリシャ神話に登場するオルフェウスの竪琴が空に上がった姿とされる星座。オルフェウスは竪琴の名手で、その旋律は嵐をも静めるほどだったという。","note":"クエスト「伝説の吟遊詩人」<br/>発見物カード:110","exp":"220"}],"4838":[{"type":"天文","name":"エリダヌス座","rank":"2","desc":"蛇行して流れる川をかたどった星座。その元となった川は、アフリカ北部のナイル川や、イタリア北部のポー川などといわれる。ギリシャ神話では、ヘリオスの息子が天を走る馬車を暴走させた際、ゼウスの落雷を受けて落ちた川ともされる。","note":"南天の川","exp":"210"}],"1969":[{"type":"鳥類","name":"インカアジサシ","rank":"3","desc":"南米の西岸に生息する海鳥。濃い灰色の体に赤いくちばし、口ひげのような白い飾り羽根が特徴。何千羽という群れで生活し、海岸の岩場で集団で佇んでいるのがよく見られる。上空から海へ一直線に飛び込み、上手に魚を捕まえる。","note":"白ひげ鳥<br/><br/>冒険経験470　カード経験235","exp":"470"}],"6186":[{"type":"海洋生物","name":"トビウオ","rank":"1","desc":"主に暖かい海に生息している。名前の由来は水上に飛び出し、羽根のような胸ビレを広げて滑空することから。海の表層を泳いでいるのは、マグロなどの捕食者から逃げるためといわれる。勢いあまって甲板に上がることもある。食べると美味。","note":"跳ねる魚の地図","exp":"120"}],"2514":[{"type":"虫類","name":"シロオビアゲハ","rank":"1","desc":"中国南部からインドにかけて生息する、白い斑点がきれいに並んだ羽を持つチョウ。\n毒性がないため、ベニモンアゲハに体色を似せることで敵から身を守る。","note":"ベニモンアゲハに似たチョウ<br/><br/>発見時経験値180　発見物カード経験値90","exp":"180"}],"6072":[{"type":"伝承","name":"ベテスダの池","rank":"4","desc":"「神の恩寵」を意味するベテスダという土地にある池。神の御使いが池の水を「動かす」と、池にはいかなる病も癒す力が一時的にだが備わったと伝えられている。","note":"","exp":"740"}],"6409":[{"type":"財宝","name":"天馬が刻まれた古代のコイン","rank":"5","desc":"カリア地方で使われていたらしい硬化。ペガサスの頭部が描かれている。アケメネス朝ペルシャは各地方に太守を置いて統治しており銀貨や銅貨は各太守によっても発行された。カリアは事実上の独立状態で、マウソロスが統治していた。","note":"","exp":""}],"6479":[{"type":"史跡","name":"在りし日のロードス島の巨像台座","rank":"5","desc":"ロードス島の港に立つ太陽神ヘリオスの巨大な青銅像。攻城者デメトリオスによる包囲を耐え切り、勝利した記念として建造された。大理石製の巨大な台座の上に、両足で港の入り口をまたぐように建てられたという説もある。","note":"","exp":""}],"132":[{"type":"宗教遺物","name":"聖母のステンドグラス","rank":"1","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40"}],"3669":[{"type":"歴史遺物","name":"クレオパトラの像","rank":"4","desc":"プトレマイオス朝最後のファラオとなったクレオパトラのものと思われる石像。プトレマイオス朝を滅ぼしたアウグストゥスが神殿を改修した際に撤去されたようだ。","note":"ダンジョン","exp":"710"}],"2525":[{"type":"虫類","name":"クロアゲハ","rank":"1","desc":"台湾島や中国を含め、広い地域に生息するチョウ。艶やかな黒い羽を持つが、雄の後羽には時間と共に変色していく模様がある。\n他のアゲハチョウより暗い場所を好む。","note":"黒いチョウの地図","exp":"190"}],"1186":[{"type":"地理","name":"セントヘレナ","rank":"2","desc":"アフリカ大陸の西、南大西洋にぽつりと浮かぶ島。陸から2000km以上離れている絶海の孤島である。しかし、ここに補給港ができればアフリカ航路を大きく短縮できるだろう。","note":"大海に浮かぶ孤島","exp":"380"}],"1502":[{"type":"小型生物","name":"アカアシガメ","rank":"1","desc":"脚に赤い斑点があるカメ。湿度の高い環境を好み、木の葉や果実などを食べる。成長すると甲羅の中央がくびれてくる。","note":"赤いカメの地図","exp":"100"}],"4812":[{"type":"財宝","name":"火熨斗","rank":"3","desc":"「ひのし」と呼ばれる布地の皺を伸ばすための道具。器状の部分に熱した炭を入れ、器の底を布地に当てて皺を伸ばしたと思われる。","note":"宋山里遺跡群 （中層隠し部屋）読み:「ひのし」","exp":""}],"1458":[{"type":"鳥類","name":"コキンチョウ","rank":"1","desc":"オーストラリアに生息する鳥。頭の色は個体によって様々で、巣にはシロアリの塚を利用する。","note":"小さな鳥の地図","exp":"155"}],"6534":[{"type":"歴史遺物","name":"ファザーリのアストロラーブ","rank":"5","desc":"古代ギリシャで考案された天文観測機器。イスラム世界では8世紀の数学者ファザーリ親子が最初に製作したと伝わり、その後イスラム世界で大きく発展した。多くは真鍮製で、太陽や月、星の位置測定や予測のほか、さまざまな機能がある。","note":"","exp":""}],"1298":[{"type":"中型生物","name":"バビルーサ","rank":"2","desc":"バビルーサとは現地の言葉で「ブタ、シカ」という意味。上あごから皮膚を突き破って生えた牙が特徴。牙はオス同士の戦いなどに用いられる。","note":"丸太のような生物<br/><br/>発見時経験値220　発見物カード経験値110","exp":"220"}],"2120":[{"type":"植物","name":"ニゲラ","rank":"1","desc":"地中海の沿岸部に咲く植物。イチゴのような甘い香りのする黒い種と、鮮やかな色を持つ花が特徴である。\nこの種は香辛料としても使用される。\n別名クロタネソウ。","note":"甘い匂いの誘惑","exp":"180"}],"2049":[{"type":"財宝","name":"ダ・ヴィンチノート","rank":"2","desc":"ダ・ヴィンチ直筆の著書。天文学や医術に関する知識や考察から、デッサンやスケッチまで幅広く記述されている。しかし文字はすべて鏡文字で書かれており、読むことは容易ではない。","note":"［勅命］[[運河開通事業の技術書","exp":"310"}],"2886":[{"type":"化石","name":"カメのような動物の石","rank":"2","desc":"黄河の南で発見されたカメと思われる生物の石。頭と思われる部分は見当たらないが、欠けてしまったのだろうか？","note":"奇妙な石の地図","exp":"330"}],"5146":[{"type":"港・集落","name":"ボルドー","rank":"1","desc":"先史時代の壁画が見つかるほど、太古から人が住んでいた街。長くイングランドの支配下にあったが、100年戦争でフランスの領土となった。水に恵まれた地勢で、農業が非常に盛ん。特に良質のワインを作っている。","note":"到達する","exp":"19"}],"2016":[{"type":"歴史遺物","name":"黄金の円盤","rank":"2","desc":"インカ帝国を興したケチュア民族の太陽神インティを模した黄金の円盤。インカ帝国の各地にある「コリカンチャ」と呼ばれる太陽の神殿には、必ずこの円盤を奉った。黄金の円盤は装飾品にも使われ王のみが身に着けられた。","note":"アンデスの儀式道具の地図","exp":"155"}],"6867":[{"type":"天文","name":"コル・カロリ","rank":"5","desc":"りょうけん座で最も明るいアルファ星。3等星で二つの星で構成される連星。春の大三角と共に「春のダイヤモンド」を形成する。名はラテン語で「チャールズの心臓」を意味する。","note":"発見物カード:425","exp":"850"}],"6453":[{"type":"気象・現象","name":"ライトピラー","rank":"2","desc":"地面から空に向かって光の柱が伸びているように見える現象。寒い地域で、遠くにある地上の光が上空に漂う氷の結晶を含んだ薄い雲に反射することで柱のように見える。","note":"ストックホルム港前。夜。たぶん冬（冬になった直後の夜に観測）<br/>発見物カード:130","exp":"260"}],"5335":[{"type":"天文","name":"おおかみ座","rank":"2","desc":"ゼウスの怒りを買ったアルカディアの王リュカオンがオオカミに姿を変えられ、天に上った姿とされる。おおかみ座とケンタウルス座は古代メソポタミアの時代から対とされることが多かった。","note":"クエスト「野獣の星座」<br/>発見物カード:140","exp":"280"}],"6681":[{"type":"大型生物","name":"ゴトランドポニー","rank":"3","desc":"スウェーデンのゴトランド島原産の馬。体高は120cmほどでポニーに分類される。石器時代には存在していたとされる古い品種で、絶滅種であるターパン馬の子孫だと考えられている。","note":"","exp":"500"}],"6766":[{"type":"虫類","name":"トドノネオオワタムシ","rank":"2","desc":"アブラムシの一種。蝋質の分泌物を身にまとい、綿のような見た目をしている。秋の終わりに大量発生すると、群れて飛ぶ。それが雪が降るように見えることから、「雪虫」という異名を持つ。","note":"発見物カード:165","exp":"330"}],"117":[{"type":"美術品","name":"円盤投げ","rank":"2","desc":"古代ギリシャの彫刻家・ミュロン作といわれる男性像。原作は青銅だと伝えられるがこれは大理石製の模作である。ローマ時代の作とされる。","note":"ギリシャの競技の像","exp":"220"}],"1316":[{"type":"地理","name":"スンダ海峡","rank":"1","desc":"スマトラ島とジャワ島の間に横たわる海峡。海峡の幅はとても狭いため、航行は困難を極める。周囲には火山島を含む多くの小島が点在する。","note":"書きかけの地図","exp":"160"}],"1848":[{"type":"宗教遺物","name":"ランソン像","rank":"1","desc":"ジャガーの頭とヘビの髪の毛、人間の体を持つ神像。インカにおいてもジャガーは神格化されているが、人間と融合した姿で描かれることはない。リマ周辺には、インカ以前から高度な文明を持った民族がいたのかもしれない。","note":"古の神像の地図","exp":"150"}],"6851":[{"type":"天文","name":"アルキバ","rank":"3","desc":"からす座のアルファ星だが、この星座の5つの恒星の中で最も暗い4等星。カラスのくちばしに位置し、名はアラビア語で「テント」を意味する。","note":"発見物カード:280","exp":"560"}],"6594":[{"type":"史跡","name":"チャン・チャン遺跡","rank":"5","desc":"南米、チムー王国の都市跡といわれる広大な古代遺跡。日干し煉瓦で作られた建物の外壁と網目状の部屋仕切りが特徴的な遺跡で、その名には「輝ける太陽」の意味があるという。","note":"レガシー伝説の王都バビロン　左下","exp":""}],"2831":[{"type":"美術品","name":"李迪の絵画","rank":"4","desc":"宋代の宮廷画人・李迪が描いた牛画。\n家畜の牛を画題にした絵は、戦乱のない平和な農村を謳歌するという意味を持つことが多い。","note":"平和を求める気持ち","exp":"660"}],"5253":[{"type":"天文","name":"ケンタウルス座","rank":"4","desc":"エリュマントスの猪の生け捕りに赴いたヘラクレスと知り合い、歓待したポロスというケンタウロスが天に上った姿とされる星座。古代ギリシャから存在する星座だが、歳差運動で地軸の向きが変わり現在のギリシャで見ることは困難である","note":"クエスト「もう一人のケンタウロス 」<br/>発見物カード:315","exp":"630"}],"4807":[{"type":"歴史遺物","name":"無血開城の誓約書","rank":"4","desc":"紅毛城を無血開城するという誓約の際に作られたと思われる書状。イスパニア、ネーデルラント双方の印が押されている。保存状態が悪く、ところどころ破れている。","note":"紅毛城（深層隠し部屋）","exp":""}],"5940":[{"type":"植物","name":"復活草","rank":"5","desc":"乾季と雨季でその姿を変える珍しい植物。その驚くべき変貌ぶりから「復活草」と呼ばれており、水がなくとも数十年生き続けるという説すら存在する。","note":"","exp":"990"}],"3589":[{"type":"地理","name":"マウイ島","rank":"1","desc":"ハワイ島から一番近い島。島群の中ではハワイ島に次いで大きい。二つの小島が溶岩で繋がり、今のマウイ島になったという。","note":"ハワイ周辺の地理調査","exp":"115"}],"6142":[{"type":"財宝","name":"二本歯のフォーク","rank":"2","desc":"11世紀にヴェネツィア総督夫人となったビザンツ皇女テオドラが、結婚時に持ち込んだカテラリーの一つ。当時のヨーロッパではフォークを使う習慣が廃れていたため、彼女ともども「異教徒かぶれの文物」として非難の的になった。","note":"","exp":"320"}],"820":[{"type":"美術品","name":"勝利","rank":"1","desc":"ミケランジェロ作の大理石像。ユリウス2世の墓標のために作られた像の一つだが、未完成のまま打ち捨てられた。老人を組み敷き、体をねじらせた若者の像である。","note":"大理石の男性像の地図","exp":"120"}],"5144":[{"type":"港・集落","name":"ホルムズ","rank":"1","desc":"ペルシャ湾のホルムズ海峡に面する街。海上交易の重要地点で、古くから栄えた。その重要性からたびたび支配勢力が変わった。畜産が盛んなほか、高級品のペルシャ絨毯やターコイズなどの宝石が流通している。","note":"到達する","exp":"130"}],"1714":[{"type":"財宝","name":"グンデル","rank":"2","desc":"ジャワ島に古くからある金属楽器。バチで金属の鍵盤を叩き、手で共鳴を適度に止めて、奏でる。ワヤン・クリの伴奏として演奏されることが多いが、祭礼や儀式でも演奏されるようだ。","note":"［勅命］[[未知の魅力","exp":"320"}],"6711":[{"type":"天文","name":"プレセペ星団","rank":"2","desc":"かに座の甲羅の中央にある星団。名はラテン語で「かいば桶」を意味する。かつては1つの天体だと考えられていたが、ガリレオ・ガリレイが星の集まりだと見抜いた。","note":"「天文学者の観測記録」<br/>発見物カード:175<br/>東アジア西部","exp":"350"}],"6625":[{"type":"鳥類","name":"タカヘ","rank":"3","desc":"クイナ科の空を飛べない鳥。ニワトリほどの大きさで、地上の生活に適応するために、分厚いクチバシと太い脚を持つ。羽は光に当たる角度によって青や緑に変化し、その色は成鳥になるにつれ鮮やかになる。","note":"","exp":"480"}],"2876":[{"type":"財宝","name":"蘭亭序","rank":"3","desc":"王羲之により書かれた行書。\n文中に何度も出てくる文字は、文脈によって形を書き分けられている。唐代の太宗皇帝がこれを気に入り、書家に模刻させたという。","note":"唐代皇帝への興味","exp":"530"}],"6354":[{"type":"レリック","name":"灼熱の大灯皿","rank":"","desc":"ロードス島の巨像が持つ巨大な炎の器。港に不当に進入する船には、この器から燃え盛る炎が降り注がれたという。","note":"トレジャーハント「古地図にまつわる伝承」","exp":""}],"6653":[{"type":"中型生物","name":"メキシコオオカミ","rank":"5","desc":"北米の森林部に生息するオオカミ。普通のオオカミより小型。自分たちより体格の大きな獲物を狩る際は、群れをなして行動する。","note":"追究クエスト","exp":"1100"}],"6461":[{"type":"鳥類","name":"繁殖羽のクロツラヘラサギ","rank":"5","desc":"朝鮮半島北西部でよく見られるサギの一種。渡り鳥で広い範囲で越冬のために南下する。通常期は、全身の羽毛が白いが、夏場の繁殖期には首が黄色く変化し、後頭部から黄色の冠羽が生えてくる。","note":"","exp":"1650"}],"1168":[{"type":"歴史遺物","name":"メソアメリカの印章","rank":"2","desc":"土器製の円筒状印章。なにに使われたのかは定かではない。顔料を塗って体に付けたり、柔らかい状態の土器の上に転がして、模様を付けたりしたのだろうか？","note":"変わった石","exp":"270"}],"585":[{"type":"財宝","name":"めっきのはげた首飾り","rank":"1","desc":"美しい細工がされた首飾りだが、めっきを施した物で、それほど価値はないようだ。めっきがはげてしまい、みすぼらしい。","note":"豪華な宝石細工の地図","exp":"19"}],"1462":[{"type":"宗教遺物","name":"シペ・トテック像","rank":"4","desc":"アステカ神話における穀物・豊穣神。その名は、「生爪をはがれたもの」という意味。豊作の保証として、生贄を要求するといわれている。","note":"クエスト「アステカの豊穣神」<br/>発見物カード:360","exp":"720"}],"1205":[{"type":"地理","name":"ラプラタ川","rank":"3","desc":"南米南東岸に河口を持つ大きな川。その河口は非常に大きく、戦艦も入り込めそうなほどだが、水深が浅く、一般的な船での遡上は無理だろう。","note":"銀と川","exp":"484"}],"310":[{"type":"財宝","name":"獅子心王の甲冑","rank":"3","desc":"「しししんおうのかっちゅう」。獅子心王とは、プランタジネット朝イングランド王のリチャード1世のこと。第3回十字軍に従軍した際に身につけていた甲冑だという。","note":"ライオン・ハーティド","exp":"528"}],"6881":[{"type":"天文","name":"カラ","rank":"5","desc":"りょうけん座のベータ星。星座の中では2番目に明るい4等星。元は南側の犬の名を指していたが、のちに星の名前となった。","note":"発見物カード:700","exp":"1400"}],"5595":[{"type":"地理","name":"レッドベイ","rank":"2","desc":"北米大陸北東部に位置する湾。天然の良港であり、捕鯨などの基地として利用される。","note":"","exp":"300"}],"2437":[{"type":"鳥類","name":"キジ","rank":"1","desc":"明るい林や草原などに生息する、日本特産の鳥。\n雄は、胸から腹にかけて光沢のある緑色、目の周りは鮮紅色で、目の覚めるような色合いをしている。","note":"色鮮やかな鳥の地図","exp":"130"}],"3388":[{"type":"宗教遺物","name":"エアのレリーフ","rank":"4","desc":"エアとはバビロニア神話に登場する神の名であり、かつてウルの南にあったとされる都市エリドゥの守護神である。洪水伝説において船の作り方を教えたという伝承がある。\nメソポタミア神話では「エンキ」と呼ばれていたようだ。","note":"メソポタミアの魔術神<br/><br/>発見時経験値740　発見物カード経験値370","exp":"740"}],"726":[{"type":"植物","name":"ハス","rank":"2","desc":"東洋で神聖な花だとされている植物。神が座る台座に描かれることが多いようだ。厚みのある上品な花弁が美しい。早朝から咲きはじめ、午後になるとつぼんでしまう。","note":"聖なる花","exp":"340"}],"2991":[{"type":"植物","name":"ハエトリソウ","rank":"2","desc":"北米大陸の東沿岸部に自生する食虫植物。トゲのついた葉は二枚で一組となっており、葉の内側には数本の毛が生えている。この毛に触れると葉が閉じ、捕らえた虫を消化して養分とする。","note":"虫取り草再び<br/><br/>発見時経験値360　発見物カード経験値180","exp":"360"}],"3615":[{"type":"地理","name":"ラドガ湖","rank":"4","desc":"サンクトペテルブルク北東に位置し、重要な水源となっている湖。湖には多数の島が点在し、大きな島には人も住んでいるようだ。冬になると凍結する。","note":"広大すぎる湖","exp":"740"}],"5063":[{"type":"港・集落","name":"サンティアゴ","rank":"2","desc":"キューバ島の南東部にある街。地形が港に適しており、付近の交易の中継点として栄えている。カリブ特有の農作物が豊富に流通している。","note":"到達する","exp":"239"}],"109":[{"type":"鳥類","name":"トパーズハチドリ","rank":"3","desc":"宝石のようにきらびやかな羽で覆われた鳥。空中で静止するように飛び、花蜜を吸う。","note":"カリブの宝石","exp":"600"}],"180":[{"type":"財宝","name":"スルタンの装束","rank":"1","desc":"スルタンとは、イスラム勢力の最高権力者のことである。これは昔のスルタンが身につけていたとされる衣装。中国産の絹を惜しげもなく使い、使われている染料も非常に高価なものだ。","note":"スルタンという存在","exp":"180"}],"5583":[{"type":"地理","name":"ロッキー山脈","rank":"2","desc":"北米大陸西部に位置する山脈。豊かな動植物と天然資源に恵まれている。","note":"クエスト「北米大陸を貫く山脈」<br/>発見物カード:160","exp":"320"}],"6902":[{"type":"植物","name":"ホウガンノキ","rank":"3","desc":"南米原産の樹木。蛇のようにうねった枝に、薄紅色の花が数多く咲く。果実は直径20cmほどにもなり、見た目が大砲の砲弾に似ていることから、この名がついた。","note":"発見物カード:265","exp":"530"}],"4976":[{"type":"宗教建築","name":"ミストラ遺跡","rank":"2","desc":"ペロポネソス半島南部にある城塞都市遺跡。ギリシャ神話の英雄メネラオスの神殿やフレスコ画のある修道院、ビザンツ建築の聖堂など、多くの建築物が存在する。当初は単なる防衛拠点だったが、次第に発展して城塞都市を形成したようだ。","note":"","exp":"270"}],"6868":[{"type":"天文","name":"ズベン・エル・ゲヌビ","rank":"3","desc":"てんびん座のアルファ星。3等星で、4つ以上の恒星から成る多重連星。名はアラビア語で「南の爪」を意味し、元々はさそり座の爪にあたる部分であった名残といわれている。","note":"発見物カード:255","exp":"510"}],"6001":[{"type":"気象・現象","name":"副虹","rank":"2","desc":"虹が2つ並行して発生した際の外側のものを副虹という。原理は不明だが、2つの虹の色の並びは逆になっている。","note":"発見物カード:120","exp":"240"}],"1790":[{"type":"財宝","name":"銀の腕輪","rank":"1","desc":"南米でも最近銀細工が増えたようだ。なんでも、インカ道の南のほうには、宝の山があるとか…。","note":"珍しい腕輪の地図","exp":"160"}],"6682":[{"type":"天文","name":"メンカル","rank":"5","desc":"クジラ座の鼻先にあたる赤色巨星。名はアラビア語で「鼻の孔」を意味する。\n\nカード：経験値410","note":"発見物カード:410","exp":"820"}],"6044":[{"type":"財宝","name":"ペスト哀歌","rank":"2","desc":"モスル地方の北部に在住していた司祭によって記された詩。原典はアラム語で248編にわたって書かれている。全体を通してペストが人々を蹂躙する様子を嘆く内容だが、当時実際に流行していたのはコレラであったという説もある。","note":"カード経験80","exp":"190"}],"2982":[{"type":"植物","name":"アメリカフジ","rank":"1","desc":"北米南部に分布する、フジの一種。\n本種に比べて花が小さく、花房も15cm程度の長さである。","note":"房状の花の地図","exp":"170"}],"3382":[{"type":"歴史遺物","name":"アトラハシス叙事詩","rank":"5","desc":"古代メソポタミアの叙事詩。ギルガメシュ叙事詩と同様に洪水伝説の記述がある。洪水を免れ、生存した人間の名が「アトラ・ハーシス」とされている。","note":"ノアの別名<br/><br/>発見時経験値1230　発見物カード経験値615","exp":"1230"}],"5722":[{"type":"気象・現象","name":"ヤコブの梯子","rank":"","desc":"雲の切れ目から太陽光が帯状に降り注いで見える現象。太陽が低くなる早朝や夕方に観測されることが多い。名前はヤコブが見た夢に由来するとされる。","note":"オホーツク西岸より奥地 バイカル湖周辺 南の凍った湖","exp":""}],"259":[{"type":"宗教遺物","name":"ブラフマー像","rank":"3","desc":"ヒンドゥー教における最高神の像。このブラフマーは創造神であるとされ、三大神の一人である。しかし、ほかのシヴァとヴィシュヌに比べるとあまり信仰の対象とはなっていないという話だ。","note":"ヒンドゥーの最高神","exp":"484"}],"6558":[{"type":"歴史遺物","name":"ヒュドラウリス","rank":"5","desc":"水圧を用いて空気を送り、音を奏でる水オルガン。紀元前2世紀ごろにアレクサンドリアの学者クテシビオスが製作したという。のちに弟子とされるヘロンらが改良し、地中海近辺に広まった。","note":"","exp":""}],"476":[{"type":"財宝","name":"オットー1世の宝冠","rank":"2","desc":"オットー1世が、初代神聖ローマ帝国皇帝に即位したときの帝冠だとされる。黄金と宝石をふんだんに使った、豪華な作りである。","note":"権威の象徴","exp":"290"}],"5703":[{"type":"気象・現象","name":"ブロッケンの妖怪","rank":"4","desc":"太陽などの光が後方から差し込み、影に周囲に虹に似た光の輪が発生する現象。発生するには広範囲の霧と日の光を遮らない開けた場所が必要である。そのため、山などの高地での観測例が多い。","note":"2017.02.07新規追加<br/>視認R9では「発見するにはスキルランクが不足」とのメッセージがでました。R11で発見。<br/>R10で発見できました。確定かと。","exp":"780"}],"6967":[{"type":"中型生物","name":"アカオザル","rank":"4","desc":"アフリカ中部の熱帯雨林などに広く生息するサル。鼻先にハート形の白い毛を持つ黒い顔と、体長の倍におよぶこともある赤茶色の尾が特徴。尾の色が名前の由来とされている。","note":"発見物カード:325","exp":"650"}],"5519":[{"type":"地理","name":"アルダブラ環礁","rank":"2","desc":"マダガスカル島の北に位置する環礁。多くのゾウガメのほか、さまざまなウミガメや鳥が生息する。","note":"「書きかけの地図」<br/>発見物カード:120<br/>ザンジバル沖のマダガスカル島の真北(2200.5017付近)","exp":"240"}],"3732":[{"type":"財宝","name":"ラムセス2世の強弓","rank":"4","desc":"古代エジプトのファラオ・ラムセス2世が使用したとされる弓。常人では引けないほど強く弓が張られているため、武器としては扱えないようだ。","note":"ダンジョン","exp":"610"}],"1993":[{"type":"海洋生物","name":"ファハカ","rank":"1","desc":"ナイル川に生息するフグ。淡水に生息するとは珍しいフグだ。","note":"釣り","exp":"160"}],"2867":[{"type":"植物","name":"エンジュ","rank":"1","desc":"主に中国に生息する、たくさんの白い花を咲かせる植物。\n薬用植物としても有名で、花の蕾を干したものは、止血剤として使われている。","note":"白い花の地図","exp":"130"}],"3579":[{"type":"宗教遺物","name":"般若経","rank":"2","desc":"はんにゃきょう。多くの仏教経典の総称。般若とはサンスクリット語でプラジューナー、「悟りの智慧」を意味する。","note":"［勅命］[[ジャワ思想調査","exp":"340"}],"1209":[{"type":"財宝","name":"ジャガーの瞳","rank":"5","desc":"全てを闇に吸い込んでしまいそうな漆黒の宝石。正体は、非常に深い色合いの黒曜石だ。メソアメリカの人々はこれを「ジャガーの双眸」だといって恐れていた。","note":"ジャガーの瞳","exp":"1014"}],"756":[{"type":"財宝","name":"ブルーダイヤ","rank":"3","desc":"青いダイヤモンド。美しい青のダイヤは非常に希少で、めったに出ない。","note":"青い宝石の鉱脈の地図","exp":"595"}],"5303":[{"type":"海洋生物","name":"ムブナ","rank":"1","desc":"アフリカ南東部の湖に棲む、鮮やかな縞模様を持つ淡水魚。縄張り意識が強い魚で、個体によって微妙に違う。どうやら、より強い魚ほどはっきりした模様を持つようである。","note":"発見時経験値120　発見物カード経験値60","exp":"120"}],"3588":[{"type":"地理","name":"ハワイ島","rank":"1","desc":"太平洋のほぼ中心にある島群の中で、最大の広さを持つ島。火山活動が活発で、島の大半は溶岩が凝結した土地から成る。","note":"太平洋の真ん中","exp":"120"}],"204":[{"type":"財宝","name":"金糸を使ったタペストリー","rank":"1","desc":"壁に掛ける豪華な布。金糸を使い、織り目はとても詰んでいる。まるで絵画のようだ。","note":"タペストリーの地図","exp":"64"}],"686":[{"type":"大型生物","name":"ゴリラ","rank":"2","desc":"西アフリカの熱帯地域に生息する、極めて大型のサルである。非常に発達した筋肉を持ち集団で生活してるようだ。行動を見る限りでは、かなり高い知能を持っているようだ。人間に近いのだろうか。","note":"クエスト「森の中の黒い影」<br/><br/>発見時経験値:350　発見物カード経験値:175","exp":"350"}],"6035":[{"type":"植物","name":"クチナシ","rank":"1","desc":"日本、中国、台湾、インドシナ半島などに分布する植物。主に\n森林に群生し、初夏から夏にかけて強い芳香を放つ白い花を咲かせるのが特徴。果実は漢方薬に使われるほか、食材や染料としても用いられる。","note":"","exp":"140"}],"4809":[{"type":"財宝","name":"金唐傘の馬印","rank":"","desc":"","note":"安土城（中層隠し部屋）","exp":""}],"2762":[{"type":"財宝","name":"白拍子の衣装","rank":"4","desc":"男装の舞衣装。白拍子（しらびょうし）とは平安時代末期に起こった歌舞、または舞い手のこと。歌いながら舞う。女性が舞うことが多かったが、男性の舞い手も存在した。","note":"麗人の舞","exp":"650"}],"3418":[{"type":"財宝","name":"ソネット集","rank":"4","desc":"シェークスピアが発表した154編からなる詩集。ソネット形式で書かれている。主なテーマはさまざまな恋愛観と人間の美、そして死についてである。\nソネットとは14行で形成される定型詩で、12世紀初頭のイタリアで確立された。","note":"妙なる調べ","exp":"700"}],"6702":[{"type":"大型生物","name":"ユキヒョウ","rank":"5","desc":"中央アジアの高山地帯に生息するヒョウ。灰色に黒い斑紋の体毛が特徴。1ｍ程長い尻尾を持つため、足場の悪い山岳でもバランスがとりやすい。人が寄り付かない高山で行動するため、民間伝承や信仰では、神秘的な生物とされている。","note":"追究クエスト「アムールヒョウの追加調査」<br/>発見物カード:650","exp":"1300"}],"3161":[{"type":"地理","name":"アバロン半島","rank":"2","desc":"テラ・ノヴァ島の南東にある半島。地形が複雑であり、いくつもの湾が存在している。\n漁場としても優れている。","note":"書きかけの地図","exp":"220"}],"1193":[{"type":"大型生物","name":"カイマン","rank":"4","desc":"カイマンとは現地の言葉で「ワニ」を指す。主に淡水に生息する。両眼の間に盛り上がる筋があり、眼鏡をかけているように見える。水中で獲物を巧みに追い込む狩りをする。","note":"アマゾン川に潜むもの","exp":"624"}],"5792":[{"type":"宗教遺物","name":"聖エウフェミアの棺","rank":"5","desc":"聖エウフェミアの遺体が収められた棺。彼女は過酷な拷問にかけられたが、最期まで信仰を捨てず、自らの苦難と殉教を神に祈ったと伝えられている。","note":"聖女の遺体","exp":"1410"}],"3178":[{"type":"財宝","name":"グリーンランド人のサガ","rank":"4","desc":"エイリーク達のグリーンランド入植と、その子ども達やソルフィンの西方探索を描いた物語。赤毛のエイリークのサガを元にした部分が見られる。赤毛のエイリークのサガに比べて、やや誇張が多い点が大きな違いである。","note":"語りの地、その手がかり","exp":"780"}],"1719":[{"type":"海洋生物","name":"アカマンボウ","rank":"2","desc":"熱帯、温帯の海に広く分布する。2mを超える円盤形の大きな体をしている。","note":"釣り","exp":"250"}],"194":[{"type":"美術品","name":"岩窟の聖母（真筆）","rank":"5","desc":"読みは「がんくつのせいぼ」。レオナルド・ダ・ヴィンチ作の絵画である。ミラノのある聖堂の依頼で描かれた物だが、報酬で折り合わず、このオリジナルは渡されなかったという。絵には聖母子と聖ヨハネ、天使が描かれている。","note":"ダ・ヴィンチの真筆","exp":"1105"}],"2810":[{"type":"財宝","name":"神農本草経","rank":"2","desc":"後漢のころ編さんされたと思われる、個々の薬の効果について記した薬物学書。300種以上の薬物が効能によって分類されている。\n神農とは、古代の伝説の人物で農耕と医学の祖であると伝わる。","note":"古書の地図","exp":"210"}],"5020":[{"type":"港・集落","name":"アレクサンドリア","rank":"1","desc":"アレクサンドロス大王が各地に作った都市、「アレクサンドリア」の一つ。地中海とアラビアの貿易中継地点として、栄えている。ナイル沿岸の肥沃な土壌で育った農産物と、アラビア経由の香辛料や香料が扱われている。","note":"到達する","exp":"49"}],"5632":[{"type":"気象・現象","name":"穴あき雲","rank":"4","desc":"薄く広がり、中央部が円形に開いた雲。開いた部分には垂れ下がるように別の雲が形成されることもある。","note":"東ベーリング海","exp":"660"}],"6971":[{"type":"植物","name":"オオベニウチワ","rank":"5","desc":"南米大陸の熱帯雨林に自生する植物。ハート型の花びらに見える部分は、苞（ほう）と呼ばれる葉が進化したもので、中心の棒状の部分が花である。色鮮やかでさまざまな種類が存在するが、有毒のため注意が必要だ。","note":"発見物カード:660","exp":"1320"}],"5575":[{"type":"財宝","name":"ガンバン","rank":"1","desc":"インドネシア地方の打楽器。橋名板の上にさまざまな大きさの木や竹を並べ、叩いて旋律を奏でる。","note":"","exp":"190"}],"1701":[{"type":"宗教遺物","name":"ゴリアテの剣","rank":"5","desc":"ゴリアテとは、旧約聖書に登場する、ペリシテ人の戦士。ペリシテ人がイスラエル王国を攻めたとき、羊飼いの少年・ダヴィデが石を投げてゴリアテを倒しこの剣を奪ってゴリアテにとどめを刺したという。","note":"未来を守る力","exp":"1183"}],"3749":[{"type":"天文","name":"おとめ座","rank":"4","desc":"黄道十二星座の1つ。正義の女神アストライア、春の女神ペルセポネ、豊穣の女神デメテルなど、さまざまな女神になぞらえられている。古代メソポタミアでは、麦穂とナツメヤシの葉を持つ2人の女性だといわれている。","note":"黄道の女神","exp":"650"}],"6607":[{"type":"美術品","name":"ポートランドの壺","rank":"5","desc":"古代ローマ帝国の時代に作られたカメオ・ガラスの壺。紺碧色の地の上に、白いガラスで天使などの人物が彫られている。古代のガラス細工の中でも、最も有名で代表的なもの。","note":"","exp":"1150"}],"2745":[{"type":"美術品","name":"姜希顔の水墨画","rank":"1","desc":"朝鮮出身の画家・姜希顔による水墨画。\n明に遊学して絵画を研究した姜希顔は、特に竹の描画に優れており高く評価された。\n山水、草花、肖像の妙手である。","note":"幽玄な水墨画の地図<br/><br/>発見時経験値170　発見物カード経験値85","exp":"170"}],"5571":[{"type":"天文","name":"じょうぎ座","rank":"3","desc":"ラカーユが制定した南天の星座のひとつ。製図で用いる直定規と指矩（さしがね）をかたどっている。","note":"マダガスカル沖で発見　18世紀第3期<br/><br/>発見物カード:255","exp":"510"}],"4970":[{"type":"史跡","name":"エピダウロス遺跡","rank":"5","desc":"ペロポネソス半島東部にある遺跡。ギリシャ神話の医療の神アスクレピオスの聖地といわれている。神殿の他に劇場や宿泊所、浴場の跡が残っている。中でも劇場は円形ステージを階段状の観覧席で囲んでおり、収容人数は1万人を超える。","note":"","exp":"1060"}],"1204":[{"type":"海洋生物","name":"オタリア","rank":"3","desc":"大型のアシカのような海獣。オスには、たてがみ状の毛が生えていて、体重はメスの2倍にもなる。","note":"巨大海獣<br/><br/>発見時経験値506　発見物カード経験値253","exp":"506"}],"2139":[{"type":"大型生物","name":"ナイルオオトカゲ","rank":"2","desc":"トカゲのような生物だが、体長がヒトより大きい個体も存在する。どうやら肉食らしく、ワニの卵や幼生すらも食べてしまうという。名前にナイルとあるがナイル川周辺以外でも目撃情報が寄せられている。","note":"［勅命］[[運河開通場所に潜むもの","exp":"310"}],"2406":[{"type":"植物","name":"ジョウモンスギ","rank":"4","desc":"屋久島にある巨大な樹木。30m余りの高さまで伸びており、幹周りは16mにも及ぶ。\n太くうねった幹が、強い生命力を物語っている。","note":"屋久島にある魅力","exp":"660"}],"4867":[{"type":"天文","name":"りゅう座","rank":"2","desc":"ギリシャ神話に登場する竜が天に上ったとされる星座。この星座のいわれについては、黄金のリンゴを守るラドンのことを指すという説の他、さまざまな説がある。","note":"クエスト「親子の間に横たわるもの」<br/>発見物カード:170","exp":"340"}],"22":[{"type":"化石","name":"角のないドラゴンの骨","rank":"1","desc":"非常に大きな動物の骨の形をした石。足が4本あり体が大きく首と尾が長く、まさに伝説のドラゴンといった姿なのだが、角と翼がない。伝説のドラゴンは誇張された姿で、これが本当の姿なのだろうか。","note":"アフリカのドラゴン","exp":"110"}],"958":[{"type":"地理","name":"セイロン島","rank":"2","desc":"インドの南に浮かぶ、比較的大きな島。赤道に近く熱帯に属する。高地が多く、茶の栽培が盛んだ。また、宝石の鉱脈が非常に多い島でもある。","note":"宝石の島","exp":"270"}],"1876":[{"type":"歴史遺物","name":"黄金の胸当て","rank":"1","desc":"カルタゴ軍がローマ軍との戦いで戦利品として得たと思われる胸当て。当時のローマ兵は精鋭でも青銅の武具しか与えられなかったので、さぞかし位の高い人物が身に着けたものだろう。","note":"古代の防具の地図","exp":"140"}],"5010":[{"type":"財宝","name":"アレキサンドライトキャッツアイ","rank":"2","desc":"希少な宝石。中央に光の筋が入ったアレキサンドライト。ダイヤモンドより高価とされる場合がある。","note":"コーカサス地方再調査","exp":""}],"1282":[{"type":"歴史遺物","name":"押し型","rank":"2","desc":"土器でできた、紋様をつけるための押し型。多くの紋様がデザインされたようだ。","note":"浮き彫りの石","exp":"280"}],"642":[{"type":"地理","name":"アンダマン諸島","rank":"1","desc":"ベンガル湾東部に浮かぶ島々。おおよそ線上に並んでいる。島には先住民がいる。彼らは身長が140cmくらいで狩猟・採集生活を送っているようだが、他民族との接触を避けるため、くわしいことは不明。","note":"書きかけの地図","exp":"175"}],"5546":[{"type":"海洋生物","name":"レッドリップトバットフィッシュ","rank":"2","desc":"ガラパゴス諸島付近に生息する魚。海底を歩くように泳ぐ。真っ赤な唇のような口が名前の由来である。","note":"","exp":"280"}],"5457":[{"type":"海洋生物","name":"ヨツメウオ","rank":"2","desc":"アマゾン川付近の、海水と淡水が混じり合う河口付近に群れで生息する魚。目の上半分を水面上に出して泳ぐという特徴がある。","note":"発見時経験値250　発見物カード経験値125","exp":"250"}],"519":[{"type":"宗教遺物","name":"古代の祭壇","rank":"1","desc":"祭祀を行うための台。文明や宗教によってさまざまなものがある。","note":"古代の祭祀場の地図","exp":"53"}],"3783":[{"type":"天文","name":"明けの明星","rank":"1","desc":"夜明け前に東の空に明るく輝く惑星。古代ギリシャ語ではポスポロス、ラテン語ではルシフェルと呼ばれた。仏教説話でも悟りを開く際に明けの明星が登場することがある。","note":"視認","exp":"150"}],"918":[{"type":"歴史遺物","name":"ガンジナーメの碑文","rank":"2","desc":"「ひぶん」。山の岩肌に刻まれた碑文。二つあり、一つはダレイオス1世のもの、もう一つは息子のクセルクセス1世のものである。","note":"繁栄の証","exp":"210"}],"924":[{"type":"財宝","name":"アラバスターの花瓶","rank":"1","desc":"アラバスターを削りだして作った花瓶。アラバスターには透明感があるので、独特の美しさがある。","note":"美しいつぼの地図","exp":"34"}],"228":[{"type":"財宝","name":"イリアス","rank":"1","desc":"ホメロス作の叙事詩。ギリシャ神話のトロイ戦争を題材とし、勇者アキレウスを中心に描かれる。イリアスとは「イリオスの物語」という意味である。イリオスとは、トロイの別名。","note":"トロイ戦争の物語","exp":"60"}],"2739":[{"type":"財宝","name":"経国大典","rank":"2","desc":"朝鮮王朝の政治の規範となっている法典。\n政治の他、経済、文化軍事など、各方面の規制が記されているという。過去に何度か改定が加えられた。","note":"朝鮮王朝政治の基準","exp":"380"}],"6206":[{"type":"財宝","name":"カルタ・マリナ","rank":"4","desc":"16世紀のスウェーデン人司教、オラウス・マグヌスが作成した北欧の海図。各地の地形が詳細に描かれ、図中のところどころに珍しい生物や怪物も描かれている。古今東西の書物や、船乗りたちから丹念に聞き出した話をもとに作成したらしい。","note":"","exp":"630"}],"19":[{"type":"大型生物","name":"アフリカゾウ","rank":"3","desc":"アフリカのサバンナ地帯で広く見られるゾウである。アフリカでは最大の生物だろう。古代都市のカルタゴでは象兵がいたといわれるが、このゾウが使役されていたのだろうか。","note":"アフリカゾウの探索","exp":"462"}],"112":[{"type":"海洋生物","name":"マナティー","rank":"4","desc":"海に住む大型の動物。アザラシのように陸に上がることはない。泳ぎが遅く警戒心も弱いのは、敵の少ない海域で海草などを食べているからだろう。海面で子に乳を与える姿が人魚と間違われたり、怪物のセイレーンと間違われたりした。","note":"カリブ海の人魚","exp":"708"}],"3228":[{"type":"歴史遺物","name":"古代の糸巻き","rank":"3","desc":"ランス・オ・メドーの居住跡で見つかった糸巻き。作りが古欧風であることから、ヴァイキングが持ち込み、ここで生活を営んでいたことがわかる。","note":"ヴァイキングの生活","exp":"470"}],"1658":[{"type":"地理","name":"ジャワ海","rank":"1","desc":"ジャワ島とカリマンタン島の間に広がる海。遠浅でよい漁場なため多くの地元漁船が航行する。ジャワ海に浮かぶ小島は全体的に低地で、塩田が数多く見られる。","note":"書きかけの地図","exp":"110"}],"547":[{"type":"歴史遺物","name":"円筒印章","rank":"1","desc":"古代メソポタミア近辺で使われていた、円筒形の印章。粘土板の上を転がして押印する。","note":"古代ペルシャの印章の地図","exp":"67"}],"1846":[{"type":"宗教遺物","name":"イラ","rank":"1","desc":"コノパと同じく、神への生贄になった動物の偶像である。コノパよりも小さく、簡略化されている。多くは白い石でできており、細かい装飾はないが愛らしい。こういった家畜がいかに身近であったかがうかがえる。","note":"「彫像の地図」<br/>発見物カード:75","exp":"150"}],"7006":[{"type":"宗教建築","name":"ワット・シーチュム","rank":"4","desc":"スコータイ時代に建立されたと伝わる寺院。かつて菩提樹に囲まれていたことから、この名がついた。礼拝堂には「不変なもの」という意味を持つ巨大な座像「プラ・アチャナ」が祀られている。","note":"カード経験値：340","exp":"680"}],"1450":[{"type":"大型生物","name":"オオアリクイ","rank":"5","desc":"歯を持たず、非常に長い舌と、大きく鋭い爪を使って、アリ塚に生息するアリを食べる。休憩のときには、ふさふさした大きな尾を保温のために使用する。","note":"アリ食いの親玉","exp":"828"}],"1309":[{"type":"地理","name":"ココ川","rank":"1","desc":"ユカタン半島の南の半島に流れる川。コロン提督がこの地に至った際も、この川の河口から上陸したという。","note":"書きかけの地図","exp":"140"}],"3298":[{"type":"地理","name":"メサ","rank":"4","desc":"テーブルのような形状の台地。北米の西部に多い。柔らかい地層の上に、水平な硬い地層がある場合、下部の柔らかい地層のみが浸食されて、テーブル状になったとみられる。","note":"研究員への助力","exp":"610"}],"6170":[{"type":"宗教遺物","name":"聖ゲオルギイのイコン","rank":"3","desc":"聖ゲオルギイこと、竜退治の伝承で名高い聖ゲオルギウスを描いたイコン。東ヨーロッパの俗信では、狼たちが毎年捕らえることができる家畜の数を定めるという。そのため、羊と狼の守護者として崇敬されることもあるようだ。","note":"","exp":"600"}],"5106":[{"type":"港・集落","name":"ナポリ","rank":"1","desc":"紀元前、ギリシャ人によって築かれた歴史ある街。かつては「新しい街」を意味するネアポリスと呼ばれた。今も、地中海の中央部に位置するため地中海交易の重要な拠点である大都市だ。","note":"到達する","exp":"28"}],"191":[{"type":"地理","name":"セネガル川","rank":"2","desc":"アフリカ西部から大西洋に注がれる大河。乾燥地帯において豊富な水をたたえるこの河の名の由来は、ベルベル語で「川」を意味する「サナージャ」、あるいはウォロフ語で「私の舟」を意味する「スヌガル」だと言われている。","note":"その文字が示すもの","exp":"210"}],"1314":[{"type":"宗教遺物","name":"聖母のステンドグラス","rank":"1","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40"}],"724":[{"type":"中型生物","name":"シファカ","rank":"2","desc":"後ろ足で跳ねるように地上を移動する。その姿は踊っているようにも見える。脚力が優れており、樹木のあいだを約10メートルも跳びこえる。おもに昼間に活動をする。","note":"精霊の舞い","exp":"360"}],"6989":[{"type":"財宝","name":"医心方の写本","rank":"5","desc":"全三十巻からなる日本最古の医学書の写本。読み方は「いしんぽう」。原本は平安時代に朝廷の典薬頭を務めた医師、丹波康頼により編纂された。唐以前の医学書の引用を主として構成されており、史料としての価値も非常に高い。","note":"","exp":""}],"583":[{"type":"財宝","name":"壊れたブローチ","rank":"1","desc":"壊れているブローチ。宝石のいくつかがはずれ、留め金も壊れている。壊れる前はさぞかし素晴らしい物だったのだろう。","note":"豪華な宝石細工の地図","exp":"18"}],"302":[{"type":"地理","name":"カイマン諸島","rank":"2","desc":"カリブ海のキューバ島南方に位置する諸島。発見当初はトルトゥーガ島（カメの意味）とも呼ばれた。ほとんどがサンゴ礁からなる、美しい島々である。","note":"サンゴの海","exp":"360"}],"559":[{"type":"歴史遺物","name":"コート・ディジーの魚鱗彩文土器","rank":"2","desc":"「ぎょりんさいもんどき」。インダス川下流に広がる遺跡から出土する、魚鱗模様の彩文土器。インダス文明のさきがけとも言える。","note":"古代人の生活","exp":"290"}],"6194":[{"type":"伝承","name":"アレクサンドリア大灯台","rank":"5","desc":"プトレマイオス1世の時代にエジプトのアレクサンドリアに建造された灯台。ファロス島の大灯台とも呼ばれ、ギザの大ピラミッドに次ぐほどの高さを誇ったが数度の地震によって倒壊した。","note":"伝承航路","exp":"1660"}],"6949":[{"type":"海洋生物","name":"ライオンタテガミクラゲ","rank":"4","desc":"ライオンのたてがみのように見える触手を持つ大型のクラゲ。冷たい海に生息するものは傘の直径が2m、全長は30mを越えることもある。長い触手は粘着性で千本近くあり、海を漂うその姿から、別名キタユウレイクラゲとも呼ばれる。","note":"発見物カード:350","exp":"700"}],"1834":[{"type":"財宝","name":"マムルークのカトラス","rank":"1","desc":"カトラスとは、やや刀身が背のほうに湾曲した刀剣。小型で扱いやすく、海賊が好んで使用したことでも有名。槍術や弓術を主にしていたマムルーク騎兵も使用していたという。","note":"曲がった武器の地図","exp":"100"}],"6429":[{"type":"虫類","name":"コノハムシの卵","rank":"5","desc":"外見が植物の葉に似ているコノハムシのメスから産み落とされる卵は、親の外見と同様に植物の種に非常によく似ており、知らなければ一見してこれが卵とは気づけない。周囲に溶け込み生存していくために得た姿なのだろう。","note":"","exp":""}],"6731":[{"type":"財宝","name":"ダヴィデのハープ","rank":"5","desc":"ダヴィデとは旧約聖書に登場する古代イスラエルの王。少年のダヴィデはこのハープを弾き、悪霊に取りつかれた先王サウルを癒したという。","note":"楽の叡智・心に響く楽器　上","exp":""}],"2103":[{"type":"歴史遺物","name":"ティソナ","rank":"5","desc":"「我がシードの歌」では、金1000マルコの価値があるとされる名剣で、モロッコのブカル将軍を討ちとって獲得した。燃える剣という意味を持つ。","note":"連鎖する好奇心<br/><br/>発見時経験値1060　発見物カード経験値530","exp":"1060"}],"1670":[{"type":"植物","name":"モウセンゴケ","rank":"1","desc":"温暖な湿原に生息する植物。葉から生えた無数の毛から粘液を分泌する。粘液に虫が引っかかると、葉はゆっくりと収縮し、虫をくるんでしまう。こうして葉に捕らえられた虫は次第に溶けてなくなってしまう。","note":"虫を捕まえる植物の地図","exp":"75"}],"1419":[{"type":"宗教遺物","name":"トラロック像","rank":"2","desc":"メソアメリカの神話における古い神で、雨を司っている。トラロックが構える死後の世界は永遠の楽園で、天災や不慮の事故・伝染病などで死んだものだけが行けるという。","note":"雨の神","exp":"350"}],"2788":[{"type":"宗教建築","name":"楽山大仏","rank":"5","desc":"四川の山の西壁に彫られた、高さ70mほどの石刻座仏。治水と航行の安全を祈願して作られた。\n完成当初は、全身が金色で彩られていたという。","note":"華南の大仏","exp":"1080"}],"6151":[{"type":"財宝","name":"メリッサの船首像","rank":"4","desc":"かつて沈没したポルトガル王族船の船首像。ジョゼの父親が贖罪の念と祈りを込めて造った。「この船を造る私に罰を。この船に乗る者に救いを。そして、我が娘に幸いを。守りたまえ、メリッサ──我が妻よ」という文字が刻まれている。","note":"クエスト「祈りと贖罪」<br/>発見物カード:400","exp":"800"}],"2619":[{"type":"宗教遺物","name":"中壇元帥の銅像","rank":"2","desc":"読みは「ちゅうだんげんすいのどうぞう」。道教で崇められている少年神の像。台北に納められていた。\n中壇元帥はナタ太子とも呼ばれ、魔力を秘めた布や、火を放つ槍を持って戦う姿で表されている。","note":"道教の少年像の地図","exp":"300"}],"192":[{"type":"美術品","name":"モナリザ","rank":"5","desc":"レオナルド・ダ・ヴィンチ作の絵画。不思議な微笑、衣服の上品な質感、空気遠近法による背景、なにより、まるで血が通っているかのような肌。まさに理想の肖像画といえる。","note":"ダ・ヴィンチ＝コード","exp":"1183"}],"5131":[{"type":"港・集落","name":"ブエノスアイレス","rank":"2","desc":"街名は「良い空気」の意味。南米東岸、広大で肥沃な平原の広がるラプラタ川河口に位置する街。四季を持つ。ウィチ人が暮らしている。","note":"到達する","exp":"269"}],"1256":[{"type":"地理","name":"セバルド島","rank":"4","desc":"近年、その存在が確認された島。気候は冷涼で、樹木はほとんど見られない。海岸線は複雑で、周囲には無数の小島が点在している。","note":"地図にない島","exp":"780"}],"2244":[{"type":"中型生物","name":"ウミイグアナ","rank":"2","desc":"海で生活する、大型の珍しいトカゲ。背中にトゲ状の鱗がトサカのように生えており、岩のようにごつごつした黒っぽい皮膚をしている。長くて平らな尾を巧みに動かして泳ぎ、海藻を食べる。海岸で群れをなして日光浴をする姿が見られる。","note":"海に棲まうトカゲ","exp":"370"}],"1174":[{"type":"財宝","name":"レスカトールの手記","rank":"5","desc":"「ミカエラ、僕は明日妹の元へ行く。僕はもう逃げないつもりだ。…ミカエラ。君ももう逃げないで。これからの君を彩るのはカリブの大地と翠玉色の海。もう僕のギターがなくても、君は一人で踊っていけるよ」手記はそこで終わっている。","note":"君に贈るレトラ<br/><br/>発見時経験値1170　発見物カード経験値585","exp":"1170"}],"3802":[{"type":"財宝","name":"ある船乗りの漂流記","rank":"4","desc":"スコットランド出身の航海長であるアレキサンダー・セルカークの無人島生活についての著述。自給自足の生活の様子が生々しく記されている。","note":"海洋冒険物語のネタ<br/><br/>発見時経験値680　発見物カード経験値340","exp":"680"}],"4797":[{"type":"地理","name":"マウナ・ケア","rank":"1","desc":"ハワイ島の北部にある山。ハワイ諸島で最も高く、常夏の島にありながら、冬には冠雪する。非常に巨大な山体が特徴。","note":"書きかけの地図","exp":"140"}],"2904":[{"type":"地理","name":"泰山","rank":"4","desc":"宗教の中心として崇められてきた山。\n秦の始皇帝以来、歴代の皇帝が、国家統一を天に報告する「封禅の儀」を行う場所で、山全体に祠や廟が点在する。","note":"儀式を行う名山","exp":"680"}],"2812":[{"type":"財宝","name":"獅子舞","rank":"3","desc":"楽に合わせ、獅子に扮して舞い踊る、伝統的な民間芸能。\n唐代に広く発展し、現在では新年を迎える日などに人前で披露される。","note":"祭に関する疑問","exp":"480"}],"3179":[{"type":"財宝","name":"メディチ家の秘薬","rank":"5","desc":"薬の商売を行っていたメディチ家秘蔵の薬。服用すれば、たちまち体調がよくなるという噂がある。","note":"メディチ家の薬","exp":"940"}],"4864":[{"type":"中型生物","name":"サルーキ","rank":"5","desc":"イラクのテペ・ガウラにも彫刻が残されている世界最古の犬種のひとつ。すさりとした美しい肢体とスピードを追求して改良繁殖された狩猟犬でおる。最も速く走れる犬だという話もある。","note":"最高の犬","exp":"1010"}],"2888":[{"type":"虫類","name":"アオマツムシ","rank":"2","desc":"中国南部に生息している虫。一生のうち一度も地上に降りないといわれる。\n樹木の葉の上や飛んでいるところをよく見かける。","note":"緑色の虫の地図","exp":"250"}],"2320":[{"type":"地理","name":"高野山","rank":"2","desc":"紀伊山地を形成する、山々の一つ。\n平安時代、空海が修行したとされる。「山」と呼ばれるが、山そのものの名ではないとのこと。\n日本仏教における聖地とされ、現在も修行のために多くの僧侶が訪れるらしい。","note":"僧侶の行方","exp":"330"}],"3268":[{"type":"植物","name":"カエンボク","rank":"2","desc":"西アフリカでよく見られる花木。赤い花がまるで炎のように見え、非常に華やかなため目を惹く。樹高は10mを超える。","note":"炎を咲かす樹木<br/><br/>発見時経験値390　発見物カード経験値195","exp":"390"}],"1250":[{"type":"歴史遺物","name":"貝の絵文字","rank":"2","desc":"貝に彫られた絵文字。なにを表しているのかはわからないが、非常に高度な技術で、美的感覚に長じていることがうかがえる。","note":"不思議な貝殻","exp":"210"}],"5133":[{"type":"港・集落","name":"ブレーメン","rank":"1","desc":"ヴェーゼル川河口に位置する港湾都市。9世紀に大司教座の街として興った。14世紀ごろにはハンザ同盟都市となり、商業都市として繁栄した。","note":"到達する","exp":"13"}],"318":[{"type":"史跡","name":"クノッソス宮殿","rank":"4","desc":"古代クレタ文明の遺跡である。ギリシャ神話に登場する、ミノス王の居城跡。この宮殿の奥には、ミノタウロスがいたという迷宮「ラビュリントス」があったと伝えられる。","note":"ラビュリントスの伝説","exp":"708"}],"2046":[{"type":"地理","name":"レバノン山脈","rank":"2","desc":"ベイルート付近の山。雪が積もるため、アラム語で「白」を表すラバンからレバノンと名づけられた。\nかつては、レバノン杉がたくさん自生していたが、古代エジプトのピラミッド製造のため大量に伐採された。","note":"レバノンの山岳","exp":"300"}],"1671":[{"type":"地理","name":"ビスマーク諸島","rank":"1","desc":"ニューギニア島の北東沖にある諸島。最大の島は、諸島の南部から東部にかけて横たわるニューブリテン島である。島々の多くは火山島であり、噴火による被害も少なくない。","note":"書きかけの地図","exp":"140"}],"6873":[{"type":"中型生物","name":"シマダイカー","rank":"3","desc":"アフリカに生息する、草食動物の一種。子鹿によく似た姿だが、ウ\nシ科に属する。体高は50cm程度。腰には黒い横縞が数多く入ってお\nり、オスメス共に耳の付け根に小さな角が生えている。","note":"","exp":""}],"636":[{"type":"美術品","name":"人間を守るキリストの犠牲","rank":"1","desc":"フランス・フロリス作の宗教画。非現実的な象徴を集めた、不思議な構成になっている。フランドル地方の画家らしく、プロテスタント寄りの内容になっている。","note":"宗教画の新しい流れ","exp":"60"}],"2261":[{"type":"地理","name":"マルキーズ諸島","rank":"5","desc":"タヒチ島から約1500km北東の海域に位置する南太平洋の諸島。\n先住民の言葉で諸島の名前を、テ・ヘヌア・エナナという。","note":"遥かなるハワイキ","exp":"1070"}],"6717":[{"type":"鳥類","name":"コクマルガラス","rank":"2","desc":"東アジアに広く分布するカラス。小柄で、全長は約33cm。毛色の色は黒に限らず、首周りから腹にかけてが白い個体も多い。越冬のために長距離を移動する渡り鳥である。","note":"追究クエスト　発見物カード:115","exp":"230"}],"1894":[{"type":"歴史遺物","name":"サンベント号","rank":"2","desc":"ポルトガルの東インド貿易船。\nアフリカ南東岸沖ペドロ・ドス・パルコスの岩礁付近で沈没した。","note":"サルベージ","exp":"260"}],"5066":[{"type":"港・集落","name":"サンフアン","rank":"2","desc":"カリブ海の東部にある街。比較的新しい街だが、ヨーロッパとの交易の窓口に当たる位置なので栄えている。サトウキビのほか、カリブ特有の農作物やサンゴが流通している。","note":"到達する","exp":"236"}],"5897":[{"type":"植物","name":"ギンピ・ギンピ","rank":"5","desc":"オーストラリアなどに分布する有毒植物。高さはおおよそ1mほど。植物全体が細かな刺毛に覆われており、素肌に触れると激しい痛みを伴う。最悪の場合、痛みが数年続くこともあるという。","note":"","exp":"1400"}],"5503":[{"type":"財宝","name":"古代のセッケン","rank":"4","desc":"動物性の脂肪と灰を混ぜて作られる伝統的なセッケン。柔らかく、独特の臭いがある。","note":"","exp":""}],"5087":[{"type":"港・集落","name":"ソファラ","rank":"1","desc":"東アフリカ南東部に位置する街。付近の交易の中心地である。大河に接しているため、農業が盛んである。また近郊の山地から産出する金と木材が流通している。","note":"到達する","exp":"78"}],"569":[{"type":"歴史遺物","name":"デメトリオス1世の鎧","rank":"2","desc":"デメトリオス1世は、アレクサンドロス大王の後継者の一人アンティゴノス1世の息子。大王亡き後、分割された領土を再統一しようとするが、捕らわれて死んだ。","note":"後継者争い","exp":"350"}],"1967":[{"type":"財宝","name":"銀の首切師の装飾","rank":"3","desc":"半円の形をした、銀の合金でできた副葬品。振ると円の縁についた玉が音を立てる。音を使った祭事に使われていたのだろうか。","note":"儀式の象徴<br/><br/>発見時経験値530　発見物カード経験値265","exp":"530"}],"2090":[{"type":"地理","name":"ベンゲラ海流","rank":"3","desc":"アフリカ西岸を北上する寒流。\nこの海域は魚が育ちやすく、豊富に獲れるようだ。潮の流れに秘密があるのだろうか。","note":"隠しメニューの秘訣","exp":"510"}],"6810":[{"type":"虫類","name":"クロゴケグモ","rank":"5","desc":"北米に生息するクモの一種。全身が黒く、丸く膨らんだ腹にはメスのみ砂時計の形をした赤い模様がある。メスが交尾後にオスを食べることから、黒い未亡人を意味する「ブラックウィドウ」と呼ばれる。強い毒を持つが攻撃性は低い。","note":"発見物カード:440","exp":"880"}],"1360":[{"type":"財宝","name":"マニックブルン","rank":"5","desc":"今から200年ほど前に作られたといわれているトンボ玉。非常に状態がよい。片面に鳥が浮かび上がり、その裏には、太陽光を表す模様が浮かび上がっている。深い群青色に柔らかな乳白色が映える、逸品である。","note":"鳥と太陽の宝玉","exp":"936"}],"6964":[{"type":"地理","name":"ルシェルシュ諸島","rank":"2","desc":"オーストラリア南西に位置する諸島。約100の島と1000を超える小島からなる。島の原始林や美しい海には、地域固有の生物も多く、さまざまな種を観察できる。","note":"発見物カード:140","exp":"280"}],"2825":[{"type":"宗教遺物","name":"武則天の偽経","rank":"3","desc":"仏典中の「大雲経」に武則天らが手を加えて創作した偽経。\n女帝出現を預言する内容を含ませたことで、自ら皇帝の地位を得る足掛かりとした。","note":"ダンジョン","exp":"480"}],"2976":[{"type":"海洋生物","name":"ダイオウグソクムシ","rank":"5","desc":"大西洋の海底に棲む巨大甲殻類。体長は最大で50cmにもなり、体重は1kgを超える。背面を海底に向けながら体をくねらせて泳ぐ。","note":"虫か、魚か<br/><br/>発見時経験値1130　発見物カード経験値565","exp":"1130"}],"1280":[{"type":"歴史遺物","name":"ナレースワン王の像","rank":"2","desc":"アユタヤ王朝21代目の王。幼少期はミャンマーで人質として育ったが、ミャンマーがアユタヤを掌握しナレースワンの父が形式的な王となると、ナレースワンの姉と引き換えに呼び戻された。その後アユタヤの軍隊を鍛え、独立へと尽力した。","note":"生きた伝説","exp":"330"}],"4973":[{"type":"天文","name":"いるか座","rank":"2","desc":"船乗りに殺されかけた吟遊詩人アリオンを助けたイルカが天に上った姿とされる星座。アリオンはシチリア島の音楽祭で優勝し、帰路に賞品を狙う船乗りに襲われた。","note":"クエスト「古代ギリシャの吟遊詩人」<br/>発見物カード:135","exp":"270"}],"3637":[{"type":"地理","name":"ノールカップ岬","rank":"2","desc":"スカンジナビア半島の北に浮かぶ小島の岬。断崖絶壁だが、上からの眺めは絶景だ。","note":"書きかけの地図","exp":"330"}],"1548":[{"type":"地理","name":"モーニントン島","rank":"1","desc":"オーストラリア北東部に存在するカーペンタリア湾最南奥の島。さらにその南部はいくつもの中型河川の河口を持ち、よい漁場となっている。","note":"書きかけの地図","exp":"160"}],"461":[{"type":"財宝","name":"銀細工の甲冑","rank":"1","desc":"地金に銀で装飾を施した甲冑。銀は強度がないが、邪を退ける力があると考えられているので、祭礼などで使われたものではないかと考えられる。","note":"銀細工の甲冑の地図","exp":"66"}],"769":[{"type":"植物","name":"熱帯スイレン","rank":"1","desc":"熱帯地方だけで生育するスイレン。鮮やかな色とりどりの花を咲かせる。観賞用に持ち帰りたいが、気温が低いとすぐ枯れてしまうという。","note":"赤道直下で咲く花","exp":"150"}],"5541":[{"type":"気象・現象","name":"夜光雲","rank":"2","desc":"日没後にのみ観測される、雲が青白く見える現象。地平線下にある太陽の光が雲に当たって発生すると思われるが、詳細な原因は不明である。","note":"","exp":"185"}],"6677":[{"type":"天文","name":"アルフェラッツ","rank":"4","desc":"アンドロメダ座で最も明るい星。名はアラビア語で「馬」を意味する。別名であるシラーは「へそ」を意味し、かつてペガスス座に属し、ペガサスの腹部であったことに由来している。","note":"発見物カード:320","exp":"640"}],"88":[{"type":"宗教遺物","name":"イシス像","rank":"1","desc":"エジプトの、豊穣と母性の女神の像。地母神ともされる。兄であるオシリスの妻であり、天空神・ホルスを産んだ。オシリスがセトに殺されると、ホルスを助けてセトを倒した。","note":"エジプトの女神","exp":"110"}],"3876":[{"type":"財宝","name":"ヤンキードゥードゥルの詞","rank":"2","desc":"アメリカ独立戦争時に北米で流行した民謡の詞が記された手記。\n替え歌が多く存在し、その詞が持つ意味もさまざまである。","note":"北米の歌","exp":"240"}],"6623":[{"type":"海洋生物","name":"ガラ・ルファ","rank":"5","desc":"通称「ドクターフィッシュ」。西アジアの河川に分布する。比較的高水温にも耐えられるため温泉にも生息している。ヒトの皮膚の角質を食べる習性があり、歯を持たないため、肌を傷つけない自然ピーリングに使われる。","note":"","exp":"830"}],"6545":[{"type":"歴史遺物","name":"アレクサンドリア大図書館の蔵書","rank":"5","desc":"古代世界で最大の知の集積地、アレクサンドリア大図書館が所蔵していたとされる巻物。大図書館ではアレクサンドリアに寄港した船の書物をすべて提出させ、写本のほうを返したという。こうして収集した書物は何十万巻に及んだと伝わる。","note":"","exp":""}],"1994":[{"type":"海洋生物","name":"ブラックアロワナ","rank":"2","desc":"稚魚は黒い魚体だが、成魚は美しい銀色をしている。オレンジ模様のヒレを持つ。","note":"釣り","exp":"260"}],"6666":[{"type":"気象・現象","name":"波状雲","rank":"","desc":"雲が波状になる現象。\n大気の波が雲を動かすことによって発生する。温暖前線、低気圧の接近時によく見られ、天候が崩れる前兆ともいわれている。","note":"1.オーストラリア北西岸　北東の哺乳類の骨の南西付近。<br/><br/>※曇り、昼から夕方に発生<br/>","exp":"300"}],"2039":[{"type":"歴史遺物","name":"メルエンプタハ碑文","rank":"2","desc":"古代エジプトのファラオ、メルエンプタハ王の時代に残されたと思われる碑文。\n損傷が激しく読み辛いが、「シェケン運河」や「エティ運河」と読める部分がある。","note":"［勅命］[[運河開通への記録","exp":"310"}],"1871":[{"type":"宗教遺物","name":"カジャワヤの薬草壷","rank":"5","desc":"カジャワヤとは、アンデスの山間部に住まう呪術師である。その役割は医師、賢人と幅広く、アンデスの人々にとって身近な存在である。カジャワヤの薬草の知識は深く、野山に育つ雑草から、患者に合った薬を処方する。","note":"失われた万能薬","exp":"1120"}],"120":[{"type":"宗教遺物","name":"ヘパイストス像","rank":"1","desc":"ギリシャ神話の火と鍛冶の神の像。醜い姿をしているとされるが、妻はもっとも美しい女神・アフロディテである。彼の鍛冶場はシチリア島の地下にあるとされている。","note":"ギリシャの神像の地図","exp":"60"}],"6813":[{"type":"小型生物","name":"マツテン","rank":"3","desc":"ヨーロッパの森林に生息するテンの一種。全身の毛は濃褐色だが、喉の部分だけ黄色い。夜行性で雑食。主に樹上で活動をするが、地面を速く走ることもできる。木のほらや茂みの中などに巣を作る。","note":"発見物カード経験値:225","exp":""}],"550":[{"type":"史跡","name":"ウル","rank":"2","desc":"古代メソポタミアで、政治と経済の中心地だったと言われるシュメール人の都市。ウル・ナンム王が建造したという、ジッグラトと呼ばれる建造物が大きな特徴。","note":"クエスト「古代メソポタミアの都市」<br/>発見物カード165","exp":"330"}],"1644":[{"type":"地理","name":"ヴァン・ディーメンズ・ランド","rank":"4","desc":"オーストラリア南東部の南にある島。この島を発見したタスマンは当時の東インド会社総督ヴァン・ディーメンにちなみ、この名をつけた。この島でしか見られない動物が多いため、生物学者には垂涎の土地である。","note":"先人の足跡","exp":"612"}],"5837":[{"type":"美術品","name":"アンデスのレタブロ","rank":"5","desc":"アンデス地方で作られる箱型の祭壇。現地の風俗や風景が盛り込まれている。色鮮やかで特徴的なデザインは、美術品として見ても一級品である。","note":"","exp":"1400"}],"3620":[{"type":"歴史遺物","name":"原初年代記","rank":"5","desc":"キエフ大公国の歴史を記した書物。12世紀ごろに年代記者ネストルにより編纂されたとされる。キエフ大公国の成り立ちや宗教について、幅広く記されている。","note":"クエスト「過ぎし年月の物語」<br/>発見物カード:465","exp":"930"}],"754":[{"type":"中型生物","name":"ブルーバック","rank":"2","desc":"アフリカ南部の草原地帯に住むレイヨウ。青灰色の毛並みがとても美しい。角を含めた高さは2mにもなり、レイヨウの中では大型のほうだろう。特異な色の毛皮が珍重されているようで、このままでは絶滅しそうだ。","note":"青い獣の調査","exp":"315"}],"5621":[{"type":"鳥類","name":"エナガ","rank":"2","desc":"ユーラシア大陸に広く分布する鳥の一種。いくつかの亜種が存在する。体長は15cm弱と小柄で体は丸く、首が短くて尾羽は長い。","note":"丸い小鳥","exp":"380"}],"3910":[{"type":"天文","name":"金星の満ち欠け","rank":"1","desc":"金星は月のように満ち欠けするだけでなく、大きさも変わって見える。これは金星が地球の周りではなく、太陽の周りを回っている明確な証拠となった。","note":"地図「金星の観測記録」<br/>発見物カード:85","exp":"170"}],"600":[{"type":"中型生物","name":"フェネックギツネ","rank":"1","desc":"耳が非常に大きい、砂漠に生息する小型のキツネ。臆病で非常に素早く、危険を感じるとあっというまにいなくなってしまう。どうも穴を掘って隠れているようだが、それにしても素早すぎる。","note":"砂漠のキツネ","exp":"80"}],"773":[{"type":"歴史遺物","name":"先史時代の壁画","rank":"1","desc":"先史時代に描かれた壁画。洞窟や古墳内部に見られる。動物や人などを描いたものが多く当時の生活がうかがい知れる。","note":"先史時代の史跡の地図","exp":"140"}],"5398":[{"type":"財宝","name":"セネト","rank":"2","desc":"古代エジプトのボードゲーム。王朝誕生以前から遊ばれており、墓の壁画や副葬品として発見されている。","note":"「古代エジプト遺物の地図」<br/>発見物カード:175","exp":"350"}],"3882":[{"type":"財宝","name":"アナサジフルート","rank":"2","desc":"北米の先住民であるアナサジ民族の縦笛。木製で長さはおよそ70cmあり、六つの穴が開いている。","note":"集落の調査","exp":"370"}],"538":[{"type":"歴史遺物","name":"ガラス状の破片","rank":"4","desc":"モヘンジョ・ダロで発見された、溶けてガラスのようになった陶器の破片。どうやったら陶器がこんな状態になるのだろうか？","note":"古代の謎","exp":"744"}],"649":[{"type":"地理","name":"パイン諸島","rank":"1","desc":"キューバの北の島々。東西に並んでいる。サンゴが美しい遠浅の海で年中暖かい。美しい白い砂浜は、サンゴの骨格が砕けたもののようだ。","note":"書きかけの地図","exp":"180"}],"1568":[{"type":"植物","name":"グレヴィレア","rank":"1","desc":"オーストラリアに生息する常緑樹。葉も花も繊細で、赤や白の花を咲かせる。","note":"繊細な花の地図","exp":"140"}],"336":[{"type":"中型生物","name":"アイアイ","rank":"4","desc":"マダガスカル島にしか生息していないと思われる動物。顔つきや前歯、行動などを見ていると非常に大型のリスだろうと思われる。しかし、手の指はリスとは異なる。独立した種かもしれない…。","note":"暗闇にうごめく影","exp":"696"}],"1586":[{"type":"地理","name":"グレートサンディ砂漠","rank":"3","desc":"オーストラリア北西部に広がる砂漠。オーストラリアの内陸西部は多くが乾燥し、そのほとんどが砂漠である。年間の降水量は少なく塩湖が存在する。","note":"巨岩が屹立する聖地","exp":"484"}],"2975":[{"type":"植物","name":"フロックス","rank":"2","desc":"花弁が鮮やかな花。赤い花はまるで炎のようである。日当たりの良い場所に生息する。","note":"炎の花<br/><br/>発見時経験値270　発見物カード経験値135","exp":"270"}],"2907":[{"type":"海洋生物","name":"ヨウスコウカワイルカ","rank":"2","desc":"長江の下流域に生息するイルカ。濁った川で暮らすためか、目が退化しているようだ。\n別名、長江女神。","note":"長江の女神","exp":"320"}],"2832":[{"type":"歴史遺物","name":"金縷玉衣","rank":"5","desc":"読みは「きんるぎょくい」。前漢時代に作られたと思われる、身分の高い者が着る喪服。四角い玉片を黄金の針金でつづって作られている。これで遺体を覆うと、腐敗を防げると考えられていた。","note":"古代王の埋葬服","exp":"960"}],"2386":[{"type":"虫類","name":"マイマイカブリ","rank":"2","desc":"平地から山地にかけて生息する、日本固有の昆虫。\nマイマイの殻へと頭を突っ込み、消化液で溶かして捕食する。その際の格好が、名前の由来となっている。","note":"カタツムリの殻を被る虫","exp":"340"}],"2348":[{"type":"財宝","name":"宇治拾遺物語","rank":"4","desc":"読みは「うじしゅういものがたり」。仏教説話や世俗説話で構成された日本の説話集。\n同様の説話集の中では教訓めいた内容が比較的少なく、滑稽な話が多い。","note":"夢のお告げと説話集","exp":"620"}],"5849":[{"type":"美術品","name":"ピクウェのアクセサリー","rank":"5","desc":"ピクウェと呼ばれる技法で作成されたアクセサリー。母材として柔らかい素材が使われているのが特徴である。","note":"","exp":"1360"}],"1912":[{"type":"宗教遺物","name":"飾られた頭蓋骨","rank":"2","desc":"メソアメリカの地で見つかった、見事な装飾の頭蓋骨。ターコイズをふんだんに使っている。元は頭蓋骨の面を全て覆っていたのだろうか。","note":"奇妙な頭蓋骨の地図","exp":"300"}],"195":[{"type":"美術品","name":"マギの礼拝","rank":"2","desc":"レオナルド・ダ・ヴィンチ作の絵画だが、未完成である。彼が最初に手がけた大作だとされるが、製作中にほかの土地へ転居したため未完成となった。絵の題材は、誕生したイエスを三人の賢人が礼拝に訪れた情景である。","note":"クエスト「ダ・ヴィンチ最初の大作」<br/>発見物カード:110","exp":"220"}],"5410":[{"type":"地理","name":"コスタデルソル","rank":"1","desc":"マラガを中心とした、300kmにおよぶ海岸線を指す。意味はスペイン語で「太陽の海岸」である。1年を通して温暖な気候で、保養地には最適だ。","note":"太陽のあふれる浜辺","exp":"20"}],"4808":[{"type":"財宝","name":"法螺貝笛","rank":"3","desc":"東の国の戦において、進退の合図のために使用されていた楽器。大きな巻貝を加工した楽器で音を出すには訓練が必要なようだ。","note":"安土城（上層隠し部屋）","exp":""}],"5039":[{"type":"港・集落","name":"カリビブ","rank":"1","desc":"南アフリカ西岸にある街。小さな街で農業・漁業が中心だが、近辺に鉱山があり、銅や亜鉛のほかダイヤモンドが産出する。","note":"到達する","exp":"67"}],"6516":[{"type":"地理","name":"モエラキ・ボールダーズ","rank":"5","desc":"ニュージーランド南島にあるモエラキ海岸に転がる、巨大な球状の岩石。表面に亀甲状の割れ目がある。マオリの伝説では、沿岸に座礁した大カヌー・アライテウル号から漂着した、ヒョウタン型のウナギを入れるかごが変化したものだという。","note":"","exp":""}],"3729":[{"type":"歴史遺物","name":"パスパ文字の石片","rank":"5","desc":"モンゴル帝国で使用されている文字が彫られたという石片。上から下に読むようだ。","note":"失われゆく文字","exp":"1180"}],"5753":[{"type":"気象・現象","name":"球電","rank":"2","desc":"空中を光の球が浮遊する現象。色は赤や黄、青など多岐にわたる報告がある。雷雨の際に目撃されることが多いが、風雨のない状況での目撃例もある。","note":"2017.02.07新規追加","exp":"360"}],"2338":[{"type":"財宝","name":"万葉集","rank":"4","desc":"約4500首を収めた和歌集。詠み手の身分や住む場所に関わらず、多様な作品が集められている。\n日本に現存する和歌集の中では、最古のものとされる。","note":"クエスト「最古の和歌集」<br/>発見物カード:65","exp":"680"}],"4840":[{"type":"天文","name":"こぐま座","rank":"3","desc":"ギリシャ神話の中で、クマに姿を変えられていた母親を、母親だと知らずに射ようとした狩人・アルカスが、天に上げられたとされる星座。母親と同じくクマの姿となっている。","note":"クエスト「北極星を含む星座」<br/>発見物カード:230","exp":"460"}],"6767":[{"type":"中型生物","name":"サプサルケ","rank":"2","desc":"朝鮮半島の固有犬種。番犬としての素質が高く、新羅時代には王室で飼われ、悪鬼を追い払う霊力があるといわれた。朝鮮半島ではサブサリなどとも呼ばれる。","note":"発見３２０，発見物カード１６０","exp":"480"}],"1667":[{"type":"宗教建築","name":"アフ・アキビのモアイ","rank":"5","desc":"ホツ・マツア王が、ラパ・ヌイに移動する前に先遣隊として遣わした七人の使者の像。他の像はすべて内陸の方向を向いているが、このモアイだけは海を見ている。伝説では、この像の見つめる先に彼らの故郷があるというが…。","note":"太陽が沈む向こうに","exp":"1131"}],"5354":[{"type":"天文","name":"くじゃく座","rank":"4","desc":"天の南極近くにある星座。２等星のピーコック以外は暗い星が多いが、形が整っていて見つけやすい。","note":"クエスト「インドの鳥の星座」<br/>発見物カード:330","exp":"660"}],"6411":[{"type":"地理","name":"サハラのオアシス","rank":"5","desc":"サハラ砂漠の地下深くには水を通しにくい粘土の層がある。ここに地下水が蓄えられており、水が蒸発すると、砂に塩が残って白くなる。これがオアシスの目印になる。","note":"追究発見物","exp":"415"}],"5660":[{"type":"小型生物","name":"スナネコ","rank":"2","desc":"サハラからアジア西南部にかけての砂漠に生息する小型の動物。体長は50cm程度。耳が大きく、その内側は砂が入り込むのを防ぐために毛で覆われている。","note":"","exp":"230"}],"2102":[{"type":"財宝","name":"我がシードの歌","rank":"4","desc":"レコンキスタの英雄といわれるエル・シードを主役にした叙情詩。史実と脚色を混ぜてある。原本は失われ、写本もところどころ欠落しているため、正確な題名、作者は不明。","note":"語り継がれる英雄<br/><br/>発見時経験値720　発見物カード経験値360","exp":"720"}],"2614":[{"type":"財宝","name":"台南の地図","rank":"5","desc":"読みは「タイナンのちず」。ネーデルラント軍が占領していた港や道路を示した台南の地図。鄭芝龍の部下だった何斌が鄭成功に献上した。台湾島へ安全に上陸するために、大きく役立った。","note":"鄭成功についての調査　　発見場所：安平の酒場主人向かって右横辺り","exp":"1040"}],"6624":[{"type":"地理","name":"ギリ・トラワンガン","rank":"3","desc":"サンゴ礁が美しい南太平洋の小島。小スンダ列島に属するギリ三島の一番西に位置する。","note":"発見物カード 253","exp":"506"}],"1705":[{"type":"宗教遺物","name":"十戒","rank":"5","desc":"旧約聖書において、モーゼが神から与えられたといわれる十の戒律を記した石板。聖書には契約の箱に納められたと記述されている。","note":"石の記憶","exp":"1235"}],"6890":[{"type":"鳥類","name":"アンナハチドリの雌","rank":"5","desc":"雌のアンナハチドリ。冠羽から喉にかけての羽色が雄と大きく異なる。また、雄の冠羽は光に反射して色が変化するが、雌の冠羽は変わらない。","note":"","exp":""}],"4865":[{"type":"天文","name":"ペルセウス座","rank":"5","desc":"ギリシャ神話に登場する英雄・ペルセウスが女神アテネによって天に上げられたとされる星座。片手には怪物・メデューサの首を携えているとされる。","note":"夜空に輝く勇者","exp":"810"}],"5467":[{"type":"鳥類","name":"クロハラトキ","rank":"1","desc":"パンタナル湿原でよく見られるトキの一種。\n飛びながら甲高い声で鳴く。胸より下の体表面が黒いのが特徴。","note":"「黒い腹を持つ鳥の地図」<br/>発見物カード:90","exp":"180"}],"783":[{"type":"植物","name":"ゲッケイジュ","rank":"3","desc":"ギリシャ神話に登場する妖精ダフネが、アポロンの愛から逃れるために姿を変えたとされる樹。その葉は料理や魔除けなど、幅広く使われている。","note":"太陽が愛でる樹","exp":"451"}],"4994":[{"type":"小型生物","name":"ヨーロッパハタリス","rank":"1","desc":"ヨーロッパの北東部に生息する、体長約20cmのリス草原や牧草地にトンネル状の長い巣穴を掘って暮らす。\n植物の葉や根、種などを食べる。 食べ物を頬袋に詰め込んで運び、巣に持ち帰るようだ。","note":"サロニカの門の外、<br/>南東にある一本杉のそば。<br/>生態調査、生物学、ランク2","exp":"80"}],"6407":[{"type":"宗教建築","name":"在りし日のマウソロス霊廟","rank":"","desc":"ハリカルナッソスに建造された壮麗な霊廟。王マウソロスとその死後に女王となった妻アルテミシアが眠る。大理石の高層建築で、各段に大きな彫像が立ち並んでいた。頂上には巨大な四頭立ての戦車と馬の像が載っていたという。","note":"","exp":""}],"25":[{"type":"地理","name":"ヴェルデ岬","rank":"1","desc":"アフリカ大陸の最西端である。アフリカ大陸探検の目安にされる。「ヴェルデ」はポルトガル語で「緑」の意味である。","note":"アフリカの最西端","exp":"90"}],"1831":[{"type":"海洋生物","name":"ビキール・ビキール","rank":"2","desc":"円筒形で鱗に覆われたヘビのような体に、15本程の羽状の背びれ、大ぶりな尾びれ、前ひれを持つ。体長1m程で茶褐色や深緑のまだらな体色が多い。熱帯アフリカの河川、及びナイル川で稀に目撃される。","note":"羽根が生えた魚","exp":"350"}],"5013":[{"type":"港・集落","name":"アチン","rank":"2","desc":"スマトラ島の北端に位置する街。マジャパヒト王国より独立した、アチェ王国の首都である。","note":"到達する","exp":"290"}],"2095":[{"type":"地理","name":"チャグレス川","rank":"2","desc":"カリブ海側から内陸へ続く川。この川を利用し、地峡を越えることができれば運河が開通するのだが…。","note":"［勅命］[[運河開通予定場所の調査","exp":"310"}],"5132":[{"type":"港・集落","name":"ブルネイ","rank":"2","desc":"ブルネイ王国の中心地で、イスラム教が布教されている。石油や鉱石などを産出する、資源豊かな国である。","note":"到達する","exp":"327"}],"1743":[{"type":"財宝","name":"マナ","rank":"5","desc":"マナとは神や精霊の力のこと。この石は島民が存在を口にするのも避けてきたほど非常に強いマナの力を秘めているらしい。石に触れるとほのかに温かく、触った場所から音も立てずに崩れていく。人には侵しがたい存在ということだろうか。","note":"精霊力の源<br/><br/>発見時経験値1209　発見物カード経験値604","exp":"1209"}],"6067":[{"type":"歴史遺物","name":"フリードリヒ2世の剣","rank":"4","desc":"神聖ローマ皇帝であった、フリードリヒ2世が愛用していたという宝剣。彼は６カ国語を操り、西ヨーロッパの開明的な君主と称えられた。しかし、生涯を通してテンプル騎士団や教皇派と対立し、何度も破門された。","note":"","exp":"650"}],"644":[{"type":"地理","name":"キプロス","rank":"1","desc":"地中海の東部に浮かぶ巨大な島。キプロスはギリシャ語で、トルコ語ではクブルスというそうだ。先史時代から文明が栄え、地理的な理由からさまざまな勢力に支配された。","note":"書きかけの地図","exp":"110"}],"6603":[{"type":"海洋生物","name":"チャイニーズバハバ","rank":"4","desc":"中国に生息する巨大魚の一種。海水と淡水が混じり合う河口付近に多いとされ、小魚やエビ、カニなどを捕食する。食用や薬用など多くの使い道がある。","note":"","exp":"640"}],"2015":[{"type":"歴史遺物","name":"祭事用の金細工","rank":"1","desc":"豊かな金を使って作った祭器。インカではあまり頓着されていないが、異国の心無い人間が見れば奪ってでもほしいお宝だろう…。","note":"アンデスの儀式道具の地図","exp":"170"}],"6129":[{"type":"植物","name":"ラフレシア・アルノルディイ","rank":"5","desc":"東南アジアに多く分布している寄生生物で、直系1m近い分厚く大きな花をつける。\nイングランドの調査隊が発見したようだが、虫を誘う酷い悪臭を放つため、近づくにも勇気が必要だったのではないだろうか…。","note":"","exp":"1030"}],"3148":[{"type":"地理","name":"アイスランド","rank":"5","desc":"ブリテン島の北西に位置する島。長い間無人島だったが、10世紀前後にケルト人やスカンジナビアの人々が移住してきた。「氷の島」の呼び名のとおり氷河で覆われた土地が多いが、火山帯に属しているため、地熱が高く比較的暖かである。","note":"クエスト「「ぶどうの地」に至る道」<br/>発見物カード:505","exp":"1010"}],"1966":[{"type":"財宝","name":"月桂冠","rank":"3","desc":"ゲッケイジュの葉が付いたままの枝を編んで冠にしたもの。\nギリシャ神話によるとアポロンの求愛を拒んだダフネは身をゲッケイジュに変えた。失意のアポロンは、その枝を編んで冠とし、生涯被り続けたという。","note":"アポロンの冠","exp":"460"}],"3182":[{"type":"地理","name":"グロスモーン山","rank":"3","desc":"北米北東部沿岸の、テラ・ノヴァ西部に位置する標高約800mの山。島の傍らを流れる寒流の影響で気温が低く、高山植物が生息する。","note":"赤茶色の台地","exp":"450"}],"5730":[{"type":"化石","name":"サメの歯の石","rank":"1","desc":"サメの歯が固まったように見える石。魔除けや装身具として加工されることもある。","note":"2017.02.07新規登録","exp":""}],"3003":[{"type":"植物","name":"オオハンゴンソウ","rank":"1","desc":"北米原産の植物。丈は2mにも及び、黄色の大きな花を咲かせる。\n種子のほか、地下茎でも繁殖する。","note":"黄色の花の地図","exp":"170"}],"6828":[{"type":"中型生物","name":"アカハナグマ","rank":"4","desc":"アンデス山脈の東に生息する、アライグマの一種。主に低地の森林で暮らし、果実や小動物などを餌とする。細長い鼻と黒い縞模様のある尾が特徴で、尾の長さは体と同じにまでなる。赤や茶など体毛は個体により様々である。","note":"発見物カード:360","exp":"720"}],"412":[{"type":"化石","name":"巻き貝の模様の石","rank":"1","desc":"非常に大きな巻貝の形の石。貝が大きくなりすぎると石になるのだろうか？　陸地で見つかるのも不思議だ。","note":"奇妙な石の地図","exp":"31"}],"1500":[{"type":"中型生物","name":"ボブキャット","rank":"1","desc":"ヤマネコの一種。しまや斑模様がある。それほど大型ではない。頬の毛が長く、尾が短いのが特徴。","note":"山猫の地図","exp":"70"}],"5213":[{"type":"歴史遺物","name":"新港文書","rank":"3","desc":"平埔の人々の間で使われていた、土地売買に関する契約文書。現地の言葉であるシラヤ語をラテン語に訳して記している。この文書はネーデルラント人宣教師の教育活動の痕跡と考えられる。","note":"","exp":""}],"6877":[{"type":"鳥類","name":"オオミズナギドリ","rank":"2","desc":"主に東アジアに生息する渡り鳥の一種。冬には南アジアやオセアニアへ南下する。細長く先が曲がったくちばしを持つ。飛翔力に優れているが地面から飛び立つことができない。海上を薙刀で水を切るように飛ぶことから、この名が付いた。","note":"発見物カード:175","exp":"350"}],"1474":[{"type":"宗教遺物","name":"ノラシンガ像","rank":"2","desc":"獅子の頭部に、人間の体を持つといわれる神獣。元はヒンドゥー教神話に出てくるナラシンハという神獣ではないかとされる。ナラシンハはヴィシュヌ神の変身した姿。","note":"獅子の頭を持つ像","exp":"280"}],"6930":[{"type":"化石","name":"ヒトデの化石","rank":"2","desc":"ヒトデが五本の腕を伸ばした状態のまま化石となったもの。きれい\nな星型をしている。","note":"発見物カード:165","exp":"330"}],"2935":[{"type":"財宝","name":"雲南斬馬刀","rank":"5","desc":"鄭成功が組織した部隊に導入されていた、刀身の長い片刃の剣。重いため、扱いが難しいが、騎兵を馬ごと切れるほどの高い破壊力を誇る。","note":"父の背中","exp":"1030"}],"2601":[{"type":"美術品","name":"長谷川等伯の屏風絵","rank":"3","desc":"日本の絵師・長谷川等伯の筆による屏風絵。江戸時代初期の主流である狩野派に対抗し、独自の作風で生み出した作品の一つである。","note":"異端の名画","exp":"490"}],"5057":[{"type":"港・集落","name":"サッサリ","rank":"1","desc":"サルデーニャ島の北部に位置する街。南部のカリアリと同じく、さまざまな文化が共存する。","note":"到達する","exp":"29"}],"6012":[{"type":"財宝","name":"エリュトゥラー海案内記","rank":"2","desc":"1世紀頃、古代ローマの属州だったエジプトで、ギリシャ人航海者により著された記録。エジプト・インド間の交易に携わる貿易業者向けに書かれたものであり、東の果てである中国も絹の産地として紹介されている。","note":"","exp":"320"}],"701":[{"type":"美術品","name":"狩人のディアナ","rank":"1","desc":"作者不詳の絵画。ローマ神話のディアナが、猟犬をともなって狩りに出かける様子を描いている。柔らかで自然な裸体が美しい。モデルはフランス王の愛妾だといわれる。","note":"クエスト「神話を題材にした裸婦画」<br/>発見物カード:80","exp":"160"}],"1956":[{"type":"植物","name":"マレシェルビア","rank":"1","desc":"南米南西部の乾燥地帯にのみ生息。花びらが星形に付いており、白や紫の花を咲かせる。","note":"星の花の地図","exp":"170"}],"5996":[{"type":"地理","name":"イビサ島","rank":"1","desc":"バレアレス諸島の西部の島。古代から人が住み、アフリカとイスパニア間の中継点となっていた。青い空と海が美しい島である。","note":"バレアレス諸島西部の調査","exp":"20"}],"2104":[{"type":"歴史遺物","name":"コラーダ","rank":"5","desc":"「我がシードの歌」では銀1000マルコ以上の価値があるとされる名剣で、バルセロナ伯との戦いに勝利した時に獲得したもの。","note":"士官の結論<br/><br/>発見時経験値1070　発見物カード経験値535","exp":"1070"}],"6419":[{"type":"歴史遺物","name":"聖剣の鞘","rank":"5","desc":"聖剣エクスカリバーを収めていた魔法の鞘。身につけた者の傷を癒やし、不死の力を与えるという。アーサー王の姉モーガンにより持ち去られ湖へと投げ込まれた。鞘を失ったのちにアーサー王は傷を負い、命を落とすことになったという。","note":"","exp":""}],"721":[{"type":"美術品","name":"ポセイドンのブロンズ像","rank":"4","desc":"昔アテネにあったという、ポセイドンの青銅像。槍投げの瞬間を詳細に模した、精巧なもの。支えにした左足の親指は少し上がり、後ろに下げた右足は踵が上がっている。今にも動き出しそうな像である。","note":"生きているような作り物","exp":"636"}],"2077":[{"type":"植物","name":"コチョウラン","rank":"2","desc":"チョウが群がって飛んでいるように見えるほど、多くの花を咲かせる。密林の木々に張り付くように自生している。","note":"［勅命］[[香料諸島方面からの献上品","exp":"330"}],"5698":[{"type":"地理","name":"クルクシェートラ平原","rank":"5","desc":"『マハーバーラタ』の物語において、最終決戦が行われた場所。バラタ民族にとっては、聖なる地であったようだ。","note":"","exp":"1370"}],"6154":[{"type":"植物","name":"オジギソウ","rank":"2","desc":"南アメリカ原産の植物で、本来の名は「ミモザ」という。手や風、熱などによる刺激で葉を閉じた後に枝が垂れ下がる性質を持つため、「オジギソウ」と呼ばれるようになった。今では正式名で呼ばれることのほうが稀である。","note":"","exp":"330"}],"2240":[{"type":"地理","name":"ダーウィン湖","rank":"4","desc":"ガラパゴス諸島の中で一番大きな島にある塩湖。海よりも水面が高く、雨もほとんど降らないにもかかわらず、湖水が枯れることはないという。","note":"森の奥の謎","exp":"750"}],"1902":[{"type":"小型生物","name":"カエルクイコウモリ","rank":"2","desc":"中米の熱帯雨林に生息するコウモリで、その名のとおりカエルを捕食する。カエルの鳴き声で毒を持つか持たないかさえ判断してしまう能力は、頭より大きな耳のおかげだろう。","note":"［勅命］[[現地における生物の調査","exp":"310"}],"1928":[{"type":"虫類","name":"バイオリンムシ","rank":"2","desc":"東南アジアの熱帯雨林に生息する、見た目がバイオリンに似ている昆虫。大きさは10cm程で昆虫の中では大型。特定のキノコの近くでよく見つかる。","note":"バイオリンを模した昆虫","exp":"350"}],"6391":[{"type":"宗教建築","name":"懸空寺","rank":"2","desc":"中国の北東部の断崖に建造された木造寺院。かつては「玄空閣」とも呼ばれていた。中には仏教、儒教、道教の開祖の像三体が並べられている。この地を訪れた詩人の李白は、岩に「壮観」の文字を残したという。","note":"","exp":"290"}],"521":[{"type":"歴史遺物","name":"家畜の骨","rank":"1","desc":"牛や馬など、家畜として飼われていた動物の骨。山羊や羊は多くの文明で飼われていたが馬はまったく見られない文明がある。","note":"古代の集落の地図","exp":"8"}],"1574":[{"type":"大型生物","name":"タイパン","rank":"2","desc":"最大で3mを超すヘビ。獲物に遭遇すると、すばやい動きで攻撃をしかけ、強力な毒で仕留める。人間も、噛まれれば死は免れないだろう。","note":"猛毒","exp":"320"}],"5694":[{"type":"史跡","name":"プスカリニ池","rank":"4","desc":"釈迦の生誕地とされるルンビニにある池。釈迦はこの池で沐浴をした生母の脇の下から生まれ、産湯にはこの池の水が使われたと伝えられている。","note":"","exp":"630"}],"5456":[{"type":"海洋生物","name":"デンキウナギ","rank":"3","desc":"強力な電気を起こせる魚。体から電気を放出し、小魚などを捕食する。南米北部に生息しており、この水域では食物連鎖の頂点に位置する生物の一つになっている。","note":"","exp":"540"}],"6960":[{"type":"小型生物","name":"ヤマカガシ","rank":"4","desc":"水辺に生息する日本固有のヘビ。生息地域や個体によって体色の差異が大きいが、赤と黒の斑点が交互に並んだものがよく見られる。牙から注入する毒と、毒腺から飛散する毒の二種類を持つ。","note":"発見物カード:390","exp":"780"}],"5536":[{"type":"気象・現象","name":"濃霧","rank":"2","desc":"微細な水滴が空気中を漂うことで発生する現象。ときには数メートル先が見えなくなる場合もある。視界不良だけでなく、農作物の成長を阻害するという報告もあるようだ。","note":"一度消えても条件合えば、上陸地点から出ずに再出現します。","exp":"140"}],"1533":[{"type":"海洋生物","name":"ホオジロザメ","rank":"2","desc":"巨大な体と凶暴さで恐れられる海の暴君。人喰いザメとしても恐れられる。","note":"釣り","exp":"260"}],"60":[{"type":"宗教遺物","name":"アグニ像","rank":"3","desc":"インド神話の火の神である。炎のような髪に金色の歯、七枚の舌という、炎をもとにした姿を持つ。悪を滅する浄化の力を持つとされる。","note":"インドの炎神","exp":""}],"5843":[{"type":"地理","name":"ローヌ川とアルヴ川","rank":"5","desc":"フランス東部を流れる河川。二つの河川は合流するが、水質が異なるため合流地からしばらくは混ざり合わず、2色に分かれた流れを見られる。","note":"","exp":"1360"}],"6322":[{"type":"鳥類","name":"ニシコウライウグイス","rank":"4","desc":"夏と冬ですみかを変える渡り鳥。ヨーロッパをはじめアフリカ、西アジアなどに広く分布する。体と翼の色が異なるのが特徴で、特に雄は黄色い体と黒い翼のコントラストが美しいという。","note":"","exp":"650"}],"6793":[{"type":"天文","name":"シャム","rank":"3","desc":"や座のアルファ星。名はアラビア語で矢を意味し、元々は\n星座全体を指す言葉であったという。","note":"視認","exp":""}],"5606":[{"type":"財宝","name":"虹の巻貝石","rank":"5","desc":"ロッキー山脈の東側で見つかった、オパールのような石。巻貝のような形をしている。","note":"","exp":"940"}],"6214":[{"type":"歴史遺物","name":"エンカルナシオン号","rank":"4","desc":"イスパニアの商船。新大陸へ物資を供給するために建造された。パナマのチャグレス川河口で嵐に遭い、沈没した。","note":"サルベージ","exp":"700"}],"709":[{"type":"中型生物","name":"コビトカバ","rank":"5","desc":"西アフリカの限られた地域にしかいない、小さなカバ。カバの子供かと思われたが、同じ大きさの個体ばかりなので違う種類だと思われる。体色もカバよりかなり濃い。水の中にいることは少なく、森や湿地にいる。","note":"水が嫌いなカバ","exp":"1040"}],"1868":[{"type":"植物","name":"コピウエ","rank":"4","desc":"堅い茎のツルのような植物。下向きに大型の花を咲かせる。鮮やかな赤い花が多い。南米大陸の南西の森林地帯に広く分布。","note":"小さな赤い鐘","exp":"620"}],"912":[{"type":"鳥類","name":"ペリカン","rank":"1","desc":"下のくちばしに大きな袋を持つ水鳥。かなり大型である。くちばしの袋は、捕らえた魚を貯めるのに使うのだろうか。","note":"白い鳥の地図","exp":"31"}],"6712":[{"type":"財宝","name":"チャラカ・サンヒター","rank":"2","desc":"インドの伝統医学であるアーユル・ヴェーダを代表する、古典医学書の1つ。クシャーナ朝カニシカ王の侍医、チャラカの著作が元になった。熱病、癇癪、腫瘤に対する研究が特にくわしい。","note":"クエスト「不老不死の秘法」 発見物カード:140","exp":"280"}],"1265":[{"type":"化石","name":"首の長いトカゲの骨","rank":"1","desc":"体長10mを超える、首の長い巨大なトカゲの骨。この生物が生きていたころは、同じ大きさのトカゲが何匹も歩き回っていたのだろうか。","note":"トカゲの骨の地図","exp":"180"}],"6024":[{"type":"化石","name":"奇妙なエビの石","rank":"5","desc":"北米北西部のバージェス頁岩から見つかった奇妙な石。エビの腹部のようでもあり、なんらかの生物の触手のようにも見える。","note":"","exp":"1230"}],"5523":[{"type":"気象・現象","name":"海底火山","rank":"2","desc":"海底の火山が活動する現象。水深が浅く、噴火の力が強いと海面から煙などが噴出する。特に噴火活動が活発な場合は島の形成に繋がることもある。","note":"","exp":"150"}],"654":[{"type":"財宝","name":"ソウルオブクイーン","rank":"5","desc":"1000カラット以上ある大きなエメラルド。エメラルドは内包物やひびが多いものだが、この石は目立ったそれがなく、非常に透明度が高い。名前は、かのクレオパトラがエメラルドを好んだことにちなむようだ。","note":"女王の心","exp":"1079"}],"3689":[{"type":"財宝","name":"グースリ","rank":"4","desc":"ロシアの伝統的な弦楽器。翼型、兜型、箱型と、時代を経るごとに形状や弦の数に改良が加えられた。\nロシアの吟遊詩人たちが使用したという。","note":"ロシアの伝統楽器","exp":"750"}],"1344":[{"type":"小型生物","name":"トビガエル","rank":"1","desc":"他のカエルと異なり、前足にも水かきがついている。それにより、木の上から跳んだときに、かなりの距離を滑空する。四肢は長く、木に登るのに適している。","note":"跳躍するカエルの地図","exp":"100"}],"3419":[{"type":"レリック","name":"ヘルメス主義","rank":"","desc":"ヘルメス・トリスメギストスを祖とする、神秘を追究する者たちの思想。様々な学問を内包した知識の結晶ともいえる思想の総称。","note":"","exp":""}],"6340":[{"type":"宗教遺物","name":"金色のリャマ像","rank":"2","desc":"リャマの姿を模した金の像。目をはじめ、鼻や耳までも細かく再現されている。インカ帝国の儀式においては、リャマが生け贄として捧げられることがあったようだ。","note":"「動物をもした金細工の像の地図」<br/>発見物カード:150","exp":"300"}],"3625":[{"type":"鳥類","name":"ドードー","rank":"5","desc":"モーリシャス諸島にしか生息しない、特殊な鳥である。ニワトリよりかなり大きく、翼は小さくて飛べない。足は太くてしっかりしているが、速く走ることはできない。島に捕食者がいないため、のんびりした鳥になったのだろう。","note":"太りすぎのガチョウのような鳥","exp":"1105"}],"6441":[{"type":"宗教建築","name":"モン・サン・ミシェル","rank":"1","desc":"サン・マロ湾に浮かぶ小島に建設された修道院。潮の満ち引きが激しく、引き潮の時には大陸から歩いて渡ることができる。英仏百年戦争においては要塞としても利用された。\nその神秘性から「西洋の驚異」と呼ばれる。","note":"","exp":"130"}],"5159":[{"type":"港・集落","name":"マリンディ","rank":"1","desc":"アフリカ東岸に位置する港湾都市。7世紀以降、ムスリム商人が来航し、海上交易で繁栄した。","note":"到達する","exp":"77"}],"2761":[{"type":"財宝","name":"パイワン民族の衣装","rank":"4","desc":"台湾島の先住民であるパイワン民族の貴族が身につける衣装。トンボ玉や、細かい刺繍が入ったきらびやかな長衣である。ヒャッポダという毒蛇と人間が結婚し、その間に生まれたのがパイワン民族だという伝説がある。","note":"毒蛇から生まれた民族","exp":"720"}],"7017":[{"type":"歴史遺物","name":"内乱記","rank":"3","desc":"ユリウス・カエサルがローマ内戦の経過を報告書としてまとめた著作。「ガリア戦記」に続く作品にあたる。紀元前49年から約二年\nにわたり、内戦初期の状況を簡潔な筆致で克明に記録している。","note":"","exp":""}],"27":[{"type":"財宝","name":"ズールーの装身具","rank":"1","desc":"アフリカ南部に居住する民族の装身具。色とりどりのビーズを使った、複雑な模様のものである。ズールーの名は「楽園の民」を意味する。非常に勇敢な民族である。","note":"アフリカの装身具の地図","exp":"56"}],"4847":[{"type":"宗教遺物","name":"ムシュフシュの壁画","rank":"4","desc":"バビロンのイシュタル門に描かれている聖獣の図。ムシュフシュは都市神マルドゥクとその子ナブーの随獣として崇められている。","note":"蓼食う酒場娘も好き好き","exp":"770"}],"782":[{"type":"鳥類","name":"ドードー","rank":"5","desc":"モーリシャス諸島にしか生息しない、特殊な鳥である。ニワトリよりかなり大きく、翼は小さくて飛べない。足は太くてしっかりしているが、速く走ることはできない。島に捕食者がいないため、のんびりした鳥になったのだろう。","note":"太りすぎのガチョウのような鳥","exp":"1105"}],"490":[{"type":"宗教建築","name":"大列柱","rank":"1","desc":"カルナック神殿の大列柱室に立ち並ぶ、134本の石柱。高さ23ｍの物と15ｍの物がある。作らせたのは古代エジプトのファラオ・ラムセス2世である。","note":"古代エジプトの建築技術","exp":"180"}],"2057":[{"type":"小型生物","name":"トマトガエル","rank":"3","desc":"マダガスカル島北西部の森林に生息する。\n普段は地中や落ち葉の下などに潜っている。水かきは小さく、動きが鈍い。生息地が限られているため、個体数は少ない。","note":"奇妙な色のカエル","exp":"500"}],"1049":[{"type":"中型生物","name":"サーバル","rank":"3","desc":"サーバルは「猟犬」という意味のポルトガル語に由来する。大きな耳と長い肢は、草たけの高い草原の中で、ウサギやネズミなどの獲物を捕らえるのに役立つ。","note":"猟犬","exp":"462"}],"2333":[{"type":"財宝","name":"方丈記","rank":"1","desc":"鴨長明が著した随筆。移り変わりゆく人の世を憂い、感慨を述べた日本文学である。\n当時の災厄についての記述と、自らの草庵生活についての記述から成る。","note":"随筆の地図","exp":"120"}],"6990":[{"type":"宗教遺物","name":"ヴィシュヌとガルーダ像","rank":"2","desc":"ヒンドゥー教の三神の一柱であるヴィシュヌが、神鳥ガルーダの方の上に立っている姿を表した青銅像。ガルーダはヴィシュヌの眷属で、乗り物でありアンコール美術にはこの二神を題材とした作品が多くある。","note":"","exp":"177"}],"3004":[{"type":"化石","name":"アゴの長いトカゲのような石","rank":"1","desc":"体長60cm以上の、トカゲのような石。他の石と重なるようにして見つかった。","note":"奇妙な石の地図","exp":"200"}],"2572":[{"type":"鳥類","name":"アリサンヒタキ","rank":"3","desc":"全長12cmほどの小さな鳥。標高の高い山中に生息し、阿里山でよく目撃されることから、この名前が付いた。","note":"阿里山の動物調査","exp":"490"}],"4969":[{"type":"地理","name":"ペロポネソス半島","rank":"1","desc":"バルカン半島の最南端に位置する半島。ギリシャ本土とはコリント海峡で繋がる。山がちで、平地は少ない。多くの遺跡があり、古くから繁栄していた半島だと思われる。","note":"「書きかけの地図」<br/>発見物カード:80","exp":"160"}],"5193":[{"type":"港・集落","name":"澳門","rank":"2","desc":"読みは「マカオ」。大きな港を擁する街。\n漁業を中心とした小さな村だったが、ポルトガル人が居留するようになってからは、ヨーロッパと東アジア間の貿易の要衝となった。","note":"到達する","exp":"335"}],"5405":[{"type":"海洋生物","name":"ムツ","rank":"3","desc":"大型の深海魚で1mを超えることもある。身は脂がのっており美味。","note":"","exp":"460"}],"6247":[{"type":"宗教遺物","name":"聖母のステンドグラス","rank":"1","desc":"聖母の絵姿をうつした古いステンドグラス。教会の改修にあわせて取り外され、倉庫にしまわれていた。様式に特徴が見られることから、学者の興味をひいているようだ。","note":"クエスト「ギルドの最初の仕事」「聖母のステンドグラス」<br/>発見物カード:20","exp":"40"}],"5934":[{"type":"港・集落","name":"サグレス","rank":"1","desc":"ポルトガルのとある王族が建設したと伝えられる村。イベリア半島の先端に位置し、外洋を航行する船団を見守る地であると同時に、他国との紛争における重要な要塞の役目も果たすという。","note":"到達する","exp":"30"}],"1576":[{"type":"海洋生物","name":"シードラゴン","rank":"3","desc":"海藻によく似た生物。周囲の海藻に擬態して身を守る。小型のエビや魚を捕食する。","note":"自由な海藻<br/><br/>発見時経験値451　発見物カード経験値225","exp":"451"}],"5261":[{"type":"歴史遺物","name":"古代インドの建築技芸書","rank":"2","desc":"インド各地にあるといわれる建築技芸書。寺院、宮殿の建築法や周囲を彩るレリーフの造形を解説している。　この書物には著者らしき建築家の名前も書かれている。","note":"コナーラク地方　再調査報酬","exp":""}],"6969":[{"type":"中型生物","name":"アビシニアコロブスの幼体","rank":"4","desc":"アビシニアコロブスの幼体は成体と異なり、全身が真っ白な毛に覆われている。生後三カ月ほど経つと、徐々に親と同じ黒い体毛へと変化していく。","note":"追究クエスト<br/>発見物カード:360","exp":"720"}],"72":[{"type":"地理","name":"ベンガル湾","rank":"2","desc":"インドの東に広がる広大な湾。ガンジス川をはじめ、大河がいくつも流れ込んでいる。沿岸には天然の良港がいくつもある。","note":"インド東の湾","exp":"350"}],"2869":[{"type":"植物","name":"フサフジウツギ","rank":"1","desc":"主に中国に生息する、枝先に房状の小さな花を咲かせる植物。\nその芳香に誘われて、チョウがよく集まってくる。","note":"小さな花の地図","exp":"160"}],"5942":[{"type":"宗教建築","name":"バターリャ修道院","rank":"4","desc":"正式名称は「勝利の聖母マリア修道院」カスティーリャ王国との戦勝記念に建てたられため「バターリャ（の戦い）」の名前で呼ばれる。数世紀にわたって建築が続けられ、その間にヨーロッパ各地で流行した多くの建築様式が取り入れられた。","note":"","exp":"740"}],"5518":[{"type":"地理","name":"セノーテ","rank":"2","desc":"ユカタン半島の石灰岩地帯で見られる、陥没した地面に地下水かだ溜まってできた泉。水底に鍾乳洞か沈んでいる場合がある。","note":"","exp":"480"}],"6293":[{"type":"歴史遺物","name":"アリイのサッシュ","rank":"5","desc":"ハワイで「アリイ」と呼ばれる権力者が、権威の象徴として身に着ける腰巻き。真紅や黄色の鮮やかな羽根で覆われており、その羽根には自然の力が宿っているという。","note":"","exp":"830"}],"817":[{"type":"財宝","name":"大理石の彫刻タイル","rank":"1","desc":"大理石にレリーフを施したタイル。壁や床にはめ込んで装飾するためのものである。","note":"大理石のレリーフの地図","exp":"69"}],"5370":[{"type":"宗教建築","name":"ディオスクーリ神殿","rank":"2","desc":"ローマ最後の王であるタルクィニウス・スペルブスと共和政ローマが戦った際、ギリシャ神話の英雄のカストルとポルックスが共和政側に助力したという伝説により建てられた神殿。柱三本のみが現存する。","note":"","exp":"300"}],"1987":[{"type":"海洋生物","name":"スヌーク","rank":"1","desc":"低い体高に尖った細長い顎が特徴のスズキに似た魚。大きなものは1mを超える。","note":"釣り","exp":"160"}],"1971":[{"type":"鳥類","name":"ヤリハシハチドリ","rank":"3","desc":"くちばしの長い、小さな鳥。槍のような形状のくちばしは、体長の約4割を占めている。毛づくろいは、くちばしが使えない代わりに長い足を使う。空中で静止するように飛び、花の蜜を吸う。","note":"長い長いくちばし","exp":"480"}],"2748":[{"type":"地理","name":"九竜の滝","rank":"2","desc":"金剛山にある滝。\n九竜とは、本来は滝つぼの名前であり、以前は衆香瀑（しゅうこうばく）と呼ばれていたらしい。しかし、いつの間にか、九竜の名が定着したという。","note":"「書きかけの地図」<br/>発見物カード:135","exp":"270"}],"6193":[{"type":"財宝","name":"ビリンバウ","rank":"2","desc":"アフリカから入ってきた、いわゆる打弦楽器の一種らしい。弓のような形をしており、「バケタ」という棒で弦を叩いて演奏する。中身をくり抜き乾燥させたヒョウタンを共鳴板としており、その他の装飾などは特にない。","note":"","exp":"210"}],"6845":[{"type":"財宝","name":"謎の手稿","rank":"5","desc":"羊皮紙に書かれた、正体不明の手稿。中世の終わり頃の作と推定されるが、未知の文字が並んでおり解読できた者はいない。文字の他に彩色された植物や天体などの図案も描かれているが、詳細は不明である。","note":"発見物カード:430","exp":"860"}],"5469":[{"type":"虫類","name":"ヒカリコメツキ","rank":"2","desc":"中南米に生息する夜行性の昆虫。\n発光する昆虫の中で最も強い光を放つといわれており、胸部にある白い斑紋から薄緑色、体の付け根から橙色を発光する。","note":"発見時経験値210　発見物カード経験値105","exp":"210"}],"1832":[{"type":"海洋生物","name":"エンドリケリ・エンドリケリ","rank":"2","desc":"扁平な頭部、硬い鱗に覆われた円筒形の太い胴、羽のような背びれなど、独特な姿をした魚。長寿で、10年以上生きる。ナイル川上流など、熱帯アフリカの河川に生息。","note":"羽根が生えた魚の仲間","exp":"350"}],"1861":[{"type":"宗教遺物","name":"彩色木製のマスク","rank":"4","desc":"木製のマスクで、アンデスの遺物としては珍しいものである。チチカカ湖付近の神殿の神像をモチーフにしているといわれている。顔の周りに太陽光のような放射状の線がある。","note":"連綿と続く文化","exp":"710"}],"2531":[{"type":"小型生物","name":"スインホーキノボリトカゲ","rank":"2","desc":"台湾島にのみ生息する全長約20cmほどのトカゲ。樹幹によくくっついている。\n体の色は樹木に似ているが、背に黄色の線が入っているため、見つけることはたやすい。","note":"移動する黄色い線","exp":"310"}],"6814":[{"type":"小型生物","name":"夏毛のユキウサギ","rank":"5","desc":"夏毛になったユキウサギ。茶褐色の毛は、灌木などに隠れるのに適している。冬になるにつれて、毛が生え変わり、全身が白くなる。","note":"追究クエスト<br/>発見物カード:470","exp":"940"}],"1541":[{"type":"歴史遺物","name":"パレンケの石棺","rank":"5","desc":"パレンケ遺跡にある、碑銘の神殿に納められた棺。蓋には、精巧なレリーフが彫られている。中には副葬品などが無数に眠っていた。","note":"マヤの王墓","exp":"1196"}],"5794":[{"type":"史跡","name":"コンドアの岩絵群","rank":"5","desc":"数千年にわたり蓄積されてきた岩絵。赤い絵と白黒の絵があり、赤い絵のほうが、より古い時代に描かれたもののようだ。","note":"","exp":""}],"299":[{"type":"歴史遺物","name":"アガメムノンの黄金の仮面","rank":"5","desc":"ギリシャ神話に登場する、ミュケナイ王・アガメムノンの副葬品ではないだろうか。イリアスは絵空事ではなくアガメムノンもアキレウスも実在したに違いない！","note":"ミュケナイの王","exp":"1144"}],"1603":[{"type":"化石","name":"大きな魚のような石","rank":"1","desc":"魚によく似た形の石。ひれのようなものが確認できるが、どこか現在の魚とは違った印象を受ける。これが生きていた時代、魚はみなこのような形をしていたのだろうか。","note":"魚の石の地図","exp":"105"}],"2344":[{"type":"財宝","name":"古今和歌集","rank":"3","desc":"読みは、「こきんわかしゅう」。帝の命で編まれた最初の和歌集。「古今」という名には昔の和歌と今の和歌を集めたという意味がある。","note":"万葉集に次ぐ和歌集","exp":"460"}],"5110":[{"type":"港・集落","name":"ハンブルク","rank":"1","desc":"北ドイツの重要な交易港として栄えている都市。内陸に豊富な鉱脈があり、鉛、スズ、銅や鉄など、多種の鉱石が産出する。","note":"到達する","exp":"14"}],"5316":[{"type":"海洋生物","name":"アフリカハイギョ","rank":"5","desc":"アフリカ南部の湖沼に棲む魚。胸や腹のヒレがムチのような形をしている。時々水面で空気を吸う必要がある一方で、乾期に湖沼が干上がっても地中に潜って繭（まゆ）を作り、休眠状態で生き延びられる。","note":"","exp":"810"}],"3543":[{"type":"レリック","name":"ビザンツ帝国の女傑","rank":"","desc":"貧しい踊り子からビザンツ帝国の皇后にまで上り詰めたテオドラは、優れた助言者として皇帝を支える聡明な人物であったという。","note":"発見時経験値2820　発見名声1125","exp":"2820"}],"6278":[{"type":"宗教遺物","name":"チャンドラの仮面","rank":"2","desc":"インド神話の月の神であるチャンドラの顔をかたどった仮面。月光を思わせる色合いと、神話で伝えられている月の特性を表現した顔つきに作られる。仮面劇で使われたり、寺院や家庭に飾られたりするようだ。","note":"","exp":"240"}],"941":[{"type":"大型生物","name":"ライオン","rank":"5","desc":"百獣の王として有名な大型の猛獣。オスは、顔のまわりから首にかけて豊かなたてがみがおおっている。十数頭の群れで生活するが、一つの群れにオスは1頭しかいない。狩りは主にメスがやるといわれている。","note":"クエスト「百獣の王」<br/>発見物カード:520","exp":"1040"}],"6994":[{"type":"美術品","name":"トゲを抜く少年像","rank":"","desc":"足裏に刺さったトゲを抜こうとする少年をかたどった彫刻。紀元前一世紀ごろに作られたブロンズ像。息づくような繊細な表現は、後世に多くの芸術家を魅了し、模刻のみならず絵画の題材としても多く取り上げられた。","note":"","exp":""}],"6057":[{"type":"歴史遺物","name":"ベリサリウスの宝剣","rank":"2","desc":"東ローマ帝国の皇帝ユスティニアヌス1世の治世に活躍した将軍、ベリサリウスが愛用したという剣。\n彼は用兵の才に優れ、少数の騎兵でたびたび勝利を収めたが、晩年は不遇であったと伝えられている。","note":"","exp":"390"}],"1593":[{"type":"中型生物","name":"オオカワウソ","rank":"1","desc":"アマゾン川流域に生息する大型のイタチ。体長は1.5mにもなり、魚やカニなどを捕えて食べる。","note":"大型のイタチの地図","exp":"100"}],"3147":[{"type":"財宝","name":"赤毛のエイリークのサガ","rank":"2","desc":"ヴァイキングの英雄・赤毛のエイリークを中心とした物語。\nエイリークのグリーンランド移住と、侠気のソルフィンによる西方探索が描かれている。","note":"クエスト「航海者・ヴァイキング」<br/>発見物カード:195","exp":"390"}],"2365":[{"type":"植物","name":"ガクアジサイ","rank":"1","desc":"小さな花が密集して咲く、日本原産の植物。土壌や開花からの日数によって、花の色が変化する。\n大きな装飾花が中央の小さな花々を囲んでおり、額に入った絵画を思わせる。","note":"額縁がある花の地図","exp":"110"}],"6511":[{"type":"美術品","name":"オリンピアのニケ像","rank":"5","desc":"オリンピアのゼウス神殿にあったと思われる勝利の女神ニケの大理石像。顔と翼は失われているが、広げた両腕や翻る衣の美しい表現が特徴的。高い石柱の上に飾られていたと考えられている。","note":"レガシー競技の聖地オリンピア　右下","exp":"2805"}],"1057":[{"type":"美術品","name":"マグダラのマリア","rank":"2","desc":"ドナテッロ作の木像。マグダラのマリアは、回心してイエスに従った女性で、イエスの死後は何も身につけず山にこもったとされる。この像は年老いた彼女の姿で、通常は若く美しく表される宗教像と一線を画している。","note":"クエスト「老いた聖女」<br/><br/>発見物カード:140","exp":"280"}],"1710":[{"type":"宗教遺物","name":"維摩経","rank":"1","desc":"ゆいまきょう。仏教経典のひとつ。内容は般若経の多くに似通っているが、維摩と文殊菩薩の対話により究極の達成地を導き出すなど物語的な構成になっている。","note":"古い法典の地図","exp":"160"}],"1257":[{"type":"宗教遺物","name":"メソアメリカの祭器","rank":"1","desc":"土器で作られた祭器。メソアメリカでは信仰や祈祷、祭礼が非常に尊ばれており、このような祭器がたくさん見つかる。","note":"メソアメリカの祭器の地図","exp":"110"}],"5460":[{"type":"財宝","name":"アトランティスの未来","rank":"5","desc":"ジョン・トラデスカントが中心となってまとめた、アトランティス調査に関する書物。島が移動する仕組みの解説や、現地調査で裏付けられた滅亡の真実、思想などがまとめられている。ある一部の高等学術機関の所蔵となるそうだ。","note":"","exp":"930"}],"1625":[{"type":"鳥類","name":"キバタン","rank":"2","desc":"真っ白な羽で覆われた体に、黄色い冠羽を持つ鳥。興奮すると冠羽を立て、驚くほど大きな鳴き声を出す。大きな群れでは数百羽にもなる。","note":"白黒はっきり<br/><br/>文化貢献度30","exp":"320"}],"6006":[{"type":"小型生物","name":"ハリネズミ","rank":"1","desc":"背面にトゲが生えている小さな生物。目が小さく鼻がとがり、愛嬌のある顔をしている。捕まえようとすると、丸まってトゲだらけになる。動作は遅い。","note":"トゲだらけのネズミ","exp":"130"}],"46":[{"type":"海洋生物","name":"クマノミ","rank":"2","desc":"暖かい海に生息する、白いしまのある魚。イソギンチャクの毒が効かないようで、敵に襲われるとイソギンチャクの触手の間に隠れてしまう。なぜ毒が効かないのかは謎だ。","note":"イソギンチャクと暮らす魚","exp":"260"}],"1526":[{"type":"財宝","name":"ミステカの耳飾り","rank":"1","desc":"中米の中腹部に存在したといわれるミステカ民族の金の耳飾り。ヨーロッパの技術と比べても劣らない高い金加工技術を持っている。やはり、これだけのものを身に付けることができるのは王族だけだろう。","note":"金細工の地図","exp":"200"}],"3902":[{"type":"天文","name":"夏の大三角","rank":"1","desc":"ヨーロッパの夏の夜空でやや細長い三角形を作る三つの1等星。天の川にかかり、他の星や星座を探す目印となる。","note":"学生の観測記録","exp":"100"}],"2036":[{"type":"財宝","name":"黄金郷の長衣","rank":"2","desc":"黄金郷と思われる地に潜入した勇敢な冒険者が持ち帰ったローブ。良質な生地から作られ高い技術を有していることがわかる。","note":"［勅命］[[黄金郷の財宝探索","exp":"310"}],"1580":[{"type":"鳥類","name":"ヒクイドリ","rank":"5","desc":"体高が1.7mにもなる大きな鳥。体に対して翼が小さいため、飛ぶことができない。その代わりに脚力が発達している。それは、人を蹴り殺すほどである。","note":"姿を見せぬ生物","exp":"923"}],"2837":[{"type":"歴史遺物","name":"封泥","rank":"3","desc":"読みは「ふうでい」。書物などに封をする時に使用された粘土で、後漢まで続いた。\n開封する際は、この封泥を壊さなければならなかったため、他者に開封されることを防いだ。この封泥には皇帝信璽と書かれており、皇帝の印だと分かる。","note":"不可解な土塊","exp":"500"}],"3532":[{"type":"レリック","name":"ルキウス・ブルートゥス","rank":"","desc":"ローマの王政から共和政への転換期に活躍した「愚か者」。その真実の姿は私情を挟まない冷徹な改革者であった。","note":"","exp":""}],"1982":[{"type":"海洋生物","name":"ゴマフエダイ","rank":"1","desc":"熱帯のマングローブ林に多く見られるフエダイの仲間。体は赤く、鋭い歯を持っている。","note":"釣り","exp":"160"}],"6674":[{"type":"天文","name":"アルフェッカ","rank":"4","desc":"かんむり座で最も明るい星。名はアラビア語で「欠けたものの明るいもの」を意味する。別名のゲンマはラテン語で「宝石」を意味し冠の中央で宝石のように輝いている。","note":"発見物カード:320","exp":"640"}],"6109":[{"type":"宗教建築","name":"フマーユーン廟","rank":"5","desc":"ムガール帝国の第2代皇帝フマーユーンの墓廟で、彼が都と定めたデリーの郊外にある。インドにおけるイスラム建築の精華の一つであり、後のタージ・マハルにも影響を与えたほか、インドの庭園建築の原型になったともいわれる。","note":"クエスト「エデンへの憧れ」<br/>発見物カード:550","exp":"1190"}],"2251":[{"type":"鳥類","name":"吸血フィンチ","rank":"4","desc":"フィンチと呼ばれる小鳥の一種。特定の鳥の翼の付け根をつつき、流れ出る血を吸う習性がある。ガラパゴス諸島の一部の島に生息する。","note":"白い鳥と黒い鳥<br/><br/>発見時経験値620　発見物カード経験値310","exp":"620"}],"160":[{"type":"小型生物","name":"マダラサラマンドラ","rank":"1","desc":"黒い体にオレンジの模様があるイモリ。炎がちらついている模様に見えないこともない。ヨーロッパでも似たイモリを見かけるが、まだらが黄色い。","note":"サラマンダーを捕まえろ<br/>希少発見物らしいです。<br/>体験版では、「サラマンダーを捕まえろ」<br/>の紹介を受けれませんでした。","exp":"80"}],"648":[{"type":"地理","name":"ナイル川","rank":"1","desc":"アフリカを流れ、地中海に注ぐ大河。毎年決まった時期に大洪水を起こし、これによって流域に肥沃な土がもたらされる。非常に長い川で、水源を突き止めるのは至難の業だと思われる。","note":"書きかけの地図","exp":"90"}],"6572":[{"type":"史跡","name":"パフォスのモザイク","rank":"5","desc":"古代ローマの遺跡、パフォスにある建物跡から見つかったモザイクタイルの床。ギリシャ神話の英雄テセウスとミノタウロスが対決している様子を描いているとされる。他にもパフォスでは神話にまつわるモザイク画が多く見つかっている。","note":"追究クエスト","exp":"1000"}],"685":[{"type":"中型生物","name":"ボンゴ","rank":"5","desc":"大きい個体では400kgにもなる、大型のレイヨウ。濃いオレンジの地に真っ白なしまが十数本ある。深い森に住み、警戒心が強く、姿をなかなか見せないため生態はほとんどわからない。","note":"クエスト「森の中の巨大レイヨウ」<br/>発見物カード:520","exp":"1040"}],"3512":[{"type":"レリック","name":"ガウェイン","rank":"","desc":"勇猛果敢で直情径行の騎士ガウェイン。彼が自戒の念をこめて身に着ける帯が名誉ある勲章の由来だといわれる。","note":"","exp":""}],"5459":[{"type":"虫類","name":"グンタイアリ","rank":"5","desc":"中南米の熱帯雨林に多く生息するアリ。一般のアリとは異なり軍隊のように隊列を組んで移動する。性格は獰猛そのもので、昆虫や鳥類などに集団で襲いかかり、瞬く間に食い殺してしまう。","note":"肉食獣が恐れるアリ<br/><br/>発見時経験値820　発見物カード経験値410","exp":"820"}],"959":[{"type":"美術品","name":"船形器","rank":"1","desc":"ラピスラズリを削りだして作った器に、金やエマイユで装飾した調度品。石の削り出しはイタリアでなされたものだが、金属部分は何度も手直しされているようだ。","note":"宝石を削りだした器","exp":"115"}],"4837":[{"type":"史跡","name":"ハトラ","rank":"2","desc":"パルティア帝国の要塞都市。100を超える防御塔を有する堅固な造りで、ローマ帝国の攻撃を幾たびも防いだ。また、要塞内の都市にはイスラムの神殿とギリシャ神殿が並び立っているという特徴がある。","note":"神の家","exp":"300"}],"2106":[{"type":"美術品","name":"聖母被昇天（ルーベンス）","rank":"5","desc":"ルーベンス作の祭壇画の一枚。聖母マリアがその生涯を終え、天国へと昇る姿を描いた。天使たちに囲まれ天へと昇る姿はまさに聖母といえるだろう。","note":"少年が見たかったもの<br/><br/>発見時経験値1070　発見物カード経験値535","exp":"1070"}],"6464":[{"type":"海洋生物","name":"乾眠中のアフリカハイギョ","rank":"5","desc":"地中で粘液と泥の被膜に包まれた繭の状態のハイギョ。ハイギョの肺は成長に応じて発達し、呼吸の大半をエラではなく肺で行うようになる。そのため水のなくなる乾期には、泥の中で休眠して生き延びられる。","note":"追究クエスト<br/>発見物カード:840","exp":"1680"}],"6725":[{"type":"宗教建築","name":"ジェンネの大モスク","rank":"5","desc":"ニジェール川沿いの交易都市ジェンネに建つ大きなモスク。川を流れてきた泥をこねて日干しレンガを作り、それらを積んだ表面にさらに泥を塗って完成させた。屋内にも泥で作られた、畳1畳ほどの太さの柱が100本程度存在する。","note":"","exp":"550"}],"2741":[{"type":"財宝","name":"仏氏雑弁","rank":"1","desc":"政治家・鄭道伝による著書。鄭道伝は、朝鮮王朝の創始者である李成桂に重用された。\nこの著書によって、儒教を中心とした政策の基礎を確立させたという。","note":"貴重な書物の地図","exp":"140"}],"3292":[{"type":"地理","name":"タンメル湖","rank":"3","desc":"ブリテン島の北部に位置する、東西に延びた細長い湖。深い青の湖水の周りを、緑の木立や田園風景が取り巻いている。特に、北東岸からの景観がひときわ美しい。","note":"ブリテン島の保養地","exp":"510"}],"5816":[{"type":"地理","name":"エルズミーア島","rank":"2","desc":"カナダの最北に位置する島。世界最北の山脈を擁し、フィヨルドや氷河がいくつも存在する。","note":"","exp":"220"}],"460":[{"type":"小型生物","name":"キンモグラ","rank":"1","desc":"地中にトンネルを掘って住んでいる動物。目は小さく、あまり見えないようだ。前足の爪が大きく発達し、土を掘りやすい。","note":"金色の動物の地図","exp":"32"}],"6349":[{"type":"歴史遺物","name":"大灯台が刻まれたコイン","rank":"2","desc":"古代アレクサンドリアで製造されたコイン。世界七不思議のひとつとされるアレクサンドリア大灯台とともに、広く信仰された航海の守護女神イシスが刻まれたものなど、様々な意匠が凝らされたものがある。","note":"","exp":"300"}],"470":[{"type":"中型生物","name":"ツチブタ","rank":"2","desc":"細長い顔と長い耳にずんぐりした体の動物。動きは緩慢だが穴を掘るのは非常に素早い。舌がとても長く、これでアリを食べているようだ。","note":"穴を掘る動物の地図","exp":"210"}],"858":[{"type":"宗教遺物","name":"ンゲウォ像","rank":"5","desc":"アフリカのシエラレオネ付近に住む、メンデ人の神像。ンゲウォは天空神で、大地を妻とする。人の近くに住んでいたが、やがて離れたと言われる。","note":"天に帰った神","exp":"949"}],"1159":[{"type":"鳥類","name":"チュウハシ","rank":"2","desc":"鮮やかな色の長いくちばしが特徴。森林の周縁部に生息し、小さな集団で食事をしたり、身を寄せ合って眠ったりする。","note":"口論の原因","exp":"370"}],"5119":[{"type":"港・集落","name":"パリ","rank":"1","desc":"セーヌ川の中州であるシテ島から発展したとされる街。シテ島を囲むように城壁が築かれそれが拡大されて現在のパリとなった。気候は比較的温暖である。","note":"到達する","exp":"38"}],"1830":[{"type":"財宝","name":"キープ","rank":"3","desc":"インカ帝国の情報記録手段。紐に結び目を付けて数を表しているという。これを解読するには専門知識が必要だそうだ。また、これを送り届けるためのチャスキと呼ばれる飛脚がいた。","note":"責任と選択","exp":"600"}],"13":[{"type":"歴史遺物","name":"アトランティスの財宝","rank":"5","desc":"伝説のアトランティス大陸に栄えた文明の遺物だと思われるもの。精巧な細工も素晴らしいが、何より興味を引くのは、見たこともないような輝きを放つ地金である。","note":"アトランティスの財宝","exp":"822"}],"2868":[{"type":"化石","name":"目がくぼんだ魚の骨","rank":"1","desc":"黄河の近くで発見された、魚と思われる生物の骨。目のくぼみが大きいのが特徴。","note":"魚の骨の地図","exp":"160"}],"6771":[{"type":"植物","name":"シャビアナ・トラフルズ","rank":"5","desc":"メキシコの砂漠地帯に原生する、エケベリアの亜種。風通しがよく乾燥した地を好む。青灰色の葉がひだ上に重なり、葉の緑だけが桃色になっている。十分な日照を得ていると、より鮮やかに色づく。","note":"追究クエスト<br/>発見物カード:430","exp":"860"}],"2017":[{"type":"中型生物","name":"ハヌマンラングール","rank":"2","desc":"体の毛は灰色で、顔が黒いサル。それほど大きくないが、尾は体よりずっと長い。植物質のものしか食べないようである。インドではサルの顔の神・ハヌマーンの使いとして大事にされているためか、人間を恐れない。","note":"猿の神の使い","exp":"350"}],"586":[{"type":"財宝","name":"金象嵌の護符","rank":"1","desc":"「きんぞうがん」。金象嵌が施された大きな護符。かなり精密な細工が施されており、宗教的な意味はもちろん美術品としての価値も高い。","note":"豪華な宝石細工の地図","exp":"115"}],"1357":[{"type":"財宝","name":"魅惑の果実","rank":"5","desc":"淡い緑と鮮やかな赤が混在するトルマリン。その色味からスイカに例えられる。トルマリンは実にさまざまな色をもつ宝石であり、ひとつの原石に複数の色が混在しているものが多い。","note":"美しく奇妙な石","exp":"1170"}],"3877":[{"type":"大型生物","name":"アメリカバイソン","rank":"2","desc":"北米やカナダの西部に生息する大型のウシ。バッファローとも呼ばれる。断熱性に優れた毛皮が特徴で、先住民の生活と密接な関わりを持つ。","note":"北米の巨牛","exp":"300"}],"896":[{"type":"植物","name":"アナナス","rank":"4","desc":"長く固い葉を持つ植物である。厚い葉にはのこぎり状のトゲがあり中心から放射状に伸びている。茎はほとんどないようだ。花は中央に穂のようになって咲き、色鮮やかである。種類が多いようだ。","note":"南国の不思議な花","exp":"624"}],"446":[{"type":"中型生物","name":"マンドリル","rank":"4","desc":"1m近い大きさのサル。20頭ほどの群れで生活しているようだ。雌雄で見た目がかなり異なり、オスはとても派手な顔をしている。この顔と大きな声のためか地元では恐れられているようだ。","note":"クエスト「恐ろしい顔のサル」<br/>発見物カード:300","exp":"612"}],"216":[{"type":"歴史遺物","name":"オベリスク","rank":"1","desc":"エジプト文明で作られた、銘文が刻まれた細長い石柱。先端がとがった、特徴のある外観をしている。古代ローマでも作られた。","note":"とがった石柱の地図","exp":"40"}],"2408":[{"type":"小型生物","name":"イシカワガエル","rank":"3","desc":"奄美大島及び沖縄本島に生息するカエル。\n緑地に紫色の宝石をちりばめたような体は、日本で最も美しいカエルと呼ばれるにふさわしい。","note":"琉球のカエル","exp":"440"}],"6811":[{"type":"財宝","name":"ドレスデン絵文書","rank":"5","desc":"マヤの絵文書の写本。現存する南北アメリカの本の中で、最も古いとされる。マヤの信仰や暦法をはじめ、数学や農業、祭事、予言や世界の終末などについて記されている。","note":"発見物カード経験値:480","exp":""}],"2712":[{"type":"植物","name":"フキスミレ","rank":"1","desc":"朝鮮半島及び中国北東部にかけて生息する植物。日当たりの良い場所を好む。\n他のスミレ同様、花は素朴である。","note":"小さな花の地図","exp":"100"}],"5763":[{"type":"化石","name":"冷凍ライオン","rank":"2","desc":"冷凍されていた子どものライオン。他に同種のライオンが発見された報告はなく、いつからシベリアの地に眠っていたのかはわからない。","note":"2017.02.07新規追加","exp":"320"}],"602":[{"type":"財宝","name":"ピーコックカラー","rank":"5","desc":"虹色に輝く、最上級の黒真珠。真円でこの色を持つものは、非常に希少である。","note":"最高の黒真珠","exp":"990"}],"1633":[{"type":"小型生物","name":"ガラゴ","rank":"3","desc":"大きな後肢を持ち、ときには数メートルものジャンプをする。物をしっかりとつかむために、常に尿で手を湿らせている。普段は、小さな家族単位で生活している。","note":"闇夜の大騒動","exp":"451"}],"5378":[{"type":"歴史遺物","name":"クレタ島の陶器","rank":"1","desc":"古代のクレタ島で作られたとみられる陶器。風化のせいで色が薄くなってはいるが、よく見ればウシの絵が描かれているのがわかる。","note":"","exp":""}],"7025":[{"type":"小型生物","name":"マーブルキャット","rank":"5","desc":"東南アジアなどの熱帯森林に分布する小型のネコ。樹上で生活し、鳥類やリスなどを捕食する。斑点模様の厚く柔らかな体毛を持ち、背には特に大きい雲に似た形の斑点がある。体毛は黄褐色で、尾は体調に匹敵する長さがある。","note":"","exp":""}],"3575":[{"type":"レリック","name":"ベオウルフ","rank":"","desc":"叙事詩に描かれる剛勇無双の勇士ベオウルフ。体は年老いても、その心は衰えずドラゴンと死闘の末、壮絶な相打ちを遂げたという。","note":"","exp":""}],"4995":[{"type":"宗教遺物","name":"蛇使いの女神像","rank":"2","desc":"クレタ島で発見された女神像。両手に蛇を握り、帽子の上に獅子を乗せている。かつて女性と蛇は神聖であったという話や、蛇と獅子は地母神の象徴だったという話から、崇拝の対象であったことがわかる。","note":"","exp":"330"}],"5306":[{"type":"鳥類","name":"クラハシコウ","rank":"2","desc":"アフリカ中部から南部にかけての湿地に棲む大型の鳥。くちばしの付け根にある黄色の部分が馬の鞍を思わせる形のため、この名がついた。胸に羽毛のない部分があり、卵を温める際はそこを使うようだ。","note":"発見時経験値270　発見物カード経験値135","exp":"270"}],"6207":[{"type":"歴史遺物","name":"ウォレスの剣","rank":"2","desc":"スコットランド王国の騎士ウィリアム・ウォレスが使った大剣。彼は圧政を敷くイングランド王エドワード1世に抵抗した末、無残にも処刑されたという。剣の長さは大人の背丈ほどもあるため、彼自身もかなりの長身だったかもしれない。","note":"","exp":"270"}],"1981":[{"type":"海洋生物","name":"コブシメ","rank":"1","desc":"南洋にすむ大型のコウイカ。カメレオンのように周りの風景に同化する。","note":"釣り","exp":"160"}],"5821":[{"type":"宗教遺物","name":"出エジプト記","rank":"3","desc":"旧約聖書の第二の書。モーゼがイスラエル人を連れてエジプトを脱出した話が中心となっている。","note":"","exp":""}],"6795":[{"type":"天文","name":"アルシャイン","rank":"3","desc":"わし座の星の一つ。ワシの頭と体の中心であるアルタイルの間に位置する。名はペルシャ語で「襲う鷲」を意味しているともいわれ、元は星座全体を指す言葉であったという。","note":"","exp":""}],"3693":[{"type":"大型生物","name":"アムールトラ","rank":"5","desc":"ロシア東部の沿岸に生息する大型のトラ。\n周辺に生息する大型の草食動物を捕食する。クマでさえ捕食できるため、最強の動物のうちの一種と言えるかもしれない。","note":"寒冷地でのトラ調査<br/><br/>発見時経験値1090　発見物カード経験値545","exp":"1090"}],"2544":[{"type":"地理","name":"淡水河","rank":"2","desc":"淡水近くを流れる穏やかな川。\n豊かな水量を誇り、台湾島北部の主要な水源である。","note":"淡水付近の地理調査","exp":"250"}],"1331":[{"type":"地理","name":"マラッカ海峡","rank":"2","desc":"マレー半島と、スマトラ島の間に横たわる海峡。東西交易において重要な通過点となるが海峡の幅は狭く、その上水深が非常に浅い。さらに、暗礁や浅瀬も多いため、航行には細心の注意が必要だ。","note":"勅命クエスト「[香料諸島方面進出の要衝」<br/>勅命代替クエスト「東国へ続く狭き道」<br/>発見物カード:160","exp":"320"}],"1927":[{"type":"鳥類","name":"アナホリフクロウ","rank":"2","desc":"地中に巣がある珍しいフクロウ。主に、他の動物が掘った穴を利用して自分の巣を作る。また、長い脚でニワトリのように走る、昼に活動するなど、他のフクロウにはない特徴が多い。南北新大陸の草原に広く分布。","note":"地に棲む鳥","exp":"330"}],"2844":[{"type":"歴史遺物","name":"元戎","rank":"5","desc":"読み方は、「げんじゅう」。連弩と呼ばれる弩を改良して作られたもので、複数の矢を連射できるようになっている。\n三国時代の蜀の軍略家である諸葛亮が、魏に対抗するために発明したといわれる。","note":"もうひとつの連弩","exp":"1160"}],"5171":[{"type":"港・集落","name":"リオデジャネイロ","rank":"2","desc":"16世紀初頭、探検家ガスパール・デ・レモスによって発見され、大きな湾を河口と間違えて「一月の川」を意味する「リオデジャネイロ」と名づけられた。","note":"到達する","exp":"268"}],"4803":[{"type":"史跡","name":"クリフ・パレス","rank":"2","desc":"北米の先住民であるアナサジ族が築いたとみられる集落の跡。巨大な岸壁をくり抜いて造られている。","note":"岩窟遺跡の調査","exp":"260"}],"6792":[{"type":"天文","name":"や座のガンマ星","rank":"3","desc":"や座で最も明るい星。位置は矢尻部分にあたり、アルファ\n星のシャムよりも明るく、３等星である。","note":"視認","exp":""}],"907":[{"type":"植物","name":"スイセン","rank":"1","desc":"黄色や白の花が咲く、可憐な植物。球根で増えるため、よく群生している。かわいらしい姿に似合わず、かなり強い毒をもち、食べると死ぬこともある。","note":"白い花の地図","exp":"18"}],"6319":[{"type":"財宝","name":"被蓋造りの手箱","rank":"2","desc":"日本で作られた小箱。下の部分よりも上の蓋を大きく作ってかぶせる構造になっている。箱の表面は漆で加工され細やかな模様が描かれている。経典を入れる箱として使われることもあるという。","note":"","exp":"380"}],"3600":[{"type":"小型生物","name":"ウオクイコウモリ","rank":"3","desc":"中南米・カリブなどに生息するコウモリの一種。川や沼の小魚などを水面から捕食する。その食性のため、体臭が強いのも特徴。","note":"夜闇に響く水音<br/><br/>発見時経験値550　発見物カード経験値275","exp":"550"}],"5136":[{"type":"港・集落","name":"ベイルート","rank":"1","desc":"非常に古い時代から栄えていた街。内陸の都市の港として重要な街である。特に、ダマスカスから運ばれてくるダマスク織とダマスカスソードは、世界的に高く評価されている。","note":"到達する","exp":"43"}],"1678":[{"type":"小型生物","name":"ライオンタマリン","rank":"5","desc":"体長25cmほどしかない小型のサル。全身を金色の毛で覆われ、ライオンに似たたてがみを持つ。果実や花、昆虫などを食べる。","note":"金色のサル","exp":"1118"}],"6294":[{"type":"地理","name":"マウント・マンガヌイ","rank":"2","desc":"ニュージーランドの北島にある死火山。マオリの神話において、神聖な地とされている。","note":"「書きかけの地図(サンフランシスコ)」<br/>発見物カード:165","exp":"330"}],"5036":[{"type":"港・集落","name":"カラカス","rank":"2","desc":"南米東岸、マラカイボの東に位置する街。街の名前はこの地に住んでいたカリブ人・カラカス人に由来する。","note":"到達する","exp":"243"}],"4835":[{"type":"歴史遺物","name":"銅鼓","rank":"2","desc":"青銅で鋳造された打楽器。中国や東南アジアで広く出土している。演奏以外にも祭祀などで使用されていたようだ。","note":"楽山大仏 （上層隠し部屋）","exp":""}],"2409":[{"type":"虫類","name":"ヨナグニサン","rank":"4","desc":"インドから東アジアにかけて幅広く分布する大型のガ。日本が分布の最北端となる。\n口を持たず、羽化したあとは食事を一切取れない。","note":"虫の話の真偽","exp":"620"}],"5037":[{"type":"港・集落","name":"カリアリ","rank":"1","desc":"サルデーニャ島の南部にある街。地理的に多くの勢力の争いに巻き込まれやすく、支配勢力が次々に変わった。その結果、さまざまな文化が共存する街となった。","note":"到達する","exp":"27"}],"1631":[{"type":"鳥類","name":"カカポ","rank":"3","desc":"現地の言葉で「夜のオウム」を意味する鳥。飛ぶことができず、夕暮れ時になると活発に動き回る。","note":"夜のオウム<br/><br/>発見時経験値462　発見物カード経験値231","exp":"462"}],"3186":[{"type":"地理","name":"テラ・ノヴァ","rank":"5","desc":"新大陸北部にある島。夏でも山間部で雪が残るなど、冷涼である。近年ジェノヴァ生まれの航海者カボットが到達した。その五百年前にヴァイキングが到達したと伝わっている、「ヴィンランド（ぶどうの地）」と考えられる。","note":"ぶどうの地に見た未来","exp":"1230"}],"5786":[{"type":"化石","name":"冷凍マンモス","rank":"5","desc":"巨大な牙を持つ象のような生物が凍り付いた姿。いつからこの地に眠っているかはわからないが、その肉は食べられそうなほどの新鮮さを保っている。","note":"","exp":"1200"}],"6933":[{"type":"天文","name":"アルレシャ","rank":"3","desc":"うお座のアルファ星。4等星で、暗く目立たない。2匹の魚をつなぐリボンの結び目にあり、名はアラビア語で「紐」を意味する。","note":"発見物カード:225","exp":"450"}],"5658":[{"type":"小型生物","name":"サバクキンモグラ","rank":"4","desc":"アフリカ南部の砂漠に生息する動物。体調は8cm程度で、体つきは丸い。前足の長い爪で穴を掘る。夜行性で、目は退化している。","note":"","exp":"620"}],"2511":[{"type":"財宝","name":"東大寺香木","rank":"4","desc":"東大寺正倉院に収蔵されている、極上の香木の一つ。\n正倉院には、沈香・麝香・白檀など多くの香木が収められており、香だけでなく薬としても用いられていた。","note":"愛され尊ばれた香料","exp":"750"}],"6909":[{"type":"虫類","name":"アズチグモの雄","rank":"4","desc":"雄のアズチグモ。体長は約3mmと、雌と比べるとかなり小さい。褐色の体は、雌と異なり周囲の環境に合わせて変色することはない。雌に捕食されないよう腹部背面に乗る姿が見られる。","note":"","exp":""}],"1012":[{"type":"植物","name":"セントポーリア","rank":"2","desc":"アフリカ南部の奥地にのみ見られる小型の植物。崖の岩の隙間に根をはわせ、厚い肉質の葉と花を持つ。花弁は独特の光沢があり、美しい。変異株が多く見られるので、品種改良に適しているだろう。","note":"密林にひっそりと咲く花","exp":"250"}],"1343":[{"type":"虫類","name":"ギラファ","rank":"1","desc":"体長が10cmを超える大型の虫。頭部についた長いハサミは強力で、威嚇や攻撃に使用される。","note":"ハサミのある虫の地図","exp":"140"}],"6638":[{"type":"海洋生物","name":"ダイオウクラゲ","rank":"5","desc":"全長10m以上にもなるクラゲ。無脊椎動物では最大級。深海に潜んでいるため目撃情報はほとんどなく、幻のクラゲとして知られる。","note":"","exp":"1040"}],"1793":[{"type":"地理","name":"ポトシ銀山","rank":"5","desc":"膨大な埋蔵量を誇る銀山ではあるが、アンデス山脈の一角にあり、周囲には4000m級の山々が連なっている。そのため銀の採掘輸送は不可能に近いだろう。","note":"クエスト「それは皇帝の山」<br/>発見物カード:520","exp":"1040"}],"5782":[{"type":"宗教遺物","name":"運命の石板","rank":"5","desc":"メソポタミア神話において、神々の書記官ナブーが所持する石版。人類の運命が刻まれているとされている。それにしては小さく見えるが、やはり人間に理解できるようなものではないのだろう。","note":"書記官の石版","exp":"1380"}],"5000":[{"type":"地理","name":"コーカサス山脈","rank":"2","desc":"ギリシャ神話にも登場する巨大な山脈。黒海からカスピ海にかけて高山が連なっており、地域によって景観の変化が大きい。","note":"","exp":""}],"6053":[{"type":"美術品","name":"聖クリストフォロスのイコン","rank":"5","desc":"正教会圏で伝えられている、聖クリストフォロスを描いたイコン。伝承では犬頭の巨人だが、キリスト教に帰依し、後に殉教したという。ロシアでは「異教の影響を排除する」という理由で人型に描かれているようだ。","note":"","exp":"1040"}],"2734":[{"type":"歴史遺物","name":"彩色樹皮の馬具","rank":"3","desc":"白樺の皮で作られた、馬に装着する泥除け。よく見るとなにか描かれた形跡がある。おそらく鮮やかに彩色されていたのだろう。","note":"新羅遺物調査協力","exp":"500"}],"5092":[{"type":"港・集落","name":"ダンツィヒ","rank":"1","desc":"10世紀ごろに建設された都市。14世紀には、ハンザ同盟にも加入した。造船業が活発なため、造船都市としての地位を確立する。","note":"到達する","exp":"37"}],"1521":[{"type":"歴史遺物","name":"ゴムボール","rank":"1","desc":"古代の球技「トラチトリ」で用いられた総ゴム製のボール。非常に重く素手や生身では怪我をするため、「トラチトリ」は防具を身に付けて行われた。","note":"奇妙な塊の地図","exp":"110"}],"2100":[{"type":"宗教遺物","name":"ウパニシャッド","rank":"3","desc":"ヒンドゥー教の聖典の一つ。哲学を記したものであり、奥義書とも呼ばれている。\n師が弟子に物事を教示する様から、そのように呼ばれるようになったらしい。","note":"インドの奥義書","exp":"500"}],"1798":[{"type":"地理","name":"ダリエン山脈","rank":"1","desc":"南米大陸北西岸から中米にかけて走る山脈。高温多湿であり、山間部は常に霧に覆われた密林が広がっている。密林は蘭の花だけでも1000種以上という多様性をもつなど、まさに動植物の楽園である。","note":"書きかけの地図","exp":"160"}],"1124":[{"type":"小型生物","name":"ピパ","rank":"2","desc":"扁平な身体と、三角形の頭を持つ。メスは自分の背中の皮膚内で卵を育てる。約二ヵ月後に、子供は小型のカエルの姿で現れる。","note":"平たい生物の調査<br/><br/>発見時経験値355　発見物カード経験値177","exp":"355"}],"5116":[{"type":"港・集落","name":"バンジェルマシン","rank":"2","desc":"カリマンタン島南岸の港。14世紀にはマジャパヒト王国の支配を受ける。現在はイスラム教の影響下にある。郊外には先住民のダヤク民族が住んでいる。","note":"到達する","exp":"323"}],"3546":[{"type":"レリック","name":"ガリアの英雄","rank":"","desc":"ガリア人を率いて果敢にカエサル率いるローマ軍と対したウェルキンゲトリクスは、フランス最初の英雄といってよいだろう。","note":"","exp":""}],"2726":[{"type":"宗教建築","name":"新羅の石仏","rank":"2","desc":"新羅時代初期に作られたと思われる石仏。\n新羅では、仏教が盛んだったため、多くの石仏が残っている。朝鮮で最古の石仏とされるものは、鼻を削って飲めば病気が治るという伝承があり、鼻が欠けているらしい。","note":"ある船乗りの願い","exp":"260"}],"555":[{"type":"歴史遺物","name":"カラカラ帝の大理石像","rank":"1","desc":"カラカラ浴場で有名なカラカラ帝の大理石像である。弟をはじめとして政敵はことごとく殺し、絶え間なく戦争を起こしていた暴君である。","note":"古代ローマの暴君","exp":"90"}],"6298":[{"type":"地理","name":"ピオピオタヒ","rank":"2","desc":"ニュージーランドの南島にあり、タスマン海に面するフィヨルド。1000ｍを超える断崖絶壁に囲まれている。一年の半分以上は雨が降る土地であり、雨天時のみ形成される滝が数多くあるという。","note":"","exp":"380"}],"5893":[{"type":"財宝","name":"八塩折之酒","rank":"5","desc":"八頭八尾の竜が殺された、と伝わる場所に落ちていた酒。ずいぶん古いもののように見えるが、中の酒は嘘のように新鮮なままである。","note":"極東のドラゴンスレイヤー","exp":"1360"}],"3813":[{"type":"史跡","name":"カンペチェ要塞","rank":"4","desc":"メキシコ湾に面する貿易港であるカンペチェに築かれた要塞。海賊の襲撃に対する防衛を目的としている。","note":"カンペチェ湾の要塞","exp":"680"}],"2652":[{"type":"中型生物","name":"チンドケン","rank":"4","desc":"朝鮮半島周辺地域によく見られる中型犬。朝鮮の珍島が発祥であるらしく、その名が付いている。\nくるんと巻かれた尾が愛らしい。","note":"自慢のイヌ","exp":"620"}],"3912":[{"type":"天文","name":"小マゼラン星雲","rank":"1","desc":"南半球で見られる星雲で、大マゼラン星雲よりやや暗い。肉眼で見られる。天の南極に近い場所にあるため、北半球では低緯度地帯でしか見られない。","note":"「天文学者の観測記録」<br/>発見物カード:95","exp":"190"}],"6995":[{"type":"地理","name":"洞庭湖","rank":"2","desc":"華南の長江中流にある淡水湖。長江と繋がっており、広大な面積を誇る。その姿は「八百里洞庭」と称えられ、古代から詩歌や神話によく登場した。長江との合流地点では、水の色がくっきりと分かれて見える。","note":"","exp":""}],"1959":[{"type":"宗教遺物","name":"マケマケ像","rank":"2","desc":"マケマケとはラパ・ヌイでモアイ以前より信仰されていた神であるようだ。マケマケの化身である鳥人（タンガタ・マヌ）の称号を得た者が島の全権を有することから、ラパ・ヌイで崇められている神の中で、中心的な存在であるといえる。","note":"古代神の復活","exp":"350"}],"2811":[{"type":"歴史遺物","name":"渾天儀","rank":"1","desc":"読み方は、「こんてんぎ」。後漢時代に発明された天体観測機器。三つの円盤を組み合わせてあり、それぞれに細かく角度目盛が刻まれている。これにより天体の天球上の位置を読み取れる。","note":"古代の道具の地図","exp":"190"}],"1439":[{"type":"化石","name":"美しい貝の石","rank":"4","desc":"貝殻が宝石となったもの。白や黒など、さまざまな色がある。","note":"貝の宝石","exp":"624"}],"6697":[{"type":"気象・現象","name":"馬蹄雲","rank":"3","desc":"馬の蹄のようなU字型の雲。積雲が消えかけているときにできやすい。出現して数十秒で形を変えて消えてしまうことが多い。","note":"","exp":"530"}],"5916":[{"type":"海洋生物","name":"レッドテールキャット","rank":"2","desc":"アマゾン川に分布するナマズの仲間。赤味を帯びた尾びれを持つことから、この名で呼ばれている。大きな口と6本のヒゲが特徴で、成長すると1mを超えることがある。","note":"アマゾン川流域  14132,4952","exp":"390"}],"2992":[{"type":"中型生物","name":"カミツキガメ","rank":"2","desc":"体長が40cmを超える、大型のカメ。でっぷりとしているため、さらに大きく見える。空腹時には粗暴な性格になるため、注意が必要。","note":"凶暴そうな生物の地図","exp":"220"}],"265":[{"type":"地理","name":"マン島","rank":"1","desc":"アイリッシュ海北部に浮かぶ島。気候が穏やかなためか古代から人が住み、耕地が多い。ここにしかいない、尾のない猫が見られる。住人はケルト系の独特の言語を話す。","note":"ブリテン西の小島","exp":"70"}],"4980":[{"type":"植物","name":"アカンサス","rank":"1","desc":"地中海沿岸に分布する草花。光沢のある深緑色の葉で長さは60cm以上にもなる。古代ギリシャでは神聖な草花とされ、神殿の柱に彫刻された。","note":"","exp":"150"}],"1447":[{"type":"中型生物","name":"ウォンバット","rank":"4","desc":"地中に掘った穴をすみかとする有袋類。土が入らないように袋は後ろ向きについている。力が強く、ときに捕食者を殺すこともある。","note":"最強のモグラ","exp":"636"}],"5868":[{"type":"天文","name":"きょしちょう座","rank":"5","desc":"南天の星座の一つ。16世紀に制定された。元となる巨嘴鳥(きょしちょう)はオオハシ科の鳥類だとされるが、複数人が制定に携わったためか、モチーフとなった鳥にも複数の説があるようだ。","note":"クエスト「新大陸の鳥の星座」<br/>発見物カード:670","exp":"1340"}],"3327":[{"type":"歴史遺物","name":"古代ギリシャ軍の三段櫂船","rank":"4","desc":"ペルシャ戦争において古代ギリシャ軍が使用したとみられる船。櫂が三段に配置されており、ペルシャの大艦隊を翻弄したという高い機動力がうかがえる。","note":"サルベージ","exp":"610"}],"1141":[{"type":"大型生物","name":"ナマケグマ","rank":"5","desc":"ずんぐりとした体と、力強い四肢を持つ。長くて粗い毛に覆われていて、爪は大きく、胸に独特の白い模様がある。果実などを食べて生活している。","note":"夢を結ぶ旅路は長く","exp":"1222"}],"5295":[{"type":"鳥類","name":"ウシツツキ","rank":"3","desc":"サハラ以南のアフリカに棲む小鳥。哺乳類の皮膚に巣食う寄生虫などをエサにしているためか、大型動物の背中などによく止まっており、尻尾に追い払われず共存している。","note":"","exp":"600"}],"416":[{"type":"化石","name":"二本足のトカゲの骨","rank":"1","desc":"大きなトカゲの骨の模様の石。二本足で立っていたと思われる。人間より小さいが、もし襲われたら無事ではすまないだろう。こんな生物がどこかにいるのだろうか？","note":"奇妙な石の地図","exp":"34"}],"4810":[{"type":"財宝","name":"村正","rank":"","desc":"","note":"安土城（深層隠し部屋）","exp":""}],"614":[{"type":"歴史遺物","name":"クフ王の象牙の像","rank":"1","desc":"ギザの第1ピラミッドの主である、クフ王の姿を彫った象牙の小さな像。クフ王の姿を表した物は、ほかに見つかっていない。","note":"姿の見えないファラオ","exp":"180"}],"282":[{"type":"美術品","name":"プリマヴェーラ","rank":"4","desc":"ボッティチェリ作の絵画。中央にヴィーナスとキューピッド、右にはゼフュロスに息を吹きかけられた女神フローラが、左には美・貞節・愛の三女神とメルクリウスが描かれている。","note":"ボッティチェリの傑作","exp":"708"}],"2271":[{"type":"史跡","name":"ヤシ油製造場跡","rank":"3","desc":"儀式に使用されていたヤシ油を製造するための場所。石の台の上で作られたヤシ油は、使用しないときもこの場所に保管される。","note":"誘いの甘い香り<br/><br/>発見時経験値490　発見物カード経験値245","exp":"490"}],"6189":[{"type":"財宝","name":"二重信仰についての論文","rank":"5","desc":"匿名で書かれた、ロシアの二重信仰に関する記録。著者はロシアの聖職者らしい。ウラジーミル1世が異教の神殿跡を教会に転用していった経緯や、異教の習慣を教会内に取り入れた例などの興味深い報告が記載されている。","note":"","exp":"1310"}],"264":[{"type":"地理","name":"サンマロ湾","rank":"1","desc":"コタンタン半島とブルターニュ半島に挟まれた湾。緯度が高いわりに温暖で、沿岸は保養地として古くから知られる。","note":"フランス北西部の海岸線","exp":"20"}],"530":[{"type":"歴史遺物","name":"古代の陶器","rank":"1","desc":"土の素地に釉薬（ゆうやく）をかけて焼いた器。技術が発達してくると、さまざまな色の物や、彩色した物が出てくる。","note":"古代の道具の地図","exp":"51"}],"3927":[{"type":"天文","name":"りょうけん座の親子星雲","rank":"2","desc":"りょうけん座にある星雲。渦巻きのような形をした、大小ふたつの星雲がつながって見える。","note":"「天文学者の観測記録」<br/>発見物カード:140","exp":"280"}],"15":[{"type":"歴史遺物","name":"リディアの貨幣","rank":"1","desc":"アナトリア半島の古代国・リディアのものと見られる貨幣。有史で最古の貨幣鋳造と思われる。","note":"アナトリア半島の古い文明","exp":"180"}],"660":[{"type":"小型生物","name":"モモンガ","rank":"1","desc":"頭から尾の先までが20cmあまりの、小型のリスの仲間。前足と後足の間に飛膜があり、木から木へ滑空する。黒い大きな目と長めの毛が愛らしい。","note":"小さな空飛ぶリス","exp":"30"}],"6431":[{"type":"歴史遺物","name":"ガリレオの軍事コンパス","rank":"2","desc":"ガリレオ・ガリレイが発明した、あらゆる内径の大砲と砲弾に対して火薬量を決定できる計算機。種々の計算、分度器、天体観測などに使用できたと言われる。パドヴァ大学教授時代のガリレオはこのコンパスで収入を得ていたという。","note":"","exp":"280"}],"4794":[{"type":"鳥類","name":"ベニハワイミツスイ","rank":"2","desc":"ハワイ諸島に生息する鳥で、大きさはスズメ程度。花の蜜を餌とする。現地ではイーウィと呼ばれ、その羽毛は支配者の衣服の飾りとして使われる。","note":"真紅の鳥","exp":"260"}],"6961":[{"type":"美術品","name":"卓上のヘラクレス","rank":"5","desc":"リュシッポスの作品を精巧に複製したブロンズ像。リュシッポスは古代ギリシャ美術の三大彫刻家の一人で、アレクサンドロス大王のためにブロンズ像を制作した。この彫像にも生き生きとした躍動感があり、原作の秀逸さをうかがえる。","note":"発見物カード:410","exp":"820"}],"1242":[{"type":"小型生物","name":"メキシコサンショウウオ","rank":"2","desc":"この生物は、完全に成体に成長することなく繁殖する。平たい尾と赤く大きな外鰓（がいさい＝羽状のエラ）を持つ。","note":"贈り物には","exp":"365"}],"5990":[{"type":"天文","name":"ティターニア","rank":"4","desc":"天王星の最も大きな衛星。妖精の女王であるティターニアの名を冠している。なお、この名は衛星の発見者の死後、その息子が付けたものである。","note":"中央大西洋<br/>18世紀-3では発見できないため装備品必須<br/>×：16世紀・紀元前","exp":"710"}],"2421":[{"type":"海洋生物","name":"アカメ","rank":"2","desc":"土佐沖から九州の東沿岸周辺とかなり狭い地域にのみ生息する魚。1mを超える大型魚だが外洋よりも河口付近での生活を好む。\n光の当たる角度によって目が赤く見えることからこの名が付いたといわれる。","note":"釣り","exp":"330"}],"5818":[{"type":"財宝","name":"金瓶梅","rank":"5","desc":"明代の通俗小説。水滸伝の番外編的作品であり、当時の生活や文化が窺い知れる緻密な描写が評価されている。","note":"","exp":"1370"}],"1769":[{"type":"小型生物","name":"マーラ","rank":"2","desc":"南米の草原に生息するネズミ。ぴょんぴょん飛び跳ねて移動する。オスとメスは常に行動を共にし、一生つがいのままである。\nまた、オスはメスに対して、とても従順である。","note":"［勅命］[[新大陸西岸方面の動物探索","exp":"310"}],"706":[{"type":"化石","name":"二本足のドラゴンの骨","rank":"4","desc":"鼻先から尾の先までが10mを超える、巨大な生物の骨。石化している。頭だけで大岩ほどもあり、口にはナイフのような歯が並ぶ。これが生きていて、伝説の通り炎を吐いたりしたら、街の一つくらい簡単に消え去ることだろう…。","note":"人間のように歩くドラゴン","exp":"744"}],"6178":[{"type":"小型生物","name":"マスクラット","rank":"4","desc":"体長は30センチほどあり、げっ歯類としては大きめ。主に沼に生息している。新大陸北の先住民たちに伝わる創世神話によると、マスクラットが原始の海の底に飛びこんで、大地のかけらを持ってきたという。","note":"","exp":"780"}],"2315":[{"type":"地理","name":"紀伊山地","rank":"2","desc":"日本の紀伊地方に存在する霊場及びその山々の総称。\n地形が険しいため、山岳仏教や修験道（しゅげんどう）を信仰する僧侶の修行の場として栄えている。","note":"［勅命］[[島国にある山の調査","exp":"270"}],"1844":[{"type":"財宝","name":"新婚用サリー","rank":"2","desc":"一枚布を体に巻き付けるようにして着るインド女性の服。インドには、新婚の妻は赤いサリーしか身にまとってはならないというしきたりがある。","note":"新妻の証","exp":"230"}],"6074":[{"type":"宗教遺物","name":"パナギア","rank":"1","desc":"生神女であるマリアやキリストのイコンが描かれた首飾り。　マリアの称号の一つであり、ギリシャ語で「完全な聖」を意味する「パナギア」の名で呼ばれ、正教会では主教以上の聖職者が身につけるという。","note":"『生神女』は『しょうしんじょ』と読む。","exp":""}],"788":[{"type":"宗教建築","name":"コナーラクの車輪","rank":"1","desc":"コナーラクの太陽神寺院の基壇（きだん）部分にある車輪。寺院全体が馬車に見立てられている。この馬車に乗り、太陽神スーリヤが天を翔けると言われている。","note":"クエスト「太陽神の馬車」<br/>発見物カード:75","exp":"150"}],"900":[{"type":"歴史遺物","name":"エジプトの和平交渉文書","rank":"5","desc":"ラムセス2世がヒッタイトと戦ったカデシュの戦いについて書かれた文書。エジプト優勢で終わった戦いに、ヒッタイト側から和平の申し出があり、それを受諾したことが書かれている。","note":"覇権を賭けた大戦","exp":"962"}],"776":[{"type":"海洋生物","name":"大カジキ","rank":"3","desc":"カジキは遠洋性の大型魚だが、この個体は並外れて大きい。口吻部が固くとがっている上に高速で泳ぐため、船に衝突すると沈没させられる。捕らえるのはとても無理だろう。","note":"クエスト「船ほどもある巨大魚」","exp":"484"}],"5134":[{"type":"港・集落","name":"プリマス","rank":"1","desc":"イングランド南西部にある港町。イングランドにとって重要な位置にあるため、栄えている。産物は各種鉱石が中心で、特に石墨は重要な交易品である。","note":"到達する","exp":"21"}],"2561":[{"type":"植物","name":"タカサゴユリ","rank":"3","desc":"台湾島の山地で多く見かけられる、花の外側が赤く染まっている植物。\n一年ほどで開花するため、荒地などでもよく繁殖している。","note":"荒地に咲くユリ","exp":"460"}],"5163":[{"type":"港・集落","name":"モザンビーク","rank":"1","desc":"アフリカ南東岸に位置する街。天然の良港でアフリカ東部の交易拠点として栄えてきた。耕作が盛んでさまざまな産物が流通するほか鉱山資源が非常に豊富である。","note":"到達する","exp":"77"}],"5522":[{"type":"地理","name":"マージー川","rank":"1","desc":"イングランド北西部を流れる川。マンチェスターなどの用水に利用され、運河が建設されると、水運でも工業発展を支えた。","note":"","exp":"100"}],"6477":[{"type":"歴史遺物","name":"巨像の灯火皿","rank":"5","desc":"ロードス島の巨像が右手に掲げていたという巨大な灯火皿。伝説では精妙な機構が組み込まれ、敵に煮えたぎった油を注ぎかけて撃退したという。また巨像の頭の内部に灯火が設置され、両眼から光を発していたという説もある。","note":"レガシー　港湾都市ロードス　右上","exp":""}],"2080":[{"type":"虫類","name":"チリアンコモン","rank":"3","desc":"南米に生息するクモ。茶色い姿で地味な印象があるが、脱皮直後はとても美しい。\n比較的おとなしい性質である。","note":"毒グモの魅惑","exp":"490"}],"3252":[{"type":"地理","name":"レトバ湖","rank":"4","desc":"西アフリカに位置する湖。海水より塩分の濃度が高い塩湖である。ピンク色の湖水をたたえており、水量の減る乾季にはその色がより鮮やかになる。","note":"バラ色の湖","exp":"620"}],"262":[{"type":"歴史遺物","name":"フラガラッハ","rank":"5","desc":"ケルト神話の太陽神・ルーの物だといわれる魔剣。ひとたびさやから放たれると、この刃から逃れられる者はいないという。","note":"フラガラッハ","exp":"1183"}],"2963":[{"type":"鳥類","name":"ノーザンカーディナル","rank":"2","desc":"北米東部でよく見られる赤い鳥。オスは真っ赤な羽毛だが、メスは茶色だという。","note":"羽ばたく真紅","exp":"370"}],"2364":[{"type":"宗教遺物","name":"式神札","rank":"4","desc":"式神を呼ぶための札。式神とは、陰陽師の命令で不思議な現象を起こすとされる霊的存在のこと。｢式｣とは｢用いる｣の意味である。昔、陰陽道を極めたある人物は、この札を使いさまざまな式神を呼び出せたというが…。","note":"命を与えられた紙片","exp":"690"}],"5845":[{"type":"天文","name":"南のコールサック","rank":"4","desc":"「石炭袋」の名を持つ暗黒星雲。みなみじゅうじ座の近くに見ることができる。天の川を背景にしているため、肉眼でも観測できる場合がある。","note":"クエスト「空に浮かぶ黒い筋」<br/>発見物カード:350","exp":"700"}],"2894":[{"type":"美術品","name":"内経図","rank":"3","desc":"人体の側面を山水画のように描いたもので、内丹術と呼ばれる道教の修行法を絵画化したもの。\n動物や天体が象徴的な意味を持って人体図に配置されている。","note":"体内の風景","exp":"440"}],"6058":[{"type":"鳥類","name":"オシドリ","rank":"4","desc":"東アジアから東南アジアにかけて生息している鳥で、オスの鮮やかな体色が特徴的。漢名「鴛鴦（えんおう）」のうち「鴛」がオス、「鴦」がメスを指す。中国や朝鮮半島、日本では仲睦まじい夫婦の象徴とされている。","note":"","exp":"700"}],"357":[{"type":"植物","name":"ホウオウボク","rank":"2","desc":"マダガスカル島に多く見られる落葉樹。開花時期には真っ赤な花が木をおおいつくし、まるで炎が燃え上がっているようである。","note":"炎の大樹","exp":"280"}],"2830":[{"type":"財宝","name":"水滸伝","rank":"4","desc":"民衆によく読まれていた明代の通俗小説。\n108人の好漢たちが築いた要塞に集まり悪徳官吏を打倒し、国を救わんとする物語。","note":"明の民に好まれる本","exp":"660"}],"1950":[{"type":"植物","name":"ジャカランダ","rank":"1","desc":"南米の熱帯に原生する紫色の花の木。大きいものは15mにもなる。開花の頃には木全体が薄紫になる程、多くの美しい花を咲かせる。花名はスペイン語で、「楽しい歌」の意味。","note":"鮮やかな花の地図","exp":"160"}],"2891":[{"type":"地理","name":"盤山","rank":"2","desc":"自然の山水や仏教の寺院が有名な、黄河下流域北方にそびえる山。松の木からなる景色、美しい水の景色など、どこを見ても魅惑的な景観を有している。","note":"書きかけの地図","exp":"350"}],"3202":[{"type":"財宝","name":"メディチ家処方箋","rank":"5","desc":"薬に関する商売を行っていたメディチ家秘蔵の処方箋。ハーブや野生の薬草、木の皮等を使った薬の調合法が記されている。","note":"薬と毒薬","exp":"940"}],"118":[{"type":"宗教遺物","name":"アテナ像","rank":"1","desc":"ギリシャ神話の女神の像である。アテナは産業、芸術、知恵、戦争の女神であり、ローマ神話ではミネルヴァという。都市国家アテナイの守護神であり、アテネのパルテノン神殿はアテナの神殿だ。","note":"ギリシャの女神像の地図","exp":"30"}],"7030":[{"type":"宗教遺物","name":"ダルマの石柱の獅子柱頭","rank":"2","desc":"アショーカ王の命で造られ、石柱の最頂部に飾られていた柱頭。四頭の獅子が座る台座には、ゾウやウマなどの動物とともに、法輪が浮き彫りされている。そのさらに下には、逆さまの蓮の花を模した装飾が見られる。","note":"","exp":""}],"768":[{"type":"宗教遺物","name":"オリンピアのヘルメス像","rank":"1","desc":"オリンピアのヘラ神殿にあったというヘルメスの像。幼児のディオニソスを抱いている。当時最高の彫刻家とされたプラクシテレスの作だといわれる。","note":"赤子を抱く神像","exp":"100"}],"6993":[{"type":"歴史遺物","name":"ヘラクレアの青銅板","rank":"5","desc":"ローマの古代都市ヘラクレアの自治法規が刻まれた、二枚の青銅板碑文。ギリシャ語とラテン語が用いられ、内容は道路や土地の区分から、集会の規則などにまで多岐にわたり、ローマ法の強い影響が随所にみられる。","note":"レガシー法の叡智・正義の象徴　右上","exp":""}],"6034":[{"type":"歴史遺物","name":"東ローマ書記官の手記","rank":"1","desc":"ビザンツ帝国の書記官が遺した手記。著者はビザンツ皇帝コンスタンティノス11世と共にコンスタンティノープル陥落戦で戦死したらしい。皇帝がオスマントルコのメフメト2世に徹底抗戦の意志を表明したときの言葉が記されている。","note":"","exp":"100"}],"4959":[{"type":"史跡","name":"アポロ・エピクリウス神殿","rank":"1","desc":"ペロポネソス半島中央部の山中にある神殿。ギリシャ神話の太陽神アポロンのために造られたといわれている。古代ギリシャにおける三つの主要な建築様式が用いられており、現地で採れる青みを帯びた方解石が素材となっている。","note":"","exp":""}],"2263":[{"type":"鳥類","name":"アオアシカツオドリ","rank":"3","desc":"鮮やかな青い足が特徴の体長80cmほどの鳥。オスがメスに向かって足を交互に持ち上げたり、翼を広げたりして興味をひく様が見られる。主にガラパゴス諸島に生息する。","note":"クエスト「可愛い変わり者」<br/>発見物カード:245","exp":"490"}],"5622":[{"type":"地理","name":"セントローレンス島","rank":"4","desc":"ベーリング海峡の南にある島。多くの海鳥やセイウチなどの動物の生息地となっている。","note":"クエスト「ベーリング海峡付近の地理調査」<br/>発見物カード:325","exp":"650"}],"2352":[{"type":"地理","name":"紀伊山地","rank":"2","desc":"日本の紀伊地方に存在する霊場及びその山々の総称。\n地形が険しいため、山岳仏教や修験道（しゅげんどう）を信仰する僧侶の修行の場として栄えている。","note":"［勅命］[[島国にある山の調査","exp":"270"}],"3002":[{"type":"地理","name":"プリンスエドワード島","rank":"1","desc":"北米に浮かぶ島。気候は温暖で肥沃な大地を持つ。その昔、島の南側は大陸と陸続きだったといわれている。","note":"書きかけの地図","exp":"190"}],"1272":[{"type":"美術品","name":"ゴリアテの首を持つダヴィデ","rank":"2","desc":"グイド・レーニ作。羊飼いのダヴィデが、巨人ゴリアテを投石器で倒し、その首をとるという聖書の一節を表現している。古典的な構図でありながら、レーニの独特の斬新な表現を垣間見ることができる。","note":"クエスト「闘士の首を持つ男」<br/>発見物カード:170","exp":"340"}],"6996":[{"type":"財宝","name":"カルナイ","rank":"2","desc":"中央アジアの伝統的な管楽器。銅あるいは真鍮でできた、非常に長い管を持つ。形状は直線や曲線、幅の広いものがあるが、いずれも一音だけを奏で、太鼓や弦楽器など他の楽器と合わせて演奏する。","note":"","exp":""}],"6379":[{"type":"財宝","name":"ピリー・レイスの地図","rank":"5","desc":"オスマントルコの海軍軍人、ピリー提督が作成した世界地図。地図の製作にあたり他の地図を多く参考にしたという。やがて、この地図は「征服者」の異名を持つメフメト2世の孫であるセリム1世へと献上された。","note":"","exp":"1060"}],"364":[{"type":"宗教遺物","name":"オニャンコポン像","rank":"4","desc":"西アフリカのアシャンティ人の神の像。万物の創造者である。かつては地上に住んでいたが、やがて天上に住むようになったと伝えられる。","note":"黄金に彩られた民族","exp":"696"}],"5004":[{"type":"天文","name":"こと座流星群","rank":"2","desc":"こと座に放射点がある流星群で、毎年4月に極大期を迎える。また非常に古くから知られており、最も古い観測記録は紀元前までさかのぼる。","note":"発見物カー:175","exp":"350"}],"150":[{"type":"歴史遺物","name":"ケルトの装身具","rank":"1","desc":"ケルト民族が使っていた装身具。金を多用し独特の文様や形態のものがある。","note":"ケルト遺物の地図","exp":"24"}],"3657":[{"type":"宗教遺物","name":"ローマのカタコンベ","rank":"2","desc":"ローマの城壁外にある地下墓地などの遺跡。ローマ帝国によるキリスト教弾圧から逃れるため、キリスト教徒たちは地下道を掘り、墓地や集会所として利用していた。その長さは20kmにも及ぶという。","note":"ダンジョン","exp":"374"}],"779":[{"type":"財宝","name":"三大陸周遊記","rank":"1","desc":"イブン・バットゥータ著のイスラム世界最大の旅行記。アフリカ、インド、中国まで踏破し、その様子をよく伝えている。","note":"壮大な旅行記","exp":"110"}],"653":[{"type":"地理","name":"ロカ岬","rank":"1","desc":"リスボンの北に突き出した岬。イベリア半島の最西端にあたる。リスボンを出て、この岬を回るとオポルトだ。","note":"書きかけの地図","exp":"20"}],"6827":[{"type":"中型生物","name":"アライグマ","rank":"3","desc":"北米の森林や湿地などに広く生息する動物。体毛は灰褐色で、目の周囲と頬が黒い。足先の指が長く、器用に物を掴むことができる。太く長い尾には、黒い縞模様が入っているのが特徴。","note":"発見物カード:260","exp":"520"}],"870":[{"type":"地理","name":"ハドソン川","rank":"2","desc":"北米大陸東部を流れる大河。流れが緩やかで航行に適しているため地域の重要な交通路である。","note":"土地開発の期待","exp":"370"}],"6539":[{"type":"伝承","name":"シルフ","rank":"5","desc":"風の精。四大元素のうち、風をつかさどるとされる精霊。大気の流れに乗って世界中を飛び回っている。細身の美少女の姿をしているらしいが、透明であるため視認できない。一説では、虚栄心が強い女性の死後の姿だともいわれる。","note":"","exp":"1060"}],"6140":[{"type":"歴史遺物","name":"カエサリオンの大理石像","rank":"1","desc":"ユリウス・カエサルとクレオパトラ7世の間に生まれた、カエサリオンの大理石像。一時はカエサルの後継者と認められたが、クレオパトラの死後、殺されたという。","note":"クレオパトラの息子","exp":"100"}],"641":[{"type":"美術品","name":"聖母被昇天（ティツィアーノ）","rank":"4","desc":"ティツィアーノ作の巨大な祭壇画。まさに天に引き上げられようとするマリアは、それまでの聖母とまったくことなる、生き生きとした生身の女性として描かれている。この絵をきっかけに、ティツィアーノは大成功した。","note":"出世作","exp":"624"}],"2714":[{"type":"植物","name":"カラムラサキツツジ","rank":"1","desc":"主に朝鮮に生息する、春に桃紫色の花を咲かせる植物。\n春告げの花として人々に慕われている。","note":"紫色の花の地図","exp":"180"}],"3822":[{"type":"海洋生物","name":"イエロースティングレイ","rank":"3","desc":"カリブ海などに生息するエイの一種。体は円形に近く、尾は短い。体表の斑模様が特徴。","note":"斑模様のエイの地図","exp":"470"}],"5022":[{"type":"港・集落","name":"アントワープ","rank":"1","desc":"ネーデルラント南部十州の中でもっとも栄えている都市。海運が盛んで、かつては北欧交易の中心地であった。近年、アムステルダムにその地位を奪われつつある。レースや高級家具、油彩画が扱われている。","note":"到達する","exp":"16"}],"1896":[{"type":"歴史遺物","name":"ピンソンの探険船","rank":"1","desc":"南アメリカへの航海を行ったビセンテ・ピンソンの船団に属していたキャラベル。セントロシェ岬への到達後、ウィンドワード海峡を経てパロスへ向かう途中、嵐に襲われて難破した。","note":"サルベージ","exp":"150"}],"1312":[{"type":"鳥類","name":"カラカラ","rank":"3","desc":"胸元と背中にある細い縞模様と、オレンジ色の顔が特徴。日常の大半は地面を歩いて過ごす。獲物は腐肉、魚、野菜、昆虫などなんでも食べる。","note":"鳥の後を追う鳥","exp":"506"}],"5542":[{"type":"気象・現象","name":"ポロロッカ","rank":"4","desc":"海から河口へと波が押し寄せる現象。主にアマゾン川などで発生する。潮の満ち引きが原因と考えられている。「ポロロッカ」は現地では「大騒音」を意味する。","note":"","exp":"680"}],"3747":[{"type":"天文","name":"アルクトゥルス","rank":"3","desc":"うしかい座で最も明るい、オレンジ色の1等星。北斗七星のひしゃくの柄の部分を伸ばすように線を引いた先にある。名はギリシャ語の「熊を守るもの」という語に由来する。スピカとともに夫婦星と呼ばれることもある。","note":"オレンジ色の明るい星","exp":"510"}],"6627":[{"type":"地理","name":"五花海","rank":"5","desc":"九寨溝でも屈指の景観を誇る巨大な湖。石灰化した成分が湖底に沈んでいる。日光が差し込むと、反射によって青やオレンジ、紫などさまざまな色を放つ。","note":"発見物カード580","exp":"1160"}],"6914":[{"type":"植物","name":"ルリジサ","rank":"1","desc":"地中海の沿岸部などに分布する一年草。ボリジとも呼ばれ、星の形をした花が咲く。開花直後は桃色をしているが、次第に青色へと変化する。","note":"","exp":""}],"4966":[{"type":"天文","name":"いて座の黒い筋の入った星雲","rank":"2","desc":"いて座のやや西にある星雲で、所々に暗黒星雲の塊が散らばっている。空が十分に暗い場所であれば肉眼で見ることができる。","note":"「天文学者の観測記録」<br/>発見物カード:125","exp":"250"}],"552":[{"type":"歴史遺物","name":"古代ローマ市民兵の盾","rank":"1","desc":"古代ローマは、市民が軍に参加していた。参加する市民は自費で装備を整え、訓練にも参加していた。装備は青銅であった。","note":"古代ローマの盾の地図","exp":"120"}],"6131":[{"type":"歴史遺物","name":"ポルトガル王子の剣","rank":"5","desc":"ポルトガル国王、ジョアン1世の妃であったフィリパ・デ・レンカストレが病床にて、セウタ攻略戦に赴く息子たちに授けた剣の一振り。攻略戦の勝利後に、いずれかの王子によって教会に献納されたようだ。","note":"","exp":"1040"}],"3898":[{"type":"天文","name":"おおぐま座","rank":"2","desc":"ゼウスの寵愛を受けたため、女神ヘラの怒りを買って巨大な熊に姿を変えられたカリストが天に昇った姿とされる。北米の先住民の神話でも熊が天に昇った姿とされる。","note":"クエスト「乙女の変身譚」<br/>発見物カード:120","exp":"240"}],"6765":[{"type":"地理","name":"ジェリーフィッシュレイク","rank":"4","desc":"パラオ諸島中部、マカラカル島にある塩湖。わずかな亀裂と洞穴により、外海と繋がるが生物の往来は隔絶している。ゴールデンジェリーフィッシュなどのクラゲが数百万匹も生息していることから名付けられた。","note":"追究クエスト<br/>発見物カード:170","exp":"340"}],"1824":[{"type":"財宝","name":"貝の耳飾り","rank":"2","desc":"アンデス文明中期のもの。貝や鉱石を砕いてモザイク画にし、それを木の枠組みに埋め込んで作っている。素朴で美しいこの細工は他の地方でも人気があったのか、あちこちで見受けられる。何らかの手段で流通していったのだろう。","note":"七色の財宝","exp":"290"}],"6672":[{"type":"中型生物","name":"リビアヤマネコ","rank":"5","desc":"別名、アフリカヤマネコ。北アフリカやアラビア半島の砂漠地帯に生息している。家猫の祖とされ、古代エジプト人がリビアヤマネコを飼い慣らしたものが家猫の起源だという。見た目は家猫のキジトラと酷似している。","note":"クエスト「迷い猫」<br/>発見物カード:415","exp":"830"}],"1461":[{"type":"大型生物","name":"タイガースネーク","rank":"1","desc":"明るい黄色の縞模様が特徴のヘビ。大変強力な毒を持ち、獲物を仕留める際に使用する。","note":"猛毒のヘビの地図","exp":"165"}],"3919":[{"type":"天文","name":"くじら座","rank":"4","desc":"エチオピアの王女アンドロメダを襲った化けクジラがペルセウスによって石に変えられた後、天に上げられた姿とされる。","note":"クエスト「海の化け物の調査」<br/>発見物カード:375","exp":"750"}],"5992":[{"type":"歴史遺物","name":"ラムセス2世の頭飾り","rank":"2","desc":"ラムセス2世は古代エジプトのファラオで、多数の建造物を作ったことで知られる。ラムセス2世の墓は墓泥棒に荒らされていたので所持品は珍しい。","note":"ファラオの装身具","exp":"220"}],"6221":[{"type":"気象・現象","name":"赤虹","rank":"3","desc":"赤い虹。霧のような雨が降ったあとに、幅が広く、色は薄いが全体的に明るい虹が出ることがある。この時に虹が朝日や夕日を浴びると、赤みを帯びて見えることが多い。","note":"","exp":"460"}],"486":[{"type":"宗教遺物","name":"ヤジュル・ヴェーダ","rank":"2","desc":"ヒンドゥー教の聖典の一つ。ヤジュスという祭詞を集めたもの。祭事で供儀を担当するアドヴァリユ祭官のためのものである。","note":"アドヴァリユ祭官の聖典","exp":"390"}],"5382":[{"type":"財宝","name":"ポリュクラテスの指輪","rank":"5","desc":"古代ギリシャで活躍した海賊で、サモス島の僭主だったポリュクラテスの指輪とされる。ポリュクラテスは指輪を海に捨てたが、数日後に献上された大魚の腹から指輪が出てきたという。金の台座にエメラルドがはまっている。","note":"古代ギリシャの海賊王<br/><br/>発見時経験値1170　発見物カード経験値585","exp":"1170"}],"678":[{"type":"大型生物","name":"チーター","rank":"5","desc":"細長い体の猛獣。体の柔軟性が非常に高く、全速力で走ると馬などよりもずっと速い。狩りのしかたは、そっと近よってから一気に襲う。ヒョウと少し似ているが、木には登らないようだ。","note":"信じられない速度","exp":"828"}],"179":[{"type":"宗教建築","name":"ストーンヘンジ","rank":"1","desc":"イングランドにある、先史時代の遺跡。祭祀場（さいしじょう）だったと考えられる。夏至の日の出の方向に入り口があり、全体は正確な円を描いている。","note":"ストーンヘンジの調査","exp":"90"}],"1575":[{"type":"地理","name":"アラフラ海","rank":"1","desc":"ニューギニア島の南西部に広がる遠浅の海。この海域を南下すれば広大な陸地があるというが…。","note":"書きかけの地図","exp":"110"}],"2508":[{"type":"史跡","name":"紅毛城","rank":"5","desc":"イスパニア人が築城した赤い城。鄭成功が台湾島を平定してからは廃屋となっている。\n華やかな外観だが、地下からは異様な雰囲気が漂ってくる…。","note":"中断された依頼","exp":"1120"}],"1672":[{"type":"中型生物","name":"カピバラ","rank":"1","desc":"巨大なネズミのような動物。湖や川近くの森林に生息している。集団で行動することで、外敵から身を守る。","note":"ネズミのような動物の地図","exp":"135"}],"1744":[{"type":"財宝","name":"ポウナムの斧","rank":"4","desc":"ポウナムとはマオリの言葉でひすいを指す。マオリの人々は鉄を知らなかったが、硬く粘りのあるひすいを長い時間をかけて削り出し斧や棍棒、首飾りなどを製作する技術を有していた。この斧はポウナムでできた刃をもつ儀式用の斧だそうだ。","note":"深緑の刃","exp":"624"}],"6466":[{"type":"歴史遺物","name":"古代の銀化ガラス器","rank":"5","desc":"虹のような色とりどりの模様が現れた古代のガラス器。砂や土の中で長年を経過したガラスは、ケイ酸や酸化アルミニウムなどの成分が周囲の物質によって化学変化を起こし、金属のように輝く。これを銀化現象という。","note":"","exp":""}],"6366":[{"type":"史跡","name":"ゲベル・バルカル","rank":"2","desc":"アフリカ北東にある砂岩の小山。アラビア語で「神聖なる山」という意味がある。崖下に広がる遺跡はエジプト第25王朝の首都ナパタとされ、エジプト文化の影響を強く受けた寺院や神殿が多くある。","note":"","exp":"280"}],"1944":[{"type":"宗教遺物","name":"タパク・ヤウリ","rank":"4","desc":"インカの初代皇帝がインティ神より贈られたとされる杖。インティ神は、この杖が大地に沈んだ所に太陽の神殿を建てるよう告げる。そして杖が沈んだ場所こそ、他ならぬインカ帝国の首都クスコであったという。","note":"へそを求めて","exp":"630"}],"1288":[{"type":"宗教遺物","name":"ラクシュミーのレリーフ","rank":"2","desc":"アンコール遺跡にあるラクシュミー像。アンコールには多数の女神像が見られる。この女神像はレンガ造りの柱に彫りこまれている。","note":"組まれた女神","exp":"280"}],"1514":[{"type":"宗教遺物","name":"宝生如来","rank":"4","desc":"ほうしょうにょらい。仏教における如来のひとり。全てのものに価値があり、その存在は平等であると説く。","note":"宝生如来像","exp":"720"}],"590":[{"type":"中型生物","name":"アザラシ","rank":"1","desc":"世界中の広い海域に生息する動物。皮下脂肪が非常に厚いため、海水の冷たさに耐えられるようだ。魚をとるために海に潜り、素晴らしい速度で泳ぐ。陸上での活動は苦手だ。","note":"黒い瞳の海獣","exp":"33"}],"1816":[{"type":"財宝","name":"金杯","rank":"1","desc":"アンデスの各地で、こういった貴金属製品が見つかる。かなり古い時代から貴金属の製法が確立されていたようで、各地で地方色豊かに、そして変遷の色濃い金細工が見つかる。","note":"金細工の地図","exp":"150"}],"67":[{"type":"大型生物","name":"ニシキヘビ","rank":"5","desc":"大型のヘビで、特に大きなものは10mにもなる。毒はないが力が強く、獲物をしめつけて殺してしまう。豚が食べられたこともあるそうだ。小さな足のような突起があるが、もっと大きくなると足が生えるのだろうか。","note":"インドの大蛇","exp":"1118"}],"3185":[{"type":"地理","name":"ファンディ湾","rank":"4","desc":"北米大陸東岸とノバスコシア半島の間に位置する湾。潮の干満の差が激しく、その潮位差は15mにも及ぶ。","note":"怪物のすむ湾","exp":"720"}],"5050":[{"type":"港・集落","name":"グランドケイマン","rank":"2","desc":"西インド諸島西部、ケイマン諸島最大の島にある街。難破船の船員や海賊達も住み着き始めているようだ。","note":"到達する","exp":"244"}],"3163":[{"type":"植物","name":"バンクスマツ","rank":"1","desc":"北米北部から北東部にかけて分布する樹木。樹形は広い円錐型で、枝は不規則に曲がりながら伸びる。","note":"枝が曲がった木の地図","exp":"170"}],"5221":[{"type":"歴史遺物","name":"エザナストーン","rank":"2","desc":"エザナ王が建立したといわれる石碑。\n王のキリスト教への改宗と、北東アフリカへの軍事遠征の記録が三つの異なる言語で刻まれている。","note":"エチオピア北部　再調査報酬","exp":"110"}],"6663":[{"type":"歴史遺物","name":"スクーダレヴ沈没船","rank":"2","desc":"ヴァイキング時代末期のヴァイキング船。敵を阻む防壁とするためデンマークの当時の首都・ロスキレ付近の海域に沈められた。","note":"","exp":""}],"5195":[{"type":"港・集落","name":"釜山","rank":"2","desc":"読みは「プサン」。\n元は漁村であったが、貿易の拠点として発展を遂げた。","note":"到達する","exp":"350"}],"6444":[{"type":"宗教遺物","name":"ベケット・ウォーター","rank":"1","desc":"イングランド教会の聖人、トマス・ベケットの血液などを水で薄めて作ったという聖水。聖人の加護により万病に効くとされた。イングランド王ヘンリー2世の親友だったベケットは、教会の自立性を巡り対立。聖堂内で王の兵士に殺害された。","note":"クエスト「殉教者の秘薬」","exp":"100"}],"66":[{"type":"地理","name":"ガンジス川","rank":"2","desc":"インド東部からベンガル湾に注ぐ大河。ヒンドゥー教徒にとって聖なる川だとされる。流域は非常に肥沃な土地が広がっている。古代から文明が発達していたようだ。","note":"クエスト「インドの聖なる川」<br/>発見物カード:135","exp":"270"}],"1251":[{"type":"中型生物","name":"コアリクイ","rank":"2","desc":"長いねばねばした舌を使い、アリを絡め取って食べる。危険を感じると、立ち上がって相手を威嚇する体勢をとる。","note":"偏った食事","exp":"280"}],"6325":[{"type":"海洋生物","name":"イロワケイルカ","rank":"5","desc":"南米やインド洋の海域に生息するイルカ。体の色が白と黒に分かれている。その体色から「パンダイルカ」とも呼ばれる。雄はお腹の模様がしずくのような形で、雌は丸い形をしている。","note":"","exp":"1010"}],"3326":[{"type":"小型生物","name":"プレーリードッグ","rank":"5","desc":"北米中央部の草原地帯に生息する動物。体長は30～40cm程度で、地面に深く掘った巣穴に住む。名前は、鳴き声がイヌに似ていることに由来する。","note":"大草原に住む動物<br/><br/>発見時経験値810　発見物カード経験値405","exp":"810"}],"2390":[{"type":"中型生物","name":"オオサンショウウオ","rank":"3","desc":"主に西日本の河川の上流に生息する、太ったトカゲのような生物。体長が1mを超えるものもいる。\n陸上での行動は鈍いが水中では機敏な動きを見せる。","note":"渓流に潜む巨大な影","exp":"600"}],"1823":[{"type":"歴史遺物","name":"ロンパイア","rank":"2","desc":"古代トラキア人が使っていた、柄も刀身も長い刀剣。刃の方向に湾曲しており、引っ掛けるようにして切り裂く用途もあった。","note":"トラキアの刀剣","exp":"350"}],"6587":[{"type":"宗教遺物","name":"シュルバ・スートラ","rank":"2","desc":"古代インドの数学に関する書物。祭壇などの修築が主題であり、祭壇を採寸する際に使用する幾何学を始め、当時の様々な知識が記されている。","note":"","exp":""}],"3770":[{"type":"天文","name":"火星","rank":"4","desc":"戦火や血を思わせる赤い色から、ローマ神話のマルスを始め、各地で戦争の神の名をつけられた惑星。他の惑星に比べ、明るさが大きく変わるのが特徴で、最も明るい時期は780日ごとにやってくる。","note":"夜空に輝く赤い星","exp":"640"}],"6136":[{"type":"地理","name":"ポルト・セグーロ","rank":"3","desc":"キリスト騎士団の騎士カブラルが発見し、上陸した地域。カブラルはガマの後任となってインド遠征隊を率い、ポルトガル人として初めて南アメリカの地を踏んだ。「安全な港」の名前に違わず良質の海岸が多く、活気のある港町もある。","note":"","exp":"460"}],"5864":[{"type":"天文","name":"おおぐま座の細長い銀河","rank":"5","desc":"おおぐま座にある、細長い形状で観測される銀河。肉眼での観測は難しいため、専門の機具を用いて観測する必要がある。","note":"発見物カード:685<br/>","exp":"1370"}],"5416":[{"type":"植物","name":"アサイー","rank":"2","desc":"南米に生息するヤシ科の植物。青紫色の小さな果実を枝に多くつける。果実は非常に栄養価が高く、現地では栄養食としても利用されているようだ。","note":"","exp":""}],"1804":[{"type":"美術品","name":"ウィトルウィウス的人体図","rank":"2","desc":"古代ローマの建築家であるウィトルウィウスが示した人体の比率をダ・ヴィンチが再考察し、図式化したもの。ダ・ヴィンチはこの図によって人物をより写実的に描こうとしたという。","note":"ダ・ヴィンチの人体図","exp":"340"}],"5164":[{"type":"港・集落","name":"モンバサ","rank":"1","desc":"アフリカ東岸の街。アフリカ・アラビア・インドの中間地点に位置するため、港湾都市として古くから栄えた。耕作が広く行われ、コーヒーなどの農産物が多く流通している。","note":"到達する","exp":"71"}],"2733":[{"type":"歴史遺物","name":"高敞支石墓群","rank":"2","desc":"読みは「こちゃんしせきぼぐん」。朝鮮半島西岸にある、大規模な支石墓群。\n大小さまざまな石材で形成されており、形態もテーブル式や基盤式など多種多様。総数は400を超えるという。","note":"地域調査依頼<br/><br/>発見時経験値320　発見物カード経験値160","exp":"320"}],"683":[{"type":"地理","name":"ジャマイカ島","rank":"2","desc":"カリブ海の、キューバ島の南に位置する大きな島。ほとんどが山地で、高地はかなり冷涼になる。また、海岸線が複雑で入り組んでおり、水深があるので港に適している。","note":"森と水の国","exp":"360"}],"1177":[{"type":"地理","name":"フィヨルド","rank":"1","desc":"寒冷地に見られる、複雑に入り組んだ海岸線のこと。なにか強力な浸食によるものと思われる。水ならもっとなだらかな浸食になるので、氷によるものではないだろうか。","note":"良港の産地","exp":"80"}],"5162":[{"type":"港・集落","name":"モガディシオ","rank":"1","desc":"アフリカ北東岸の街。古代から人が住むが、気候が厳しく耕作には向かない。畜産は盛んで、主な交易品は畜産物である。それ以外には鉱物資源も産出している。","note":"到達する","exp":"75"}],"1695":[{"type":"海洋生物","name":"ピライーバ","rank":"2","desc":"アマゾン川に生息するナマズの中でも、特に大きい。体長の2倍以上もある長いヒゲをもつ。","note":"釣り","exp":"260"}],"5855":[{"type":"小型生物","name":"マヌルネコ","rank":"5","desc":"バイカル湖周辺などに生息するネコの仲間。体毛が長く密集して生えているため、ずんぐりして見える。威嚇の際に、上唇の片端を吊り上げ、犬歯をむき出しにする特徴的な行動をとる。","note":"","exp":"1370"}],"1096":[{"type":"地理","name":"ユカタン半島","rank":"2","desc":"キューバ島につらなるように突き出した大きな半島である。石灰岩質だが熱帯性の気候で雨量が多く、耕作は可能だろう。内陸には巨大な建造物のようなものが見える。強大な勢力が存在するのだろうか…。","note":"カリブの果て","exp":"375"}],"5207":[{"type":"宗教遺物","name":"ズメエヴィク","rank":"2","desc":"中世に使用された肖像入りの首飾り。片面にはキリスト教徒の聖人と蛇、もう片面には祈祷の言葉が刻まれる。","note":"","exp":"250"}],"2301":[{"type":"財宝","name":"王家の首飾り","rank":"4","desc":"コパン遺跡から発見されたヒスイの首飾り。10cmを超える棒状のヒスイには紐が通せるようになっている。中間点には外部に通じる穴があり、その部分から別のヒスイを合わせて「Ｔ」の形を作り出している。これはコパン王家を表すとされる。","note":"王家の墓への手掛かり","exp":"740"}],"6339":[{"type":"地理","name":"フアン･フェルナンデス諸島","rank":"2","desc":"南米南部の沖合、太平洋に浮かぶ群島。三つの島で構成される。島の地形は険しく、火山島となっている。自然豊かで多くの動物が生息している。","note":"ペルー海盆12960:5734","exp":"320"}],"2563":[{"type":"小型生物","name":"タイワンリス","rank":"3","desc":"アジア全域など、広く分布する、イヌのような鳴き声で鳴くリス。前歯が鋭いため、研ぐのに用いられた木は、樹皮が削れていることが多い。\n気性が荒く、幼少期以降は単独で行動する。","note":"姿の見えないイヌ","exp":"520"}],"5817":[{"type":"財宝","name":"ケツァールの羽の王冠","rank":"5","desc":"幻の鳥ケツァールの羽で飾られた王冠。ただでさえ珍しい鳥なのだから、捕獲のされすぎで絶滅しないか心配である。","note":"","exp":"1474"}],"6596":[{"type":"史跡","name":"バールバール神殿","rank":"2","desc":"バーレーン島の北部にある古代の神殿。メソポタミアの神エンキとその妻ニンフルサグへの礼拝のために作られたとされる。神殿は時代ごとにその上に積み重ねるように作られ、3段階になっている。","note":"","exp":"350"}],"2606":[{"type":"宗教遺物","name":"道成寺の鐘","rank":"3","desc":"ある寺院に奉納されている、いわくつきの釣鐘。ある女に追われた僧侶が鐘の中に逃げ込んだものの、ヘビに化けた女に鐘ごと焼き殺されたという伝説がある。よく見たら、なにかが巻きついたような形跡がある…。","note":"置かれた釣鐘","exp":"510"}],"6384":[{"type":"虫類","name":"オオカマキリ","rank":"3","desc":"東アジアに生息する大型のカマキリ。気性が荒く、肉食性で共食いをすることもある。雌は植物の枝などに泡状の卵鞘を産み付ける。そこから200匹近い幼虫が生まれるが、そのうち成虫になれるのはわずか数匹だという。","note":"","exp":"490"}],"5204":[{"type":"歴史遺物","name":"修道士のかかと","rank":"1","desc":"ヒール・ストーンとも呼ばれる高さ6mほどの立石。倒れないように安定させる工夫がされている。夏至の日には、ストーンヘンジ中心の祭壇石とこの石を結ぶ直線上に太陽が昇るという。","note":"ソールズベリー平原再調査の報酬","exp":""}],"5592":[{"type":"気象・現象","name":"間欠泉","rank":"2","desc":"一定周期で地中から水蒸気や熱湯が噴き上がる現象。地中でどのような現象が発生しているかはわからないが、高温の噴出物であることから、火山活動との関係性がうかがえる。","note":"ワンガヌイ西（ワンガヌイ郊外）で発見。<br/>郊外に出たすぐの場所で発見できました。<br/>東の奥、行き止まりで現象見れます。","exp":"270"}],"6974":[{"type":"宗教遺物","name":"アルジュナの苦行","rank":"4","desc":"インド南東部にある巨大な岸壁彫刻。神々や動物などが一枚岩に精緻に刻まれている。叙事詩マハーバーラタの「アルジュナの苦行」を表現しているという説のほか、「ガンガーの降下」とされる説もある。","note":"発見物カード:375","exp":"750"}],"2852":[{"type":"財宝","name":"短歌行","rank":"4","desc":"三国時代の英傑・曹操が、赤壁の戦い前夜に宴席で詠んだといわれる詩。\n酒について詠んだ前半部分と、能力のある人材を求める詩を詠んだ後半部分からなる。","note":"クエスト「奸雄の素顔」<br/>発見物カード:320","exp":"640"}],"5580":[{"type":"地理","name":"ケスタ","rank":"5","desc":"北米大陸北東部などで見られる地形の一種。硬い地層と軟らかい地層が交互に重なった斜面が浸食されることによって、緩い斜面と急な崖が連続する地形となっている。ナイアガラの滝は、この急な崖の部分にあたるとみられる。","note":"","exp":""}],"256":[{"type":"大型生物","name":"ヒグマ","rank":"1","desc":"クマの中でも特に大型で危険な種類である。オスの大きい個体は体長が2mを超える。人間の力などは問題にならない。雑食性で冬眠の習性があるため、秋の準備期間と冬眠明けの春先は特に危険。","note":"クエスト「ヒグマの生息地調査」<br/>発見物カード:70","exp":"140"}],"587":[{"type":"財宝","name":"宝石をちりばめた小箱","rank":"1","desc":"色とりどりの宝石をちりばめた、美しい箱。高貴な婦人の宝石箱ではないだろうか。","note":"豪華な宝石細工の地図","exp":"38"}],"6796":[{"type":"大型生物","name":"シェトランドポニー","rank":"2","desc":"イングランドの北東にあるシェトランド諸島原産の馬。体は小さいが丈夫で、力も強い。灰、青、茶、黒、白など様々な毛色が存在する。農耕や荷運びに古くから使われている。","note":"「亜寒帯動物の生息地図」<br/>発見物カード:110","exp":"220"}],"6224":[{"type":"気象・現象","name":"ファイヤーデビル","rank":"3","desc":"炎の竜巻。山火事などで大規模な火災が発生し、周囲に風を遮るものがない場合に発生することがある。上昇気流によって炎が竜巻になった姿は見る者に恐怖を与えるが、奇妙な美しさを感じる者もいるという。","note":"","exp":"500"}],"6644":[{"type":"歴史遺物","name":"ハサーの翼","rank":"2","desc":"ハサーは、有翼重騎兵のこと。ポーランドの華美な装いをした勇猛な騎兵で、猛禽の羽でできた大きな羽飾りを背負った。この羽飾りに風を通して音を立て敵の恐怖心を煽るのだという。","note":"","exp":"260"}],"6518":[{"type":"小型生物","name":"オリオフリネラ","rank":"5","desc":"特定の高地にしか生息しておらず、その環境にあわせ独自の進化を遂げたとされるカエルの一種。オタマジャクシの期間がなく、卵から直接カエルの姿で孵化することや、水かきを持たず、泳いだり飛び跳ねたりできないことが特徴といわれる。","note":"","exp":""}],"6991":[{"type":"宗教遺物","name":"ホルスを抱くイシス像","rank":"2","desc":"末期王朝期のエジプトで制作された像。女神イシスが息子のホルスに授乳している姿がかたどられている。子を守る母の愛を表したこの像は、キリスト教の聖母子像の在り方にも影響を与えたと考えられている。","note":"","exp":""}],"3153":[{"type":"財宝","name":"銀食器","rank":"4","desc":"メディチ家が所有する銀製の食器。貴族の間ではそれほど珍しいものではないらしい。毒に反応して黒く変色することから、毒殺を防止するために使用され始めたという。","note":"命を守る食器","exp":"710"}],"2375":[{"type":"中型生物","name":"チン","rank":"3","desc":"中国から朝鮮を通じ、日本へ伝わったといわれる犬。体高は25cmほどしかない。\n毛並みは繊細でつやがあり、性格は穏和でおとなしい。屋内での飼育に向いた愛玩犬である。","note":"飼いやすい愛玩犬","exp":"520"}],"1024":[{"type":"植物","name":"ゲッカビジン","rank":"4","desc":"普段は厚みのある葉しか目に付かないが、夜になると20cmにもなる白い大輪の花を咲かせる。透き通るような純白の花弁が美しく、開花すると甘く強い香りが周囲に漂う。","note":"夜しか現れない美人","exp":"720"}],"2343":[{"type":"宗教遺物","name":"鎮魂の勾玉","rank":"2","desc":"読みは「たましずめのまがたま」。日本の陰陽師たちが儀式に使うという特別な勾玉。\n日本の神道では、鎮魂とは、生者の不安定な魂を体につなぎ留めておくための行為を指すらしい。","note":"大切なお守り","exp":"290"}],"5244":[{"type":"天文","name":"みなみじゅうじ座","rank":"4","desc":"ケンタウルス座の南にある、全天で一番小さな星座。1等星を2つ含み、天の南極を探す際によく利用される。","note":"クエスト「南の目印」<br/>発見物カード:350","exp":"700"}],"6727":[{"type":"鳥類","name":"オオムジアマツバメ","rank":"4","desc":"南米にある巨大なイグアスの滝の裏側に生息する鳥。長い翼を持つため、高速な水平飛行が可能で、滝を簡単に突破できる。","note":"小さな鳥の地図 発見物カード:305","exp":"610"}],"3753":[{"type":"天文","name":"ふたご座","rank":"4","desc":"黄道十二星座の1つ。アルゴ船での探検に参加した双子、カストルとポリュデウケスが天に昇った姿とされる。ギリシャ以外でも2つの星は組み合わせとされることが多く、北欧神話では巨人グーゼの目とされている。","note":"兄弟星","exp":"720"}],"24":[{"type":"植物","name":"クンシラン","rank":"1","desc":"南アフリカで見られる多年生の植物。赤やオレンジの豪華な花が美しい。つやがあり規則的に並ぶ葉も大変見ごたえがある。観賞用として高い評価が得られるだろう。","note":"アフリカの高貴な花<br/><br/>発見時経験値90　発見物カード経験値45","exp":"90"}],"6514":[{"type":"史跡","name":"デルフォイのスタディオン","rank":"5","desc":"デルフォイにあった陸上競技場。名称は古代ギリシャの距離単位に由来し、1スタディオンは約180メートルだが各都市で差があったという。デルフォイではオリンピアなどと並ぶ大規模な競技大会、ビューティア大祭が行われていた。","note":"","exp":""}],"477":[{"type":"宗教遺物","name":"カッパドキアの壁画","rank":"3","desc":"カッパドキアの内部のいたるところに見られる壁画。長い年月に渡って次々に描かれたため、いろいろなタイプのものがある。","note":"見てはいけないもの","exp":"506"}],"1183":[{"type":"財宝","name":"アギラールの聖書","rank":"2","desc":"コルテスより以前にメソアメリカの地に上陸してきたイスパニア人聖職者。現地人によりとらわれの身となる。その際身に付けたマヤ語を用いてコルテスの通訳として活躍する。この聖書はとらわれている間ずっと腰につけていたというもの。","note":"望郷の念を抱きつづけて<br/><br/>発見時経験値260　発見物カード経験値130","exp":"260"}],"2879":[{"type":"宗教遺物","name":"阿弥陀経残巻","rank":"1","desc":"極楽浄土の様子を経文と絵画で表した作品。元となる経文は「仏説阿弥陀経」で、六朝時代の僧・鳩摩羅什が翻訳したもの。","note":"古の書物の地図","exp":"160"}],"2332":[{"type":"地理","name":"鳥取砂丘","rank":"2","desc":"日本の中国地方に位置する海岸砂丘。\n見た目は小規模な砂漠のようだが、雨や雪が降り、砂丘独特の動植物も多く見られる。","note":"書きかけの地図","exp":"220"}],"5717":[{"type":"気象・現象","name":"レンズ雲","rank":"2","desc":"山や山脈の上空に発生する平たい形状の雲。上空の風が強い時に発生しやすいことから、悪天候になる前触れとしても各地で知られている。","note":"2017.02.07新規追加","exp":"370"}],"6550":[{"type":"史跡","name":"在りし日の大灯台","rank":"5","desc":"高さ130メートル以上と伝わる巨大な灯台。紀元前3世紀ごろにプトレマイオス朝エジプトの首都、アレクサンドリア沖合にあるファロス島に建設された。最上部の灯室には巨大な鏡が置かれ、昼は陽光を反射させるのに用いられたという。","note":"","exp":""}],"873":[{"type":"鳥類","name":"フラミンゴ","rank":"1","desc":"首と足が非常に長い、大型の鳥。美しいピンクの羽を持つ。数万羽にもなる群れで生活するため壮観である。ツルに似ているがくちばしが異なるのでそれほど近い種類ではないかもしれない。","note":"桃色の大きな鳥","exp":"80"}],"5222":[{"type":"宗教遺物","name":"ウル・ナンム法典","rank":"1","desc":"ウル第三王朝の初代王ウル・ナンムによって発布された法典。古代バビロンのハンムラビ法典に影響を与えたとされる。\n損害賠償に重点が置かれた刑罰が規定されている。","note":"","exp":"198"}],"2948":[{"type":"海洋生物","name":"アオミノウミウシ","rank":"3","desc":"5～8cm程度の小型のウミウシ。アフリカ東岸や南岸などにかけて生息する。\n青と銀の体色が鮮やかで、海の宝石ともいえる姿をしている。","note":"波間の青き宝石","exp":"600"}],"1829":[{"type":"財宝","name":"タプ・イ・アルカ","rank":"3","desc":"ケチュア語で、「緑の石」を意味する、エメラルドの原石である。アンデス山脈の北部に住むチブチャ民族の族長が、祭祀を行うために祭器として用いていた。","note":"ソニュカサパ","exp":"500"}],"6599":[{"type":"史跡","name":"在りし日のバビロンの空中庭園","rank":"5","desc":"新バビロニア王国の王ネブカドネザル2世が技術の粋を集めて作ったとされる建造物。階段状に何層にも連なった庭園は、その様から空中庭園と呼ばれ、王妃の緑豊かな故郷を懐かしむ心を癒すために建造したともいわれている。","note":"レガシー伝説の王都バビロン　中央","exp":"4000"}],"5349":[{"type":"天文","name":"たて座の散開星団","rank":"5","desc":"たて座にある散開星団で、かなりの数の星が密集している。","note":"発見物カード:465","exp":"930"}],"3305":[{"type":"鳥類","name":"シマセゲラ","rank":"2","desc":"北米の東部に生息するキツツキの一種。体長は25cm程度。背中の白と黒の縞模様と、頭頂部の鮮やかな朱色が目を引く。","note":"クエスト「模様の鳥」<br/>発見物カード:200","exp":"400"}],"5268":[{"type":"歴史遺物","name":"アスタルテ像","rank":"1","desc":"豊穣を司る女神の像。古代ギリシャではアフロディテと同一の女神とされている。フェニキアでは古い世界を破壊し、新しい世界を創造する、死と再生の女神ともいわれる。","note":"ビュルサの丘　再調査報酬","exp":""}],"5054":[{"type":"港・集落","name":"コピアポ","rank":"2","desc":"南北に長く広がる砂漠の南に位置する、オアシスの街。降雨が少なく、水は貴重である。","note":"到達する","exp":"260"}],"6029":[{"type":"宗教遺物","name":"聖大公妃オリガの洗礼着","rank":"4","desc":"キエフ大公イーゴリ1世の妃であるオリガがコンスタンティノープルで洗礼を受けた時に着ていたと言われる洗礼着。\n簡素な造りの洗礼着だが、独特の刺繍が施されている。","note":"","exp":"990"}],"5014":[{"type":"港・集落","name":"アテネ","rank":"1","desc":"古代ギリシャ時代から続く、長い歴史を誇る街。アクロポリスの丘にはパルテノン神殿がそびえ、かつては高さ10mのアテナ像があったという。特産品はオリーブのほか、良質の大理石も産する。","note":"到達する","exp":"34"}],"6846":[{"type":"天文","name":"ディアデム","rank":"3","desc":"かみのけ座の2番目に明るいアルファ星で、2つの5等星がお互いに公転する連星として知られる。頭に巻き付ける王冠の名であり、古代エジプトの王妃ベレニケ2世の冠という説もある。","note":"発見物カード:250","exp":"500"}],"1859":[{"type":"歴史遺物","name":"アタカマの巨人","rank":"2","desc":"黒い石で輪郭を取り、内側を平らに掘って描かれた、全長約80mほどの地上絵。平らな地面ではなく、傾斜地に描かれているのには、なにか意図があるのだろうか。","note":"奇妙な絵","exp":"220"}],"6830":[{"type":"鳥類","name":"サンジャク","rank":"5","desc":"東アジアから南アジアにかけての山地に生息する鳥。森林に棲み、樹上に巣を作る。\nヤマムスメと同じく黒い頭と赤いくちばしを持つが、腹が白い、頭の後ろの毛が白い斑点のように見えるなど、特徴は異なる。","note":"追究クエスト<br/>発見物カード:410","exp":"820"}],"916":[{"type":"中型生物","name":"アビシニアコロブス","rank":"2","desc":"黒と白の毛並みが美しいサル。完全に草食性のようで、樹上で葉をもりもり食べている。同じようなサルがほかにもいるようだが、毛並みはこのサルが一番で美しい。","note":"白黒のサル","exp":"260"}],"5401":[{"type":"海洋生物","name":"ドラド","rank":"3","desc":"金色に輝くサケに似た大型の淡水魚。成魚は体長1mにもなる。その姿から、スペイン語で黄金を意味するドラドの名がついた。鋭い歯と強靭なあご、獰猛な性格から、川の虎とも呼ばれている。南米の河川でのみ見られる。","note":"パラグアイ川上流。入り口右の水辺。<br/>釣りR10+1<br/><br/>発見時経験値480　発見物カード経験値240","exp":"480"}],"6134":[{"type":"鳥類","name":"オオグンカンドリ","rank":"3","desc":"主に太平洋やインド洋に生息する、グンカンドリの仲間。広げた翼が2mを超えるほど大きくなるが、体重は軽い。オスメス共に全身が黒いが、オスには赤い喉袋、メスは喉から胸にかけて白いという特徴があり、区別しやすい。","note":"","exp":"540"}],"576":[{"type":"中型生物","name":"ジャコウネコ","rank":"2","desc":"タヌキと猫の間のような動物。目のまわりが黒く、体には斑点がある。肛門の近くの腺から悪臭のする分泌物が取れ、これを希釈すると高価な香料になる。夜行性で樹上で活動することが多いため、目撃するのは困難だ。","note":"香料を産む猫","exp":"260"}],"539":[{"type":"歴史遺物","name":"ミイラ","rank":"1","desc":"死体に防腐処置を施し保存したもの。特に古代エジプトでは死者の復活が信じられていたため、非常に高度な技術が発展した。","note":"古代の墳墓の地図","exp":"190"}],"2088":[{"type":"宗教遺物","name":"ワロチリ文書","rank":"5","desc":"アンデスに伝わる神話や伝承をまとめた、ある宣教師の著書。\n水の神パリアカカと炎の神との戦いを始め、様々な神話や伝承が記されている。","note":"クエスト「伝承の未来」<br/>発見物カード:535","exp":"1070"}],"2611":[{"type":"宗教遺物","name":"福徳正神像","rank":"5","desc":"読みは「ふくとくせいしんのぞう」。五穀豊穣や蓄財祈願の信仰から生まれた自然神の像で、土地公とも呼ばれる。\n主に人々に財を与える福の神として、台湾島で親しまれている。","note":"土地公","exp":"950"}],"3758":[{"type":"天文","name":"いて座","rank":"5","desc":"黄道十二星座の1つ。ケンタウロスの賢者ケイロンが天に昇った姿とされる。天の川にかかる部分に、ひしゃくに似た並びの6つの星があり、ヨーロッパではミルク・ディッパー東洋では南斗六星と呼ばれることがある。","note":"クエスト「蠍を狙う射手」<br/>発見物カード470","exp":"940"}],"1965":[{"type":"財宝","name":"コイヌール","rank":"5","desc":"ペルシャ語で、「光の山」を意味する名がつけられた大きなダイヤモンド。原石は800カラットを超えたといわれている。代々、インドの王が所持していたものだが、ムガール帝国、サファヴィー朝と変遷し、消息を絶っていた。","note":"魔性のダイヤモンド","exp":"1190"}],"5870":[{"type":"虫類","name":"ヒカリキノコバエ","rank":"5","desc":"オーストラリアなどに生息する昆虫。幼虫は洞窟の天井に生息し、発光する成分を含んだ粘液を体から垂らし、虫をおびき寄せて捕食する。","note":"","exp":"1420"}],"5304":[{"type":"宗教遺物","name":"ニャウの仮面","rank":"5","desc":"アフリカ南東部に住むチェワ人が葬儀の際に身に着ける仮面。仮面を着けた踊り手はニャウと呼ばれる存在になり、死者の霊を祖先の世界に届ける役目を果たすという。","note":"南東アフリカの風習","exp":"970"}],"494":[{"type":"植物","name":"ヤグルマキク","rank":"1","desc":"ヨーロッパ南東部に咲く花。青、白、桃などさまざまな色がある。古代エジプトでは魔よけの花として、ギリシャ神話では傷薬の花として親しまれた。","note":"古代エジプトの魔よけ","exp":"80"}],"2086":[{"type":"地理","name":"ネバド・パリアカカ","rank":"5","desc":"アンデス山脈に連なる山。水の神パリアカカが姿を変えたといわれるだけあって、山頂には雪が積もっている。この山で採れた氷は、リマにも運ばれているらしい。","note":"彼女が見つめる山","exp":"820"}],"6803":[{"type":"小型生物","name":"ユキウサギ","rank":"5","desc":"北極圏など寒いところに生息する、ウサギの一種。冬毛は真っ白であり、雪に紛れるのに適している。季節によって姿を変える。","note":"発見物カード:460","exp":"920"}],"2412":[{"type":"宗教遺物","name":"ハートスカラベ","rank":"3","desc":"スカラベをかたどった護符のうち、特殊なもの。裏面には、死者の書が刻まれている。\n復活の祈りを込めて、ミイラの心臓の上に置かれた。","note":"ダンジョン","exp":"530"}],"6860":[{"type":"天文","name":"ポリマ","rank":"1","desc":"おとめ座のガンマ星。この星座の恒星の中ではスピカに次いで\n２番目に明るい３等星。名前はカメーネと呼ばれるローマ神話\nの女神の一人「ポリマ」に由来すると言われている。","note":"クエスト「続・科学の星座」<br/>発見物カード:190","exp":"380"}],"2319":[{"type":"地理","name":"卑南渓","rank":"2","desc":"台湾島東部を流れる川の一つ。\n卑南とは、先住民である卑南民族の頭目を意味する。\n複雑に削られた川の地形が、中国の黄山に似ていることから「小黄山」とも呼ばれる。","note":"［勅命］[[調査における水場の確保","exp":"340"}],"2692":[{"type":"財宝","name":"訓民正音","rank":"2","desc":"朝鮮王朝4代王・世宗の命により編さんされたという書物。\n朝鮮語の表記に用いられるハングルについて記されている。","note":"正しい言語を求めて","exp":"340"}],"5607":[{"type":"地理","name":"ヒューロン湖","rank":"2","desc":"北米大陸北東部に位置する湖のひとつ。世界で第四位の面積を誇る広大な湖である。","note":"","exp":""}],"3781":[{"type":"天文","name":"冬の大三角","rank":"4","desc":"ヨーロッパでは冬の南の空に現れる、3つの明るい星を結んで描かれる三角形。3つの星はすべて1等星で、ほぼ正三角形を描くため見つけやすい。さまざまな星座を見つける目印となる。","note":"視認","exp":"610"}],"2570":[{"type":"地理","name":"姐妹潭","rank":"2","desc":"阿里山の山中にある、大きさが違う二つの湖の総称。\nかつて、阿里山に住む二人の娘がこの地で命を絶ったという伝説がある。","note":"クエスト「姉妹の運命」<br/><br/>発見時経験値320　発見物カード経験値160","exp":"320"}],"801":[{"type":"中型生物","name":"マントヒヒ","rank":"2","desc":"岩山で大きな規模の群れを作るサル。オスは長い飾り毛が目立つ。牙が大きく、近づくのは危険だろう。","note":"大きなサルの地図","exp":"260"}],"5084":[{"type":"港・集落","name":"セビリア","rank":"1","desc":"フェニキア人によって基礎が築かれ、古代ローマの時代から栄えていた。イスラム勢力に支配された間に大きく発展し、現在ではイスラムとヨーロッパの文化が混在した、独特の街並みを有する。","note":"到達する","exp":"32"}],"5241":[{"type":"天文","name":"ハレー彗星","rank":"5","desc":"イングランドの天文学者エドモンド・ハレーが記録から周期的に現れることを予言した彗星。およそ76年ほどの周期で目撃され、時には大接近が記録されている。1066年のノルマン・コンクエストの前に現れた彗星もハレー彗星だとされる。","note":"クエスト「予言された彗星出現」<br/>発見物カード:505","exp":"1010"}],"3752":[{"type":"天文","name":"しし座","rank":"4","desc":"黄道十二星座の1つ。ヘラクレスの12の冒険の最初に倒された、ネメアの獅子が天に上げられた姿とされる。ネメアの獅子の毛皮は武器で貫けず、ヘラクレスは3日間も獅子の体を締め続けて倒したという。","note":"クエスト「天空の獅子」<br/>発見物カード:325","exp":"650"}],"5152":[{"type":"港・集落","name":"マスリパタム","rank":"1","desc":"インド東岸に位置する街。交易の中継点として開発された。熱帯性の農作物のほか、インド特有の織物や繊維が豊富に流通している。","note":"到達する","exp":"176"}],"1292":[{"type":"歴史遺物","name":"ナラーティハパテ王の懐剣","rank":"3","desc":"ナラーティハパテ王のものと思われる懐剣。ナラーティハパテ王はパガン朝最後の王である。過剰な寺院造営により国が衰えているところをフビライに攻め込まれ、パガンを放棄することとなった。","note":"最後の王","exp":"539"}],"5055":[{"type":"港・集落","name":"コペンハーゲン","rank":"1","desc":"ヨーロッパ北部のシェラン島東岸にあり急速に発展しつつある街。コペンハーゲンとはデンマークの言葉で「商人の港」を意味する。農作物や加工食品のほか、琥珀（こはく）やぜいたくな調度類が流通する。","note":"到達する","exp":"41"}],"3296":[{"type":"歴史遺物","name":"バタシーの盾","rank":"5","desc":"ロンドンの近くで発見された、青銅製の盾。なかには木製のものも存在する。装飾の特徴から、おそらくケルト文化に関するものだと思われる。","note":"ケルトの盾","exp":"840"}],"5925":[{"type":"史跡","name":"ウルグ・ベク天文台跡","rank":"3","desc":"学者たちを保護し、自身も天文学者であったサマルカンドの領主ウルグ・ベクによって建造された天文台。当時のイスラム世界において先進的な研究施設であった。","note":"","exp":"500"}],"5733":[{"type":"宗教遺物","name":"オシリスの棺","rank":"5","desc":"オシリスが謀殺された時に用いられた棺。川に流され、着いた先で木に包まれ、そのまま柱に使われ、中の遺体はバラバラにされた。これほど波乱万丈な生涯を送った棺も珍しいだろう。","note":"死ぬほど気持ちいい棺<br/>2017.02.07新規追加","exp":"1360"}],"2851":[{"type":"歴史遺物","name":"縦目仮面","rank":"5","desc":"独特な造形の仮面。\n縦の目が特徴的で、その形は伝説上の初代の蜀王・蚕叢を連想させる。","note":"養蚕と蚕叢<br/><br/>発見時経験値1060　発見物カード経験値530","exp":"1060"}],"34":[{"type":"中型生物","name":"アラビアオリックス","rank":"1","desc":"長い角を持つ、ウシのような動物。砂漠地帯に住む。それほど大型ではない。地面に穴を掘って座っている姿をよく見かける。おそらく体温を調整しているのだろう。","note":"アラビアの動物の地図","exp":"96"}],"2999":[{"type":"植物","name":"ブルーボネット","rank":"1","desc":"北米に生息する花。密集して、青く小さな花を咲かすさまは、まるでじゅうたんのようである。","note":"青い小さな花の地図","exp":"110"}],"6492":[{"type":"植物","name":"プヤ・ライモンディの花","rank":"5","desc":"百年に一度、花を咲かせるといわれるプヤ・ライモンディの花。その巨体一面に咲く花をたまたま目にすることができるのは、時の運に恵まれた者だけなのだろう。","note":"追究クエスト","exp":"1720"}],"1718":[{"type":"海洋生物","name":"マゼランアイナメ","rank":"2","desc":"南の海に生息する魚。非常に大きな口をしていて、タラのようにも見える。","note":"釣り","exp":"260"}],"1015":[{"type":"宗教遺物","name":"ハデス像","rank":"1","desc":"ギリシャ神話の冥府の神の像。ハデスは冥府を治める厳格な神であると同時に、鉱物や宝石をつかさどる富の神としても知られる。","note":"冥府の王","exp":"90"}],"4853":[{"type":"天文","name":"アルゴル","rank":"2","desc":"ペルセウス座に含まれる星。約三日の周期で光の強さが変わる。アルゴスは「悪魔」を意味するといわれ、星座図上ではペルセウスの携えている怪物・メデューサの首の部分に位置する。","note":"「明るい星の観測記録」<br/>発見物カード:135","exp":"270"}],"3672":[{"type":"植物","name":"セイヨウオニシバリ","rank":"3","desc":"南ヨーロッパからロシアに至るまで、広く分布する低木。早春に花を咲かせる。果実や枝には毒を持っている。","note":"手に取れない花","exp":"470"}],"1766":[{"type":"財宝","name":"銀とルビーのイヤリング","rank":"1","desc":"ある交易商が妻に贈ったといわれるイヤリング。銀もルビーもヨーロッパでは手に入りにくいもので、さぞかし裕福な豪商の手によって作成を依頼されたものなのだろう。","note":"凝った装飾の地図","exp":"150"}],"276":[{"type":"地理","name":"ペルシャ湾","rank":"1","desc":"アラビア半島とペルシャにはさまれた海域である。クロチョウガイなどの生息に適した環境で、古代から真珠が採れたという記録がある。真珠は今でも大変な貴重品である。","note":"クエスト「ペルシャの海」<br/>発見物カード:100","exp":"200"}],"2599":[{"type":"歴史遺物","name":"蒔絵の硯箱","rank":"3","desc":"日本で作られた、硯や筆を収める箱。蒔絵の技法が用いられた、秀逸な工芸品である。\n蒔絵とは、漆器の表面に漆で紋様を描き、漆が乾く前に金粉などの金属粉を蒔いて定着させる技法である。","note":"歴史に残る名品","exp":"460"}],"6936":[{"type":"史跡","name":"ティパサの遺跡","rank":"2","desc":"アフリカ北岸の街、アルジェ近郊にある都市の跡。古代フェニキア人によって造られ、バシリカや大聖堂、劇場などの施設が残されている。侵攻と宗教の問題により、街は七世紀に打ち捨てられた。","note":"発見物カード:125","exp":"250"}],"3668":[{"type":"宗教遺物","name":"セクメト像","rank":"4","desc":"雌ライオンの頭を持つ女神像。太陽神ラーが自分を崇めない人間を滅ぼすために地上に派遣したという伝説がある。伝染病を司るとされ、カルナック神殿の一角でよく発掘されるという。","note":"ダンジョン","exp":"640"}],"6752":[{"type":"天文","name":"タランチュラ星雲","rank":"5","desc":"かじき座にある星雲で大マゼラン雲の最先端に位置する。1751年、ラカーユが喜望峰へ遠征した時に初めて発見したとされる。","note":"","exp":""}],"711":[{"type":"中型生物","name":"ホシガメ","rank":"1","desc":"インドを中心に生息するリクガメ。草食性でなぜか赤い植物を特に好むようだ。甲羅に放射状の模様があり、大変美しい。","note":"水に入らないカメ","exp":"180"}],"1270":[{"type":"中型生物","name":"オセロット","rank":"3","desc":"名前は「野生の虎」を意味する現地の言葉に由来する。森林地帯や乾燥した荒地など、様々な環境に生息する。主に地上で活動するが木登りも得意である。その姿はなかなか目撃できない。","note":"姿を見せない生物<br/><br/>発見時経験値511　発見物カード経験値255","exp":"511"}],"1815":[{"type":"財宝","name":"星の花","rank":"4","desc":"南米西岸で産出される桃色の宝石。インカローズとも呼ばれる。花のような優しい色彩と星の光のような輝きは見るものの疲れを癒し純朴で温かな気持ちを呼び覚ましてくれる。","note":"癒しの宝石","exp":"350"}],"856":[{"type":"歴史遺物","name":"ソクラテスの盃","rank":"5","desc":"ソクラテスが獄中で毒ニンジンをあおって自殺したときの盃。ソクラテスは古代ギリシャ最大の哲学者で、弟子にプラトンがいる。","note":"哲学者と悪妻","exp":"1040"}],"2828":[{"type":"化石","name":"巨大なゾウの骨","rank":"5","desc":"黄河付近で発見された大型のゾウの骨。\n左右の牙の間が狭く、鼻を通すことはできそうもない。","note":"大型生物の骨をめぐる論争","exp":"1120"}],"3295":[{"type":"史跡","name":"巨人のテーブル","rank":"5","desc":"バレン高原に存在する古代史跡。新石器時代に建てられた墓だと思われる。この巨大な岩を、どのように運んだのだろうか…。","note":"巨人の積み上げた石","exp":"820"}],"5738":[{"type":"海洋生物","name":"ゴロミャンカ","rank":"2","desc":"バイカル湖に生息する深海魚ならぬ深湖魚。ウロコや浮袋を持たないが、その豊富な脂肪分によって浮くことができる。","note":"2017.02.07新規追加","exp":"270"}],"1536":[{"type":"歴史遺物","name":"古代の水田跡","rank":"1","desc":"インドシナ半島沿岸は水量の豊かな川が多く流れ、古代から稲作が盛んだった。これがいつごろのものか特定できれば、この地域に人が住み始めた時期も分かるのだろうが…。","note":"古代の集落の地図","exp":"140"}],"3485":[{"type":"レリック","name":"ディドー","rank":"","desc":"地中海世界でローマと覇を競ったカルタゴ。その伝説の建国者は運命に翻弄された美しき女王であったといわれる。","note":"","exp":""}],"6975":[{"type":"宗教建築","name":"黄陵廟","rank":"5","desc":"長江のほとりにある寺院。夏王朝の王、禹の治水を助けた神牛を祀るための廟であり、その歴史は春秋時代にまで遡るという。創建の由来にちなんで当初は「黄牛廟」と呼ばれていた。","note":"発見物カード:550","exp":"1100"}],"5987":[{"type":"歴史遺物","name":"ハドリアヌス帝の大理石像","rank":"1","desc":"ハドリアヌス帝は、古代ローマ五賢帝の三人目である。防衛策に徹して制度を整え、ローマを発展させた。","note":"五賢帝の大理石像","exp":"70"}],"2921":[{"type":"歴史遺物","name":"地下墓地の骨","rank":"2","desc":"リマの教会地下に葬られた人骨。頭蓋骨や他の部分の骨が、絵画のように並べられている様は圧巻である。\n骨の損傷はあまりなくどれも原形を保っている。","note":"ダンジョン","exp":"370"}],"5740":[{"type":"地理","name":"オリホン島","rank":"1","desc":"バイカル湖に浮かぶ最大の島。島の東側は山地になっており、それ以外にも針葉樹林、草原、小さな砂漠、湖など、変化に富んだ地形をしている。古くからモンゴル系の民族が住んでいる。","note":"2017.02.07新規追加","exp":"200"}],"6642":[{"type":"史跡","name":"ウバール遺跡","rank":"5","desc":"紀元前、乳香の貿易によって栄えたオアシス都市の遺跡。残存する要塞の壁から推測するに、乳香の交易路の要衝として往時は栄えていたと考えられる。","note":"レガシー商の叡智・財貨の交易路　左上","exp":""}],"4956":[{"type":"植物","name":"アネモネ","rank":"2","desc":"地中海沿岸に咲く花。花の色は鮮やかで多様である。ギリシャ神話では、女神アフロディテに愛された美少年アドニスが流した血からアネモネが生まれたといわれている。","note":"アフロディテの切ない花<br/><br/>発見時経験値260　発見物カード経験値130","exp":"260"}],"2081":[{"type":"虫類","name":"パラポネラ","rank":"5","desc":"体長3cmもあるアリ。集団生活をしているが体が大きいので単独で行動する。強力な毒を持ち、刺されると死に至ることもある。\n単体としては昆虫の中で最強と目される。","note":"巨大なアリ","exp":"830"}],"6365":[{"type":"宗教建築","name":"ブッダガヤの大菩提寺","rank":"3","desc":"インドの北東部にある巨大な寺院。瞑想の末に釈迦が悟りを開いた場所とされる。52mもの高さの塔はレンガ造りで九つの層があり、その頂上の四方に小塔が立つ「五堂形式」となっている。","note":"","exp":"440"}],"4792":[{"type":"植物","name":"パンノキ","rank":"","desc":"オセアニアで栽培されている植物。その実は蒸し焼きや丸焼きなどにして食べられる。加工することで日持ちのする非常食にすることもできる便利な作物である。","note":"クエスト「主食にできる木の実」<br/>発見物カード:120","exp":"240"}],"5628":[{"type":"地理","name":"カプリ島","rank":"1","desc":"ナポリの南に位置する島。かつてローマ帝国の皇帝の別荘地とされていた。島の外周の大部分は絶壁に囲まれており、海蝕洞が存在する。","note":"","exp":"160"}],"6338":[{"type":"史跡","name":"ディキスの石球","rank":"2","desc":"中南米の密林で発見された石球群。大きさはまちまちであり、最も大きいものは直径2mを超える。製作の目的や手法は不明。","note":"","exp":"280"}],"6023":[{"type":"財宝","name":"料理の形式","rank":"2","desc":"14世紀イングランドの王侯貴族向けの料理本で、フランス語由来の調理用語が使われている。リチャード2世の料理長によって編纂されたといわれ、当時はまだ珍しかった砂糖やインド・アジア・中東産の香辛料やハーブを使った料理が多い。","note":"カード経験150","exp":"300"}],"1222":[{"type":"歴史遺物","name":"ひすいの装飾花瓶","rank":"2","desc":"ひすいで作られた豪華な花瓶。外面中腹には陶器の装飾がついている。これだけ手の込んだ花瓶であれば、貴族の持ち物と思っていいだろう。","note":"マヤの芸術","exp":"270"}],"6274":[{"type":"宗教遺物","name":"スーリヤの仮面","rank":"2","desc":"インド神話に登場する太陽神スーリヤの顔をかたどった仮面。\nインドではこうして金属や石などで作った神の顔を寺院や家庭の各所に飾ることが多いらしい。太陽の光と熱を現地の人々の感覚で表現した顔つきとなっている。","note":"","exp":"370"}],"62":[{"type":"宗教遺物","name":"梵字の巻物","rank":"3","desc":"「ぼんじ」。インドの梵字で書かれた巻物。梵字はもともとサンスクリット語の文字だがやがて宗教的意味が強くなった。","note":"インドの古文書の地図","exp":"410"}],"6144":[{"type":"宗教遺物","name":"フェルナンドの聖書","rank":"1","desc":"フェルナンド王子が普段使っている聖書の写本。ページの紙自体は古びているが、大きな傷などはまったく見当たらない。随分長く、丁寧に読まれてきたようだ。「忠義ある限り尽くさん」と書かれたメモが二枚挟まれている。","note":"","exp":"130"}],"974":[{"type":"財宝","name":"ローマ法大全","rank":"1","desc":"ビザンツ帝国皇帝・ユスティニアヌス1世が作らせた法典である。「法学提要」「学説類集」「勅法類集」「新勅法類集」からなる。法学の基礎。","note":"法学の基盤","exp":"200"}],"184":[{"type":"宗教遺物","name":"祭礼用マスク","rank":"1","desc":"祭礼で使われる仮面。威厳を持たせるためか奇妙な表情だ。鳥の羽や色石などで美しく飾られている。","note":"セウタの仮面の噂","exp":"30"}],"2370":[{"type":"小型生物","name":"モリアオガエル","rank":"1","desc":"日本固有のカエル。主に本州と佐渡島に分布している。\n水中に産卵するほとんどのカエルと異なり、水面上にせり出した木の枝などに卵を産み付けるのが特徴。","note":"水辺のカエルの地図","exp":"90"}],"629":[{"type":"鳥類","name":"コンゴウインコ","rank":"5","desc":"極彩色の大型インコ。尾までいれると1m以上あり、非常に美しい。赤が基調のものがほとんどだが、青い種類もいるようだ。インコの例にもれず、飛ぶのはあまりうまくない。","note":"七色の鳥","exp":"910"}],"658":[{"type":"美術品","name":"イコン","rank":"1","desc":"正教会で信仰に用いられる聖像。宗教上の聖人や重要なシーンを描いたものである。","note":"小さな宗教画の地図","exp":"26"}],"4998":[{"type":"天文","name":"ケフェウス座の花のような星雲","rank":"2","desc":"ケフェウス座の腰にあたる星の近くにある星雲。雲の形状が美しい青い花を思わせる。","note":"テラ・ノヴァ沖　視認<br/>「天文学者の観測記録」<br/>発見物カード:145","exp":"290"}],"1425":[{"type":"財宝","name":"メキシコ征服記","rank":"2","desc":"コルテス軍に従軍したベルナール・ディアスの著。コルテスが本国を発ってからの足跡を綴っている。作成途中に放棄されたようで、内容は不十分だ。これが完成されて世に出されれば、後世に伝わる重要な記録となろう。","note":"コルテス探険記録","exp":"210"}],"5166":[{"type":"港・集落","name":"ヤッファ","rank":"1","desc":"紀元前から存在する、歴史のある街。さまざまな文明の交流点で、歴史の舞台として興味深い土地である。乾燥気味の土地に適した作物が栽培されるほか、この地方の特色である高い製鉄技術による産物が流通している。","note":"到達する","exp":"37"}],"206":[{"type":"美術品","name":"旧約聖書のタペストリー","rank":"1","desc":"シモン・ブーエの原画をもとにした連作タペストリーの一つ。旧約聖書をもとにした内容で、全部で八枚あるという。分厚く豪華なゴブラン織りのタペストリーである。","note":"タペストリーの地図","exp":"70"}],"921":[{"type":"鳥類","name":"アカトビ","rank":"2","desc":"うろこのように見える羽の重なりが美しく、群をなして低空を飛行する。翼を部分的に曲げて、尾を船の舵のように使って常に傾斜姿勢で飛びながら獲物を探す。","note":"緋色のハンター","exp":"265"}],"2882":[{"type":"地理","name":"青城山","rank":"3","desc":"重慶付近の山の一つで道教の発祥地。\n樹齢の古い木々が多く一年を通して緑に覆われていることから、この名前が付いたといわれる。","note":"クエスト「不老不死を求めて」<br/>発見物カード:240","exp":"480"}],"5412":[{"type":"財宝","name":"ボンビーリャ","rank":"2","desc":"南米に住むグアラニーの人々が、茶の一種を飲むときに使用する道具。先端に複数の穴を空けた筒で、飲んだ際に茶葉が口に入らない構造になっている。","note":"","exp":""}],"6502":[{"type":"美術品","name":"オリンピア大祭の勝者の像","rank":"5","desc":"オリンピアで4年に1回開催されていた競技祭で勝利した選手の像。勝者は神と並ぶ栄誉を与えられ、神域に自らの像を立てることを許された。参加資格はギリシャ人である男子に限られていたという。","note":"","exp":""}],"6261":[{"type":"小型生物","name":"オオガラゴ","rank":"2","desc":"アフリカ南部の森林に多く生息している、小さなサルの一種。ふさふさとした長い尾が特徴。夜行性で、昼は樹上や木のうろなどに隠れて眠っていることが多い。雑食で、虫や果実をはじめ、小鳥やその卵、花や種子などまで食べる。","note":"","exp":"230"}],"6676":[{"type":"天文","name":"デネブ・カイトス","rank":"4","desc":"くじら座で最も明るいオレンジ色の星。くじらの尾に輝く。アラビア語で「2匹目の蛙」の意味。みなみのうお座のフォーマルハウトが1匹目の蛙にあたる。名はアラビア語の「海の怪物の南の尾」に由来する。","note":"発見物カード:400","exp":"800"}],"6434":[{"type":"歴史遺物","name":"シッカートの自動計算機械","rank":"5","desc":"世界初の自動計算機とされ、ドイツのテュービンゲン大学ヘブライ語教授ヴィルヘイム・シッカートが17世紀前半に作成。別名「計算する時計」。6桁の加減算や込み入った乗算ができ、天文計算に使用する想定だったといわれる。","note":"レガシー　数の叡智・世界の計算機　左上","exp":""}],"4972":[{"type":"史跡","name":"ミュケナイ遺跡","rank":"4","desc":"ペロポネソス半島の北東部にある遺跡。紀元前に栄えていた、ミュケナイ文明の中心地。数々の黄金細工が発見されており、当時は金がよく利用されていたとみられる。","note":"","exp":"720"}],"2043":[{"type":"財宝","name":"ダ・ヴィンチノート","rank":"2","desc":"ダ・ヴィンチ直筆の著書。天文学や医術に関する知識や考察から、デッサンやスケッチまで幅広く記述されている。しかし文字はすべて鏡文字で書かれており、読むことは容易ではない。","note":"［勅命］[[運河開通事業の技術書","exp":"310"}],"1517":[{"type":"大型生物","name":"ミズシカ","rank":"1","desc":"濃い茶色の被毛で覆われたシカ。オスは長さ1m以上の三股の枝角を持つ。夜行性でさまざまな植物を餌とする。","note":"野生のシカの地図","exp":"110"}],"2723":[{"type":"小型生物","name":"クロアカコウモリ","rank":"4","desc":"洞窟のような暗い場所に生息するコウモリ。コウモリといえば地味な色合いを連想するがこれは橙色に見える。朝鮮の人々は、その橙色を金色と呼んだ。","note":"黄金の飛翔物体<br/><br/>発見時経験値350　発見物カード経験値175","exp":"750"}],"662":[{"type":"小型生物","name":"フェレット","rank":"1","desc":"別名をケナガイタチという。普通のイタチより毛足が長いため、見た目はかわいらしい。とはいえ、やはりイタチなので強烈な悪臭を放つ。船員たちに連れ帰らないよう、きつく言いつけなくては。","note":"小型肉食獣の地図","exp":"27"}],"1841":[{"type":"宗教遺物","name":"精霊の像","rank":"4","desc":"ニューギニアで信仰されている精霊を形にした像。この島では精霊を称え、木像で具現化する。","note":"ニューギニアの精霊信仰","exp":"720"}],"6931":[{"type":"小型生物","name":"ブラウンバシリスク","rank":"4","desc":"クレストと呼ばれる、帆のようなたてがみが特徴のトカゲの一種。中南米の熱帯雨林に生息する。体は茶褐色をしており、バシリスクの仲間としては最大と言われている。","note":"発見物カード:390","exp":"780"}],"1306":[{"type":"虫類","name":"アトラスオオカブト","rank":"3","desc":"三本の長い角が特徴である虫。黒くてつやのある大きな体をしている。攻撃性が強く、すばやい動きをする。","note":"図鑑に載せたい","exp":"451"}],"5847":[{"type":"海洋生物","name":"フシギウオ","rank":"4","desc":"赤道付近にのみ生息するとみられる深海魚の一種。特徴の少ない魚だが、幼体の頃のみ、体よりも長い腹ビレを持つ。ヒレの先には房状の器官がたくさんあるが、なんのためのものなのかはいまだ解明されていない。","note":"","exp":"620"}],"4858":[{"type":"天文","name":"ぎょしゃ座","rank":"2","desc":"五角形の星の並びが特徴的な星座。ギリシャ神話においては、アテナイ王・エリクトニオスとも、ヘルメスの息子・ミュルティロスであるともいわれる。","note":"クエスト「天に昇った優れた王」<br/><br/>発見物カード:175<br/>","exp":"350"}],"1341":[{"type":"地理","name":"セレベス海","rank":"2","desc":"セレベス島北部に広がる海。魚の豊富な海域として知られているが水深が深いため、波は高く、海流も複雑である。周囲の島々の交流航路として船の往来が絶えない。","note":"香料諸島の空白地帯","exp":"280"}],"3423":[{"type":"レリック","name":"レメゲトン","rank":"","desc":"かのソロモン王の秘術や、悪魔や天使の使役法が記された魔道書。数多の知識が記されているのだが、良いものばかりとも思えない。","note":"","exp":""}],"5651":[{"type":"海洋生物","name":"ニシキアナゴ","rank":"2","desc":"浅い海の底に生息する魚。太平洋やインド洋で見られる。体調は最大で40cm程度となる。黄色と白色の縞模様が特徴。","note":"ボルネオ島北西端付近","exp":"310"}],"1311":[{"type":"地理","name":"サンマティアス湾","rank":"1","desc":"南米南東岸にある湾。付近を流れる海流は寒流で、比較的寒い地域にあたる。北部には、水が黒い不思議な川が流れている。","note":"書きかけの地図","exp":"90"}],"545":[{"type":"歴史遺物","name":"木の棺","rank":"1","desc":"古くから埋葬に使われた木の棺。直方体の物から、人の形に加工した、手の込んだ物までさまざまである。","note":"古代の墳墓の地図","exp":"11"}],"6815":[{"type":"財宝","name":"ターコイズの双頭蛇","rank":"5","desc":"アステカ帝国で作られた工芸品。双頭の蛇をかたどっており、全身は当時アステカで貴重だったターコイズのモザイクに覆われ、口や牙は貝殻で装飾されている。儀式などで使用された胸飾りではないかと推測される。","note":"発見物カード:480","exp":"960"}],"6326":[{"type":"中型生物","name":"ヘアリーブッシュバイパー","rank":"2","desc":"中央アフリカに生息するヘビ。全身を逆立ったうろこが覆っているため、植物などに這い上がりやすい。相手の動きを止める神経毒と、大量出血を促す出血毒の二種類の毒を使って獲物を仕留める。","note":"","exp":"310"}],"874":[{"type":"小型生物","name":"トビウサギ","rank":"1","desc":"長くてふさふさした尾と大きな耳が特徴。一回の跳躍で、ゆうに2mを超える。夜行性で、いくつかの巣穴を掘って生活する。","note":"逃げ足の速いウサギ","exp":"160"}],"3666":[{"type":"歴史遺物","name":"アンデスの織物","rank":"3","desc":"アンデス高原の人々がアルパカの毛や木綿を様々な手段で鮮やかに染めて作った織物。発色も素晴らしいが、織りの技術も極めて高く模様を再現することは非常に難しい。","note":"ダンジョン","exp":"510"}],"6850":[{"type":"天文","name":"ネカル","rank":"2","desc":"うしかい座のベータ星で、牛飼いの頭の部分に位置する。アラビア語で「牡牛を追う者」に由来する。","note":"発見物カード:150","exp":"300"}],"5045":[{"type":"港・集落","name":"キルワ","rank":"1","desc":"東アフリカのスワヒリ海岸に位置する港町。季節風にのってやってくるアラブやペルシャ商人たちの一時的な居留地として次第に発展した。","note":"到達する","exp":"76"}],"6540":[{"type":"史跡","name":"カイト・ベイ要塞","rank":"2","desc":"アレクサンドリアの半島部にある要塞。七不思議の一つアレクサンドリアの大灯台が14世紀の地震で崩壊した跡地に、マムルーク朝スルタンであるカイト・ベイが建設した。崩壊した大灯台の資材も、建造に再利用されたと考えられている。","note":"","exp":"280"}],"455":[{"type":"小型生物","name":"ヤドクガエル","rank":"5","desc":"極彩色のカエル。色はさまざまで、別の種類なのか個体差なのかよくわからないほどだ。いずれも毒を持ち、特に毒が強いものは粘液を矢に塗って、狩りに使うのだそうだ。","note":"禁断のイチゴ","exp":"1040"}],"6847":[{"type":"天文","name":"ニハル","rank":"2","desc":"うさぎ座で2番目に明るいベータ星。3等星であり、黄色味を帯びた輝きをもつ。名はアラビア語で「喉の渇きを癒やし始めたラクダたち」を意味する。","note":"発見物カード:105","exp":"210"}],"661":[{"type":"小型生物","name":"オコジョ","rank":"1","desc":"イタチに似た小型の動物。冬には白い毛に生えかわる。完全な肉食で、ネズミや小鳥を食べるようだ。","note":"小型肉食獣の地図","exp":"45"}],"1818":[{"type":"財宝","name":"金の器","rank":"1","desc":"クスコ近郊で見つかった金の器。金が豊富なこの地では、皇帝だけでなく貴族階級も、金の器や盃で食事をしていたという。さすがに一般階級ではそういうことはなさそうだが。","note":"金細工の地図","exp":"140"}],"1610":[{"type":"鳥類","name":"レア","rank":"1","desc":"ダチョウによく似た大型のトリ。飛ぶことはできず、草原や低木地に生息し、植物の葉や種子を好んで食べる。","note":"脚の長い動物の地図","exp":"75"}],"5260":[{"type":"宗教遺物","name":"カーリーのレリーフ","rank":"2","desc":"寺院の壁に数多く彫られているレリーフの一つ。本尊シヴァ神の妻であるカーリーが、夫の腹の上で踊る様子が見事な手法で彫られている。","note":"タンジャーウール地方　再調査報酬","exp":""}],"561":[{"type":"史跡","name":"モヘンジョ・ダロ","rank":"3","desc":"インダス文明の大都市遺跡。非常によく整備された街並みを持ち、下水道すら完備されている。「死の丘」などと呼ばれるのは、全体に人骨が散在するためである。","note":"古代文明の大都市","exp":"473"}],"5417":[{"type":"小型生物","name":"グラスフロッグ","rank":"2","desc":"主に南米の多湿帯に生息するカエルの珍種。腹部が半透明になっており、心臓や消化管などの内臓が透けて見える。生息範囲は非常に狭いようだ。","note":"奇妙なカエルの地図（アマゾン奥地再調査報酬）","exp":""}],"2068":[{"type":"虫類","name":"ミズカマキリ","rank":"4","desc":"カマキリと名がついているがカマキリの仲間ではない。\n昆虫や小魚を餌とし、捕らえた獲物に消化液を送り、溶けた体液を吸う。翅があり、空を飛ぶこともできる。","note":"吸血鬼現る<br/><br/>発見時経験値650　発見物カード経験値325","exp":"650"}],"3232":[{"type":"歴史遺物","name":"ミョルニル","rank":"5","desc":"北欧神話の雷神トールの戦槌。すさまじい破壊力を誇り、一撃で倒せなかったのはロキの子・ヨルムンガンドくらいである。\n北欧ではミョルニルをお守りとしてペンダントにしたり、儀式に用いたりする。","note":"ヴィンランドの詩","exp":"1360"}],"6598":[{"type":"史跡","name":"シーギリヤ","rank":"5","desc":"セイロン島の中央付近にある遺跡。アヌラーダプラ王国の王となったカッサパ1世が弟による王権奪取を恐れ、高さ200m近い切り立った突岩の上に王宮を建設し、その周辺に遷都したといわれる。","note":"レガシー伝説の王都バビロン　下","exp":"2250"}],"1748":[{"type":"虫類","name":"ミイロタイマイ","rank":"5","desc":"ニューギニアに生息する美しいチョウ。宝石のように輝く羽を持ち群れで空中を素早く飛び回る。","note":"夢か現か<br/><br/>発見時経験値1040　発見物カード経験値520","exp":"1040"}],"5067":[{"type":"港・集落","name":"サンフランシスコ","rank":"2","desc":"北米西部にある街。カリフォルニアのゴールドラッシュによって爆発的に人口が増え、産業や流通業が急激に発展した。活気のある街だが、治安の悪化も懸念されている。","note":"到達する","exp":"330"}],"3895":[{"type":"天文","name":"うしかい座","rank":"2","desc":"古代ギリシャの叙事詩オデュッセイアにも記述があり、古くから存在していた星座。おおぐま座を追う牛飼いといわれるが、ギリシャ神話にはっきりとした由来がない。","note":"クエスト「叙事詩に登場する星座」<br/>発見物カード:220","exp":"440"}],"6342":[{"type":"歴史遺物","name":"モヘンジョ・ダロの像","rank":"2","desc":"南アジアで発見された石像。上流階級の人物をかたどっているとされる。像の片肌を出してまとった衣服には凝った模様があり、西方の文化の影響がうかがえるようだ。","note":"","exp":"360"}],"5898":[{"type":"史跡","name":"アラム・ムルの神の門","rank":"5","desc":"チチカカ湖周辺にある遺跡。扉のように見える窪みがある。古代の王アラム・ムルはこの窪みを通って姿を消すと、二度と戻ってこなかったと伝えられる。","note":"","exp":"1400"}],"1866":[{"type":"歴史遺物","name":"銅製の仮面","rank":"2","desc":"南米の文化では金や銀の装飾がよく見られるが、それよりもさらに古くから銅は用いられていた。こういった仮面は王の持物、もしくは副葬品が主なことから、銅の価値が高かったことがうかがえる。","note":"神をかたどった仮面<br/><br/>発見時経験値320　発見物カード経験値160","exp":"320"}],"5729":[{"type":"歴史遺物","name":"カルナの耳環","rank":"5","desc":"『マハーバーラタ』に登場する英雄カルナが身に着けていたという黄金の耳環。鎧と共に身に着けると、不死身の力を得ると伝えられている。","note":"インドの人気者","exp":"1470"}],"6724":[{"type":"天文","name":"きりん座の渦巻星雲","rank":"2","desc":"きりん座にある渦巻のような形をした星雲。キリンの前足辺りに位置する。","note":"「天文学者の観測記録」 アイスランド海盆視認<br/>発見物カード:145<br/>    <br/>    <br/>※特定できないが前提ある可能性高そう。「きりん座」「キリン：大型生物」だけではなさそうです。","exp":"290"}],"6592":[{"type":"史跡","name":"アイト・ベン・ハッドゥ","rank":"5","desc":"アトラス山脈の麓、モロッコの内陸部にある要塞化された集落跡。一つしかない入口、入り組んだ構造の通路、建物1階には窓がないなど、集落は外敵から身を守る城塞のような造りになっているという。","note":"レガシー伝説の王都バビロン　左上","exp":"2250"}],"2373":[{"type":"海洋生物","name":"ツチクジラ","rank":"1","desc":"北太平洋の比較的暖かい海域に生息するクジラ。体長およそ10m。頭の形が槌（つち）に似ていることから、この名が付いたという。","note":"槌に似た頭のクジラの地図","exp":"150"}],"5612":[{"type":"財宝","name":"クー・スティック","rank":"2","desc":"北米の先住民族の戦士が所持する棒。羽根などで装飾されている。戦いで「カウンティング・クー」（相手を殺さず、棒だけを当てて去る）と呼ばれる勇者の行為をするために使われるという。","note":"経験値は補正入ってたので誤差あるかも。","exp":"381"}],"6148":[{"type":"歴史遺物","name":"アルジュバロータの長弓","rank":"2","desc":"ポルトガル王ジョアン1世が使っていたとされる長弓。息子のエンリケに譲られ、サグレスの訓練学校に保管されていた。","note":"","exp":"243"}],"5796":[{"type":"歴史遺物","name":"コンスタンティヌスの寄進状","rank":"5","desc":"教皇領成立の根拠として用いられた寄進状。コンスタンティヌス帝の書いたものとされているが、偽書ではないか、と疑われている。","note":"教皇領の根拠","exp":"1360"}],"6359":[{"type":"財宝","name":"蒸留術の書","rank":"5","desc":"蒸留術に関する書物。ヨーロッパに伝来し、ドイツ語に翻訳されたことで、蒸留術が周知された。植物から精油を抽出する方法やその効能、保存法などが記されている。蒸留で生成された精油は、ペスト治療などにも用いられたとされる。","note":"","exp":"1110"}],"1135":[{"type":"美術品","name":"聖母子と幼児ヨハネ","rank":"2","desc":"ラファエロ作の絵画。別名を、「小椅子の聖母」という。ラファエロのそれまでの聖母像と異なり、生気にあふれている。恋人であるマルゲリータをモデルにしているとうわさされている。","note":"教会の宗教画の地図","exp":"255"}],"1802":[{"type":"美術品","name":"メランコリア","rank":"3","desc":"アルブレヒト・デューラーの代表作ともいえる銅版画。この版画の中には球や多面体から砂時計や秤などの日用品に至る様々なものが描きこまれている。これらがなにを表しているのか、デューラー本人しか知りえない。","note":"デューラーの憂鬱","exp":"480"}],"5661":[{"type":"地理","name":"トドラ渓谷","rank":"2","desc":"アフリカ北西部に位置する雄大な渓谷。切り立った断崖が並んでおり、見事な景観を成している。","note":"","exp":"220"}],"1880":[{"type":"地理","name":"チャグレス川","rank":"2","desc":"カリブ海側から内陸へ続く川。この川を利用し、地峡を越えることができれば運河が開通するのだが…。","note":"［勅命］[[運河開通予定場所の調査","exp":"310"}],"514":[{"type":"歴史遺物","name":"サッフォーの詩集","rank":"4","desc":"古代ギリシャの女流詩人であるサッフォーの詩集。もとは9集あったと伝えられるが、美しい乙女への賛歌が多いため、不道徳とされて中世に多くが失われた。","note":"古代の禁書","exp":"612"}],"2610":[{"type":"宗教遺物","name":"火渡りの神輿","rank":"5","desc":"読みは「ひわたりのみこし」。古代から台湾島に伝わる神輿。清めの儀式で使われた。\nこの神輿を担ぎ、熱い灰の上を歩くと、穢れが取り除かれ、災いを避けられるといわれている。","note":"灰の上を歩く祭り","exp":"1060"}],"3967":[{"type":"天文","name":"ミラ","rank":"5","desc":"約332日の周期で2等星から10等星まで明るさを変えるくじら座の恒星。名はラテン語で不思議なものを意味し、1779年には1等星まで明るくなった。","note":"発見物カード:410","exp":"820"}],"2794":[{"type":"財宝","name":"百済王の冠飾り","rank":"2","desc":"百済の遺跡で発見された、冠を飾るためのもの。百済王が使用していたものと思われる。金で作られており、とても豪華だ。","note":"ダンジョン","exp":"370"}],"2556":[{"type":"鳥類","name":"タカサゴマシコ","rank":"4","desc":"山麓の森林や農耕地に生息する鳥。\n雄は鮮やかな赤い色をしており、とても目立つが、めったに見られない。台湾島では阿里山で見かけられる。","note":"台湾島の鳥調査","exp":"680"}],"1530":[{"type":"虫類","name":"メガネトリバネアゲハ","rank":"1","desc":"黒い大きな模様に、黄金色がかった緑の羽を持つチョウ。羽を広げると、大人の手のひらほどもある。","note":"大きなチョウの地図","exp":"110"}],"2846":[{"type":"財宝","name":"三国志","rank":"3","desc":"漢代末期から三国時代にかけての興亡を記した歴史書。\n蜀の陳寿が編さんしたと伝わっている。\nこれを元にした説話も多い。","note":"小説より面白い歴史","exp":"460"}],"3873":[{"type":"地理","name":"バランスロック","rank":"2","desc":"北米西部の内陸にある巨大な岩。長い年月を経て岩が侵食されたのか、不安定で倒れそうに見える状態で立っている。","note":"書きかけの地図","exp":"280"}],"5654":[{"type":"虫類","name":"キリアツメゴミムシダマシ","rank":"4","desc":"南西アフリカのナミブ砂漠に生息する虫。背の凹凸は水を引き寄せやすい性質を持ち、霧から水分を集めて飲めるようになっている。","note":"","exp":"740"}],"606":[{"type":"宗教遺物","name":"アヌビス像","rank":"1","desc":"エジプト神話の死者の神。山犬の姿、もしくは山犬の頭を持つ姿で表される。死後、死者の心臓の重さを真実の羽と比べ、死者の行く末を決めるという。","note":"裁きの山犬の姿","exp":"110"}],"6997":[{"type":"歴史遺物","name":"法令の木簡","rank":"5","desc":"日本最古の律令「飛鳥浄御原令」に関する記述が残る木簡。飛鳥浄\n御原令は、天武天皇と持統天皇により制定された日本初の法典であ\nり、これにより刑法と民法が初めて体系的に整備された。","note":"","exp":"1500"}],"1273":[{"type":"美術品","name":"赤いターバンの男の肖像","rank":"3","desc":"ヤン・ファン・エイク作。諸説あるが、エイク本人を描いたものといわれている。彼はそれまでの画法を改良して、この絵のように細部まで描き込むことを可能にし、深く多彩な光陰を表現することに成功した。","note":"新たな技法","exp":"462"}],"5311":[{"type":"小型生物","name":"パフアダー","rank":"5","desc":"アフリカ中南部に生息する毒ヘビ。太い体に矢筈模様があり、全長は2ｍ近くになることがある。危険を察知すると「パフ、パフ」と空気を噴いて威嚇し、それが名前の由来だという。大きい毒牙と多量の毒を持ち、非常に危険。","note":"","exp":"930"}],"2378":[{"type":"植物","name":"ハマゴウ","rank":"2","desc":"東アジアからオーストラリアの、比較的暖かい地方に広く分布する海浜植物。果実は生薬として用いられる。\n枝や葉には香りがあり香の材料としても用いられる。","note":"香の材料","exp":"240"}],"6526":[{"type":"財宝","name":"ケプラー式望遠鏡","rank":"2","desc":"ケプラーが原理を考案した屈折式望遠鏡。のちにシャイナーによって製作された。対物と接眼、いずれも凸レンズを使う。ガリレオ式よりもさらに高倍率で広視野だが、上下逆に映るため、主として天体観測に用いられたとされる。","note":"","exp":""}],"6972":[{"type":"小型生物","name":"キエリテン","rank":"1","desc":"アジアに広く生息するテンの一種。主に胸周りの体毛が鮮やかな橙色であることが名前の由来になっている。体は黄褐色で、頭や四肢は黒く、顎下の体毛は白いなど、体毛の色合いが特徴的である。","note":"発見物カード:315","exp":"630"}],"85":[{"type":"歴史遺物","name":"メンカウラー王のトライアド","rank":"2","desc":"メンカウラー王はギザのピラミッドのうち、一番小さなピラミッドの主である。これはメンカウラー王と両脇に二柱の女神を置いた石像。","note":"エジプトの王の遺物","exp":"220"}],"2322":[{"type":"財宝","name":"京人形","rank":"2","desc":"日本の堺近辺で作られる人形。土産物として江戸の町によく運ばれてくるらしい。\n元々は、子供の身代わりに災いを引き受けるものとして用いられたという。","note":"名物土産物","exp":"260"}],"5477":[{"type":"中型生物","name":"リスザル","rank":"2","desc":"体長30cm、尾長40cm、体重1kgほどの小型のサル。数十頭の群れを作って生活している。温和で寂しがりな性格で、一頭だけにすると死んでしまうといわれる。","note":"クエスト「サルの生態調査」<br/>発見物カード:175","exp":"350"}],"2674":[{"type":"地理","name":"白馬江","rank":"3","desc":"かつて、百済と新羅が争った地に流れる川。広い川幅と緩やかな流れ、白い砂州と緑の山並みが調和し美しい風景を作り出している。","note":"歴史の川","exp":"460"}],"6467":[{"type":"大型生物","name":"ウリボウ","rank":"5","desc":"イノシシの幼体。ずんぐりした体に短く鋭い牙を持つ。イノシシは警戒心が強く、人間を襲うこともある動物だが、幼体はとてもかわいらしく、その瓜に似た見た目からウリボウと呼ばれる。","note":"追究クエスト<br/>発見物カード:550","exp":"1100"}],"1315":[{"type":"地理","name":"モルッカ海","rank":"2","desc":"セレベス島の東に位置する海。多くの島があり、それぞれに独自の民族が生活しているようだ。また、貴重な香辛料を産出する島があることでも知られている。","note":"香りたつ海","exp":"320"}],"161":[{"type":"地理","name":"カイマン諸島","rank":"2","desc":"カリブ海のキューバ島南方に位置する諸島。発見当初はトルトゥーガ島（カメの意味）とも呼ばれた。ほとんどがサンゴ礁からなる、美しい島々である。","note":"サンゴの海","exp":"360"}],"6450":[{"type":"歴史遺物","name":"アランビック","rank":"5","desc":"8世紀ごろのペルシャで発達した蒸留器。イスラム圏からヨーロッパにかけて、化学者や錬金術師たちに広く用いられた。香料の材料から成分を蒸留して作られた精油は、蒸留酒と合わせて香水の原型となったとされる。","note":"","exp":""}],"800":[{"type":"史跡","name":"ジンバブエ遺跡","rank":"2","desc":"アフリカ南方にある、石造の建造物群。ショナ語で「石の家」という意味で、モノモタパ王国の都であった。アフリカで石造建築物を持つ文化は珍しい。","note":"大いなる石の家","exp":"260"}],"5557":[{"type":"植物","name":"ギョリュウバイ","rank":"5","desc":"オーストラリア大陸南東部およびニュージーランド列島原産の木。マオリの言葉では「マヌカ」と呼ばれる。蜜や葉にさまざまな薬効がある。","note":"薬効多き低木<br/><br/>発見時経験値1040　発見物カード経験値520","exp":"1040"}],"5764":[{"type":"地理","name":"カトマンズ盆地","rank":"2","desc":"ヒマラヤ山脈に囲まれた盆地。近辺に三つの王国が存在し、複雑な政治事情が展開されているようだ。","note":"","exp":""}],"3293":[{"type":"地理","name":"バースの鉱泉地","rank":"4","desc":"ブリテン島の南西部に位置する地域。古来より温泉がわく場所として有名である。ローマ帝国時代には皇帝の支配下に置かれて発展したこともあり、浴場などローマ式の建造物が残っている。","note":"ブリテン島の温泉場","exp":"610"}],"4800":[{"type":"宗教遺物","name":"ポリアフ像","rank":"3","desc":"ハワイ島の雪の女神。冬になると雪に閉ざされるマウナ・ケア山に住むとされる。かつて火山の女神ペレと争って彼女を島の南側にある火山に追いやったという伝説がある。","note":"クエスト「ハワイの雪神」<br/>発見物カード:250","exp":"504"}],"308":[{"type":"宗教遺物","name":"オドゥドゥア像","rank":"4","desc":"アフリカのヨルバ人の神の像。最高神であるオロルンが海と交わってオドゥドゥアを産みオドゥドゥアが大地と人間を作ったと伝えられている。","note":"ヨルバの創世物語","exp":"720"}],"5169":[{"type":"港・集落","name":"ラスパルマス","rank":"1","desc":"マディラの南方に浮かぶカナリア諸島の街。年中温暖な気候で過ごしやすく、美しい景観に恵まれている。温かい気候はサトウキビの栽培に向いており、近海ではサンゴが採れるようだ。","note":"到達する","exp":"25"}],"7014":[{"type":"天文","name":"シャウラ","rank":"3","desc":"さそり座のラムダ星で2等星。アルファ星のアンタレスに次いで明るい。サソリの毒針の部分に位置し、名はアラビア語で「針」を意味する。","note":"南太平洋海盆北視認","exp":""}],"5127":[{"type":"港・集落","name":"ファロ","rank":"1","desc":"リスボンの南に位置する、小都市。レコンキスタのとき、ポルトガル国内で最後までイスラム勢力が残っていた都市である。13世紀にポルトガル王がこの街を占拠し、レコンキスタは完了した。","note":"到達する","exp":"17"}],"603":[{"type":"宗教遺物","name":"サラスバティー像","rank":"3","desc":"インド神話の女神の像である。サラスバティーは、三大神の一人で創造をつかさどるブラフマーの妻であり最上の女神とされる。","note":"最高の女神","exp":"484"}],"6417":[{"type":"史跡","name":"ウルルの心臓","rank":"5","desc":"ウルルにあるハート型のくぼみ。その形から「ウルルの心臓」とも言われる。枯れることのないムティジュル泉の近くにある。現地の人たちからは神聖な場所として大切にされている。","note":"","exp":""}],"5160":[{"type":"港・集落","name":"マルセイユ","rank":"1","desc":"古代ギリシャ時代にマッシリアという名で築かれた街。ヴェネツィア商人も出入りし、交易が盛んである。周辺で農業が盛んなため、種々の農作物が豊富に取引される。","note":"到達する","exp":"29"}],"44":[{"type":"財宝","name":"金のアラビア風ランプ","rank":"2","desc":"黄金造りの、アラビア風ランプ。全体に美しいアラベスクが施されており、地金は18金である。ひんぱんに使われた形跡があり、これほどの物でありながら日用品だったようだ。","note":"イスラム文化の工芸品","exp":"280"}],"1618":[{"type":"歴史遺物","name":"穴の開いた頭蓋骨","rank":"2","desc":"南米で多く見つかる頭蓋骨。なにかの儀式のときに、死者の頭蓋骨をくりぬいたのか、それとも生きた人間の頭に穴を開けたのだろうか？","note":"奇妙な頭蓋骨の地図","exp":"255"}],"5662":[{"type":"化石","name":"背骨が上に伸びたトカゲの骨","rank":"2","desc":"アフリカ大陸北部で発見された、巨大なトカゲのような生物の骨。全長は約15mで、背骨から上方へと伸びる突起が特徴的である。","note":"","exp":"240"}],"1505":[{"type":"中型生物","name":"テナガザル","rank":"1","desc":"主に樹上で生活しているサル。長い手で枝をつかみ、体を振り子のように揺らして移動する。果物を食べる。","note":"手の長い動物の地図","exp":"75"}],"6509":[{"type":"史跡","name":"キロキティア","rank":"2","desc":"地中海の東部に浮かぶ巨大な島・キプロスにある先史時代の遺跡。遺跡内に残った石造りの土台は、円筒形の住居跡とされ、周りには集落を守るための外壁が張り巡らされていたとされる。","note":"","exp":"352"}],"889":[{"type":"中型生物","name":"マングース","rank":"2","desc":"毒蛇を食べる動物。大きなイタチのような外見をしている。毒が効かないわけではなく、かまれれば死んでしまうそうだ。体が小さい割りに気が荒い。","note":"毒蛇の天敵","exp":"330"}],"5732":[{"type":"財宝","name":"イエティの頭皮","rank":"4","desc":"謎の人型生物イエティの頭皮とされ、現地で祀られていた。伝承では神の使いだとされているが、実在するのだろうか…？","note":"","exp":"740"}],"3664":[{"type":"宗教遺物","name":"クヌム像","rank":"5","desc":"古代エジプトで信仰されていた羊頭の創造神の像。ナイル川を司る神でもあり、クフ王の名はこの神に由来するといわれる。","note":"ダンジョン","exp":"966"}],"2522":[{"type":"植物","name":"リュウガン","rank":"2","desc":"台湾島や中国南部などの暖かい地域で、初夏に黄白色の小花をたくさん付ける植物。\n直径2cmほどの果実が実る。\n果実を半分に切った時の見た目が龍の目玉に見えることから、この名前が付いた。","note":"龍の目に似た果実","exp":"270"}],"6396":[{"type":"歴史遺物","name":"石灰モルタルが塗られた石","rank":"5","desc":"石灰モルタルが塗られた大きな四角い石。石灰モルタルはギザのピラミッドにも使用されている。表面を整えたり高さを合わせたりする目的で塗られたと思われるが、この技術によってピラミッドが風化せず保たれたともいわれる。","note":"レガシー：砂漠に栄えた巨石文明","exp":"1950"}],"6452":[{"type":"歴史遺物","name":"貴妃の香","rank":"5","desc":"古代中国で服用されていた、食べる香「体身香」。絶世の美女といわれ、牡丹の花にも例えられた楊貴妃が愛用したとも伝わる。服用を続けると体から芳香が漂うようになるという。","note":"レガシー・香の叡智　右上","exp":"2550"}],"3765":[{"type":"天文","name":"水星","rank":"3","desc":"夕暮れと明け方のわずかな時間にのみ見られる惑星。古代ギリシャでは宵の水星をヘルメス、明けの水星をアポロンと読んでいた。金星に比べると暗く、太陽に近いため、観測はやや難しい。","note":"クエスト「コペルニクスの依頼」<br/>発見物カード:225","exp":"450"}],"5350":[{"type":"地理","name":"ヘクラ山","rank":"2","desc":"アイスランド南部にある火山。\nヘクラとは地元の言葉で頭巾を意味する。\nアイスランドで最も活動的な火山で、何度も噴火が記録されている。","note":"","exp":""}],"4958":[{"type":"歴史遺物","name":"クレタ島の陶器","rank":"1","desc":"古代のクレタ島で作られたとみられる陶器。風化のせいで色が薄くなってはいるが、よく見ればウシの絵が描かれているのがわかる。","note":"","exp":""}],"5931":[{"type":"地理","name":"サグレスの岩崖","rank":"2","desc":"「航海者の村」と呼ばれるサグレスの近くに位置し、ユーラシア大陸の最南西端にあたるサンヴィセンテ岬にも近い。サグレス岬を含んだこの一帯は地中海を往復する船乗りたちの間で海路の目印とされている。","note":"","exp":""}],"2977":[{"type":"地理","name":"エンジェルフォール","rank":"3","desc":"南米大陸の北部に位置する大滝。\n落差が1km近くあるため、流れる水のほとんどが落下途中で散ってしまう。そのため、滝つぼも存在しない。","note":"遥か高みより落ちる水","exp":"440"}],"5873":[{"type":"天文","name":"イカルス","rank":"5","desc":"小惑星の一つ。その軌道がかなり太陽の近くを通っていることからギリシャ神話のイカロスの名にちなんで名づけられた。十数年ごとに地球の近くも通り過ぎるようだ。","note":"発見物カード:635","exp":"1370"}],"499":[{"type":"歴史遺物","name":"ファランクスの槍","rank":"1","desc":"ファランクスとは古代ギリシャの重装歩兵密集部隊のことである。このような長い槍を構え、盾と兜と脛当てで武装し、密集して敵に突入した。","note":"古代ギリシャの槍の地図","exp":"59"}],"5667":[{"type":"天文","name":"パラス","rank":"2","desc":"火星の軌道の外側にある小惑星帯に位置する天体。同様の天体の中では、ケレスに次ぐ大きさとされている。","note":"「天文学者の観測記録」<br/>発見物カード:115","exp":"230"}],"5431":[{"type":"地理","name":"アゾレス諸島","rank":"1","desc":"イベリア半島南西端から西に1300kmほどに位置する諸島。これまでの航海技術では大陸を離れた航海が困難だったため、存在が認識されていなかった。年間を通して温暖なので、耕作に向いていると思われる。","note":"大西洋の真ん中","exp":"90"}],"3894":[{"type":"中型生物","name":"ビーバー","rank":"4","desc":"北米などの森林地方の水辺に生息する動物。手に水かきがあり、水中生活に適している。泥やかじり倒した木で川の水を堰き止め、その中に巣を作る。巣に限らず、住みやすいように周囲の環境まで変える習性がある。","note":"クエスト「すみかを造る動物」<br/>発見物カード:185","exp":"660"}],"6399":[{"type":"歴史遺物","name":"イムホテプの設計図","rank":"5","desc":"パピルスに古代エジプトの文字と図面らしきものが書かれている。初のピラミッドといわれるジェセル王の階段ピラミッドを築いた、宰相イムホテプによるピラミッドの設計図かもしれない。","note":"レガシー：砂漠に栄えた巨石文明","exp":"1500"}],"2912":[{"type":"歴史遺物","name":"彩色壁画の欠片","rank":"2","desc":"パレンケ遺跡内部に施された壁画の一部。\n欠片であるにも関わらず、繊細な彫刻が施されている。薄れてしまってはいるが、大部分に赤で彩色された跡があり、細部は緑、青、黄色で彩られている。","note":"ダンジョン","exp":"360"}],"6548":[{"type":"中型生物","name":"テングキノボリヘビ","rank":"5","desc":"マダガスカル島に生息するヘビ。先端がくちばしのような形をした特徴的な頭部を持つ。擬態能力に優れ、主に樹上で生活すると考えられている。","note":"追究クエスト","exp":"1720"}],"7026":[{"type":"虫類","name":"ヒゲナガオトシブミ","rank":"3","desc":"東アジアの森や草むらに生息する赤褐色の昆虫。頭部と胸部が長いのが特徴で、雄はより長く、雌はやや短い。卵を産みつけた葉を切り取り、折りたたんでゆりかごをつくる習性がある。孵化した幼虫はその葉を食べて成長する。","note":"","exp":""}],"6802":[{"type":"歴史遺物","name":"カルマル・ニッケル号","rank":"3","desc":"ネーデルラントで建造されたピンネース船。第一次英蘭戦争中に、スコットランド沖でイングランド海軍の攻撃を受け、沈没した。","note":"サルベージ<br/>発見物カード:225","exp":"495"}],"3939":[{"type":"天文","name":"かみのけ座の渦巻星雲","rank":"2","desc":"かみのけ座にある渦巻きのような形をした星雲。はっきりとした黒い雲を伴うのが特徴である。","note":"「天文学者の観測記録」<br/>発見物カード:165","exp":"330"}],"1825":[{"type":"財宝","name":"ワイナ・カパックの財宝","rank":"3","desc":"インカ帝国の北方、キト周辺の制圧に執心したインカ皇帝ワイナ・カパックの財宝。制圧完了の暁に、皇帝自らかの地に納めた品のようだが、その後のヨーロッパ人の来訪による混乱で、存在を忘れられていたようだ。","note":"先王の支配の証","exp":"500"}],"1255":[{"type":"宗教遺物","name":"儀式用ケルト","rank":"1","desc":"ひすいでできた大きなケルト。これだけの大きさであれば、日用として使ったものではなく、儀式用に飾られたものであろう。","note":"緑の小さな石","exp":"100"}],"2848":[{"type":"史跡","name":"豫園","rank":"5","desc":"読みは「ゆえん」。\n四川の役人が、故郷を懐かしむ両親のために贈った庭園。\nこの名前には、平和な楽しい園という意味が込められている。","note":"きらびやかな庭園","exp":"810"}],"28":[{"type":"地理","name":"ブランコ岬","rank":"1","desc":"西アフリカのアルギンの近くにある岬。かつては、エンリケ航海王子の艦隊もここに到達したという。大西洋にのぞむ、南洋の岬だ。","note":"アフリカの地理調査<br/><br/>発見時経験値90　発見物カード経験値45","exp":"90"}],"5544":[{"type":"気象・現象","name":"真珠母雲","rank":"2","desc":"通常よりも高層の上空に発生する特殊な雲。日没後に太陽の光を受けて、真珠母貝と呼ばれるアコヤガイに似た色を見せる。","note":"西シベリア平原　北東大岩付近<br/>たぶん冬・夜間・晴天<br/>大岩の西側で待ち、満月がでるとok。季節は？ですが、１時間近く待ちました。雪・曇りが多い","exp":"360"}],"6915":[{"type":"小型生物","name":"シロヘラコウモリ","rank":"3","desc":"中米の熱帯雨林などに生息する小型のコウモリ。体長は4cm程度。白い体毛に覆われ、耳と鼻が黄色い。活動しない日中は、大きな葉を屋根のように折り曲げ、その裏側に寄り集まって過ごすという。","note":"","exp":""}],"2037":[{"type":"美術品","name":"四人の使徒","rank":"2","desc":"デューラー作の絵画。四名の使徒が描かれている。\n赤と白の鮮やかな衣装は衣擦れの音すら聞こえてきそうなほどである。キリスト教では、赤は慈愛を、白は無垢を表している。","note":"描かれた使徒","exp":"310"}],"6683":[{"type":"天文","name":"アルデラミン","rank":"4","desc":"ケフェウス座で最も明るい星。エチオピアの王ケフェウスの右肩にあたり、アラビア語で「右の前腕部」を意味する。7500年後、北極星になると予測されている。","note":"発見物カード:355","exp":"710"}],"3181":[{"type":"地理","name":"ラブラドル半島","rank":"5","desc":"新大陸北部にある半島で、南部ですら長期に渡り海が凍結するという厳しい気候の地域。ヴァイキングの伝説で「マルクランド（森の国）」と名づけた地と思われる。","note":"氷海がもたらした幸運","exp":"1130"}],"3529":[{"type":"レリック","name":"スパルタクス","rank":"","desc":"古代ローマを震撼させた、大規模な反乱。一説によると、反乱を率いた剣闘士はトラキアの王子だったともいわれる。","note":"初回発見時経験値1550　初回発見時名声1240(名声2万越えのため620*2しています)","exp":"1550"}],"4798":[{"type":"地理","name":"ダイヤモンドヘッド","rank":"1","desc":"ハワイ島の北西の島に位置する山脈。巨大な火山烟云に上っていた火口の迹が残っている。山頂付近で発見された透明な石は、ダイヤモンドを連想させる。","note":"「書きかけの地図」<br/>発見物カード:65","exp":"130"}],"5930":[{"type":"史跡","name":"アルメンドレスの環状列石","rank":"2","desc":"ポルトガル各地にあるクロムレック（環状列石）の一つ。リスボンの東にある古都エヴォラの郊外にあり、規模も古さもポルトガル随一だという。","note":"","exp":"300"}],"1297":[{"type":"中型生物","name":"サンビームヘビ","rank":"2","desc":"光の加減で、虹のように輝くうろこを持つヘビ。土の中に巣穴をつくり、カエルや小型の哺乳類を食べる。","note":"輝くヘビ","exp":"320"}],"3804":[{"type":"地理","name":"カイエトゥール滝","rank":"5","desc":"南米北東部に位置する滝。落差は約220mで、一段の滝としてはかなりの規模である。","note":"南米北東部の地理情報","exp":"810"}],"5596":[{"type":"気象・現象","name":"オーロラ","rank":"2","desc":"北極や南極の周辺で光の帯もようなものが観測される現象。\n色は薄い黄色のようなものから赤いものまでさまざまである。\n遥か昔から空に浮かぶ光についての伝説があるが、もしかするとこの現象が関係しているのかもしれない。","note":"文化貢献度15","exp":"230"}],"1929":[{"type":"大型生物","name":"グアナコ","rank":"2","desc":"南米の山岳や草原の荒地に生息。背部や側部は明るい茶褐色、首から腹部にかけては白色の柔らかな体毛をしている。おとなしい性格だが、好奇心が強い。現地では古くから荷運び用の動物として親しまれていた。","note":"ラクダに似た動物<br/><br/>発見時経験値340　発見物カード経験値170","exp":"170"}],"6856":[{"type":"美術品","name":"女史箴図","rank":"5","desc":"じょししんず。東晋の画家・顧愷之が描いたとされる絵巻物。原画は散逸し、写本のみが伝わっている。西晋の政治家・張華の記した宮廷女官を戒めるための詩を絵にした。宮中の様々な場面を描き、女官の心得を独特の画風で表現している。","note":"追究クエスト<br/>発見物カード:475","exp":"950"}],"1361":[{"type":"宗教遺物","name":"分別善悪応報経","rank":"2","desc":"ぶんべつぜんあくおうほうきょう。仏教の経典のひとつ。人間が行う様々な悪の行いのあと、訪れる死後の世界でどのような目に遭うかを書き綴っている。その様子は、ボロブドゥール遺跡に160面のレリーフにして描かれている。","note":"因果応報の物語","exp":"350"}],"1164":[{"type":"植物","name":"オオオニバス","rank":"2","desc":"水に浮かぶ巨大な葉の直径が2mにもなる蓮。子供ほどの体重であれば乗ることができる。花は、日がたつと白から赤へ変化していく。","note":"植物の船","exp":"270"}],"5692":[{"type":"中型生物","name":"パミールアルガリ","rank":"2","desc":"アルガリの亜種とされる生物。山地や高原に生息する。マルコポーロが発見したという逸話があり、マルコポーロシープという別名を持つ。","note":"2017.02.07新規追加","exp":"370"}],"931":[{"type":"宗教遺物","name":"アフロディテ像","rank":"1","desc":"ギリシャ神話の、愛と美の女神の像。ローマ神話ではヴィーナスという。ギリシャ神話でトロイ戦争はアフロディテとアテナとヘラの争いから端を発したと伝えられる。","note":"美の女神の像","exp":"60"}],"1788":[{"type":"歴史遺物","name":"剣闘士の兜","rank":"3","desc":"剣闘士とは、古代ローマの闘技場などで見世物として戦っていた、競技用戦士のこと。多くは戦争で得た捕虜などが剣闘士となったが中にはローマ市民からの志願もあった。暴君と名高いコンモドゥス帝も、剣闘士に志願した一人である。","note":"パンとサーカス","exp":"470"}],"6664":[{"type":"歴史遺物","name":"キレニア沈没船","rank":"2","desc":"古代ギリシャで活躍した貿易船。主な積荷はアンフォラ（陶器のつぼ）に入ったワイン。紀元前3世紀にサモス島を出港し、キプロス島に到着する直前に沈没した。","note":"","exp":""}],"1319":[{"type":"地理","name":"大スンダ列島","rank":"2","desc":"スマトラ島、ジャワ島カリマンタン島、セレベス島で構成される列島。古くから多くの民族や王朝が変遷したため、時代や場所により文化、宗教が異なっているようだ。","note":"クエスト「列島横断航路」<br/>発見物カード:160","exp":"320"}],"6205":[{"type":"宗教建築","name":"ゴーマテーシュワラの立像","rank":"2","desc":"インド西部のシュラバナベラゴラの岩山にあるジャイナ教の聖者、ゴーマテーシュワラの石像。彼は「剛腕を持つ者」を意味するバーフバリの名を持ち、衣服を含む一切の私物を持たずに何年も瞑想を続けたといわれる。","note":"もうひとつの信仰","exp":"370"}],"2816":[{"type":"宗教遺物","name":"大秦景教流行中国碑","rank":"2","desc":"読みは「たいしんけいきょうりゅうこうちゅうごくひ」。キリスト教の教派の一つ、景教の教義と布教状況が記された碑。\n景教は唐代には広まっていたが、武宗の廃仏政策により、この碑も一緒に排斥されていたようだ。","note":"東西宗教交流","exp":"330"}],"5611":[{"type":"化石","name":"巨大なペンギンの骨","rank":"1","desc":"北米中部で見つかった巨大なペンギンのような骨。通常の水鳥と異なり、くちばしに歯のようなものが付いている。","note":"","exp":"170"}],"5172":[{"type":"港・集落","name":"リガ","rank":"1","desc":"13世紀初めに、ドイツ騎士団によって築かれた街。バルト海に面しており、ロシア地方との重要な交易拠点。重要な産物は多種の鉱物と羽毛である。","note":"到達する","exp":"40"}],"5025":[{"type":"港・集落","name":"ウィレムスタッド","rank":"2","desc":"カリブ海最南端、キュラソー島東南部に位置する街。15世紀末、アロンソ・オヘーダとアメリゴ・ヴェスプッチによって発見された。","note":"到達する","exp":"246"}],"1225":[{"type":"歴史遺物","name":"カンシュル王の腕輪","rank":"4","desc":"パカル王の息子で、チャン・バラム王の弟であるカンシュル王の腕輪。緻密な彫刻と細かい彩色が施された、豪華なものである。","note":"紋章文字に秘められた歴史","exp":"780"}],"5120":[{"type":"港・集落","name":"パルマ","rank":"1","desc":"地中海に浮かぶマジョルカ島にある街。歴史は古く、古代ローマ時代から栄えた。白い砂浜と青い海に囲まれた美しい島で、独特の植物も多い。産物としては、タイムなどの香辛料が豊富で、近海ではサンゴが採れる。","note":"到達する","exp":"8"}],"2669":[{"type":"鳥類","name":"カササギ","rank":"2","desc":"朝鮮半島と日本の一部に生息するカラスの一種。\nカチカチという鳴き声のため、一部の地域では「カチガラス」とも呼ばれている。\n飛ぶと翼の白い模様が目立つ。","note":"恋の架け橋","exp":"370"}],"5929":[{"type":"史跡","name":"プラハのオルロイ","rank":"2","desc":"神聖ローマ帝国の古都プラハで造られた天文時計。当時の天文学者たちの間で使用されていた天体測定機器（アストロラーベ）の機能と時計としての機能を併せ持っており、時間だけでなく太陽や月の位置までわかる。","note":"","exp":""}],"3155":[{"type":"宗教建築","name":"パエストゥム遺跡","rank":"3","desc":"古代ギリシャおよび古代ローマの遺跡。イタリアのカンパーニャ地方に位置する。神殿などの宗教施設の他に、広場や市場らしき跡も見られる。","note":"女神の神殿","exp":"510"}],"2988":[{"type":"地理","name":"イグアスの滝","rank":"4","desc":"およそ4kmという幅を持つ、南米の大滝。\nイグアスとは現地の言葉で「壮大なる水」という意味である。世界最大級の幅で流れ落ちる奔流の様子は、名に違わず圧巻である。","note":"壮大なる水<br/><br/>発見時経験値680　発見物カード経験値340","exp":"680"}],"5822":[{"type":"植物","name":"ヤレータ","rank":"4","desc":"アンデス山脈の高地に生息する多年生植物。一つ一つは小さいが、寄り集まって自生するため、大きな塊のように見える。","note":"","exp":"710"}],"335":[{"type":"小型生物","name":"カーペットカメレオン","rank":"5","desc":"色とりどりに織り込まれた絨毯のような体色をしている。よく動く目で獲物を捕え、ゆっくりと近づいて、すばやく捕食する。その様子から「悪魔の使い」とも呼ばれている。","note":"悪魔の使い","exp":"1196"}],"3614":[{"type":"地理","name":"氷山","rank":"3","desc":"北極海に浮かぶ流氷の中でも、ひときわ大きく高さのある氷塊。\n衝突した船は、沈没を避けられないだろう。","note":"氷海世界","exp":"530"}],"493":[{"type":"宗教遺物","name":"太陽の船","rank":"5","desc":"ギザにあるクフ王のピラミッド近くから発掘された、木製の船。全長が40m以上ある。死んだファラオの魂を太陽神のもとへ運ぶための、儀式用の船だと思われる。","note":"古代エジプトの信仰","exp":"1001"}],"4952":[{"type":"地理","name":"ピンドス山脈","rank":"1","desc":"ギリシャ地方の西側にある山脈。\n約160kmの長さに2000m級の山々が連なっている。バルカン半島を縦断するようにそびえているため、ギリシャの屋根、またはギリシャの背骨といわれる。","note":"経験値修正した","exp":"170"}],"2699":[{"type":"宗教遺物","name":"トルハルバン","rank":"2","desc":"「石の爺さん」という意味を持つ石像。元は済州島で作られていたものらしい。\n魔除けのために、街角や建物の入口などに置くそうだ。","note":"見慣れぬ石像","exp":"290"}],"5078":[{"type":"港・集落","name":"スエズ","rank":"1","desc":"紅海の最北端にある街だ。内陸を経由する交易や、メッカに巡礼する人々の通過点として古くから栄えた。エジプトとアラビアの産物が流通している。","note":"到達する","exp":"125"}],"5486":[{"type":"虫類","name":"スカシジャノメチョウ","rank":"2","desc":"中南米などの熱帯雨林で見られるチョウ。\nガラスのような透明な羽を持ち、後羽には赤や紫色のぼかしのような模様が入っている。","note":"","exp":"260"}],"6580":[{"type":"植物","name":"ムユウジュ","rank":"5","desc":"仏教三大聖木の一つであり、釈迦の誕生にかかわるとされる木。\n淡い赤橙色の花を咲かせ、インドでは乙女の恋心を叶える木や幸福の木として親しまれている。","note":"","exp":""}],"1216":[{"type":"鳥類","name":"オウギワシ","rank":"5","desc":"頭にある黒い扇形の冠羽が特徴のワシ。熱帯林の中を高速で飛び回り、力強い脚と大きな爪でサルなどの中型の動物、さらには大型の鳥をも捕食する。","note":"空の支配者<br/><br/>発見時経験値1131　発見物カード経験値565","exp":"1131"}],"1027":[{"type":"大型生物","name":"オーロックス","rank":"1","desc":"家畜の牛の祖先だと思われる動物。肩までの高さが2m、オスの体重は1000kgにもなる。家畜の牛の牧草を確保するため追われ、今ではごく限られた地域にしかいないようだ。","note":"野生のオーロックスの調査","exp":"180"}],"5668":[{"type":"海洋生物","name":"オオクラゲダコ","rank":"4","desc":"耳のような形のひれを持つタコ。他のタコよりも深海に生息しているため、このひれを使用して移動しているのだろう。","note":"","exp":"320"}],"6321":[{"type":"財宝","name":"赤備えの鎧","rank":"3","desc":"全体を赤色で統一された日本の甲冑。混戦の戦場であっても目立つことから、敵の注意を引きつけるとともに、自軍の目印にもなったという。特に武勇に優れた将や部隊が身に着けたとされる。","note":"","exp":"530"}],"1669":[{"type":"宗教建築","name":"アフ・トンガリキのモアイ","rank":"2","desc":"ラパ・ヌイの島の北東部にある、十五体のモアイ。十五体すべて同じ方向を向いている。島内のモアイの中でも大きなほうで、成人男性の三倍はある。","note":"ラノ・ララクの像の調査","exp":"350"}],"5999":[{"type":"地理","name":"コスタデルソル","rank":"1","desc":"マラガを中心とした、300kmにおよぶ海岸線を指す。意味はスペイン語で「太陽の海岸」である。1年を通して温暖な気候で、保養地には最適だ。","note":"太陽のあふれる浜辺","exp":"20"}],"1266":[{"type":"化石","name":"鳥のようなトカゲの骨","rank":"2","desc":"全体を見るとトカゲに似た形をしているが、頭の部分が鳥のくちばしのように細くなっている。だが、翼があった形跡は見られない。これは、鳥とトカゲの中間にあたる生物だったのだろうか。","note":"トカゲの骨の地図","exp":"225"}],"6614":[{"type":"歴史遺物","name":"カーテナ","rank":"5","desc":"イングランド王家に伝わる剣。切っ先がない形状をしていることから、慈悲の剣、無鋒剣の名でも呼ばれ、戴冠宝器の一つに数えられている。","note":"レガシー美の叡智　右上","exp":"2650"}],"362":[{"type":"財宝","name":"王女の涙","rank":"2","desc":"古王国時代の副葬品と思われる耳飾り。古代エジプトの悲恋物語を追跡中に発見した。見事な細工が施されており、非常に高い身分の人物の愛用品であったことは間違いないようだ。","note":"王女の涙","exp":"300"}],"6188":[{"type":"植物","name":"ヤドリギ","rank":"1","desc":"他の樹木の枝の上に寄生する植物で、古代ギリシャやローマをはじめとするヨーロッパ全土でさまざまな伝承がある。古代ケルト人の間では神聖な植物とされ、同じく神聖視されているオークに宿生するものが特に珍重された。","note":"","exp":"150"}],"6546":[{"type":"海洋生物","name":"カエルアンコウ","rank":"5","desc":"奇妙な姿のアンコウ。泳ぎが下手で、胸びれを前足のように使って海底を歩く。カエルを思わせるそのずんぐりとした姿は、とても愛らしい。","note":"追究クエスト","exp":"1150"}],"579":[{"type":"財宝","name":"貴婦人のドレス","rank":"1","desc":"絹や宝石をふんだんに使った、豪華な衣装。縫製も非常にていねいで、おそらく非常に身分の高い女性が身につけていたものだと思われる。","note":"豪華な衣服の地図","exp":"113"}],"6854":[{"type":"植物","name":"ジャボチカバ","rank":"3","desc":"南米に広く分布する常緑樹。木の幹に直接花が咲き、実がなるのが特徴。白く小さな花の後には直径3センチほどの実ができる。実は柔らかく甘酸っぱいため食用にされるほか、果皮が伝統的に薬として使われている。","note":"発見物カード:85","exp":"170"}],"6350":[{"type":"歴史遺物","name":"ヘレポリス","rank":"2","desc":"「ロードス包囲戦」でロードス島攻略の為、デメトリオスが送りこんだ全高40メートル、全幅20メートルにもおよぶ巨大な攻城塔。内部はいくつかの層に分かれ、各階層には様々な兵器を搭載していたとされる。","note":"","exp":"300"}],"6657":[{"type":"歴史遺物","name":"新安沈船","rank":"3","desc":"元のころの貿易船。陶磁器や銅銭香木など大量の交易品を積んでいた。日本の博多へ向かう途中、沈没。","note":"東アジア東部　済州島北","exp":""}],"2824":[{"type":"宗教遺物","name":"太極図説","rank":"2","desc":"道教で重んじられる太極図を踏まえて、万物生成の原理を図式化した書物。\n万物は、陰陽と五行によって作られると説いている。","note":"ダンジョン","exp":"320"}],"6970":[{"type":"財宝","name":"ミツバチを模した黄金のペンダント","rank":"5","desc":"クレタ島の遺跡で発見された黄金のペンダント。二匹のハチが向かい合う姿がかたどられており、垂れ下がる円型の飾りは蜂蜜のしずくを表すとされる。精巧な細工から、当時の金工技術の高さがうかがえる。","note":"発見物カード:430","exp":"860"}],"3427":[{"type":"レリック","name":"テンプル騎士団","rank":"","desc":"中世に活躍し、巨額の資産を持っていた騎士団。聖地からいくつかの秘宝を持ち帰ったという伝説があるが真実は闇の中である。","note":"","exp":""}],"640":[{"type":"美術品","name":"マクシミリアンの狩猟","rank":"1","desc":"原画はベルナールト・ファン・オルレイ。神聖ローマ帝国皇帝であるマクシミリアン1世の狩猟風景のタペストリー。12枚の連作物の七枚目で、9月と呼ばれる。縦4.5m、幅5.5mの巨大なものである。","note":"クエスト「十二枚の連作タペストリー」<br/>発見物カード:30","exp":"65"}],"452":[{"type":"美術品","name":"聖母戴冠（リッピ）","rank":"1","desc":"フラ・フィリッポ・リッピ作の祭壇画。彼はそれまでにない独特の色使いで、表情豊かな作品を生み出した。ボッティチェリやダ・ヴィンチなど、多くの画家に多大な影響を及ぼしたという。","note":"教会の宗教画の地図","exp":"150"}],"1970":[{"type":"鳥類","name":"ラケットハチドリ","rank":"2","desc":"尾羽が美しい、小さな鳥。雄の特徴である、長い棒の先にラケットが付いたような尾羽は雌をひきつけるためといわれている。寒冷地の鳥らしく、足の周りにはふさふさした羽毛が生えている。南米のアンデス山脈の一部の地域にのみ生息。","note":"長く美しい尾羽","exp":"330"}],"837":[{"type":"虫類","name":"カンター","rank":"2","desc":"インドの奥地に生息する大型の虫。頭部に大きなハサミのようなものが付いている。明かりに寄ってくる性質があり、虚弱体質で人間の手に渡ると、すぐに弱ってしまう。","note":"虫の図鑑","exp":"210"}],"6923":[{"type":"鳥類","name":"ブロンズトキ","rank":"5","desc":"細長く湾曲したくちばしと光沢のある羽を持つ鳥。沼や湿原に生息し、主に水生生物を餌とする。体の赤褐色と金属のような羽の光沢から、この名がついたといわれる。","note":"発見物カード:475","exp":"950"}],"1029":[{"type":"中型生物","name":"ハイエナ","rank":"1","desc":"犬に似た動物。他の肉食動物が食べのこした死体をあさるが、狩りもうまい。群れで生活している。","note":"野生の犬の地図","exp":"24"}],"376":[{"type":"美術品","name":"ヴィーナスの誕生","rank":"2","desc":"ボッティチェリ作の絵画。ヴィーナス、つまりギリシャ神話のアフロディテが、海の泡から生まれたときの様子を描いている。左の二人はゼフュロスとフローラ、右は時の女神のホーラである。","note":"海から生まれた女神","exp":"300"}],"5669":[{"type":"海洋生物","name":"ゴブリンシャーク","rank":"3","desc":"見た目から、邪悪な聖霊にたとえられるサメの一種。大きく突出した特徴的な吻を持っているが、非常に柔らかい。生存時は両顎は口の中に収納されているが、死亡時、時間が経過すると剥き出しになる。","note":"","exp":"270"}],"508":[{"type":"美術品","name":"ダヴィデ","rank":"4","desc":"ミケランジェロ作の大理石像。高さ4mを超える巨大なものである。これはゴリアテを打ち倒す直前の、緊張したダヴィデである。関節や筋肉、血管などすべてがリアルで、いまにも動き出しそうだ。","note":"古代の英雄の巨像","exp":"684"}],"1837":[{"type":"宗教遺物","name":"エノク書","rank":"1","desc":"旧約聖書の偽典のひとつ。エノクとは「従う者」という意味を持ちノアの曽祖父に当たる人物だとされる。エノク書によれば、エノクは神によって天に連れられた後に天使メタトロンに変容させられたとある。","note":"古の書物の地図","exp":"140"}],"6892":[{"type":"港・集落","name":"西安","rank":"2","desc":"読みは「シーアン」。漢や唐など複数の歴代王朝が首都とした。唐の時代には「長安」と呼ばれ、世界的大都市の１つとされていた。シルクロードの起点とも考えられている。","note":"","exp":""}],"273":[{"type":"美術品","name":"天馬にまたがる名声の女神","rank":"1","desc":"高さ3mを超える、巨大な大理石像。ペガサスに乗った女神がラッパを吹き鳴らしている姿である。宮殿の水場を飾るために作られたという。","note":"ペガサスと女神の大理石像","exp":"120"}],"2073":[{"type":"財宝","name":"金細工の耳飾り","rank":"2","desc":"本国に届けられるはずだった、金で作られた耳飾り。この地域独特の細工が施されているため、ヨーロッパでの価値は高いだろう。","note":"［勅命］[[失踪した調査隊の追跡調査","exp":"310"}],"1646":[{"type":"地理","name":"カンガルー島","rank":"2","desc":"オーストラリア南東部にある島。イングランドのマシュー・フリンダースにより発見された。多種多様な動物が生息している。内陸は洞窟や砂漠、一枚岩の巨石が存在するなど、変化に富んでいる。","note":"奇岩島","exp":"270"}],"1197":[{"type":"財宝","name":"謎の石板","rank":"1","desc":"「ひすいの仮面はいただいたぜ。あんたへの恨み、これでたっぷり晴らさせてもらった。あんたは最高の冒険者だよ。\n　　シュレッテンワルダー」\n石板はヨーロッパ風で新しいものである。","note":"偽りの真実","exp":"1"}],"3530":[{"type":"レリック","name":"ピュロス","rank":"","desc":"エピロスのピュロス王はアレクサンドロス大王のあとを継がんとした戦術の天才である。その名は空しい苦闘と共に記憶されている。","note":"","exp":"1680"}],"790":[{"type":"美術品","name":"天馬にまたがるメルクリウス","rank":"1","desc":"「天馬にまたがる名声の女神」と対になっている巨大な大理石像。ペガサスにローマ神話の神・メルクリウスがまたがっている。対にして置けば、豪華な眺めだろう。","note":"クエスト「対になった天馬の像」<br/>発見物カード:60","exp":"120"}],"500":[{"type":"財宝","name":"ギリシャ案内記","rank":"1","desc":"パウサニアスが書いた古代ギリシャ案内書。実際に見て歩いた情景を、詳細に記録している。この案内記のおかげで、古代ギリシャの研究が進んでいる。","note":"古代ギリシャの風景","exp":"110"}],"5707":[{"type":"宗教遺物","name":"ヒマヴァットの像","rank":"4","desc":"ヒマラヤ山脈を神格化したものとされる、ヒマヴァット神の像。その名は「凍る寒さの」という意味の言葉に由来するという。","note":"発見物カード:325","exp":"650"}],"3329":[{"type":"中型生物","name":"アメリカアカオオカミ","rank":"2","desc":"北米の中部および南部に生息するオオカミの一種。同様の地域にすむコヨーテと似ているが、コヨーテよりやや大型である。体色には個体差があるが、総じて赤みがかっている。","note":"「赤いオオカミの地図」<br/>発見物カード:155","exp":"310"}],"14":[{"type":"地理","name":"オトラント海峡","rank":"1","desc":"イタリア半島とバルカン半島の間にある、アドリア海の出入り口。幅は狭いところで80km程度である。","note":"アドリア海の出入り口","exp":"20"}],"3686":[{"type":"中型生物","name":"セイウチ","rank":"5","desc":"極北の沿岸に群れで生息する大型の動物。体毛がなく体は脂肪に覆われている。大きく発達した、上あごの牙が特徴的だ。","note":"ウランゲリ島での生物調査","exp":"810"}],"6800":[{"type":"天文","name":"サドル","rank":"3","desc":"はくちょう座で2番目に明るい星。十字に並ぶはくちょう座のちょうど交点に位置する。名はアラビア語で「雌鶏の胸」を意味する。","note":"イオニア海視認","exp":"600"}],"922":[{"type":"歴史遺物","name":"黄金の玉座","rank":"3","desc":"豪華な装飾の施された黄金の玉座。背もたれにはファラオとその王妃と見られる人物の彫刻がある。彫刻の二人は、ひと組のサンダルを片方ずつ履くなど、仲睦まじい様子だ。","note":"飛べない鳥","exp":"517"}],"2875":[{"type":"歴史遺物","name":"乙支文徳の詩文","rank":"2","desc":"乙支文徳は、高句麗の将軍。\n隋軍が攻めてきた時、乙支文徳は停戦を促すこの詩文を送った。\n隋軍が油断したところで反撃に出、そのまま隋軍を追い払い、国を守った。","note":"勝敗決する詩文","exp":"290"}],"1974":[{"type":"小型生物","name":"カブトトカゲ","rank":"1","desc":"骨張った三角形の頭を持つトカゲ。一匹のオスが数匹のメスと暮らし、落ち葉の中に隠れて生活する。","note":"兜をつけた動物の地図","exp":"110"}],"899":[{"type":"海洋生物","name":"ジンベエザメ","rank":"1","desc":"15mを超える大型のサメである。背中には独特の白斑がある。サメとはいっても、鋭い歯もなく泳ぎも遅くて、まったく害のない魚である。ほかの魚がついていることが多く、このサメがいると大漁が見こめるという。","note":"クエスト「熱帯の巨大な魚」<br/>発見物カード:40","exp":"80"}],"3917":[{"type":"天文","name":"りょうけん座","rank":"3","desc":"うしかい座の牛飼いが連れている猟犬とされる星座。二頭の猟犬からなり、北側の犬はアステリオン、南側の犬はカラという。","note":"クエスト「牛飼いに連れられた星座」<br/>発見物カード:250","exp":"500"}],"3663":[{"type":"宗教遺物","name":"クフ王の平板石碑","rank":"4","desc":"葬礼に用いられたと思われる石碑。平たい石灰岩にヒエログリフが彫られ、彩色が施されている。ヒエログリフは非常に神聖視されており、特殊な目的以外には使われなかったといわれる。","note":"ダンジョン","exp":"693"}],"3013":[{"type":"歴史遺物","name":"水中豹の水差し","rank":"2","desc":"メキシコ湾沿岸のミシシッピ川付近に居住していたと思われる民族の生活用具。これは、その民族の神話に登場する架空動物・水中豹をかたどった水差しである。","note":"先住民の土器の地図","exp":"120"}],"752":[{"type":"植物","name":"クレロデンドルム","rank":"4","desc":"青く美しい花びらは、チョウや妖精に例えられるほどである。花が咲く様は、それらが寄り集まっているようにも見える。","note":"青い羽の生えた花","exp":"708"}],"5937":[{"type":"史跡","name":"ギマランイス城","rank":"4","desc":"ポルトガルの初代国王であるアフォンソ一世が生まれ育った城。かつてギマラインスは修道院と集落しか存在しない土地だったが、北方のヴァイキングの襲撃と略奪から街を守るため、城が建造された。","note":"クエスト「独立を果たした王」<br/>発見物カード:345","exp":"690"}],"2419":[{"type":"中型生物","name":"ヤクシカ","rank":"1","desc":"屋久島に生息するシカの一種。日本本土に生息するシカと比べると一回り小さい。\n角の枝分かれも二つがほとんどで本土のシカより一つ少ない。","note":"島にすむシカの地図","exp":"90"}],"2738":[{"type":"史跡","name":"景福宮","rank":"4","desc":"朝鮮王朝の王宮として建築された、豪華な宮殿。\n宮の名前は、王とその子孫、国民みんなが太平盛大の福を享受するように、祈りを込めて付けられたという。","note":"漢陽の宮殿","exp":"620"}],"2453":[{"type":"植物","name":"キキョウ","rank":"2","desc":"東アジアの日当たりの良い山野で育つ植物。蕾は、花びら同士がつながった風船のような形をしており、星型の花が咲く。根は生薬としても利用される。","note":"凛と咲く青の花","exp":"330"}],"5182":[{"type":"港・集落","name":"ヴィスビー","rank":"1","desc":"バルト海に浮かぶゴトランド島にあるハンザ同盟の都市。13世紀末頃に、バルト海での商業の覇権を争っていたリューベックとの政争に敗れ、ハンザの一員となった。","note":"到達する","exp":"39"}],"2321":[{"type":"宗教遺物","name":"神楽鈴","rank":"2","desc":"読みは、「かぐらすず」。日本で、神道の儀式に用いられる鈴。神楽と呼ばれる歌舞の中で、舞い手はこの鈴を振り鳴らす。その音が神を呼ぶといわれている。","note":"巫女の鈴探し","exp":"260"}],"1543":[{"type":"地理","name":"フィリピン海","rank":"2","desc":"ミンダナオ島、ルソン島の東に位置する海。色とりどりの魚が映える美しい海だが、夏になると猛烈な豪雨に見舞われることがある。","note":"マニラ東の海域調査","exp":"220"}],"3649":[{"type":"海洋生物","name":"イッカククジラ","rank":"5","desc":"北極海に生息するクジラの一種。雄のほとんどが、長く伸びた一本の牙を持っているのが特徴。牙には螺旋状の溝が入っている。","note":"ユニコーンの角","exp":"1010"}],"1525":[{"type":"財宝","name":"ヨハネ騎士団長の盾","rank":"1","desc":"ヨハネ騎士団は、十字軍の時代に傷病者を看護する目的で創設された。紋章は八角白十字である。現在も地中海で活動を続けている。","note":"十字軍時代の騎士団","exp":"100"}],"1635":[{"type":"地理","name":"コロ海","rank":"1","desc":"フィジー諸島が囲い込む内海を指す。内海であるにも関わらず、水深が深い。しかし、諸島周辺の浅瀬はサンゴ礁に覆われており、幻想的な景観で、見る者を魅了する。","note":"フィジー諸島の近海調査","exp":"100"}],"5618":[{"type":"史跡","name":"アフィントンの白馬","rank":"2","desc":"およそ3000年前に描かれたとされる地上絵。長さ110mほど。","note":"","exp":"380"}],"5028":[{"type":"港・集落","name":"オスロ","rank":"1","desc":"11世紀中ごろ、ヴァイキングの王・ハーラルにより建設された街。オスロとは、ノルド語で「神の牧場」という意味である。酪農、林業、水産業が盛ん。","note":"到達する","exp":"39"}],"5043":[{"type":"港・集落","name":"カンディア","rank":"1","desc":"クレタ島にある街。緯度がかなり低いため、気温が高い。ギリシャ神話に登場するミノス王の宮殿・ラビュリントスがあったという。オリーブ栽培と漁業が盛んなほか、高級な染料も採れる。","note":"到達する","exp":"18"}],"5223":[{"type":"植物","name":"アーティチョーク","rank":"1","desc":"直径15cmほどの紫色の球のような花を付ける植物。茎の高さは成人男性以上になり、葉は大きくギザギザしている。ヨーロッパでは古くから食用にされ、食欲不振の改善や二日酔い防止として愛用されていた。","note":"","exp":"160"}],"2670":[{"type":"歴史遺物","name":"鄭道伝の辞世の句","rank":"3","desc":"鄭道伝は、高麗末期朝鮮王朝初期の学者であり、政治家。李成桂に重用された。\n鄭道伝は遼東出兵を計画した矢先、政敵に暗殺されてしまう。その際にこの詩が詠まれたという。","note":"朝鮮王朝初期の調査","exp":"490"}],"6316":[{"type":"植物","name":"プヤ・ライモンディ","rank":"5","desc":"アンデスの高山帯に分布する巨大な植物。百年ほど経つと巨大な花を一度咲かせ、その後は枯れてしまう。大きく細長い葉には、硬く鋭いトゲが多く生えている。別名「アンデスの女王」。","note":"クエスト「百年に一度だけの花」<br/>発見物カード:535","exp":"1070"}],"3869":[{"type":"海洋生物","name":"コククジラ","rank":"2","desc":"北米大陸やユーラシア大陸の北部沿岸を回遊する、やや小型のクジラ。黒い肌に付着した貝などが、模様のように見えるのが特徴。","note":"斑模様のクジラの地図","exp":"210"}],"883":[{"type":"鳥類","name":"エジプトハゲワシ","rank":"2","desc":"大きな幅広い翼で上昇気流に乗って、何時間も飛び続ける。食事方法が変わっていて、ダチョウなどの殻の厚い卵を、石を使って割って食べる。","note":"道具を使う鳥","exp":"350"}],"6055":[{"type":"中型生物","name":"ペキニーズ","rank":"5","desc":"「京巴(ジンバー)」と呼ばれる小型犬。中国の宮廷内で長年、愛玩されてきた。毛が黄色いものは特に珍重されるという。宮廷から持ち出せば死刑といわれるが、実際は規格外の子犬が市場に持ち込まれ、ひそかに飼っている者もいるようだ。","note":"これまで以上の高い犬","exp":"830"}],"5041":[{"type":"港・集落","name":"カルヴィ","rank":"1","desc":"ジェノヴァの南にあるコルシカ島の街。コルシカ島は、古代ローマ時代から、複数の勢力の争いの場となってきた。この街は、ジェノヴァが築いた。","note":"到達する","exp":"17"}],"5865":[{"type":"天文","name":"エンケ彗星","rank":"5","desc":"太陽の周りを回る彗星の一つ。中でも特に周期が短いと考えられている。おうし座流星群の母彗星として、流星群の元となる物質を放出しているようだ。","note":"クエスト「流星群の元」<br/>発見物カード:680","exp":"1360"}],"6296":[{"type":"中型生物","name":"細犬","rank":"1","desc":"中国産の猟犬。ほっそりとした姿が特徴。古代の絵画にも、細犬と思われる犬の姿が描かれていることがある。","note":"","exp":"200"}],"6940":[{"type":"天文","name":"アルゲニブ","rank":"3","desc":"ペガスス座のガンマ星で、青白く輝く。秋の四辺形を構成する星の中で唯一の3等星。名はアラビア語で「翼」を意味する。","note":"発見物カード:275","exp":"550"}],"5450":[{"type":"中型生物","name":"タテガミオオカミ","rank":"3","desc":"南米で最も大きいイヌ科動物。脚力はチーターに匹敵するといわれ、短距離走なら90kmで走れる。民話では、ニワトリを睨んだだけで殺せる動物とされる。","note":"クエスト「奇妙な噂話調査」<br/>発見物カード:235","exp":"470"}],"5779":[{"type":"地理","name":"キモロス島","rank":"5","desc":"エーゲ海に浮かぶ島の一つ。南海岸に銀色の岩場があり、交易の場として使われているらしい。島には毒蛇が生息しているため、エキドナ島と呼ばれることもあるようだ。","note":"2017.02.07新規追加","exp":"1360"}],"2553":[{"type":"財宝","name":"人面のつぼ","rank":"2","desc":"台湾島で見つかった、腹部に人の顔が描かれたつぼ。\nうっすらと描かれた眉や切れ長の目など、その表現力は当時の人々が高い製陶技術を持っていたことを示している。","note":"ダンジョン","exp":"330"}],"329":[{"type":"歴史遺物","name":"ローランの角笛","rank":"4","desc":"ローランが決死の覚悟を伝えるために吹いたと伝えられる、象牙の角笛。細密な彫刻が施されており、工芸品としても価値が高い。","note":"ローランの角笛<br/><br/>発見時経験値780　発見物カード経験値390","exp":"780"}],"6848":[{"type":"天文","name":"アルネブ","rank":"2","desc":"うさぎ座で最も明るい3等星のアルファ星。ウサギの体にあたる場所に位置し、名はアラビア語で「ウサギ」を意味する。","note":"発見物カード:130","exp":"260"}],"4964":[{"type":"歴史遺物","name":"クレタ島の陶器","rank":"1","desc":"古代のクレタ島で作られたとみられる陶器。風化のせいで色が薄くなってはいるが、よく見ればウシの絵が描かれているのがわかる。","note":"","exp":""}],"2854":[{"type":"財宝","name":"孫子兵法","rank":"3","desc":"春秋時代の将軍・孫武が著した兵法書。天運に左右されると考えられていた戦争の勝因、敗因について分析している。","note":"兵法の極意","exp":"530"}],"5211":[{"type":"植物","name":"オオバオオヤマレンゲ","rank":"1","desc":"中国東北部から朝鮮半島にかけて分布する植物。初夏には良い香りのする純白の花を咲かせる。恥じらうようにやや下向きに咲く姿が可憐とされ、天女花とも呼ばれる。","note":"朝鮮半島北岸　陸地再調査報酬","exp":""}],"3378":[{"type":"史跡","name":"ウルク","rank":"4","desc":"古代メソポタミアにおいて栄えた、シュメール人の都市の一つ。古代の文字が刻まれた粘土板が多数見つかっており、かつての政治・経済の中心地であったことを物語っている。","note":"伝説の王にまつわる遺跡","exp":"700"}],"6929":[{"type":"植物","name":"グラジオラス・アブレヴィアトゥス","rank":"4","desc":"古代ローマの剣闘士が用いた剣、グラディウスの名がつけられた花の一種。剣の形をした葉が由来とされる。朱色で筒状の花は独特の形状で、植物の分類を決めるまで議論を呼んだ。","note":"発見物カード:325","exp":"650"}],"1661":[{"type":"地理","name":"バルデス半島","rank":"1","desc":"南米南部から大西洋に突き出した半島。沿岸ではアザラシの、南大西洋側ではクジラの姿を見ることができる、生物の楽園である。","note":"書きかけの地図","exp":"175"}],"5114":[{"type":"港・集落","name":"バルパライソ","rank":"2","desc":"マゼラン海峡を通ってきた船が停泊することで栄えた港街。街の名前には「天国の谷」という意味がある。","note":"到達する","exp":"250"}],"4813":[{"type":"歴史遺物","name":"金環の耳飾り","rank":"4","desc":"金製の特殊な耳飾り。切れ込みの入った部分があり、そこに耳を挟むなどして身につけると思われる。","note":"宋山里遺跡群 （深層隠し部屋）","exp":""}],"5383":[{"type":"鳥類","name":"タチヨタカ","rank":"2","desc":"主に中南米に生息する中型の鳥。枝に止まる際に、垂直に立つことから名づけられた。夜行性で、夜に獲物を見つけられるよう、目が大きく発達している。","note":"アマゾン奥地　再調査報酬","exp":""}],"1238":[{"type":"地理","name":"マラカイボ湖","rank":"2","desc":"ベネズエラ湾の奥にある湖。湖の周辺では杭の上に建てられた家屋が見られる。湖の沿岸には、近年イスパニア人によって建てられた街がある。","note":"小さなヴェネツィア","exp":"380"}],"3582":[{"type":"財宝","name":"ウリウリ","rank":"2","desc":"ハワイの伝統的楽器。木の実やひょうたんの中身をくり貫き、種などを入れて振って音を出す。鮮やかに染めた羽根が飾り付けられている。各種の儀式にも使用される。","note":"ハワイの伝統楽器","exp":"233"}],"6209":[{"type":"中型生物","name":"スナドリネコ","rank":"2","desc":"東南アジア・インドの沼沢地や川沿いの森林など、水が豊富な地域に生息する猫。名前は「漁（すなど）る」に由来し、岸辺で魚を捕食する。泳ぎに長け、水に潜って魚を狙うこともある。大きさは成体でもトラの子供と変わらない。","note":"例外づくめ","exp":"370"}],"995":[{"type":"財宝","name":"東方見聞録","rank":"1","desc":"13世紀終わりごろ、元朝のフビライに仕えたマルコ・ポーロの口述を記録した本。この中に、黄金の国ジパングが登場する。","note":"冒険者のバイブル","exp":"55"}],"6351":[{"type":"歴史遺物","name":"包囲戦の古代武具","rank":"2","desc":"「ロードス包囲戦」での敵援軍到着により、早急な撤退を余儀なくされたデメトリオス軍は多くの武具を置きざりにして撤退したとされ、その一部は鋳潰され巨像の建材として使われたとされる。","note":"","exp":"300"}],"1865":[{"type":"植物","name":"カラファテ","rank":"2","desc":"南米のパタゴニアで見られる樹木。小ぶりな黄色い花をたくさん咲かせ、紫の小さな実をつける。「カラファテの実を食べた者は再びカラファテの地に帰ってくる」と言われている。","note":"旅人が再び訪れる木","exp":"280"}],"6071":[{"type":"伝承","name":"ブギーマン","rank":"5","desc":"子どもの心から生まれるといわれる、恐ろしい幽霊。共通の見た目は持たず、多くの地域に伝承が残っている。それぞれの地域で親が子どもをしつけるためにその存在を口にしたのだろう。","note":"","exp":"1660"}],"211":[{"type":"歴史遺物","name":"デュランダル","rank":"4","desc":"聖騎士ローランが愛用したと伝えられる、水晶をあしらった名剣。鍛え抜かれた刀身は岩をも砕くという。多くの変遷を経て、アムステルダムの教会に安置されていたところを発見された。","note":"デュランダル","exp":"756"}],"497":[{"type":"美術品","name":"御者の像","rank":"1","desc":"デルフォイ遺跡で発見された御者の青銅像。競技会で優勝した御者の功績を讃えるために奉納されたものであろう。均整の取れたすばらしい像である。","note":"古代ギリシャの傑作","exp":"130"}],"6656":[{"type":"小型生物","name":"キマダラチズガメ","rank":"2","desc":"ミシシッピ流域のパスカグーラ川に生息する亀。背甲にはトゲ状の突起があり、黄色や橙色のまだら模様が入っている。","note":"","exp":"300"}],"5345":[{"type":"天文","name":"たて座","rank":"2","desc":"1684年にポーランドの天文学者ヘヴェリウスが国王ヤン3世ソビエツキを称えて作った星座。ヤン3世は第二次ウィーン包囲戦で活躍して勇名を馳せた。いて座の北西にある。","note":"「天文学者の観測記録」<br/>発見物カード:315","exp":"310"}],"6213":[{"type":"歴史遺物","name":"デ・アトーチャ号","rank":"4","desc":"イスパニアのガレオン船。新大陸の貴金属、宝石などを満載し帰国途中、嵐に遭い、フロリダ沖で沈没した。","note":"サルベージ","exp":"710"}],"95":[{"type":"美術品","name":"オーロラ姫のティアラ","rank":"3","desc":"眠れる森の王女の伝説で有名な、オーロラ姫のティアラ。婚礼に用いたとされる。子孫を通じてイングランドに渡るも、戦乱で紛失。このたび、イングランドの教会に寄贈されたものが発見された。美しい細工で芸術的価値が高い。","note":"オーロラ姫のティアラ","exp":"506"}],"4862":[{"type":"天文","name":"コップ座","rank":"2","desc":"大きな杯をかたどった星座。古くから各地で知られており、神の所持品や象徴などといわれている。","note":"無上の杯","exp":"350"}],"523":[{"type":"歴史遺物","name":"古代の敷物","rank":"1","desc":"古代文明で使われていた敷物。動物の毛や麻などで織られている。","note":"古代の集落の地図","exp":"52"}],"4863":[{"type":"史跡","name":"ボルシッパ","rank":"3","desc":"シュメール文明の古代都で、名前は「海の角」という意味。「舌の塔」と呼ばれる大規模なジッグラトの遺跡があり、バベルの塔の遺跡であると考えられている。","note":"クエスト「海の角」<br/>発見物カード:265","exp":"530"}],"1523":[{"type":"歴史遺物","name":"ヨーク","rank":"1","desc":"古代の球技、「トラチトリ」で用いられた防具。「トラチトリ」は時に戦闘行為として、時に神への祈祷舞踊として行なわれた。","note":"競技用具の地図","exp":"110"}],"5148":[{"type":"港・集落","name":"ポンディシェリ","rank":"1","desc":"インド東岸に位置する街。東南アジアへの主要な中継点である。香辛料と香料を中心に、宝石も扱われている。","note":"到達する","exp":"177"}],"2504":[{"type":"美術品","name":"寺社縁起絵巻","rank":"1","desc":"ある寺院と、そこに関わる仏僧についての奇跡譚がまとめられた、日本の絵巻物。\n貴賎の別なく、信仰を求める人々の様子が、表情豊かに描かれている。","note":"絵巻物の地図","exp":"200"}],"2360":[{"type":"虫類","name":"ジャコウアゲハ","rank":"2","desc":"東アジアに広く生息するチョウ。細長く伸びた後ろ羽を持つ。\n雄はベルベットのような光沢を帯びた黒色の羽を持つのに対し、雌は比較的地味な褐色の羽を持つ。","note":"ベルベットの羽","exp":"330"}],"3763":[{"type":"天文","name":"みなみのうお座","rank":"5","desc":"ヨーロッパでは秋の南の空に現れる星座。周りに明るい星が少ないため、魚の口にあたる1等星フォーマルハウトを目印に見つけやすい。怪物テュポンに襲われた女神アフロディテが、魚になって逃げた姿とも、うお座の親魚ともいわれる。","note":"クエスト「ネクタルを飲む魚」<br/>発見物カード:475","exp":"950"}],"4849":[{"type":"天文","name":"ケフェウス座","rank":"3","desc":"ギリシャ神話におけるエチオピア王・ケフェウスが、天に昇ったとされる星座。カッシオペイアの夫であり、アンドロメダの父親でもある。","note":"クエスト「苦渋の決断」<br/>発見物カード:245","exp":"490"}],"6254":[{"type":"宗教建築","name":"アルカディ修道院","rank":"3","desc":"クレタ島に造られた修道院。16世紀にヴェネツィア様式を取り入れて建造された。それより以前からあった修道院を改修したとの説もある。島に住むキリスト教徒からは「生きた修道院」と呼ばれており、精神的支柱になっているようだ。","note":"","exp":"480"}],"1252":[{"type":"中型生物","name":"ヤブイヌ","rank":"2","desc":"平べったい顔に小さい耳、長い胴と短い肢を持つ。ずんぐりとした体型が愛らしい。前に走るのと同じ速さで、後ろ向きに走れる。泳ぎや潜水も得意。","note":"面白い特技","exp":"210"}],"5943":[{"type":"史跡","name":"未完の礼拝堂","rank":"1","desc":"バターリャ修道院にある礼拝堂の一つ。王族たちが永眠する場所として使うため、ドゥアルテ王子が建築計画を主導した。","note":"クエスト「輝きの世代「<br/>発見物カード:95","exp":"193"}],"1542":[{"type":"地理","name":"マレー半島","rank":"2","desc":"スマトラ島の北に位置する半島。マレー人の根拠地であり、古くから交易の要衝として栄えた。内陸部は広大な密林が広がり、他の地域では見られない動植物が数多く生息している。","note":"クエスト「東西交易の要衝」<br/>発見物カード:135","exp":"270"}],"6443":[{"type":"地理","name":"ウユニ塩湖","rank":"2","desc":"かつてアンデス山脈が隆起した際、取り残された大量の海水によって形成された広大な塩原。雨が降ると冠水して湖のようになり、水面が空を映し出すため「天空の鏡」とも呼ばれる。","note":"クエスト「2つの空に挟まれて」<br/>発見物カード:120","exp":"240"}],"6424":[{"type":"化石","name":"凍り付いた幼いマンモス","rank":"5","desc":"幼いマンモスが凍り付いた姿。成体と比べて体はかなり小さく、特徴的な長い体毛や大きな牙が生えそろう前に凍り付いた個体のようだ。いつからこの地に眠っていたのかは分からない。","note":"","exp":""}],"5226":[{"type":"史跡","name":"ヴィッラ・アドリアーナ","rank":"3","desc":"イタリアのティヴォリにある、ハドリアヌス帝が建造した別荘。皇帝がローマ帝国の巡察にでかけ、各地で魅了されたものを再現した建築物がいくつも存在している。","note":"","exp":""}],"6173":[{"type":"財宝","name":"アルスター物語の写本","rank":"2","desc":"「アルスター物語群」とも呼ばれ、アイルランド神話の一つとされている伝承をまとめたもの。アルスター国の王や戦士たちの物語が多く収められており、物語のほとんどがキリストの生涯と同時代の出来事であるとされている。","note":"","exp":"260"}],"2340":[{"type":"宗教遺物","name":"狛犬","rank":"2","desc":"日本の寺院に多く見られる、二体一対の像。イヌに似た、想像上の獣をかたどっている。二体のうち一体は口を開き、もう一体は口を閉じた状態で置かれている。守り神として、人々に慕われているらしい。","note":"一対の守護獣","exp":"240"}],"5727":[{"type":"宗教建築","name":"シャクパック・アタ","rank":"2","desc":"イスラム教の宣教師であるシャクパック・アタによって作られたモスク。ウスチュルト台地にはこのような岩窟モスクが複数存在するようだ。","note":"2017.02.07新規追加","exp":"370"}],"3695":[{"type":"宗教遺物","name":"銀の十字架","rank":"3","desc":"スラブ民族が所持していたと思われる銀の十字架。スラブの人々は6世紀頃からバルト海沿岸、バルカン半島から黒海沿岸にまで広がった民族である。","note":"十字架の地図","exp":"470"}],"6195":[{"type":"史跡","name":"アルタイ山脈の岩刻絵群","rank":"5","desc":"ザナドゥの周辺で見られる、岩に刻まれた動物たちの絵。羊や馬、ヤギなどの動物や、動物を追う狩人の姿が描かれている。古代の人々の生活の様子を垣間見れる貴重な遺跡。","note":"山壁の絵","exp":"830"}],"2538":[{"type":"大型生物","name":"サンバー","rank":"2","desc":"台湾島やインドなどの広い地域に分布するシカ。全長150cm以上に成長し、雄には角がある。\n夜行性で、昼間は木陰などで休んでいる姿が見られる。","note":"大型のシカの地図","exp":"320"}],"6553":[{"type":"史跡","name":"ヘラクレスの塔","rank":"5","desc":"イベリア半島北西部に建つ古代ローマ時代の灯台。アレクサンドリアの大灯台をモデルに造られたといわれ、ギリシャ神話の英雄ヘラクレスにちなんで名づけられた。この地の伝説の王ブレオガンの逸話からブリガンティウムの塔とも呼ばれる。","note":"レガシー『英知の灯アレクサンドリア』右上","exp":""}],"6397":[{"type":"歴史遺物","name":"クフ王時代のパピルス","rank":"5","desc":"クフ王の時代の文書。世界最古のパピルスと考えられている。パピルスの茎を打ち伸ばした紙片に、ピラミッドの建造や使用された石の運搬に携わった労働者たちの日々の生活が書かれているらしい。","note":"レガシー：砂漠に栄えた巨石文明","exp":"1950"}],"6495":[{"type":"財宝","name":"エフェソスのコイン","rank":"5","desc":"古代都市エフェソスのコイン。女神アルテミスを象徴する鹿や蜂の意匠が刻まれている。交易の要所であったエフェソスは、巨大神殿の参拝者だけでなく商人やキリスト教の伝道者たちも訪れる、活気に満ちた街だったという。","note":"レガシー　女神信仰のエフェソス　下","exp":""}],"1463":[{"type":"宗教遺物","name":"ヤジロウの碗","rank":"4","desc":"ヤジロウとは、ザビエルをジパングに連れてきたという東洋人である。ジパングを出てマラッカに滞在していたザビエルを訪ね、ジパングでの布教を薦めたといわれる。これはヤジロウがジパングを離れる際に持ち出した、自前の碗であるという","note":"クエスト「黄金の国から来た男」<br/>発見物カード:335","exp":"672"}],"1324":[{"type":"地理","name":"ハルマヘラ島","rank":"3","desc":"テルナーテ島の東に位置する島。北部がテルナーテ王国の、南部がティドレ王国の支配下にある。島は密林に覆われ、恐ろしい熱病にかかる土地でもあるため、人口は多くない。","note":"クエスト「揺れる巨島」<br/>発見物カード:236","exp":"473"}],"1749":[{"type":"鳥類","name":"ハルパゴルニスワシ","rank":"5","desc":"アオテアロアに生息している大型のワシ。\n大きなものになると、広げた翼が3mにもなりワシの中でも傑出した体躯を誇っている。\nモアを主食にしているようだ。モアの減少に伴い、数が減っているらしい。","note":"天空の王者<br/><br/>発見時経験値1163　発見物カード経験値581","exp":"1163"}],"2801":[{"type":"植物","name":"モクレン","rank":"2","desc":"主に中国南西部に生息する、紫色の花を咲かせる植物で、高貴な花とされている。甘くて上品な芳香を放つ。","note":"花の涙","exp":"330"}],"3578":[{"type":"鳥類","name":"アラエ・ウラ","rank":"2","desc":"ハワイに火をもたらしたとされる伝説の鳥。「ウラ」とはハワイ語で赤色を意味し、額とクチバシの根元が鮮やかな赤色をしている。","note":"火を運ぶ鳥","exp":"234"}],"2990":[{"type":"小型生物","name":"カロリナハコガメ","rank":"2","desc":"北米東部に生息しているハコガメの一種。背甲がドーム状になっていて、上から見ると円形。雄は雌より頭部が大型で、後肢の爪は太く短い。","note":"丸く見える生物の地図","exp":"220"}],"6491":[{"type":"植物","name":"キメラセントポーリア","rank":"5","desc":"アフリカ南部の奥地でのみ見られる小型の植物セントポーリアの変異個体。通常個体と同様に、花弁は独特の光沢があり、変異体独特の縞模様もたいへん美しい。","note":"追究クエスト","exp":"1200"}],"1651":[{"type":"地理","name":"サモア諸島","rank":"3","desc":"フィジー諸島の東北東に位置する諸島。主要な島はサバイイ島とウポル島の二つである。両島とも火山島であり海岸線には美しいサンゴ礁が広がっている。","note":"神の投げし岩","exp":"484"}],"3780":[{"type":"天文","name":"アンタレス","rank":"4","desc":"さそり座で最も明るい1等星で、赤く輝く。星座図では、サソリの心臓に位置する。名は「アレス（火星）に対抗するもの」を意味する。","note":"視認","exp":"740"}],"2492":[{"type":"歴史遺物","name":"左鎮人の頭骨","rank":"1","desc":"読みは「さちんじんのずこつ」。遥か昔、台湾島に住んでいた人類の頭骨。\n周囲から骨角器なども見つかっており、狩猟生活をしていた時代の人類であると推察される。","note":"奇妙な頭蓋骨の地図","exp":"190"}],"6106":[{"type":"宗教遺物","name":"道を知れ","rank":"3","desc":"11世紀ドイツの修道女であるビンゲンのヒルデガルトの著作で、預言めいた文章と、寓意画のような挿絵が特徴的。内容は教会や信仰に関するものであり、いずれも神の啓示のもとに記されたものと言われている。","note":"","exp":"540"}],"1681":[{"type":"虫類","name":"ネプチューンオオカブト","rank":"4","desc":"槍のように長い角が二本と短い角が二本、交差するように生えている大型の虫。体表は黒色で光沢がある。","note":"槍を持った虫","exp":"732"}],"7010":[{"type":"大型生物","name":"ガウルの幼体","rank":"2","desc":"ガウルの幼体は成体と異なり、前進が薄茶色の毛に覆われている。成長するにつれて毛の色は濃くなり、下肢に白い毛が現れ始める。","note":"","exp":""}],"6398":[{"type":"歴史遺物","name":"クフ王の棺","rank":"5","desc":"クフ王の大ピラミッドの中に置かれている花崗岩の棺。途中の通路を通れない大きさのため、建築中に作られたものとされる。発見された当時から蓋はなく中身は空だった。発見前に盗掘されたとも思えないのだが…。","note":"レガシー：砂漠に栄えた巨石文明","exp":"2250"}],"2730":[{"type":"宗教遺物","name":"大蔵経の版木","rank":"2","desc":"大蔵経とは、経典の総集のこと。\n契丹からの侵略を契機に、国家防衛を祈願するため、高麗で製作が開始された。\n完成は1200年代半ば。版木は、八万余りあるという。","note":"祈願の経典","exp":"380"}],"1563":[{"type":"歴史遺物","name":"粘土細工の像","rank":"1","desc":"マヤ地域西部で見つかった粘土細工の像。さまざまな姿があるが、神々を模しているのだろうか。","note":"メソアメリカの像の地図","exp":"150"}],"582":[{"type":"財宝","name":"祭事用の短剣","rank":"1","desc":"祭事に用いられたと思われる短剣。宝石や金の豪華な装飾が施されており、実用性は低そうである。","note":"豪華な武器の地図","exp":"59"}],"489":[{"type":"宗教遺物","name":"マヌの法典","rank":"2","desc":"ヒンドゥー教の法典。バラモン教・ヒンドゥー教の基本となる内容で、12章から成る。記述は法律にとどまらず生活上の儀礼や教義にまで及ぶ。","note":"古代インドの法典","exp":"280"}],"319":[{"type":"美術品","name":"聖母子と聖ヨハネ","rank":"3","desc":"ラファエロ作の絵画。別名があり、「美しき女庭師」という。由来は、聖母子の背景に描かれた美しい田園風景であろう。柔らかな筆致の名作である。","note":"ラファエロの聖母子画","exp":"440"}],"6575":[{"type":"歴史遺物","name":"動物型土製品","rank":"5","desc":"日本で発見された、土製の焼き物。土偶は地母神信仰から人の女性の形をしているものが多いというのが通説だが、これらは動物の姿をしている。狩猟の儀式のために作られたものだろうか。","note":"","exp":"1550"}],"3385":[{"type":"宗教遺物","name":"イナンナ像","rank":"3","desc":"イナンナは、シュメールの豊穣と愛の女神とされる。ウルクの守護神として崇拝されていた。\nアッカドではイシュタルと呼ばれた。","note":"ウルクの女神","exp":"500"}],"5561":[{"type":"植物","name":"サイコトリア・ペッピギアーナ","rank":"4","desc":"中南米に群生する低木で、唇のように見える苞が特徴。見た目とは裏腹に、古くから痛み止めとしても使用されており、頭痛や捻挫に効果がある。","note":"妖艶な植物<br/><br/>発見時経験値620　発見物カード経験値310","exp":"620"}],"3817":[{"type":"財宝","name":"ポートロイヤルの貨幣","rank":"4","desc":"ポートロイヤルの造幣局で鋳造された貨幣。ポートロイヤルに大量に流入する貴金属が材料となっている。","note":"ある街の貨幣の地図<br/><br/>発見時経験値650　発見物カード経験値325","exp":"650"}],"2905":[{"type":"宗教遺物","name":"帛画","rank":"2","desc":"読みは「はくが」。\n帛とは絹布のことであり、帛画とはそうした絹布に描かれた、古代中国の絵画を指す。\n絹という脆い素材であるため、良い保存状態で発見されることは稀である。","note":"古代の絹織物","exp":"360"}],"1187":[{"type":"地理","name":"アセンション","rank":"2","desc":"南大西洋に浮かぶ小さな島。まさに絶海の孤島で、アフリカ大陸まで2000kmはある。正確に島にたどりつくことが困難なので、ここに街を作るのは無理だと思われる。","note":"若い男の悩み","exp":"380"}],"5540":[{"type":"財宝","name":"アサラト","rank":"3","desc":"西アフリカに伝わる打楽器。木の実の中に種を入れ、二つの木の実を紐で繋げて振って鳴らす。子どもをあやすために作られた打楽器で、現地では玩具として親しまれている。","note":"","exp":"220"}],"1638":[{"type":"地理","name":"バヌアツ","rank":"3","desc":"オーストラリアからはるか東北東、ニューカレドニア島から北北東に位置する諸島。島の半数は火山島である。島々は山がちで、最高峰はエスピリトゥサント島のタブウェマサナ山である。島ごとに独自の文化が発達しているようだ。","note":"もうひとつの航路","exp":"495"}],"189":[{"type":"宗教遺物","name":"ガネーシャ像","rank":"3","desc":"インド神話の神の像である。シヴァとパールヴァティーの子供で、頭が象である。富と幸運、学問をつかさどるため、商売の神として非常に人気がある。","note":"ゾウの頭を持つ神","exp":"440"}],"145":[{"type":"歴史遺物","name":"ラブリュス","rank":"4","desc":"エーゲ海で栄えたクレタ文明における宗教的な象徴。両刃の斧で、さまざまな場所に刻印されている。ミノス王の宮殿は、ラビュリントスと呼ばれる。","note":"クレタ島の伝説","exp":"636"}],"5516":[{"type":"宗教建築","name":"ラリベラの岩窟教会群","rank":"2","desc":"エチオピアに存在する教会堂群。石をくりぬいて作り上げた建造物は世界的に見ても非常に珍しい。具体的な建造方法はよくわかっていない。","note":"","exp":"360"}],"71":[{"type":"宗教遺物","name":"菩薩像","rank":"2","desc":"「ぼさつぞう」。仏教の菩薩の像。菩薩というのは、もともとは悟りを開く前の釈迦を指すという。その後解釈が変わり、あえて仏とならない存在をいうようになった。","note":"インドの菩薩像の地図","exp":"260"}],"193":[{"type":"美術品","name":"岩窟の聖母（祭壇画）","rank":"3","desc":"読みは「がんくつのせいぼ」。レオナルド・ダ・ヴィンチ作の絵画である。ミラノの聖堂の依頼で描かれた絵画が報酬で折り合わず、複製であれば安くてよいということで描かれたものである。この絵の製作には弟子の手も入っているそうだ。","note":"ダ・ヴィンチの祭壇画","exp":"440"}],"1716":[{"type":"海洋生物","name":"地中海カジキ","rank":"5","desc":"地中海特有のカジキ。他のカジキと比べ、上アゴのクチバシが短いようだ。","note":"釣り","exp":"816"}],"5219":[{"type":"歴史遺物","name":"ビブロス文字の石碑の破片","rank":"1","desc":"古代文字が刻まれている石碑の破片。文字は古代ビブロスで使われていたと思われ、丁寧に彫られている。ばらばらになった破片をつなぎ合わせると読めるようになるのだろうか。","note":"ビブロス郊外　再調査報酬","exp":""}],"6031":[{"type":"財宝","name":"和氏の璧","rank":"4","desc":"春秋戦国時代の中国北方の国・趙に伝わる宝物。「かしのへき」と読む。楚の卞和(べんか)という人物によって原石が発見された。のちに趙に伝わり「完璧」という言葉の由来にもなったいわくつきの宝物である。","note":"カード経験365","exp":"730"}],"1221":[{"type":"宗教遺物","name":"チャック像","rank":"2","desc":"アステカの神・トラロックと同列とされる雨の神。雨だけでなく、様々な気象を司るといわれている。","note":"マヤの気象を司る神","exp":"290"}],"6984":[{"type":"中型生物","name":"ビントロング","rank":"","desc":"東南アジアの密林などに生息する夜行性の動物。体がクマ、頭がネコに似ているため、クマネコとも呼ばれる。独特の香ばしい体臭が特徴。太く長い尻尾は枝に巻きつけて体を支えたり、バランスを保つ役割がある。","note":"経験値1530＋765","exp":"1530"}],"2356":[{"type":"宗教遺物","name":"八咫烏の旗","rank":"2","desc":"読みは「やたがらすのはた」。三本脚のカラスが描かれた旗。\n日本神話では、このカラスは神の使いとされているらしい。\n「咫」とは長さの単位であり、日本神話には「八咫」という長さがよく登場するそうだ。","note":"御使いの鳥<br/><br/>発見時経験値360　発見物カード経験値180","exp":"360"}],"6894":[{"type":"歴史遺物","name":"景龍観鐘","rank":"5","desc":"景龍観と呼ばれる道教の殿堂造られた大型の釣鐘。鐘の高さは2mを越え、鐘には皇帝の真筆による銘文が記されている。","note":"","exp":""}],"5301":[{"type":"虫類","name":"サハラサバクアリ","rank":"2","desc":"サハラに生息する、非常に優れた方向感覚を持つアリ。回り道をしてエサを見つけても、一直線に巣に戻れる。また、砂丘の形が風で変わっても迷うことはない。","note":"","exp":"220"}],"2885":[{"type":"化石","name":"翼の生えた小さなドラゴンの骨","rank":"2","desc":"雲台山近辺で見つかった、スズメほどの小さな生物の骨。細い翼や湾曲した脚のつま先がとても特徴的だ。","note":"小さなトカゲの地図","exp":"250"}],"5111":[{"type":"港・集落","name":"バイーア","rank":"2","desc":"バイーアとは「湾」の意味。大西洋に面し、トドス・オス・サントス（「諸聖人の湾」）を取り囲む半島に位置する南米の街。","note":"到達する","exp":"266"}],"1984":[{"type":"海洋生物","name":"シーラカンス","rank":"5","desc":"ほかの魚とはなにかが違う、奇妙な魚。ヒレの根元にもウロコが生えていたり、尾ビレの形が変わっていたり、浮き袋に脂肪が詰まっていたりなど…。勘に過ぎないが、とてつもない存在のように思えてならない。","note":"生きた石の魚<br/><br/>発見時経験値1124　発見物カード経験値562","exp":"1124"}],"1171":[{"type":"鳥類","name":"オウギタイランチョウ","rank":"5","desc":"鮮やかな色の扇のようなとさかを持つ。オスのとさかは赤、メスのものは黄色で、ともに先端が青い。","note":"羽飾り","exp":"816"}],"6965":[{"type":"財宝","name":"新羅の金製耳飾り","rank":"3","desc":"新羅時代の黄金の耳飾り。王族の副葬品として出土する。最上部には太い耳環、その下に中間飾、垂飾と並ぶのが特徴。金線や金粒を施した細かい文様により、非常に豪華な作りとなっている。","note":"発見物カード:255","exp":"510"}],"1900":[{"type":"虫類","name":"ジンメンカメムシ","rank":"3","desc":"東南アジアに生息するカメムシの一種。逆さから見ると体の模様が人の顔に見える。模様は様々で笑顔や泣き顔に見える個体もいる。","note":"ニヤリと笑う昆虫","exp":"480"}],"1857":[{"type":"歴史遺物","name":"フェニキアのガラスつぼ","rank":"1","desc":"手先が器用だったフェニキア人は、多くの工芸品を作成し、交易した。材料であるケイ素分の多い海砂を用いて優秀なガラス製品を作った。ガラスの製法はエジプトから学んでいたと見られ、二国の蜜月さが伺われる。","note":"ガラス細工の地図","exp":"160"}],"2113":[{"type":"歴史遺物","name":"アブキールの難破船","rank":"2","desc":"カタロニアの貿易船の一隻。\nアレクサンドリアの北東に位置する、アブキール湾で沈没した。","note":"サルベージ","exp":"270"}],"5179":[{"type":"港・集落","name":"ロンドン","rank":"1","desc":"古代ローマ人が築いた砦・ロンディニウムがもとになった街。11世紀ごろから栄え、今ではイングランドの中心地である。羊毛が豊富に取引されるほか、周辺の街の鉱物資源を背景に精錬技術の進歩が目覚ましい。","note":"到達する","exp":"26"}],"307":[{"type":"宗教遺物","name":"オロルン像","rank":"1","desc":"アフリカのヨルバ人の最高神の像。四百一の神をまとめているといわれる。世界は最初海しかなく、オロルンが海と交わってオドゥドゥアとオバタラを作り二人に大地と人間を作らせたという。","note":"ヨルバの神話","exp":"180"}],"1720":[{"type":"海洋生物","name":"キングクリップ","rank":"2","desc":"最大で2mにもなる巨大魚。南半球の深い海に生息する。イタチウオの一種。","note":"釣り","exp":"250"}],"6564":[{"type":"海洋生物","name":"デンキナマズ","rank":"5","desc":"デンキウナギに次いで強力な電気を発生させられる魚。体から電気を放出して、小魚などを捕食したり、周囲を探ったりする。ナイル川に古くから生息するといわれ、古代の文献には雷神のように記述されている。","note":"追究クエスト","exp":"1500"}],"5077":[{"type":"港・集落","name":"ジョファール","rank":"1","desc":"アラビア海沿岸に位置する港町。モンスーンの季節には大量の雨が降る。","note":"到達する","exp":"127"}],"1438":[{"type":"宗教遺物","name":"ケツアルパパロトル像","rank":"3","desc":"メソアメリカの古い神話に登場する。神話上の神だと考えられている。ケツアルパパロトルとは「羽毛に覆われた蝶」という意味で、どういう役割をしているのかは不明である。","note":"謎の多い古代神","exp":"473"}],"4868":[{"type":"地理","name":"メソポタミア湿原","rank":"2","desc":"チグリス・ユーフラテス川の下流に広がる湿地帯。「肥沃な三日月地帯」の一部であり、古代から農業が盛んである。","note":"書きかけの地図","exp":"330"}],"528":[{"type":"歴史遺物","name":"鉄の武具","rank":"1","desc":"古代の鉄の武具。青銅器が主流の時代に、硬い鉄器を作る技術があれば無敵といえる。ヒッタイトは製鉄技術を独占し強国となった。","note":"古代の鉄器の地図","exp":"54"}],"1810":[{"type":"地理","name":"グアヤキル湾","rank":"1","desc":"南米大陸北西岸に位置する湾。南岸にはトゥンベスの街を擁している。湾の沖合いは北からの暖流と南からの寒流がぶつかり、潮目を形成している。","note":"書きかけの地図","exp":"100"}],"6118":[{"type":"鳥類","name":"ニジキジ","rank":"5","desc":"インドなどに生息する大型のキジ。他のキジの仲間と比較して体格がよく、短い尾羽が特徴的。特にオスの羽毛は、虹を思わせる金属のような光沢があり、これが名前の由来となった。","note":"","exp":"1190"}],"1582":[{"type":"植物","name":"バンクシア","rank":"4","desc":"大量の花蜜を有する植物。蜜を食料とする生物の重要な食料源となっている。果実は非常に堅く、山火事などで焼かれて割れ、種子を地上に落とす。","note":"ヨーロッパからの依頼","exp":"720"}],"1211":[{"type":"宗教建築","name":"鷲とジャガーのレリーフ","rank":"2","desc":"チチェンイッツァの神殿のひとつに彫られていたレリーフ。左にジャガー、右の鷲は心臓をつかんでいる。","note":"クエスト「神殿の壁画調査」<br/>発見物カード:125","exp":"250"}],"5945":[{"type":"植物","name":"ギニアショウガ","rank":"2","desc":"西アフリカなどに生息する植物。メレゲッタとも呼ばれる。乾燥した種子はピリッとした辛さを持つ香辛料であり、地方によってはコショウの代わりに用いられる。","note":"","exp":"260"}],"5705":[{"type":"歴史遺物","name":"蒼き狼の像","rank":"5","desc":"モンゴル人の祖とされる伝説の獣。『元朝秘史』の記述から、チンギス・ハンの別名として用いられることもある。妻は、白き牝鹿であったという。","note":"","exp":"1639"}],"6746":[{"type":"気象・現象","name":"黒雪","rank":"2","desc":"雪や氷が黒や灰色に色づく現象。その原因などについて確たる情報はないが、一説には石炭が関係しているとされる。","note":"","exp":""}],"399":[{"type":"鳥類","name":"カンムリヅル","rank":"1","desc":"頭に美しい飾り羽があるツル。アフリカでしか見られないようだ。ツルはフラミンゴやサギに似ているが、立っているときの姿や飛び方が違うので、近い種類ではないようだ。","note":"冠をかぶった鳥","exp":"140"}],"784":[{"type":"地理","name":"コスタデルソル","rank":"1","desc":"マラガを中心とした、300kmにおよぶ海岸線を指す。意味はスペイン語で「太陽の海岸」である。1年を通して温暖な気候で、保養地には最適だ。","note":"太陽のあふれる浜辺","exp":"20"}],"6776":[{"type":"地理","name":"ジェイタ洞窟","rank":"4","desc":"ベイルートより北にある石灰岩洞窟。全長は約9km。洞窟は上下に分かれており、様々な種類の鍾乳石が確認できる。石器時代の人類の痕跡があり、青銅器などが発見された。先史時代の文明を辿るのに重要な遺跡として非常に価値が高い。","note":"発見物カード経験値：380","exp":"760"}],"340":[{"type":"鳥類","name":"ヤツガシラ","rank":"3","desc":"見る角度によって深い緑色や黒に変わる、光沢のある羽が特徴。紅色のくちばしと、白い斑模様の尾を持つ。グループで活動し、主に昆虫を食べる。","note":"違う色の同じ鳥","exp":"539"}],"6497":[{"type":"化石","name":"大きな頭の魚の化石","rank":"5","desc":"大きさこそ違うが、強靭な顎を持つ巨大な生物の頭骨と同じ特徴を持った魚の化石。重厚な頭骨と異なり体の骨はもろく、死後の化石などでは頭骨のみ残っていることが多い。","note":"","exp":"990"}],"2663":[{"type":"財宝","name":"瑠璃製の杯","rank":"2","desc":"新羅に縁ある場所でよく発掘される杯。美しい瑠璃色のガラスで作られている。\n特別な装飾があるわけではないが、とても目を引く。","note":"青の宝物","exp":"240"}],"2602":[{"type":"宗教遺物","name":"装飾経","rank":"2","desc":"装飾を施した上質の紙に風俗画を描き、その上から仏教の経文を書き写したもの。\n平安時代の華やかな貴族文化を表しており、美術品としても高く評価される。","note":"華やかな経文","exp":"370"}],"6380":[{"type":"歴史遺物","name":"クフ王が描かれたレリーフ","rank":"2","desc":"古代エジプトのファラオ、クフ王が描かれたレリーフの一部。カルトゥーシュと呼ばれるヒエログリフの曲線がファラオの名を囲んでいる。同様のレリーフには、生贄とされた牛が描かれたものや、弓を引く王が描かれたものなどがある。","note":"","exp":"270"}],"1279":[{"type":"歴史遺物","name":"土器製ローラー","rank":"2","desc":"土器でできた、紋様をつけるための道具。焼き物の紋様づけに使ったり、印としても用いられたようである。","note":"石集め","exp":"310"}],"6884":[{"type":"植物","name":"エピポギウム・アフィルム","rank":"5","desc":"ブリテン島で発見されたランの一種。葉を持たず、小さな花を咲かせる。見つけるのが極めて難しいことから、「幽霊ラン」と呼ばれることもある。","note":"追究クエスト","exp":""}],"3847":[{"type":"鳥類","name":"アメリカシロヅル","rank":"2","desc":"北米からカナダにかけて、湿潤な草原に生息するツル。ツルにしては体が大きく、真っ白な毛に覆われている。","note":"北米のツルの生態調査<br/><br/>発見時経験値240　発見物カード経験値120","exp":"240"}],"6576":[{"type":"植物","name":"ムシトリスミレ","rank":"5","desc":"中米の熱帯高山に自生する食虫植物。一見するとスミレに似た花を咲かせる可愛らしい植物であるが、れっきとした食虫植物である。葉の表面に粘液で覆われた細かい毛が生え、とまった虫を捕らえて消化吸収する。","note":"","exp":""}],"2971":[{"type":"植物","name":"ドルステニア・フォエチダ","rank":"2","desc":"アラビア半島原産の多肉植物。太陽のような形をしたものの中心には、ごく小さな雄花と雌花が多数集まっている。","note":"太陽の花","exp":"260"}],"4954":[{"type":"史跡","name":"パルテノン神殿","rank":"3","desc":"アテネにあるアクロポリスの丘に建てられた神殿。アテネの守護神である、女神アテナの聖域といわれている。白大理石を使用したパルテノン神殿には、細部の装飾が美しい古代ギリシャの建築様式が用いられている。","note":"","exp":"540"}],"7019":[{"type":"歴史遺物","name":"マグナ・カルタ","rank":"2","desc":"13世紀初頭のイングランドで作成された、全63条からなるラテン語の憲章。「自由の大憲章」とも呼ばれ、ジョン王の統治に反発した貴族たちが、王権を法の下に制限するために起草した。ジョン王が貴族の要求を受け入れて署名し、発布した。","note":"","exp":""}],"2696":[{"type":"歴史遺物","name":"伽耶の短甲","rank":"3","desc":"伽耶時代に作られた鉄の短甲。\n短甲とは、主に胴体を保護するための武具のこと。これは三角形の鉄板が鋲で固定され、胸と背中に渦巻状の鉄板が取り付けられている。","note":"鉄の国の名残","exp":"530"}],"449":[{"type":"美術品","name":"失楽園","rank":"1","desc":"マザッチョ作の壁画。礼拝堂の壁に、複数の画家が描いたものの一つである。マザッチョは線遠近法を生かし、それまでとは大きく異なる、生気にあふれた絵画を描いた。","note":"教会の宗教画の地図","exp":"90"}],"2020":[{"type":"歴史遺物","name":"マゼラン南米冒険記","rank":"2","desc":"マゼランが南米で航海を中断していた時に記したと思われる書物。先住民族などについて記載されている。","note":"［勅命］[[新大陸西岸進出の先人の記録","exp":"310"}],"2897":[{"type":"財宝","name":"黄帝内経","rank":"2","desc":"古くから伝わる針灸医学の規範となる書物。前漢の時代に編さんされたと思われる。\n複数の医学論文をつづり合わせたもので、著者や編集者は明らかではない。","note":"古い医学書の地図","exp":"260"}],"3905":[{"type":"レリック","name":"ほらふき男爵","rank":"","desc":"巧みな話術と機知で知られたミュンヒハウゼン男爵。彼の冒険譚は今も人々を楽しませている。","note":"","exp":""}],"3818":[{"type":"地理","name":"エルーセラ島","rank":"5","desc":"カリブ海の西インド諸島のうち、バハマ諸島に属する島。サンゴ岩礁の島であり、細長い形をしている。","note":"ナッソー付近の航路調査","exp":"950"}],"2411":[{"type":"歴史遺物","name":"カルトゥーシュ","rank":"3","desc":"古代エジプトの象形文字の一つ。ファラオの名前を囲んだ曲線であり、壁画などに描かれている。ファラオの名前を囲むことにより、これを守るものとされている。","note":"ダンジョン","exp":"420"}],"23":[{"type":"植物","name":"バオバブ","rank":"1","desc":"アフリカの乾燥地帯に広く分布する落葉樹。高さはさほどではないが、幹が太りやすい。水を多く含むため、乾季にはゾウが水を求めて倒してしまうことがある。","note":"アフリカの巨木","exp":"130"}],"3162":[{"type":"鳥類","name":"ミサゴ","rank":"2","desc":"北米をはじめとして、ほぼ全地域の沿岸部に生息する大型の鳥。\n水面を低空飛行し、魚を捕食する。全体的に黒褐色だが、頭頂部は真っ白な冠羽を持つ。","note":"力強い鳥の地図","exp":"320"}],"43":[{"type":"財宝","name":"世界史序説","rank":"1","desc":"イブン・ハルドゥーン著の歴史書。14世紀後半に書かれたもので、王朝の興亡の法則性などを考察している。","note":"イスラムの歴史観","exp":"170"}],"1003":[{"type":"財宝","name":"覇王の宝冠","rank":"1","desc":"所有するものに覇をもたらすと伝えられる、豪華な宝冠。しかし、言い伝えは作られたものらしい。ハンザ同盟の富をつぎ込んで作られたという。","note":"北欧の覇","exp":"150"}],"1559":[{"type":"小型生物","name":"フクロネコ","rank":"1","desc":"ネコに似た有袋類。夜行性で、昆虫や小動物を捕食する。","note":"ネコに似た動物の地図","exp":"135"}],"139":[{"type":"歴史遺物","name":"クラウ・ソナス","rank":"5","desc":"ケルト神話四大秘宝の一つで不敗の剣と言われる。ダーナ神族の王・ヌァザの持ち物で、一度さやから抜かれると、逃れられる敵はいないという。","note":"クラウ・ソナス","exp":"1222"}],"5691":[{"type":"地理","name":"サラミス島","rank":"5","desc":"エーゲ海に位置する島の一つ。サラミスの海戦の際、ギリシャ艦隊の集結地となった。","note":"2017.02.07新規追加","exp":"1340"}],"2729":[{"type":"宗教遺物","name":"石窟庵の仏像","rank":"5","desc":"石窟庵内部に鎮座している仏像。\n額にガラスが埋め込まれており、太陽光が石窟内を満たすと、そのガラスが輝くという。新羅は石造建築だけでなく、石仏彫刻の技術力も高かったようだ。","note":"闇の中の光","exp":"810"}],"5386":[{"type":"歴史遺物","name":"戦術書","rank":"2","desc":"ギリシャのポリュアエヌスの著作。アケメネス朝ペルシャの王・カンビュセス2世がエジプトのペルシウムの街を攻略する際に、エジプト人が神聖視していたネコを巧みに利用したという逸話を伝えている。","note":"","exp":"230"}],"1742":[{"type":"宗教遺物","name":"法華経","rank":"1","desc":"ほっけきょう。仏教経典のひとつ。全てのものは縁起をもって仏たりえるという、仏教独自の因果関係について書かれている。","note":"古い法典の地図","exp":"160"}],"1751":[{"type":"中型生物","name":"カモノハシ","rank":"5","desc":"カワウソのような体にカモのくちばしを持つ生物。卵を産み、孵化した子を、母乳で育てる。オスは後ろ足にある蹴爪から敵に毒を打ち込むことができる。","note":"驚天動地","exp":"1209"}],"3899":[{"type":"天文","name":"大マゼラン星雲","rank":"2","desc":"マゼランが世界周航する際に記録を残していたため、この名で呼ばれるようになる。マゼラン以前のヨーロッパの航海者はケープの雲と呼んでいた。北半球では赤道近くまで南下しないと見られない。","note":"「天文学者の観測記録」<br/>発見物カード:105","exp":"210"}],"3260":[{"type":"地理","name":"ツブカル山","rank":"3","desc":"アトラス山脈の西部に連なるモロッコ最高峰の山。山頂からはアトラス山脈の雄大な景色を見ることができる。","note":"山脈の頂上","exp":"500"}],"2116":[{"type":"歴史遺物","name":"コロン提督の手記","rank":"2","desc":"ポルトベロに到達したコロン提督による報告書の一部。どうやら調査の途中で紛失してしまった物のようだ。","note":"［勅命］[[ある調査の追加調査","exp":"310"}],"1934":[{"type":"鳥類","name":"トキイロコンドル","rank":"5","desc":"翼を広げると1.8mにもなる大型の鳥。動物の死がいを餌とし、生きた動物を襲うことはない。鮮やかな体色をしていて、くちばしの上部にオレンジ色の肉垂が付いている。","note":"伝説を追う資格","exp":"1222"}],"5509":[{"type":"港・集落","name":"ロッテルダム","rank":"1","desc":"北海に面する街。ライン川などの複数の川が北海に流れ込む地点に位置する。16世紀頃から港湾都市として発達し、大西洋貿易の要となっている。","note":"座標　52,2492","exp":"15"}],"861":[{"type":"美術品","name":"ピエタ","rank":"3","desc":"ミケランジェロ作の大理石像。処刑されたイエスを抱く聖母マリアの像である。人間の肉体、衣服のひだなど、冷たい石だとは思えない出来だ。イエスに比べてマリアが若いが、これも表現方法の一つである。","note":"天才の青年時代","exp":"451"}],"5397":[{"type":"天文","name":"とびうお座","rank":"3","desc":"天の南極近くにある星座。星座図では、かじき座に追いかけられているように描かれることがある。","note":"「天文学者の観測記録」<br/>発見物カード:230","exp":"460"}],"5657":[{"type":"財宝","name":"サロン","rank":"3","desc":"インドネシアの民族音楽「ガムラン」で用いられる楽器。半月形に盛り上った青銅板が金具で留めてあり、水牛の角や小さな木槌で打って演奏する。","note":"","exp":"490"}],"6832":[{"type":"美術品","name":"エスコリアルの無原罪の御宿り","rank":"3","desc":"「無原罪の御宿り」を主題とし描かれた油彩画。イスパニアの画家ムリーリョの作。彼はこの主題で多くの作品を残しているが、美しい聖母マリアと、身にまとう白と青の衣が共通した特徴。幻想的な作風は後の芸術に多大な影響を与えた。","note":"","exp":""}],"1679":[{"type":"虫類","name":"プラチナコガネ","rank":"5","desc":"最大の特徴は、宝石のように金銀に光り輝く羽。このような光沢を持った種は、稀にしか見られない。","note":"謎の光","exp":"1014"}],"4852":[{"type":"レリック","name":"星の記録","rank":"","desc":"アレクサンドリア図書館の破壊を免れ、隠されていた古代の天文観測記録。古代人は天を見て国家の命運を知ろうとしていた。","note":"","exp":""}],"2986":[{"type":"鳥類","name":"パープル・ガリヌール","rank":"3","desc":"熱帯の湿地でよく見られる鳥。青みがかった羽毛が鮮やかである。細い脚で水草の上を歩くさまは、まるで水面を歩いているようだ。","note":"虹色を求めて","exp":"480"}],"3900":[{"type":"天文","name":"土星の環","rank":"2","desc":"土星を囲む環。初期の天体望遠鏡でも環の存在は見つけられたが、観測が難しかった。望遠鏡の性能が向上すると、いくつかの環の観測に成功したが、何で構成されているのかは不明である。","note":"「土星の観測記録」","exp":"260"}],"6738":[{"type":"中型生物","name":"タイワンヤマネコ","rank":"5","desc":"台湾島の固有種とされるヤマネコ。耳の先が丸く後ろには白い斑点がある。日本のイリオモテヤマネコとは非常に種が近い。獲物を捕らえると前足で叩いて弱らせる習性を持つ。","note":"カード経験:520","exp":"1040"}],"2247":[{"type":"中型生物","name":"ピンクイグアナ","rank":"5","desc":"体長1mほどのピンク色をした大型トカゲ。\nガラパゴス諸島の特定の島の火山にしか生息しておらず、滅多に見られない。","note":"幻の桃色トカゲ","exp":"930"}],"5532":[{"type":"気象・現象","name":"黄砂","rank":"3","desc":"ユーラシア大陸内の陸部から微小な砂が風に乗って移動し、周辺地域へ降りそそぐ現象。農作物や周辺住民の健康にも影響を及ぼし、海を越えて被害を発生させることもある。","note":"","exp":"260"}],"3311":[{"type":"財宝","name":"武器の操作","rank":"4","desc":"ネーデルラントの総督マウリッツ伯の著作。マウリッツ伯は、軍事訓練の手法を細かく分化し、一つ一つの手順に対する理解度を高めることに成功。その情報を包み隠さずこの書物にまとめた。各軍の練度は著しく向上したという。","note":"傭兵に贈る兵法書<br/><br/>発見時経験値740　発見物カード経験値370","exp":"740"}],"1870":[{"type":"宗教遺物","name":"ナイムラップの黄金仮面","rank":"3","desc":"インカ以前にもランバイェケ周辺には高度な文明をもった都市国家が存在していた。ナイムラップとはこの都市国家で語り継がれている伝説的な王のこと。南方から船団で現れ、死して後は翼が生えて飛び去ったと伝えられている。","note":"神をかたどった黄金","exp":"500"}],"6790":[{"type":"鳥類","name":"シロチドリ","rank":"4","desc":"ヨーロッパ、アジア、アフリカなど広く生息する水鳥。渡り鳥であり、季節によって棲む場所を変える。背は灰色、首回りと腹は白い羽を持つ。砂浜や河川敷などに飛来し、水辺の昆虫などを食べる。","note":"発見物カード:350","exp":"700"}],"1478":[{"type":"宗教遺物","name":"チナラート仏","rank":"5","desc":"スコータイ時代に作られた仏像の一つ。この時代の仏像は、ふっくらした丸い顔に、丸みを帯びた体つきが特徴である。男性像でも腰のくびれがあり、写実的な西洋像とは一線を画す。この像の制作にヴィシュヌ神が手伝ったという伝説がある。","note":"ヴィシュヌが手を貸す美しさ","exp":"1040"}],"5603":[{"type":"気象・現象","name":"彩雲","rank":"2","desc":"上空の雲が赤や黄、緑などの色で彩られる現象。比較的、薄い雲で観測されることが多いため、雲の薄さが発生原因に含まれると思われる。一部地域では、吉兆と言われる。","note":"","exp":"300"}],"2898":[{"type":"鳥類","name":"コジュケイ","rank":"2","desc":"中国南部や台湾島に生息する、変わった鳴き声を持つ鳥。\n用心深い性格で、めったに姿を見せない。早朝になると群れで餌を探しに行くようだ。","note":"変わった鳥の地図","exp":"220"}],"5064":[{"type":"港・集落","name":"サントドミンゴ","rank":"2","desc":"イスパニョーラ島の南東部にある街。開拓されたばかりの街だが、航海の便がよく、カリブの交易の中心地として栄えている。カリブ特有の農作物のほか、サトウキビの栽培が広く行われている。","note":"到達する","exp":"240"}],"3742":[{"type":"海洋生物","name":"ホッキョククジラ","rank":"5","desc":"極北の海に生息するクジラの一種。大きく湾曲した下顎が特徴。頭蓋骨が頑強であり、その頭で流氷を砕き、海面に出る。","note":"氷海の永住者","exp":"1200"}],"1852":[{"type":"史跡","name":"クスコ","rank":"5","desc":"インカ帝国中心都市。クスコとは現地の言葉で「へそ」という意味だという。滑らかで美しい巨石を幾重にも組んで作られ、その間には爪の先も入らないほどだ。この技術には目を見張るものがある。","note":"アンデスにそびえる都","exp":"520"}],"2979":[{"type":"虫類","name":"オオカバマダラ","rank":"3","desc":"羽全体を覆う黒いふちと、白い斑点が特徴のチョウ。飛行能力に優れており、渡り鳥のように、数千キロにも及ぶ大移動を行うともいわれている。","note":"流浪のチョウ","exp":"480"}],"1476":[{"type":"宗教遺物","name":"ハヌマーンのレリーフ","rank":"2","desc":"ラーマーヤナに登場するハヌマーンのレリーフ。同じくラーマーヤナに登場する魔王・ラヴァナとの合戦の様子を彫りこんだもののようだ。","note":"ラーマを助ける猿の神<br/><br/>発見時経験値280　発見物カード経験値140","exp":"280"}],"1692":[{"type":"美術品","name":"ミロのヴィーナス","rank":"5","desc":"メロス島で出土した大理石の女性像。他の像と組み合わされていたと思われる。豊かな肢体の柔らかな曲線と着衣のひだが美しい。","note":"メロス島を惑わす女神","exp":"1222"}],"3321":[{"type":"地理","name":"カールズバッド洞窟群","rank":"5","desc":"北米の南西部に位置する洞窟群。巨大な地下室や多数の鍾乳石を有する。中は無数のコウモリのすみかとなっており、日没時と夜明けには大群で出入りする様子が見られる。","note":"黒雲渦巻く洞窟<br/><br/>発見時経験値810　発見物カード経験値405","exp":"810"}],"3540":[{"type":"レリック","name":"ジャンヌを継ぐ者","rank":"","desc":"諸侯と傭兵の寄せ集めの軍から国王の常備軍へ。リッシュモン元帥の軍制改革はフランスの大国化に大きく貢献したといえよう。","note":"","exp":""}],"3871":[{"type":"化石","name":"長いトサカを持つドラゴンの骨","rank":"2","desc":"北米で発見された、長いトサカを持つドラゴンの骨。頭部の大きさから類推するに、体もかなり大きいと思われる。","note":"奇妙な石の地図","exp":"240"}],"5466":[{"type":"小型生物","name":"アグーチ","rank":"1","desc":"パンタナル湿原でよく見られる体長50～70cmの動物。\nリスのような外見をしているが、大型で足が細長く、尻尾が短い。動きは俊敏で。走るのが速く、6mほど跳躍するといわれている。","note":"「リスに似た中型動物の地図」<br/>発見物カード:90","exp":"180"}],"1754":[{"type":"海洋生物","name":"ベルーガ","rank":"3","desc":"黒海に見られる大型のチョウザメ。体長6m、重さ数トンのものもいるようだ。","note":"釣り","exp":"528"}],"245":[{"type":"地理","name":"ゴトランド島","rank":"1","desc":"バルト海最大の島。先史時代から人が住んでいたそうだ。ハンザ同盟の時代には、交易上重要な存在だった。\n「神の島」もしくは、「神の国」とも呼ばれている。","note":"バルト海の神の島","exp":"80"}],"231":[{"type":"宗教遺物","name":"ニーベルンゲンの指輪","rank":"5","desc":"ラインの黄金で作られた指輪。世界のすべてを持ち主に与えるという。イスパニアの王室が手に入れたものが本物かどうかは明らかではないが、伝承どおりの、美しい黄金の指輪であることは間違いない。","note":"ニーベルンゲンの指輪","exp":"880"}],"1792":[{"type":"地理","name":"フンボルト海流","rank":"4","desc":"南米大陸の西岸を大陸の南端からグアヤキル湾まで北上する寒流。水流は遅く水温は非常に低いが、この海流に乗って魚群が北上するため、南米南西岸は広範囲に豊かな漁場を持つ。","note":"クエスト「砂漠と海の関係」<br/>発見物カード:370","exp":"740"}],"3207":[{"type":"植物","name":"バルサムモミ","rank":"3","desc":"北米北東部を中心に広く分布する樹木。樹高は20m程度で、円錐型に枝を広げる。バニラに似たほのかな甘い香りを放つ。","note":"甘い香りの木<br/><br/>発見時経験値440　発見物カード経験値220","exp":"440"}],"1262":[{"type":"美術品","name":"ラオコーン（腕曲げ）","rank":"5","desc":"ローマで出土したラオコーン像の完全な姿。体をよじり苦痛に耐える表情から、天罰の恐ろしさがまざまざと伝わってくる。","note":"蘇るトロイ戦争","exp":"1183"}],"275":[{"type":"財宝","name":"ベリアルの宝玉","rank":"1","desc":"聖書のソロモン王が、悪魔や精霊72体を封じ込めたという宝玉の一つ。この宝石にはベリアルが封じられているという。真偽の程は不明だ。\n宝玉はよく見ると傷があり、「松の島の北の街」と彫られている。","note":"ベリアルの宝玉","exp":"100"}],"3785":[{"type":"天文","name":"プロキオン","rank":"3","desc":"シリウスやベテルギウスと共に冬の大三角を構成する星。こいぬ座に属する星で、名は犬の先駆けという意味。古代エジプトでは、洪水を知らせるシリウスに先立って昇るとして重視された。","note":"発見物カード:225","exp":"450"}],"1687":[{"type":"大型生物","name":"アナコンダ","rank":"5","desc":"アマゾン川流域に生息する大蛇。巨大なもので7mほどに成長する。夜に活動をし、水辺に来る動物を襲うほか、ワニを食べることもある。","note":"アマゾンの大蛇","exp":"1170"}],"6903":[{"type":"史跡","name":"大明宮遺跡","rank":"5","desc":"唐代の首都である、長安城の北東に建てられた大宮殿の跡。634年に建造され、政治の中心地となった。広大な丘陵をはじめ、多くの宮殿が建ち並んでいたが、戦火で全て消失した。","note":"","exp":""}],"3811":[{"type":"地理","name":"エル・リモンの滝","rank":"2","desc":"イスパニョーラ島の北東部に位置する滝。落差は約40mで、水流は比較的穏やかである。","note":"書きかけの地図","exp":"400"}],"2858":[{"type":"財宝","name":"玉璽","rank":"5","desc":"読みは「ぎょくじ」。皇帝が用いる印章で、始皇帝が定めた。\n史書では玉でできていると伝えられるが、なんらかの事情があって金で覆われたと思われる。伝国の玉璽であると思われるが、今となっては定かではない。","note":"いつか帰るところ","exp":"1250"}],"6116":[{"type":"美術品","name":"至聖三者のイコン","rank":"5","desc":"15世紀ロシアの修道士アンドレイ・ルブリョフが、ある修道士の依頼で作成したとされるイコン。アブラハムを訪れた三天使が木の下に座っている様子が描かれ、三位一体の神を象徴していると解釈される。","note":"","exp":"940"}],"885":[{"type":"虫類","name":"毒サソリ","rank":"1","desc":"尾の先のトゲに毒を持つ虫。体の作りはエビなどに近いようだ。毒はかなり強く、人間が死ぬこともある。砂漠地帯にいると思われがちだが、意外といろいろな地域にいる。","note":"毒のある虫の地図","exp":"34"}],"5535":[{"type":"気象・現象","name":"幻日","rank":"4","desc":"太陽が複数並んで見える現象。大気中の微粒子が幻影の発生に関係していると考えられるが、いまだに詳細は解明されていない。","note":"","exp":"374"}],"5238":[{"type":"植物","name":"イナゴマメ","rank":"2","desc":"10m以上の高さになる常緑高木。温暖な土地で生育し、乾燥にも耐える。その実は糖分を含んで甘く、古代より甘味料として食された。「聖ヨハネのパン」ともいわれ、聖書にも登場する。","note":"","exp":"310"}],"4872":[{"type":"大型生物","name":"ペルシャヒョウ","rank":"2","desc":"中東に生息するヒョウ科の亜種。ヒョウの亜種の中で最大である。通常のヒョウとは異なり、胸や腹にも斑点が存在する。","note":"大型のヒョウの地図","exp":"220"}],"983":[{"type":"歴史遺物","name":"カリグラ帝の大理石像","rank":"1","desc":"古代ローマのカリグラ帝の大理石像。カリグラという名は、本名ではない。史上1、2位を争うような暴君であったという。","note":"暴帝の彫像","exp":"50"}],"5075":[{"type":"港・集落","name":"ジャマイカ","rank":"2","desc":"カリブ海の南部に浮かぶジャマイカ島にある街。全体的に山がちなので、高山に適しているコーヒーの栽培が盛んである。","note":"到達する","exp":"237"}],"2829":[{"type":"美術品","name":"徽宗の花鳥画","rank":"5","desc":"宋代の皇帝・徽宗の作品。\n徽宗は花鳥画に長けており、この絵も気品に満ちた絵であるとして高い評価を得ている。","note":"悪役の素顔","exp":"830"}],"3810":[{"type":"財宝","name":"海賊史","rank":"5","desc":"17世紀末から18世紀初頭にかけて活動していた海賊の伝記集。さまざまな海賊の生涯が克明に記されている。","note":"欧州に伝わる海賊譚<br/><br/>発見時経験値1210　発見物カード経験値605","exp":"1210"}],"5641":[{"type":"財宝","name":"ウラノメトリア","rank":"2","desc":"17世紀の初頭に、ドイツの法律家であるヨハン・バイエルが出版した星図書。全天の星座が収録されている。星図上にギリシャ文字やローマ文字の符号を添え、参照しやすくしてある。","note":"発見時経験値270　発見物カード経験値135","exp":"270"}],"1509":[{"type":"財宝","name":"ナーガラクルターガマ","rank":"3","desc":"マジャパヒトの宮廷詩人プラパンチャが編さんした歴史書。マジャパヒトの最盛期の様子を克明に著している。","note":"クエスト「伝国の名著」<br/>発見物カード:230","exp":"462"}],"384":[{"type":"大型生物","name":"人食いトラ","rank":"3","desc":"トラの中でも特に凶暴で、人を襲うもの。体重が300kg近くありそうな、トラの中でも特に体の大きな個体だ。トラはもともと森の奥深くに生息する動物だが、容易に捕まえられる人間を狙うようになり、人里近くに現れたのだろう。","note":"害をなす猛獣","exp":"484"}],"5755":[{"type":"地理","name":"ハロン湾","rank":"5","desc":"多数の小島が浮かび、美しい景観を備えた大きな湾。漢字で書くと「下竜湾」であり、竜が造ったという伝説がある。","note":"2017.02.07新規追加","exp":"1370"}],"923":[{"type":"小型生物","name":"ゴールデンハムスター","rank":"1","desc":"背が赤茶色で腹が白く尾がほとんどないネズミ。動きが緩慢で地上で生活し、巣穴は自分で掘る。非常に大きな頬袋を持ち、大量のエサや巣材を運んでいる姿を見かける。","note":"尾のないネズミの地図","exp":"24"}],"6":[{"type":"歴史遺物","name":"ダレイオス3世の鎧","rank":"1","desc":"アケメネス朝ペルシャの最後の王、ダレイオス3世の鎧。アレクサンドロス大王に攻め込まれて連敗し、敗走先の総督に殺されてペルシャは滅びた。","note":"アケメネス朝の最後","exp":"160"}],"6348":[{"type":"歴史遺物","name":"大灯台のトリトン像","rank":"2","desc":"全高130メートルを超える大灯台の四方に飾られていたとされるトリトンの像。最頂部には父であるポセイドンの像も飾られていたとされ、大灯台は海を象徴する神々の加護をうけた。","note":"","exp":"300"}],"6871":[{"type":"美術品","name":"デューラーの自画像","rank":"5","desc":"神聖ローマ帝国の画家デューラーの作。数ある自画像のうちの一作で、デューラーが26歳の時のものとされる。画家の地位向上と、自身の着道楽を表した、豪奢な姿で描かれている。","note":"発見物カード:425","exp":"850"}],"6696":[{"type":"財宝","name":"天工開物","rank":"2","desc":"明の学者・宋応星の著作。中国全土を歴遊し「座学より実学で学ぶべし」の精神で作られた産業技術書。明代の産業を網羅している。中国では評判されず、散逸してしまったが、日本では貝原益軒らに珍重にされて残った。","note":"漢陽 書庫　産業技術書の地図　財宝　R8","exp":"280"}],"2532":[{"type":"中型生物","name":"タイワンハブ","rank":"2","desc":"主に台湾島や中国に生息している、毒性の強いヘビ。顔が細長く、長い牙を持つため、噛まれると体の深部まで毒が回ってしまう。\n樹上での活動が多く、夜行性である。","note":"毒蛇の脅威","exp":"240"}],"5844":[{"type":"美術品","name":"イスラムの彫刻小箱","rank":"5","desc":"後ウマイヤ朝で作られた象牙細工。精緻な浮き彫りで四面に別々の場面が描かれ、四面を繋ぐように細かな文様が刻み込まれている。高貴な人物のために作られたもののようだ。","note":"","exp":"1370"}],"2717":[{"type":"海洋生物","name":"ヤナギナマズ","rank":"1","desc":"朝鮮の渓流に生息する珍しいナマズ。\n地元では、山のナマズを意味する、「サンメギ」という名で呼ばれている。","note":"山の魚の地図","exp":"130"}],"929":[{"type":"植物","name":"ヨーロッパカエデ","rank":"1","desc":"冬が近づくと葉が赤や黄色に色づく落葉樹。木の数が多いと大変美しい。実には羽のようなものがついており、風に乗って飛ぶ。","note":"美しい木の地図","exp":"10"}],"2731":[{"type":"宗教遺物","name":"百済の舎利容器","rank":"1","desc":"仏教が盛んだった百済時代のものと思われる舎利容器。ある寺院に保管されているものは入れ子の設計になっており、青銅の容器の中に銀の容器が、銀の容器の中に金の容器が収められているという。","note":"朝鮮の遺物の地図","exp":"130"}],"2592":[{"type":"歴史遺物","name":"台湾全島図","rank":"1","desc":"台湾島の全体図と思われる絵図。\n台湾地域の地図は三つの諸島として描かれたものが多かったが、この地図では一つの島になっている。","note":"大きな島の地図","exp":"150"}],"6476":[{"type":"史跡","name":"在りし日のロードス島の巨像頭部","rank":"5","desc":"ロードス島の港に立つ太陽神ヘリオスの巨大な青銅像。攻城者デメトリオスによる包囲を耐え切り、勝利した記念として建造された。頭には太陽光線を表すサークレットを付けている。顔立ちはアレクサンドロス大王を模しているともされる。","note":"","exp":""}],"6415":[{"type":"財宝","name":"プラトンの手引きの原本","rank":"5","desc":"哲学者プラトンが書いた哲学書の原本。対話形式で書かれている。元はアカデメイアの学生に向けたものとの説もある。内容は、哲学に留まらず政治や教育についても深く触れられている。","note":"","exp":""}],"115":[{"type":"宗教建築","name":"ギザのピラミッド","rank":"1","desc":"三つ並んだ巨大なピラミッド。大きい順にクフ王、カフラー王、メンカウラー王のもの。巨大な石を正確に積み上げて造られている。現在の技術で同じものを造れるだろうか？","note":"ギザのピラミッドの調査","exp":"145"}],"1261":[{"type":"美術品","name":"ラオコーンの右腕","rank":"5","desc":"ローマで出土したラオコーン像の、折れた右腕。ラオコーン像には天をつかむような伸ばした右腕がつけられていたが、これは曲げられている。","note":"失われた右腕","exp":"1053"}],"1973":[{"type":"鳥類","name":"コンドル","rank":"5","desc":"とても大きな鳥。中には翼を広げると3mになるものもいる。大きな翼を広げたまま、高所を滑空する姿がよく見られる。高地の断崖の岩陰に巣を作り、死んだ大型動物の肉を好んで食べる。50年以上生きる長寿の鳥。","note":"優雅に舞う巨大鳥","exp":"1080"}],"3299":[{"type":"鳥類","name":"リョコウバト","rank":"3","desc":"北米の東岸に生息する鳥。体長は約40cmで、長くとがった翼と尾羽を持つ。非常に大きな群れで渡りを行う習性があり、夏は北米北東部などで、冬は主にメキシコ湾岸で過ごす。","note":"大群で渡る鳥","exp":"510"}],"2883":[{"type":"地理","name":"黄河","rank":"3","desc":"雲台山の北部を流れる大河。\n下流域は「中原」と呼ばれ古代文明が発祥した地である。\n古来、よく氾濫し川の流れが変わっている。","note":"華北の古代文明","exp":"530"}],"542":[{"type":"歴史遺物","name":"古代の副葬品","rank":"1","desc":"故人を葬るときに一緒に埋葬された道具類。古代文明では、死後の世界で使うための物として、日用品や武具、装飾品などを墓室に納めた。","note":"古代の墳墓の地図","exp":"16"}],"890":[{"type":"歴史遺物","name":"海の民の剣","rank":"2","desc":"ヒッタイト王国を滅ぼした、謎の古代民族「海の民」が使っていたと思われる鉄剣。ヒッタイトの製鉄技術を盗んだのだろうか？","note":"謎の古代民族","exp":"310"}],"342":[{"type":"財宝","name":"医学典範","rank":"1","desc":"「いがくてんぱん」。イブン・シーナー著の医学書である。アラビア医学の集大成といわれ、ペルシャからヨーロッパにかけて広く学ばれている。","note":"医学書の最高権威","exp":"110"}],"3885":[{"type":"財宝","name":"ラリアット","rank":"3","desc":"ウシなどの動物を捕まえるための投げ縄。\n罠の先が輪になっており、家畜の体に掛けて引っ張ると締まる仕組みになっている。","note":"伝説の牛追い人","exp":"460"}],"3176":[{"type":"植物","name":"クロトウヒ","rank":"1","desc":"北米東部から北部にかけて分布する樹木。高さは25m程度にまで伸び、円錐型に枝を広げる。材木としては堅いため、建築材として有用である。","note":"硬質な木の地図","exp":"190"}],"5890":[{"type":"中型生物","name":"ジャックウサギ","rank":"2","desc":"体長が40cmを超える、大型のウサギ。北米に生息する。脚が発達しており、時速30km以上で走ることができる。","note":"","exp":"240"}],"3791":[{"type":"天文","name":"リゲル","rank":"2","desc":"オリオン座で最も明るい、青白い星。オリオン座の右下に位置し、星座図ではオリオンの左膝にあたる。リゲルという名はアラビア語で足を意味するリジルからきている。冬のダイヤモンドの一角。","note":"視認","exp":"340"}],"3310":[{"type":"財宝","name":"方法序説","rank":"3","desc":"フランスの哲学者、デカルトの著作。物事の捉え方・考え方について、デカルト本人の自伝も含めて書かれている。三十年戦争でマウリッツ伯の軍に入隊していたころの記述もある。","note":"大国の思惑<br/><br/>発見時経験値520　発見物カード経験値260","exp":"520"}],"370":[{"type":"美術品","name":"果物かご","rank":"2","desc":"カラバッジオ作の、果物かごを描いた絵画。人物を描かない絵はこれまでの常識を打ち破るものだ。やや生気を失いかけた果物や葉が生々しく、これまでにない魅力がある。","note":"果物かごだけの絵","exp":"380"}],"6855":[{"type":"財宝","name":"虫入り琥珀","rank":"5","desc":"中に虫などを含んでいる琥珀。樹液が昆虫や葉などを包み込んだまま固まり、何千万年もの時を経て化石化、琥珀となって産出したもの。偶然の産物で、希少価値がある。","note":"発見物カード:465","exp":"930"}],"6062":[{"type":"港・集落","name":"マンガロール","rank":"1","desc":"インド南西部の港湾都市。古くから重要な港であり、多くの王朝が支配権を争った。都市内にあるマンガラデーヴィー寺院と同じく、ヒンドゥー教の神の名に由来する。","note":"到達する","exp":"180"}],"6480":[{"type":"財宝","name":"攻城者デメトリオスのコイン","rank":"5","desc":"戦に長け、攻城者の異名を持つデメトリオス1世のコイン。アレクサンドロス大王没後のディアドコイ戦争で活躍したが、ロードス包囲戦では島民の抵抗に遭って撤退。島民は彼らの残した武具を利用し、戦勝記念の巨像を建てたという。","note":"レガシー港湾都市ロードス　左上","exp":"1650"}],"3608":[{"type":"財宝","name":"海賊の約定書","rank":"5","desc":"ある海賊がしたためた約定書。無法者の海賊たちが取り交わす約定に、どれほどの効力があるのかは不明。","note":"海賊論<br/><br/>発見時経験値1110　発見物カード経験値555","exp":"1110"}],"6745":[{"type":"鳥類","name":"モモアカノスリ","rank":"3","desc":"新大陸に生息する中型の猛禽類。群れを成して狩りを行うという、猛禽類では珍しい習性を持つ。人間に親しみやすく、飼育しやすい鷹として知られる。別名はハリスホーク。","note":"","exp":"450"}],"1528":[{"type":"海洋生物","name":"ナイルパーチ","rank":"1","desc":"ナイル川流域に広く分布するスズキの仲間。大きなものは200kgにもなるようだ。","note":"釣り","exp":"150"}],"1333":[{"type":"地理","name":"バンダ海","rank":"1","desc":"セレベス島の南東にある海。200以上の小島があるといわれる。この小島のどれかに貴重な香辛料の原産地があるのかもしれない。","note":"書きかけの地図","exp":"155"}],"5946":[{"type":"美術品","name":"アズレージョ","rank":"3","desc":"ポルトガルやイスパニアで生産されるタイル細工。細密に描かれた装飾が特徴。その技術はイベリア半島にイスラム国家が進出していた時代にもたらされ、ポルトガル建築に欠かせない要素となるまでに発展を遂げた。","note":"","exp":""}],"6222":[{"type":"地理","name":"ガッガル・ハークラー川","rank":"5","desc":"古代にはインダス川と並行して流れていたとされる川。今は雨季に流れるだけだが、「リグ・ヴェーダ」にもサラスバティー川として賛歌が残っている。一説にはヒンドゥー教の女神サラスバティーはこの川の神格化であるという。","note":"","exp":"1030"}],"6798":[{"type":"天文","name":"スラファト","rank":"3","desc":"こと座に位置する３等星。名はアラビア語で亀を意味し、亀の\n甲羅に弦を張り、琴がつくられていたことに由来しているとい\nる。","note":"視認","exp":""}],"6573":[{"type":"歴史遺物","name":"自省録","rank":"5","desc":"マルクス・アウレリウスは「五賢帝」のひとり。皇帝にして、偉大なストア派の哲学者であったことから「哲人君主」の名で呼ばれている。彼の哲学的な思索は、著書『自省録』に日記や散文の形でまとめられて、後世に伝わっている。","note":"クエスト「古代ローマ皇帝の遺物の追加調査」","exp":""}],"5995":[{"type":"史跡","name":"カルタゴ遺跡","rank":"1","desc":"古代フェニキア人が造った都市国家の跡。第三次ポエニ戦争でローマに滅ぼされたといわれる。カエサルによって再建されたが、7世紀末に廃墟となった。","note":"ポエニ戦争の爪跡","exp":"110"}],"5135":[{"type":"港・集落","name":"ヘルデル","rank":"1","desc":"アムステルダムの北にある小都市。北海に面しており、漁業が盛んである。","note":"到達する","exp":"15"}],"1850":[{"type":"史跡","name":"マチュピチュ","rank":"5","desc":"高い峰々に囲まれたインカ帝国の都市。ケチュア語で「老いた峰」を意味する。段々畑や居住区、神殿などが計画的に配置され、インカの高度な建築技術がうかがえる。","note":"儀式の場所<br/><br/>発見時経験値1200　発見物カード経験値600","exp":"1200"}],"2839":[{"type":"美術品","name":"毛松の絵画","rank":"1","desc":"サルを描いた画。\n南宋の画家・毛松の作品であるとされ、優れた表現力を発揮した名品といわれている。","note":"動物の絵画の地図","exp":"130"}],"1647":[{"type":"地理","name":"ラパ・ヌイ","rank":"5","desc":"太平洋の東側に存在する、絶海の孤島。沿岸に巨大な像が屹立していることから、ここが「星を見る島」であることは間違いない。ラパ・ヌイとは現地の言葉で「大きい島」という意味。","note":"星を見る島","exp":"949"}],"540":[{"type":"歴史遺物","name":"黄金の棺","rank":"1","desc":"黄金造りの棺。古代の王族や貴族のものと思われる。みごとな装飾から、埋葬者の権力の大きさがわかる。","note":"古代の墳墓の地図","exp":"40"}],"1691":[{"type":"虫類","name":"テイオウゼミ","rank":"2","desc":"体長10cmほど、羽を広げると20cmにもなる最大級のセミ。","note":"大きな羽の虫の地図","exp":"255"}],"260":[{"type":"歴史遺物","name":"アブ・シンベルの巨像","rank":"2","desc":"アブ・シンベル神殿の入り口にそびえる、四体の巨像。すべてラムセス2世の像である。高さは20mあり足元にはファラオの親族が彫られている。","note":"ファラオの巨大な像","exp":"330"}],"5246":[{"type":"史跡","name":"トフェ","rank":"1","desc":"古代カルタゴの遺跡。\nバアル・ハモン神やタニト神の聖域とされており、多数の墓石などが見つかってる。","note":"","exp":"200"}],"3872":[{"type":"地理","name":"モレーン湖","rank":"2","desc":"北米西部の、標高の高い場所にある湖。氷河の雪解け水によって形成されるといわれる。夏季の一時期にのみ満水になり、流れ込んだ砂などが太陽光で屈折すると、水面が美しいターコイズブルーに染まる。","note":"書きかけの地図","exp":"220"}],"5470":[{"type":"鳥類","name":"ズグロハゲコウ","rank":"1","desc":"パンタナル湿原の象徴と呼ばれる鳥。\n全長1.2m、翼を広げると2mにも達する。\n頭部の黒い皮膚がむき出しになっていることから、ズグロハゲコウの呼び名がついたといわれている。","note":"発見時経験値120　発見物カード経験値60","exp":"120"}],"1976":[{"type":"小型生物","name":"コウテイタマリン","rank":"5","desc":"南米北部の熱帯の森林に棲む、小さなサル。立派な髭をたくわえた姿から「皇帝」の名前がついた。樹上で生活し、果物を食べる。","note":"森の小さなおじいさん","exp":"1020"}],"3008":[{"type":"化石","name":"キバのあるトカゲのような石","rank":"2","desc":"ジョギンズで出土したトカゲに似た石。\nトカゲにしては、アゴの部分が細長い気もするが、古代にはこんな生物が生息していたのだろうか？","note":"奇妙な石の地図","exp":"230"}],"3230":[{"type":"歴史遺物","name":"白銀の鎧","rank":"5","desc":"スカンジナビア半島に遺されたヴァイキングメイル。兜と同じく白銀で装飾された、侠気のソルフィンのもの。オリガとスノッリの一族に、口伝のサガと共に代々伝えられていたようだ。","note":"相容れぬものが創る詩","exp":"1100"}],"2725":[{"type":"植物","name":"スモモ","rank":"3","desc":"朝鮮、日本、中国と、東アジアの広範囲に分布する植物。初春に白い花を咲かせ、果実は酸味が強い。\n古くから人々に慕われてきた植物である。","note":"小さな果実<br/><br/>発見時経験値460　発見物カード経験値230","exp":"460"}],"2337":[{"type":"歴史遺物","name":"古代の木簡","rank":"1","desc":"日本で発見された、文字が記された木札。紙を作る技術がなかった時代のもので、中国などでも同様のものが見られる。\nつづられた文字からは当時の人々の生活がうかがい知れる。","note":"古代の書き物の地図","exp":"190"}],"1276":[{"type":"宗教遺物","name":"ガルーダ像","rank":"3","desc":"ヒンドゥー教における神鳥。ヴィシュヌを背に乗せて大空を舞うという。ヒンドゥー教圏ではガルーダを特別に信仰することが多々あるようだ。","note":"ヒンドゥーの神像","exp":"462"}],"1181":[{"type":"地理","name":"サンサルバドル島","rank":"2","desc":"1492年10月12日、イスパニアのコロンがカリブ海で最初に上陸した島である。この名称はコロンが付けたものだが、現地の住民はこの島を「グアナハニ」と呼んでいた。","note":"最初の新大陸","exp":"360"}],"249":[{"type":"地理","name":"メノルカ島","rank":"1","desc":"バレアレス諸島東部の島。西の大きな島はマジョルカ島という。名の由来は、スペイン語のマヨール（大きい）とメノール（小さい）である。気候がよく、静かな島である。","note":"クエスト「バレアレス諸島の地形調査」<br/>発見物カード:10","exp":"20"}],"5986":[{"type":"虫類","name":"ホタル","rank":"1","desc":"腹部が光る小型の昆虫である。森の中で、ほうぼうが点滅している様子は大変美しい。なぜ腹が光るのかは不明だ。","note":"光る虫","exp":"20"}],"5252":[{"type":"宗教遺物","name":"オリンピアのゼウス像","rank":"5","desc":"世界七不思議の一つであり、遠い昔、オリンピアにて祀られていたゼウス像の複製品。右手には勝利の女神ニケの像、左手には錫杖を持つ。本来遺跡に祀られていたものはかなり巨大で全長十数mはあるらしい。","note":"","exp":""}],"5372":[{"type":"地理","name":"サモス島","rank":"2","desc":"エーゲ海東部の島。ギリシャ神話の女神ヘラが生まれた場所ともされ、ヘラを祀る神殿の遺跡がある。また、古代ギリシャを代表する数学者ピタゴラスの故郷でもある。","note":"発見経験値240 カード経験値120","exp":"240"}],"372":[{"type":"地理","name":"ザンベジ川","rank":"1","desc":"アフリカ南東部を流れる川。アフリカでも5本の指に入るだろう。小型船が航行可能な流域が広く、この地方の重要な交通手段だ。内陸には、モシ・オア・トゥニャと呼ばれる壮大な滝があるそうだ。","note":"河口付近の漁場","exp":"120"}],"2590":[{"type":"財宝","name":"百歩蛇のつぼ","rank":"2","desc":"百歩蛇（ヒャッポダ）をかたどった陶器のつぼ。\n台湾島先住民であるルカイ民族やパイワン民族の制度では、貴族の身分の象徴とされ、平民は所有できない。","note":"古代の道具の地図","exp":"290"}],"301":[{"type":"歴史遺物","name":"ハンムラビ法典","rank":"5","desc":"古代バビロンのハンムラビ王が発布した、成文法典。\n「目には目を」とあるが、これは公正な処罰を与えるという意味である。","note":"メソポタミア文明への探求","exp":"949"}],"1557":[{"type":"歴史遺物","name":"古代のブーメラン","rank":"1","desc":"先住民族が用いた狩猟用ブーメラン。木製で滑らかに研いであり、空気抵抗を抑えてよく飛ぶようにしてある。彼らは狩猟・採集民族としてこの大地に生きてきたといわれる。","note":"古代の武器の地図","exp":"160"}],"5209":[{"type":"歴史遺物","name":"百合若大臣","rank":"1","desc":"昔から伝わる百合若という若者の英雄譚。若者は戦の帰りに家来に裏切られ、島に置き去りにされるが苦労の末に帰郷する。古代ギリシャにも似た物語があると聞くが関連はあるのだろうか。","note":"","exp":""}],"6505":[{"type":"地理","name":"モーリシャス島","rank":"5","desc":"マダガスカル島の東に浮かぶモーリシャス諸島で最も大きな島。サンゴ礁と白い砂に囲まれ、海岸近くの海はさまざまな色に見えるという。内陸部でも土の色が七色に輝く場所があるなど、美しい光景が見られる。","note":"","exp":"1800"}],"833":[{"type":"地理","name":"ランズエンド岬","rank":"1","desc":"ブリテン島南西端の岬である。意味は英語で「地の果て」。細長い岬で対岸が見えないため、このように呼ばれるのだろう。","note":"地の果ての岬","exp":"20"}],"1606":[{"type":"宗教遺物","name":"中論","rank":"2","desc":"ちゅうろん。ナーガールジュナの著。仏教の中道について記したもの。一般的な論書というよりは、詩歌的な部分が多く、文芸作品としても素晴らしい価値がある。","note":"古い法典の地図","exp":"255"}],"5112":[{"type":"港・集落","name":"バスラ","rank":"1","desc":"ペルシャ湾奥に位置する街。7世紀に建設され、8世紀には交易と文化の中心地であったという。しかし、アッバース朝が衰退するにつれて重要性を失っていった。それでも、ペルシャ絨毯をはじめ重要な産物が流通している。","note":"到達する","exp":"128"}],"1163":[{"type":"宗教遺物","name":"蛇の彫像","rank":"2","desc":"マヤによく見られる蛇の像。ガラガラヘビと思われる。ガラガラヘビは脱皮ごとに節が増えるため、時を重視したマヤ人たちに尊ばれたという。","note":"蛇をかたどった神像","exp":"330"}],"113":[{"type":"地理","name":"キューバ島","rank":"2","desc":"カリブ海でもっとも大きいと思われる島。最近になって開拓が進められ、タバコなどのカリブ特有の作物が栽培されている。","note":"カリブ最大の島","exp":"360"}],"3630":[{"type":"レリック","name":"イタリアの剣","rank":"","desc":"ハンニバルを追い、果敢に戦いを仕掛け続けた猛将マルケルス。その勇猛さはハンニバル軍に引けを取らなかったという。","note":"","exp":""}],"5872":[{"type":"鳥類","name":"ナナイロフウキンチョウ","rank":"5","desc":"南米に生息する鳥。頭や腹、背中が鮮やかに色づき、その配色の美しさで知られる。大きさは十数cmほどで、肉食。他のフウキンチョウ類も雄は美しい配色のものが多い。","note":"","exp":"1430"}],"5104":[{"type":"港・集落","name":"ナタール","rank":"1","desc":"インド洋に面した、アフリカ南部沿岸に位置する港町。ナタールとはポルトガル語でクリスマスという意味である。","note":"到達する","exp":"75"}],"5892":[{"type":"美術品","name":"ベレスタ","rank":"1","desc":"ロシアで作られる小物入れ。白樺の皮を利用して作られている。繊細な装飾は芸術品としても評価が高い。","note":"","exp":""}],"5616":[{"type":"小型生物","name":"ナキウサギ","rank":"2","desc":"北米やアジアなどの寒冷な地方に生息するウサギの一種。体長は18cm程度で、四肢は短く、耳が丸い。","note":"","exp":"230"}],"2048":[{"type":"歴史遺物","name":"メルエンプタハ碑文","rank":"2","desc":"古代エジプトのファラオ、メルエンプタハ王の時代に残されたと思われる碑文。\n損傷が激しく読み辛いが、「シェケン運河」や「エティ運河」と読める部分がある。","note":"［勅命］[[運河開通への記録","exp":"310"}],"469":[{"type":"中型生物","name":"アナグマ","rank":"1","desc":"クマのような、タヌキのような、ずんぐりした動物。穴を掘って群れで生活し、その巣穴はあまりに広くて調査できないほどである。","note":"穴を掘る動物の地図","exp":"13"}],"2887":[{"type":"鳥類","name":"キンケイ","rank":"2","desc":"中国南西部の山地に生息する鳥。赤と、光沢のある金色を基調とした、派手な姿をしている。\nとても用心深く、身を隠すのが上手で、めったに見かけることがない。","note":"鮮やかな色の鳥の地図","exp":"330"}],"5334":[{"type":"天文","name":"はと座","rank":"3","desc":"16世紀末に作られた星座で、聖書のノアの方舟に登場するハトに由来する。ノアは方舟からハトを放ち、大洪水の水が引いていくことを知ったといわれる。","note":"クエスト「聖書に由来する星座」<br/>発見物カード:240","exp":"480"}],"5033":[{"type":"港・集落","name":"カカドゥ","rank":"2","desc":"オーストラリアの北岸に位置する街。ガグジュと呼ばれる民族名が名前の由来である。周囲には湿地が広がり、数多くの動植物が生息している。また、カカドゥ周辺には壁画が多く見られ、古くから人が住んでいたことが予想される。","note":"到達する","exp":"355"}],"2513":[{"type":"植物","name":"バンレイシ","rank":"3","desc":"ネーデルラント人によって台湾島に持ち込まれた植物。\n果実の表面が仏像の頭部に似ていることから釈迦頭とも呼ばれる。","note":"風変わりな果物","exp":"490"}],"6191":[{"type":"史跡","name":"ムティジュルの泉","rank":"5","desc":"ウルルのふもとにある池で、岩山から伝ってくる雨水によって、決して涸れることがないという。クニヤという名のニシキヘビの祖先が虹色の蛇に姿を変えて、今もなお池に棲むという伝承が現地人たちの間に残っている。","note":"","exp":"1110"}],"6574":[{"type":"小型生物","name":"冬毛のクロテン","rank":"5","desc":"イタチ科の小型生物。ユーラシア大陸に広く分布するが、毛皮目的で乱獲されたため、近年はその数を減らしている。冬毛が美しく、中でも日本の北の地域にのみ生息するエゾクロテンの冬毛姿は特に麗しく愛らしい。","note":"追究クエスト<br/>発見物カード:750","exp":"1500"}],"568":[{"type":"歴史遺物","name":"ハドリアヌス帝の大理石像","rank":"1","desc":"ハドリアヌス帝は、古代ローマ五賢帝の三人目である。防衛策に徹して制度を整え、ローマを発展させた。","note":"五賢帝の大理石像","exp":"70"}],"1613":[{"type":"美術品","name":"放蕩息子の酒宴","rank":"1","desc":"レンブラント作の人物画。聖書の一節、富豪の息子が娼婦と豪遊する場面を描いたといわれる。レンブラントらしからぬ明暗のはっきりしないタッチは、題材の向こうに現実的ななにかを見ているからかもしれない。","note":"人物画の地図","exp":"180"}],"317":[{"type":"歴史遺物","name":"ラダメスとアイーダの墓石","rank":"2","desc":"古代エジプトの将軍ラダメスと女官アイーダの死をいたんで建てられたと思われる石碑。二人は共に神殿の礎として生き埋めとなったが、その最後の言葉がこの石碑に刻まれていた。","note":"ラダメスとアイーダの墓石","exp":"270"}],"5664":[{"type":"気象・現象","name":"オーロラ爆発","rank":"4","desc":"オーロラが放射状に広がりながら、数分間、色や形状を変化させ続ける現象。オーロラと同様に、その発生原因などは不明である。","note":"","exp":"700"}],"527":[{"type":"歴史遺物","name":"ガラスの装身具","rank":"1","desc":"装飾用の加工を施したガラス。さまざまな文明で見られ、色や形に特徴がある。ガラスは古代から用いられてきた素材の一つ。","note":"古代の装身具の地図","exp":"34"}],"2569":[{"type":"鳥類","name":"ゴシキドリ","rank":"5","desc":"中国南部から東南アジアにかけて生息する、体が五色で彩られている鳥。樹幹にくちばしで丸く出入り口を掘り巣を作る。夜はその巣で眠る。","note":"遠き地への調査依頼<br/><br/>文化貢献度50","exp":"930"}],"6904":[{"type":"財宝","name":"虎模様の金メダル","rank":"4","desc":"虎の模様があしらわれた黄金のメダル。虎が下肢を反らした曲線的な姿は、ギリシャやペルシャなどの文化の影響とみられ、東西交易が盛んであった証拠ともいえる。","note":"","exp":""}],"893":[{"type":"財宝","name":"アゾート","rank":"4","desc":"錬金術の書物に記述されていた、謎の多い物質。ギザのピラミッドの玄室で発見された。来歴も用法も不明だが錬金術における極めて重要な物質であるらしい。","note":"謎の文書","exp":"720"}],"238":[{"type":"海洋生物","name":"セミクジラ","rank":"1","desc":"暖かな海で見られる、動作の緩やかなクジラである。体には多数のフジツボなどが付着する。死んだあと沈まないのだが、なぜかは不明である。","note":"のんびりしたクジラ","exp":"70"}],"2543":[{"type":"鳥類","name":"カンムリチメドリ","rank":"2","desc":"台湾島に生息する、全長約15cmの小さな鳥。濃い茶色の冠のような頭と、つぶらな眼が特徴である。\n人懐こく人間のすぐ近くにまで寄ってくる。","note":"子煩悩の父","exp":"310"}],"5452":[{"type":"鳥類","name":"チョピ","rank":"3","desc":"黒い姿をした、小型の鳥。集団で生活をすることが多い。透き通った美しい声でさえずって、多くの人を魅了する。だが、なんのためにさえずるのかは定かではないようだ。","note":"","exp":"470"}],"1545":[{"type":"地理","name":"グレートオーストラリア湾","rank":"2","desc":"オーストラリアの南に広がる湾｡1000kmにも及ぶ長い海岸線と広い遠浅の海が続く。湾の沿岸部には海に突き出た断崖が数百kmに渡って続いている場所がある。この断崖は南から吹き付ける強風によって形作られたようだ。","note":"地の果ての断崖","exp":"330"}],"6568":[{"type":"宗教遺物","name":"ガンガーの像","rank":"5","desc":"ガンジス川を神格化したものとされる、女神ガンガーの像。ヒマラヤ山脈を神格化したヒマヴァット神の娘といわれ、人々に恵みを与える聖なる川のような存在として信仰されている。","note":"追究クエスト","exp":"1150"}],"6769":[{"type":"植物","name":"リトープス","rank":"2","desc":"ハマミズナ科リトープス属の多肉植物。原生地は南アフリカ。乾燥地を好み、非常に成長が遅い。岩陰など日の当たらない場所に群生する。独特な形をしており、中央の割れ目から開花するという珍しい特徴がある。","note":"発見物カード:105","exp":"210"}],"5754":[{"type":"地理","name":"ジェームズ湾","rank":"5","desc":"北米大陸北部の、ハドソン湾南部に位置する湾。冬から春は流氷に閉ざされるものの、発達した干潟には多くの渡り鳥が飛来する。","note":"2017.02.07新規追加","exp":"1340"}],"3623":[{"type":"歴史遺物","name":"イーゴリ遠征物語","rank":"3","desc":"イーゴリ公による遠征記録を綴った叙事詩。キエフ大公国時代に書かれたとされる。イーゴリ公は遊牧民撃退のため遠征を行った。","note":"遠征叙事詩","exp":"460"}],"5343":[{"type":"天文","name":"かじき座","rank":"2","desc":"大マゼラン雲近くにある星座。16世紀の末にネーデルラントの航海者ペーテル・ケイセルとフレデリク・デ・ハウトマンが考案した。","note":"「天文学者の観測記録」<br/>発見物カード:160","exp":"320"}],"2062":[{"type":"地理","name":"グレートビター湖","rank":"2","desc":"カイロとスエズの狭間にある、比較的大きな湖。この他にも、小中の湖が存在しているらしい。これらの湖は、スエズ運河の一部となるだろう。","note":"［勅命］[[運河開通場所の地形調査","exp":"310"}],"1202":[{"type":"地理","name":"マラジョ島","rank":"3","desc":"アマゾン川の河口にある島。大きさはジャマイカ島よりも大きいと思われるほど巨大。この島には、古くから人が住んでいた形跡がある。","note":"河口にある島","exp":"473"}],"252":[{"type":"財宝","name":"バンシーの涙","rank":"2","desc":"ケルトの言い伝えに残る、死を告げる妖精バンシーの名を冠した宝石。魔槍ゲイボルグにはめこまれていたが、不吉を恐れて宝石だけ外され、地中深く埋められていた。","note":"バンシーの涙","exp":"310"}],"753":[{"type":"海洋生物","name":"アオウミガメ","rank":"1","desc":"温暖な海に住む、青いウミガメ。水から上げると意外に茶色い体をしている。甲羅の直径が1m以上にもなる。","note":"青い海の青いカメ","exp":"140"}],"1628":[{"type":"美術品","name":"ろうそくに火を灯す少年","rank":"4","desc":"エル・グレコ作。ろうそくに火を灯す少年の静謐な表情と、火の一瞬のゆらめきをとらえた名画である。エル・グレコがイスパニアに渡る前に描かれたもので、彼の特徴である人物を引き伸ばして描く画法は用いられていない。","note":"間延びしていない絵","exp":"720"}],"6932":[{"type":"海洋生物","name":"タテジマキンチャクダイ","rank":"5","desc":"インド洋や太平洋などの暖流域に生息する美しい魚。幼魚から成魚にかけて大きく色や模様が変化する。成魚は深い青色の体に鮮やかな黄色の縞を持つ。縄張り意識が強く、同種とも争う。","note":"発見物カード:425","exp":"850"}],"5997":[{"type":"小型生物","name":"マダラサラマンドラ","rank":"1","desc":"黒い体にオレンジの模様があるイモリ。炎がちらついている模様に見えないこともない。ヨーロッパでも似たイモリを見かけるが、まだらが黄色い。","note":"サラマンダーを捕まえろ<br/>希少発見物らしいです。<br/>体験版では、「サラマンダーを捕まえろ」<br/>の紹介を受けれませんでした。","exp":"80"}],"3270":[{"type":"財宝","name":"砂漠のバラ","rank":"4","desc":"砂漠でまれに見られるバラの形に似た、石の塊のようなもの。おそらく砂が固まったものだと思われるが、中には半透明のものもありまるで水晶のようにも見える。","note":"砂の花","exp":"610"}],"2060":[{"type":"地理","name":"ネムルト山","rank":"2","desc":"トルコ東部にそびえる標高2000mほどの山。\n頂上部には神像の彫刻が並んでいるらしい。","note":"謎に包まれた山","exp":"300"}],"3658":[{"type":"歴史遺物","name":"埋もれたガラス器","rank":"2","desc":"ローマのカタコンベに埋もれていたガラスの器。紀元前1世紀に近東で吹きガラスの技術が生まれ、ローマ帝国時代には広く作られるようになった。この器は初期のキリスト教徒が使っていたものと思われる。","note":"ダンジョン","exp":"400"}],"1240":[{"type":"鳥類","name":"レンカク","rank":"2","desc":"長い脚と、きわめて大きな足が特徴。足指も長く、水面に浮いた葉の上を歩ける。湿原や草地に生息し、昆虫を餌としている。","note":"水の上に立つ鳥","exp":"370"}],"6973":[{"type":"美術品","name":"聖ルチアの埋葬","rank":"2","desc":"カラバッジオ作の油彩画。信仰を貫いて殉教した聖ルチアの埋葬の場面が描かれている。彼女の殉教地とされるシラクサの教会のために制作された。写実的な筆致が、深い悲壮感を伝えている。","note":"発見物カード:120","exp":"240"}],"2566":[{"type":"地理","name":"阿里山","rank":"5","desc":"台湾島の中南部にある山々の総称。\n珍しい動物や、熱帯地域などで自生する植物などが多く生息している。","note":"生物学者の望む地","exp":"1150"}],"5530":[{"type":"気象・現象","name":"バンファイパヤーナク","rank":"3","desc":"川に火の玉が出現する現象。マレー半島の特定の地域でのみ観測される。火の玉は水面から上空数百メートルまで上昇し、その後消える。多い日では、1時間に数千個現れるという。","note":"","exp":"270"}],"700":[{"type":"財宝","name":"白銀の燭台","rank":"1","desc":"銀は金属の中でも特に白く輝くものだが、この燭台はひときわ白く輝いている。銀に混ぜる金属の種類と割合に秘密があるというが、解明することはできないだろう…。","note":"神秘的な燭台","exp":"100"}],"765":[{"type":"植物","name":"チューリップ","rank":"1","desc":"つぼのような花が咲く植物。赤や黄色などさまざまな色がある。球根で増える。最近人気が出てきており、品種改良も行われている。","note":"赤い花の地図","exp":"49"}],"2804":[{"type":"植物","name":"シャガ","rank":"1","desc":"中国や日本に生息する春に群青色の花を咲かせる植物。\n暗い場所でも生育するが、花は一日しか持たず、開花した翌日には萎んでしまう。","note":"命短き花","exp":"200"}],"6947":[{"type":"天文","name":"シェラタン","rank":"3","desc":"おひつじ座のベータ星で、3等星。名はアラビア語で「2つ」を意味すると言われているが、その2つが何を指しているかは分かっていない。","note":"発見物カード:245<br/>中央大西洋 視認","exp":"490"}],"1501":[{"type":"化石","name":"巨大なワニのような骨","rank":"1","desc":"アマゾンの陸地で発見された、体長10mを超えるワニに似た巨大な生物の骨。広大な森林地帯であるこの地は、かつては水に覆われていたのかもしれない。","note":"ワニのような骨の地図","exp":"140"}],"1761":[{"type":"海洋生物","name":"ウミユリ","rank":"4","desc":"海中の生物。深い海の底に根を張り、ゆらゆらと揺れる。\n姿は、海草などの海中の植物よりも、陸上の植物に近い。しかし、海中を移動することもあるため、動物である可能性が高い。","note":"時を止めた花","exp":"720"}],"353":[{"type":"化石","name":"ヒレのあるドラゴンの骨","rank":"1","desc":"頭から体にかけては巨大なトカゲのようで、手足がウミガメのようなヒレになっている動物の骨。体長は2mほどで、石のように変化している。ヒレがあるのだから、海か湖にいたのだろう。なぜ陸で見つかったのだろうか。","note":"泳げるドラゴン","exp":"170"}],"1547":[{"type":"地理","name":"カーペンタリア湾","rank":"2","desc":"アーネムランドとヨーク岬半島に挟まれた、オーストラリア北東部の湾。面積は広大であるものの、全体的に水深は浅い。沿岸部はマングローブに覆われており、湾に注ぎ込む河川にはワニが生息している。港の建造は困難だろう…。","note":"えぐれた大地","exp":"275"}],"2704":[{"type":"地理","name":"竜頭岩","rank":"3","desc":"済州島の海岸にある、竜の頭のような形をした岩。\n白鹿潭に棲んでいた竜が海に出ようとしたところ、天帝の怒りに触れ、石にされたという伝説がある。","note":"洋上怪物騒動","exp":"510"}],"75":[{"type":"歴史遺物","name":"ロロの兜","rank":"1","desc":"ヴァイキングの首領・ロロが使っていたといわれる兜。彼は北フランス沿岸をしばしば襲撃した。西フランク王はこれを抑えるため、ロロをノルマンディー公に任じた。","note":"クエスト「ヴァイキングの国」<br/>発見物カード75","exp":"150"}],"3923":[{"type":"天文","name":"アンドロメダ座の渦巻星雲","rank":"2","desc":"アンドロメダ座にある渦巻きのような形をした星雲。アンドロメダの腰の右側に当たる位置にあり、肉眼でも見られる。","note":"「天文学者の観測記録」<br/>発見物カード:110","exp":"220"}],"5506":[{"type":"港・集落","name":"ヴィアナドカステロ","rank":"1","desc":"イベリア半島西部に位置する街。外洋を目指す船の母港として重要な拠点である。","note":"座標　15770,3052","exp":"16"}],"3831":[{"type":"財宝","name":"占事略决","rank":"5","desc":"読みは「せんじりゃっけつ」。陰陽師・安倍晴明がまとめた書物の写本。式占の一種である六壬神課に関し、基本的な説明や占いの方法が記されている。","note":"東洋占術の解説書","exp":"1230"}],"5142":[{"type":"港・集落","name":"ペルナンブコ","rank":"2","desc":"南米大陸の東部沿岸に位置する港町。大西洋交易の拠点として発展してきた。","note":"到達する","exp":"246"}],"1467":[{"type":"宗教建築","name":"パガン遺跡","rank":"4","desc":"パガン王朝時代に建設されたという寺院群。広大な敷地に無数の寺院や仏塔が建てられている。その数は400万ともいわれているが、元によって破壊され現在は3000弱しか残っていない。","note":"クエスト「塔の並ぶ大地」<br/>発見物カード:320","exp":"648"}],"2389":[{"type":"地理","name":"石見銀山","rank":"4","desc":"読みは「いわみぎんざん」。日本の中国地方に位置する山。\n膨大な銀を産出しており、多方面から注目されている。\n佐摩銀山という別名から、ここの銀はソーマ銀とも呼ばれることがある。","note":"東方の鉱脈<br/><br/>発見時経験値740　発見物カード経験値370","exp":"740"}],"5407":[{"type":"財宝","name":"蛇型記章","rank":"2","desc":"古代エジプトのファラオの頭を飾るコブラの記章。金のコブラに宝石の象嵌が施されている。","note":"","exp":"320"}],"2051":[{"type":"財宝","name":"ルバイヤート","rank":"2","desc":"オマル・ハイヤームの著した四行詩集。\nペルシャ語で四行詩を意味する。美酒と酒姫に対する賛歌を歌い続け、刹那的快楽主義を主張している。","note":"奇妙な詩集","exp":"350"}],"6601":[{"type":"植物","name":"プロソピス・キネラリア","rank":"3","desc":"中東の乾燥地域に自生する、エンドウマメ科の植物。「ガフの木」とも呼ばれる。生命力が非常に高く、砂漠のような干ばつ地でも育つ。樹齢数百年にも及ぶ個体もあるという。","note":"","exp":"500"}],"6117":[{"type":"歴史遺物","name":"ノイマーゲンのワイン船","rank":"4","desc":"ノイマーゲンのワイン商の墓から出土した副葬品。ノイマーゲンはローマ帝国期よりワイン生産の盛んなモーゼル川流域の街。獣頭のガレー船にワイン樽が満載され、二人の収税人と多くの漕ぎ手が乗っている。当初は二隻構成だったようだ。","note":"クエスト「植民都市のワイン商」<br/>発見物カード:370","exp":"740"}],"1484":[{"type":"植物","name":"カトレア","rank":"1","desc":"濃く色づいた筒状の花びらを中央に、そこから放射状に形の異なる花びらが出ている。華やかでとても美しい。","note":"紫の花の地図","exp":"105"}],"616":[{"type":"財宝","name":"王妃の首飾り","rank":"1","desc":"とある王妃の持ち物であったと伝えられる首飾り。巨大なルビーと大粒のサファイヤ、そして多数のダイヤモンドがちりばめられており、王家の権力を象徴している。","note":"思い出の首飾り","exp":"110"}],"1166":[{"type":"歴史遺物","name":"ケルト","rank":"2","desc":"ケルトとは儀式用の斧のことである。細かい彫刻がされていることが多い。これを使って神々に踊りを捧げたり祖先に祈ったりした。","note":"石の遺物","exp":"340"}],"6320":[{"type":"中型生物","name":"インドオオコウモリ","rank":"2","desc":"果汁を主食とする大型のコウモリ。飛ぶ時は視覚に頼るため目が大きい。横から見た顔がキツネに似ていることから「空飛ぶキツネ」とも呼ばれる。","note":"","exp":"370"}],"2082":[{"type":"鳥類","name":"ケツァール","rank":"5","desc":"中南米山岳地帯の森林に生息する鳥。全長は約35cm。オスは飾り羽を持っており、それを含めると全長90cmにも達する。アステカの神の使いであり、鮮やかな濃緑色の羽が日に照らされた姿は、まさに虹色の神鳥である。","note":"クエスト「虹色の神鳥」<br/>発見物カード:555","exp":"1110"}],"1503":[{"type":"植物","name":"ダリア","rank":"1","desc":"幾重にもなった花びらの中心に、黄色い管状の花が付いている。大きなもので20cm以上にもなる。","note":"大きな赤い花の地図","exp":"70"}],"6905":[{"type":"大型生物","name":"クロコダイル","rank":"4","desc":"細長い口先が特徴的なワニ。体長は2.5mほどで、地上をすばやく動くことができる。","note":"南東の大陸にすむワニ","exp":"624"}],"6478":[{"type":"歴史遺物","name":"巨像の親指","rank":"5","desc":"ロードス島にあった巨像の親指。青銅で作られている。大プリニウスの「博物誌」によると「倒壊した像の親指を腕で抱えられる者はほとんどおらず、指はあらゆる彫像よりも大きい」とされている。","note":"","exp":""}],"186":[{"type":"歴史遺物","name":"女王ゼノビアの小剣","rank":"3","desc":"ゼノビアは、ローマ帝国に反旗を翻したパルミラの女王である。一時は巨大な領土を支配したが、アウレリアヌス帝に敗れて捕らわれローマに連れていかれた。","note":"ゼノビアの小剣","exp":"451"}],"4793":[{"type":"植物","name":"セコイア","rank":"2","desc":"北米西岸に生えている杉の仲間。非常に背が高くなり、中には100m近くに達するものもあるという。分厚い樹皮に囲まれており、山火事にも強いようだ。","note":"巨木の地図","exp":"220"}],"1334":[{"type":"地理","name":"ベラウ湾","rank":"2","desc":"ニューギニア島の西端に突き出た、鳥のくちばし状の地形に挟まれた湾。西には無数の島々を望める。","note":"書きかけの地図","exp":"210"}],"5638":[{"type":"天文","name":"水がめの流星群","rank":"2","desc":"みずがめ座の水がめの部分の方角から飛び出すように現れる流星群。ハレー彗星が母体と推定される。","note":"「天文学者の観測記録」<br/>発見物カード:140","exp":"280"}],"2949":[{"type":"地理","name":"マウント・デザート島","rank":"2","desc":"入り江を挟み、左右に分かれている島。全土で、カコウ岩でできた岩肌が見られる。人があまり踏み入っていないからか、多くの動植物が生息している。","note":"北大陸の風景","exp":"250"}],"6382":[{"type":"小型生物","name":"モルモット","rank":"3","desc":"南米などに生息するネズミ。性格はおとなしく、警戒心が強い。ストレスがあると食事を取らなくなることもある。群れで行動し、鳴き声でお互いの意思疎通を行う。モルモット独特の跳躍がある。","note":"","exp":"600"}],"562":[{"type":"地理","name":"サントリニ島","rank":"1","desc":"クレタ島のカンディアから北北東にある小さな島である。中央に火山があり、はるか昔に大噴火を起こしたと伝えられている。伝説の古代文明・アトランティスがあったという説もある。","note":"古代文明の伝説","exp":"20"}],"6906":[{"type":"化石","name":"巨大な角を持つシカの化石","rank":"5","desc":"巨大な角を持つ大きなシカの化石。角の長さは約3m、重さは約40kgにもなる。体高も人の背丈をゆうに超えていたようだ。何千年以上もの遠い昔から、この地に眠っていたのだろうか。","note":"","exp":""}],"1267":[{"type":"化石","name":"背中にとげのあるドラゴンの骨","rank":"5","desc":"背中に、二股に分かれたとげのような骨がある。そのまま突き出ていたのか、船の帆のように皮が張られていたのか。謎は尽きない。","note":"新大陸のドラゴン<br/><br/>発見時経験値1027　発見物カード経験値513","exp":"1027"}],"1693":[{"type":"美術品","name":"瀕死のガリア人","rank":"5","desc":"ペルガモン王国の王、アッタロス1世が作らせたといわれている青銅像の模造。模造でありながら非常によい出来である。ペルガモン王国に度々侵攻したガラティア人が死に直面したときの複雑な表情を見事に表している。","note":"ペルガモンの忘れ形見","exp":"910"}],"381":[{"type":"海洋生物","name":"オニイトマキエイ","rank":"4","desc":"マンタとも呼ばれる、非常に大きなエイ。幅が5m以上にもなり、海中で優雅に羽ばたく姿は一度は見ておくべきだろう。一見すると恐ろしい姿をしているが攻撃性などはまったくなく、近づいてもゆったりと泳いでいる。","note":"海中の悪魔","exp":"624"}],"6181":[{"type":"宗教遺物","name":"聖地への旅","rank":"2","desc":"4世紀ローマ帝国のヒスパニア属州であったイベリア半島南部出身の女性、エゲリアが書き残した聖地巡礼の記録。\nイベリア半島からイェルサレム、シナイ半島などへ巡礼に出向いた時の出来事を記している。","note":"","exp":"270"}],"1594":[{"type":"地理","name":"アンデス山脈","rank":"4","desc":"南米大陸西岸の山脈。南米大陸北端から南端まで貫き、6000ｍ級の高峰が連なる。北部赤道付近は冷涼で過ごしやすく、わずかながら農耕も行われている。","note":"新大陸西岸の巨大山脈","exp":"624"}],"955":[{"type":"美術品","name":"聖アンナと聖母子","rank":"2","desc":"レオナルド・ダ・ヴィンチ作の絵。聖アンナの膝にマリアが座り、幼いイエスを抱こうとしている。アンナはマリアの母であるが、ここではマリアと同じくらいの年齢で描かれている。この絵は未完成だそうだ。","note":"変わった構図の聖母子画","exp":"280"}],"3599":[{"type":"歴史遺物","name":"ウラジーミル1世の金貨","rank":"4","desc":"キエフ大公国を治めたウラジーミル1世の肖像と紋章が彫られた金貨。ウラジーミル1世は、東ローマ帝国皇帝バシレイオス2世の妹と結婚し、キエフ大公国の権威を大きく高めるなど、政治的手腕に優れていた。","note":"キエフ大公国の全盛期","exp":"640"}],"2357":[{"type":"宗教遺物","name":"山伏の修験道具","rank":"2","desc":"読みは、「やまぶしのしゅげんどうぐ」。修験道の行者が修行に用いる道具一式。\n修験道とは、山岳信仰に仏教や神道などが結び付いた日本の宗教である。行者はこれらを身に着け、山にこもって苦行を積む。","note":"山に寄せる信仰","exp":"300"}],"6762":[{"type":"海洋生物","name":"アコヤガイ","rank":"2","desc":"岩礁帯に広く生息している。体内に入った砂利などの異物を分泌物で固め、真珠を作る性質を持つ。アコヤガイの真珠は貝類の中でも特に光沢が美しいという。古代よりペルシャ湾周辺には真珠にまつわる物語が多く残されている。","note":"発見物カード経験値：190","exp":"380"}],"5502":[{"type":"歴史遺物","name":"プネウマティカ","rank":"5","desc":"アレクサンドリアのヘロンが記した文献。古代エジプトの神殿に設置された、聖水の自動販売機の仕組みを記している。","note":"蒸気機関研究の始まり <br/><br/>発見時経験値1000　発見物カード経験値500","exp":"1000"}],"1648":[{"type":"地理","name":"ソロモン海","rank":"2","desc":"ニューギニア島の東に広がる海。周囲を諸島に囲まれており、その諸島に暮らす人々は古くから交流をもっているという。雨季には突然の暴風雨に見舞われることもあるが、それ以外はサンゴ礁の発達した穏やかな海といえる。","note":"ニューギニア島東の海域調査","exp":"320"}],"4855":[{"type":"天文","name":"アケルナル","rank":"1","desc":"エリダスヌス座の中で最も明るい星。エリダヌス座の南端に位置している。南半球では目立つ星だが、北半球で観測できる場所は限られている。","note":"「明るい星の観測記録」<br/><br/>発見物カード:90","exp":"180"}],"1791":[{"type":"大型生物","name":"メガネグマ","rank":"3","desc":"南米に生息するクマ。顔に、メガネのような白い模様がある。人の背丈ほどの大きさで、標高2000m前後の高地の森に棲む。木登りが得意で夜行性。","note":"メガネをかけるクマ","exp":"540"}],"1914":[{"type":"歴史遺物","name":"コハウ・ロンゴロンゴ","rank":"3","desc":"ラパ・ヌイ独自の文字であるロンゴロンゴ文字を書きつけた板。名は「物言う木」という意味である。ラパ・ヌイ島民でも特殊な職業の者でないと読むことができず、解読できる者も年々減っているそうだ。","note":"古代文字の地図","exp":"506"}],"5371":[{"type":"海洋生物","name":"ボドワード","rank":"4","desc":"南米の河川や湖に生息するナマズの仲間．\n成長するにつれて，皮膚が黒く，鎧のように硬くなる．","note":"釣り発見：R17で確認．R15でも確認<br/>パラグアイ川上流．<br/>MAP左にある四角い橋が4か所かかっている所の左下(左上も)．<br/>□の中央に向かって釣り使用<br/><br/>発見時経験値660　発見物カード経験値330","exp":"660"}],"42":[{"type":"歴史遺物","name":"トゥグリル・ベグの王冠","rank":"3","desc":"トゥグリル・ベグは、セルジューク朝トルコの始祖。最初のスルタンとなった。これはアッバース朝のカリフからスルタン位を受けた際の宝冠と言われる。","note":"クエ：イスラムの王制","exp":"473"}],"5023":[{"type":"港・集落","name":"アンボイナ","rank":"2","desc":"モルッカ諸島南方に位置する小島にあり、クローブなどの香辛料を産する街。香辛料を求め、ヨーロッパからの進出が相次いだ。","note":"到達する","exp":"350"}],"6107":[{"type":"天文","name":"アンティノウス座","rank":"4","desc":"ローマ皇帝ハドリアヌスが側近アンティノウスの死を悼んで、わし座の南側の星を使って制定した星座。「アルマゲスト」に記述がある。わし座と隣接していたため、ギリシャ神話に登場するガニュメデスと混同されることが多かったという。","note":"クエスト「最後の「神」」<br/>発見物カード:390","exp":"780"}],"5862":[{"type":"天文","name":"うさぎ座","rank":"5","desc":"オリオン座の南にある星座で、トレミー48星座の一つ。元となった神話では、人間の身勝手さが語られており、その戒めとしてウサギを星座としたとされている。","note":"クエスト「小さく可愛い星座」<br/>発見物カード:665","exp":"1330"}],"6643":[{"type":"天文","name":"がか座","rank":"2","desc":"南天の星座。主に南半球で観測できる。はと座とちょうこくぐ座の南側に位置する。ちょうこくしつ座に置いてある画架（イーゼル）の形を表した星座で、フランスの天文学者・ラカーユが設定した。","note":"「天文学者の観測記録」<br/>発見物カード:190","exp":"380"}],"485":[{"type":"歴史遺物","name":"インダス式角型印章","rank":"1","desc":"インダス文明で使われていた角型の印章。幾何学模様や動物などの図柄と共に、インダス文字が記されている。","note":"古代インドの印章の地図","exp":"120"}],"5693":[{"type":"地理","name":"北極ツンドラ地帯","rank":"4","desc":"一年中溶けることのない永久凍土が広がる地域。トナカイなどの生物が生息し、短い夏には表面付近の土壌にコケや灌木などが育つ場合もあるため、不毛の土地というわけではない。","note":"2017.02.07新規追加","exp":"740"}],"1828":[{"type":"歴史遺物","name":"チャスキの肩掛け袋","rank":"2","desc":"チャスキとは、情報を遠方へ配送する役目を負った者である。情報はインカ独特の「キープ」と呼ばれる縄と、口頭で運ばれた。チャスキは一日に200kmも走ったといわれる。恐ろしい健脚だ。","note":"凶兆の伝達者","exp":"220"}],"3744":[{"type":"天文","name":"北極星","rank":"1","desc":"こぐま座で最も明るい星で、天の北極にある2等星。ポラリスとも呼ばれる。周囲に明るい星がなく見つけやすい。ほとんど動かないように見えるため、北半球では夜間に方位を知るうえで重要な星である。","note":"クエスト「星空の導き手」<br/>発見物カード:60","exp":"120"}],"758":[{"type":"財宝","name":"ブロンズの男性像","rank":"1","desc":"青銅の男性像。古代ギリシャ風の、威厳のある像だ。当時のものではなく、最近の作だと思われる。","note":"青銅の男性像の地図","exp":"57"}],"4796":[{"type":"地理","name":"キラウエア火山","rank":"1","desc":"ハワイ島東南部の活火山。活発で溶岩が頻繁に出ているため、現地の言葉の中では、山名が「散発」している。","note":"書きかけの地図","exp":"80"}],"6037":[{"type":"美術品","name":"初花肩衝","rank":"5","desc":"天下三大名物とされる茶入。歴代の天下人が持っていたとされ、その価値は計り知れない","note":"","exp":"1340"}],"1184":[{"type":"宗教遺物","name":"エティエンヌの杖","rank":"2","desc":"少年十字軍を率いた、羊飼いの少年・エティエンヌが持っていたという杖。歴史の犠牲になった、少年少女の無念がこもっているようだ…。","note":"クエスト「悲劇の十字軍」<br/>発見物カード:135","exp":"270"}],"6147":[{"type":"植物","name":"サギソウ","rank":"4","desc":"日本など極東アジアに生息する植物で、谷などの低めの湿地に群生しやすい。\n花の開いた様子がシラサギが翼を広げたように見えるため、この名で呼ばれる。","note":"","exp":"680"}],"1911":[{"type":"小型生物","name":"チンチラ","rank":"2","desc":"リスをひと回り大きくしたような生物。高地の寒冷地域に生息しているためか、柔らかで密度の高い体毛をしている。夜行性で、山の岩場に棲む。","note":"まんまるでふわふわ","exp":"300"}],"6637":[{"type":"気象・現象","name":"赤潮","rank":"","desc":"海水が赤く変色する現象。水温変化や富栄養化など発生原因は諸説ある。ヨハネ黙示録に第二の天使のラッパによって海が血の色に染まり、海の生き物の三分の一が死ぬという記述があり、古くから恐れられていた。","note":"","exp":"350"}],"217":[{"type":"小型生物","name":"ハリネズミ","rank":"1","desc":"背面にトゲが生えている小さな生物。目が小さく鼻がとがり、愛嬌のある顔をしている。捕まえようとすると、丸まってトゲだらけになる。動作は遅い。","note":"トゲだらけのネズミ","exp":"130"}],"6271":[{"type":"地理","name":"ソロモン諸島","rank":"2","desc":"16世紀のスペイン人探検家、アルバロ・デ・メンダーニャ・デ・ネイラが発見した群島のひとつ。\n島の名前は、海岸で砂金を見つけたことでソロモン王の財宝の島とメンダーニャが仮定したことに由来する。","note":"","exp":"220"}],"1564":[{"type":"歴史遺物","name":"化粧された土器","rank":"1","desc":"色とりどりの顔料で彩色された土器。非常に高度な技術を有していたと思われる。","note":"メソアメリカの土器の地図","exp":"180"}],"6002":[{"type":"気象・現象","name":"ブルーファイア","rank":"4","desc":"インドネシアのジャワ島で見られる、青い炎が噴きあがる現象。岩の間から噴き出す硫黄ガスが燃焼する際に青く光ったものと考えらている。また、ガスが液体化して燃焼しながら流れることもあるという。","note":"","exp":"690"}],"1656":[{"type":"地理","name":"スールー海","rank":"1","desc":"周囲をルソン島、カリマンタン島、ミンダナオ島に囲まれた閉鎖的な海。水温は高く、この海でしか見られない生物もいるようだ。また、サンゴ礁も多く見られる。","note":"書きかけの地図","exp":"75"}],"6454":[{"type":"歴史遺物","name":"エジプト王女の香油","rank":"5","desc":"古代エジプトで愛された調合香料、キフィ。乳香や没薬、香り高い花々で作られていた。壁画の女性が頭に載せている円錐形の固形物がキフィと考えられ、溶け出して香りを放っていたとも推測されるが、詳しくは不明である。","note":"","exp":""}],"5322":[{"type":"史跡","name":"ツォディロの岩絵","rank":"3","desc":"カラハリ砂漠の丘陵地帯にある岩に描かれた絵。非常に狭い範囲に鮮やかな数千もの絵が描かれており、この地の歴史を知る手がかりとなりそうだ。","note":"","exp":""}],"3328":[{"type":"植物","name":"ハナミズキ","rank":"2","desc":"北米原産の花木。晩春に白色や淡いピンク色の花を咲かせ、秋には赤い実をつける。","note":"華やかな花木の地図","exp":"210"}],"3736":[{"type":"鳥類","name":"ベニヒワ","rank":"4","desc":"寒冷地や高山地帯に生息する小型の鳥。額の辺りが赤く色づいているのが特徴。雑食で、種子や昆虫などを幅広く食べる。","note":"赤い額の鳥","exp":"610"}],"2740":[{"type":"財宝","name":"朝鮮経国典","rank":"1","desc":"経国大典より以前に使用されていたという法典。\n鄭道伝はこの法典を記すことで、朝鮮王朝の法制の基礎を作った。","note":"貴重な書物の地図","exp":"160"}],"2300":[{"type":"史跡","name":"古代の闘技場","rank":"4","desc":"古代の球技「トラチトリ」が行われていたと思われる球場。\n他のマヤ文明の遺跡でも球場は見られるが、コパンのものは最大級であることから、当時の勢力の大きさが窺える。","note":"クエスト「広場にある斜面」<br/>発見物カード:360","exp":"720"}],"2493":[{"type":"地理","name":"石雨傘","rank":"1","desc":"台湾島の海岸にある、海の浸食で削れた岩。一本の細長い岩が、大きな岩石を支えておりその姿は傘の形によく似ている。","note":"書きかけの地図","exp":"130"}],"6401":[{"type":"宗教建築","name":"屈折ピラミッド","rank":"5","desc":"クフ王の父であるスネフェル王のピラミッドと伝わる。横から見ると頂上へ向かう角度が途中から緩やかになっている。同時期に作っていたピラミッドが完成直前に崩壊したため対策として途中から屈折させたという説も。","note":"レガシー：砂漠に栄えた巨石文明","exp":"2250"}],"379":[{"type":"宗教遺物","name":"ポセイドン像","rank":"1","desc":"ギリシャ神話の海神の像。ポセイドンは多くの愛人を持ち、その子供にはポリュフェモスなど、凶暴な怪物が多い。有名なメデューサもポセイドンの愛人でその子供がペガサスである。","note":"海神の像","exp":"60"}],"6346":[{"type":"史跡","name":"ヘプタスタディオン","rank":"2","desc":"アレクサンドリア大灯台が建設されたファロス島とアレクサンドリアの街との距離およそ1キロメートルを結ぶ長大な堤防。その長さ（ヘプタ=7）と距離の単位（スタディオン）からヘプタスタディオンといわれる。","note":"","exp":"300"}],"2347":[{"type":"地理","name":"九十九里浜","rank":"2","desc":"日本の太平洋岸にある砂浜海岸。沿岸部は漁場に恵まれている。\nその名は、長々と延びた浜辺に由来する。","note":"江戸を支える食の基盤","exp":"290"}],"6945":[{"type":"歴史遺物","name":"ダーリ","rank":"2","desc":"オセアニアとニューギニアの間にある海峡諸島の先住民の頭飾り。中央には真珠や亀の甲羅があしらわれ、外側には白い鳥の羽根が飾られている。儀式の舞踊に使われるという。","note":"発見物カード:175","exp":"350"}],"6645":[{"type":"植物","name":"アデニウム","rank":"2","desc":"アラビア半島原産の植物。美しい花を咲かせ「砂漠の薔薇」と呼ばれる。花びらは鮮やかで大きいが、寒さに弱い。","note":"","exp":"230"}],"138":[{"type":"歴史遺物","name":"クセルクセス1世の石像","rank":"1","desc":"クセルクセス1世は、アケメネス朝ペルシャの王。ダレイオス1世の息子で、ペルセポリスの建造を引き継いで行った。","note":"クセルクセス１世の遺物","exp":"180"}],"6722":[{"type":"天文","name":"やまねこ座","rank":"5","desc":"北天の星座。おおぐま座とぎょしゃ座の間に位置する。すらりとした山猫の姿を表す。天文学者へヴェリウスが17世紀に設定した。","note":"発見物カード:600","exp":"1200"}],"960":[{"type":"海洋生物","name":"クロチョウガイ","rank":"2","desc":"熱帯の海に生息する、大きめの二枚貝。黒真珠が取れる。真珠はまれにしか見つからないため、古代から非常な貴重品だった。クレオパトラはこの黒真珠を酢に溶かして飲んだといわれている。","note":"宝石を生む貝","exp":"370"}],"633":[{"type":"美術品","name":"キリスト昇架","rank":"4","desc":"「しょうか」。ルーベンス作の祭壇画。イエスが打ち付けられた十字架が、立てられようとしている場面だ。波を打つような筋肉、浮き上がるイエスの白い肉体など、これまでの宗教画と異なる表現がされている。","note":"社交的な画家","exp":"780"}],"1236":[{"type":"小型生物","name":"アベコベガエル","rank":"2","desc":"他のカエルと違い、幼生の期間が長いため、成体の4倍近い大きさまで成長する。その後の変態の過程で体が縮む。","note":"縮む体<br/><br/>発見時経験値255　発見物カード経験値127","exp":"255"}],"5027":[{"type":"港・集落","name":"オクスフォード","rank":"1","desc":"ロンドンの北西に位置する学問都市。\n羊毛の集散地として栄えていたが、8世紀に女子修道院が創立された。12世紀には学者たちが集まり出し、学問の都として発展した。","note":"到達する","exp":"25"}],"759":[{"type":"歴史遺物","name":"ヌフの船","rank":"3","desc":"ヌフとは、東アフリカの伝説で、人類初の船を作った人だと言われる。これは、アラビアから東アフリカで作られている船で、古代と同じ作り方をされているものだ。","note":"昔からある高性能の船","exp":"473"}],"1244":[{"type":"地理","name":"フロリダ半島","rank":"2","desc":"カリブ海とメキシコ湾の玄関口になっている半島。平坦な地形で、沼や湿地で覆われている。今にも海に沈んでしまいそうなほどだ。","note":"沈みかけの大地","exp":"370"}],"5053":[{"type":"港・集落","name":"コッコラ","rank":"1","desc":"ボスニア湾中央に面するフィンランドの街。グスタフ2世アドルフが築いた。工業品取引のための港だったが、やがて造船の重要拠点となって繁栄した。","note":"到達する","exp":"43"}],"2818":[{"type":"美術品","name":"唐の宮廷画","rank":"3","desc":"宮中の女性が楽の練習をしている風景を描いた絵画。その風俗から唐代に描かれたものと思われる。\n描いた人物の詳細は不明。","note":"高尚な娘のための絵画","exp":"530"}],"1807":[{"type":"美術品","name":"聖マルコの遺体の運搬","rank":"2","desc":"ヴェネツィアのグランデ・ディ・サン・マルコ同信会館のために描かれた連作「聖マルコ伝」の代表作とされる絵画。人物には強烈な明暗がつけられ、巧みな遠近法と相まって絵画に臨場感と緊張感を与えている。","note":"聖マルコを救う信者の絵","exp":"330"}],"5194":[{"type":"港・集落","name":"重慶","rank":"2","desc":"読み方は、「チョンチン」。長江上流に位置し、自然に囲まれている街。\n夏は酷暑だが、冬は比較的過ごしやすい。この地で、二重の慶事があったことから、この名前が付いたといわれている。","note":"到達する","exp":"380"}],"6520":[{"type":"植物","name":"レインボーユーカリ","rank":"5","desc":"その名の通り、色とりどりの樹皮を持つのが特徴的な高木樹。年を経るごとに外側の樹皮がはがれ落ちていき、内側に新しい樹皮が現れる。これを繰り返す過程で樹皮の色が変化していくといわれている。","note":"クエスト「染め上げられた樹木」<br/>発見物カード:595","exp":"1190"}],"326":[{"type":"歴史遺物","name":"マルクス・アウレリウス帝騎馬像","rank":"1","desc":"古代ローマ五賢帝最後の一人マルクス・アウレリウス帝の青銅像。騎乗像としては最古の物だと思われる。美術作品としての価値だけにとどまらず、当時の馬具の研究材料として重要である。","note":"ローマ皇帝の騎乗像","exp":"75"}],"3703":[{"type":"レリック","name":"ブルターニュの雌獅子","rank":"","desc":"フランス沿岸部を荒らし回り、ブルターニュの雌獅子と恐れられた女海賊ジャンヌ。彼女の復讐心は満たされたのだろうか。","note":"ブルターニュの雌獅子の剣<br/><br/>発見時経験値2260　発見時名声1800","exp":""}],"2256":[{"type":"地理","name":"ケプロイの滝","rank":"2","desc":"ポンペイ島最大の山から流れ落ちる滝。\nポンペイ島は雨が多いため滝の水量も多く、迫力がある。滝つぼにはウナギが生息している。","note":"クエスト「現地調達のすすめ」<br/>発見物カード:180","exp":"360"}],"1041":[{"type":"海洋生物","name":"カツオノエボシ","rank":"1","desc":"透き通った青い体を持つクラゲ。体部は水面に浮かんでおり、その周辺に数十mもの長さがある触手が伸びている。激烈な毒があり、人が死ぬことも珍しくない。切れた触手だけが浮遊して、被害が出ることもある。","note":"洋上の危険物","exp":"20"}],"122":[{"type":"歴史遺物","name":"ギリシャ火","rank":"1","desc":"7世紀ごろ、ビザンツ帝国で使用された火炎剤。石油に硫黄や松脂を混ぜたもので、激しく発火し水では消せない火が生じるという。もともとは東方から伝わったものだそうだ。","note":"ギリシャ火","exp":"80"}],"6959":[{"type":"化石","name":"ストロマトライト","rank":"5","desc":"層状の化石で、地球に初めて酸素をもたらしたとされる珪藻類と、土砂などが幾重にも積み重なったもの。多くは化石だが、一部の限られた海域などでは、原生しているものを確認することができる。","note":"発見物カード:810","exp":"1620"}],"475":[{"type":"宗教建築","name":"デルフォイ遺跡","rank":"1","desc":"古代ギリシャにおいて世界の中心だと考えられた場所。アポロン神殿があり、その神託は絶対的なものだった。ソクラテスもここで神託を受けた。","note":"権威ある神託","exp":"100"}],"3846":[{"type":"化石","name":"前脚と首の長いドラゴンの骨","rank":"3","desc":"体長およそ25m、体高も16mに及ぶ巨大な生物の骨。長い首と、後脚より長い前脚が特徴のようだ。","note":"脚と首の長い骨の調査","exp":"470"}],"940":[{"type":"美術品","name":"聖母子と二天使","rank":"1","desc":"フラ・フィリッポ・リッピ作の聖母子と天使の絵。宗教画は形式を重視した象徴的な描き方をされるのが常であったが、彼は生気に満ちた人物で宗教画を描いた。この聖母のモデルは彼の妻だといわれる。","note":"美人画の先駆け","exp":"190"}],"1313":[{"type":"植物","name":"アマリリス","rank":"3","desc":"鮮やかな赤色がとても美しい。この花には、どことなく気品を感じる。","note":"思い出の花","exp":"600"}],"1054":[{"type":"歴史遺物","name":"ヒッタイトの和平交渉文書","rank":"5","desc":"ヒッタイトがエジプトと戦ったカデシュの戦いについて書かれた文書。エジプトと停戦に至った経緯が詳細に書かれている。ただし、エジプトで見つかった同文書とはかなり内容が食い違っている。","note":"歴史の裏側","exp":"962"}],"1440":[{"type":"小型生物","name":"フクロモモンガ","rank":"2","desc":"滑空する有袋類。長くてふさふさした毛で覆われた尾を持つ。滑空する際に、その尾は舵の役割を果たす。小さな群れで生活し、樹液や種子を食べる。","note":"二つの顔","exp":"280"}],"466":[{"type":"歴史遺物","name":"スキピオの兜","rank":"5","desc":"カルタゴの将軍ハンニバルと戦った、大スキピオの兜。大スキピオはハンニバルに奪われた領土を奪還し、ザマの戦いでハンニバルを完全に打ち破った。","note":"軍神対軍神","exp":"988"}],"2654":[{"type":"虫類","name":"ホソオチョウ","rank":"2","desc":"朝鮮半島に生息するアゲハチョウ。後羽に長い突起があることからこう呼ばれる。\n地上の低いところを緩やかに飛翔する。","note":"尻尾のあるチョウ","exp":"300"}],"406":[{"type":"海洋生物","name":"猛毒の海蛇","rank":"1","desc":"熱帯の海で見られる、海に住むヘビ。猛毒を持つものが多く、かまれるとほぼ死亡する。しかし、性質はおとなしく、刺激しなければ襲ってこないようだ。","note":"危険な海蛇の地図","exp":"68"}],"1998":[{"type":"海洋生物","name":"レッドエンペラー","rank":"2","desc":"オーストラリアの周辺に生息するフエダイの仲間。身は大変おいしい。","note":"釣り","exp":"250"}],"4978":[{"type":"鳥類","name":"エレオノラハヤブサ","rank":"3","desc":"エーゲ海の島々に生息しているハヤブサ。集団で狩りや子育てを行う。群れを成して、狩りの成功率を上げ、敵からも身を守りやすくしているようだ。","note":"","exp":"600"}],"2956":[{"type":"化石","name":"キバのある動物の骨","rank":"3","desc":"巨大なキバが特徴的な動物の骨。チーターやトラに似た形なことから、俊敏な動きで獲物を追い、このキバで捕食したのだろう。","note":"古の生命","exp":"470"}],"3581":[{"type":"宗教遺物","name":"ロノマクア","rank":"2","desc":"ハワイの神の一つで、豊穣や気候などに関する諸事を司る「ロノ」神を象徴した飾り。収穫祭で飾られる。白布を垂らした木の中央にロノを模した顔が彫られている。","note":"陸地の白帆","exp":"233"}],"6180":[{"type":"財宝","name":"アルスター物語の異本","rank":"2","desc":"アルスター物語に登場する英雄である、クーフーリンの伝承の一つを記したもの。物語の内容はキリスト教の教義を色濃く反映しており、他のアルスター物語での描写とは明らかに異色である。","note":"","exp":"390"}],"1110":[{"type":"中型生物","name":"クモザル","rank":"1","desc":"黒っぽい体色で、手足と尾がとても長いサルである。手足と尾を使い、木から木へ飛び移る姿は大きなクモのようだ。サルは手が人間に似ていて器用なものが多いが、このサルは親指がない。","note":"手足の長いサルの地図","exp":"75"}],"5689":[{"type":"歴史遺物","name":"シギルの偶像","rank":"2","desc":"世界で最も古いとされる木製の彫像。細長い体に刻まれた模様は暗号のようでもあるが、その意味を理解することは困難である。","note":"古代からのメッセージ","exp":"380"}],"6363":[{"type":"虫類","name":"チリクワガタ","rank":"3","desc":"南アメリカに生息する大型のクワガタ。雄は巨大な顎が特徴。頭部が小さいため顎の挟む力は弱く、相手を投げ飛ばすために使う。性格は雌雄を問わず非常に好戦的。","note":"","exp":"440"}],"3170":[{"type":"財宝","name":"コジモのメダル","rank":"5","desc":"ロレンツォの祖父、コジモの横顔が彫られた金のメダル。コジモは芸術や学術への援助を惜しまず、メディチ家ひいてはフィレンツェの発展に大きく貢献した。その功績を称えているのだろう。","note":"祖父の肖像","exp":"1030"}],"6541":[{"type":"宗教建築","name":"エーヴベリーのストーンサークル","rank":"5","desc":"ブリテン島にある、先史時代の遺跡。遺跡内にある巨大な石が立ち並ぶストーンサークルはとても広大で、小さな村であればその中に収まるほどだ。遺跡の用途は不明だが、そこで儀式でも行っていたのだろうか。","note":"","exp":""}],"1354":[{"type":"宗教遺物","name":"阿しゅく如来","rank":"3","desc":"あしゅくにょらい。仏教における、如来のひとり。サンスクリット語の名には「不動である」「堅固な」という意味がある。そこから転じているのか、この如来には、力強く堅固な意思と、猛けき力が宿っているという。","note":"阿しゅく如来像","exp":"517"}],"1826":[{"type":"史跡","name":"フマナ平原","rank":"5","desc":"南米大陸の中腹、アンデス山脈の西側の裾野にある高原。砂漠が広がっており、ところどころにくぼみがある。なにやらただのくぼみではなさそうだが…。","note":"未開の土地の妙なもの","exp":"1030"}],"5856":[{"type":"鳥類","name":"ガマグチヨタカ","rank":"5","desc":"東南アジアを中心に広域に生息する鳥。大きく平たいくちばしが特徴で、口を開いた姿が日本の「がまぐち」に似ていることからこの名で呼ばれている。","note":"","exp":"1430"}],"6543":[{"type":"宗教遺物","name":"ヴァーユ像","rank":"5","desc":"インド神話に伝わる風の神。始まりの原人から生まれ、最初にソーマを受け取った神とされる。インドラとともに空界を治めるほどの力を持つ存在で、その姿は非常に美しいといわれる。","note":"追究クエスト","exp":"1150"}],"2071":[{"type":"海洋生物","name":"ニタリ","rank":"2","desc":"太平洋熱帯域に生息。胴体と同じくらい長い尾が特徴で、尾をムチのように叩いて小魚を捕まえる。\nサメとしては珍しく、海面を跳ねることも。性格はわりとおとなしい。","note":"尾の長いサメ","exp":"350"}],"334":[{"type":"歴史遺物","name":"アグリッピナの髪飾り","rank":"2","desc":"アグリッピナとは、古代ローマのカリグラ帝の妹であり、クラウディウス帝の妻。ネロ帝の母でもある。これは息子に暗殺されたときにつけていたものだという。","note":"悪妻にして鬼母","exp":"370"}],"3820":[{"type":"財宝","name":"海賊の隠し財宝","rank":"5","desc":"ある海賊が収奪した金銀財宝を詰め、隠しておいたもの。\n長らく放置されていたらしく箱は古びているが、中身はきれいに保たれている。","note":"隠された財宝","exp":"1090"}],"6127":[{"type":"伝承","name":"トゥースフェアリー","rank":"3","desc":"抜けた乳歯を枕の下に入れておくと、いつの間にか金貨と取り換えてくれるという妖精。抜けた乳歯についての伝承は文化ごとに様々であり、この妖精にまつわる話は、主にヨーロッパのものである。","note":"","exp":"440"}],"6400":[{"type":"歴史遺物","name":"アル・アジーズの計画書","rank":"5","desc":"エジプトを支配したアイユーブ朝スルタンであるアル・アジーズの時代の書類。巨大な石積みを崩すための手法が書かれているとされる。アル・アジーズがピラミッドの破壊を試みた時の計画書かもしれない。","note":"レガシー：砂漠に栄えた巨石文明","exp":"1500"}],"1346":[{"type":"植物","name":"トレニア","rank":"1","desc":"花径が2cmほどの小さな花。中心を包み込むように花弁を付ける。色は淡青、桃、黄など様々である。","note":"小さな花の地図","exp":"110"}],"464":[{"type":"虫類","name":"ドルーリーオオアゲハ","rank":"2","desc":"アフリカで見られる非常に大きなチョウ。ひらひらと飛んでいる様子は鳥かコウモリと見間違うほどである。大型のものは羽を広げると20cm以上ある。近くで見るとぎょっとするほどの迫力だ。","note":"空を飛ぶ生物","exp":"340"}],"532":[{"type":"歴史遺物","name":"古代の馬具","rank":"2","desc":"馬を扱うための道具類である。くつわやあぶみ、鞍が発明されるまで、馬はもっぱら荷役や農耕、馬車用に使われていた。","note":"古代の道具の地図","exp":"390"}],"5009":[{"type":"地理","name":"カスピ海","rank":"2","desc":"世界でも類を見ないほど巨大な湖。流入する河川は100を超える。チョウザメが多く生息しているなど特有の生態系を保っている。","note":"","exp":""}],"6744":[{"type":"鳥類","name":"アンナハチドリ","rank":"5","desc":"別名「飛ぶ宝石」と讃えられる、華麗な色彩を持つハチドリ。オスは東部の羽毛が光を反射するため、角度が変わると変色したように見える。繁殖期になると、オスは頻繁に冠羽を変色させ、メスを惹きつける。","note":"発見物カード:525","exp":"1050"}],"65":[{"type":"宗教遺物","name":"ハヌマーン像","rank":"2","desc":"インド神話に登場する猿神の像。ラーマーヤナで、主人公ラーマを助けて大活躍するため広く信仰される。毛が白いとされているためインドの白い猿はハヌマーンの使いとして手厚く保護される。","note":"インドの神像の地図","exp":"245"}],"6286":[{"type":"地理","name":"カボ・デ・ロス・アマンテス","rank":"3","desc":"グアム島の北岸に位置する岬。身分の差により結ばれることを許されなかった恋人たちが身を投げたという伝説がある。","note":"","exp":"600"}],"41":[{"type":"財宝","name":"サラディンの剣","rank":"4","desc":"アイユーブ朝の創始者サラーフ・アッディーンの剣。第3回十字軍でリチャード獅子心王（しししんおう）らと戦った。異教徒への寛容な対応で知られる。","note":"イスラムの英雄","exp":"648"}],"771":[{"type":"歴史遺物","name":"石器","rank":"1","desc":"石を削って作った、先史時代の道具類。木の棒にしばりつけて槍にしたり、そのまま手に持って包丁やナイフのように使ったりしたと考えられる。","note":"先史時代の史跡の地図","exp":"15"}],"2820":[{"type":"歴史遺物","name":"虎符","rank":"2","desc":"主に戦国時代～漢代に使用された、虎の形の割符。徴兵の際に用いられた。\nこの割符が合致していなければ兵を動かせなかったといわれる。","note":"クエスト「三国時代の遺物」<br/>発見物カード:165","exp":"330"}],"1404":[{"type":"中型生物","name":"ドール","rank":"1","desc":"森林や草原に10頭前後の群れで生息する。嗅覚で獲物を追跡し、イノシシやレイヨウなどを捕食する。","note":"野生の犬の地図","exp":"110"}],"1654":[{"type":"地理","name":"メコンデルタ","rank":"4","desc":"メコン川の河口に位置し、無数の島を有する湿地帯。島の形成過程は三角州と同じく、メコン川が運搬した土砂が堆積してできたもののようだ。そのため、河口に存在する島の多くが低地であり、雨季になると水没する。","note":"河口の群島","exp":"744"}],"3806":[{"type":"地理","name":"マルティニーク島","rank":"3","desc":"カリブ海の西インド諸島に属する火山島。起伏に富んだ地形を緑の木々が覆い、それを青い海が取り巻くという美しい島である。","note":"書きかけの地図<br/>※5ブメして出ず、何か前提があるか？","exp":"510"}],"5913":[{"type":"海洋生物","name":"トリカジカ","rank":"2","desc":"東アジア近海に生息するスズキの仲間。体に比べて頭が大きく、逆に尾のほうは細く短くなっている。大きな頭にある目も大きく、それが鳥の顔に似ていることが、名前の由来だろう。","note":"釣りで発見。間宮海峡から日本海にかけてのあたりで釣れました。<br/>オホーツク海(6533,2497付近)","exp":"370"}],"1499":[{"type":"化石","name":"かぎ爪のある巨大な獣の骨","rank":"1","desc":"かぎ爪を持った巨大な生物の骨。形からはクマを思わせるが、それとは比べ物にならないほどに大きい。どれほど恐ろしい生物だったのだろう。","note":"獣の骨の地図","exp":"190"}],"6899":[{"type":"虫類","name":"ゴライアスオオツノハナムグリ","rank":"3","desc":"アフリカの熱帯雨林などに生息する、コガネムシの一種。体長はおよそ10cmと同種の中では大型。幼虫は寒さに弱く、20度以下の環境では死に至ることもあるという。乾季に泥で繭を作り、雨季に繭を出て成虫となる性質を持つ。","note":"","exp":""}],"1778":[{"type":"歴史遺物","name":"マゼラン南米冒険記","rank":"2","desc":"マゼランが南米で航海を中断していた時に記したと思われる書物。先住民族などについて記載されている。","note":"［勅命］[[新大陸西岸進出の先人の記録","exp":"310"}],"1039":[{"type":"歴史遺物","name":"バトゥの財宝","rank":"3","desc":"バトゥとは、チンギス・ハンの長子であるジュチの子。大規模なヨーロッパ遠征を行いキプチャク・ハン国を興した。これはバトゥの財産の一部であるらしい。","note":"遊牧民族の西進","exp":"495"}],"6022":[{"type":"財宝","name":"白砂糖のデザート","rank":"2","desc":"白砂糖「だけ」を材料に作られた、屋敷や城の模型。古くからヨーロッパ各地の王侯貴族たちの宴席で供されており、見て楽しんだ後に粉々にして列席者に振る舞われた。\n家の財力を誇示するため、豪華な装飾をつけることもあるようだ。","note":"新郎の見栄にかけて","exp":"230"}],"3188":[{"type":"地理","name":"ルイスヒルズ","rank":"1","desc":"北米北東部沿岸の、テラ・ノヴァ西部に位置する山。標高は814mであり、同じくロングレンジ山脈に属するグロスモーン山よりもやや高く、テラ・ノヴァで最も高い山とされる。","note":"書きかけの地図","exp":"200"}],"1043":[{"type":"化石","name":"翼のあるドラゴンの骨","rank":"2","desc":"巨大な翼のある竜の形をした岩盤。アレクサンドリアの近隣の岩場で発見された。大きく広げた翼がまがまがしい。これこそが伝説にうたわれるドラゴンの骨かもしれない。","note":"翼のあるドラゴンの骨<br/><br/>発見時経験値370　発見物カード経験値185","exp":"370"}],"5269":[{"type":"歴史遺物","name":"ヴァイキングの鉄盾","rank":"2","desc":"ヴァイキングが使用していた鉄盾。かつてこの地に入植したヴァイキングが残したと見られる。付近には溶鉱炉の跡があり、鉄釘などの道具も多く見つかっている。","note":"","exp":"360"}],"5565":[{"type":"地理","name":"ハイアムスビーチ","rank":"2","desc":"オーストラリア大陸の南東部にある海岸。\n真っ白に輝く、きめ細やかな砂が特徴。","note":"","exp":"270"}],"5547":[{"type":"海洋生物","name":"ヤシガニ","rank":"4","desc":"大型の甲殻類。一見カニのように見えるが、実はヤドカリの仲間のようだ。かなりの雑食性であり、木の実から死肉まで幅広く食す。食用目的に各地で乱獲が続いており、保護が必要になる可能性もある。","note":"クエスト「消える巨大カニ」<br/>発見物カード:320","exp":"640"}],"6946":[{"type":"財宝","name":"鍍金銅蚕","rank":"3","desc":"金めっきが施された蚕をかたどった銅製品。中国において、漢代に多く作られたとされ、シルクロードの繁栄をうかがわせる。","note":"","exp":""}],"5051":[{"type":"港・集落","name":"ケープ","rank":"1","desc":"アフリカ南部、喜望峰近辺に作られた街。近辺は暴風域で、危険である。鉱山に恵まれた地帯で、銅や鉄のほかに金、ダイヤモンドが産出する。","note":"到達する","exp":"74"}],"1943":[{"type":"宗教遺物","name":"シウコアトル像","rank":"1","desc":"アステカ神話における火の蛇の神。アステカ独自の暦によると、太陽を日の出から天の頂点まで届ける役目を担っているという。","note":"メソアメリカの像の地図","exp":"200"}],"1662":[{"type":"地理","name":"マカッサル海峡","rank":"2","desc":"カリマンタン島と、セレベス島の間に横たわる海峡。古くからの交通の要衝であり、特にマカッサルは巨大な港を持ち、交通の要として栄えている。","note":"書きかけの地図","exp":"210"}],"2874":[{"type":"歴史遺物","name":"新羅語の碑文","rank":"2","desc":"高句麗時代に建てられたと思われる石碑。四面に渡り、文字が刻まれている。\n高句麗と新羅の関係について書かれているらしいが、損傷が激しく解読は難しい。","note":"古い石碑の地図","exp":"250"}],"4960":[{"type":"中型生物","name":"ギリシャリクガメ","rank":"2","desc":"北アフリカやヨーロッパ南東の乾燥した土地に生息しているカメ。住む場所によって模様の色や形が異なるが、後ろ脚の付け根にトゲのような鱗がある点は共通している。\nギリシャ織のモザイク模様が、名前の由来になっている。","note":"","exp":"380"}],"1579":[{"type":"海洋生物","name":"コンゴウフグ","rank":"1","desc":"箱のように角張った体が特徴。目の上には小さな突起がある。海底の砂に水を吹きかけ、エサを追い出して食べる。","note":"箱のような魚の地図","exp":"160"}],"5574":[{"type":"天文","name":"ほ座の花のような星雲","rank":"2","desc":"ほ座の付近に存在する星雲。淡く暗めの星雲で、大きく広がっている。","note":"「天文学者の観測記録」<br/>発見物カード:165","exp":"330"}],"4854":[{"type":"天文","name":"アルビレオ","rank":"1","desc":"星座図上で、はくちょう座のくちばしに位置する星。天体望遠鏡で見ると、金色と青色の二つの星が並んでいるのがわかる。","note":"「明るい星の観測記録」<br/>発見物カード:55","exp":"110"}],"811":[{"type":"宗教遺物","name":"ブードゥー教の祭壇","rank":"4","desc":"ブードゥー教とは、アフリカの宗教にキリスト教が取り入れられて発達した新しい宗教である。これはその祭壇で、ロアと呼ばれる精霊を呼び出すためのものだろう。ろうそくや鈴などが祭器として使われている。","note":"大西洋沿岸宗教の融合","exp":"756"}],"183":[{"type":"史跡","name":"オリンピア遺跡","rank":"1","desc":"多数の神殿や競技場がある古代ギリシャの遺跡。オリンピック競技が行われていたため、各種競技に関連する建造物が多い。","note":"ゼウスに捧げる祭典","exp":"100"}],"6740":[{"type":"財宝","name":"錦衣衛の牙牌","rank":"4","desc":"明の皇帝直属軍の一つ「錦衣衛」で使用された、象牙製の札。身分を証明するもので、腰から下げて携行する。裏に注意書きが刻まれており、公務の際は着用義務があった。他人に貸したり、紛失した者は罪に問われたという。","note":"カード経験:450","exp":"900"}],"2962":[{"type":"植物","name":"カルミア","rank":"2","desc":"北米に生息する花。つぼみの形が多角形で、星に似ている。花の一つ一つは小さいが、集団で咲くと大きな球体のように見える。","note":"クエスト「食器の木」<br/>発見物カード:130","exp":"260"}],"1660":[{"type":"地理","name":"ガイナス岬","rank":"1","desc":"ベネズエラ湾西岸に突き出した半島の先端部にある岬。近年、ヨーロッパ人の進出が盛んな場所である。","note":"書きかけの地図","exp":"145"}],"1957":[{"type":"植物","name":"メガスケパスマ・エリトロクラミス","rank":"1","desc":"枝の先に鮮やかな赤い花をいくつも咲かせる植物。その筒状の花の連なりは、まるで炎を束ねたかのように見える。大きいものは樹高4m程に成長する。中米の熱帯に生息。","note":"日陰に咲く花の地図","exp":"160"}],"5292":[{"type":"中型生物","name":"パタスザル","rank":"4","desc":"アフリカのサバンナに生息するサル。樹上でも素早いが、地上でも非常に速く走れ、時速で55kmにも達する。昼間は地表で生活し、夜は低木の上で休むことが多いようだ。","note":"","exp":"620"}],"6126":[{"type":"伝承","name":"虹蛇","rank":"5","desc":"太陽が神に見立てられるように、虹も偉大な存在の象徴として見なされる。創造主としての性質を持つ「虹蛇」は、強大な存在として語られることの多い蛇や龍の中でも、頭一つ抜けた存在と言えるだろう。","note":"","exp":"1330"}],"6019":[{"type":"財宝","name":"ドゥアルテの著作","rank":"1","desc":"ドゥアルテ王子が自ら執筆した著作。政治家としての在り方を書いたものや乗馬の心得を書いたものなどがあり様々な分野に精通していることが窺える。","note":"","exp":"123"}],"1750":[{"type":"鳥類","name":"コトドリ","rank":"5","desc":"竪琴のような特殊な形の尾羽を持つ鳥。繁殖期には、さえずりながら尾を振り動かしてメスを誘う。驚くべきはその声で、鳥の鳴き声に限らずありとあらゆる音をまねることができる。","note":"奇怪<br/><br/>発見時経験値1040　発見物カード経験値520","exp":"1040"}],"3875":[{"type":"天文","name":"へびつかい座","rank":"4","desc":"ギリシャ神話に登場する名医アスクレピオスが空に上った姿とされる。アスクレピオスは死者をも蘇らせることができ、これを怒った冥界の王ハデスが大神ゼウスに雷で打ち殺させたという。","note":"クエスト「伝説の名医」<br/>発見物カード:375","exp":"770"}],"1556":[{"type":"鳥類","name":"アオバズク","rank":"1","desc":"がっちりとした小型のフクロウ。夕暮れになると活動を始め、昆虫やネズミなどを捕食する。","note":"小さな鳥の地図","exp":"140"}],"5811":[{"type":"財宝","name":"マナス","rank":"3","desc":"キルギス地方に伝わる長大な叙事詩。マナスという名の英雄と、その子孫たちの活躍が描かれている。マナスチという語り部が口伝でのみ伝承している。","note":"","exp":""}],"5869":[{"type":"気象・現象","name":"フライング・ダッチマン","rank":"4","desc":"喜望峰近海に出没するという幽霊船。ある嵐の日、船長が風を罵ったためその船は呪われてしまい、その結果永遠にさまようことになったという。","note":"ケープ　出航所役人前の桟橋　雨　たぶん夜","exp":"340"}],"1764":[{"type":"宗教遺物","name":"ノンモ像","rank":"1","desc":"ノンモとは、アフリカ北西部に居住する民族ドゴンの地上における創造神のことである。上半身は人間、下半身は蛇の姿で描かれる。","note":"アフリカの神像の地図","exp":"140"}],"105":[{"type":"海洋生物","name":"チョウチョウウオ","rank":"1","desc":"熱帯の海で見られる美しい色の魚。平べったい体をしており、口はとがっている。さまざまな色や模様のものがいる。","note":"カラフルな魚の地図","exp":"29"}],"5323":[{"type":"中型生物","name":"オオヨロイトカゲ","rank":"2","desc":"アフリカ南東部の草原に生息するトカゲ。大きいものは全長40cmほどになる。背は硬い鱗に覆われ、それが名前の由来になっている。日光浴を非常に好むようだ。","note":"","exp":"320"}],"816":[{"type":"美術品","name":"受胎告知のマリア","rank":"1","desc":"リーメンシュナイダー作の彩色大理石像。受胎告知を受けたマリアの像である。イタリア方面のマリア像とは違う魅力があり、清楚な美しさが印象的だ。","note":"大理石のマリア像","exp":"60"}],"6692":[{"type":"鳥類","name":"アカアシカツオドリ","rank":"2","desc":"インド洋、大西洋、太平洋の熱帯および亜熱帯の海域に分布する海鳥。群れを形成して生活する習慣がある。眼の周囲の青みがかった灰色の皮膚と、真っ赤な足が特徴。","note":"「変わった鳥の地図」<br/>発見物カード:115","exp":"230"}],"5040":[{"type":"港・集落","name":"カルカッタ","rank":"1","desc":"ベンガル湾に面する河口の街。東南アジアへ向かう際の重要な拠点で、中国からの商品も扱われる。高級な繊維や、宝石などが流通する。","note":"到達する","exp":"179"}],"1":[{"type":"史跡","name":"ボイン渓谷遺跡群","rank":"2","desc":"アイルランドにある、先史時代の遺跡群。緻密な石組みの墳墓が並ぶ。奥の墓室には冬至の前後数日のみ、朝日が差し込む。","note":"アイルランドの遺跡","exp":"250"}],"1822":[{"type":"歴史遺物","name":"ヒッタイトの戦車","rank":"2","desc":"アナトリアの古代王国ヒッタイトで発明された戦車。二輪で六輻の車輪を備え、馬が牽く車体に乗った御者が弓を爪弾いて戦う。","note":"ヒッタイトの戦術兵器","exp":"360"}],"1983":[{"type":"海洋生物","name":"シビレエイ","rank":"2","desc":"体内に左右一対の発電器官を持ち、それにより小魚やエビなどを電気で麻痺させて捕食する。","note":"釣り","exp":"340"}],"2330":[{"type":"地理","name":"壱岐","rank":"1","desc":"読みは「いき」。九州北西部の玄界灘に位置する島。\n暖流である対馬海流の影響で、気候は比較的温暖である。\n古くから海路上の中継地点として、朝鮮半島と九州をつないできた場所でもある。","note":"書きかけの地図","exp":"130"}],"6515":[{"type":"歴史遺物","name":"競技者を描いたアムフォラ","rank":"5","desc":"古代ギリシャの競技者を描いたつぼ。黒地に赤、もしくは赤地に黒で描かれている。競技種目は徒競走、円盤投げ、槍投げ、走り幅跳びなどのほか、格闘技や拳闘、戦車競走、武装競争などがあった。競技は衣服を身につけず行われたと伝わる。","note":"レガシー競技の聖地オリンピア　左上","exp":"1500"}],"1940":[{"type":"歴史遺物","name":"カネテの難破船","rank":"2","desc":"南米から本国へ向かう途中だった、イスパニアの貿易船。\nスピルヴァーゲン船長が率いるネーデルラント船との戦いで沈没した。","note":"サルベージ<br/>発見物カード:195","exp":"390"}],"2500":[{"type":"財宝","name":"五弦の琵琶","rank":"4","desc":"読みは、「ごげんのびわ」。日本で作られた質素な作りの琵琶。ある宝物庫には、昔インドから日本に贈られたとされる美しい五弦の琵琶が保管されているらしいが詳細は不明。実物を見られる者は限られているようだ。","note":"伝来の弦楽器","exp":"690"}],"6160":[{"type":"海洋生物","name":"カラチョウザメ","rank":"4","desc":"中国各地に古くから生息するチョウザメの仲間。長江で多く見られており、産卵の時期には上流の金沙江まで遡上するという。「本草綱目」で滋養強壮に良いとされるが、そもそも水揚げ自体が珍しく、生息数もはっきりしない。","note":"","exp":"640"}],"5706":[{"type":"地理","name":"トゥズバイル塩湖","rank":"4","desc":"ウスチュルト台地に存在する塩湖。雪解け水や雨によって形成される。様々な条件が満たされると、水面に周囲の岩山が映し出され、幻想的な光景をみることができる。","note":"2017.02.07新規追加","exp":"720"}],"3907":[{"type":"地理","name":"バフィン湾","rank":"2","desc":"グリーンランドの西に位置する湾。湾内には多数の氷山が浮いており、航行は困難を極める。","note":"書きかけの地図","exp":"230"}],"2260":[{"type":"地理","name":"グアム島","rank":"4","desc":"マニラの東、ニューギニアの北に位置する小さな島。マゼランが太平洋を航海して99日目に、初めて見つけた島だといわれている。","note":"太平の果て","exp":"630"}],"4348":[{"type":"海洋生物","name":"カラフトマス","rank":"2","desc":"北太平洋に生息するサケ。川で産まれ、成体になると海で生活するが、産卵期にはまた川へ戻って卵を産む。オスのみ、繁殖期に背中が山型に変形する。","note":"釣り","exp":"220"}],"1278":[{"type":"歴史遺物","name":"フビライ・ハンの鞍","rank":"2","desc":"元朝皇帝であるフビライが使っていたという馬の鞍。騎馬民族であるモンゴル人は一般的に木の鞍を使うが、これは長期行軍用になめし革で作られている。","note":"大帝国の足音","exp":"290"}],"5391":[{"type":"宗教遺物","name":"プロメテウスの鎖","rank":"5","desc":"コーカサスの山中で見つかった頑丈な鎖。伝説では、天界から火を盗んで人間に与えたプロメテウスが、ヘパイストスの作った鎖で、コーカサスの山中に縛られ、生きたまま肝臓をハゲタカについばまれるという罰を受けたといわれている。","note":"","exp":"1210"}],"3878":[{"type":"財宝","name":"カウボーイのネッカチーフ","rank":"2","desc":"北米西部のカウボーイが首に巻く布。装身具としての用途のほか、口もとを覆って砂埃を吸うのを防いだり、仲間への合図に使ったりするなど、実用性も兼ね備えている。","note":"ウシを追う人","exp":"280"}],"1326":[{"type":"地理","name":"小スンダ列島","rank":"2","desc":"ジャワ島以東の比較的小さな島々の総称。あまりに多くの島があるため、全容を把握することは難しい。島それぞれに独自の文化がある。","note":"クエスト「列島のさらに東へ」<br/>発見物カード:165","exp":"330"}],"1899":[{"type":"宗教遺物","name":"宣教師の遺品","rank":"2","desc":"異国の地で教えを広めようとしていた宣教師の遺品。ヨーロッパでは見慣れた物だ。","note":"［勅命］[[現地における思想についての調査","exp":"310"}],"5325":[{"type":"歴史遺物","name":"ホモ・ハビリスの石器","rank":"1","desc":"大昔に使われていたと思われる石製の道具。加工の跡がないため、他の地域で見つかる石器よりも古い時代のものと考えられる。主に狩猟に用いられたのだろう。","note":"","exp":""}],"2491":[{"type":"財宝","name":"口簧琴","rank":"1","desc":"読みは、「こうこうきん」。台湾島の先住民の玩具。\n竹や金属などで製作される。音程の異なる複数の弁を持つ。","note":"笛のような楽器の地図","exp":"120"}],"1885":[{"type":"歴史遺物","name":"黒曜石の槍","rank":"4","desc":"アステカの古い武器には、金属製のものがあまり見られない。青銅は使われていたようだが、武器としては用いられなかったようだ。","note":"アステカ人と黒曜石","exp":"744"}],"6671":[{"type":"海洋生物","name":"オーストラリアウンバチクラゲ","rank":"3","desc":"属名のキロネックスの名で知られる。体は半透明で箱形。触手は長い。世界で最も強い毒性を持ち、刺されると人間ですら数分で死に至るという。そのため「殺人クラゲ」の異名で恐れられている。","note":"","exp":"500"}],"2369":[{"type":"中型生物","name":"ニホンカモシカ","rank":"1","desc":"山林に生息する、日本固有のカモシカ。雌も雄と同様の角を持ち、いずれも生え変わることはない。\n毛皮は保温効果と耐水性に優れており、広く重宝されている。","note":"シカに似た動物の地図","exp":"150"}],"1711":[{"type":"財宝","name":"クラップスティック","rank":"1","desc":"オーストラリア先住民が儀式のときに、ディジュリドゥの合いの手として鳴らす拍子木。ディジュリドゥを伴奏にクラップスティックを両手に持った歌い手が儀式の歌を歌い上げる。","note":"拍子木の地図","exp":"160"}],"2955":[{"type":"小型生物","name":"レッサーサイレン","rank":"1","desc":"ウナギのような体に、二本の肢が生えている両生類。肢は四本の指を持ち、しっかりとした構造になっている。","note":"足のある魚の地図","exp":"140"}],"3016":[{"type":"海洋生物","name":"ホンビノスガイ","rank":"1","desc":"食用にもされる、一般的な二枚貝。殻の表面はザラザラしている。比較的多くの場所で見ることができる。","note":"よく見る貝の地図","exp":"90"}],"5801":[{"type":"史跡","name":"エル・カズネ","rank":"5","desc":"ペトラ遺跡の王墓。盗賊が宝物を隠したという伝説から、宝物殿と呼ばれるようになったようだ。","note":"","exp":"1370"}],"6925":[{"type":"地理","name":"アンドロメダの岩","rank":"5","desc":"ヤッファの海岸に浮かぶ岩。ギリシャ神話では、海神ポセイドンの怒りを鎮めるために、エチオピアの王女アンドロメダが生贄として鎖で繋がれた場所だといわれている。","note":"発見物カード:560","exp":"1120"}],"3670":[{"type":"歴史遺物","name":"ハトシェプスト女王の像","rank":"5","desc":"古代エジプト最初の女性ファラオであるハトシェプストは、破壊されていたカルナック神殿を修復し、巨大なオベリスクを始めとする建築物を増築した。その際にこの像が作られたと考えられる。","note":"ダンジョン","exp":"1010"}],"2724":[{"type":"鳥類","name":"カンムリツクシガモ","rank":"4","desc":"朝鮮半島から中国北東部にかけての湿地帯に生息する鳥。\n冠状の飾り羽があることから名付けられた。","note":"美しい水鳥","exp":"680"}],"5702":[{"type":"地理","name":"イムジャ湖","rank":"2","desc":"チョモランマのふもとにある湖。氷河の後退により溶けた水がせき止められ、湖が形成されている。せき止めている部分が決壊した場合、大きな被害をもたらすのではと考えられている。","note":"2017.02.07新規追加","exp":"240"}],"6900":[{"type":"化石","name":"細長いクジラのような生物の化石","rank":"5","desc":"大きく細長いクジラのような姿をした海洋生物の化石。体長と比べて小さい頭骨には、多くの鋭い歯が並んでいる。空洞になっている椎骨を脳髄と液体で満たし、浮力を得ていたと考えられる。","note":"","exp":""}],"592":[{"type":"大型生物","name":"クロヒョウ","rank":"4","desc":"全身が黒いヒョウ。普通のヒョウと違う種類というわけではないらしい。ほかのヒョウと同じように、木の上で生活することが多いようだ。黒い毛は艶があり、非常に美しい。","note":"黒い猛獣","exp":"708"}],"3792":[{"type":"天文","name":"オリオンのベルト","rank":"2","desc":"オリオン座の中ほどにある3つの星。2等星が3つ並ぶため見つけやすい。星座図ではオリオンのベルトに見立てられる。右端にある星はミンタカと呼ばれ、ほぼ天の赤道の上にあるため、春分や秋分の日の太陽と同様の軌道に見える。","note":"視認<br/><br/>発見時経験値380　発見物カード経験値190","exp":"380"}],"1473":[{"type":"史跡","name":"テノチティトラン","rank":"5","desc":"アステカ帝国の首都。テスココ湖の中心にある島に作られた都で、岸に向けて3本の橋が架かるさまは壮麗。コルテスも「あまりに広く美しいので半分しか報告しません」と報告書に記している。","note":"別世界","exp":"1274"}],"4791":[{"type":"宗教遺物","name":"ペレ像","rank":"2","desc":"ハワイ島の火山の女神で、はるか南の島で生まれたと言われる。\n数多くの兄弟神とともにハワイに移り住み、島の南東にある火山を住まいとしたとされる。","note":"クエスト「常夏の島の火山神」<br/>発見物カード:160","exp":"320"}],"1674":[{"type":"歴史遺物","name":"ポンペイのパン","rank":"2","desc":"火山の噴火によって滅びたポンペイの街で見つかったパン。火山灰に覆われて、奇跡的に朽ち果てず残った。\n食べやすいように八等分にナイフを入れた状態で、カチカチに乾燥し、真っ黒になっている。まさしく食事の直前だったのだろう…。","note":"民家の地図","exp":"305"}],"6898":[{"type":"地理","name":"サハラの目","rank":"3","desc":"アフリカ北西部の砂漠にある窪地。直径は約50kmに及ぶ。高台から眺めると目のように見えることから、この名で呼ばれるようになったという。","note":"","exp":""}],"6375":[{"type":"気象・現象","name":"スーパーセル","rank":"4","desc":"超巨大な積乱雲と、それが起こす激しい嵐のこと。豪雨や雷、大量の雹が長時間にわたって降る。水平方向に回転する空気が積乱雲を巨大化させ、上昇気流と下降気流の分離により嵐の持続時間がながくなる。","note":"発生時間短いです。夏でした。","exp":"690"}],"1249":[{"type":"鳥類","name":"メンフクロウ","rank":"2","desc":"顔がハートの形をしたフクロウ。生息域は広く、森林、草地、サバンナなど様々である。暗闇の中でも音だけで獲物の位置を正確に捕らえ、捕獲する。","note":"白いハート","exp":"360"}],"5342":[{"type":"歴史遺物","name":"ウィダ号","rank":"4","desc":"演説好きで知られる海賊、サミュエル・ベラミーの船。一味は積荷の酒で泥酔している隙を突かれ、捕虜に船を座礁させられ、一網打尽となった。","note":"サルベージ","exp":"355"}],"2596":[{"type":"財宝","name":"梅瓶","rank":"2","desc":"焼物の一種で、口が小さく背丈が高く、足元に対して肩が広く張っている器の総称。\n中国の古い時代から見られ、景徳鎮製のものは特に人気が高い。","note":"サルベージ。読み方は｢めいぴん」","exp":"280"}],"597":[{"type":"宗教遺物","name":"エシュ像","rank":"2","desc":"アフリカのヨルバ人の神の像。月食や日食を起こす、いたずら者の神だという。","note":"混乱をもたらす神","exp":"220"}],"3651":[{"type":"宗教遺物","name":"スヴァローグのレリーフ","rank":"2","desc":"スラブ神話に登場する神の像。スヴァローグは太陽神・ダジボーグの父であり、かまどや火を司るとされた。","note":"スラブ地方の石版の地図","exp":"330"}],"5780":[{"type":"地理","name":"パンゴン湖","rank":"2","desc":"ユーラシア大陸中央部に存在する海水と淡水が入り混じった湖。塩湖としては世界で最も高地にある。冬には１ｍに達するほどの厚い氷が張ることもある。","note":"","exp":"210"}],"2833":[{"type":"財宝","name":"太公望の釣竿","rank":"5","desc":"周の時代に軍師として活躍した太公望の持ち物といわれる釣竿。\n一説によると、渭水のほとりで釣りをしていたところ、のちの文王に「祖父の太公が待ち望んだ傑物だ」と称えられ、迎えられたという。","note":"太公望の魚釣り<br/><br/>発見時経験値1060　発見物カード経験値530","exp":"1060"}],"1522":[{"type":"植物","name":"アイス・ブルー","rank":"1","desc":"たくさんの青みがかった白い苞（ほう）を円柱状につけ、工芸品のような美しい形になる植物。高さ1mほどに成長する。","note":"工芸品のような花の地図","exp":"180"}],"1786":[{"type":"地理","name":"月の谷","rank":"1","desc":"アタカマ砂漠内の乾ききった岩塩地帯。草木はまったく生息しておらず、巨大な岩山が谷を形成している。空に浮かぶ月の表面に似ていると誰かが言ったことから、そう呼ばれるようになったそうだ。","note":"書きかけの地図","exp":"150"}],"5364":[{"type":"植物","name":"クワ","rank":"2","desc":"初夏に赤黒い実をつける、高さ15mほどの落葉樹。もともとクワの実は白かったが、ピュラモスとティズベーの悲劇によって二人の血に染まり、赤黒い実になったという伝説がギリシャ神話に伝えられている。","note":"戯曲の題材探し<br/><br/>発見時経験値380　発見物カード経験値190","exp":"380"}],"536":[{"type":"歴史遺物","name":"青銅器の破片","rank":"1","desc":"古代の青銅器の破片。青銅は扱いやすいので古代からよく用いられた。","note":"古代の道具の地図","exp":"11"}],"6536":[{"type":"史跡","name":"登封観星台","rank":"5","desc":"元代の学者・郭守敬が建設した、巨大な天文台。日陰の長さから季節や緯度の高低などを計算する。元国各地に置かれた観測拠点の中心であり、授時暦はこれら観測拠点から集めた記録を参考にしたといわれる。","note":"レガシー星の叡智　右下","exp":"2550"}],"1348":[{"type":"地理","name":"バリ島","rank":"3","desc":"ジャワ島の東に位置する島。イスラム教を国教とする国が増えるなか、バリ島には独自のヒンドゥー教が広まっている。","note":"ヒンドゥー教の支流","exp":"484"}],"3584":[{"type":"植物","name":"カナヴァオ","rank":"2","desc":"ハワイ固有種のアジサイ。実を食べると子宝に恵まれるとされ、古来より煮たり干されたりして食されている。そのため、アジサイに多く実がなると、縁起がよいと喜ばれる。","note":"繁栄を願う植物","exp":"279"}],"665":[{"type":"財宝","name":"象牙の女神像","rank":"2","desc":"象牙を削りだして作られた女神の像。非常に緻密な細工が施されている。","note":"象牙の女神像の地図","exp":"280"}],"2535":[{"type":"虫類","name":"ホッポゼミ","rank":"2","desc":"台湾島にのみ生息する小さな体と赤い目が特徴的なセミ。朝や夕方によく鳴き、鳴き声は遠くまで響く。\n別名ホッポヒグラシ。","note":"小さなセミの地図","exp":"340"}],"1490":[{"type":"小型生物","name":"アカメアマガエル","rank":"1","desc":"大きな赤い目玉、緑色の体にわき腹の青と白の縞模様が特徴。その鮮やかな体色を隠すため、肢を折り曲げて葉の上で休息をとる。","note":"赤い目のカエルの地図","exp":"70"}],"1201":[{"type":"財宝","name":"オーロラの雫","rank":"3","desc":"色とりどりのひすいでできたサークレット。ひとつひとつが大粒で細工も非常に精巧にできている。微妙な色彩をたたえるこのサークレットを、オーロラのひとしずくだと例えたのもうなずける。","note":"オーロラの雫","exp":"533"}],"5510":[{"type":"港・集落","name":"ポーツマス","rank":"1","desc":"ブリテン島南部の街。十字軍やフランスとの戦争において、軍港として機能した。その後の産業革命を経て造船業を中心に発展した。","note":"座標　16256,2488","exp":"15"}],"2252":[{"type":"地理","name":"ナナラウド山","rank":"2","desc":"ポンペイ島のほぼ中心に位置する山。\n標高は約800mで、ポンペイ島では一番高い。滝も多く存在するようだ。","note":"小島と山","exp":"350"}],"6708":[{"type":"虫類","name":"モモイロヤママユ","rank":"2","desc":"ヤママユガの一種。主に北米東部とカナダ南部に分布する。体長はおよそ3cm。全身がピンクと黄色の綿毛に覆われているのが特徴。幼虫はカエデを主食とするが、成虫は口部が退化して接触しなくなり、夜間に繁殖行動のみを行う。","note":"発見物カード:160","exp":"320"}],"1353":[{"type":"宗教建築","name":"ボロブドゥール遺跡","rank":"4","desc":"ジャワ島のほぼ中央にある仏教遺跡。基壇の上に積み重ねられたピラミッド型の形状。レリーフや仏像、仏塔がおびただしいほど存在する大規模なものだ。中には釈迦の遺骨を納めた仏塔があるというが…。","note":"眠り続けた遺跡","exp":"756"}],"5024":[{"type":"港・集落","name":"イスタンブール","rank":"1","desc":"かつてはビザンツ帝国の首都・コンスタンティノープルとして栄えた街。1453年、オスマントルコに占領され、首都・イスタンブールとなった。世界最大規模の都市である。ぜいたく品が扱われるほか果樹栽培なども盛んである。","note":"到達する","exp":"50"}],"1892":[{"type":"歴史遺物","name":"カピタナ号","rank":"2","desc":"クリストバル・コロン四回目の航海「崇高な航海」で旗艦を務めたキャラベル。\nベルムーダ号との衝突で遭難して一年あまりの後、ディエゴ・メンデスに救助され、サンタグロリア湾に廃棄された。","note":"サルベージ","exp":"310"}],"2666":[{"type":"財宝","name":"東医宝鑑","rank":"3","desc":"許浚により記された、全25巻の医学書。\n道教の影響を受けたこの医学書は、基礎の部分こそ明の李朱医学であるが、朝鮮独自の医学も存分に織り込まれている。今後の医学の発展に大きく寄与するだろう。","note":"宮廷医学の書","exp":"480"}],"6474":[{"type":"宗教遺物","name":"銀のアルテミス小像","rank":"2","desc":"銀製の小さな像。女神アルテミスをかたどったものとされるが、その姿はギリシャ神話とは大きく異なる。高さのある冠をかぶり、胸に多数の丸い飾りがついている。両腕を広げて両足を揃えた姿勢はエジプトや小アジアの影響があるようだ。","note":"クエスト「称えよ我らが大いなる女神を」<br/>発見物カード:140","exp":"280"}],"3301":[{"type":"地理","name":"アイオナ島","rank":"3","desc":"ブリテン島北部、西側にある、とても小さな島。一日あれば徒歩で島を一周できる。\n修道僧・コルンバによりこの島に建てられた修道院を拠点として、信者たちは布教活動を行った。","note":"布教の拠点","exp":"500"}],"5002":[{"type":"天文","name":"こぎつね座の鉄亜鈴型の星雲","rank":"2","desc":"こぎつね座のやや南にある、楕円形の中央がくびれた特徴的な形をした星雲。","note":"「天文学者の観測記録」<br/>発見物カード:165","exp":"330"}],"468":[{"type":"歴史遺物","name":"ソロモンの鍵","rank":"5","desc":"古代ユダヤ王国のソロモン王が記したとされる魔術書。72の悪魔を召喚し、使役する方法が書かれていると言われる。","note":"激闘の果てに<br/><br/>発見時経験値1209　発見物カード経験値604","exp":"1209"}],"1200":[{"type":"歴史遺物","name":"チャン・バラム王の王冠","rank":"3","desc":"パカル王の息子で、その跡を継いだチャン・バラム王のものといわれている。勇壮な造りで、その力を誇示するように、大きな黒曜石がついている。","note":"王の血と神々の護り","exp":"539"}],"4845":[{"type":"天文","name":"ふたご座流星群","rank":"3","desc":"ふたご座の方角から、飛び出して来るように見える流星群。一年のうち約15日間、出現する。流星群の中では比較的穏やかな見え方をする。","note":"「ふたご座流星群」<br/>h発見物カード:255","exp":"510"}],"748":[{"type":"財宝","name":"カール大帝の宝冠","rank":"2","desc":"東フランクの王、カール大帝が西ローマ皇帝に即位した際の宝冠。これにより西ローマが復活、帝権と教皇権の提携が確立し、ビザンツ帝国に対抗することになる。","note":"西ローマ帝国復活","exp":"390"}],"3001":[{"type":"地理","name":"パムリコ湾","rank":"2","desc":"複数の岬に囲まれた、三角状の入り江。黒髭と恐れられている海賊が活動拠点にしていたといわれている。もしかすると現在も…。","note":"「書きかけの地図」<br/>発見物カード:110","exp":"220"}],"5889":[{"type":"植物","name":"ローレルジンチョウゲ","rank":"5","desc":"ヨーロッパ全土に分布する低木の有毒植物。花や実、草部分に猛毒があり、樹液に触れると発疹などの原因になる。口にすると内臓や神経を損傷するなど、毒性は強い。","note":"","exp":"1340"}],"2860":[{"type":"植物","name":"ヒナゲシ","rank":"3","desc":"中国からヨーロッパにかけて広い地域で生息する、寒さに強い一年草。四枚弁の薄い花びらを持つ。秦時代の将軍・項羽の愛姫・虞美人に由来する「虞美人草」という名でも呼ばれる。彼女の墓には、この花がよく咲いたといわれている。","note":"虞美人草","exp":"540"}],"5197":[{"type":"港・集落","name":"雲台山","rank":"2","desc":"読み方は、「ユンタイシャン」。春秋時代には越の王・勾践がこの地を首都とした、歴史のある街。平坦な地が続く農作地で、茶の産地としても有名。","note":"到達する","exp":"350"}],"1337":[{"type":"地理","name":"ジャワ島","rank":"2","desc":"スマトラ島の南東に位置する島。東西に細長い地形になっている。山がちで、多くの火山を有している。古くから仏教とヒンドゥー教が広まっていたが、近年はイスラム教が拡大しているようだ。","note":"スマトラ南東の島","exp":"220"}],"5360":[{"type":"宗教建築","name":"エレウシス神殿","rank":"2","desc":"アテネ近くのエレウシスにあったデメテル神殿の遺跡。\nこの神殿で行われた秘儀の存在は古代には広く知られており、\n即位前のハドリアヌスなど有力者も参加している。","note":"","exp":""}],"1821":[{"type":"財宝","name":"金の腕輪","rank":"1","desc":"豊富な金を使用して作られた腕輪。貴族の持ち物だったと思っていいだろう。年代は古いものではなく、最近作られたもののようだ。","note":"珍しい腕輪の地図","exp":"150"}],"808":[{"type":"地理","name":"チャゴス諸島","rank":"2","desc":"インド洋の中央付近に点在する島々。ほとんどがサンゴ礁におおわれている。インドからは1600kmあまり離れている。耕作は不可能で人が定住するのは無理だろう。","note":"大海原の真ん中","exp":"380"}],"6748":[{"type":"伝承","name":"アイトワラス","rank":"5","desc":"バルト海東岸の都市で信仰されている蛇の精霊。一度家にすみつくと追い出しにくいが、家の者に富を授けると伝わる。部屋の中では黒猫や雄鶏、外ではドラゴンや尾の燃えているヘビなどに姿を変えるといわれる。","note":"","exp":""}],"6532":[{"type":"歴史遺物","name":"ネブラの天文盤","rank":"5","desc":"先史時代のヨーロッパで作られた青銅製の円盤。太陽と月、星々が金を貼って表されている。両手で抱えるほどの大きさで、天体観測に使用された道具と考えられる。","note":"レガシー星の叡智　中央","exp":"2700"}],"1045":[{"type":"美術品","name":"聖ドニの殉教","rank":"1","desc":"アンリ・ベルショーズ作の祭壇画。当時、金地に鮮やかな色彩で描く手法が流行し、これもそれにならった作風である。","note":"流行した宗教画","exp":"110"}],"6968":[{"type":"大型生物","name":"ピューマの幼体","rank":"5","desc":"ピューマの幼体は成体と異なり、黒い斑点模様と縞模様の尾、青色の目を持つ。成長とともに、この特徴は消えていくが、これは周囲の環境に溶け込み、危険から身を守るためのものだと考えられる。","note":"追究クエスト<br/>発見物カード:510","exp":"1020"}],"5461":[{"type":"中型生物","name":"フサオマキザル","rank":"3","desc":"南米北東部などに生息するサル。非常に高い知能を持っており、石で木の実を割ったり、木を叩いて中にいる虫を探したりすることができる。","note":"南米の賢者<br/><br/>発見時経験値490　発見物カード経験値245","exp":"490"}],"525":[{"type":"歴史遺物","name":"古代のコーヒー","rank":"1","desc":"コーヒーはエチオピア原産で古代から薬として飲まれていた。当時は、実を干し、煮出して飲んでいたようだ。","note":"古代の食品の地図","exp":"27"}],"6076":[{"type":"伝承","name":"カリュブディスの渦潮","rank":"4","desc":"古来、自然現象を元にして神話が作られる例は枚挙に暇がない。航海の難所であるメッシナ海峡もその例に漏れず、渦潮を発生させる大食いの怪物が潜んでいるとされ、船乗りたちを恐れさせた。","note":"","exp":""}],"6549":[{"type":"歴史遺物","name":"ユークリッド原論","rank":"5","desc":"アレクサンドリアの数学者であるエウクレイデス(ユークリッド)が紀元前3世紀ごろに編纂した数学書。別称は「幾何学原論」。ピタゴラスなどの先人と自らの数学理論をまとめた書物で、後世の数学理論における基礎となった。","note":"","exp":""}],"1338":[{"type":"地理","name":"カリマンタン島","rank":"2","desc":"マラッカ海峡の東に位置する巨大な島。全体的に山がちで、生息する生物は、大型生物から昆虫まで多岐にわたる。鉱物資源も豊富でダイヤモンドの鉱脈も存在するようだが、島は密林に覆われており開発は進んでいない。","note":"マラッカ東の大陸調査","exp":"280"}],"345":[{"type":"大型生物","name":"ジャガー","rank":"5","desc":"「一度の跳躍で獲物を殺す」という名のとおり、獲物を一撃で噛み砕く力を持っている。その力はカメの甲羅をも割り、ときにはワニまで捕食するという。木登りが得意で、泳ぎもうまい。主に単独で行動する。","note":"一撃！","exp":"1118"}],"2983":[{"type":"海洋生物","name":"ビンナガ","rank":"3","desc":"胸ビレが長いマグロの仲間。真上から見ると羽を広げているように見える。脂がよく乗っており食用としても利用価値が高い。","note":"釣り","exp":"530"}],"6691":[{"type":"鳥類","name":"コールダック","rank":"4","desc":"別名ナキアヒル。ネーデルランドでアヒルを品種改良したものといわれている。大きな鳴き声で野生の鴨を誘導するおとりとして使われていた。\n愛玩用ペットとしても人気がある。","note":"クエスト「西洋の小さな鴨」<br/>発見物カード:305","exp":"610"}],"456":[{"type":"中型生物","name":"エリマキキツネザル","rank":"2","desc":"襟を付けたような長い毛を持つ。白毛と赤毛の二種類がおり、そのどちらも、うるさいくらいの声で鳴く。果実をよく食べる。","note":"襟の色","exp":"260"}],"2363":[{"type":"鳥類","name":"オナガドリ","rank":"4","desc":"日本原産のニワトリの一種。突然変異で生まれたという。\n雄の尾羽の一部は、生え変わることがないため、極めて長く伸びている。","note":"尾の長いニワトリ","exp":"620"}],"5233":[{"type":"宗教遺物","name":"正義の女神","rank":"3","desc":"ローマ神話の「正義」を司る女神ユースティティアを模した彫像。手には正邪を量る天秤と力を象徴する剣を持つ。さまざまな女神と同一視されることもある。","note":"","exp":"810"}],"5476":[{"type":"大型生物","name":"アメリカヌマジカ","rank":"1","desc":"パンタナル湿原でよく見られる動物。\n南米に生息するシカの中で最も大きいといわれている。\n二本に枝分かれした太い角は最長で約60cmにもなる。","note":"大型のシカの地図<br/><br/>発見時経験値100　発見物カード経験値50","exp":"100"}],"1991":[{"type":"海洋生物","name":"バラマンディ","rank":"2","desc":"東南アジアからオーストラリア沿岸に広く分布する巨大なスズキの一種。","note":"釣り","exp":"350"}],"479":[{"type":"財宝","name":"賢者の石","rank":"5","desc":"パラケルススがアゾートを用いて精製した、正体不明の物質。その製法は秘密とされている。錬金術では、この物質の生成に成功したら、その成果と手がかりのすべてを放棄しなくてはいけないとされている。","note":"賢者の石","exp":"1170"}],"5858":[{"type":"財宝","name":"バガヴァッド・ギーター","rank":"5","desc":"ヒンドゥー教の聖典の一つ。叙事詩であるマハーバーラタに含まれている。クリシュナと五王子の一人アルジュナの対話形式で書かれており、各カーストのなすべきことが語られている。","note":"","exp":"1370"}],"2890":[{"type":"地理","name":"雲南石林カルスト","rank":"2","desc":"重慶より更に南方に広がる、多くの奇岩が林立している地。景観と穏やかな気候に恵まれている。","note":"書きかけの地図","exp":"360"}],"1493":[{"type":"中型生物","name":"クズリ","rank":"5","desc":"ずんぐりとした大きな体を持つ。強靭なあごは、凍った肉や骨も噛み砕くことができる。やわらかい雪の上でも沈むことなく素早い動きができる。","note":"森の悪魔","exp":"949"}],"1785":[{"type":"地理","name":"オクシデンタル山脈","rank":"2","desc":"アンデス山脈の支脈。オクシデンタル山脈はコピアポの北でアンデス山脈より派生し、トゥンベス付近まで走っている。アンデス山脈との相違点として活発な火山を有していることが挙げられる。","note":"書きかけの地図","exp":"260"}],"1741":[{"type":"宗教遺物","name":"ワシククの祭礼用土器","rank":"1","desc":"ワシクク地方の祭事に使われた土器。飲料などの液体を入れることはなく、神像同様に信仰の対象になった。前面・背面の両面に同じ顔がつけられている。丸い瞳と、にんまりと笑ったような口元は、ヨーロッパではあまり見ない意匠である。","note":"祭礼用土器の地図","exp":"90"}],"804":[{"type":"植物","name":"ナナカマド","rank":"1","desc":"目の詰まった硬い木でかまどで7回燃やしても燃え尽きないといわれる。木工細工によく用いられる。秋になると美しく紅葉する。","note":"大きな木の地図","exp":"47"}],"821":[{"type":"財宝","name":"大理石のテーブル","rank":"1","desc":"大理石を使った豪華なテーブル。美しい装飾が施されている。相当な財力がなければ、こんな調度品はそろえられないだろう。","note":"大理石の調度の地図","exp":"61"}],"2107":[{"type":"歴史遺物","name":"ケルチ様式のつぼ","rank":"3","desc":"カッファの周辺で栄えていた王国のために作られたつぼ。\nこのつぼを輸入していた王国も、模造品を製作していたようだ。","note":"特別製のつぼ","exp":"490"}],"4843":[{"type":"天文","name":"からす座","rank":"1","desc":"ギリシャ神話の中で、アポロンの使いの鳥が天に上げられたとされる星座。アポロンが恋人を殺す原因となる誤報をもたらしたため、罰を受けて天上界から追放され、星座になったのだという。","note":"嘘か錯誤か","exp":"100"}],"2800":[{"type":"植物","name":"サンザシ","rank":"2","desc":"中国に生息する植物。キリストの冠にも使用されたといわれる。\n盆栽や庭木にも用いられ、果実は食用や薬用に使われる。","note":"薬になる植物","exp":"270"}],"1258":[{"type":"地理","name":"三角州","rank":"4","desc":"上流から押し流された砂や泥土が河口付近に堆積してできる、河口の浅瀬部分。長い年月をかけて泥土が溜まり続ければ、いつしか浅瀬は島になるのかもしれない。","note":"大河を割る島","exp":"624"}],"6141":[{"type":"歴史遺物","name":"ハンニバルの大理石像","rank":"1","desc":"ハンニバルはカルタゴの将軍で、共和制ローマを攻めて功績があった。一時はイタリア半島まで攻め込んだが、ザマの戦いで大スキピオに敗れた。","note":"名将軍の采配","exp":"120"}],"1320":[{"type":"地理","name":"チャオプラヤ川","rank":"4","desc":"ヤーデインの西に広がる湾の最奥に河口を持つ大河。下流域では、その豊かな水量を利用し、浮稲による稲作が行われている。運河としても広く利用されているようだ。","note":"王朝を支える川","exp":"636"}],"6718":[{"type":"財宝","name":"火焔太鼓","rank":"5","desc":"雅楽で用いられる左右一対の大型の太鼓。\nそれぞれ周囲が龍と鳳凰の彫刻で飾られている。鎌倉幕府の初代将軍・頼朝が寄進したとされるものが有名。","note":"楽の叡智・心に響く楽器　右上","exp":""}],"2328":[{"type":"財宝","name":"今昔物語集","rank":"2","desc":"読みは「こんじゃくものがたりしゅう」。日本・インド・中国の説話が千話以上収められた日本の書物。\n話の書き出しが、すべて「今は昔」となっているのが特徴である。","note":"説話集の地図","exp":"230"}],"2736":[{"type":"歴史遺物","name":"新羅の木簡","rank":"1","desc":"損傷の激しい木簡。新羅の遺物が多く発見される場所で、よく出土する。\nこの地域で過去に起きた出来事を記録したもののようだが、傷みがひどく解読できない。","note":"古文書の地図","exp":"140"}],"1890":[{"type":"歴史遺物","name":"ボン・ジェズス号","rank":"2","desc":"ポルトガルの東インド貿易船。\nリスボンからインド方面に向かう途中、マダガスカル島から東の地点で暗礁に乗り上げ、沈没した。","note":"サルベージ","exp":"310"}],"5562":[{"type":"天文","name":"しぶんぎ座","rank":"2","desc":"フランスの天文学者ラランドによって制定された星座。彼の使用した観測機器からこの名がつけられた。一月にはこの星座の近くで流星群を見ることができる。","note":"空に浮かんだ観測機器<br/><br/>発見時経験値350　発見物カード経験値175","exp":"350"}],"2114":[{"type":"歴史遺物","name":"サルベッタ号","rank":"2","desc":"ヴェネツィアの商船の一隻。\nベイルートの沖を航海中、海賊に襲われ沈没した。","note":"サルベージ","exp":"360"}],"1162":[{"type":"地理","name":"ホンジュラス湾","rank":"1","desc":"ユカタン半島の東に渡る湾。広大な面積にサンゴ礁が広がる。美しいカリブの海の中でも格別に美しい。","note":"クエスト「最も美しい海」<br/>発見物カード:60","exp":"120"}],"1554":[{"type":"小型生物","name":"クビナガガメ","rank":"1","desc":"首の長い水生のカメ。長い首は甲羅に収めることができないほどである。","note":"首の長い動物の地図","exp":"140"}],"3254":[{"type":"植物","name":"キング・プロテア","rank":"4","desc":"南アフリカに分布する花木。丈はおよそ2mまで伸び、直径30cm程度の風格のある立派な花を咲かせる。","note":"王者の花","exp":"700"}],"6177":[{"type":"宗教建築","name":"リンディスファーン修道院跡","rank":"4","desc":"ブリテン諸島にキリスト教が伝来した頃からの歴史を持つ修道院の跡で、福音書の装飾写本が製作されたことで名高い。ヴァイキングの襲撃による修道士の退去と復興を経た後、数百年後のイングランド王の迫害によって完全に廃墟と化した。","note":"","exp":"630"}],"1153":[{"type":"宗教遺物","name":"ケツアルコアトル像","rank":"3","desc":"アステカ神話における文化神。アステカの神には珍しい、生贄を求めない平和を愛する神だといわれている。テスカトリポカの罠に嵌められ、中央を去るときに「葦の1の年に戻る」と言い残したという。","note":"アステカの文化神","exp":"539"}],"6679":[{"type":"天文","name":"カフ","rank":"4","desc":"カシオペヤ座にある2等星。エチオピアの王妃カシオペヤの腕の付け根にある。名はアラビア語で「染めた手」を意味する。アラビアには「プレアデスの両手」という星列がありその染められた爪にあたる星だった。","note":"発見物カード:355","exp":"710"}],"5210":[{"type":"宗教遺物","name":"石製の浮屠塔","rank":"2","desc":"宋代に作られたと見られる浮屠塔。仏塔とも呼ばれる。釈迦本人の仏舎利を納めた塚を模したとされる。五段に区切られ、それぞれの段に仏像が彫られている。","note":"","exp":""}],"6978":[{"type":"財宝","name":"ギジャーク","rank":"2","desc":"中央アジアの伝統的な弦楽器。弦は四本で、胴の下側に取り付けられ半円形の脚を膝にのせて弓で演奏する。ペルシャの楽器が、東西交易を通じて伝わったと考えられている。","note":"発見物カード:145","exp":"290"}],"1253":[{"type":"地理","name":"サンアントニオ岬","rank":"1","desc":"ラプラタ川南岸の岬。沿岸部は湿地帯になっている。近くには、ブエノスアイレスという街がある。","note":"目印を探せ","exp":"180"}],"171":[{"type":"宗教遺物","name":"ウンクルンクル像","rank":"2","desc":"南アフリカに住むズールーの天空神の像。ウンクルンクルはズールーの言葉で「先祖」を意味する。死ぬことになった人間に、子を作ることを許し、火を与えた。","note":"ズールーの神話","exp":"220"}],"5259":[{"type":"宗教遺物","name":"上座部仏教の仏典","rank":"2","desc":"釈迦の教えを純粋な形で保存した経典。仏教の一派で、南伝ともよばれる上座部仏教のもの。パガン王朝最初の王であるアノーヤター王が国内に広めるために使用したものと思われる。","note":"バガン地方　再調査報酬","exp":""}],"6501":[{"type":"宗教遺物","name":"コヨルシャウキの円板","rank":"3","desc":"アステカの女神・コヨルシャウキの浮彫りがある巨大な石の円板。弟にあたる太陽神ウィツィロポチトリ誕生の際に戦いを挑むが倒され、体をバラバラにされたという神話の場面を描いている。女神の名は頬につけたコヨリという鈴に由来する。","note":"","exp":""}],"1460":[{"type":"小型生物","name":"フクロモグラ","rank":"1","desc":"モグラに似た有袋類。砂漠に生息し、地中を掘り進んで移動する。その際に出合った生物はなんでも捕食する。","note":"白いモグラの地図","exp":"80"}],"3913":[{"type":"大型生物","name":"ビッグホーン","rank":"3","desc":"北米西部に生息する大きなヒツジ。鼻などを除いた体の大半を覆う茶色い毛並みと、半月状に弧を描く大きな角が特徴。この角はメスよりもオスのほうが大きくなる。","note":"立派な角を持つウシ","exp":"500"}],"1350":[{"type":"小型生物","name":"トビヘビ","rank":"2","desc":"樹上性でトカゲやカエルなどを食べるヘビ。敵から逃れるときなど肋骨を広げて扁平な体にして、体をくねらせて滑空する。","note":"空飛ぶヘビ","exp":"280"}],"5721":[{"type":"植物","name":"サラソウジュ","rank":"4","desc":"幹高が30mにも達する巨大な木。釈迦が入滅した際、その四方にこの木が二本ずつ生えていたといわれている。そのため二本一組で沙羅双樹と呼ばれるようになった。","note":"2017.02.07新規追加","exp":""}],"2510":[{"type":"虫類","name":"ベニモンアゲハ","rank":"4","desc":"中国南部からインドにかけて生息する、黒い羽に赤や白の斑点を持つチョウ。\n幼虫時に食べる草から毒を体内に取り込み、敵から身を守る。","note":"チョウが持つ毒<br/><br/>発見時経験値740　発見物カード経験値370","exp":"740"}],"246":[{"type":"地理","name":"フィンランド湾","rank":"1","desc":"リガの北にある、東西に長い湾。水深はかなり浅い。緯度の高さにくらべて、沿岸部は比較的温暖である。","note":"バルト海の湾の調査","exp":"80"}],"2957":[{"type":"植物","name":"メイフラワー","rank":"3","desc":"ヨーロッパから北アフリカにかけて広く分布する植物。セイヨウサンザシとも呼ばれる。五月ごろ、五枚の花弁を持つ花を咲かせる。","note":"船を守護する木","exp":"440"}],"5938":[{"type":"植物","name":"アルファローバ","rank":"3","desc":"ポルトガルにおけるイナゴマメの別名。\nその果実は甘く、栄養価も高いため、お菓子などの材料として珍重される。","note":"","exp":"600"}],"2054":[{"type":"宗教遺物","name":"アヌケト像","rank":"2","desc":"ナイル川に増水をもたらすといわれている女神の像。\nパピルスの杖と羽つきの冠をかぶったこの女神の恩恵で、エジプトは古代から栄えていたのだろう。","note":"［勅命］[[運河開通を見つめる像","exp":"310"}],"1901":[{"type":"虫類","name":"コノハムシ","rank":"2","desc":"外見が植物の葉に似ている虫。この特徴があるのはメスの成体で、産み落とす卵も植物の種に似ている。南国の果物の葉を好んで食べる。オーストラリア、東南アジア、インドの熱帯林に生息。","note":"木の葉の化け物","exp":"290"}],"3787":[{"type":"天文","name":"レグルス","rank":"4","desc":"しし座で最も明るい1等星。名はラテン語で小さな王を意味する。古代の占星術では王や王家を象徴する星とされていた。コル・レオニスという別名がありこちらは獅子の心臓を意味する。","note":"視認","exp":"730"}],"3807":[{"type":"宗教遺物","name":"創世記（宗教遺物）","rank":"5","desc":"旧約聖書第一の書。世界の起源や人類の創造、イスラエル民族の古い歴史の物語などで構成されている。","note":"クエスト「聖書についての相談事」<br/>発見物カード:580","exp":"1160"}],"2083":[{"type":"史跡","name":"手形で描かれた壁画","rank":"3","desc":"先住民によって作られた洞窟壁画。「多くの手の洞窟」という意味を持つ。\n赤い顔料によって残された手形の他に、この近辺で見られる野生動物を模した絵も一緒に描かれている。","note":"洞窟で見た恐怖","exp":"500"}],"1123":[{"type":"地理","name":"アマゾン川","rank":"3","desc":"南米大陸を横断する大河。流域には広大な森林が広がっていて、動植物の楽園となっている。そこは、航海者の心をかき立てる未知の領域といえよう。","note":"動植物の楽園","exp":"533"}],"6458":[{"type":"美術品","name":"楢柴肩衝","rank":"5","desc":"天下三肩衝の一つと称される茶入。その価値から名だたる人物のもとを渡ったとされる一品。江戸の大火事の際に破損し、修繕されたのち、所在不明になったといわれる。","note":"追究クエスト　発見物カード:1075","exp":"2150"}],"3653":[{"type":"大型生物","name":"アムールヒョウ","rank":"2","desc":"ロシア東部の沿岸に生息する大型のヒョウ。どうやら他のヒョウとは生態が異なり、獲物を樹上に運ぶ習性がないようだ。","note":"極北の猛獣の地図","exp":"370"}],"1954":[{"type":"植物","name":"ファイアーバード","rank":"4","desc":"新大陸の熱帯に生息するバショウの一種。鮮やかな紅い花を咲かせる。花弁の形は火の鳥を思わせる。","note":"鳥の名を持つ花","exp":"700"}],"3652":[{"type":"地理","name":"チュクチ半島","rank":"2","desc":"ベーリング海峡に接する半島。極寒の土地だが、氷の大地の下に豊富な資源が眠っているのか、人が生活していた形跡がある。","note":"書きかけの地図","exp":"360"}],"1739":[{"type":"財宝","name":"戦士の頭飾り","rank":"2","desc":"ニューギニアの部族間闘争の際に、戦士たちが身に着ける頭飾り。極楽鳥の体に特定の時期だけ見られる飾り羽を、ふんだんに用いて作る。この頭飾りと精霊の加護が宿った胸飾り、そして体中に施したペイントが、仲間たちの士気を高める。","note":"頭飾りの地図","exp":"210"}],"5273":[{"type":"歴史遺物","name":"インカの土器","rank":"2","desc":"インカ帝国で使われていたものとよく似た模様の土器。かつてはインカ人が島を訪れていたと思われる。この場所になにを求めて来たのだろうか。","note":"ガラパゴス奥地　再調査報酬","exp":"220"}],"5317":[{"type":"虫類","name":"ヒヨケムシ","rank":"2","desc":"体長のおよそ3分の1を鋏角が占めるクモに似た生物。大型のものはネズミや小鳥なども捕食することがある。毒を持つという話はないが、うかつに近づかないほうがよいだろう。","note":"","exp":""}],"6027":[{"type":"財宝","name":"ペドロからの手紙","rank":"2","desc":"ペドロ王子が兄弟に宛てた手紙の写し。各王子に、それぞれ文化、貿易、戦争、宗教について書かれた手紙を出していたようだ。エンリケ王子宛ての手紙が最も多く、ヴェネチアによる東方貿易についての資料が添付されている。","note":"","exp":"210"}],"6863":[{"type":"中型生物","name":"シャムネコ","rank":"3","desc":"シャム原産の猫。毛は短く、顔や耳、尻尾、手足など一部の毛色が濃い。シャムの王侯貴族など、限られた者のみが買うことを許されているという。","note":"発見物カード:140","exp":"280"}],"2488":[{"type":"財宝","name":"安土城瓦","rank":"3","desc":"安土城の屋根に葺かれた黒い軒瓦。前面には三つ巴の紋があり、凹んでいる部分には金箔が貼られている。\n火災により、燻された跡が残っている。","note":"ダンジョン","exp":"520"}],"2853":[{"type":"歴史遺物","name":"資治通鑑","rank":"2","desc":"読み方は、「しじつがん」。春秋時代から宋代までを記してある歴史書。\n「史記」や「漢書」とは違った文体で書かれており、読みやすさを重視したと考えられている。","note":"勉学に励む少女","exp":"310"}],"6324":[{"type":"中型生物","name":"スカンク","rank":"2","desc":"北米から南米にかけて広く生息する動物。白と黒の体毛が特徴。危険を感じると警告の体勢を取り、最終手段として悪臭の分泌液を肛門から出す。射程は5mほど。臭いに鈍感な猛禽類には効果が薄く、捕食されてしまう。","note":"","exp":"350"}],"6436":[{"type":"歴史遺物","name":"ローマ教皇のアバカス","rank":"5","desc":"ローマ帝国で使用されていたという計算用器具。溝ソロバン。青銅など金属製の板の溝にはめ込んだ珠を移動して計算する。西欧世界では長く忘れられていたが、10?11世紀ころのローマ教皇シルウェステル2世が改良して再導入された。","note":"レガシー・数の叡智　右上","exp":""}],"1753":[{"type":"海洋生物","name":"セイルフィッシュ","rank":"5","desc":"バショウカジキ。比較的小型であるが、立派な背ビレが特徴の美しい魚体を持つ。","note":"釣り","exp":"828"}],"703":[{"type":"中型生物","name":"ヤマアラシ","rank":"1","desc":"全身に長いトゲが生えている動物。アフリカで見られる。普段はおとなしいが、危険を感じると全身のトゲを逆立て、後ろ向きに突進してくる。大量のノミがついており、トゲも痛いがノミも困る。","note":"クエスト「針山のような動物」<br/>発見物カード:60","exp":"120"}],"3316":[{"type":"史跡","name":"ガムラ・ウプサラ","rank":"4","desc":"ストックホルムより北に位置する地域名。\n中世まで北欧の中心地として栄え、歴代のスウェーデン王の墳墓と居城があった。近くには北欧最古のウプサラ大学があり、グスタフ2世アドルフの右腕であるオクセンシェルナなどを輩出している。","note":"戴冠の地<br/><br/>発見時経験値750　発見物カード経験値375","exp":"750"}],"409":[{"type":"小型生物","name":"グリーンバシリスク","rank":"5","desc":"川に面した樹上に生息していて、襲われると水に飛び込んで難を逃れる。後肢で水の上を走ることもある。オスには頭部、背中、尾の三カ所にたてがみがある。","note":"奇跡を起こすトカゲ","exp":"1033"}],"1589":[{"type":"地理","name":"アーネムランド","rank":"3","desc":"オーストラリア最北部にある半島を指す。中央部は山がちだが海岸線は高低差の少ない地表が続く。古代のアボリジニたちが書いたといわれる岩絵が多数残る。","note":"クエスト「始まりの地」<br/>発見物カード:240","exp":"484"}],"3688":[{"type":"歴史遺物","name":"ヘイムスクリングラ","rank":"4","desc":"古代ノルド語で「世界の輪」の意味。13世紀頃に編纂されたとされる、サガの一種。\nこのサガによると、アイスランドの各方角には守護者が存在しているという。","note":"世界の環","exp":"630"}],"1572":[{"type":"海洋生物","name":"コビトペンギン","rank":"2","desc":"最小のペンギン。地下の穴や岩場などに巣を作り、オスとメスが交代で卵を温める。海で潜水を繰り返し、魚を捕らえる。","note":"泳ぐ鳥","exp":"285"}]};